_e118_readonly_init() {
    if test -z "${E118_TMPDIR:-}"; then
        E118_TMPDIR=$(mktemp -d /tmp/ex199e136-readonly.XXXXXX) || return 1
        chmod 700 "$E118_TMPDIR" 2>/dev/null || true
    fi
}

_e118_audit() {
    _e118_readonly_init || return 1
    title "V199e137：脚本与运行态审计"
    echo "脚本：$SCRIPT_PATH"
    echo "版本：$SCRIPT_VERSION"
    echo "SHA256：$(sha256sum "$SCRIPT_PATH" 2>/dev/null | awk '{print $1}' || echo unknown)"
    echo "权限：$(stat -c '%a %U:%G' "$SCRIPT_PATH" 2>/dev/null || echo unknown)"
    echo "行数：$(wc -l < "$SCRIPT_PATH" 2>/dev/null || echo unknown)"
    echo "Bash语法：$(bash -n "$SCRIPT_PATH" 2>/dev/null && echo PASS || echo FAIL)"
    echo "快捷入口：$(readlink -f "$SYMLINK" 2>/dev/null || echo 未安装)"
    if test -e "$SYMLINK"; then
        echo "快捷入口同版：$(cmp -s "$SCRIPT_PATH" "$SYMLINK" && echo yes || echo no)"
    fi
    echo
    echo "Xray Core：$($XRAY_BIN version 2>/dev/null | head -n1 || echo 未安装)"
    echo "Xray 服务：$(systemctl is-active xray 2>/dev/null || echo unknown) / $(systemctl is-enabled xray 2>/dev/null || echo unknown)"
    if test -s "$CONFIG"; then
        echo "配置权限：$(stat -c '%a %U:%G' "$CONFIG" 2>/dev/null || echo unknown)"
        if jq empty "$CONFIG" >/dev/null 2>&1; then info "config.json JSON：通过"; else error "config.json JSON：失败"; fi
        _e116_show_config_brief || true
        if test -x "$XRAY_BIN"; then _e118_xray_test_config "$CONFIG" 1 && info "Xray Core 配置测试：通过" || error "Xray Core 配置测试：失败"; fi
        if _e116_config_has_reality_file "$CONFIG"; then
            info "Reality 基础结构：通过"
            local password; password=$(_e118_reality_password 2>/dev/null || true)
            test -n "$password" && info "Reality Password(pbk)：可用" || error "Reality Password(pbk)：缺失/无法派生"
        else
            warn "未发现 Reality 入站；若当前是 VLESSENC/SS2022 单协议则正常。"
        fi
    else
        warn "config.json 不存在。"
    fi
    echo
    echo "DAT timer：$(systemctl is-enabled xray-dat-update.timer 2>/dev/null || echo disabled) / $(systemctl is-active xray-dat-update.timer 2>/dev/null || echo inactive)"
    echo "geoip.dat：$(stat -c '%s bytes, %y' "$DAT_DIR/geoip.dat" 2>/dev/null || echo missing)"
    echo "geosite.dat：$(stat -c '%s bytes, %y' "$DAT_DIR/geosite.dat" 2>/dev/null || echo missing)"
    _e88_show_init_window_state || true
    echo
    _e116_show_ssh_guard_state || true
    echo
    _e121_show_log_retention || true
    echo
    echo "热更新状态："
    test -s "$E118_STATE_FILE" && sed 's/^/  /' "$E118_STATE_FILE" || echo "  尚无 e118 状态记录"
    echo "最近事务备份：$(cat "$E118_DIR/latest_backup.txt" 2>/dev/null || echo none)"
}

_e118_self_test() {
    _e118_readonly_init || return 1
    local pass=0 fail=0 name sample oldtest
    _e118_test_ok() { pass=$((pass+1)); printf '  [PASS] %s\n' "$*"; }
    _e118_test_bad() { fail=$((fail+1)); printf '  [FAIL] %s\n' "$*"; }
    title "V199e137：只读自检"
    bash -n "$SCRIPT_PATH" && _e118_test_ok "bash -n" || _e118_test_bad "bash -n"
    test "$SCRIPT_VERSION" = "199e131" && _e118_test_ok "版本常量" || _e118_test_bad "版本常量"
    for name in preflight hot_update_from_legacy _e116_install_mode _e118_commit_config _e118_restore_state \
        e77_build_full_config e77_generate_vlessenc_pair do_user_manager do_summary install_update_dat \
        _e116_install_ssh_guard _e121_install_fail2ban_guard _e121_select_fail2ban_source \
        _e121_validate_ssh_log_flow _e121_test_and_repair_ssh_jails _e121_verify_fail2ban_runtime \
        _e121_detect_ssh_ports _e121_write_ssh_port_guard _e121_verify_ssh_port_guard \
        _e121_install_log_retention _e121_check_and_clean_space \
        _e116_apply_init_window_default30 main_menu; do
        declare -F "$name" >/dev/null 2>&1 && _e118_test_ok "函数 $name" || _e118_test_bad "缺少函数 $name"
    done
    sample=$'PrivateKey: AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA\nPassword: BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB'
    if _e118_parse_x25519_output "$sample" && test "$E77_REALITY_PRIV" = "AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA" && test "$E77_REALITY_PUB" = "BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB"; then
        _e118_test_ok "Xray 26 Password 密钥解析"
    else _e118_test_bad "Xray 26 Password 密钥解析"; fi
    sample=$'Private key: CCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCC\nPublic key: DDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDDD'
    _e118_parse_x25519_output "$sample" && _e118_test_ok "旧版 Public key 密钥解析" || _e118_test_bad "旧版 Public key 密钥解析"
    sample=$'{\n  "inbound": {"settings": {"decryption": "mlkem768x25519plus.native.0rtt.server-key"}},\n  "outbound": {"settings": {"encryption": "mlkem768x25519plus.native.0rtt.client-key"}}\n}'
    if e77_generate_vlessenc_pair_from_text "$sample" \
        && test "$E77_VLESSENC_DECRYPTION" = "mlkem768x25519plus.native.0rtt.server-key" \
        && test "$E77_VLESSENC_ENCRYPTION" = "mlkem768x25519plus.native.0rtt.client-key"; then
        _e118_test_ok "VLESSENC JSON 成对解析"
    else _e118_test_bad "VLESSENC JSON 成对解析"; fi
    _e118_valid_sid aabbccdd && ! _e118_valid_sid abc && _e118_test_ok "ShortId 偶数十六进制校验" || _e118_test_bad "ShortId 校验"
    if declare -f _e121_write_ssh_port_guard | grep -q 'f2b-before-allow' \
        && declare -f _e121_write_ssh_port_guard | grep -q 'XRAY_SSH_E121' \
        && declare -f _e121_write_ssh_port_guard | grep -q 'discover_f2b_chain' \
        && declare -f _e121_write_ssh_port_guard | grep -q 'prime_f2b_family' \
        && declare -f _e121_write_ssh_port_guard | grep -q 'ipv6_fail2ban_chain' \
        && declare -f _e121_write_ssh_port_guard | grep -q 'OnBootSec=45s'; then
        _e118_test_ok "SSH 开机端口自检与 IPv4/IPv6 fail2ban 链发现"
    else _e118_test_bad "SSH 开机端口/链序守护缺失"; fi
    if declare -f _e121_write_fail2ban_candidates | grep -q 'backend = systemd'; then
        _e118_test_bad "fail2ban 后端仍写死 systemd"
    else
        _e118_test_ok "fail2ban 后端按探测结果生成"
    fi
    if declare -f _e121_write_fail2ban_candidates | grep -q 'actionstart_on_demand=false' \
        && declare -f _e121_write_fail2ban_candidates | grep -q '%(action_)s'; then
        _e118_test_ok "fail2ban action 启动即建链且端口使用官方动态插值"
    else _e118_test_bad "fail2ban action 仍可能按需延迟建链"; fi
    if declare -f _e121_select_fail2ban_source | grep -q '_e121_prepare_rsyslog_auth_log' \
        && declare -f _e121_select_fail2ban_source | grep -q 'E121_RSYSLOG_LOG'; then
        _e118_test_ok "fail2ban journald/专用3天文件日志回退"
    else _e118_test_bad "fail2ban 文件日志回退缺失"; fi
    if declare -f _e121_prepare_rsyslog_auth_log | grep -q '_e121_validate_ssh_log_flow' \
        && ! declare -f _e121_detect_ssh_log | grep -Eq '/var/log/(messages|syslog)'; then
        _e118_test_ok "SSH 文件日志实时写入验证"
    else _e118_test_bad "SSH 文件日志可能仅凭存在即误判"; fi
    if declare -f _e116_install_ssh_guard | grep -q '_e121_install_ssh_guard' \
        && declare -f _e118_install_fail2ban_guard | grep -q '_e121_install_fail2ban_guard' \
        && declare -f _e118_impl_hot_update | grep -q '_e116_install_ssh_guard' \
        && declare -f _e118_impl_hot_update | grep -q '_e121_install_log_retention'; then
        _e118_test_ok "菜单11热更新已接入 e121 fail2ban 层"
    else _e118_test_bad "菜单11仍可能调用旧 fail2ban 实现"; fi
    if declare -f _e121_install_log_retention | grep -q 'MaxRetentionSec=3day' \
        && declare -f _e121_install_log_retention | grep -q 'MaxFileSec=1day' \
        && declare -f _e121_install_log_retention | grep -q 'Storage=persistent' \
        && declare -f _e121_install_log_retention | grep -q 'rotate 3' \
        && declare -f _e121_check_and_clean_space | grep -q 'E121_LOG_RETENTION_SCRIPT' \
        && ! declare -f _e121_check_and_clean_space | grep -q 'vacuum-time=2d' \
        && ! declare -f _e121_install_log_retention | grep -q '30day' \
        && declare -f enable_journald_volatile_default | grep -q '_e121_install_log_retention'; then
        _e118_test_ok "日志3天滚动且清理菜单不再压缩到2天"
    else _e118_test_bad "日志3天保留存在冲突"; fi
    if declare -f _e118_impl_apply_init_window_default30 | grep -q '_e105_install_init_window_boot_restore 30 30'; then _e118_test_ok "init30 显式传参"; else _e118_test_bad "init30 仍可能回落32"; fi
    if declare -f _e118_xray_test_config | grep -q 'run -test -config' \
        && ! declare -f _e118_xray_test_config | grep -Eq '\$XRAY_BIN[[:space:]]+test([[:space:]]|")'; then
        _e118_test_ok "Xray 测试命令"
    else _e118_test_bad "Xray 测试命令"; fi
    if declare -f _update_matrix | grep -q 'security.*reality'; then _e118_test_ok "SNI 更新限定 Reality"; else _e118_test_bad "SNI 更新选择器"; fi
    if ! declare -f e77_build_full_config | grep -q 'domainMatcher' \
        && ! declare -f e77_build_full_config | grep -q 'type: "field"' \
        && declare -f e77_build_full_config | grep -q 'network: "raw"'; then
        _e118_test_ok "Xray 26 路由/RAW 字段"
    else _e118_test_bad "仍含已移除路由字段或未使用 RAW"; fi
    echo
    echo "自检结果：PASS=$pass FAIL=$fail"
    test "$fail" -eq 0
}

