vm.swappiness = 10
vm.vfs_cache_pressure = 50
vm.dirty_ratio = 35
vm.overcommit_memory = 0
vm.max_map_count = 262144
fs.file-max = 1048576
fs.nr_open = 1048576
fs.inotify.max_user_instances = 262144
fs.aio-max-nr = 262144
kernel.pid_max = 4194304
kernel.randomize_va_space = 2
