            4) print_magenta ">>> 初始化云网络联通..."; bash "$UPDATE_DAT_SCRIPT" >/dev/null 2>&1 || true; ensure_xray_is_alive; info "配置已穿透替换系统！当前路由库完成热加载！"; local _p=""; read -rp "按 Enter 退回..." _p || true ;;
            5) do_update_core ;;
            6) if choose_sni; then _update_matrix; do_summary; while true; do local rb=""; read -rp "任务完毕，按 Enter 返回，或按 b 连续变更: " rb || true; if test "$rb" = "b" || test "$rb" = "B"; then if choose_sni; then _update_matrix; do_summary; else break; fi; else break; fi; done; fi ;;
            7) _global_block_rules ;;
            8) do_fallback_probe ;;
            9) do_status_menu ;;
            10) do_sys_init_menu ;;
            11) hot_update_from_legacy ;;
            12) do_space_cleanup_menu ;;
            13) do_network_params_menu_e56 ;;
            14) do_tcp_diag_menu_e63 ;;
            15) do_install_repair_e77 ;;
            16) e77_audit_runtime_state; _e52_pause ;;
            88) do_uninstall ;;
            0) exit 0 ;;
            *) echo -e "${red}错误拦截：代码解析为空值！${none}"; sleep 1 ;;
        esac
    done
}


#==============================================================================
# V198e88 FINAL OVERRIDE LAYER
# 目标：保留 V198e82 三协议主体，只扩展 13) 网络参数应用中心。
#==============================================================================

E88_NOTSENT_LOWAT_FILE="$CONFIG_DIR/tcp_notsent_lowat.txt"
E88_NETWORK_MENU_STATE_FILE="$CONFIG_DIR/network_menu_e88.txt"

_e88_install_self_entrypoint() {
    mkdir -p "$SCRIPT_DIR" 2>/dev/null || true
    if test -f "$SCRIPT_PATH"; then
        cp -f "$SCRIPT_PATH" "$SYMLINK" 2>/dev/null || true
        cp -f "$SCRIPT_PATH" "$SCRIPT_DIR/ex198e88.sh" 2>/dev/null || true
        cp -f "$SCRIPT_PATH" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
        chmod +x "$SYMLINK" "$SCRIPT_DIR/ex198e88.sh" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
        hash -r 2>/dev/null || true
    fi
    echo "198e88" > "$SCRIPT_VERSION_FILE" 2>/dev/null || true
}

_e88_default_iface() {
    if declare -F _get_default_iface >/dev/null 2>&1; then
        _get_default_iface 2>/dev/null && return 0
    fi
    ip route get 1.1.1.1 2>/dev/null | awk '{for(i=1;i<=NF;i++) if($i=="dev"){print $(i+1); exit}}' || true
}

_e88_escape_key_re() { printf '%s' "$1" | sed 's/[.[\*^$()+?{}|\\]/\\&/g'; }

_e88_sysctl_get() {
    local key="$1"
    sysctl -n "$key" 2>/dev/null | awk '{$1=$1; print}' || echo "unsupported"
}

_e88_sysctl_persistent() {
    local key="$1" file="${2:-$NETWORK_OPT_CONF}" re val
    re=$(_e88_escape_key_re "$key")
    if test -f "$file"; then
        val=$(awk -F= -v re="^[[:space:]]*${re}[[:space:]]*=" '$0 ~ re {v=$2; gsub(/^[ \t]+|[ \t]+$/, "", v)} END{if(v!="") print v}' "$file" 2>/dev/null || true)
        test -n "$val" && echo "$val" || echo "未写入"
    else
        echo "文件不存在"
    fi
}

_e88_strip_key_conflicts() {
    local key="$1" re f
    re=$(_e88_escape_key_re "$key")
    mkdir -p "$BACKUP_DIR/sysctl" 2>/dev/null || true
    for f in /etc/sysctl.conf /etc/sysctl.d/*.conf; do
        test -f "$f" || continue
        if test "$(readlink -f "$f" 2>/dev/null || echo "$f")" = "$(readlink -f "$NETWORK_OPT_CONF" 2>/dev/null || echo "$NETWORK_OPT_CONF")"; then
            continue
        fi
        if grep -Eq "^[[:space:]]*${re}[[:space:]]*=" "$f" 2>/dev/null; then
            cp -af "$f" "$BACKUP_DIR/sysctl/$(basename "$f").e88.$(date +%Y%m%d_%H%M%S).bak" 2>/dev/null || true
            sed -i -E "/^[[:space:]]*${re}[[:space:]]*=/d" "$f" 2>/dev/null || true
            warn "已从冲突文件中移除 ${key}：$f"
        fi
    done
}

_e88_set_sysctl_key() {
    local key="$1" value="$2" label="${3:-e88}" re
    mkdir -p /etc/sysctl.d "$CONFIG_DIR" "$BACKUP_DIR/sysctl" 2>/dev/null || true
    _e88_strip_key_conflicts "$key"
    if test -f "$NETWORK_OPT_CONF"; then
        cp -af "$NETWORK_OPT_CONF" "$BACKUP_DIR/sysctl/99-network-optimized.conf.e88.$(date +%Y%m%d_%H%M%S).bak" 2>/dev/null || true
    else
        touch "$NETWORK_OPT_CONF" 2>/dev/null || true
    fi
    re=$(_e88_escape_key_re "$key")
    sed -i -E "/^[[:space:]]*${re}[[:space:]]*=/d" "$NETWORK_OPT_CONF" 2>/dev/null || true
    cat >> "$NETWORK_OPT_CONF" <<EOF_E88_SYSCTL_KEY

# V198e88 ${label}
${key} = ${value}
EOF_E88_SYSCTL_KEY
    if sysctl -w "${key}=${value}" >/tmp/xray-e88-sysctl.log 2>&1; then
        info "运行态已应用：${key}=${value}"
    else
        warn "当前内核可能不支持：${key}=${value}；永久配置已写入，详情：/tmp/xray-e88-sysctl.log"
        sed 's/^/    /' /tmp/xray-e88-sysctl.log 2>/dev/null || true
    fi
    echo "${key}=${value}" >> "$E88_NETWORK_MENU_STATE_FILE" 2>/dev/null || true
}

_e88_validate_notsent_lowat() {
    local v="${1:-}"
    [[ "$v" =~ ^[0-9]+$ ]] || return 1
    if test "$v" -eq 0 2>/dev/null; then return 0; fi
    test "$v" -ge 4096 2>/dev/null && test "$v" -le 4194304 2>/dev/null
}

_e88_current_notsent_lowat() { _e88_sysctl_get net.ipv4.tcp_notsent_lowat; }
_e88_persistent_notsent_lowat() { _e88_sysctl_persistent net.ipv4.tcp_notsent_lowat; }

_e88_set_tcp_notsent_lowat() {
    local val="${1:-}" label="${2:-手动}"
    if ! _e88_validate_notsent_lowat "$val"; then
        error "tcp_notsent_lowat 数值非法：$val；允许 0 或 4096~4194304。"
        return 1
    fi
    _e88_set_sysctl_key net.ipv4.tcp_notsent_lowat "$val" "${label}: TCP unsent write queue low watermark"
    echo "$val" > "$E88_NOTSENT_LOWAT_FILE" 2>/dev/null || true
    _e88_show_tcp_notsent_lowat_state
}

_e88_show_tcp_notsent_lowat_state() {
    local run perm saved
    run=$(_e88_current_notsent_lowat)
    perm=$(_e88_persistent_notsent_lowat)
    saved=$(cat "$E88_NOTSENT_LOWAT_FILE" 2>/dev/null || echo "未记录")
    echo ""
    echo -e "  ${cyan}tcp_notsent_lowat 状态：${none}"
    printf "    %-30s %s\n" "运行态(sysctl):" "$run"
    printf "    %-30s %s\n" "永久配置($NETWORK_OPT_CONF):" "$perm"
    printf "    %-30s %s\n" "e88记录:" "$saved"
    echo ""
    echo "    26214  = 极低排队/网页响应优先：小包更灵敏，但高 RTT 极限吞吐可能受限。"
    echo "    32768  = 低延迟响应档：网页、ChatGPT、App 刷新优先。"
    echo "    65536  = 均衡档：日常翻墙、视频、下载混合使用。"
    echo "    131072 = 高吞吐档：高 RTT、大文件、测速更激进。"
}

_e88_show_notsent_conflicts() {
    echo ""
    echo -e "  ${cyan}tcp_notsent_lowat 定义来源扫描：${none}"
    grep -R "^[[:space:]]*net\.ipv4\.tcp_notsent_lowat[[:space:]]*=" \
      /etc/sysctl.conf /etc/sysctl.d /usr/lib/sysctl.d /lib/sysctl.d 2>/dev/null | sed 's/^/    /' || true
}

_e88_manual_tcp_notsent_lowat() {
    local v=""
    echo ""
    warn "手动值建议先测 26214 / 32768 / 65536 / 131072；过大可能增加排队延迟，过小可能限制高 RTT 吞吐。"
    read -rp "请输入 tcp_notsent_lowat 数值（0 或 4096~4194304，默认 26214）: " v || true
    v=${v:-26214}
    _e88_set_tcp_notsent_lowat "$v" "手动输入"
}

_e88_show_core_network_state() {
    local iface qdisc txq
    iface=$(_e88_default_iface)
    echo ""
    echo -e "  ${cyan}关键网络参数状态（运行态 / 永久态）：${none}"
    printf "    %-34s %-18s %-18s\n" "参数" "运行态" "永久态"
    printf "    %-34s %-18s %-18s\n" "----" "------" "------"
    local key
    for key in \
        net.core.default_qdisc \
        net.ipv4.tcp_congestion_control \
        net.ipv4.tcp_ecn \
        net.ipv4.tcp_fastopen \
        net.ipv4.tcp_mtu_probing \
        net.ipv4.tcp_adv_win_scale \
        net.ipv4.tcp_app_win \
        net.ipv4.tcp_notsent_lowat \
        net.ipv4.tcp_slow_start_after_idle \
        net.ipv4.tcp_autocorking \
        net.ipv4.tcp_tso_win_divisor \
        net.core.rmem_default \
        net.core.wmem_default \
        net.core.rmem_max \
        net.core.wmem_max; do
        printf "    %-34s %-18s %-18s\n" "$key" "$(_e88_sysctl_get "$key")" "$(_e88_sysctl_persistent "$key")"
    done
    echo ""
    echo -e "  ${cyan}网卡运行态：${none}"
    if test -n "$iface"; then
        txq=$(ip -o link show "$iface" 2>/dev/null | sed -n 's/.*qlen \([0-9][0-9]*\).*/\1/p' | head -n1)
        qdisc=$(tc qdisc show dev "$iface" 2>/dev/null | head -n1 || true)
        printf "    %-18s %s\n" "默认出口网卡:" "$iface"
        printf "    %-18s %s\n" "txqueuelen:" "${txq:-unknown}"
        printf "    %-18s %s\n" "tc qdisc:" "${qdisc:-unknown}"
        if command -v ethtool >/dev/null 2>&1; then
            ethtool -k "$iface" 2>/dev/null | grep -E 'generic-segmentation-offload|generic-receive-offload|tcp-segmentation-offload|large-receive-offload|rx-gro-hw|tx-udp-segmentation' | sed 's/^/    /' || true
        fi
    else
        warn "未识别默认出口网卡。"
    fi
}

_e88_show_network_param_discussion() {
    title "V198e88 可放入 13 菜单管理的网络参数说明"
    cat <<'EOF_E88_DISCUSS'
  一、建议放进 13 菜单并可切换的高价值参数：
    1) tcp_notsent_lowat：影响小包响应、发送队列排队和高 RTT 吞吐；已提供 26214/32768/65536/131072/手动。
    2) rmem/wmem/tcp_rmem/tcp_wmem：影响高 RTT、大带宽连接的接收/发送缓冲；原菜单已有高吞吐、均衡、手动。
    3) default_qdisc + tcp_congestion_control：建议 fq + bbr；这是 VPS 代理的基础 pacing 组合。
    4) tcp_adv_win_scale + tcp_app_win：影响接收窗口与应用保留窗口；建议默认 1/31，实验可测 2/31。
    5) tcp_mtu_probing：建议 1，降低路径 MTU 黑洞导致的卡顿。
    6) tcp_ecn / tcp_fastopen：建议稳态关闭，即 0；不是默认提速开关。
    7) txqueuelen：建议 3000；过小可能压吞吐，过大可能增加排队延迟。
    8) GRO/GSO/TSO/LRO：建议 GRO/GSO/TSO 保留 ON，LRO OFF；降低 CPU 压力且避免 LRO 转发副作用。
    9) MSS clamp：建议可一键应用；用于 PMTU/分片异常时减少握手后卡顿。

  二、建议只显示、不做常规切换的参数：
    netdev_budget/dev_weight、tcp_retries、tcp_fin_timeout、somaxconn、backlog、ipfrag、dirty_ratio 等。
    它们会影响系统整体行为，过度菜单化容易造成“越调越乱”。

  三、当前 e88 菜单策略：
    保留原 1-12 项；新增 13-25 项。只把“最常用且可回退”的网络项放进菜单。
EOF_E88_DISCUSS
}

_e88_apply_fq_bbr_stable_core() {
    title "应用 e88 稳态核心：fq + bbr + ECN=0 + TFO=0 + MTU probing=1"
    if declare -F apply_fq_qdisc_default >/dev/null 2>&1; then apply_fq_qdisc_default || true; fi
    _e88_set_sysctl_key net.core.default_qdisc fq "fq pacing 队列"
    _e88_set_sysctl_key net.ipv4.tcp_congestion_control bbr "BBR 拥塞控制"
    _e88_set_sysctl_key net.ipv4.tcp_ecn 0 "关闭 ECN，减少兼容性问题"
    _e88_set_sysctl_key net.ipv4.tcp_ecn_fallback 1 "ECN fallback"
    _e88_set_sysctl_key net.ipv4.tcp_fastopen 0 "关闭 TFO，避免跨境兼容性毛刺"
    _e88_set_sysctl_key net.ipv4.tcp_mtu_probing 1 "启用 MTU probing"
    _e88_set_sysctl_key net.ipv4.tcp_slow_start_after_idle 0 "关闭空闲后慢启动"
    _e88_set_sysctl_key net.ipv4.tcp_autocorking 0 "关闭 autocorking，降低代理小包等待"
    _e88_set_sysctl_key net.ipv4.tcp_tso_win_divisor 6 "TSO 窗口分割"
    _e88_show_core_network_state
}

_e88_set_adv_app_profile() {
    local scale="$1" app="$2" label="$3"
    if ! [[ "$scale" =~ ^-?[0-9]+$ ]] || test "$scale" -lt -2 2>/dev/null || test "$scale" -gt 4 2>/dev/null; then
        error "tcp_adv_win_scale 非法：$scale；建议 -2~4。"; return 1
    fi
    if ! [[ "$app" =~ ^[0-9]+$ ]] || test "$app" -lt 0 2>/dev/null || test "$app" -gt 31 2>/dev/null; then
        error "tcp_app_win 非法：$app；建议 0~31。"; return 1
    fi
    _e88_set_sysctl_key net.ipv4.tcp_adv_win_scale "$scale" "$label"
    _e88_set_sysctl_key net.ipv4.tcp_app_win "$app" "$label"
    _e88_show_core_network_state
}

_e88_manual_adv_app() {
    local scale app
    read -rp "请输入 tcp_adv_win_scale（-2~4，默认 1）: " scale || true
    scale=${scale:-1}
    read -rp "请输入 tcp_app_win（0~31，默认 31）: " app || true
    app=${app:-31}
    _e88_set_adv_app_profile "$scale" "$app" "手动接收窗口参数"
}

_e88_set_txqueuelen() {
    local val="$1" iface service_script
    if ! [[ "$val" =~ ^[0-9]+$ ]] || test "$val" -lt 128 2>/dev/null || test "$val" -gt 20000 2>/dev/null; then
        error "txqueuelen 非法：$val；建议 1000 / 3000，允许 128~20000。"; return 1
    fi
    iface=$(_e88_default_iface)
    test -n "$iface" || { error "无法识别默认出口网卡。"; return 1; }
    ip link set dev "$iface" txqueuelen "$val" 2>/dev/null || warn "运行态设置 txqueuelen 失败：$iface $val"
    echo "$val" > "$CONFIG_DIR/txqueuelen_e88.txt" 2>/dev/null || true
    service_script="/usr/local/bin/xray-txqueue-e88.sh"
    cat > "$service_script" <<EOF_E88_TXQ
#!/usr/bin/env bash
set -e
ip link set dev "$iface" txqueuelen "$val" 2>/dev/null || true
EOF_E88_TXQ
    chmod +x "$service_script" 2>/dev/null || true
    cat > /etc/systemd/system/xray-txqueue-e88.service <<EOF_E88_TXQ_SERVICE
[Unit]
Description=Xray e88 txqueuelen runtime restore
After=network-online.target
Wants=network-online.target

[Service]
Type=oneshot
ExecStart=$service_script
RemainAfterExit=yes

[Install]
WantedBy=multi-user.target
EOF_E88_TXQ_SERVICE
    systemctl daemon-reload >/dev/null 2>&1 || true
    systemctl enable --now xray-txqueue-e88.service >/dev/null 2>&1 || true
    info "txqueuelen 已设置并做开机恢复：$iface = $val"
    _e88_show_core_network_state
}

_e88_manual_txqueue() {
    local v
    read -rp "请输入 txqueuelen（建议 1000 或 3000，默认 3000）: " v || true
    v=${v:-3000}
    _e88_set_txqueuelen "$v"
}

_e88_apply_offload_default() {
    local iface script
    iface=$(_e88_default_iface)
    test -n "$iface" || { warn "未识别默认出口网卡，跳过 offload。"; return 0; }
    if declare -F apply_gso_gro_on_default >/dev/null 2>&1; then apply_gso_gro_on_default || true; fi
    if command -v ethtool >/dev/null 2>&1; then
        ethtool -K "$iface" gro on gso on tso on lro off rx-gro-hw on tx-udp-segmentation on 2>/dev/null || true
        ethtool -C "$iface" adaptive-rx on 2>/dev/null || true
    fi
    script="/usr/local/bin/xray-offload-e88.sh"
    cat > "$script" <<EOF_E88_OFFLOAD
#!/usr/bin/env bash
set -e
if command -v ethtool >/dev/null 2>&1; then
    ethtool -K "$iface" gro on gso on tso on lro off rx-gro-hw on tx-udp-segmentation on 2>/dev/null || true
    ethtool -C "$iface" adaptive-rx on 2>/dev/null || true
fi
EOF_E88_OFFLOAD
    chmod +x "$script" 2>/dev/null || true
    cat > /etc/systemd/system/xray-offload-e88.service <<EOF_E88_OFFLOAD_SERVICE
[Unit]
Description=Xray e88 NIC offload restore
After=network-online.target
Wants=network-online.target

[Service]
Type=oneshot
ExecStart=$script
RemainAfterExit=yes

[Install]
WantedBy=multi-user.target
EOF_E88_OFFLOAD_SERVICE
    systemctl daemon-reload >/dev/null 2>&1 || true
    systemctl enable --now xray-offload-e88.service >/dev/null 2>&1 || true
    info "GRO/GSO/TSO 已保持 ON，LRO 已保持 OFF，并创建开机恢复服务。"
    _e88_show_core_network_state
}

_e88_apply_mss_clamp() {
    local script
    if declare -F _apply_mss_chain_e52 >/dev/null 2>&1; then _apply_mss_chain_e52 || true; fi
    script="/usr/local/bin/xray-mss-clamp-e88.sh"
    cat > "$script" <<'EOF_E88_MSS_SCRIPT'
#!/usr/bin/env bash
set -e
modprobe iptable_mangle >/dev/null 2>&1 || true
modprobe xt_TCPMSS >/dev/null 2>&1 || true
iptables -t mangle -N XRAY_MSS_CLAMP 2>/dev/null || true
iptables -t mangle -F XRAY_MSS_CLAMP 2>/dev/null || true
iptables -t mangle -A XRAY_MSS_CLAMP -p tcp -m tcp --tcp-flags SYN,RST SYN -j TCPMSS --clamp-mss-to-pmtu 2>/dev/null || true
iptables -t mangle -C POSTROUTING -j XRAY_MSS_CLAMP 2>/dev/null || iptables -t mangle -A POSTROUTING -j XRAY_MSS_CLAMP 2>/dev/null || true
EOF_E88_MSS_SCRIPT
    chmod +x "$script" 2>/dev/null || true
    cat > /etc/systemd/system/xray-mss-clamp-e88.service <<EOF_E88_MSS_SERVICE
[Unit]
Description=Xray e88 MSS clamp restore
After=network-online.target
Wants=network-online.target

[Service]
Type=oneshot
ExecStart=$script
RemainAfterExit=yes

[Install]
WantedBy=multi-user.target
EOF_E88_MSS_SERVICE
    systemctl daemon-reload >/dev/null 2>&1 || true
    systemctl enable --now xray-mss-clamp-e88.service >/dev/null 2>&1 || true
    info "MSS clamp 已应用并写入开机恢复服务。"
    iptables -t mangle -S XRAY_MSS_CLAMP 2>/dev/null | sed 's/^/    /' || true
}

_e88_apply_response_profile() {
    title "应用 e88 响应优先基线（不重构节点）"
    _e88_apply_fq_bbr_stable_core
    _e88_set_tcp_notsent_lowat 26214 "e88 响应优先基线"
    _e88_set_adv_app_profile 1 31 "e88 响应优先基线"
    _e88_set_txqueuelen 3000
    _e88_apply_offload_default
    _e88_apply_mss_clamp
    echo "response-26214" > "$CONFIG_DIR/network_profile_e88.txt" 2>/dev/null || true
}

_e88_apply_throughput_profile() {
    title "应用 e88 高吞吐基线（不重构节点）"
    if declare -F apply_default_full_sysctl_profile_e60 >/dev/null 2>&1; then
        apply_default_full_sysctl_profile_e60 || true
    elif declare -F write_full_network_optimized_conf_e60 >/dev/null 2>&1; then
        write_full_network_optimized_conf_e60 1 31 || true
    fi
    _e88_apply_fq_bbr_stable_core
    _e88_set_tcp_notsent_lowat 131072 "e88 高吞吐基线"
    _e88_set_adv_app_profile 1 31 "e88 高吞吐基线"
    _e88_set_txqueuelen 3000
    _e88_apply_offload_default
    _e88_apply_mss_clamp
    echo "throughput-131072" > "$CONFIG_DIR/network_profile_e88.txt" 2>/dev/null || true
}

# 覆盖 13) 网络参数菜单：保留 e82 notsent 管理，并新增安全网络栈参数管理。
do_network_params_menu_e56() {
    while true; do
        clear
        title "网络参数应用中心（V198e88：缓冲 / notsent / fq+BBR / adv_win / txqueue / offload / MSS）"
        if declare -F show_network_buffer_params_e56 >/dev/null 2>&1; then show_network_buffer_params_e56; fi
        _e88_show_tcp_notsent_lowat_state
        _e88_show_core_network_state
        if declare -F show_network_sysctl_conflicts_e58 >/dev/null 2>&1; then show_network_sysctl_conflicts_e58; fi
        _e88_show_notsent_conflicts
        echo ""
        echo "  1) 应用默认高吞吐档：7990577 / 97108868（并切 notsent=131072）"
