        echo "  10) 高级发烧：内核双轨编译(APT/源码)/网络/应用层 60余项极限全控板"
        echo -e "  ${cyan}11) 从旧 ex198e 环境稳态热更新到 V198e88${none}"
        echo -e "  ${cyan}12) 清理空间（安全释放 / 快照收敛 / 显示硬盘与 Swap）${none}"
        echo -e "  ${cyan}13) 应用网络参数（缓冲/notsent/fq+BBR/adv_win/txqueue/offload/MSS）${none}"
