#==============================================================================
# V198e88 FINAL OVERRIDE LAYER
# 目标：审查 V198e83 菜单 13，补齐五项网络参数的注释、默认值、一键默认、手动修改与热更新默认落地。
#   - tcp_adv_win_scale：默认 1，吞吐实验 2-3
#   - tcp_app_win：默认 31，允许 0~31
#   - txqueuelen：默认 3000
#   - GRO/GSO/TSO/LRO：默认 O/O/O/X
#   - MSS clamp：默认 ON
#==============================================================================

E88_NET_MANUAL_STATE_FILE="$CONFIG_DIR/network_manual_e88.txt"
E88_MSS_STATE_FILE="$CONFIG_DIR/mss_clamp_e88.txt"
E88_OFFLOAD_STATE_FILE="$CONFIG_DIR/offload_ooox_e88.txt"

_e88_install_self_entrypoint() {
    mkdir -p "$SCRIPT_DIR" "$CONFIG_DIR" 2>/dev/null || true
    if test -f "$SCRIPT_PATH"; then
        cp -f "$SCRIPT_PATH" "$SYMLINK" 2>/dev/null || true
        cp -f "$SCRIPT_PATH" "$SCRIPT_DIR/ex198e88.sh" 2>/dev/null || true
        cp -f "$SCRIPT_PATH" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
        chmod +x "$SYMLINK" "$SCRIPT_DIR/ex198e88.sh" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
        hash -r 2>/dev/null || true
    fi
    echo "198e88" > "$SCRIPT_VERSION_FILE" 2>/dev/null || true
    info "V198e88 已安装/刷新快捷入口：$SYMLINK"
}
# 兼容旧流程仍调用 e88/e77 安装入口的情况。
e88_install_self_entrypoint() { _e88_install_self_entrypoint "$@"; }
e77_install_self_entrypoint() { _e88_install_self_entrypoint "$@"; }

_e88_note_line() { printf "    %-28s %s\n" "$1" "$2"; }

_e88_show_menu13_manual_notes() {
    title "V198e88 菜单13：五项网络参数注释与默认值"
    local iface txq mss_state off_state
    iface=$(_e88_default_iface 2>/dev/null || true)
    if test -n "$iface"; then
        txq=$(ip -o link show "$iface" 2>/dev/null | sed -n 's/.*qlen \([0-9][0-9]*\).*/\1/p' | head -n1)
    fi
    mss_state=$(cat "$E88_MSS_STATE_FILE" 2>/dev/null || echo "unknown")
    off_state=$(cat "$E88_OFFLOAD_STATE_FILE" 2>/dev/null || echo "unknown")

    echo "  【默认策略】"
    _e88_note_line "tcp_adv_win_scale" "默认 1；吞吐实验 2-3；过大可能放大排队/内存压力。当前：$(_e88_sysctl_get net.ipv4.tcp_adv_win_scale)"
    _e88_note_line "tcp_app_win" "默认 31；允许 0~31；普通代理建议 31。当前：$(_e88_sysctl_get net.ipv4.tcp_app_win)"
    _e88_note_line "txqueuelen" "默认 3000；1000 偏低排队，3000 偏稳态吞吐。当前：${txq:-unknown}"
    _e88_note_line "GRO/GSO/TSO/LRO" "默认 OOOX，即 GRO=ON/GSO=ON/TSO=ON/LRO=OFF。记录：$off_state"
    _e88_note_line "MSS clamp" "默认 ON；用于降低 PMTU 黑洞/分片异常导致的卡顿。记录：$mss_state"
    echo ""
    echo "  【符号说明】"
    echo "    O = ON / 开启；X = OFF / 关闭。"
    echo "    OOOX = GRO ON、GSO ON、TSO ON、LRO OFF。"
    echo ""
    echo "  【建议】"
    echo "    日常翻墙：adv=1 / app=31 / txqueue=3000 / OOOX / MSS=ON。"
    echo "    高 RTT 吞吐测试：adv 可试 2 或 3，app 仍建议 31。"
}

_e88_set_tcp_adv_win_scale_manual() {
    local v cur
    cur=$(_e88_sysctl_get net.ipv4.tcp_adv_win_scale)
    echo ""
    warn "tcp_adv_win_scale：默认 1；吞吐实验 2-3；允许 -31~31，但强烈建议先测 1/2/3。"
    read -rp "请输入 tcp_adv_win_scale（默认 ${cur:-1}，直接回车用 1）: " v || true
    v=${v:-1}
    if ! [[ "$v" =~ ^-?[0-9]+$ ]] || test "$v" -lt -31 2>/dev/null || test "$v" -gt 31 2>/dev/null; then
        error "tcp_adv_win_scale 非法：$v；允许 -31~31。"
        return 1
    fi
    if test "$v" -gt 3 2>/dev/null || test "$v" -lt 0 2>/dev/null; then
        warn "你输入的是非常规值 $v；脚本允许写入，但建议先对比 1/2/3 的体感和测速。"
    fi
    _e88_set_sysctl_key net.ipv4.tcp_adv_win_scale "$v" "V198e88 手动：tcp_adv_win_scale，默认1，吞吐2-3"
    echo "tcp_adv_win_scale=$v" >> "$E88_NET_MANUAL_STATE_FILE" 2>/dev/null || true
}

_e88_set_tcp_app_win_manual() {
    local v cur
    cur=$(_e88_sysctl_get net.ipv4.tcp_app_win)
    echo ""
    warn "tcp_app_win：默认 31；允许 0~31；普通代理建议 31。"
    read -rp "请输入 tcp_app_win（默认 ${cur:-31}，直接回车用 31）: " v || true
    v=${v:-31}
    if ! [[ "$v" =~ ^[0-9]+$ ]] || test "$v" -lt 0 2>/dev/null || test "$v" -gt 31 2>/dev/null; then
        error "tcp_app_win 非法：$v；允许 0~31。"
        return 1
    fi
    if test "$v" -ne 31 2>/dev/null; then
        warn "非 31 属于实验值，可能改变应用保留窗口，普通翻墙不建议长期使用。"
    fi
    _e88_set_sysctl_key net.ipv4.tcp_app_win "$v" "V198e88 手动：tcp_app_win，默认31，范围0~31"
    echo "tcp_app_win=$v" >> "$E88_NET_MANUAL_STATE_FILE" 2>/dev/null || true
}

_e88_set_txqueuelen_manual() {
    local v iface
    iface=$(_e88_default_iface 2>/dev/null || true)
    echo ""
    warn "txqueuelen：默认 3000；1000 偏低排队，3000 偏稳态，高于 5000 可能增加排队延迟。"
    read -rp "请输入 txqueuelen（默认 3000）: " v || true
    v=${v:-3000}
    if ! [[ "$v" =~ ^[0-9]+$ ]] || test "$v" -lt 100 2>/dev/null || test "$v" -gt 20000 2>/dev/null; then
        error "txqueuelen 非法：$v；建议 100~20000，常用 1000/3000/5000。"
        return 1
    fi
    if test "$v" -gt 5000 2>/dev/null; then warn "txqueuelen=$v 偏大，可能增加 bufferbloat。"; fi
    _e88_set_txqueuelen "$v"
    echo "txqueuelen=$v" >> "$E88_NET_MANUAL_STATE_FILE" 2>/dev/null || true
}

_e88_apply_offload_profile() {
    local pattern="${1:-OOOX}" iface gro gso tso lro script
    pattern=$(printf '%s' "$pattern" | tr '[:lower:]' '[:upper:]' | tr -cd 'OX')
    if ! [[ "$pattern" =~ ^[OX]{4}$ ]]; then
        error "GRO/GSO/TSO/LRO 输入非法：$pattern；请用 4 位 O/X，例如 OOOX。"
        return 1
    fi
    iface=$(_e88_default_iface 2>/dev/null || true)
    if test -z "$iface"; then warn "未识别默认出口网卡。"; return 1; fi

    gro=${pattern:0:1}; gso=${pattern:1:1}; tso=${pattern:2:1}; lro=${pattern:3:1}
    gro=$([ "$gro" = "O" ] && echo on || echo off)
    gso=$([ "$gso" = "O" ] && echo on || echo off)
    tso=$([ "$tso" = "O" ] && echo on || echo off)
    lro=$([ "$lro" = "O" ] && echo on || echo off)

    title "应用 GRO/GSO/TSO/LRO = $pattern（O=ON，X=OFF）"
    if command -v ethtool >/dev/null 2>&1; then
        ethtool -K "$iface" gro "$gro" gso "$gso" tso "$tso" lro "$lro" 2>/dev/null || warn "部分 offload 项可能被虚拟网卡/云厂商锁定，已尽力应用。"
    else
        warn "缺少 ethtool，跳过运行态 offload 设置。"
    fi

    script="/usr/local/bin/xray-offload-e88.sh"
    cat > "$script" <<EOF_E88_OFFLOAD_SCRIPT
#!/usr/bin/env bash
set +e
export PATH="/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin"
IFACE="$iface"
command -v ethtool >/dev/null 2>&1 || exit 0
ethtool -K "\$IFACE" gro $gro gso $gso tso $tso lro $lro 2>/dev/null || true
exit 0
EOF_E88_OFFLOAD_SCRIPT
    chmod +x "$script" 2>/dev/null || true
    cat > /etc/systemd/system/xray-offload-e88.service <<EOF_E88_OFFLOAD_SERVICE
[Unit]
Description=Xray e88 GRO/GSO/TSO/LRO restore
After=network-online.target
Wants=network-online.target

[Service]
Type=oneshot
ExecStart=$script
RemainAfterExit=yes

[Install]
WantedBy=multi-user.target
EOF_E88_OFFLOAD_SERVICE
    systemctl daemon-reload >/dev/null 2>&1 || true
    systemctl enable --now xray-offload-e88.service >/dev/null 2>&1 || true
    echo "$pattern" > "$E88_OFFLOAD_STATE_FILE" 2>/dev/null || true
    info "已应用并持久化：GRO/GSO/TSO/LRO=$pattern（默认推荐 OOOX）。"
    _e88_show_core_network_state
}

_e88_manual_offload_profile() {
    local p
    echo ""
    warn "GRO/GSO/TSO/LRO 默认 OOOX：GRO ON、GSO ON、TSO ON、LRO OFF。"
    echo "  示例："
    echo "    OOOX = 推荐默认"
    echo "    XXXX = 全关闭，仅排障短测"
    echo "    OOX X 中间不要空格，必须 4 位 O/X"
    read -rp "请输入 4 位 O/X（默认 OOOX）: " p || true
    p=${p:-OOOX}
    _e88_apply_offload_profile "$p"
}

_e88_mss_clamp_off() {
    title "关闭 MSS clamp（移除 XRAY_MSS_CLAMP 链与 e88 恢复服务）"
    systemctl disable --now xray-mss-clamp-e88.service >/dev/null 2>&1 || true
    rm -f /etc/systemd/system/xray-mss-clamp-e88.service /usr/local/bin/xray-mss-clamp-e88.sh 2>/dev/null || true
    systemctl daemon-reload >/dev/null 2>&1 || true
    local IPT
    for IPT in iptables iptables-legacy iptables-nft; do
        command -v "$IPT" >/dev/null 2>&1 || continue
        while "$IPT" -t mangle -D POSTROUTING -j XRAY_MSS_CLAMP 2>/dev/null; do :; done
        "$IPT" -t mangle -F XRAY_MSS_CLAMP 2>/dev/null || true
        "$IPT" -t mangle -X XRAY_MSS_CLAMP 2>/dev/null || true
    done
    echo "OFF" > "$E88_MSS_STATE_FILE" 2>/dev/null || true
    info "MSS clamp 已关闭。默认推荐是 ON；仅在明确不需要 PMTU 防卡顿时关闭。"
}

_e88_mss_clamp_on() {
    # 复用 e88/e83 已有宽容实现，失败只警告。
    if declare -F _e88_apply_mss_clamp >/dev/null 2>&1; then
        _e88_apply_mss_clamp || true
    elif declare -F _apply_mss_chain_e52 >/dev/null 2>&1; then
        _apply_mss_chain_e52 || true
    fi
    echo "ON" > "$E88_MSS_STATE_FILE" 2>/dev/null || true
    info "MSS clamp 默认 ON 已记录。"
}

_e88_manual_mss_clamp() {
    local v
    echo ""
    warn "MSS clamp 默认 ON：用于减少 PMTU/分片异常导致的连接卡顿。"
    read -rp "设置 MSS clamp？1=ON(默认)，0=OFF: " v || true
    v=${v:-1}
    case "$v" in
        1|on|ON|On|o|O) _e88_mss_clamp_on ;;
        0|off|OFF|Off|x|X) _e88_mss_clamp_off ;;
        *) error "输入无效。"; return 1 ;;
    esac
}

_e88_apply_menu13_defaults() {
    title "应用 V198e88 菜单13默认五项：adv=1 / app=31 / txqueue=3000 / OOOX / MSS=ON"
    _e88_set_sysctl_key net.ipv4.tcp_adv_win_scale 1 "V198e88 默认：tcp_adv_win_scale=1，吞吐实验2-3"
    _e88_set_sysctl_key net.ipv4.tcp_app_win 31 "V198e88 默认：tcp_app_win=31，范围0~31"
    _e88_set_txqueuelen 3000 || true
    _e88_apply_offload_profile OOOX || true
    _e88_mss_clamp_on || true
    echo "e88-defaults" > "$CONFIG_DIR/network_profile_e88.txt" 2>/dev/null || true
    _e88_show_menu13_manual_notes
}

