#==============================================================================
# V198e88 FINAL OVERRIDE LAYER
# 目标：按用户指定策略，在 V198e85 基础上只增量加入：
#   1) RPS/RFS 增强和读回验证（热更新默认执行，单核自动跳过）
#   2) initcwnd/initrwnd 起步窗口：查看、恢复默认、12、20、32、手动
#   3) IPv4/IPv6 出口检测 + gai.conf 优先级只读查看
# 保持不动：
#   - 动态缓冲区计算不加入
#   - BBR3/XanMod 状态审计不加入
#   - nf_conntrack/Realm 转发专项不加入
#   - Speedtest/网络诊断工具不加入
#   - tcp_fastopen 保持 0
#   - DNS 净化不加入
#   - 不禁用 IPv6
#   - 不加入 Snell
#   - 不照搬 FORWARD 链 MSS clamp
#==============================================================================

E88_RPS_STATE_FILE="$CONFIG_DIR/rps_rfs_e88.txt"

_e88_cpu_mask_all_safe() {
    local cores="${1:-$(nproc 2>/dev/null || echo 1)}"
    if ! [[ "$cores" =~ ^[0-9]+$ ]] || test "$cores" -lt 1 2>/dev/null; then cores=1; fi
    if declare -F cpu_mask_all >/dev/null 2>&1; then
        cpu_mask_all "$cores" 2>/dev/null | tr 'A-F' 'a-f' || echo "1"
        return 0
    fi
    python3 - "$cores" <<'PY' 2>/dev/null || awk -v n="$cores" 'BEGIN{ if(n<=1) print "1"; else if(n>=31) print "ffffffff"; else printf "%x\n", (2^n)-1 }'
import sys
n=int(sys.argv[1])
print(format((1 << n) - 1, 'x'))
PY
}

_e88_norm_hex_mask() {
    local v="${1:-0}"
    v=$(printf '%s' "$v" | tr -d ',[:space:]' | tr 'A-F' 'a-f')
    v=$(printf '%s' "$v" | sed 's/^0*//')
    test -n "$v" || v="0"
    echo "$v"
}

_e88_is_physical_netdev() {
    local dev="${1:-}"
    test -n "$dev" || return 1
    case "$dev" in
        lo|docker*|veth*|br-*|virbr*|zt*|tailscale*|wg*|tun*|tap*|cni*|flannel*|calico*|kube*|podman*|vnet*|vmnet*)
            return 1 ;;
    esac
    test -d "/sys/class/net/$dev/queues"
}

_e88_apply_rps_rfs() {
    title "V198e88：应用 RPS/RFS 多核收包优化 + 读回验证"
    local cpu_count mask flow_entries per_queue rps_ok=0 touched=0 dev d rxq rxq_dir verify_val devs=""
    cpu_count=$(nproc 2>/dev/null || echo 1)
    if ! [[ "$cpu_count" =~ ^[0-9]+$ ]]; then cpu_count=1; fi
    if test "$cpu_count" -le 1 2>/dev/null; then
        warn "当前为单核 CPU，RPS/RFS 无需分担，已跳过。"
        echo "single-core-skip $(date '+%F %T')" > "$E88_RPS_STATE_FILE" 2>/dev/null || true
        return 0
    fi

    mask=$(_e88_cpu_mask_all_safe "$cpu_count")
    mask=$(_e88_norm_hex_mask "$mask")
    flow_entries=$((4096 * cpu_count))
    test "$flow_entries" -lt 4096 2>/dev/null && flow_entries=4096
    per_queue=$((flow_entries / cpu_count))
    test "$per_queue" -lt 1024 2>/dev/null && per_queue=1024

    echo "$flow_entries" > /proc/sys/net/core/rps_sock_flow_entries 2>/dev/null || true

    for d in /sys/class/net/*; do
        test -e "$d" || continue
        dev=$(basename "$d")
        _e88_is_physical_netdev "$dev" || continue
        for rxq in /sys/class/net/$dev/queues/rx-*/rps_cpus; do
            test -f "$rxq" || continue
            touched=$((touched + 1))
            echo "$mask" > "$rxq" 2>/dev/null || true
            verify_val=$(_e88_norm_hex_mask "$(cat "$rxq" 2>/dev/null || echo 0)")
            if test "$verify_val" = "$mask"; then rps_ok=1; fi
        done
        for rxq_dir in /sys/class/net/$dev/queues/rx-*/; do
            test -d "$rxq_dir" || continue
            if test -f "${rxq_dir}rps_flow_cnt"; then
                echo "$per_queue" > "${rxq_dir}rps_flow_cnt" 2>/dev/null || true
            fi
        done
        devs="${devs} ${dev}"
    done

    cat > /usr/local/bin/xray-rps-rfs-e88.sh <<EOF_E88_RPS_SCRIPT
#!/usr/bin/env bash
set +e
export PATH="/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin"
CPU_COUNT=\$(nproc 2>/dev/null || echo 1)
if ! [[ "\$CPU_COUNT" =~ ^[0-9]+$ ]] || [ "\$CPU_COUNT" -le 1 ]; then exit 0; fi
MASK="$mask"
FLOW_ENTRIES="$flow_entries"
PER_QUEUE="$per_queue"
echo "\$FLOW_ENTRIES" > /proc/sys/net/core/rps_sock_flow_entries 2>/dev/null || true
for d in /sys/class/net/*; do
    [ -e "\$d" ] || continue
    dev=\$(basename "\$d")
    case "\$dev" in
        lo|docker*|veth*|br-*|virbr*|zt*|tailscale*|wg*|tun*|tap*|cni*|flannel*|calico*|kube*|podman*|vnet*|vmnet*) continue ;;
    esac
    [ -d "/sys/class/net/\$dev/queues" ] || continue
    for rxq in /sys/class/net/\$dev/queues/rx-*/rps_cpus; do
        [ -f "\$rxq" ] && echo "\$MASK" > "\$rxq" 2>/dev/null || true
    done
    for rxq_dir in /sys/class/net/\$dev/queues/rx-*/; do
        [ -f "\${rxq_dir}rps_flow_cnt" ] && echo "\$PER_QUEUE" > "\${rxq_dir}rps_flow_cnt" 2>/dev/null || true
    done
done
exit 0
EOF_E88_RPS_SCRIPT
    chmod +x /usr/local/bin/xray-rps-rfs-e88.sh 2>/dev/null || true

    cat > /etc/systemd/system/xray-rps-rfs-e88.service <<'EOF_E88_RPS_SERVICE'
[Unit]
Description=Xray e88 RPS/RFS restore after boot
After=network-online.target
Wants=network-online.target

[Service]
Type=oneshot
ExecStart=/usr/local/bin/xray-rps-rfs-e88.sh
RemainAfterExit=yes

[Install]
WantedBy=multi-user.target
EOF_E88_RPS_SERVICE
    systemctl daemon-reload >/dev/null 2>&1 || true
    systemctl enable --now xray-rps-rfs-e88.service >/dev/null 2>&1 || true

    {
        echo "time=$(date '+%F %T')"
        echo "cpu_count=$cpu_count"
        echo "mask=0x$mask"
        echo "flow_entries=$flow_entries"
        echo "per_rxq_flow_cnt=$per_queue"
        echo "devices=${devs:-none}"
        echo "rps_touched=$touched"
        echo "rps_verified=$rps_ok"
    } > "$E88_RPS_STATE_FILE" 2>/dev/null || true

    if test "$touched" -eq 0 2>/dev/null; then
        warn "未找到可写 rx 队列，当前虚拟化网卡可能不暴露 RPS/RFS。"
    elif test "$rps_ok" -eq 1 2>/dev/null; then
        info "RPS/RFS 已启用并读回验证成功：CPU=${cpu_count}，mask=0x${mask}，flow_entries=${flow_entries}，网卡:${devs:-unknown}"
    else
        warn "RPS 写入已尝试，但读回未完全匹配；可能被云厂商/内核限制。"
    fi
}

_e88_show_rps_rfs_state() {
    title "V198e88：RPS/RFS 当前状态"
    local cpu_count mask flow_entries dev d rxq rxq_dir
    cpu_count=$(nproc 2>/dev/null || echo 1)
    mask=$(_e88_cpu_mask_all_safe "$cpu_count")
    flow_entries=$(cat /proc/sys/net/core/rps_sock_flow_entries 2>/dev/null || echo "unknown")
    echo "  CPU 核心数: $cpu_count"
    echo "  推荐 RPS 掩码: 0x$mask"
    echo "  net.core.rps_sock_flow_entries: $flow_entries"
    echo "  e88 记录文件: $E88_RPS_STATE_FILE"
    if test -f "$E88_RPS_STATE_FILE"; then sed 's/^/    /' "$E88_RPS_STATE_FILE"; fi
    echo ""
    echo "  网卡队列读回："
    for d in /sys/class/net/*; do
        test -e "$d" || continue
        dev=$(basename "$d")
        _e88_is_physical_netdev "$dev" || continue
        echo "    [$dev]"
        for rxq in /sys/class/net/$dev/queues/rx-*/rps_cpus; do
            test -f "$rxq" || continue
            echo "      $(basename "$(dirname "$rxq")")/rps_cpus=$(cat "$rxq" 2>/dev/null || echo '?')"
        done
        for rxq_dir in /sys/class/net/$dev/queues/rx-*/; do
            test -f "${rxq_dir}rps_flow_cnt" || continue
            echo "      $(basename "$rxq_dir")/rps_flow_cnt=$(cat "${rxq_dir}rps_flow_cnt" 2>/dev/null || echo '?')"
        done
    done
}

_e88_default_route_clean() {
    local route
    route=$(ip route show default 2>/dev/null | head -n1 || true)
    test -n "$route" || return 1
    echo "$route" | sed 's/[[:space:]]\+initcwnd[[:space:]]\+[0-9]\+//g; s/[[:space:]]\+initrwnd[[:space:]]\+[0-9]\+//g'
}

_e88_show_init_window_state() {
    title "V198e88：TCP 起步窗口 initcwnd / initrwnd 当前状态"
    local route cw rw
    route=$(ip route show default 2>/dev/null | head -n1 || true)
    if test -z "$route"; then warn "未检测到默认路由。"; return 0; fi
    cw=$(echo "$route" | sed -n 's/.*[[:space:]]initcwnd[[:space:]]\+\([0-9]\+\).*/\1/p')
    rw=$(echo "$route" | sed -n 's/.*[[:space:]]initrwnd[[:space:]]\+\([0-9]\+\).*/\1/p')
    echo "  默认路由："
    echo "    $route"
    echo ""
    echo "  当前 initcwnd: ${cw:-系统默认/未显式设置}"
    echo "  当前 initrwnd: ${rw:-系统默认/未显式设置}"
    echo ""
    echo "  可选档位："
    echo "    默认：移除路由上的 initcwnd/initrwnd，由内核按默认策略处理"
    echo "    12：轻微加速起步，风险低"
    echo "    20：中等起步窗口，适合高 RTT 测试"
    echo "    32：激进起步窗口，可能提高短连接启动速度，也可能增加突发排队"
    echo "    手动：自定义 2~100，建议谨慎"
}

_e88_set_init_window() {
    local cw="${1:-}" rw="${2:-$1}" clean
    if ! [[ "$cw" =~ ^[0-9]+$ ]] || ! [[ "$rw" =~ ^[0-9]+$ ]]; then
        error "initcwnd/initrwnd 必须为数字。"
        return 1
    fi
    if test "$cw" -lt 2 2>/dev/null || test "$cw" -gt 100 2>/dev/null || test "$rw" -lt 2 2>/dev/null || test "$rw" -gt 100 2>/dev/null; then
        error "initcwnd/initrwnd 建议范围 2~100。"
        return 1
    fi
    clean=$(_e88_default_route_clean 2>/dev/null || true)
    if test -z "$clean"; then warn "未检测到默认路由，无法设置。"; return 1; fi
    if ip route change $clean initcwnd "$cw" initrwnd "$rw" 2>/dev/null; then
        info "已设置默认路由 initcwnd=$cw initrwnd=$rw。"
        _e88_show_init_window_state
    else
        warn "设置失败。可能是路由项或云厂商网络限制；不影响其它优化。"
        return 1
    fi
}

_e88_reset_init_window_default() {
    local clean
    title "V198e88：恢复 initcwnd/initrwnd 为系统默认"
    clean=$(_e88_default_route_clean 2>/dev/null || true)
    if test -z "$clean"; then warn "未检测到默认路由，无法恢复。"; return 1; fi
    if ip route change $clean 2>/dev/null; then
        info "已移除默认路由上的 initcwnd/initrwnd 显式设置，恢复系统默认。"
        _e88_show_init_window_state
    else
        warn "恢复失败。可能是当前默认路由不支持 route change。"
        return 1
    fi
}

_e88_manual_init_window() {
    local cw rw
    _e88_show_init_window_state
    echo ""
    read -rp "请输入 initcwnd（建议 12/20/32，默认 20）: " cw || true
    cw=${cw:-20}
    read -rp "请输入 initrwnd（默认与 initcwnd 相同：$cw）: " rw || true
    rw=${rw:-$cw}
    _e88_set_init_window "$cw" "$rw"
}

_e88_show_ip_gai_state() {
    title "V198e88：IPv4/IPv6 出口检测 + gai.conf 优先级查看（只读，不禁用 IPv6）"
    echo "  出口检测："
    printf "    IPv4: "
    curl -4 -s --connect-timeout 4 https://api.ipify.org 2>/dev/null || curl -4 -s --connect-timeout 4 https://ip.sb 2>/dev/null || echo "不可达/未配置"
    echo ""
    printf "    IPv6: "
    curl -6 -s --connect-timeout 4 https://api64.ipify.org 2>/dev/null || curl -6 -s --connect-timeout 4 https://ip.sb 2>/dev/null || echo "不可达/未配置"
    echo ""
    echo ""
    echo "  gai.conf 状态："
    if test -f /etc/gai.conf; then
        echo "    /etc/gai.conf 存在；未注释 precedence/label 规则如下："
        grep -nE '^[[:space:]]*(precedence|label)[[:space:]]+' /etc/gai.conf 2>/dev/null | sed 's/^/      /' || echo "      未发现未注释 precedence/label。"
    else
        echo "    /etc/gai.conf 不存在，系统使用默认 getaddrinfo 优先级。"
    fi
    echo ""
    echo "  当前解析优先级测试："
    if command -v getent >/dev/null 2>&1; then
        getent ahosts api.ipify.org 2>/dev/null | head -n 8 | sed 's/^/    /' || true
    else
        echo "    getent 不存在，跳过。"
    fi
}

# 覆盖 13) 网络参数菜单：保留 V198e85 已有 1-32，新增 e88 的 33-41。
