hot_update_from_legacy() {
    title "V198e88：稳态热更新（保留 e85 主体 + RPS/RFS + initcwnd/IP查看菜单）"
    set +e
    trap - ERR

    mkdir -p "$CONFIG_DIR" "$SCRIPT_DIR" "$BACKUP_DIR" 2>/dev/null || true
    _e88_install_self_entrypoint || true
    local bdir
    if declare -F e76_state_snapshot >/dev/null 2>&1; then
        bdir=$(e76_state_snapshot "hotupdate_e88")
    else
        bdir="$BACKUP_DIR/hotupdate_e88_$(date +%Y%m%d_%H%M%S)"; mkdir -p "$bdir" 2>/dev/null || true
        cp -a "$CONFIG" "$bdir/config.json.bak" 2>/dev/null || true
        cp -a "$NETWORK_OPT_CONF" "$bdir/99-network-optimized.conf.bak" 2>/dev/null || true
    fi
    info "已创建热更新快照：$bdir"

    repair_dns_if_broken || true
    install_update_dat || true
    fix_xray_systemd_limits || true
    apply_hotupdate_fast_sysctl || true
    remove_xray_env_buffer || true

    # 按用户要求：保持 tcp_fastopen=0，不默认启用 TFO=3。
    _e88_set_sysctl_key net.ipv4.tcp_fastopen 0 "V198e88 热更新：保持 tcp_fastopen=0，不默认启用 TFO=3" || true

    # 保持 e85 已覆盖内容不动：notsent=26214 + 五项默认 + POSTROUTING MSS clamp。
    _e88_set_tcp_notsent_lowat 26214 "热更新默认极低排队响应值" || true
    _e88_apply_menu13_defaults || true

    # 新增：RPS/RFS 增强和读回验证。单核/不支持时自动跳过，不作为致命失败。
    _e88_apply_rps_rfs || true

    if declare -F e76_config_semantic_ok >/dev/null 2>&1 && e76_config_semantic_ok "$CONFIG"; then
        force_apply_xray_core_defaults_e52 >/dev/null 2>&1 || true
        harden_xray_reality_profile >/dev/null 2>&1 || true
        fix_permissions || true
        systemctl daemon-reload >/dev/null 2>&1 || true
        if systemctl restart xray >/dev/null 2>&1; then
            info "Xray 已基于有效现网配置重启。"
        else
            warn "Xray 重启失败；可执行：journalctl -u xray --no-pager -n 80"
        fi
    else
        warn "未发现有效现网节点配置。V198e88 已安装为 xrv；请执行 xrv → 1 重新搭建。"
    fi

    echo "198e88" > "$SCRIPT_VERSION_FILE" 2>/dev/null || true
    _e88_show_tcp_notsent_lowat_state || true
    _e88_show_menu13_manual_notes || true
    _e88_show_core_network_state || true
    _e88_show_rps_rfs_state || true
    _e88_show_init_window_state || true
    _e88_show_ip_gai_state || true
    if declare -F e77_audit_runtime_state >/dev/null 2>&1; then e77_audit_runtime_state || true; fi
    set -e
    trap '_err_handler $? $LINENO "$BASH_COMMAND"' ERR
    info "V198e88 热更新完成。现在可输入：xrv → 13；新增 33-41：RPS/RFS、initcwnd/initrwnd、IPv4/IPv6/gai.conf 查看。"
    return 0
}

#==============================================================================
# V198e88 FINAL OVERRIDE LAYER
# 目标：审计 V198e86 后做保守热更新：
#   1) 保持菜单13原有 1-35 不动，更新 36-42 起步窗口与 IPv4/IPv6 检测项。
#   2) initcwnd/initrwnd 新档位：默认恢复/18/22/自动16-32/手动。
#   3) 自动检测不跑 speedtest，不禁 IPv6，不加入 BBR3/XanMod/Snell/Realm/DNS净化/FORWARD MSS。
#   4) 热更新仍保持 e85/e86 稳态：notsent=26214、五项默认、RPS/RFS、TFO=0、POSTROUTING MSS。
#==============================================================================

E88_INIT_WINDOW_STATE_FILE="$CONFIG_DIR/init_window_e88.txt"

_e88_init_window_note() {
    mkdir -p "$CONFIG_DIR" 2>/dev/null || true
    {
        echo "time=$(date '+%F %T')"
        echo "mode=${1:-unknown}"
        echo "initcwnd=${2:-unset}"
        echo "initrwnd=${3:-unset}"
        echo "note=${4:-}"
        echo "route=$(ip route show default 2>/dev/null | head -n1 || true)"
    } > "$E88_INIT_WINDOW_STATE_FILE" 2>/dev/null || true
}

_e88_default_route_clean() {
    local route
    route=$(ip route show default 2>/dev/null | head -n1 || true)
    test -n "$route" || return 1
    printf '%s\n' "$route" | sed 's/[[:space:]]\+initcwnd[[:space:]]\+[0-9]\+//g; s/[[:space:]]\+initrwnd[[:space:]]\+[0-9]\+//g'
}

_e88_show_init_window_state() {
    title "V198e88：TCP 起步窗口 initcwnd / initrwnd 当前状态"
    local route cw rw persisted
    route=$(ip route show default 2>/dev/null | head -n1 || true)
    if test -z "$route"; then warn "未检测到默认路由。"; return 0; fi
    cw=$(printf '%s\n' "$route" | sed -n 's/.*[[:space:]]initcwnd[[:space:]]\+\([0-9]\+\).*/\1/p')
    rw=$(printf '%s\n' "$route" | sed -n 's/.*[[:space:]]initrwnd[[:space:]]\+\([0-9]\+\).*/\1/p')
    persisted=$(cat "$CONFIG_DIR/initcwnd.txt" 2>/dev/null || true)
    echo "  默认路由："
    echo "    $route"
    echo ""
    echo "  当前 initcwnd: ${cw:-系统默认/未显式设置}"
    echo "  当前 initrwnd: ${rw:-系统默认/未显式设置}"
    echo "  持久化记录: ${persisted:-未记录}"
    echo "  e88 记录文件: $E88_INIT_WINDOW_STATE_FILE"
    if test -f "$E88_INIT_WINDOW_STATE_FILE"; then sed 's/^/    /' "$E88_INIT_WINDOW_STATE_FILE"; fi
    echo ""
    echo "  e88 档位说明："
    echo "    36：恢复默认20说明项；实际动作是移除默认路由显式 initcwnd/initrwnd，并删除持久化记录。"
    echo "    37：18，稳态偏快，适合日常网页/轻中度高 RTT。"
    echo "    38：22，高 RTT 响应实验，比 20 略激进。"
    echo "    39：32，激进起步窗口，适合测速/短连接爆发实验。"
    echo "    40：自动检测，按 RTT/重传/丢包在 16~32 间跳跃选择。"
    echo "    41：手动输入，范围 2~100，建议日常不要超过 32。"
}

_e88_install_init_window_boot_restore() {
    local cw="${1:-}" rw="${2:-$1}"
    test -n "$cw" || return 0
    mkdir -p "$SCRIPT_DIR" "$CONFIG_DIR" 2>/dev/null || true
    cat > /usr/local/bin/xray-init-window-e88.sh <<'EOF_E88_INIT_BOOT'
#!/usr/bin/env bash
set +e
export PATH="/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin"
CONFIG_DIR="/usr/local/etc/xray"
CWND_VAL=$(cat "$CONFIG_DIR/initcwnd.txt" 2>/dev/null | tr -cd '0-9' || true)
RWND_VAL=$(cat "$CONFIG_DIR/initrwnd.txt" 2>/dev/null | tr -cd '0-9' || true)
[ -n "$CWND_VAL" ] || exit 0
[ -n "$RWND_VAL" ] || RWND_VAL="$CWND_VAL"
DEF_ROUTE=$(ip route show default 2>/dev/null | head -n 1 || true)
[ -n "$DEF_ROUTE" ] || exit 0
CLEAN_ROUTE=$(printf '%s\n' "$DEF_ROUTE" | sed 's/[[:space:]]\+initcwnd[[:space:]]\+[0-9]\+//g; s/[[:space:]]\+initrwnd[[:space:]]\+[0-9]\+//g')
ip route change $CLEAN_ROUTE initcwnd "$CWND_VAL" initrwnd "$RWND_VAL" 2>/dev/null || true
exit 0
EOF_E88_INIT_BOOT
    chmod +x /usr/local/bin/xray-init-window-e88.sh 2>/dev/null || true
    cat > /etc/systemd/system/xray-init-window-e88.service <<'EOF_E88_INIT_SERVICE'
[Unit]
Description=Xray e88 TCP initcwnd/initrwnd restore after boot
After=network-online.target
Wants=network-online.target
Before=xray.service

[Service]
Type=oneshot
ExecStart=/usr/local/bin/xray-init-window-e88.sh
RemainAfterExit=yes

[Install]
WantedBy=multi-user.target
EOF_E88_INIT_SERVICE
    systemctl daemon-reload >/dev/null 2>&1 || true
    systemctl enable xray-init-window-e88.service >/dev/null 2>&1 || true
    systemctl restart xray-init-window-e88.service >/dev/null 2>&1 || true
    if declare -F update_hw_boot_script >/dev/null 2>&1; then update_hw_boot_script >/dev/null 2>&1 || true; fi
}

_e88_set_init_window() {
    local cw="${1:-}" rw="${2:-$1}" mode="${3:-manual}" clean
    if ! [[ "$cw" =~ ^[0-9]+$ ]] || ! [[ "$rw" =~ ^[0-9]+$ ]]; then
        error "initcwnd/initrwnd 必须为数字。"
        return 1
    fi
    if test "$cw" -lt 2 2>/dev/null || test "$cw" -gt 100 2>/dev/null || test "$rw" -lt 2 2>/dev/null || test "$rw" -gt 100 2>/dev/null; then
        error "initcwnd/initrwnd 建议范围 2~100。"
        return 1
    fi
    clean=$(_e88_default_route_clean 2>/dev/null || true)
    if test -z "$clean"; then warn "未检测到默认路由，无法设置。"; return 1; fi
    if ip route change $clean initcwnd "$cw" initrwnd "$rw" 2>/dev/null; then
        mkdir -p "$CONFIG_DIR" 2>/dev/null || true
        echo "$cw" > "$CONFIG_DIR/initcwnd.txt" 2>/dev/null || true
        echo "$rw" > "$CONFIG_DIR/initrwnd.txt" 2>/dev/null || true
        _e88_install_init_window_boot_restore "$cw" "$rw" || true
        _e88_init_window_note "$mode" "$cw" "$rw" "已设置默认路由并写入持久化记录。"
        info "已设置默认路由 initcwnd=$cw initrwnd=$rw，并写入开机恢复。"
        _e88_show_init_window_state
    else
        warn "设置失败。可能是路由项或云厂商网络限制；不影响其它优化。"
        return 1
    fi
}

_e88_reset_init_window_default20() {
    local clean
    title "V198e88：恢复 initcwnd/initrwnd 默认20（移除默认路由显式值）"
    clean=$(_e88_default_route_clean 2>/dev/null || true)
    if test -z "$clean"; then warn "未检测到默认路由，无法恢复。"; return 1; fi
    if ip route change $clean 2>/dev/null; then
        rm -f "$CONFIG_DIR/initcwnd.txt" "$CONFIG_DIR/initrwnd.txt" 2>/dev/null || true
        systemctl disable --now xray-init-window-e88.service >/dev/null 2>&1 || true
        rm -f /etc/systemd/system/xray-init-window-e88.service /usr/local/bin/xray-init-window-e88.sh 2>/dev/null || true
        systemctl daemon-reload >/dev/null 2>&1 || true
        if declare -F update_hw_boot_script >/dev/null 2>&1; then update_hw_boot_script >/dev/null 2>&1 || true; fi
        _e88_init_window_note "reset-default20" "unset" "unset" "按菜单说明恢复默认20：实际已移除默认路由显式 initcwnd/initrwnd，并删除持久化记录。"
        info "已移除默认路由上的 initcwnd/initrwnd 显式设置；系统将使用内核默认策略。e88 推荐默认参考值为 20。"
        _e88_show_init_window_state
    else
        warn "恢复失败。可能是当前默认路由不支持 route change。"
        return 1
    fi
}

_e88_manual_init_window() {
    local cw rw
    _e88_show_init_window_state
    echo ""
    read -rp "请输入 initcwnd（建议 18/22，默认 20）: " cw || true
    cw=${cw:-20}
    read -rp "请输入 initrwnd（默认与 initcwnd 相同：$cw）: " rw || true
    rw=${rw:-$cw}
    _e88_set_init_window "$cw" "$rw" "manual"
}

_e88_ss_rtt_avg_ms() {
    ss -ti 2>/dev/null | awk '
    {
      for (i=1;i<=NF;i++) {
        if ($i ~ /^rtt:/) {
          v=$i; sub(/^rtt:/,"",v); split(v,a,"/");
          if (a[1] ~ /^[0-9.]+$/) { total+=a[1]; count++ }
        }
      }
    }
    END { if (count>0) printf "%d\n", total/count }'
}

_e88_ping_rtt_avg_ms() {
    local host out avg
    for host in 1.1.1.1 8.8.8.8; do
        if command -v ping >/dev/null 2>&1; then
            out=$(LC_ALL=C ping -c 4 -W 1 "$host" 2>/dev/null || true)
            avg=$(printf '%s\n' "$out" | awk -F'/' '/min\/avg\/max|round-trip/ {print int($5); exit}')
            if [[ "$avg" =~ ^[0-9]+$ ]] && test "$avg" -gt 0 2>/dev/null; then echo "$avg"; return 0; fi
        fi
    done
    return 1
}

_e88_ss_retrans_count() {
    ss -ti 2>/dev/null | grep -oE 'retrans:[0-9]+/[0-9]+' | awk -F'[/:]' '{s+=$3} END{print s+0}' 2>/dev/null || echo 0
}

_e88_ping_loss_percent() {
    local host out loss
    for host in 1.1.1.1 8.8.8.8; do
        if command -v ping >/dev/null 2>&1; then
            out=$(LC_ALL=C ping -c 4 -W 1 "$host" 2>/dev/null || true)
            loss=$(printf '%s\n' "$out" | awk -F',' '/packet loss/ {gsub(/[^0-9.]/,"",$3); print int($3); exit}')
            if [[ "$loss" =~ ^[0-9]+$ ]]; then echo "$loss"; return 0; fi
        fi
    done
    echo "unknown"
}

_e88_auto_init_window_16_32() {
    title "V198e88：initcwnd/initrwnd 16~32 自动检测、自动跳跃"
    local rtt source retrans loss cw reason
    rtt=$(_e88_ss_rtt_avg_ms 2>/dev/null || true)
    source="ss -ti 活跃连接 RTT"
    if ! [[ "$rtt" =~ ^[0-9]+$ ]] || test "$rtt" -le 0 2>/dev/null; then
        rtt=$(_e88_ping_rtt_avg_ms 2>/dev/null || true)
        source="ping 1.1.1.1/8.8.8.8 平均 RTT"
    fi
    retrans=$(_e88_ss_retrans_count 2>/dev/null || echo 0)
    loss=$(_e88_ping_loss_percent 2>/dev/null || echo unknown)

    if ! [[ "$rtt" =~ ^[0-9]+$ ]] || test "$rtt" -le 0 2>/dev/null; then
        cw=20
        reason="未取得可靠 RTT，回落到 e88 推荐默认 20。"
    elif test "$rtt" -lt 80 2>/dev/null; then
        cw=16; reason="RTT<80ms，低延迟线路，选择 16，减少起步突发。"
    elif test "$rtt" -lt 150 2>/dev/null; then
        cw=18; reason="RTT 80~149ms，选择 18，稳态偏快。"
    elif test "$rtt" -lt 240 2>/dev/null; then
        cw=22; reason="RTT 150~239ms，选择 22，提升高 RTT 起步。"
    elif test "$rtt" -lt 330 2>/dev/null; then
        cw=26; reason="RTT 240~329ms，跳到 26，增强慢启动前几轮。"
    elif test "$rtt" -lt 430 2>/dev/null; then
        cw=28; reason="RTT 330~429ms，跳到 28。"
    else
        cw=32; reason="RTT>=430ms，跳到 32 激进起步。"
    fi

    if [[ "$retrans" =~ ^[0-9]+$ ]] && test "$retrans" -gt 0 2>/dev/null && test "$cw" -gt 22 2>/dev/null; then
        reason="$reason 检测到 TCP retrans=$retrans，自动封顶到 22，避免弱网起步过猛。"
        cw=22
    fi
    if [[ "$loss" =~ ^[0-9]+$ ]] && test "$loss" -ge 10 2>/dev/null && test "$cw" -gt 18 2>/dev/null; then
        reason="$reason ping 丢包约 ${loss}%，自动封顶到 18。"
        cw=18
    elif [[ "$loss" =~ ^[0-9]+$ ]] && test "$loss" -ge 3 2>/dev/null && test "$cw" -gt 22 2>/dev/null; then
        reason="$reason ping 丢包约 ${loss}%，自动封顶到 22。"
        cw=22
    fi

    echo "  检测来源: $source"
    echo "  RTT: ${rtt:-unknown} ms"
    echo "  ss retrans: ${retrans:-0}"
    echo "  ping loss: ${loss:-unknown}%"
    echo "  自动选择: initcwnd=$cw initrwnd=$cw"
    echo "  理由: $reason"
    echo ""
    _e88_set_init_window "$cw" "$cw" "auto16-32"
}

# 覆盖 13) 网络参数菜单：保留 V198e85/V198e86 已有 1-35，按用户要求更新 36-42。
do_network_params_menu_e56() {
