        echo "  7) 切换 tcp_notsent_lowat = 26214（极低排队/网页响应优先，永久应用）"
        echo "  8) 切换 tcp_notsent_lowat = 32768（低延迟响应档，永久应用）"
        echo "  9) 切换 tcp_notsent_lowat = 65536（均衡推荐档，永久应用）"
