    set -e
    trap '_err_handler $? $LINENO "$BASH_COMMAND"' ERR
    info "V198e88 热更新完成。现在可输入：xrv → 13；已更新 36-42：默认20恢复、18/22、16-32自动跳跃、手动、IPv4/IPv6只读检测。"
