_e88_show_init_window_state() {
    title "V198e88：TCP 起步窗口 initcwnd / initrwnd 当前状态"
    local route cw rw persisted_cw persisted_rw
    route=$(ip route show default 2>/dev/null | head -n1 || true)
    cw=$(printf '%s\n' "$route" | sed -n 's/.*[[:space:]]initcwnd[[:space:]]\+\([0-9]\+\).*/\1/p')
    rw=$(printf '%s\n' "$route" | sed -n 's/.*[[:space:]]initrwnd[[:space:]]\+\([0-9]\+\).*/\1/p')
    persisted_cw=$(cat "$CONFIG_DIR/initcwnd.txt" 2>/dev/null || true)
    persisted_rw=$(cat "$CONFIG_DIR/initrwnd.txt" 2>/dev/null || true)
    echo "  默认路由: ${route:-未发现}"
    echo "  当前 initcwnd: ${cw:-系统默认/未显式设置}"
    echo "  当前 initrwnd: ${rw:-系统默认/未显式设置}"
    echo "  持久化 initcwnd: ${persisted_cw:-未记录}"
    echo "  持久化 initrwnd: ${persisted_rw:-未记录}"
    echo ""
    echo "  e88 推荐默认：initcwnd/initrwnd = 21"
    echo "  18：稳态偏响应；26：高 RTT/高吞吐起步；32：激进实验；手动：2~100。"
}

_e88_reset_init_window_default21() {
    title "V198e88：恢复 initcwnd/initrwnd 默认21（移除默认路由显式值后重写）"
    local clean
    clean=$(_e88_default_route_clean 2>/dev/null || true)
    if test -z "$clean"; then
        warn "未发现默认路由，无法恢复 initcwnd/initrwnd。"
        return 1
    fi
    # 先移除旧的显式 initcwnd/initrwnd，再按 e88 默认 21 重新写入，避免旧值残留。
    ip route change $clean 2>/dev/null || true
    _e88_set_init_window 21 21 "default21"
}

_e88_manual_init_window() {
    title "V198e88：手动输入 initcwnd/initrwnd"
    _e88_show_init_window_state
    local cw rw
    read -rp "请输入 initcwnd（建议 18/21/26，默认 21）: " cw || true
    cw=${cw:-21}
    read -rp "请输入 initrwnd（默认与 initcwnd 相同：$cw）: " rw || true
    rw=${rw:-$cw}
    _e88_set_init_window "$cw" "$rw" "manual"
}

