#==============================================================================
# V198e89 FINAL OVERRIDE LAYER
# 目标：
#   1) 主菜单新增 BBR 本体替换 / 自定义编译中心。
#   2) 11 热更新写入 e89 代码提示、创建 BBRX 工作目录，不自动替换内核模块。
#   3) 支持自动检测 BBR v1 / BBR3-XanMod 倾向，支持备份原 tcp_bbr.ko 与系统 TCP 设置。
#   4) 支持普通 Linux 主线 BBR v1、BBR3/XanMod 两套“全部参数自定义”。
#   5) 模块型 CONFIG_TCP_CONG_BBR=m 才允许同名替换 bbr；内置型只提示改内核或新增算法，不强行覆盖。
#==============================================================================

readonly E89_BBRX_ROOT="/etc/bbrx" 2>/dev/null || E89_BBRX_ROOT="/etc/bbrx"
readonly E89_BBRX_CURRENT="/etc/bbrx/current" 2>/dev/null || E89_BBRX_CURRENT="/etc/bbrx/current"
readonly E89_BBRX_BACKUP_ROOT="/var/backups/bbrx" 2>/dev/null || E89_BBRX_BACKUP_ROOT="/var/backups/bbrx"
readonly E89_BBRX_BUILD_ROOT="/usr/local/src/bbrx-e89" 2>/dev/null || E89_BBRX_BUILD_ROOT="/usr/local/src/bbrx-e89"
readonly E89_BBRX_SYSCTL="/etc/sysctl.d/99-bbrx-replace.conf" 2>/dev/null || E89_BBRX_SYSCTL="/etc/sysctl.d/99-bbrx-replace.conf"
readonly E89_BBRX_MODULES_LOAD="/etc/modules-load.d/tcp_bbr.conf" 2>/dev/null || E89_BBRX_MODULES_LOAD="/etc/modules-load.d/tcp_bbr.conf"

_e89_bbr_pause() { if declare -F _e52_pause >/dev/null 2>&1; then _e52_pause; else local _p=""; read -rp "按 Enter 继续..." _p || true; fi; }

_e89_bbr_prepare_dirs() {
    mkdir -p "$E89_BBRX_ROOT" "$E89_BBRX_CURRENT" "$E89_BBRX_BACKUP_ROOT" "$E89_BBRX_BUILD_ROOT" 2>/dev/null || true
}

_e89_bbr_kconfig_value() {
    local krel cfg val
    krel="$(uname -r 2>/dev/null || true)"
    for cfg in "/boot/config-$krel" "/lib/modules/$krel/build/.config" "/proc/config.gz"; do
        if test "$cfg" = "/proc/config.gz" && test -f "$cfg"; then
            val=$(zcat "$cfg" 2>/dev/null | awk -F= '/^CONFIG_TCP_CONG_BBR=/{print $2; exit}' || true)
            test -n "$val" && { echo "$val"; return 0; }
        elif test -f "$cfg"; then
            val=$(awk -F= '/^CONFIG_TCP_CONG_BBR=/{print $2; exit}' "$cfg" 2>/dev/null || true)
            test -n "$val" && { echo "$val"; return 0; }
        fi
    done
    echo "unknown"
}

_e89_bbr_mod_path() { modinfo -n tcp_bbr 2>/dev/null || true; }

_e89_bbr_find_source() {
    local krel cand
    krel="$(uname -r 2>/dev/null || true)"
    if test -n "${BBR_SOURCE:-}" && test -f "${BBR_SOURCE:-}"; then echo "$BBR_SOURCE"; return 0; fi
    for cand in \
        "/lib/modules/$krel/build/net/ipv4/tcp_bbr.c" \
        "/usr/src/linux-headers-$krel/net/ipv4/tcp_bbr.c" \
        "/usr/src/linux-source-$krel/net/ipv4/tcp_bbr.c" \
        /usr/src/linux*/net/ipv4/tcp_bbr.c \
        /compile/linux*/net/ipv4/tcp_bbr.c \
        /root/linux*/net/ipv4/tcp_bbr.c; do
        if test -f "$cand"; then echo "$cand"; return 0; fi
    done
    return 1
}

_e89_bbr_source_kind() {
    local src="${1:-}"
    if test -n "$src" && test -f "$src"; then
        if grep -qE 'bbr_inflight_headroom|bbr_beta|bbr_probe_rtt_win_ms|bbr_bw_probe_max_rounds|BBR_VERSION[[:space:]]+3' "$src" 2>/dev/null; then
            echo "bbr3"
        else
            echo "bbrv1"
        fi
    else
        if uname -r 2>/dev/null | grep -qiE 'xanmod|bbr3'; then echo "bbr3"; else echo "unknown"; fi
    fi
}

_e89_bbr_recommend_kind() {
    local src kind
    src="$(_e89_bbr_find_source 2>/dev/null || true)"
    kind="$(_e89_bbr_source_kind "$src")"
    if test "$kind" = "unknown"; then
        if uname -r 2>/dev/null | grep -qiE 'xanmod|bbr3'; then kind="bbr3"; else kind="bbrv1"; fi
    fi
    echo "$kind"
}

_e89_bbr_detect() {
    title "V198e89：BBR 本体自动检测与编译建议"
    _e89_bbr_prepare_dirs
    local krel cfgv cc av modp src kind rec
    krel="$(uname -r 2>/dev/null || echo unknown)"
    cfgv="$(_e89_bbr_kconfig_value)"
    cc="$(sysctl -n net.ipv4.tcp_congestion_control 2>/dev/null || echo unknown)"
    av="$(sysctl -n net.ipv4.tcp_available_congestion_control 2>/dev/null || echo unknown)"
    modp="$(_e89_bbr_mod_path)"
    src="$(_e89_bbr_find_source 2>/dev/null || true)"
    kind="$(_e89_bbr_source_kind "$src")"
    rec="$(_e89_bbr_recommend_kind)"
    echo "  当前内核：$krel"
    echo "  CONFIG_TCP_CONG_BBR：$cfgv"
    echo "  当前拥塞控制：$cc"
    echo "  可用拥塞控制：$av"
    echo "  tcp_bbr 模块路径：${modp:-未发现/可能内置}"
    echo "  可用 tcp_bbr.c 源码：${src:-未发现}"
    echo "  源码类型判断：$kind"
    hr
    if test "$cfgv" = "m" && test -n "$modp" && test -f "$modp"; then
        print_green "  替换可行性：可执行同名替换 tcp_bbr.ko，新算法仍叫 bbr。"
    elif test "$cfgv" = "y"; then
        print_yellow "  替换可行性：当前 BBR 是内核内置，不能用 .ko 无损覆盖原 bbr。"
        print_yellow "  建议：重编整个内核，或新增 bbrx/bbrx3 算法名；本中心不会强行覆盖内置 BBR。"
    else
        print_yellow "  替换可行性：未能确认模块型 BBR。若 modinfo 无路径，不能执行同名替换。"
    fi
    if test "$rec" = "bbr3"; then
        echo -e "  ${cyan}推荐编译方案：2) BBR3 / XanMod → bbrx3_v1 参数模板${none}"
    else
        echo -e "  ${cyan}推荐编译方案：1) 普通 Linux 主线 BBR v1 → bbrx_v1 参数模板${none}"
    fi
}

_e89_bbr_backup_state() {
    _e89_bbr_prepare_dirs
    local ts bdir modp cfgv cc av
    ts="$(date +%Y%m%d_%H%M%S)"
    bdir="$E89_BBRX_BACKUP_ROOT/$ts"
    mkdir -p "$bdir" || return 1
    modp="$(_e89_bbr_mod_path)"
    cfgv="$(_e89_bbr_kconfig_value)"
    cc="$(sysctl -n net.ipv4.tcp_congestion_control 2>/dev/null || true)"
    av="$(sysctl -n net.ipv4.tcp_available_congestion_control 2>/dev/null || true)"
    {
        echo "BACKUP_TS=$ts"
        echo "KERNEL_RELEASE=$(uname -r 2>/dev/null || true)"
        echo "CONFIG_TCP_CONG_BBR=$cfgv"
        echo "ORIGINAL_CC=$cc"
        echo "AVAILABLE_CC=$av"
        echo "ORIGINAL_BBR_KO=$modp"
    } > "$bdir/meta.env"
    uname -a > "$bdir/uname.txt" 2>/dev/null || true
    sysctl -a 2>/dev/null | grep -E 'net\.ipv4\.tcp_|net\.core\.default_qdisc|net\.core\.[rw]mem|net\.core\.somaxconn' > "$bdir/sysctl_before.conf" 2>/dev/null || true
    sysctl net.ipv4.tcp_available_congestion_control > "$bdir/available_cc_before.txt" 2>/dev/null || true
    sysctl net.ipv4.tcp_congestion_control > "$bdir/selected_cc_before.txt" 2>/dev/null || true
    tc qdisc show > "$bdir/qdisc_before.txt" 2>/dev/null || true
    ip route show table main > "$bdir/route_before.txt" 2>/dev/null || true
    lsmod > "$bdir/modules_before.txt" 2>/dev/null || true
    modinfo tcp_bbr > "$bdir/modinfo_tcp_bbr_before.txt" 2>/dev/null || true
    if test -n "$modp" && test -f "$modp"; then
        cp -a "$modp" "$bdir/tcp_bbr.ko.orig" 2>/dev/null || true
        sha256sum "$modp" > "$bdir/tcp_bbr.ko.orig.sha256" 2>/dev/null || true
    fi
    local src
    src="$(_e89_bbr_find_source 2>/dev/null || true)"
    if test -n "$src" && test -f "$src"; then cp -a "$src" "$bdir/tcp_bbr.c.orig" 2>/dev/null || true; fi
    tar -czf "$bdir/sysctl_files_backup.tar.gz" /etc/sysctl.conf /etc/sysctl.d /etc/modules-load.d 2>/dev/null || true
    echo "$bdir"
}

