_e89_param_int() {
    local __var="$1" orig="$2" rec="$3" min="$4" max="$5" label="$6" desc="$7" val
    while true; do
        echo ""
        echo -e "${cyan}参数：${none}$label"
        echo "  原版：$orig"
        echo "  推荐：$rec"
        echo "  说明：$desc"
        read -rp "  请输入 [$min-$max]，回车=$rec，r=原版，q=退出: " val || true
        if [[ "$val" =~ ^[qQ]$ ]]; then return 1; fi
        if [[ "$val" =~ ^[rR]$ ]]; then val="$orig"; fi
        val="${val:-$rec}"
        val="${val%% *}"
        if [[ "$val" =~ ^[0-9]+$ ]] && test "$val" -ge "$min" 2>/dev/null && test "$val" -le "$max" 2>/dev/null; then
            printf -v "$__var" '%s' "$val"
            return 0
        fi
        error "输入非法：$val"
    done
}

_e89_param_bool() {
    local __var="$1" orig="$2" rec="$3" label="$4" desc="$5" val
    while true; do
        echo ""
        echo -e "${cyan}参数：${none}$label"
        echo "  原版：$orig"
        echo "  推荐：$rec"
        echo "  说明：$desc"
        read -rp "  请输入 1=true / 0=false，回车=$rec，r=原版，q=退出: " val || true
        if [[ "$val" =~ ^[qQ]$ ]]; then return 1; fi
        if [[ "$val" =~ ^[rR]$ ]]; then val="$orig"; fi
        val="${val:-$rec}"
        if test "$val" = "1" || test "$val" = "0"; then printf -v "$__var" '%s' "$val"; return 0; fi
        error "输入非法：$val"
    done
}

_e89_param_expr() {
    local __var="$1" orig="$2" rec="$3" label="$4" desc="$5" val
    echo ""
    echo -e "${cyan}参数：${none}$label"
    echo "  原版：$orig"
    echo "  推荐：$rec"
    echo "  说明：$desc"
    read -rp "  请输入 C 表达式，回车=$rec，r=原版，q=退出: " val || true
    if [[ "$val" =~ ^[qQ]$ ]]; then return 1; fi
    if [[ "$val" =~ ^[rR]$ ]]; then val="$orig"; fi
    val="${val:-$rec}"
    if ! echo "$val" | grep -Eq '^[A-Za-z0-9_[:space:]<</+*()-]+$'; then
        error "表达式含不安全字符，已拒绝。"
        return 1
    fi
    printf -v "$__var" '%s' "$val"
}

