_e89_collect_bbrv1_params() {
    local mode="${1:-recommended}"
    _e89_bbrv1_defaults
    if test "$mode" = "custom"; then
        _e89_show_bbrv1_table
        _e89_param_int BW_SCALE 24 24 20 28 "BW_SCALE" "带宽估算缩放位数；除非你知道内核定点数行为，否则保持 24。" || return 1
        _e89_param_int BBR_SCALE 8 8 6 10 "BBR_SCALE" "gain 缩放位数；保持 8 最稳。" || return 1
        _e89_param_int CYCLE_LEN 8 8 4 12 "CYCLE_LEN" "PROBE_BW 周期长度；原版为 8。" || return 1
        _e89_param_int BBR_MIN_RTT_WIN_SEC 10 15 8 30 "bbr_min_rtt_win_sec" "高 RTT 代理线路建议 15；太大会延迟发现新路径 RTT。" || return 1
        _e89_param_int BBR_PROBE_RTT_MODE_MS 200 160 100 300 "bbr_probe_rtt_mode_ms" "ProbeRTT 最短持续时间；太低可能测不准，太高体感卡。" || return 1
        _e89_param_int BBR_MIN_TSO_RATE 1200000 1200000 600000 3000000 "bbr_min_tso_rate" "低速 TSO 阈值；第一版不建议改。" || return 1
        _e89_param_int BBR_PACING_MARGIN_PERCENT 1 1 0 5 "bbr_pacing_margin_percent" "pacing 余量；0 更激进，1 更稳。" || return 1
        _e89_param_int BBR_HIGH_GAIN 288 265 220 320 "bbr_high_gain" "百分比整数，265=2.65x；开局提速强度。" || return 1
        local dm=""; read -rp "bbr_drain_gain 是否自动按 high_gain 反算？[Y/n]: " dm || true
        if [[ "$dm" =~ ^[nN]$ ]]; then BBR_DRAIN_GAIN_MODE="manual"; _e89_param_int BBR_DRAIN_GAIN 34 37 25 80 "bbr_drain_gain" "百分比整数，37=0.37x；建议自动。" || return 1; else BBR_DRAIN_GAIN_MODE="auto"; BBR_DRAIN_GAIN=0; fi
        _e89_param_int BBR_CWND_GAIN 200 215 180 280 "bbr_cwnd_gain" "百分比整数，215=2.15x；高 RTT/高 BDP 略增。" || return 1
        _e89_param_int BBR_PACING_GAIN_0 125 130 110 160 "bbr_pacing_gain[0]" "上探增益，130=1.30x。" || return 1
        _e89_param_int BBR_PACING_GAIN_1 75 82 60 100 "bbr_pacing_gain[1]" "下探增益，82=0.82x。" || return 1
        _e89_param_int BBR_PACING_GAIN_2 100 100 90 110 "bbr_pacing_gain[2]" "巡航，建议 100。" || return 1
        _e89_param_int BBR_PACING_GAIN_3 100 100 90 110 "bbr_pacing_gain[3]" "巡航，建议 100。" || return 1
        _e89_param_int BBR_PACING_GAIN_4 100 100 90 110 "bbr_pacing_gain[4]" "巡航，建议 100。" || return 1
        _e89_param_int BBR_PACING_GAIN_5 100 100 90 110 "bbr_pacing_gain[5]" "巡航，建议 100。" || return 1
        _e89_param_int BBR_PACING_GAIN_6 100 100 90 110 "bbr_pacing_gain[6]" "巡航，建议 100。" || return 1
        _e89_param_int BBR_PACING_GAIN_7 100 100 90 110 "bbr_pacing_gain[7]" "巡航，建议 100。" || return 1
        _e89_param_int BBR_CYCLE_RAND 7 7 0 7 "bbr_cycle_rand" "随机起始周期；保持 7。" || return 1
        _e89_param_int BBR_CWND_MIN_TARGET 4 4 4 16 "bbr_cwnd_min_target" "最小 cwnd；通常 4。" || return 1
        _e89_param_int BBR_FULL_BW_THRESH 125 125 110 150 "bbr_full_bw_thresh" "百分比整数，125=1.25x；STARTUP 增长判断。" || return 1
        _e89_param_int BBR_FULL_BW_CNT 3 3 2 8 "bbr_full_bw_cnt" "连续几轮无增长后退出 STARTUP。" || return 1
        _e89_param_int BBR_LT_INTVL_MIN_RTTS 4 4 2 16 "bbr_lt_intvl_min_rtts" "长期限速器采样最小 RTT 轮数。" || return 1
        _e89_param_int BBR_LT_LOSS_THRESH 50 50 20 100 "bbr_lt_loss_thresh" "Policer 识别阈值；不建议第一版改。" || return 1
        _e89_param_int BBR_LT_BW_RATIO_DIV 8 8 4 16 "bbr_lt_bw_ratio_div" "生成 BBR_UNIT/N；N 越小容忍越宽。" || return 1
        _e89_param_int BBR_LT_BW_DIFF_NUM 4000 4000 100 10000 "bbr_lt_bw_diff_num" "生成 NUM/DIV；长期带宽差异判断。" || return 1
        _e89_param_int BBR_LT_BW_DIFF_DIV 8 8 1 64 "bbr_lt_bw_diff_div" "长期带宽差异除数。" || return 1
        _e89_param_int BBR_LT_BW_MAX_RTTS 48 48 16 96 "bbr_lt_bw_max_rtts" "识别到限速器后保持长期带宽 RTT 数。" || return 1
        _e89_param_int BBR_EXTRA_ACKED_GAIN 100 100 0 150 "bbr_extra_acked_gain" "ACK 聚合补偿，第一版不放大。" || return 1
        _e89_param_int BBR_EXTRA_ACKED_WIN_RTTS 5 5 2 16 "bbr_extra_acked_win_rtts" "ACK 聚合窗口。" || return 1
        _e89_param_expr BBR_ACK_EPOCH_ACKED_RESET_THRESH "1U << 20" "1U << 20" "bbr_ack_epoch_acked_reset_thresh" "ACK epoch 重置阈值；建议固定。" || return 1
        _e89_param_int BBR_EXTRA_ACKED_MAX_US 100000 100000 50000 300000 "bbr_extra_acked_max_us" "ACK 聚合补偿时间上限。" || return 1
    fi
}

_e89_collect_bbr3_params() {
    local mode="${1:-recommended}"
    _e89_bbr3_defaults
    if test "$mode" = "custom"; then
        _e89_show_bbr3_table
        _e89_param_int BBR_VERSION 3 3 3 3 "BBR_VERSION" "BBR3 版本标识，固定 3。" || return 1
        _e89_param_int BW_SCALE 24 24 20 28 "BW_SCALE" "带宽估算缩放位数。" || return 1
        _e89_param_int BBR_SCALE 8 8 6 10 "BBR_SCALE" "gain 缩放位数。" || return 1
