        _e89_param_int BBR_TSO_RTT_SHIFT 9 9 7 12 "bbr_tso_rtt_shift" "TSO 与 RTT 适配。" || return 1
        _e89_param_int BBR_PACING_MARGIN_PERCENT 1 1 0 5 "bbr_pacing_margin_percent" "pacing 余量。" || return 1
        _e89_param_int BBR_STARTUP_PACING_GAIN 277 260 220 320 "bbr_startup_pacing_gain" "百分比整数，260=2.60x。" || return 1
        _e89_param_int BBR_STARTUP_CWND_GAIN 200 200 180 280 "bbr_startup_cwnd_gain" "STARTUP cwnd 增益。" || return 1
        local dm=""; read -rp "bbr_drain_gain 是否自动按 startup_pacing_gain 反算？[Y/n]: " dm || true
        if [[ "$dm" =~ ^[nN]$ ]]; then BBR_DRAIN_GAIN_MODE="manual"; _e89_param_int BBR_DRAIN_GAIN 34 38 25 80 "bbr_drain_gain" "百分比整数，38=0.38x；建议自动。" || return 1; else BBR_DRAIN_GAIN_MODE="auto"; BBR_DRAIN_GAIN=0; fi
        _e89_param_int BBR_CWND_GAIN 200 215 180 300 "bbr_cwnd_gain" "稳态 cwnd gain。" || return 1
        _e89_param_int BBR_PACING_GAIN_UP 125 130 110 160 "bbr_pacing_gain[UP]" "上探增益。" || return 1
        _e89_param_int BBR_PACING_GAIN_DOWN 91 88 70 100 "bbr_pacing_gain[DOWN]" "下探排队列增益。" || return 1
        _e89_param_int BBR_PACING_GAIN_CRUISE 100 100 90 110 "bbr_pacing_gain[CRUISE]" "巡航。" || return 1
        _e89_param_int BBR_PACING_GAIN_REFILL 100 100 90 120 "bbr_pacing_gain[REFILL]" "回填。" || return 1
        _e89_param_int BBR_CWND_MIN_TARGET 4 4 4 16 "bbr_cwnd_min_target" "最小 cwnd。" || return 1
        _e89_param_int BBR_FULL_BW_THRESH 125 125 110 150 "bbr_full_bw_thresh" "STARTUP 带宽增长判断。" || return 1
        _e89_param_int BBR_FULL_BW_CNT 3 3 2 8 "bbr_full_bw_cnt" "STARTUP 退出计数。" || return 1
        _e89_param_int BBR_EXTRA_ACKED_GAIN 100 100 0 150 "bbr_extra_acked_gain" "ACK 聚合补偿。" || return 1
        _e89_param_int BBR_EXTRA_ACKED_WIN_RTTS 5 5 2 16 "bbr_extra_acked_win_rtts" "ACK 聚合窗口。" || return 1
        _e89_param_expr BBR_ACK_EPOCH_ACKED_RESET_THRESH "1U << 20" "1U << 20" "bbr_ack_epoch_acked_reset_thresh" "ACK epoch 重置阈值。" || return 1
        _e89_param_int BBR_EXTRA_ACKED_MAX_US 100000 100000 50000 300000 "bbr_extra_acked_max_us" "ACK 聚合补偿时间上限。" || return 1
        _e89_param_bool BBR_PRECISE_ECE_ACK 1 1 "bbr_precise_ece_ack" "ECN 精确 ACK。" || return 1
        _e89_param_int BBR_ECN_MAX_RTT_US 5000 5000 0 50000 "bbr_ecn_max_rtt_us" "ECN 逻辑 RTT 限制。" || return 1
        _e89_param_int BBR_BETA 30 25 10 50 "bbr_beta" "loss 后收缩比例，25=0.25x。" || return 1
        _e89_param_int BBR_ECN_ALPHA_GAIN_DIV 16 16 1 32 "bbr_ecn_alpha_gain_div" "生成 1/N，默认 16。" || return 1
        _e89_param_int BBR_ECN_ALPHA_INIT 100 100 50 100 "bbr_ecn_alpha_init" "ECN 初始强度。" || return 1
        _e89_param_int BBR_ECN_FACTOR_NUM 1 1 1 8 "bbr_ecn_factor_num" "ECN 降 inflight 分子。" || return 1
        _e89_param_int BBR_ECN_FACTOR_DIV 3 3 2 16 "bbr_ecn_factor_div" "ECN 降 inflight 分母。" || return 1
        _e89_param_int BBR_ECN_THRESH 50 50 20 80 "bbr_ecn_thresh" "ECN 阈值。" || return 1
        _e89_param_int BBR_ECN_REPROBE_GAIN 50 50 20 80 "bbr_ecn_reprobe_gain" "ECN 后重新探测比例。" || return 1
        _e89_param_int BBR_LOSS_THRESH_PERMILLE 20 25 10 50 "bbr_loss_thresh" "千分比，25=2.5%。" || return 1
        _e89_param_bool BBR_LOSS_PROBE_RECOVERY 1 1 "bbr_loss_probe_recovery" "TLP/loss recovery 行为。" || return 1
        _e89_param_int BBR_FULL_LOSS_CNT 6 6 0 16 "bbr_full_loss_cnt" "STARTUP loss 退出计数。" || return 1
        _e89_param_int BBR_FULL_ECN_CNT 2 2 0 8 "bbr_full_ecn_cnt" "STARTUP ECN 退出计数。" || return 1
        _e89_param_int BBR_INFLIGHT_HEADROOM 15 12 5 25 "bbr_inflight_headroom" "百分比，越小越激进。" || return 1
        _e89_param_int BBR_BW_PROBE_CWND_GAIN 1 1 0 3 "bbr_bw_probe_cwnd_gain" "PROBE_UP cwnd 增量。" || return 1
        _e89_param_int BBR_BW_PROBE_MAX_ROUNDS 63 48 16 96 "bbr_bw_probe_max_rounds" "最大等待探测轮数。" || return 1
        _e89_param_int BBR_BW_PROBE_RAND_ROUNDS 2 2 0 8 "bbr_bw_probe_rand_rounds" "随机探测轮数。" || return 1
        _e89_param_int BBR_BW_PROBE_BASE_US 2000000 2000000 1000000 5000000 "bbr_bw_probe_base_us" "基础探测间隔 us。" || return 1
        _e89_param_int BBR_BW_PROBE_RAND_US 1000000 1000000 0 3000000 "bbr_bw_probe_rand_us" "随机探测间隔 us。" || return 1
        _e89_param_bool BBR_FAST_PATH 1 1 "bbr_fast_path" "快路径。" || return 1
        _e89_param_bool BBR_FAST_ACK_MODE 1 1 "bbr_fast_ack_mode" "快 ACK 模式。" || return 1
    fi
}

