_e89_perl_replace_define() {
    local file="$1" name="$2" value="$3"
    NAME="$name" VALUE="$value" perl -0pi -e 'my $n=$ENV{NAME}; my $v=$ENV{VALUE}; s/^#define\s+\Q$n\E\s+[^\n]*/#define $n $v/mg' "$file" 2>/dev/null || true
}

_e89_perl_replace_const() {
    local file="$1" name="$2" value="$3"
    if ! grep -q "$name" "$file" 2>/dev/null; then warn "源码无参数 $name，跳过。"; return 0; fi
    NAME="$name" VALUE="$value" perl -0pi -e 'my $n=$ENV{NAME}; my $v=$ENV{VALUE}; s/static\s+const\s+([A-Za-z0-9_]+)\s+\Q$n\E\s*=\s*[^;]+;/static const $1 $n = $v;/sg' "$file" 2>/dev/null || true
}

_e89_perl_replace_array() {
    local file="$1" body="$2"
    BODY="$body" perl -0pi -e 'my $b=$ENV{BODY}; s/static\s+const\s+int\s+bbr_pacing_gain\[\]\s*=\s*\{.*?\};/static const int bbr_pacing_gain[] = {\n$b\n};/sg' "$file" 2>/dev/null || true
}

_e89_bool_c() { if test "${1:-0}" = "1"; then echo "true"; else echo "false"; fi; }

_e89_patch_bbr_source_from_conf() {
    local src="$1" conf="$2" kind="$3"
    # shellcheck disable=SC1090
    source "$conf"
    if test "$kind" = "bbr3"; then
        _e89_perl_replace_define "$src" "BBR_VERSION" "$BBR_VERSION"
        _e89_perl_replace_define "$src" "BW_SCALE" "$BW_SCALE"
        _e89_perl_replace_define "$src" "BBR_SCALE" "$BBR_SCALE"
        _e89_perl_replace_const "$src" "bbr_min_rtt_win_sec" "$BBR_MIN_RTT_WIN_SEC"
        _e89_perl_replace_const "$src" "bbr_probe_rtt_mode_ms" "$BBR_PROBE_RTT_MODE_MS"
        _e89_perl_replace_const "$src" "bbr_probe_rtt_win_ms" "$BBR_PROBE_RTT_WIN_MS"
        _e89_perl_replace_const "$src" "bbr_probe_rtt_cwnd_gain" "BBR_UNIT * $BBR_PROBE_RTT_CWND_GAIN / 100"
        _e89_perl_replace_const "$src" "bbr_tso_rtt_shift" "$BBR_TSO_RTT_SHIFT"
        _e89_perl_replace_const "$src" "bbr_pacing_margin_percent" "$BBR_PACING_MARGIN_PERCENT"
        _e89_perl_replace_const "$src" "bbr_startup_pacing_gain" "BBR_UNIT * $BBR_STARTUP_PACING_GAIN / 100 + 1"
        _e89_perl_replace_const "$src" "bbr_startup_cwnd_gain" "BBR_UNIT * $BBR_STARTUP_CWND_GAIN / 100"
        if test "${BBR_DRAIN_GAIN_MODE:-auto}" = "manual"; then _e89_perl_replace_const "$src" "bbr_drain_gain" "BBR_UNIT * $BBR_DRAIN_GAIN / 100"; else _e89_perl_replace_const "$src" "bbr_drain_gain" "BBR_UNIT * 100 / $BBR_STARTUP_PACING_GAIN"; fi
        _e89_perl_replace_const "$src" "bbr_cwnd_gain" "BBR_UNIT * $BBR_CWND_GAIN / 100"
        _e89_perl_replace_array "$src" "    BBR_UNIT * $BBR_PACING_GAIN_UP / 100, /* UP */\n    BBR_UNIT * $BBR_PACING_GAIN_DOWN / 100, /* DOWN */\n    BBR_UNIT * $BBR_PACING_GAIN_CRUISE / 100, /* CRUISE */\n    BBR_UNIT * $BBR_PACING_GAIN_REFILL / 100, /* REFILL */"
        _e89_perl_replace_const "$src" "bbr_cwnd_min_target" "$BBR_CWND_MIN_TARGET"
        _e89_perl_replace_const "$src" "bbr_full_bw_thresh" "BBR_UNIT * $BBR_FULL_BW_THRESH / 100"
        _e89_perl_replace_const "$src" "bbr_full_bw_cnt" "$BBR_FULL_BW_CNT"
        _e89_perl_replace_const "$src" "bbr_extra_acked_gain" "BBR_UNIT * $BBR_EXTRA_ACKED_GAIN / 100"
        _e89_perl_replace_const "$src" "bbr_extra_acked_win_rtts" "$BBR_EXTRA_ACKED_WIN_RTTS"
        _e89_perl_replace_const "$src" "bbr_ack_epoch_acked_reset_thresh" "$BBR_ACK_EPOCH_ACKED_RESET_THRESH"
        _e89_perl_replace_const "$src" "bbr_extra_acked_max_us" "$BBR_EXTRA_ACKED_MAX_US"
        _e89_perl_replace_const "$src" "bbr_precise_ece_ack" "$(_e89_bool_c "$BBR_PRECISE_ECE_ACK")"
        _e89_perl_replace_const "$src" "bbr_ecn_max_rtt_us" "$BBR_ECN_MAX_RTT_US"
        _e89_perl_replace_const "$src" "bbr_beta" "BBR_UNIT * $BBR_BETA / 100"
        _e89_perl_replace_const "$src" "bbr_ecn_alpha_gain" "BBR_UNIT * 1 / $BBR_ECN_ALPHA_GAIN_DIV"
        _e89_perl_replace_const "$src" "bbr_ecn_alpha_init" "BBR_UNIT * $BBR_ECN_ALPHA_INIT / 100"
        _e89_perl_replace_const "$src" "bbr_ecn_factor" "BBR_UNIT * $BBR_ECN_FACTOR_NUM / $BBR_ECN_FACTOR_DIV"
        _e89_perl_replace_const "$src" "bbr_ecn_thresh" "BBR_UNIT * $BBR_ECN_THRESH / 100"
        _e89_perl_replace_const "$src" "bbr_ecn_reprobe_gain" "BBR_UNIT * $BBR_ECN_REPROBE_GAIN / 100"
        _e89_perl_replace_const "$src" "bbr_loss_thresh" "BBR_UNIT * $BBR_LOSS_THRESH_PERMILLE / 1000"
        _e89_perl_replace_const "$src" "bbr_loss_probe_recovery" "$(_e89_bool_c "$BBR_LOSS_PROBE_RECOVERY")"
        _e89_perl_replace_const "$src" "bbr_full_loss_cnt" "$BBR_FULL_LOSS_CNT"
        _e89_perl_replace_const "$src" "bbr_full_ecn_cnt" "$BBR_FULL_ECN_CNT"
        _e89_perl_replace_const "$src" "bbr_inflight_headroom" "BBR_UNIT * $BBR_INFLIGHT_HEADROOM / 100"
        _e89_perl_replace_const "$src" "bbr_bw_probe_cwnd_gain" "$BBR_BW_PROBE_CWND_GAIN"
        _e89_perl_replace_const "$src" "bbr_bw_probe_max_rounds" "$BBR_BW_PROBE_MAX_ROUNDS"
        _e89_perl_replace_const "$src" "bbr_bw_probe_rand_rounds" "$BBR_BW_PROBE_RAND_ROUNDS"
        _e89_perl_replace_const "$src" "bbr_bw_probe_base_us" "$BBR_BW_PROBE_BASE_US"
        _e89_perl_replace_const "$src" "bbr_bw_probe_rand_us" "$BBR_BW_PROBE_RAND_US"
        _e89_perl_replace_const "$src" "bbr_fast_path" "$(_e89_bool_c "$BBR_FAST_PATH")"
        _e89_perl_replace_const "$src" "bbr_fast_ack_mode" "$(_e89_bool_c "$BBR_FAST_ACK_MODE")"
    else
        _e89_perl_replace_define "$src" "BW_SCALE" "$BW_SCALE"
        _e89_perl_replace_define "$src" "BBR_SCALE" "$BBR_SCALE"
        NAME="CYCLE_LEN" VALUE="$CYCLE_LEN" perl -0pi -e 'my $v=$ENV{VALUE}; s/(CYCLE_LEN\s*=\s*)[0-9]+/$1$v/sg' "$src" 2>/dev/null || true
        _e89_perl_replace_const "$src" "bbr_min_rtt_win_sec" "$BBR_MIN_RTT_WIN_SEC"
        _e89_perl_replace_const "$src" "bbr_probe_rtt_mode_ms" "$BBR_PROBE_RTT_MODE_MS"
        _e89_perl_replace_const "$src" "bbr_min_tso_rate" "$BBR_MIN_TSO_RATE"
        _e89_perl_replace_const "$src" "bbr_pacing_margin_percent" "$BBR_PACING_MARGIN_PERCENT"
        _e89_perl_replace_const "$src" "bbr_high_gain" "BBR_UNIT * $BBR_HIGH_GAIN / 100 + 1"
        if test "${BBR_DRAIN_GAIN_MODE:-auto}" = "manual"; then _e89_perl_replace_const "$src" "bbr_drain_gain" "BBR_UNIT * $BBR_DRAIN_GAIN / 100"; else _e89_perl_replace_const "$src" "bbr_drain_gain" "BBR_UNIT * 100 / $BBR_HIGH_GAIN"; fi
        _e89_perl_replace_const "$src" "bbr_cwnd_gain" "BBR_UNIT * $BBR_CWND_GAIN / 100"
        _e89_perl_replace_array "$src" "    BBR_UNIT * $BBR_PACING_GAIN_0 / 100,\n    BBR_UNIT * $BBR_PACING_GAIN_1 / 100,\n    BBR_UNIT * $BBR_PACING_GAIN_2 / 100,\n    BBR_UNIT * $BBR_PACING_GAIN_3 / 100,\n    BBR_UNIT * $BBR_PACING_GAIN_4 / 100,\n    BBR_UNIT * $BBR_PACING_GAIN_5 / 100,\n    BBR_UNIT * $BBR_PACING_GAIN_6 / 100,\n    BBR_UNIT * $BBR_PACING_GAIN_7 / 100,"
        _e89_perl_replace_const "$src" "bbr_cycle_rand" "$BBR_CYCLE_RAND"
        _e89_perl_replace_const "$src" "bbr_cwnd_min_target" "$BBR_CWND_MIN_TARGET"
        _e89_perl_replace_const "$src" "bbr_full_bw_thresh" "BBR_UNIT * $BBR_FULL_BW_THRESH / 100"
        _e89_perl_replace_const "$src" "bbr_full_bw_cnt" "$BBR_FULL_BW_CNT"
        _e89_perl_replace_const "$src" "bbr_lt_intvl_min_rtts" "$BBR_LT_INTVL_MIN_RTTS"
        _e89_perl_replace_const "$src" "bbr_lt_loss_thresh" "$BBR_LT_LOSS_THRESH"
        _e89_perl_replace_const "$src" "bbr_lt_bw_ratio" "BBR_UNIT / $BBR_LT_BW_RATIO_DIV"
        _e89_perl_replace_const "$src" "bbr_lt_bw_diff" "$BBR_LT_BW_DIFF_NUM / $BBR_LT_BW_DIFF_DIV"
        _e89_perl_replace_const "$src" "bbr_lt_bw_max_rtts" "$BBR_LT_BW_MAX_RTTS"
        _e89_perl_replace_const "$src" "bbr_extra_acked_gain" "BBR_UNIT * $BBR_EXTRA_ACKED_GAIN / 100"
        _e89_perl_replace_const "$src" "bbr_extra_acked_win_rtts" "$BBR_EXTRA_ACKED_WIN_RTTS"
        _e89_perl_replace_const "$src" "bbr_ack_epoch_acked_reset_thresh" "$BBR_ACK_EPOCH_ACKED_RESET_THRESH"
        _e89_perl_replace_const "$src" "bbr_extra_acked_max_us" "$BBR_EXTRA_ACKED_MAX_US"
    fi
    # 替换模式保持算法名为 bbr，不改成 bbrx；确保 MODULE_ALIAS 也仍指向 bbr。
    perl -0pi -e 's/\.name\s*=\s*"bbrx3?"/.name = "bbr"/g; s/MODULE_ALIAS_TCP_CONGESTION\("bbrx3?"\)/MODULE_ALIAS_TCP_CONGESTION("bbr")/g' "$src" 2>/dev/null || true
}

_e89_install_new_ko_to_original_path() {
    local newko="$1" orig="$2"
    test -f "$newko" || return 1
    test -n "$orig" || return 1
    mkdir -p "$(dirname "$orig")" 2>/dev/null || true
    case "$orig" in
        *.ko.xz) xz -T0 -f -c "$newko" > "$orig" ;;
        *.ko.zst) zstd -q -f -c "$newko" > "$orig" ;;
        *.ko.gz) gzip -c "$newko" > "$orig" ;;
        *) cp -af "$newko" "$orig" ;;
    esac
}

_e89_build_replace_bbr() {
    local kind="$1" conf="$2" cfgv modp src work newko bdir release_now
    title "V198e89：编译并同名替换 tcp_bbr.ko（算法名仍为 bbr）"
    _e89_bbr_prepare_dirs
    cfgv="$(_e89_bbr_kconfig_value)"
    modp="$(_e89_bbr_mod_path)"
    src="$(_e89_bbr_find_source 2>/dev/null || true)"
    if test "$cfgv" != "m"; then
        error "当前 CONFIG_TCP_CONG_BBR=$cfgv，不是模块型 m；为避免破坏内核，拒绝同名替换。"
        warn "如需内置型 BBR 真替换，请走完整内核源码编译路线。"
        return 1
    fi
    if test -z "$modp" || test ! -f "$modp"; then error "未找到原版 tcp_bbr.ko 路径，拒绝替换。"; return 1; fi
    if test -z "$src" || test ! -f "$src"; then
        error "未找到与当前内核匹配的 tcp_bbr.c 源码。"
        warn "可安装 linux-headers/linux-source，或导出 BBR_SOURCE=/path/to/tcp_bbr.c 后重试。"
        return 1
    fi
    if test ! -d "/lib/modules/$(uname -r)/build"; then
        error "缺少 /lib/modules/$(uname -r)/build，无法编译外部模块。请安装当前内核 headers。"
        return 1
    fi
    bdir="$(_e89_bbr_backup_state)" || { error "备份失败，拒绝继续。"; return 1; }
    _e89_bbr_write_original_param_note "$bdir" "$kind"
    cp -af "$conf" "$bdir/generated_new_params.conf" 2>/dev/null || true
    info "已创建替换前完整备份：$bdir"
    work="$E89_BBRX_BUILD_ROOT/build_$(date +%Y%m%d_%H%M%S)_$kind"
    mkdir -p "$work" || return 1
    cp -af "$src" "$work/tcp_bbr.c"
    cp -af "$work/tcp_bbr.c" "$bdir/tcp_bbr.c.new.before_patch" 2>/dev/null || true
    _e89_patch_bbr_source_from_conf "$work/tcp_bbr.c" "$conf" "$kind"
    cp -af "$work/tcp_bbr.c" "$bdir/tcp_bbr.c.new" 2>/dev/null || true
    cat > "$work/Makefile" <<'EOF_MAKE'
obj-m += tcp_bbr.o
all:
	$(MAKE) -C /lib/modules/$(shell uname -r)/build M=$(PWD) modules
clean:
	$(MAKE) -C /lib/modules/$(shell uname -r)/build M=$(PWD) clean
EOF_MAKE
    info "开始编译 tcp_bbr.ko：$work"
    if ! make -C "/lib/modules/$(uname -r)/build" M="$work" modules; then
        error "编译失败，原系统未替换。工作目录：$work"
        return 1
    fi
    newko="$work/tcp_bbr.ko"
    if test ! -f "$newko"; then error "编译后未发现 $newko，拒绝替换。"; return 1; fi
    cp -af "$newko" "$bdir/tcp_bbr.ko.new" 2>/dev/null || true
    sha256sum "$newko" > "$bdir/tcp_bbr.ko.new.sha256" 2>/dev/null || true
    cat > "$bdir/rollback.sh" <<EOF_ROLLBACK
#!/usr/bin/env bash
set -e
ORIG_KO="$modp"
BACKUP_DIR="$bdir"
sysctl -w net.ipv4.tcp_congestion_control=cubic >/dev/null 2>&1 || true
modprobe -r tcp_bbr 2>/dev/null || rmmod tcp_bbr 2>/dev/null || true
if test -f "\$BACKUP_DIR/tcp_bbr.ko.orig"; then cp -af "\$BACKUP_DIR/tcp_bbr.ko.orig" "\$ORIG_KO"; fi
depmod -a
modprobe tcp_bbr || true
sysctl -w net.ipv4.tcp_congestion_control=bbr >/dev/null 2>&1 || true
sysctl --system >/dev/null 2>&1 || true
echo "已回滚到备份：\$BACKUP_DIR"
EOF_ROLLBACK
    chmod +x "$bdir/rollback.sh" 2>/dev/null || true
    echo ""
    read -rp "是否临时切到 cubic 并尝试卸载旧 tcp_bbr 后立即热替换？[Y/n]: " release_now || true
    if ! [[ "$release_now" =~ ^[nN]$ ]]; then
        sysctl -w net.ipv4.tcp_congestion_control=cubic >/dev/null 2>&1 || true
        modprobe -r tcp_bbr 2>/dev/null || rmmod tcp_bbr 2>/dev/null || warn "旧 tcp_bbr 当前仍被引用，磁盘替换仍会执行；可能需重启后才完全生效。"
    fi
    if ! _e89_install_new_ko_to_original_path "$newko" "$modp"; then
        error "写入新模块失败，尝试保持原状态。"
        return 1
    fi
    depmod -a >/dev/null 2>&1 || true
    modprobe tcp_bbr 2>/dev/null || warn "modprobe tcp_bbr 未立即成功；如果旧模块仍在内存中，请重启后验证。"
    cat > "$E89_BBRX_SYSCTL" <<'EOF_SYSCTL'
net.core.default_qdisc = fq
net.ipv4.tcp_congestion_control = bbr
EOF_SYSCTL
    echo "tcp_bbr" > "$E89_BBRX_MODULES_LOAD"
    sysctl -p "$E89_BBRX_SYSCTL" >/dev/null 2>&1 || true
    info "替换完成。永久配置：$E89_BBRX_SYSCTL / $E89_BBRX_MODULES_LOAD"
    info "回滚脚本：$bdir/rollback.sh"
    sysctl net.ipv4.tcp_congestion_control 2>/dev/null || true
    sysctl net.ipv4.tcp_available_congestion_control 2>/dev/null || true
    modinfo tcp_bbr 2>/dev/null | sed -n '1,8p' || true
}

_e89_bbrv1_flow() {
    local m conf go
    while true; do
        title "V198e89：普通 Linux 主线 BBR v1 → bbrx_v1 参数中心"
        echo "  1) 查看参数表：参数 / 原版 BBR / bbrx_v1 建议 / 说明"
        echo "  2) 使用 bbrx_v1 推荐参数生成配置"
        echo "  3) 自定义全部参数并生成配置"
        echo "  4) 使用当前配置编译并替换 bbr"
        echo "  0) 返回"
        read -rp "请选择: " m || true
        case "${m:-}" in
            1) _e89_show_bbrv1_table; _e89_bbr_pause ;;
            2) _e89_collect_bbrv1_params recommended || return; conf="$(_e89_write_bbrv1_conf)"; info "已写入：$conf"; read -rp "是否立即编译并替换 bbr？[y/N]: " go || true; [[ "$go" =~ ^[yY]$ ]] && _e89_build_replace_bbr bbrv1 "$conf"; _e89_bbr_pause ;;
            3) _e89_collect_bbrv1_params custom || return; conf="$(_e89_write_bbrv1_conf)"; info "已写入：$conf"; read -rp "是否立即编译并替换 bbr？[y/N]: " go || true; [[ "$go" =~ ^[yY]$ ]] && _e89_build_replace_bbr bbrv1 "$conf"; _e89_bbr_pause ;;
            4) conf="$E89_BBRX_CURRENT/bbrv1_replace.conf"; if test -f "$conf"; then _e89_build_replace_bbr bbrv1 "$conf"; else warn "配置不存在，请先执行 2 或 3。"; fi; _e89_bbr_pause ;;
            0) return ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

_e89_bbr3_flow() {
    local m conf go
    while true; do
        title "V198e89：BBR3 / XanMod → bbrx3_v1 参数中心"
