            3) _e89_collect_bbr3_params custom || return; conf="$(_e89_write_bbr3_conf)"; info "已写入：$conf"; read -rp "是否立即编译并替换 bbr？[y/N]: " go || true; [[ "$go" =~ ^[yY]$ ]] && _e89_build_replace_bbr bbr3 "$conf"; _e89_bbr_pause ;;
            4) conf="$E89_BBRX_CURRENT/bbr3_replace.conf"; if test -f "$conf"; then _e89_build_replace_bbr bbr3 "$conf"; else warn "配置不存在，请先执行 2 或 3。"; fi; _e89_bbr_pause ;;
