_e89_bbr_show_backups() {
    title "V198e89：BBR 替换备份列表"
    ls -1dt "$E89_BBRX_BACKUP_ROOT"/* 2>/dev/null | head -n 20 | nl -w2 -s') ' || echo "  暂无备份。"
}

_e89_bbr_rollback_latest() {
    local bdir rb
    bdir=$(ls -1dt "$E89_BBRX_BACKUP_ROOT"/* 2>/dev/null | head -n1 || true)
    if test -z "$bdir" || test ! -d "$bdir"; then error "未找到可回滚备份。"; return 1; fi
    rb="$bdir/rollback.sh"
    if test -x "$rb"; then bash "$rb"; else error "备份中没有 rollback.sh：$bdir"; return 1; fi
}

_e89_bbr_status() {
    title "V198e89：当前 BBR / qdisc / 模块状态"
    echo "  内核：$(uname -r 2>/dev/null || true)"
    echo "  CONFIG_TCP_CONG_BBR：$(_e89_bbr_kconfig_value)"
    sysctl net.ipv4.tcp_congestion_control 2>/dev/null || true
    sysctl net.ipv4.tcp_available_congestion_control 2>/dev/null || true
    sysctl net.core.default_qdisc 2>/dev/null || true
    echo ""
    echo "  tcp_bbr 模块路径：$(_e89_bbr_mod_path)"
    modinfo tcp_bbr 2>/dev/null | sed -n '1,14p' || true
    echo ""
    echo "  活跃连接 BBR 摘要："
    ss -tin 2>/dev/null | grep -i 'bbr' | head -n 20 || echo "    未发现 ss -tin 中的 bbr 连接样本。"
}

do_bbr_body_replace_menu_e89() {
    _e89_bbr_prepare_dirs
    local opt rec
    while true; do
        rec="$(_e89_bbr_recommend_kind)"
        title "V198e89：BBR 本体替换 / 自定义编译中心"
        echo "  自动建议：$(test "$rec" = "bbr3" && echo "BBR3 / XanMod → bbrx3_v1" || echo "普通 Linux 主线 BBR v1 → bbrx_v1")"
        echo ""
        echo "  1) 自动检测当前 BBR 类型，并推荐编译方案"
        echo "  2) 普通 Linux 主线 BBR v1 → 自定义全部参数 → 替换 bbr"
        echo "  3) BBR3 / XanMod → 自定义全部参数 → 替换 bbr"
        echo "  4) 查看已备份的原版 BBR / 系统 TCP 设置"
        echo "  5) 无损切换回最近一次编译前 BBR"
        echo "  6) 查看当前拥塞控制 / qdisc / BBR 状态"
        echo "  0) 返回主菜单"
        read -rp "请选择: " opt || true
        case "${opt:-}" in
            1) _e89_bbr_detect; _e89_bbr_pause ;;
            2) _e89_bbrv1_flow ;;
            3) _e89_bbr3_flow ;;
            4) _e89_bbr_show_backups; _e89_bbr_pause ;;
            5) _e89_bbr_rollback_latest; _e89_bbr_pause ;;
            6) _e89_bbr_status; _e89_bbr_pause ;;
            0) return ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

hot_update_from_legacy() {
    title "V198e89：稳态热更新（e88 基线 + BBR 本体替换中心）"
    set +e
    trap - ERR

    mkdir -p "$CONFIG_DIR" "$SCRIPT_DIR" "$BACKUP_DIR" "$E89_BBRX_ROOT" "$E89_BBRX_CURRENT" "$E89_BBRX_BACKUP_ROOT" 2>/dev/null || true
    _e88_install_self_entrypoint || true
    local bdir
    if declare -F e76_state_snapshot >/dev/null 2>&1; then
        bdir=$(e76_state_snapshot "hotupdate_e89")
    else
        bdir="$BACKUP_DIR/hotupdate_e89_$(date +%Y%m%d_%H%M%S)"; mkdir -p "$bdir" 2>/dev/null || true
        cp -a "$CONFIG" "$bdir/config.json.bak" 2>/dev/null || true
        cp -a "$NETWORK_OPT_CONF" "$bdir/99-network-optimized.conf.bak" 2>/dev/null || true
    fi
    info "已创建热更新快照：$bdir"

    repair_dns_if_broken || true
    install_update_dat || true
    fix_xray_systemd_limits || true
    apply_hotupdate_fast_sysctl || true
    remove_xray_env_buffer || true

    _e88_set_sysctl_key net.ipv4.tcp_fastopen 0 "V198e89 热更新：保持 tcp_fastopen=0，不默认启用 TFO=3" || true
    _e88_set_tcp_notsent_lowat 26214 "热更新默认极低排队响应值" || true
    _e88_apply_menu13_defaults || true
    _e88_apply_rps_rfs || true
    _e88_set_init_window 21 21 "hotupdate-default21" || true
    _e89_bbr_prepare_dirs || true

    if declare -F e76_config_semantic_ok >/dev/null 2>&1 && e76_config_semantic_ok "$CONFIG"; then
        force_apply_xray_core_defaults_e52 >/dev/null 2>&1 || true
        harden_xray_reality_profile >/dev/null 2>&1 || true
        fix_permissions || true
        systemctl daemon-reload >/dev/null 2>&1 || true
        if systemctl restart xray >/dev/null 2>&1; then
            info "Xray 已基于有效现网配置重启。"
        else
            warn "Xray 重启失败；可执行：journalctl -u xray --no-pager -n 80"
        fi
    else
        warn "未发现有效现网节点配置。V198e89 已安装为 xrv；请执行 xrv → 1 重新搭建。"
    fi

    echo "198e89" > "$SCRIPT_VERSION_FILE" 2>/dev/null || true
    _e88_show_tcp_notsent_lowat_state || true
    _e88_show_menu13_manual_notes || true
    _e88_show_core_network_state || true
    _e88_show_rps_rfs_state || true
    _e88_show_init_window_state || true
    if declare -F e77_audit_runtime_state >/dev/null 2>&1; then e77_audit_runtime_state || true; fi
    set -e
    trap '_err_handler $? $LINENO "$BASH_COMMAND"' ERR
    info "V198e89 热更新完成。主菜单新增：17) BBR 本体替换 / 自定义编译中心。"
    info "BBR 中心目录：$E89_BBRX_ROOT；备份目录：$E89_BBRX_BACKUP_ROOT。"
    return 0
}

main_menu() {
    while true; do
        clear
        echo -e "${blue}======================================================================${none}"
        echo -e "  ${magenta}Xray System Advanced Management V198e89 - (Reality / VLESSENC / SS2022 / BBR本体替换中心)${none}"
        local svc sys_ver arch_level dns_mode tz_line notsent_now notsent_perm qdisc cc adv app bbr_cfg
        svc=$(systemctl is-active xray 2>/dev/null || echo "inactive")
        if test "$svc" = "active"; then svc="${green}平稳在线 (Running)${none}"; else svc="${red}离线静默 (Stopped)${none}"; fi
        sys_ver=$(uname -r 2>/dev/null || echo "未探测到数据")
        if declare -F detect_x86_64_level >/dev/null 2>&1; then arch_level="$(detect_x86_64_level 2>/dev/null || echo '?')"; else arch_level="?"; fi
        dns_mode=$(cat "${E67_DNS_MODE_FILE:-/usr/local/etc/xray/dns_mode.txt}" 2>/dev/null || echo auto)
        tz_line=$(date '+%Z %z' 2>/dev/null || echo unknown)
        notsent_now=$(_e88_current_notsent_lowat)
        notsent_perm=$(_e88_persistent_notsent_lowat)
        qdisc=$(_e88_sysctl_get net.core.default_qdisc)
        cc=$(_e88_sysctl_get net.ipv4.tcp_congestion_control)
        adv=$(_e88_sysctl_get net.ipv4.tcp_adv_win_scale)
        app=$(_e88_sysctl_get net.ipv4.tcp_app_win)
        bbr_cfg=$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)
        echo -e "  引擎态势: $svc | 全局快捷指令: ${cyan}xrv${none} | 外部识别 IP: ${yellow}$(_get_ip 2>/dev/null || echo "探测异常")${none}"
        echo -e "  系统装配内核: ${cyan}${sys_ver}${none} | 微架构侦测: x64-v${yellow}${arch_level}${none} | qdisc/cc: ${yellow}${qdisc}/${cc}${none} | BBR配置:${yellow}${bbr_cfg}${none}"
        echo -e "  DNS模式: ${cyan}${dns_mode}${none} | 时间轴: ${cyan}${tz_line}${none} | notsent: ${yellow}${notsent_now}${none}/${cyan}${notsent_perm}${none} | adv/app: ${yellow}${adv}/${app}${none}"
        echo -e "${blue}======================================================================${none}"
        echo "  1) 创建/重构协议节点：Reality Vision / VLESSENC 自选 / SS2022"
        echo "  2) 用户凭证生命周期与独立参数化管理控制"
        echo "  3) 节点链接与多维信息输出聚合中心"
        echo "  4) 人工发起数据强联，执行路由解析规则库强制覆盖更新"
        echo "  5) Xray Core 手动更新/修复（不设置自动更新）"
        echo "  6) 修改或全自动剔除被拦截的防封伪装特征矩阵域名"
        echo "  7) 系统防火墙策略配置 (阻止内网 BT 滥用及第三方广告请求)"
        echo "  8) Reality Fallback 底层限速沙盒分析器"
        echo "  9) 全景网络连接审计日志与商用级别网络流量记账本"
        echo "  10) 高级发烧：内核双轨编译(APT/源码)/网络/应用层 60余项极限全控板"
        echo -e "  ${cyan}11) 从旧 ex198e 环境稳态热更新到 V198e89${none}"
        echo -e "  ${cyan}12) 清理空间（安全释放 / 快照收敛 / 显示硬盘与 Swap）${none}"
        echo -e "  ${cyan}13) 应用网络参数（缓冲/notsent/adv_win/app_win/txqueue/OOOX/MSS）${none}"
        echo -e "  ${cyan}14) TCP 重传 / 单连接诊断中心（只读排障）${none}"
        echo -e "  ${cyan}15) 检查现有配置并重新输出节点${none}"
        echo -e "  ${cyan}16) 状态隔离审计 + VLESSENC 能力检查${none}"
        echo -e "  ${magenta}17) BBR 本体替换 / 自定义编译中心（bbrx_v1 / bbrx3_v1）${none}"
        echo "  0) 折叠命令控制台，返回底层终端"
        echo -e "  ${red}88) 物理不可逆自毁！撤销环境安全防线与系统配置设定${none}"
        hr
        local num=""
        read -rp "请输入操作代码指令: " num || true
        case "${num:-}" in
            1) do_install ;;
            2) do_user_manager ;;
            3) do_summary; while true; do local rb=""; read -rp "输出完毕，按 Enter 退出或者按 b 发起特征替换: " rb || true; if test "$rb" = "b" || test "$rb" = "B"; then if choose_sni; then _update_matrix; do_summary; else break; fi; else break; fi; done ;;
            4) print_magenta ">>> 初始化云网络联通..."; bash "$UPDATE_DAT_SCRIPT" >/dev/null 2>&1 || true; ensure_xray_is_alive; info "配置已穿透替换系统！当前路由库完成热加载！"; local _p=""; read -rp "按 Enter 退回..." _p || true ;;
            5) do_update_core ;;
            6) if choose_sni; then _update_matrix; do_summary; while true; do local rb=""; read -rp "任务完毕，按 Enter 返回，或按 b 连续变更: " rb || true; if test "$rb" = "b" || test "$rb" = "B"; then if choose_sni; then _update_matrix; do_summary; else break; fi; else break; fi; done; fi ;;
            7) _global_block_rules ;;
            8) do_fallback_probe ;;
            9) do_status_menu ;;
            10) do_sys_init_menu ;;
            11) hot_update_from_legacy ;;
            12) do_space_cleanup_menu ;;
            13) do_network_params_menu_e56 ;;
            14) do_tcp_diag_menu_e63 ;;
            15) do_install_repair_e77 ;;
            16) e77_audit_runtime_state; _e52_pause ;;
            17) do_bbr_body_replace_menu_e89 ;;
            88) do_uninstall ;;
            0) exit 0 ;;
            *) echo -e "${red}错误拦截：代码解析为空值！${none}"; sleep 1 ;;
        esac
    done
}



#==============================================================================
# V198e90 FINAL OVERRIDE LAYER
# 目标：
#   1) 修复 CONFIG_TCP_CONG_BBR=y 内置型 BBR 两套参数都无法替换的问题：
#      - 模块型 m：继续使用 e89 的 tcp_bbr.ko 同名替换路线。
#      - 内置型 y：转入“补丁 tcp_bbr.c + 完整源码内核编译”路线，重启后生效。
#   2) 自定义参数输入时同步展示“参数 / 原版 / 推荐 / 说明”，并支持 ? 随时查看完整参数表。
#   3) 11 热更新升级为 V198e90，保留 e88/e89 稳态网络参数与 BBRX 工作目录。
#==============================================================================

# 保存 e89 的关键函数，e90 在外层接管。
if declare -F _e89_build_replace_bbr >/dev/null 2>&1; then
    eval "$(declare -f _e89_build_replace_bbr | sed '1s/_e89_build_replace_bbr/_e90_build_replace_bbr_module_base/')"
fi
if declare -F _execute_compilation >/dev/null 2>&1; then
    eval "$(declare -f _execute_compilation | sed '1s/_execute_compilation/_e90_execute_compilation_base/')"
fi
if declare -F hot_update_from_legacy >/dev/null 2>&1; then
    eval "$(declare -f hot_update_from_legacy | sed '1s/hot_update_from_legacy/hot_update_from_legacy_e89_base/')"
fi

_e90_bbr_compile_mode_text() {
    local cfgv
    cfgv="$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)"
    case "$cfgv" in
        m) echo "模块型 m：可热替换 tcp_bbr.ko" ;;
        y) echo "内置型 y：需补丁源码并完整编译内核，重启后生效" ;;
        *) echo "未知：需先自动检测" ;;
    esac
}

_e90_show_param_input_banner() {
    local kind="$1"
    echo ""
    if test "$kind" = "bbr3"; then
        print_yellow "下面进入 BBR3 / XanMod 全参数自定义。每一项都会显示：参数 / 原版 BBR3 / bbrx3_v1 建议 / 说明。"
        print_yellow "输入 ? 可随时查看完整参数表；回车=推荐值；r=原版值；q=退出。"
        _e89_show_bbr3_table
    else
        print_yellow "下面进入普通 Linux 主线 BBR v1 全参数自定义。每一项都会显示：参数 / 原版 BBR / bbrx_v1 建议 / 说明。"
        print_yellow "输入 ? 可随时查看完整参数表；回车=推荐值；r=原版值；q=退出。"
        _e89_show_bbrv1_table
    fi
}

_e90_show_table_by_current_kind() {
    case "${E90_PARAM_KIND:-}" in
        bbr3) _e89_show_bbr3_table ;;
        *) _e89_show_bbrv1_table ;;
    esac
}

# 覆盖 e89 的参数输入函数：不再只显示三行，而是用表格式提示。
_e89_param_int() {
    local __var="$1" orig="$2" rec="$3" min="$4" max="$5" label="$6" desc="$7" val orig_clean rec_clean
    while true; do
        echo ""
        echo -e "${blue}--------------------------------------------------------------------------${none}"
        printf "  %-32s | %-18s | %-18s | %s\n" "参数" "原版" "bbrx_v1/bbrx3_v1建议" "说明"
        echo "  ------------------------------------------------------------------------"
        printf "  %-32s | %-18s | %-18s | %s\n" "$label" "$orig" "$rec" "$desc"
        echo -e "${blue}--------------------------------------------------------------------------${none}"
        read -rp "  请输入 [$min-$max]，回车=$rec，r=原版，?=完整表，q=退出: " val || true
        if [[ "$val" =~ ^[qQ]$ ]]; then return 1; fi
        if test "$val" = "?"; then _e90_show_table_by_current_kind; continue; fi
        if [[ "$val" =~ ^[rR]$ ]]; then val="$orig"; fi
        val="${val:-$rec}"
        # 支持用户从说明里复制“2.65x/2.0%”一类展示值：只取第一个整数片段。
        val="${val%% *}"; val="${val%%x}"; val="${val%%%}"
        val="$(echo "$val" | sed -E 's/[^0-9].*$//' 2>/dev/null || echo "$val")"
        if [[ "$val" =~ ^[0-9]+$ ]] && test "$val" -ge "$min" 2>/dev/null && test "$val" -le "$max" 2>/dev/null; then
            printf -v "$__var" '%s' "$val"
            return 0
        fi
        error "输入非法：$val"
    done
}

_e89_param_bool() {
    local __var="$1" orig="$2" rec="$3" label="$4" desc="$5" val
    while true; do
        echo ""
        echo -e "${blue}--------------------------------------------------------------------------${none}"
        printf "  %-32s | %-18s | %-18s | %s\n" "参数" "原版" "bbrx3_v1建议" "说明"
        echo "  ------------------------------------------------------------------------"
        printf "  %-32s | %-18s | %-18s | %s\n" "$label" "$orig" "$rec" "$desc"
        echo -e "${blue}--------------------------------------------------------------------------${none}"
        read -rp "  请输入 1=true / 0=false，回车=$rec，r=原版，?=完整表，q=退出: " val || true
        if [[ "$val" =~ ^[qQ]$ ]]; then return 1; fi
        if test "$val" = "?"; then _e90_show_table_by_current_kind; continue; fi
        if [[ "$val" =~ ^[rR]$ ]]; then val="$orig"; fi
        val="${val:-$rec}"
        if test "$val" = "1" || test "$val" = "0"; then printf -v "$__var" '%s' "$val"; return 0; fi
        error "输入非法：$val"
    done
}

_e89_param_expr() {
    local __var="$1" orig="$2" rec="$3" label="$4" desc="$5" val
    while true; do
        echo ""
        echo -e "${blue}--------------------------------------------------------------------------${none}"
        printf "  %-32s | %-18s | %-18s | %s\n" "参数" "原版" "建议" "说明"
        echo "  ------------------------------------------------------------------------"
        printf "  %-32s | %-18s | %-18s | %s\n" "$label" "$orig" "$rec" "$desc"
        echo -e "${blue}--------------------------------------------------------------------------${none}"
        read -rp "  请输入 C 表达式，回车=$rec，r=原版，?=完整表，q=退出: " val || true
        if [[ "$val" =~ ^[qQ]$ ]]; then return 1; fi
        if test "$val" = "?"; then _e90_show_table_by_current_kind; continue; fi
        if [[ "$val" =~ ^[rR]$ ]]; then val="$orig"; fi
        val="${val:-$rec}"
        if ! echo "$val" | grep -Eq '^[A-Za-z0-9_[:space:]<</+*()-]+$'; then
            error "表达式含不安全字符，已拒绝。"
            continue
        fi
        printf -v "$__var" '%s' "$val"
        return 0
    done
}

# 覆盖采集函数：自定义模式先显示完整表，避免必须退出查看说明。
_e89_collect_bbrv1_params() {
    local mode="${1:-recommended}" drain_mode
    E90_PARAM_KIND="bbrv1"
    _e89_bbrv1_defaults
    if test "$mode" = "custom"; then
        _e90_show_param_input_banner bbrv1
        _e89_param_int BW_SCALE 24 24 20 28 "BW_SCALE" "带宽估算缩放位数；普通用户不建议改。" || return 1
        _e89_param_int BBR_SCALE 8 8 6 10 "BBR_SCALE" "gain 缩放位数；普通用户不建议改。" || return 1
        _e89_param_int CYCLE_LEN 8 8 4 12 "CYCLE_LEN" "PROBE_BW 增益周期长度；改动会影响数组长度语义。" || return 1
        _e89_param_int BBR_MIN_RTT_WIN_SEC 10 15 8 30 "bbr_min_rtt_win_sec" "最小 RTT 采样窗口；高 RTT 线路略放大。" || return 1
        _e89_param_int BBR_PROBE_RTT_MODE_MS 200 160 100 300 "bbr_probe_rtt_mode_ms" "ProbeRTT 持续时间；缩短可减少体感卡顿。" || return 1
        _e89_param_int BBR_MIN_TSO_RATE 1200000 1200000 600000 3000000 "bbr_min_tso_rate" "低速 TSO 阈值。" || return 1
        _e89_param_int BBR_PACING_MARGIN_PERCENT 1 1 0 5 "bbr_pacing_margin_percent" "pacing 余量；0 更激进，1 更稳。" || return 1
        _e89_param_int BBR_HIGH_GAIN 288 265 220 320 "bbr_high_gain" "STARTUP 提速增益；265 表示 2.65x。" || return 1
        echo ""
        read -rp "bbr_drain_gain 建议自动按 high_gain 反算。是否手动输入？[y/N]: " drain_mode || true
        if [[ "$drain_mode" =~ ^[yY]$ ]]; then BBR_DRAIN_GAIN_MODE="manual"; _e89_param_int BBR_DRAIN_GAIN 34 38 25 80 "bbr_drain_gain" "DRAIN 排队列增益；38 表示 0.38x。" || return 1; else BBR_DRAIN_GAIN_MODE="auto"; BBR_DRAIN_GAIN=0; fi
        _e89_param_int BBR_CWND_GAIN 200 215 180 280 "bbr_cwnd_gain" "稳态 cwnd 增益；215 表示 2.15x。" || return 1
        _e89_param_int BBR_PACING_GAIN_0 125 130 110 160 "bbr_pacing_gain[0]" "PROBE_BW 上探强度。" || return 1
        _e89_param_int BBR_PACING_GAIN_1 75 82 60 100 "bbr_pacing_gain[1]" "PROBE_BW 下探/让路强度。" || return 1
        _e89_param_int BBR_PACING_GAIN_2 100 100 90 110 "bbr_pacing_gain[2]" "巡航阶段。" || return 1
        _e89_param_int BBR_PACING_GAIN_3 100 100 90 110 "bbr_pacing_gain[3]" "巡航阶段。" || return 1
        _e89_param_int BBR_PACING_GAIN_4 100 100 90 110 "bbr_pacing_gain[4]" "巡航阶段。" || return 1
        _e89_param_int BBR_PACING_GAIN_5 100 100 90 110 "bbr_pacing_gain[5]" "巡航阶段。" || return 1
        _e89_param_int BBR_PACING_GAIN_6 100 100 90 110 "bbr_pacing_gain[6]" "巡航阶段。" || return 1
        _e89_param_int BBR_PACING_GAIN_7 100 100 90 110 "bbr_pacing_gain[7]" "巡航阶段。" || return 1
        _e89_param_int BBR_CYCLE_RAND 7 7 0 7 "bbr_cycle_rand" "随机起始周期。" || return 1
        _e89_param_int BBR_CWND_MIN_TARGET 4 4 4 16 "bbr_cwnd_min_target" "最小 cwnd。" || return 1
        _e89_param_int BBR_FULL_BW_THRESH 125 125 110 150 "bbr_full_bw_thresh" "STARTUP 带宽增长判断；125=1.25x。" || return 1
        _e89_param_int BBR_FULL_BW_CNT 3 3 2 8 "bbr_full_bw_cnt" "STARTUP 退出计数。" || return 1
        _e89_param_int BBR_LT_INTVL_MIN_RTTS 4 4 2 16 "bbr_lt_intvl_min_rtts" "长期限速器采样 RTT。" || return 1
        _e89_param_int BBR_LT_LOSS_THRESH 50 50 20 100 "bbr_lt_loss_thresh" "Policer 识别阈值。" || return 1
        _e89_param_int BBR_LT_BW_RATIO_DIV 8 8 4 16 "bbr_lt_bw_ratio_div" "长期带宽一致性判断，表达为 BBR_UNIT/N。" || return 1
        _e89_param_int BBR_LT_BW_DIFF_NUM 4000 4000 100 8000 "bbr_lt_bw_diff_num" "长期带宽差异分子。" || return 1
        _e89_param_int BBR_LT_BW_DIFF_DIV 8 8 1 64 "bbr_lt_bw_diff_div" "长期带宽差异分母。" || return 1
        _e89_param_int BBR_LT_BW_MAX_RTTS 48 48 16 96 "bbr_lt_bw_max_rtts" "识别限速器后保持长期带宽的 RTT 数。" || return 1
        _e89_param_int BBR_EXTRA_ACKED_GAIN 100 100 0 150 "bbr_extra_acked_gain" "ACK 聚合补偿。" || return 1
        _e89_param_int BBR_EXTRA_ACKED_WIN_RTTS 5 5 2 16 "bbr_extra_acked_win_rtts" "ACK 聚合窗口。" || return 1
        _e89_param_expr BBR_ACK_EPOCH_ACKED_RESET_THRESH "1U << 20" "1U << 20" "bbr_ack_epoch_acked_reset_thresh" "ACK epoch 重置阈值。" || return 1
        _e89_param_int BBR_EXTRA_ACKED_MAX_US 100000 100000 50000 300000 "bbr_extra_acked_max_us" "ACK 聚合补偿时间上限。" || return 1
    fi
    unset E90_PARAM_KIND
}

