        _e89_param_int BBR_EXTRA_ACKED_MAX_US 100000 100000 50000 300000 "bbr_extra_acked_max_us" "ACK 聚合补偿时间上限。" || return 1
        _e89_param_bool BBR_PRECISE_ECE_ACK 1 1 "bbr_precise_ece_ack" "ECN 精确 ACK。" || return 1
        _e89_param_int BBR_ECN_MAX_RTT_US 5000 5000 0 50000 "bbr_ecn_max_rtt_us" "ECN RTT 限制。" || return 1
        _e89_param_int BBR_BETA 30 25 10 50 "bbr_beta" "loss 后收缩比例；25=0.25x。" || return 1
        _e89_param_int BBR_ECN_ALPHA_GAIN_DIV 16 16 1 32 "bbr_ecn_alpha_gain_div" "ECN EWMA 增益分母，表示 1/N。" || return 1
        _e89_param_int BBR_ECN_ALPHA_INIT 100 100 50 100 "bbr_ecn_alpha_init" "ECN 初始强度。" || return 1
        _e89_param_int BBR_ECN_FACTOR_NUM 1 1 1 10 "bbr_ecn_factor_num" "ECN 降 inflight 比例分子。" || return 1
        _e89_param_int BBR_ECN_FACTOR_DIV 3 3 2 20 "bbr_ecn_factor_div" "ECN 降 inflight 比例分母。" || return 1
        _e89_param_int BBR_ECN_THRESH 50 50 20 80 "bbr_ecn_thresh" "ECN 阈值；50=0.50x。" || return 1
        _e89_param_int BBR_ECN_REPROBE_GAIN 50 50 20 80 "bbr_ecn_reprobe_gain" "ECN 后重新探测比例。" || return 1
        _e89_param_int BBR_LOSS_THRESH_PERMILLE 20 25 10 50 "bbr_loss_thresh" "loss 阈值；25=2.5%。" || return 1
        _e89_param_bool BBR_LOSS_PROBE_RECOVERY 1 1 "bbr_loss_probe_recovery" "TLP recovery 是否降速。" || return 1
        _e89_param_int BBR_FULL_LOSS_CNT 6 6 0 16 "bbr_full_loss_cnt" "STARTUP loss 退出计数。" || return 1
        _e89_param_int BBR_FULL_ECN_CNT 2 2 0 8 "bbr_full_ecn_cnt" "STARTUP ECN 退出计数。" || return 1
        _e89_param_int BBR_INFLIGHT_HEADROOM 15 12 5 25 "bbr_inflight_headroom" "高 loss 后保留余量，越小越激进。" || return 1
        _e89_param_int BBR_BW_PROBE_CWND_GAIN 1 1 0 3 "bbr_bw_probe_cwnd_gain" "PROBE_UP cwnd 增量。" || return 1
        _e89_param_int BBR_BW_PROBE_MAX_ROUNDS 63 48 16 96 "bbr_bw_probe_max_rounds" "最大等待探测轮数。" || return 1
        _e89_param_int BBR_BW_PROBE_RAND_ROUNDS 2 2 0 8 "bbr_bw_probe_rand_rounds" "探测随机轮数。" || return 1
        _e89_param_int BBR_BW_PROBE_BASE_US 2000000 2000000 1000000 5000000 "bbr_bw_probe_base_us" "基础探测间隔。" || return 1
        _e89_param_int BBR_BW_PROBE_RAND_US 1000000 1000000 0 3000000 "bbr_bw_probe_rand_us" "随机探测间隔。" || return 1
        _e89_param_bool BBR_FAST_PATH 1 1 "bbr_fast_path" "快路径。" || return 1
        _e89_param_bool BBR_FAST_ACK_MODE 1 1 "bbr_fast_ack_mode" "快 ACK 模式。" || return 1
    fi
    unset E90_PARAM_KIND
}

_e90_kernel_patch_before_compile() {
    local ksrc="net/ipv4/tcp_bbr.c" conf="${E90_BBR_KERNEL_CONF:-}" kind="${E90_BBR_KERNEL_KIND:-}" bdir="${E90_BBR_KERNEL_BACKUP:-}"
    test -n "$conf" || return 0
    test -n "$kind" || return 0
    if test ! -f "$ksrc"; then
        warn "当前源码树未发现 $ksrc，无法注入 BBR 自定义参数；将继续原编译流程。"
        return 0
    fi
    info "V198e90：正在把自定义 $kind 参数注入当前内核源码：$ksrc"
    if test -n "$bdir" && test -d "$bdir"; then cp -af "$ksrc" "$bdir/tcp_bbr.c.kernel.before_patch" 2>/dev/null || true; fi
    _e89_patch_bbr_source_from_conf "$ksrc" "$conf" "$kind"
    if test -n "$bdir" && test -d "$bdir"; then cp -af "$ksrc" "$bdir/tcp_bbr.c.kernel.after_patch" 2>/dev/null || true; fi
    if test -x ./scripts/config; then
        ./scripts/config --enable CONFIG_TCP_CONG_BBR 2>/dev/null || true
        ./scripts/config --enable CONFIG_DEFAULT_BBR 2>/dev/null || true
        if test "$kind" = "bbr3"; then ./scripts/config --enable CONFIG_TCP_BBR3 2>/dev/null || true; fi
        ./scripts/config --set-str CONFIG_DEFAULT_TCP_CONG "bbr" 2>/dev/null || true
        ./scripts/config --set-str CONFIG_LOCALVERSION "-bbrx90" 2>/dev/null || true
        make olddefconfig >/dev/null 2>&1 || true
    fi
    info "V198e90：BBR 本体参数已补丁进源码。后续 make install 安装新内核，重启后生效。"
}

_execute_compilation() {
    if test -n "${E90_BBR_KERNEL_CONF:-}"; then
        _e90_kernel_patch_before_compile || true
    fi
    if declare -F _e90_execute_compilation_base >/dev/null 2>&1; then
        _e90_execute_compilation_base "$@"
    else
        error "未找到原始 _execute_compilation，无法继续。"
        return 1
    fi
}

_e90_build_builtin_bbr_kernel() {
    local kind="$1" conf="$2" rec bdir confirm route bbr_arg
    title "V198e90：内置型 BBR 源码补丁 + 完整内核编译路线"
    warn "当前 CONFIG_TCP_CONG_BBR=y：BBR 已经编进内核，不存在 tcp_bbr.ko 可替换。"
    warn "正确处理方式：下载/进入内核源码 → patch net/ipv4/tcp_bbr.c → 编译安装新内核 → 重启后生效。"
    warn "旧内核会保留，可在 GRUB/VNC 中回滚；这不是无重启热替换。"
    echo ""
    echo "  当前配置文件：$conf"
    echo "  参数模板：$kind"
    echo "  自动建议：$(_e89_bbr_recommend_kind 2>/dev/null || echo unknown)"
    echo ""
    read -rp "确认走完整内核编译？输入 YES 继续: " confirm || true
    if test "$confirm" != "YES"; then warn "已取消内置型 BBR 编译。"; return 1; fi

    bdir="$(_e89_bbr_backup_state)" || { error "备份失败，拒绝继续。"; return 1; }
    _e89_bbr_write_original_param_note "$bdir" "$kind"
    cp -af "$conf" "$bdir/generated_new_params.conf" 2>/dev/null || true
    info "已创建编译前完整备份：$bdir"

    export E90_BBR_KERNEL_KIND="$kind"
    export E90_BBR_KERNEL_CONF="$conf"
    export E90_BBR_KERNEL_BACKUP="$bdir"

    echo ""
    if test "$kind" = "bbr3" || uname -r 2>/dev/null | grep -qiE 'xanmod|bbr3'; then
        echo -e "  ${cyan}1) 源码编译 XanMod，并注入当前 BBR 参数 ${none}(推荐给 XanMod/BBR3)"
        echo -e "  ${yellow}2) 源码编译 Linux Mainline，并注入当前 BBR 参数${none}"
        echo "  0) 取消"
        read -rp "请选择编译路线 (默认 1): " route || true
        route="${route:-1}"
    else
        echo -e "  ${cyan}1) 源码编译 Linux Mainline，并注入当前 BBR 参数 ${none}(推荐给 BBR v1)"
        echo -e "  ${yellow}2) 源码编译 XanMod，并注入当前 BBR 参数${none}"
        echo "  0) 取消"
        read -rp "请选择编译路线 (默认 1): " route || true
        route="${route:-1}"
        if test "$route" = "1"; then route="mainline"; elif test "$route" = "2"; then route="xanmod"; fi
    fi

    bbr_arg="bbr"
    test "$kind" = "bbr3" && bbr_arg="bbr3"

    case "$route" in
        1|xanmod)
            if test "$kind" = "bbrv1" && uname -r 2>/dev/null | grep -qiE 'xanmod|bbr3'; then
                warn "你在 XanMod/BBR3 环境选择了 BBR v1 模板。建议返回选 3) BBR3 / XanMod。"
            fi
            _compile_kernel_xanmod
            ;;
        2|mainline)
            _compile_kernel_mainline "$bbr_arg"
            ;;
        0)
            warn "已取消。"
            ;;
        *)
            warn "无效选择，已取消。"
            ;;
    esac

    unset E90_BBR_KERNEL_KIND E90_BBR_KERNEL_CONF E90_BBR_KERNEL_BACKUP
}

# 统一替换入口：m 走模块替换；y 走源码编译替换。
_e89_build_replace_bbr() {
    local kind="$1" conf="$2" cfgv
    cfgv="$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)"
    case "$cfgv" in
        m)
            if declare -F _e90_build_replace_bbr_module_base >/dev/null 2>&1; then
                _e90_build_replace_bbr_module_base "$kind" "$conf"
            else
                error "模块型替换基函数缺失。"
                return 1
            fi
            ;;
        y)
            _e90_build_builtin_bbr_kernel "$kind" "$conf"
            ;;
        *)
            error "无法确认 CONFIG_TCP_CONG_BBR=$cfgv。请先执行自动检测。"
            warn "如果你确定是模块型，可检查 modinfo tcp_bbr；如果是内置型，需要完整内核编译。"
            return 1
            ;;
    esac
}

_e89_bbr_detect() {
    title "V198e90：BBR 本体自动检测与编译建议"
    _e89_bbr_prepare_dirs
    local krel cfgv cc av modp src kind rec
    krel="$(uname -r 2>/dev/null || echo unknown)"
    cfgv="$(_e89_bbr_kconfig_value)"
    cc="$(sysctl -n net.ipv4.tcp_congestion_control 2>/dev/null || echo unknown)"
    av="$(sysctl -n net.ipv4.tcp_available_congestion_control 2>/dev/null || echo unknown)"
    modp="$(_e89_bbr_mod_path)"
    src="$(_e89_bbr_find_source 2>/dev/null || true)"
    kind="$(_e89_bbr_source_kind "$src")"
    rec="$(_e89_bbr_recommend_kind)"
    echo "  当前内核：$krel"
    echo "  CONFIG_TCP_CONG_BBR：$cfgv"
    echo "  当前拥塞控制：$cc"
    echo "  可用拥塞控制：$av"
    echo "  tcp_bbr 模块路径：${modp:-未发现/可能内置}"
    echo "  可用 tcp_bbr.c 源码：${src:-未发现；内置型可在源码编译时下载源码后补丁}"
    echo "  源码类型判断：$kind"
    hr
    if test "$cfgv" = "m" && test -n "$modp" && test -f "$modp"; then
        print_green "  替换可行性：模块型 BBR，可执行同名替换 tcp_bbr.ko，新算法仍叫 bbr。"
    elif test "$cfgv" = "y"; then
        print_yellow "  替换可行性：内置型 BBR，不能替换 .ko；e90 将改走完整内核源码补丁编译路线。"
        print_yellow "  生效方式：新内核安装成功后重启进入新内核。旧内核保留，可 GRUB/VNC 回滚。"
    else
        print_yellow "  替换可行性：未能确认模块型或内置型 BBR。"
    fi
    if test "$rec" = "bbr3"; then
        echo -e "  ${cyan}推荐编译方案：BBR3 / XanMod → bbrx3_v1 参数模板${none}"
    else
        echo -e "  ${cyan}推荐编译方案：普通 Linux 主线 BBR v1 → bbrx_v1 参数模板${none}"
    fi
    echo "  当前替换路线：$(_e90_bbr_compile_mode_text)"
}

_e89_bbrv1_flow() {
    local m conf go
    while true; do
        title "V198e90：普通 Linux 主线 BBR v1 → bbrx_v1 参数中心"
        echo "  当前替换路线：$(_e90_bbr_compile_mode_text)"
        echo ""
        echo "  1) 查看参数表：参数 / 原版 BBR / bbrx_v1 建议 / 说明"
        echo "  2) 使用 bbrx_v1 推荐参数生成配置"
        echo "  3) 自定义全部参数并生成配置（输入时同步显示参数表字段）"
        echo "  4) 使用当前配置替换 bbr（m=模块热替换；y=整内核编译）"
        echo "  0) 返回"
        read -rp "请选择: " m || true
        case "${m:-}" in
            1) _e89_show_bbrv1_table; _e89_bbr_pause ;;
            2) _e89_collect_bbrv1_params recommended || return; conf="$(_e89_write_bbrv1_conf)"; info "已写入：$conf"; read -rp "是否立即替换 bbr？[y/N]: " go || true; [[ "$go" =~ ^[yY]$ ]] && _e89_build_replace_bbr bbrv1 "$conf"; _e89_bbr_pause ;;
            3) _e89_collect_bbrv1_params custom || return; conf="$(_e89_write_bbrv1_conf)"; info "已写入：$conf"; read -rp "是否立即替换 bbr？[y/N]: " go || true; [[ "$go" =~ ^[yY]$ ]] && _e89_build_replace_bbr bbrv1 "$conf"; _e89_bbr_pause ;;
            4) conf="$E89_BBRX_CURRENT/bbrv1_replace.conf"; if test -f "$conf"; then _e89_build_replace_bbr bbrv1 "$conf"; else warn "配置不存在，请先执行 2 或 3。"; fi; _e89_bbr_pause ;;
            0) return ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

_e89_bbr3_flow() {
    local m conf go
    while true; do
        title "V198e90：BBR3 / XanMod → bbrx3_v1 参数中心"
