do_bbr_body_replace_menu_e89() {
    _e89_bbr_prepare_dirs
    local opt rec
    while true; do
        rec="$(_e89_bbr_recommend_kind)"
        title "V198e90：BBR 本体替换 / 自定义编译中心"
        echo "  自动建议：$(test "$rec" = "bbr3" && echo "BBR3 / XanMod → bbrx3_v1" || echo "普通 Linux 主线 BBR v1 → bbrx_v1")"
        echo "  当前替换路线：$(_e90_bbr_compile_mode_text)"
        echo ""
        echo "  1) 自动检测当前 BBR 类型，并推荐编译方案"
        echo "  2) 普通 Linux 主线 BBR v1 → 自定义全部参数 → 替换 bbr"
        echo "  3) BBR3 / XanMod → 自定义全部参数 → 替换 bbr"
        echo "  4) 查看已备份的原版 BBR / 系统 TCP 设置"
        echo "  5) 无损切换回最近一次编译前 BBR / 或旧内核 GRUB 回滚提示"
        echo "  6) 查看当前拥塞控制 / qdisc / BBR 状态"
        echo "  0) 返回主菜单"
        read -rp "请选择: " opt || true
        case "${opt:-}" in
            1) _e89_bbr_detect; _e89_bbr_pause ;;
            2) _e89_bbrv1_flow ;;
            3) _e89_bbr3_flow ;;
            4) _e89_bbr_show_backups; _e89_bbr_pause ;;
            5) _e89_bbr_rollback_latest || warn "如果本次是内置型整内核编译，请通过云厂商 VNC/GRUB 选择旧内核回滚。"; _e89_bbr_pause ;;
            6) _e89_bbr_status; _e89_bbr_pause ;;
            0) return ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

hot_update_from_legacy() {
    title "V198e90：稳态热更新（e88/e89 基线 + 内置型 BBR 源码编译路线）"
    if declare -F hot_update_from_legacy_e89_base >/dev/null 2>&1; then
        hot_update_from_legacy_e89_base "$@" || true
    fi
    mkdir -p "$E89_BBRX_ROOT" "$E89_BBRX_CURRENT" "$E89_BBRX_BACKUP_ROOT" "$E89_BBRX_BUILD_ROOT" 2>/dev/null || true
    echo "198e90" > "$SCRIPT_VERSION_FILE" 2>/dev/null || true
    if test -f "${SCRIPT_PATH:-$0}"; then
        cp -f "${SCRIPT_PATH:-$0}" "$SYMLINK" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e90.sh" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
        chmod +x "$SYMLINK" "$SCRIPT_DIR/ex198e90.sh" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
    fi
    info "V198e90 热更新完成：17) BBR 本体替换中心已支持 CONFIG_TCP_CONG_BBR=y 的整内核源码补丁编译路线。"
    info "自定义参数输入时已同步显示：参数 / 原版 / 建议 / 说明，并支持 ? 查看完整表。"
}

main_menu() {
    while true; do
        clear
        echo -e "${blue}======================================================================${none}"
        echo -e "  ${magenta}Xray System Advanced Management V198e90 - (BBR内置/模块双路线 + 参数说明增强)${none}"
        local svc sys_ver arch_level dns_mode tz_line notsent_now notsent_perm qdisc cc adv app bbr_cfg
        svc=$(systemctl is-active xray 2>/dev/null || echo "inactive")
        if test "$svc" = "active"; then svc="${green}平稳在线 (Running)${none}"; else svc="${red}离线静默 (Stopped)${none}"; fi
        sys_ver=$(uname -r 2>/dev/null || echo "未探测到数据")
        if declare -F detect_x86_64_level >/dev/null 2>&1; then arch_level="$(detect_x86_64_level 2>/dev/null || echo '?')"; else arch_level="?"; fi
        dns_mode=$(cat "${E67_DNS_MODE_FILE:-/usr/local/etc/xray/dns_mode.txt}" 2>/dev/null || echo auto)
        tz_line=$(date '+%Z %z' 2>/dev/null || echo unknown)
        notsent_now=$(_e88_current_notsent_lowat 2>/dev/null || echo '?')
        notsent_perm=$(_e88_persistent_notsent_lowat 2>/dev/null || echo '?')
        qdisc=$(_e88_sysctl_get net.core.default_qdisc 2>/dev/null || echo '?')
        cc=$(_e88_sysctl_get net.ipv4.tcp_congestion_control 2>/dev/null || echo '?')
        adv=$(_e88_sysctl_get net.ipv4.tcp_adv_win_scale 2>/dev/null || echo '?')
        app=$(_e88_sysctl_get net.ipv4.tcp_app_win 2>/dev/null || echo '?')
        bbr_cfg=$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)
        echo -e "  引擎态势: $svc | 全局快捷指令: ${cyan}xrv${none} | 外部识别 IP: ${yellow}$(_get_ip 2>/dev/null || echo "探测异常")${none}"
        echo -e "  系统装配内核: ${cyan}${sys_ver}${none} | 微架构侦测: x64-v${yellow}${arch_level}${none} | qdisc/cc: ${yellow}${qdisc}/${cc}${none} | BBR配置:${yellow}${bbr_cfg}${none}"
        echo -e "  DNS模式: ${cyan}${dns_mode}${none} | 时间轴: ${cyan}${tz_line}${none} | notsent: ${yellow}${notsent_now}${none}/${cyan}${notsent_perm}${none} | adv/app: ${yellow}${adv}/${app}${none}"
        echo -e "${blue}======================================================================${none}"
        echo "  1) 创建/重构协议节点：Reality Vision / VLESSENC 自选 / SS2022"
        echo "  2) 用户凭证生命周期与独立参数化管理控制"
        echo "  3) 节点链接与多维信息输出聚合中心"
        echo "  4) 人工发起数据强联，执行路由解析规则库强制覆盖更新"
        echo "  5) Xray Core 手动更新/修复（不设置自动更新）"
        echo "  6) 修改或全自动剔除被拦截的防封伪装特征矩阵域名"
        echo "  7) 系统防火墙策略配置 (阻止内网 BT 滥用及第三方广告请求)"
        echo "  8) Reality Fallback 底层限速沙盒分析器"
        echo "  9) 全景网络连接审计日志与商用级别网络流量记账本"
        echo "  10) 高级发烧：内核双轨编译(APT/源码)/网络/应用层 60余项极限全控板"
        echo -e "  ${cyan}11) 从旧 ex198e 环境稳态热更新到 V198e90${none}"
        echo -e "  ${cyan}12) 清理空间（安全释放 / 快照收敛 / 显示硬盘与 Swap）${none}"
        echo -e "  ${cyan}13) 应用网络参数（缓冲/notsent/adv_win/app_win/txqueue/OOOX/MSS）${none}"
        echo -e "  ${cyan}14) TCP 重传 / 单连接诊断中心（只读排障）${none}"
        echo -e "  ${cyan}15) 检查现有配置并重新输出节点${none}"
        echo -e "  ${cyan}16) 状态隔离审计 + VLESSENC 能力检查${none}"
        echo -e "  ${magenta}17) BBR 本体替换 / 自定义编译中心（模块型m/内置型y双路线）${none}"
        echo "  0) 折叠命令控制台，返回底层终端"
        echo -e "  ${red}88) 物理不可逆自毁！撤销环境安全防线与系统配置设定${none}"
        hr
        local num=""
        read -rp "请输入操作代码指令: " num || true
        case "${num:-}" in
            1) do_install ;;
            2) do_user_manager ;;
            3) do_summary; while true; do local rb=""; read -rp "输出完毕，按 Enter 退出或者按 b 发起特征替换: " rb || true; if test "$rb" = "b" || test "$rb" = "B"; then if choose_sni; then _update_matrix; do_summary; else break; fi; else break; fi; done ;;
            4) print_magenta ">>> 初始化云网络联通..."; bash "$UPDATE_DAT_SCRIPT" >/dev/null 2>&1 || true; ensure_xray_is_alive; info "配置已穿透替换系统！当前路由库完成热加载！"; local _p=""; read -rp "按 Enter 退回..." _p || true ;;
            5) do_update_core ;;
            6) if choose_sni; then _update_matrix; do_summary; while true; do local rb=""; read -rp "任务完毕，按 Enter 返回，或按 b 连续变更: " rb || true; if test "$rb" = "b" || test "$rb" = "B"; then if choose_sni; then _update_matrix; do_summary; else break; fi; else break; fi; done; fi ;;
            7) _global_block_rules ;;
            8) do_fallback_probe ;;
            9) do_status_menu ;;
            10) do_sys_init_menu ;;
            11) hot_update_from_legacy ;;
            12) do_space_cleanup_menu ;;
            13) do_network_params_menu_e56 ;;
            14) do_tcp_diag_menu_e63 ;;
            15) do_install_repair_e77 ;;
            16) e77_audit_runtime_state; _e52_pause ;;
            17) do_bbr_body_replace_menu_e89 ;;
            88) do_uninstall ;;
            0) exit 0 ;;
            *) echo -e "${red}错误拦截：代码解析为空值！${none}"; sleep 1 ;;
        esac
    done
}



#==============================================================================
# V198e91 FINAL OVERRIDE LAYER
# 目标：
#   1) 审计并修复 e90 内置型 BBR 编译路线：确认后不再被旧源码门禁二次拦截。
#   2) BBR 源码补丁改为 fail-fast：源码类型不匹配/参数未命中/缺 scripts/config 时拒绝浪费编译时间。
#   3) BBR 自定义参数输入继续内联显示“参数 / 原版 / 建议 / 说明”。
#   4) 11 热更新升级为 V198e91，并写入 ex198e91/latest。
#==============================================================================

# 保存 e90 关键函数，便于 e91 包装调用。
if declare -F hot_update_from_legacy >/dev/null 2>&1; then
    eval "$(declare -f hot_update_from_legacy | sed '1s/hot_update_from_legacy/hot_update_from_legacy_e90_base/')"
fi
if declare -F _e90_build_builtin_bbr_kernel >/dev/null 2>&1; then
    eval "$(declare -f _e90_build_builtin_bbr_kernel | sed '1s/_e90_build_builtin_bbr_kernel/_e91_build_builtin_bbr_kernel_e90_base/')"
fi

_e91_pause() { local _p=""; read -rp "按 Enter 继续..." _p || true; }

_e91_bbr_compile_mode_text() {
    local cfgv
    cfgv="$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)"
    case "$cfgv" in
        m) echo "模块型 m：使用 tcp_bbr.ko 同名热替换，通常无需重启" ;;
        y) echo "内置型 y：补丁 net/ipv4/tcp_bbr.c 并完整编译内核，必须重启后生效" ;;
        *) echo "未知：请先执行自动检测，禁止盲改" ;;
    esac
}

_e91_kernel_source_kind() {
    local f="$1"
    if grep -Eq 'bbr_inflight_headroom|bbr_bw_probe_max_rounds|bbr_probe_rtt_win_ms|bbr_startup_pacing_gain|bbr_beta' "$f" 2>/dev/null; then
        echo "bbr3"
    else
        echo "bbrv1"
    fi
}

_e91_conf_sane() {
    local conf="$1" kind="$2"
    test -f "$conf" || { error "配置文件不存在：$conf"; return 1; }
    if ! grep -q '^BBR_TYPE=' "$conf" 2>/dev/null; then
        error "配置文件缺少 BBR_TYPE：$conf"
        return 1
    fi
    case "$kind" in
        bbr3)
            grep -q '^BBR_STARTUP_PACING_GAIN=' "$conf" 2>/dev/null || { error "BBR3 配置缺少 BBR_STARTUP_PACING_GAIN。"; return 1; }
            grep -q '^BBR_LOSS_THRESH_PERMILLE=' "$conf" 2>/dev/null || { error "BBR3 配置缺少 BBR_LOSS_THRESH_PERMILLE。"; return 1; }
            ;;
        bbrv1)
            grep -q '^BBR_HIGH_GAIN=' "$conf" 2>/dev/null || { error "BBR v1 配置缺少 BBR_HIGH_GAIN。"; return 1; }
            grep -q '^BBR_PACING_GAIN_0=' "$conf" 2>/dev/null || { error "BBR v1 配置缺少 BBR_PACING_GAIN_0。"; return 1; }
            ;;
        *) error "未知 BBR 参数模板：$kind"; return 1 ;;
    esac
    return 0
}

_e91_verify_patch_hit() {
    local src="$1" conf="$2" kind="$3"
    # shellcheck disable=SC1090
    source "$conf"
    if test "$kind" = "bbr3"; then
        grep -Eq "bbr_cwnd_gain[[:space:]]*=[[:space:]]*BBR_UNIT[[:space:]]*\*[[:space:]]*$BBR_CWND_GAIN[[:space:]]*/[[:space:]]*100" "$src" || return 1
        grep -Eq "bbr_loss_thresh[[:space:]]*=[[:space:]]*BBR_UNIT[[:space:]]*\*[[:space:]]*$BBR_LOSS_THRESH_PERMILLE[[:space:]]*/[[:space:]]*1000" "$src" || return 1
        grep -Eq "bbr_inflight_headroom[[:space:]]*=[[:space:]]*BBR_UNIT[[:space:]]*\*[[:space:]]*$BBR_INFLIGHT_HEADROOM[[:space:]]*/[[:space:]]*100" "$src" || return 1
    else
        grep -Eq "bbr_high_gain[[:space:]]*=[[:space:]]*BBR_UNIT[[:space:]]*\*[[:space:]]*$BBR_HIGH_GAIN[[:space:]]*/[[:space:]]*100" "$src" || return 1
        grep -Eq "bbr_cwnd_gain[[:space:]]*=[[:space:]]*BBR_UNIT[[:space:]]*\*[[:space:]]*$BBR_CWND_GAIN[[:space:]]*/[[:space:]]*100" "$src" || return 1
        grep -Eq "BBR_UNIT[[:space:]]*\*[[:space:]]*$BBR_PACING_GAIN_0[[:space:]]*/[[:space:]]*100" "$src" || return 1
    fi
    return 0
}

_e90_kernel_patch_before_compile() {
    local ksrc="net/ipv4/tcp_bbr.c"
    local conf="${E91_BBR_KERNEL_CONF:-${E90_BBR_KERNEL_CONF:-}}"
    local kind="${E91_BBR_KERNEL_KIND:-${E90_BBR_KERNEL_KIND:-}}"
    local bdir="${E91_BBR_KERNEL_BACKUP:-${E90_BBR_KERNEL_BACKUP:-}}"
    local detected before after

    test -n "$conf" || return 0
    test -n "$kind" || return 0
    _e91_conf_sane "$conf" "$kind" || return 1

    if test ! -f "$ksrc"; then
        error "当前源码树未发现 $ksrc，拒绝继续编译，避免生成未注入参数的新内核。"
        return 1
    fi
    if test ! -x ./scripts/config; then
        error "当前源码树缺少 ./scripts/config，拒绝继续编译，避免 Kconfig 未正确写入。"
        return 1
    fi

    detected="$(_e91_kernel_source_kind "$ksrc")"
    if test "$detected" != "$kind" && test "${XRAY_BBRX_ALLOW_KIND_MISMATCH:-0}" != "1"; then
        error "源码类型与参数模板不匹配：源码=$detected，配置=$kind。"
        warn "如确实要强制交叉注入，请设置 XRAY_BBRX_ALLOW_KIND_MISMATCH=1 后重试；默认拒绝浪费编译时间。"
        return 1
    fi

    info "V198e91：正在注入 BBR 参数：kind=$kind source=$ksrc conf=$conf"
    before="$(sha256sum "$ksrc" 2>/dev/null | awk '{print $1}')"
    if test -n "$bdir" && test -d "$bdir"; then
        cp -af "$ksrc" "$bdir/tcp_bbr.c.kernel.before_patch" 2>/dev/null || true
    fi

    _e89_patch_bbr_source_from_conf "$ksrc" "$conf" "$kind"

    if ! _e91_verify_patch_hit "$ksrc" "$conf" "$kind"; then
        error "BBR 参数补丁未命中关键字段，拒绝继续编译。"
        warn "请检查当前源码是否真为 $kind，或改用推荐的 BBR 参数模板。"
        return 1
    fi

    after="$(sha256sum "$ksrc" 2>/dev/null | awk '{print $1}')"
    if test "$before" = "$after" && test "${XRAY_BBRX_ALLOW_NOOP_PATCH:-0}" != "1"; then
        warn "tcp_bbr.c 哈希未变化，可能源码已是同一组参数。默认继续写入 Kconfig，但建议确认不是重复编译。"
    fi

    if test -n "$bdir" && test -d "$bdir"; then
        cp -af "$ksrc" "$bdir/tcp_bbr.c.kernel.after_patch" 2>/dev/null || true
        diff -u "$bdir/tcp_bbr.c.kernel.before_patch" "$bdir/tcp_bbr.c.kernel.after_patch" > "$bdir/tcp_bbr.c.kernel.patch.diff" 2>/dev/null || true
    fi

    ./scripts/config --enable CONFIG_TCP_CONG_BBR 2>/dev/null || true
    ./scripts/config --enable CONFIG_DEFAULT_BBR 2>/dev/null || true
    if test "$kind" = "bbr3"; then ./scripts/config --enable CONFIG_TCP_BBR3 2>/dev/null || true; fi
    ./scripts/config --set-str CONFIG_DEFAULT_TCP_CONG "bbr" 2>/dev/null || true
    ./scripts/config --set-str CONFIG_LOCALVERSION "-bbrx91" 2>/dev/null || true

    if ! make olddefconfig >/dev/null 2>&1; then
        error "make olddefconfig 失败，拒绝继续编译。"
        return 1
    fi

    info "V198e91：BBR 本体参数与 Kconfig 已注入源码，后续 make install 安装新内核，重启后生效。"
    return 0
}

# 源码编译入口：BBR 内置替换任务已完成一次强确认时，不再被旧门禁要求手动 export。
_compile_kernel_xanmod() {
    if test -n "${E91_BBR_KERNEL_CONF:-${E90_BBR_KERNEL_CONF:-}}"; then
        export XRAY_ALLOW_SOURCE_KERNEL_COMPILE=1
        _compile_kernel_xanmod_legacy_e53
    else
        _kernel_source_gate_e53 || return 0
        _compile_kernel_xanmod_legacy_e53
    fi
}

_compile_kernel_mainline() {
    if test -n "${E91_BBR_KERNEL_CONF:-${E90_BBR_KERNEL_CONF:-}}"; then
        export XRAY_ALLOW_SOURCE_KERNEL_COMPILE=1
        _compile_kernel_mainline_legacy_e53 "${1:-bbr3}"
    else
        _kernel_source_gate_e53 || return 0
        _compile_kernel_mainline_legacy_e53 "${1:-bbr3}"
    fi
}

_e90_build_builtin_bbr_kernel() {
    local kind="$1" conf="$2" bdir confirm route recommended alt bbr_arg old_allow rc
    title "V198e91：内置型 BBR 源码补丁 + 完整内核编译路线"
    warn "当前 CONFIG_TCP_CONG_BBR=y：BBR 编进内核，不存在 tcp_bbr.ko 可热替换。"
    warn "正确路线：补丁 net/ipv4/tcp_bbr.c → 完整编译安装新内核 → 重启后生效。"
    warn "旧内核会保留；请确保有 VPS 快照 / VNC / 救援模式。"
    echo ""
    echo "  当前配置文件：$conf"
    echo "  参数模板：$kind"
    echo "  自动建议：$(_e89_bbr_recommend_kind 2>/dev/null || echo unknown)"
    echo ""
    _e91_conf_sane "$conf" "$kind" || return 1
    if declare -F _kernel_source_precheck_e52 >/dev/null 2>&1; then
        _kernel_source_precheck_e52 || { error "源码编译资源门槛未通过。"; return 1; }
    fi
    read -rp "确认已有快照/VNC/救援模式，并开始完整内核编译？输入 YES 继续: " confirm || true
    if test "$confirm" != "YES"; then warn "已取消内置型 BBR 编译。"; return 1; fi

    bdir="$(_e89_bbr_backup_state)" || { error "备份失败，拒绝继续。"; return 1; }
    _e89_bbr_write_original_param_note "$bdir" "$kind"
    cp -af "$conf" "$bdir/generated_new_params.conf" 2>/dev/null || true
    info "已创建编译前完整备份：$bdir"

    export E91_BBR_KERNEL_KIND="$kind"
    export E91_BBR_KERNEL_CONF="$conf"
    export E91_BBR_KERNEL_BACKUP="$bdir"
    export E90_BBR_KERNEL_KIND="$kind"
    export E90_BBR_KERNEL_CONF="$conf"
    export E90_BBR_KERNEL_BACKUP="$bdir"

    if test "$kind" = "bbr3" || uname -r 2>/dev/null | grep -qiE 'xanmod|bbr3'; then
        recommended="xanmod"; alt="mainline"
    else
        recommended="mainline"; alt="xanmod"
    fi
    echo ""
    echo -e "  ${cyan}1) 源码编译 ${recommended}，并注入当前 BBR 参数 ${none}(推荐)"
    echo -e "  ${yellow}2) 源码编译 ${alt}，并注入当前 BBR 参数${none}"
    echo "  0) 取消"
    read -rp "请选择编译路线 (默认 1): " route || true
    route="${route:-1}"
    case "$route" in
        1) route="$recommended" ;;
        2) route="$alt" ;;
        0) warn "已取消。"; unset E91_BBR_KERNEL_KIND E91_BBR_KERNEL_CONF E91_BBR_KERNEL_BACKUP E90_BBR_KERNEL_KIND E90_BBR_KERNEL_CONF E90_BBR_KERNEL_BACKUP; return 1 ;;
        *) warn "无效选择，已取消。"; unset E91_BBR_KERNEL_KIND E91_BBR_KERNEL_CONF E91_BBR_KERNEL_BACKUP E90_BBR_KERNEL_KIND E90_BBR_KERNEL_CONF E90_BBR_KERNEL_BACKUP; return 1 ;;
    esac

    bbr_arg="bbr"
    test "$kind" = "bbr3" && bbr_arg="bbr3"
    old_allow="${XRAY_ALLOW_SOURCE_KERNEL_COMPILE:-}"
    export XRAY_ALLOW_SOURCE_KERNEL_COMPILE=1
    rc=0
    case "$route" in
        xanmod) _compile_kernel_xanmod || rc=$? ;;
        mainline) _compile_kernel_mainline "$bbr_arg" || rc=$? ;;
    esac
    if test -n "$old_allow"; then export XRAY_ALLOW_SOURCE_KERNEL_COMPILE="$old_allow"; else unset XRAY_ALLOW_SOURCE_KERNEL_COMPILE; fi
    unset E91_BBR_KERNEL_KIND E91_BBR_KERNEL_CONF E91_BBR_KERNEL_BACKUP E90_BBR_KERNEL_KIND E90_BBR_KERNEL_CONF E90_BBR_KERNEL_BACKUP

    if test "$rc" -ne 0; then
        error "内置型 BBR 源码编译/安装流程未完成。备份目录：$bdir"
        return "$rc"
    fi
    info "V198e91：内置型 BBR 源码编译流程结束。请重启后验证 uname -r 与 ss -tin。"
    return 0
}

_e89_build_replace_bbr() {
    local kind="$1" conf="$2" cfgv
    cfgv="$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)"
    case "$cfgv" in
        m)
            if declare -F _e90_build_replace_bbr_module_base >/dev/null 2>&1; then
                _e90_build_replace_bbr_module_base "$kind" "$conf"
            else
                error "未找到模块型 BBR 替换基线函数。"
                return 1
            fi
            ;;
        y)
            _e90_build_builtin_bbr_kernel "$kind" "$conf"
            ;;
        *)
            error "当前 CONFIG_TCP_CONG_BBR=$cfgv，无法判断替换路线。"
            warn "请执行 17 → 1 自动检测，或先安装/编译支持 BBR 的内核。"
            return 1
            ;;
    esac
}

_e91_bbrv1_flow() {
    local m conf go
    while true; do
        title "V198e91：普通 Linux 主线 BBR v1 → bbrx_v1 参数中心"
        echo "  当前替换路线：$(_e91_bbr_compile_mode_text)"
        echo ""
        echo "  1) 查看参数表：参数 / 原版 BBR / bbrx_v1 建议 / 说明"
        echo "  2) 使用 bbrx_v1 推荐参数生成配置"
        echo "  3) 自定义全部参数并生成配置（输入时同步显示参数表字段，?=完整表）"
        echo "  4) 使用当前配置替换 bbr（m=模块热替换；y=整内核编译）"
        echo "  0) 返回"
        read -rp "请选择: " m || true
        case "${m:-}" in
            1) _e89_show_bbrv1_table; _e91_pause ;;
            2) _e89_collect_bbrv1_params recommended || return; conf="$(_e89_write_bbrv1_conf)"; info "已写入：$conf"; read -rp "是否立即替换 bbr？[y/N]: " go || true; [[ "$go" =~ ^[yY]$ ]] && _e89_build_replace_bbr bbrv1 "$conf"; _e91_pause ;;
            3) _e89_collect_bbrv1_params custom || return; conf="$(_e89_write_bbrv1_conf)"; info "已写入：$conf"; read -rp "是否立即替换 bbr？[y/N]: " go || true; [[ "$go" =~ ^[yY]$ ]] && _e89_build_replace_bbr bbrv1 "$conf"; _e91_pause ;;
            4) conf="$E89_BBRX_CURRENT/bbrv1_replace.conf"; if test -f "$conf"; then _e89_build_replace_bbr bbrv1 "$conf"; else warn "配置不存在，请先执行 2 或 3。"; fi; _e91_pause ;;
            0) return ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

_e91_bbr3_flow() {
    local m conf go
    while true; do
        title "V198e91：BBR3 / XanMod → bbrx3_v1 参数中心"
        echo "  当前替换路线：$(_e91_bbr_compile_mode_text)"
        echo ""
        echo "  1) 查看参数表：参数 / 原版 BBR3 / bbrx3_v1 建议 / 说明"
        echo "  2) 使用 bbrx3_v1 推荐参数生成配置"
        echo "  3) 自定义全部参数并生成配置（输入时同步显示参数表字段，?=完整表）"
        echo "  4) 使用当前配置替换 bbr（m=模块热替换；y=整内核编译）"
        echo "  0) 返回"
        read -rp "请选择: " m || true
        case "${m:-}" in
            1) _e89_show_bbr3_table; _e91_pause ;;
            2) _e89_collect_bbr3_params recommended || return; conf="$(_e89_write_bbr3_conf)"; info "已写入：$conf"; read -rp "是否立即替换 bbr？[y/N]: " go || true; [[ "$go" =~ ^[yY]$ ]] && _e89_build_replace_bbr bbr3 "$conf"; _e91_pause ;;
            3) _e89_collect_bbr3_params custom || return; conf="$(_e89_write_bbr3_conf)"; info "已写入：$conf"; read -rp "是否立即替换 bbr？[y/N]: " go || true; [[ "$go" =~ ^[yY]$ ]] && _e89_build_replace_bbr bbr3 "$conf"; _e91_pause ;;
            4) conf="$E89_BBRX_CURRENT/bbr3_replace.conf"; if test -f "$conf"; then _e89_build_replace_bbr bbr3 "$conf"; else warn "配置不存在，请先执行 2 或 3。"; fi; _e91_pause ;;
            0) return ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

do_bbr_body_replace_menu_e89() {
    _e89_bbr_prepare_dirs
    local opt rec
    while true; do
        rec="$(_e89_bbr_recommend_kind)"
        title "V198e91：BBR 本体替换 / 自定义编译中心"
        echo "  自动建议：$(test "$rec" = "bbr3" && echo "BBR3 / XanMod → bbrx3_v1" || echo "普通 Linux 主线 BBR v1 → bbrx_v1")"
        echo "  当前替换路线：$(_e91_bbr_compile_mode_text)"
        echo ""
        echo "  1) 自动检测当前 BBR 类型，并推荐编译方案"
        echo "  2) 普通 Linux 主线 BBR v1 → 自定义全部参数 → 替换 bbr"
        echo "  3) BBR3 / XanMod → 自定义全部参数 → 替换 bbr"
        echo "  4) 查看已备份的原版 BBR / 系统 TCP 设置"
        echo "  5) 无损切换回最近一次编译前 BBR / 或旧内核 GRUB 回滚提示"
        echo "  6) 查看当前拥塞控制 / qdisc / BBR 状态"
        echo "  0) 返回主菜单"
        read -rp "请选择: " opt || true
        case "${opt:-}" in
            1) _e89_bbr_detect; _e91_pause ;;
            2) _e91_bbrv1_flow ;;
            3) _e91_bbr3_flow ;;
            4) _e89_bbr_show_backups; _e91_pause ;;
            5) _e89_bbr_rollback_latest || warn "如果本次是内置型整内核编译，请通过云厂商 VNC/GRUB 选择旧内核回滚。"; _e91_pause ;;
            6) _e89_bbr_status; _e91_pause ;;
            0) return ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

hot_update_from_legacy() {
    title "V198e91：稳态热更新（e90 审计修复 + BBR 双路线稳态化）"
    if declare -F hot_update_from_legacy_e90_base >/dev/null 2>&1; then
        hot_update_from_legacy_e90_base "$@" || true
    fi
    mkdir -p "$E89_BBRX_ROOT" "$E89_BBRX_CURRENT" "$E89_BBRX_BACKUP_ROOT" "$E89_BBRX_BUILD_ROOT" 2>/dev/null || true
    echo "198e91" > "$SCRIPT_VERSION_FILE" 2>/dev/null || true
    if test -f "${SCRIPT_PATH:-$0}"; then
        cp -f "${SCRIPT_PATH:-$0}" "$SYMLINK" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e91.sh" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
        chmod +x "$SYMLINK" "$SCRIPT_DIR/ex198e91.sh" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
    fi
    info "V198e91 热更新完成：修复内置型 BBR 编译二次门禁、参数补丁 fail-fast、版本/菜单标识。"
    info "进入：xrv → 17。CONFIG_TCP_CONG_BBR=m 走模块热替换；=y 走完整内核源码补丁编译。"
}

