}


#==============================================================================
# V198e92 FINAL OVERRIDE LAYER
# 目标：
#   1) e91 作为基线，不重构大框架，只做尾部覆盖增量。
#   2) 吸收旧脚本思想：CONFIG_VIRTIO 防砖检查、/boot 空间检查、initramfs/boot 校验、jq 安全写入规范。
#   3) SNI 只做 Top20 重新测速，不默认全量扫。
#   4) 增加 JSON 配置写入审计器、服务状态雷达增强、硬件能力自适应剥离审计。
#   5) netot / tc 带宽控制、ex188t45、ex62、ex55、g7g50x12、41/40 系列暂不并入。
#==============================================================================

# 保存 e91 最终函数，e92 仅在外层接管。
if declare -F hot_update_from_legacy >/dev/null 2>&1 && ! declare -F hot_update_from_legacy_e91_base >/dev/null 2>&1; then
    eval "$(declare -f hot_update_from_legacy | sed '1s/hot_update_from_legacy/hot_update_from_legacy_e91_base/')"
fi
if declare -F _execute_compilation >/dev/null 2>&1 && ! declare -F _execute_compilation_e91_base >/dev/null 2>&1; then
    eval "$(declare -f _execute_compilation | sed '1s/_execute_compilation/_execute_compilation_e91_base/')"
fi
if declare -F _e90_kernel_patch_before_compile >/dev/null 2>&1 && ! declare -F _e90_kernel_patch_before_compile_e91_base >/dev/null 2>&1; then
    eval "$(declare -f _e90_kernel_patch_before_compile | sed '1s/_e90_kernel_patch_before_compile/_e90_kernel_patch_before_compile_e91_base/')"
fi

E92_AUDIT_DIR="${CONFIG_DIR}/audit_e92"
E92_JSON_AUDIT_DIR="${E92_AUDIT_DIR}/json"
E92_BOOT_AUDIT_DIR="${E92_AUDIT_DIR}/boot"
E92_HW_AUDIT_DIR="${E92_AUDIT_DIR}/hardware"
E92_SNI_AUDIT_DIR="${E92_AUDIT_DIR}/sni"
E92_SERVICE_AUDIT_DIR="${E92_AUDIT_DIR}/service"

_e92_pause() {
    if declare -F _e91_pause >/dev/null 2>&1; then _e91_pause; else local _p=""; read -rp "按 Enter 继续..." _p || true; fi
}

_e92_ts() { date +%Y%m%d_%H%M%S; }

_e92_prepare_dirs() {
    mkdir -p "$E92_AUDIT_DIR" "$E92_JSON_AUDIT_DIR" "$E92_BOOT_AUDIT_DIR" "$E92_HW_AUDIT_DIR" "$E92_SNI_AUDIT_DIR" "$E92_SERVICE_AUDIT_DIR" "$LOG_DIR" 2>/dev/null || true
}

_e92_int_or_zero() {
    local v="${1:-0}"
    if [[ "$v" =~ ^[0-9]+$ ]]; then echo "$v"; else echo 0; fi
}

_e92_json_count() {
    local file="$1" expr="$2"
    jq -r "$expr" "$file" 2>/dev/null | head -n1 | awk '{if($0 ~ /^[0-9]+$/) print $0; else print 0}' 2>/dev/null || echo 0
}

_e92_xray_test_config() {
    local target_config="$1"
    if declare -F verify_xray_config >/dev/null 2>&1; then
        verify_xray_config "$target_config"
        return $?
    fi
    if test ! -s "$target_config"; then error "配置文件为空或不存在：$target_config"; return 1; fi
    jq empty "$target_config" >/dev/null 2>&1 || { error "配置文件不是合法 JSON：$target_config"; return 1; }
    if test -x "$XRAY_BIN"; then
        "$XRAY_BIN" run -test -config "$target_config" >/dev/null 2>&1 || "$XRAY_BIN" -test -config "$target_config" >/dev/null 2>&1 || return 1
    fi
    return 0
}

_e92_json_meta_line() {
    local f="$1"
    local inb outb clients reality
    inb=$(_e92_json_count "$f" '(.inbounds // []) | length')
    outb=$(_e92_json_count "$f" '(.outbounds // []) | length')
    clients=$(_e92_json_count "$f" '[.inbounds[]? | select(.protocol=="vless") | .settings.clients[]?] | length')
    reality=$(_e92_json_count "$f" '[.inbounds[]? | select(.protocol=="vless") | .streamSettings.realitySettings.serverNames[]?] | length')
    echo "inbounds=$inb outbounds=$outb vless_clients=$clients reality_serverNames=$reality"
}

# V198e92：覆盖安全 jq 写入函数，加入结构审计、diff 摘要、数量防回退。
_safe_jq_write() {
    test -f "$CONFIG" || { error "未找到配置文件：$CONFIG"; return 1; }
    _e92_prepare_dirs
    backup_config

    local ts bdir tmp err before_meta after_meta before_in after_in before_out after_out before_clients after_clients
    ts="$(_e92_ts)"
    bdir="$E92_JSON_AUDIT_DIR/$ts"
    mkdir -p "$bdir" 2>/dev/null || true
    tmp=$(mktemp /tmp/xray.e92.safejq.XXXXXX.json) || return 1
    err="$bdir/jq.err"

    cp -a "$CONFIG" "$bdir/config.before.json" 2>/dev/null || true
    before_meta="$(_e92_json_meta_line "$CONFIG")"
    echo "before: $before_meta" > "$bdir/meta.txt"

    set +e
    jq "$@" "$CONFIG" > "$tmp" 2>"$err"
    local jq_res=$?
    set -e

    if test "$jq_res" -ne 0 || test ! -s "$tmp"; then
        error "V198e92 JSON 写入审计：jq 修改失败或输出为空，拒绝覆盖。"
        sed 's/^/    /' "$err" 2>/dev/null || true
        rm -f "$tmp" 2>/dev/null || true
        restore_latest_backup >/dev/null 2>&1 || true
        return 1
    fi

    if ! jq empty "$tmp" >/dev/null 2>&1; then
        error "V198e92 JSON 写入审计：jq 产物不是合法 JSON，拒绝覆盖。"
        rm -f "$tmp" 2>/dev/null || true
        restore_latest_backup >/dev/null 2>&1 || true
        return 1
    fi

    before_in=$(_e92_json_count "$CONFIG" '(.inbounds // []) | length')
    after_in=$(_e92_json_count "$tmp" '(.inbounds // []) | length')
    before_out=$(_e92_json_count "$CONFIG" '(.outbounds // []) | length')
    after_out=$(_e92_json_count "$tmp" '(.outbounds // []) | length')
    before_clients=$(_e92_json_count "$CONFIG" '[.inbounds[]? | select(.protocol=="vless") | .settings.clients[]?] | length')
    after_clients=$(_e92_json_count "$tmp" '[.inbounds[]? | select(.protocol=="vless") | .settings.clients[]?] | length')

    before_in=$(_e92_int_or_zero "$before_in"); after_in=$(_e92_int_or_zero "$after_in")
    before_out=$(_e92_int_or_zero "$before_out"); after_out=$(_e92_int_or_zero "$after_out")
    before_clients=$(_e92_int_or_zero "$before_clients"); after_clients=$(_e92_int_or_zero "$after_clients")

    if test "$before_in" -gt 0 && test "$after_in" -lt "$before_in"; then
        error "V198e92 JSON 写入审计：inbounds 数量减少 ${before_in}→${after_in}，疑似误擦配置，拒绝覆盖。"
        cp -a "$tmp" "$bdir/config.rejected.json" 2>/dev/null || true
        rm -f "$tmp" 2>/dev/null || true
        restore_latest_backup >/dev/null 2>&1 || true
        return 1
    fi
    if test "$before_out" -gt 0 && test "$after_out" -lt "$before_out"; then
        error "V198e92 JSON 写入审计：outbounds 数量减少 ${before_out}→${after_out}，疑似误擦配置，拒绝覆盖。"
        cp -a "$tmp" "$bdir/config.rejected.json" 2>/dev/null || true
        rm -f "$tmp" 2>/dev/null || true
        restore_latest_backup >/dev/null 2>&1 || true
        return 1
    fi
    if test "$before_clients" -gt 0 && test "$after_clients" -lt "$before_clients"; then
        error "V198e92 JSON 写入审计：VLESS 用户数减少 ${before_clients}→${after_clients}，疑似误删用户，拒绝覆盖。"
        cp -a "$tmp" "$bdir/config.rejected.json" 2>/dev/null || true
        rm -f "$tmp" 2>/dev/null || true
        restore_latest_backup >/dev/null 2>&1 || true
        return 1
    fi

    if ! _e92_xray_test_config "$tmp"; then
        error "V198e92 JSON 写入审计：Xray 核心测试失败，拒绝覆盖。"
        cp -a "$tmp" "$bdir/config.rejected.json" 2>/dev/null || true
        rm -f "$tmp" 2>/dev/null || true
        restore_latest_backup >/dev/null 2>&1 || true
        return 1
    fi

    after_meta="$(_e92_json_meta_line "$tmp")"
    echo "after:  $after_meta" >> "$bdir/meta.txt"
    diff -u "$CONFIG" "$tmp" > "$bdir/config.diff" 2>/dev/null || true
    cp -a "$tmp" "$bdir/config.after.json" 2>/dev/null || true

    mv -f "$tmp" "$CONFIG"
    fix_permissions
    info "V198e92 JSON 写入审计通过：$bdir"
    return 0
}

do_json_config_audit_e92() {
    _e92_prepare_dirs
    title "V198e92：JSON 配置写入审计器"
    if test ! -f "$CONFIG"; then error "未找到配置文件：$CONFIG"; _e92_pause; return 1; fi
    echo "配置路径：$CONFIG"
    echo "文件权限：$(stat -c '%a %U:%G' "$CONFIG" 2>/dev/null || echo unknown)"
    echo "文件大小：$(wc -c < "$CONFIG" 2>/dev/null || echo 0) bytes"
    echo ""
    if jq empty "$CONFIG" >/dev/null 2>&1; then info "JSON 语法：通过"; else error "JSON 语法：失败"; fi
    if _e92_xray_test_config "$CONFIG"; then info "Xray 配置测试：通过"; else error "Xray 配置测试：失败"; fi
    echo ""
    echo "结构摘要：$(_e92_json_meta_line "$CONFIG")"
    echo ""
    echo "Inbound 概览："
    jq -r '.inbounds[]? | "  tag=\(.tag // "-") protocol=\(.protocol // "-") listen=\(.listen // "-") port=\(.port // "-")"' "$CONFIG" 2>/dev/null || true
    echo ""
    echo "Outbound 概览："
    jq -r '.outbounds[]? | "  tag=\(.tag // "-") protocol=\(.protocol // "-")"' "$CONFIG" 2>/dev/null || true
    _e92_pause
}

