run_sni_top20_rescan_e92() {
    title "V198e92：Top 20 SNI 重新测速（不全量扫）"
    _e92_prepare_dirs
    _e92_seed_sni_cache_if_empty

    if test ! -s "$SNI_CACHE_FILE"; then
        error "SNI Top20 缓存为空，无法复测。"
        return 1
    fi

    local tmp old_backup sni old_ms old_type time_raw ms key
    tmp=$(mktemp /tmp/sni_top20_e92.XXXXXX) || return 1
    old_backup="$E92_SNI_AUDIT_DIR/sni_cache.before.$(_e92_ts).txt"
    cp -a "$SNI_CACHE_FILE" "$old_backup" 2>/dev/null || true

    echo "仅复测当前缓存前 20 个 SNI，不触发 130+ 全量扫描。"
    echo ""
    while read -r sni old_ms old_type; do
        test -n "${sni:-}" || continue
        valid_domain "$sni" || continue
        key=""
        if read -t 0.05 -n 1 -s key 2>/dev/null; then
            echo -e "\n${yellow}已手动中止，整理已测结果。${none}"
            break
        fi
        set +e
        time_raw=$(LC_ALL=C curl -sL -w "%{time_connect}" -o /dev/null --connect-timeout 2 -m 4 "https://$sni" 2>/dev/null || echo "0")
        set -e
        ms=$(echo "$time_raw" | awk '{print int($1 * 1000)}' 2>/dev/null || echo "0")
        if test "${ms:-0}" -gt 0 2>/dev/null; then
            echo -e "  ${green}存活${none} $sni : ${yellow}${ms}ms${none}"
            echo "$ms $sni ${old_type:-NORM}" >> "$tmp"
        else
            echo -e "  ${gray}超时${none} $sni"
        fi
    done < <(head -n 20 "$SNI_CACHE_FILE" 2>/dev/null)

    if test -s "$tmp"; then
        sort -n "$tmp" | awk '{print $2, $1, $3}' > "$SNI_CACHE_FILE"
        info "Top20 复测完成，已更新缓存：$SNI_CACHE_FILE"
        info "旧缓存备份：$old_backup"
    else
        warn "Top20 复测没有成功节点，保留旧缓存。"
    fi
    rm -f "$tmp" 2>/dev/null || true
}

choose_sni() {
    while true; do
        _e92_seed_sni_cache_if_empty
        if test -s "$SNI_CACHE_FILE"; then
            echo -e "\n  ${cyan}【SNI 候选缓存 - Top 20】${none}"
            local idx=1 s t p delay
            while read -r s t p; do
                test -n "${s:-}" || continue
                if [[ "${t:-}" =~ ^[0-9]+$ ]] && test "$t" -lt 999 2>/dev/null; then
                    delay="${t}ms"
                else
                    delay="未测速"
                fi
                printf '  %2d) %-40s (%b%s%b)\n' "$idx" "$s" "$cyan" "$delay" "$none"
                idx=$((idx + 1))
            done < "$SNI_CACHE_FILE"

            echo -e "  ${yellow}r) 重新测速当前 Top 20${none}"
            echo -e "  ${yellow}f) 全量扫描候选域名${none}"
            echo "  m) 多选模式（构建多域名矩阵）"
            echo "  0) 手动输入自定义 SNI"
            echo "  q) 返回上级菜单"

            local sel=""
            read -rp "  请输入对应编号 (默认 1): " sel || true
            sel=${sel:-1}
            case "$sel" in
                q|Q) return 1 ;;
                r|R) run_sni_top20_rescan_e92 || true; continue ;;
                f|F) run_sni_scanner || true; continue ;;
            esac

            if test "$sel" = "m" || test "$sel" = "M"; then
                local m_sel="" i picked
                local -a arr=()
                read -rp "请输入序号（空格分隔，如 1 3 5；all=全部 Top20）: " m_sel || true
                if test "$m_sel" = "all"; then
                    while read -r picked _; do valid_domain "$picked" && arr+=("$picked"); done < "$SNI_CACHE_FILE"
                else
                    for i in $m_sel; do
                        picked=""
                        [[ "$i" =~ ^[0-9]+$ ]] && picked=$(awk "NR==$i {print \$1}" "$SNI_CACHE_FILE" 2>/dev/null || true)
                        test -n "$picked" && valid_domain "$picked" && arr+=("$picked")
                    done
                fi
                test "${#arr[@]}" -gt 0 || { error "未选择到有效 SNI。"; continue; }
                set_sni_json_array "${arr[@]}"
            elif test "$sel" = "0"; then
                local d=""
                read -rp "请输入自定义 SNI 域名: " d || true
                BEST_SNI=${d:-www.microsoft.com}
                valid_domain "$BEST_SNI" || { error "域名格式非法。"; continue; }
                set_sni_json_array "$BEST_SNI"
            else
                local picked=""
                [[ "$sel" =~ ^[0-9]+$ ]] && picked=$(awk "NR==$sel {print \$1}" "$SNI_CACHE_FILE" 2>/dev/null || true)
                test -n "$picked" || { error "输入序号无效。"; continue; }
                valid_domain "$picked" || { error "缓存中的域名格式异常。"; continue; }
                set_sni_json_array "$picked"
            fi

            if verify_sni_strict "$BEST_SNI"; then
                print_green ">>> 质检完毕，目标域名特征合规。"
                break
            fi
            local force_use=""
            warn "该域名 TLS/SNI/ALPN 特征不完整。"
            read -rp "是否强制使用？(y/N): " force_use || true
            [[ "$force_use" =~ ^[yY]$ ]] && break
        else
            warn "SNI 缓存不存在，先生成候选缓存。"
            _e92_seed_sni_cache_if_empty
        fi
    done
    return 0
}


_e92_kernel_config_file() {
    local krel="${1:-$(uname -r)}"
    if test -f "/boot/config-$krel"; then echo "/boot/config-$krel"; return 0; fi
    if test -f "/proc/config.gz"; then echo "/proc/config.gz"; return 0; fi
    return 1
}

_e92_kernel_config_grep() {
    local cfg="$1" pat="$2"
    if test "$cfg" = "/proc/config.gz"; then
        zgrep -E "$pat" "$cfg" 2>/dev/null || true
    else
        grep -E "$pat" "$cfg" 2>/dev/null || true
    fi
}

e92_boot_kernel_safety_audit() {
    _e92_prepare_dirs
    local ts out cfg krel boot_mp boot_avail root_avail initrd
    ts="$(_e92_ts)"
    out="$E92_BOOT_AUDIT_DIR/boot_kernel_audit_$ts.txt"
    krel="$(uname -r 2>/dev/null || echo unknown)"
    boot_mp="/boot"
    test -d /boot || boot_mp="/"
    boot_avail=$(df -Pm "$boot_mp" 2>/dev/null | awk 'NR==2{print int($4)}' || echo 0)
    root_avail=$(df -Pm / 2>/dev/null | awk 'NR==2{print int($4)}' || echo 0)
    initrd=""

    {
        echo "V198e92 boot/kernel safety audit"
        echo "time=$(date '+%F %T')"
        echo "kernel=$krel"
        echo "boot_mount=$boot_mp"
        echo "boot_available_mb=$boot_avail"
        echo "root_available_mb=$root_avail"
        echo ""
    } > "$out"

    title "V198e92：/boot + initramfs + CONFIG_VIRTIO 防砖检查"
    echo "当前内核：$krel"
    echo "boot 挂载点：$boot_mp，可用 ${boot_avail}MB"
    echo "根分区可用：${root_avail}MB"

    if test "${boot_avail:-0}" -lt 250 2>/dev/null; then
        warn "/boot 可用空间低于 250MB，源码编译/安装新内核前建议清理旧内核。"
        echo "WARN boot space below 250MB" >> "$out"
    else
        info "/boot 空间检查通过。"
        echo "OK boot space" >> "$out"
    fi

    for f in "/boot/initrd.img-$krel" "/boot/initramfs-$krel.img" "/boot/initramfs-${krel}.img"; do
        if test -s "$f"; then initrd="$f"; break; fi
    done
    if test -n "$initrd"; then
        info "initramfs 存在：$initrd"
        echo "OK initramfs=$initrd" >> "$out"
    else
        warn "未发现当前内核 initramfs 文件；若是特殊云内核可忽略，但源码编译前应确认 initramfs 生成逻辑。"
        echo "WARN initramfs missing" >> "$out"
    fi

    cfg="$(_e92_kernel_config_file "$krel" 2>/dev/null || echo "")"
    if test -z "$cfg"; then
        warn "未找到当前内核 config，无法检查 VIRTIO/NVME/XEN/HYPERV 驱动。"
        echo "WARN config missing" >> "$out"
    else
        echo "config=$cfg" >> "$out"
        echo ""
        echo "关键防砖驱动状态："
        local keys key line
        keys="CONFIG_VIRTIO CONFIG_VIRTIO_PCI CONFIG_VIRTIO_BLK CONFIG_VIRTIO_NET CONFIG_SCSI_VIRTIO CONFIG_BLK_DEV_NVME CONFIG_NVME_CORE CONFIG_XEN_BLKDEV_FRONTEND CONFIG_XEN_NETDEV_FRONTEND CONFIG_HYPERV_STORAGE CONFIG_HYPERV_NET"
        for key in $keys; do
            line="$(_e92_kernel_config_grep "$cfg" "^${key}=" | head -n1 || true)"
            if test -n "$line"; then
                echo "  $line"
                echo "$line" >> "$out"
            else
                echo "  ${key}=未发现"
                echo "${key}=missing" >> "$out"
            fi
        done
    fi

    echo ""
    info "审计报告：$out"
}

_e92_kernel_source_boot_space_guard() {
    local boot_mp boot_avail
    boot_mp="/boot"; test -d /boot || boot_mp="/"
    boot_avail=$(df -Pm "$boot_mp" 2>/dev/null | awk 'NR==2{print int($4)}' || echo 0)
    if test "${boot_avail:-0}" -lt 250 2>/dev/null; then
        error "/boot 可用空间仅 ${boot_avail}MB，低于 250MB，拒绝继续源码内核编译，避免 make install / initramfs 半途失败。"
        return 1
    fi
    return 0
}

_e92_kernel_source_config_enforce_boot_safety() {
    if test ! -x ./scripts/config; then return 0; fi
    info "V198e92：注入 VPS 防砖关键 Kconfig（VIRTIO/NVME/XEN/HYPERV + initramfs 友好项）。"
    ./scripts/config --enable CONFIG_VIRTIO 2>/dev/null || true
    ./scripts/config --enable CONFIG_VIRTIO_PCI 2>/dev/null || true
    ./scripts/config --enable CONFIG_VIRTIO_BLK 2>/dev/null || true
    ./scripts/config --enable CONFIG_VIRTIO_NET 2>/dev/null || true
    ./scripts/config --enable CONFIG_SCSI_VIRTIO 2>/dev/null || true
    ./scripts/config --enable CONFIG_BLK_DEV_NVME 2>/dev/null || true
    ./scripts/config --enable CONFIG_NVME_CORE 2>/dev/null || true
    ./scripts/config --enable CONFIG_XEN_BLKDEV_FRONTEND 2>/dev/null || true
    ./scripts/config --enable CONFIG_XEN_NETDEV_FRONTEND 2>/dev/null || true
    ./scripts/config --enable CONFIG_HYPERV_STORAGE 2>/dev/null || true
    ./scripts/config --enable CONFIG_HYPERV_NET 2>/dev/null || true
    ./scripts/config --enable CONFIG_DEVTMPFS 2>/dev/null || true
    ./scripts/config --enable CONFIG_DEVTMPFS_MOUNT 2>/dev/null || true
    return 0
}

_e90_kernel_patch_before_compile() {
    _e92_kernel_source_boot_space_guard || return 1
    _e92_kernel_source_config_enforce_boot_safety || return 1
    if declare -F _e90_kernel_patch_before_compile_e91_base >/dev/null 2>&1; then
        _e90_kernel_patch_before_compile_e91_base "$@" || return 1
    fi
    _e92_kernel_source_config_enforce_boot_safety || return 1
    return 0
}

_e92_post_kernel_install_audit() {
    local ver initrd
    ver=$(make kernelversion 2>/dev/null || echo "")
    test -n "$ver" || return 0
    for f in "/boot/initrd.img-$ver" "/boot/initramfs-$ver.img" "/boot/initramfs-${ver}.img"; do
        if test -s "$f"; then initrd="$f"; break; fi
    done
    if test -n "${initrd:-}"; then
        info "V198e92：新内核 initramfs 检查通过：$initrd"
    else
        warn "V198e92：未发现新内核 $ver 的 initramfs，请在重启前检查 update-initramfs/dracut 输出。"
    fi
}

_execute_compilation() {
    _e92_kernel_source_boot_space_guard || return 1
    if declare -F _execute_compilation_e91_base >/dev/null 2>&1; then
        _execute_compilation_e91_base "$@"
        local rc=$?
        _e92_post_kernel_install_audit || true
        return "$rc"
    fi
    error "未找到 e91 编译基线函数，无法继续。"
    return 1
}

e92_hardware_capability_audit() {
    _e92_prepare_dirs
    local iface out ts
    ts="$(_e92_ts)"
    out="$E92_HW_AUDIT_DIR/hardware_capability_$ts.txt"
    iface=$(ip route get 1.1.1.1 2>/dev/null | awk '{for(i=1;i<=NF;i++) if($i=="dev"){print $(i+1); exit}}' || echo "")
    title "V198e92：硬件能力自适应剥离审计"
    echo "默认出口网卡：${iface:-未知}"
    {
        echo "V198e92 hardware capability audit"
        echo "time=$(date '+%F %T')"
        echo "iface=${iface:-unknown}"
        echo ""
    } > "$out"

    if test -z "$iface"; then
        error "无法识别默认出口网卡。"
        echo "ERROR no default iface" >> "$out"
        _e92_pause
        return 1
    fi

    echo ""
    echo "1) ethtool offload 能力："
    if command -v ethtool >/dev/null 2>&1; then
        ethtool -k "$iface" 2>/dev/null | awk '/tcp-segmentation-offload|generic-segmentation-offload|generic-receive-offload|large-receive-offload|rx-gro-hw|tx-udp-segmentation/ {print "  " $0}' | tee -a "$out" || true
    else
        warn "缺少 ethtool。"
        echo "WARN ethtool missing" >> "$out"
    fi

    echo ""
    echo "2) 队列路径："
    local p found=0
    for p in /sys/class/net/"$iface"/queues/rx-* /sys/class/net/"$iface"/queues/tx-*; do
        if test -d "$p"; then
            found=1
            echo "  $p" | tee -a "$out"
            test -f "$p/rps_cpus" && echo "    rps_cpus=$(cat "$p/rps_cpus" 2>/dev/null)" | tee -a "$out"
            test -f "$p/xps_cpus" && echo "    xps_cpus=$(cat "$p/xps_cpus" 2>/dev/null)" | tee -a "$out"
        fi
    done
    if test "$found" -eq 0; then warn "未发现标准 rx/tx queue 路径，RPS/XPS 应跳过。"; echo "WARN no queues" >> "$out"; fi

    echo ""
    echo "3) 当前 qdisc："
    tc qdisc show dev "$iface" 2>/dev/null | sed 's/^/  /' | tee -a "$out" || true

    echo ""
    info "审计报告：$out"
    warn "本功能只做能力剥离审计，不直接修改网卡。后续网络参数应用时应按这些能力跳过不支持项。"
}

do_service_radar_e92() {
    _e92_prepare_dirs
    local ts out pid fd rss cpu est ports cc qdisc iface
    ts="$(_e92_ts)"
    out="$E92_SERVICE_AUDIT_DIR/service_radar_$ts.txt"
    iface=$(ip route get 1.1.1.1 2>/dev/null | awk '{for(i=1;i<=NF;i++) if($i=="dev"){print $(i+1); exit}}' || echo "")
    pid=$(systemctl show -p MainPID --value xray 2>/dev/null || echo 0)
    fd="0"; rss="?"; cpu="?"
    if [[ "$pid" =~ ^[0-9]+$ ]] && test "$pid" -gt 0 2>/dev/null; then
        fd=$(ls "/proc/$pid/fd" 2>/dev/null | wc -l 2>/dev/null || echo 0)
        rss=$(ps -o rss= -p "$pid" 2>/dev/null | awk '{printf "%.1fMB", $1/1024}' || echo "?")
        cpu=$(ps -o %cpu= -p "$pid" 2>/dev/null | awk '{print $1"%"}' || echo "?")
    fi
    est=$(ss -Htan state established 2>/dev/null | wc -l 2>/dev/null || echo 0)
    ports=$(ss -H -tuln 2>/dev/null | awk '{print $5}' | sed 's/.*://' | sort -n | uniq | xargs echo 2>/dev/null || true)
    cc=$(sysctl -n net.ipv4.tcp_congestion_control 2>/dev/null || echo "?")
    qdisc=$(sysctl -n net.core.default_qdisc 2>/dev/null || echo "?")

    title "V198e92：服务状态雷达增强"
    {
        echo "V198e92 service radar"
        echo "time=$(date '+%F %T')"
        echo "xray_active=$(systemctl is-active xray 2>/dev/null || echo inactive)"
        echo "xray_enabled=$(systemctl is-enabled xray 2>/dev/null || echo disabled)"
        echo "pid=$pid fd=$fd rss=$rss cpu=$cpu"
        echo "established=$est"
        echo "iface=${iface:-unknown} cc=$cc qdisc=$qdisc"
        echo "listen_ports=$ports"
        echo ""
    } > "$out"

    echo "Xray 状态：$(systemctl is-active xray 2>/dev/null || echo inactive) / $(systemctl is-enabled xray 2>/dev/null || echo disabled)"
    echo "MainPID：$pid | FD：$fd | RSS：$rss | CPU：$cpu"
    echo "ESTABLISHED TCP：$est"
    echo "默认网卡：${iface:-未知} | cc/qdisc：$cc/$qdisc"
    echo "监听端口：${ports:-无}"
    echo "" 
    echo "Top 远端 IP："
    ss -Htan state established 2>/dev/null | awk '{print $5}' | sed -E 's/^\[?([^]]+)\]?:[0-9]+$/\1/' | sort | uniq -c | sort -nr | head -n 10 | sed 's/^/  /' | tee -a "$out" || true
    echo ""
    echo "BBR/连接摘要："
    ss -tin 2>/dev/null | grep -iE 'bbr|cubic|reno|rtt|bytes_acked|pacing_rate' | head -n 20 | sed 's/^/  /' | tee -a "$out" || true
    echo ""
    echo "最近 Xray 日志："
    journalctl -u xray.service --no-pager -n 12 2>/dev/null | sed 's/^/  /' | tee -a "$out" || true
    echo ""
    info "雷达报告：$out"
}

do_e92_audit_center() {
    while true; do
        title "V198e92：安全审计 / Top20复测 / 启动防砖中心"
        echo "  1) /boot + initramfs + CONFIG_VIRTIO 防砖检查"
        echo "  2) JSON 配置写入审计器"
        echo "  3) 服务状态雷达增强"
        echo "  4) 硬件能力自适应剥离审计"
        echo "  5) Top 20 SNI 重新测速（不全量扫）"
        echo "  6) 一键生成 e92 综合审计快照"
        echo "  0) 返回主菜单"
        hr
        local opt=""
        read -rp "请选择: " opt || true
        case "${opt:-}" in
            1) e92_boot_kernel_safety_audit; _e92_pause ;;
            2) do_json_config_audit_e92 ;;
            3) do_service_radar_e92; _e92_pause ;;
            4) e92_hardware_capability_audit; _e92_pause ;;
            5) run_sni_top20_rescan_e92; _e92_pause ;;
            6)
                e92_boot_kernel_safety_audit || true
                do_service_radar_e92 || true
                e92_hardware_capability_audit || true
                info "综合审计快照已生成在：$E92_AUDIT_DIR"
                _e92_pause
                ;;
            0) return ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

hot_update_from_legacy() {
    title "V198e92：稳态热更新（e91 基线 + 安全审计增强，不重构大框架）"
    if declare -F hot_update_from_legacy_e91_base >/dev/null 2>&1; then
        hot_update_from_legacy_e91_base "$@" || true
    fi

    _e92_prepare_dirs
    _e92_seed_sni_cache_if_empty || true

    # 热更新只做轻量审计初始化，不执行网络测速、不启用 TC、不源码编译。
    e92_boot_kernel_safety_audit >/dev/null 2>&1 || true

    echo "198e92" > "$SCRIPT_VERSION_FILE" 2>/dev/null || true
    if test -f "${SCRIPT_PATH:-$0}"; then
        cp -f "${SCRIPT_PATH:-$0}" "$SYMLINK" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e92.sh" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
        chmod +x "$SYMLINK" "$SCRIPT_DIR/ex198e92.sh" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
    fi

    info "V198e92 热更新完成。"
    info "新增入口：xrv → 18 安全审计 / Top20复测 / 启动防砖中心。"
    info "已初始化：JSON 审计目录、boot/initramfs/VIRTIO 检查、Top20 SNI 缓存；未启用 tc 限速，未合并旧脚本危险逻辑。"
}

