#==============================================================================
# V198e93 FINAL OVERRIDE LAYER
# 目标：
#   1) 保留 V198e92 大框架，不重构主体；
#   2) 修复 e92 JSON 审计对“删除用户”的误拦截；
#   3) 新增 19) Xray 跨境链路速度诊断中心；
#   4) 新增 20) TC 带宽控制模块（自定义上限/启停/开机自启/恢复默认不启用）。
#==============================================================================

# 保留 e92 热更新入口，e93 覆盖时继续调用。
if declare -F hot_update_from_legacy >/dev/null 2>&1; then
    eval "$(declare -f hot_update_from_legacy | sed '1s/hot_update_from_legacy/hot_update_from_legacy_e92_base/')"
fi

E93_AUDIT_DIR="$CONFIG_DIR/audit_e93"
E93_SPEED_AUDIT_DIR="$E93_AUDIT_DIR/speed"
E93_TC_CONF="$CONFIG_DIR/tc-limit-e93.conf"
E93_TC_SCRIPT="/usr/local/bin/xray-tc-limit-e93.sh"
E93_TC_SERVICE="/etc/systemd/system/xray-tc-limit-e93.service"
E93_TC_LOG="$LOG_DIR/tc-limit-e93.log"

_e93_pause() { local _p=""; read -rp "按 Enter 继续..." _p || true; }
_e93_ts() { date +%Y%m%d_%H%M%S; }

_e93_prepare_dirs() {
    mkdir -p "$CONFIG_DIR" "$SCRIPT_DIR" "$BACKUP_DIR" "$LOG_DIR" "$E93_AUDIT_DIR" "$E93_SPEED_AUDIT_DIR" 2>/dev/null || true
}

_e93_default_iface() {
    ip route get 1.1.1.1 2>/dev/null | awk '{for(i=1;i<=NF;i++) if($i=="dev"){print $(i+1); exit}}'
}

_e93_valid_mbit() {
    local v="${1:-}"
    [[ "$v" =~ ^[0-9]+$ ]] || return 1
    test "$v" -ge 1 2>/dev/null || return 1
    test "$v" -le 10000 2>/dev/null || return 1
}

_e93_xray_test_config() {
    local f="${1:-$CONFIG}"
    test -s "$f" || return 1
    if ! command -v "$XRAY_BIN" >/dev/null 2>&1; then
        # 未安装 Xray 时只做 JSON 语法检查，不误拦安装流程。
        jq empty "$f" >/dev/null 2>&1
        return $?
    fi
    "$XRAY_BIN" run -test -config "$f" >/dev/null 2>&1 || "$XRAY_BIN" -test -config "$f" >/dev/null 2>&1
}

# V198e93：修复 e92 JSON 审计误拦“删除用户”的问题。
# 规则：
#   - inbounds/outbounds 数量减少：仍拒绝，避免误擦配置。
#   - VLESS clients 数量减少：只报警并留痕，不拒绝，因为用户管理里“删除用户”是正常操作。
_safe_jq_write() {
    test -f "$CONFIG" || { error "未找到配置文件：$CONFIG"; return 1; }
    if ! command -v jq >/dev/null 2>&1; then error "缺少 jq，无法安全写入 JSON。"; return 1; fi

    _e92_prepare_dirs 2>/dev/null || true
    _e93_prepare_dirs
    backup_config

    local ts bdir tmp err before_meta after_meta before_in after_in before_out after_out before_clients after_clients
    ts="$(_e93_ts)"
    bdir="${E92_JSON_AUDIT_DIR:-$CONFIG_DIR/audit_e92/json}/e93_$ts"
    mkdir -p "$bdir" 2>/dev/null || true
    tmp=$(mktemp /tmp/xray.e93.safejq.XXXXXX.json) || return 1
    err="$bdir/jq.err"

    cp -a "$CONFIG" "$bdir/config.before.json" 2>/dev/null || true
    if declare -F _e92_json_meta_line >/dev/null 2>&1; then
        before_meta="$(_e92_json_meta_line "$CONFIG")"
    else
        before_meta="inbounds=$(jq '(.inbounds // []) | length' "$CONFIG" 2>/dev/null || echo 0) outbounds=$(jq '(.outbounds // []) | length' "$CONFIG" 2>/dev/null || echo 0)"
    fi
    echo "before: $before_meta" > "$bdir/meta.txt"
    printf '%s\n' "jq_args=$*" > "$bdir/filter.txt" 2>/dev/null || true

    set +e
    jq "$@" "$CONFIG" > "$tmp" 2>"$err"
    local jq_res=$?
    set -e

    if test "$jq_res" -ne 0 || test ! -s "$tmp"; then
        error "V198e93 JSON 写入审计：jq 修改失败或输出为空，拒绝覆盖。"
        sed 's/^/    /' "$err" 2>/dev/null || true
        rm -f "$tmp" 2>/dev/null || true
        restore_latest_backup >/dev/null 2>&1 || true
        return 1
    fi

    if ! jq empty "$tmp" >/dev/null 2>&1; then
        error "V198e93 JSON 写入审计：jq 产物不是合法 JSON，拒绝覆盖。"
        cp -a "$tmp" "$bdir/config.rejected.json" 2>/dev/null || true
        rm -f "$tmp" 2>/dev/null || true
        restore_latest_backup >/dev/null 2>&1 || true
        return 1
    fi

    before_in=$(jq '(.inbounds // []) | length' "$CONFIG" 2>/dev/null || echo 0)
    after_in=$(jq '(.inbounds // []) | length' "$tmp" 2>/dev/null || echo 0)
    before_out=$(jq '(.outbounds // []) | length' "$CONFIG" 2>/dev/null || echo 0)
    after_out=$(jq '(.outbounds // []) | length' "$tmp" 2>/dev/null || echo 0)
    before_clients=$(jq '[.inbounds[]? | select(.protocol=="vless") | .settings.clients[]?] | length' "$CONFIG" 2>/dev/null || echo 0)
    after_clients=$(jq '[.inbounds[]? | select(.protocol=="vless") | .settings.clients[]?] | length' "$tmp" 2>/dev/null || echo 0)

    before_in=$(_e92_int_or_zero "$before_in" 2>/dev/null || echo 0); after_in=$(_e92_int_or_zero "$after_in" 2>/dev/null || echo 0)
    before_out=$(_e92_int_or_zero "$before_out" 2>/dev/null || echo 0); after_out=$(_e92_int_or_zero "$after_out" 2>/dev/null || echo 0)
    before_clients=$(_e92_int_or_zero "$before_clients" 2>/dev/null || echo 0); after_clients=$(_e92_int_or_zero "$after_clients" 2>/dev/null || echo 0)

    if test "$before_in" -gt 0 && test "$after_in" -lt "$before_in"; then
        error "V198e93 JSON 写入审计：inbounds 数量减少 ${before_in}→${after_in}，疑似误擦配置，拒绝覆盖。"
        cp -a "$tmp" "$bdir/config.rejected.json" 2>/dev/null || true
        rm -f "$tmp" 2>/dev/null || true
        restore_latest_backup >/dev/null 2>&1 || true
        return 1
    fi
    if test "$before_out" -gt 0 && test "$after_out" -lt "$before_out"; then
        error "V198e93 JSON 写入审计：outbounds 数量减少 ${before_out}→${after_out}，疑似误擦配置，拒绝覆盖。"
        cp -a "$tmp" "$bdir/config.rejected.json" 2>/dev/null || true
        rm -f "$tmp" 2>/dev/null || true
        restore_latest_backup >/dev/null 2>&1 || true
        return 1
    fi
    if test "$before_clients" -gt 0 && test "$after_clients" -lt "$before_clients"; then
        warn "V198e93 JSON 审计：VLESS 用户数减少 ${before_clients}→${after_clients}。这可能是正常删除用户，已记录但不拦截。"
        echo "WARN clients decreased ${before_clients}->${after_clients}" >> "$bdir/meta.txt"
    fi

    if ! _e93_xray_test_config "$tmp"; then
        error "V198e93 JSON 写入审计：Xray 核心测试失败，拒绝覆盖。"
        cp -a "$tmp" "$bdir/config.rejected.json" 2>/dev/null || true
        rm -f "$tmp" 2>/dev/null || true
        restore_latest_backup >/dev/null 2>&1 || true
        return 1
    fi

    if declare -F _e92_json_meta_line >/dev/null 2>&1; then
        after_meta="$(_e92_json_meta_line "$tmp")"
    else
        after_meta="inbounds=$after_in outbounds=$after_out clients=$after_clients"
    fi
    echo "after:  $after_meta" >> "$bdir/meta.txt"
    diff -u "$CONFIG" "$tmp" > "$bdir/config.diff" 2>/dev/null || true
    cp -a "$tmp" "$bdir/config.after.json" 2>/dev/null || true

    mv -f "$tmp" "$CONFIG"
    fix_permissions
    info "V198e93 JSON 写入审计通过：$bdir"
    return 0
}

_e93_install_tc_component() {
    _e93_prepare_dirs

    if test ! -f "$E93_TC_CONF"; then
        cat > "$E93_TC_CONF" <<'EOF'
# V198e93 TC bandwidth control config
# 默认不启用；必须在菜单中手动开启。
TC_ENABLE=0
TC_IFACE="auto"
TC_EGRESS_MBIT=""
TC_LEAF_QDISC="fq"
TC_RESTORE_QDISC="fq"
TC_MODE="egress-htb-fq"
EOF
        chmod 600 "$E93_TC_CONF" 2>/dev/null || true
    fi

    cat > "$E93_TC_SCRIPT" <<'EOF'
#!/usr/bin/env bash
set -euo pipefail
PATH="/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin"

CONF="/usr/local/etc/xray/tc-limit-e93.conf"
LOG="/var/log/xray/tc-limit-e93.log"

log() {
    mkdir -p "$(dirname "$LOG")" 2>/dev/null || true
    echo "[$(date '+%F %T')] $*" >> "$LOG" 2>/dev/null || true
}

default_iface() {
    ip route get 1.1.1.1 2>/dev/null | awk '{for(i=1;i<=NF;i++) if($i=="dev"){print $(i+1); exit}}'
}

valid_mbit() {
    local v="${1:-}"
    [[ "$v" =~ ^[0-9]+$ ]] || return 1
    test "$v" -ge 1 2>/dev/null || return 1
    test "$v" -le 10000 2>/dev/null || return 1
}

load_conf() {
    if test ! -f "$CONF"; then
        echo "配置文件不存在：$CONF"
        exit 1
    fi
    # shellcheck disable=SC1090
    . "$CONF"
    IFACE="${TC_IFACE:-auto}"
    if test "$IFACE" = "auto"; then IFACE="$(default_iface)"; fi
    MBIT="${TC_EGRESS_MBIT:-}"
    RESTORE="${TC_RESTORE_QDISC:-fq}"
    LEAF="${TC_LEAF_QDISC:-fq}"
    test -n "$IFACE" || { echo "无法识别默认出口网卡"; exit 1; }
}

apply_limit() {
    load_conf

    if test "${TC_ENABLE:-0}" != "1"; then
        echo "TC_ENABLE=0，未启用。"
        log "skip enable=0"
        exit 0
    fi

    if ! valid_mbit "$MBIT"; then
        echo "TC_EGRESS_MBIT 无效：$MBIT；允许范围 1-10000 Mbit/s"
        exit 1
    fi

    modprobe sch_htb 2>/dev/null || true
    modprobe sch_fq 2>/dev/null || true
    modprobe sch_fq_codel 2>/dev/null || true

    tc qdisc replace dev "$IFACE" root handle 1: htb default 10
    tc class replace dev "$IFACE" parent 1: classid 1:1 htb rate "${MBIT}mbit" ceil "${MBIT}mbit"
    tc class replace dev "$IFACE" parent 1:1 classid 1:10 htb rate "${MBIT}mbit" ceil "${MBIT}mbit"

    if tc qdisc replace dev "$IFACE" parent 1:10 handle 10: fq 2>/dev/null; then
        LEAF_USED="fq"
    elif tc qdisc replace dev "$IFACE" parent 1:10 handle 10: fq_codel 2>/dev/null; then
        LEAF_USED="fq_codel"
    else
        LEAF_USED="none"
    fi

    log "applied iface=$IFACE egress=${MBIT}mbit leaf=$LEAF_USED"
    echo "已应用出口总限速：$IFACE ${MBIT}mbit，叶子队列：$LEAF_USED"
}

stop_limit() {
    load_conf || true
    if test -z "${IFACE:-}"; then IFACE="$(default_iface)"; fi
    test -n "${IFACE:-}" || { echo "无法识别默认出口网卡"; exit 1; }

    tc qdisc del dev "$IFACE" root 2>/dev/null || true
    case "${RESTORE:-fq}" in
        fq|fq_codel|pfifo_fast|cake)
            tc qdisc replace dev "$IFACE" root "$RESTORE" 2>/dev/null || tc qdisc replace dev "$IFACE" root fq 2>/dev/null || true
            ;;
        *)
            tc qdisc replace dev "$IFACE" root fq 2>/dev/null || true
            ;;
    esac
    log "stopped iface=$IFACE restore=${RESTORE:-fq}"
    echo "已停用 TC 限速，并尝试恢复 root qdisc=${RESTORE:-fq}：$IFACE"
}

status_limit() {
    load_conf || true
    if test -z "${IFACE:-}"; then IFACE="$(default_iface)"; fi
    echo "配置文件：$CONF"
    echo "TC_ENABLE=${TC_ENABLE:-0}"
    echo "网卡：${IFACE:-unknown}"
    echo "出口上限：${MBIT:-unset} Mbit/s"
    echo "恢复 qdisc：${RESTORE:-fq}"
    echo
    if test -n "${IFACE:-}"; then
        echo "[qdisc]"
        tc qdisc show dev "$IFACE" 2>/dev/null || true
        echo
        echo "[class]"
        tc class show dev "$IFACE" 2>/dev/null || true
        echo
        echo "[qdisc stats]"
        tc -s qdisc show dev "$IFACE" 2>/dev/null || true
    fi
}

case "${1:-status}" in
    apply) apply_limit ;;
    stop) stop_limit ;;
    status) status_limit ;;
    *) echo "用法：$0 {apply|stop|status}"; exit 1 ;;
esac
EOF

    chmod +x "$E93_TC_SCRIPT" 2>/dev/null || true

    cat > "$E93_TC_SERVICE" <<EOF
[Unit]
Description=Xray V198e93 egress TC bandwidth limiter
After=network-online.target
Wants=network-online.target

[Service]
Type=oneshot
ExecStart=$E93_TC_SCRIPT apply
ExecStop=$E93_TC_SCRIPT stop
RemainAfterExit=yes

[Install]
WantedBy=multi-user.target
EOF

    systemctl daemon-reload >/dev/null 2>&1 || true
}

_e93_tc_write_conf() {
    local mbit="${1:-}" enable="${2:-1}" iface="${3:-auto}" restore="${4:-fq}"

    if test -n "$mbit"; then
        if ! _e93_valid_mbit "$mbit"; then
            error "带宽上限无效：$mbit，允许范围 1-10000 Mbit/s。"
            return 1
        fi
    fi

    _e93_prepare_dirs
    cat > "$E93_TC_CONF" <<EOF
# V198e93 TC bandwidth control config
TC_ENABLE=$enable
TC_IFACE="$iface"
TC_EGRESS_MBIT="$mbit"
TC_LEAF_QDISC="fq"
TC_RESTORE_QDISC="$restore"
TC_MODE="egress-htb-fq"
EOF
    chmod 600 "$E93_TC_CONF" 2>/dev/null || true
    info "已写入 TC 配置：$E93_TC_CONF"
}

do_tc_bandwidth_menu_e93() {
    _e93_install_tc_component || true

    while true; do
        clear
        title "V198e93：TC 带宽控制模块（出口上限 / 启停 / 开机自启）"
        local iface qdisc enabled active mbit tenable restore
        iface="$(_e93_default_iface 2>/dev/null || echo "")"
        qdisc=""
        if test -n "$iface"; then qdisc=$(tc qdisc show dev "$iface" 2>/dev/null | head -n 1 || true); fi
        enabled=$(systemctl is-enabled xray-tc-limit-e93.service 2>/dev/null || echo "disabled")
        active=$(systemctl is-active xray-tc-limit-e93.service 2>/dev/null || echo "inactive")
        tenable=$(awk -F= '/^TC_ENABLE=/{gsub(/"/,"",$2); print $2}' "$E93_TC_CONF" 2>/dev/null || echo "0")
        mbit=$(awk -F= '/^TC_EGRESS_MBIT=/{gsub(/"/,"",$2); print $2}' "$E93_TC_CONF" 2>/dev/null || echo "")
        restore=$(awk -F= '/^TC_RESTORE_QDISC=/{gsub(/"/,"",$2); print $2}' "$E93_TC_CONF" 2>/dev/null || echo "fq")

        echo -e "  默认出口网卡: ${cyan}${iface:-未知}${none}"
        echo -e "  当前 root qdisc: ${cyan}${qdisc:-未读取}${none}"
        echo -e "  TC配置启用: ${cyan}${tenable:-0}${none} | 服务: ${cyan}${active}/${enabled}${none}"
        echo -e "  当前出口上限: ${cyan}${mbit:-未设置}${none} Mbit/s | 停用恢复: ${cyan}${restore:-fq}${none}"
        hr
        echo "  1) 查看 TC / qdisc / class / stats 当前状态"
        echo "  2) 设置出口总上限，并立即开启"
        echo "  3) 只写入出口总上限配置，不立即开启"
        echo "  4) 按当前配置立即开启 TC 限速"
        echo "  5) 立即关闭 TC 限速，恢复默认 fq，并保留配置"
        echo "  6) 开启开机自动启用 TC 限速"
        echo "  7) 关闭开机自动启用 TC 限速"
        echo "  8) 恢复默认：关闭限速 + 禁用开机自启 + 配置改为不启用"
        echo "  9) 删除 e93 TC 组件（服务/脚本/配置）"
        echo "  10) 查看 TC/BBR/fq/cake 关系说明"
        echo "  0) 返回主菜单"
        hr

        local opt=""
        read -rp "请选择: " opt || true
        case "${opt:-}" in
            1)
                "$E93_TC_SCRIPT" status || true
                _e93_pause
                ;;
            2)
                local bw=""
                read -rp "请输入出口总上限 Mbit/s，例如 80、100、300、800: " bw || true
                if _e93_tc_write_conf "$bw" 1 "auto" "fq"; then
                    "$E93_TC_SCRIPT" apply || warn "TC 应用失败，请查看：$E93_TC_LOG"
                fi
                _e93_pause
                ;;
            3)
                local bw=""
                read -rp "请输入出口总上限 Mbit/s，仅写配置不应用: " bw || true
                _e93_tc_write_conf "$bw" 1 "auto" "fq" || true
                _e93_pause
                ;;
            4)
                if ! grep -q '^TC_ENABLE=1' "$E93_TC_CONF" 2>/dev/null; then
                    warn "当前 TC_ENABLE 不是 1。将尝试按配置开启；若未设置带宽会失败。"
                    sed -i 's/^TC_ENABLE=.*/TC_ENABLE=1/' "$E93_TC_CONF" 2>/dev/null || true
                fi
                "$E93_TC_SCRIPT" apply || warn "TC 应用失败，请检查带宽上限和网卡。"
                _e93_pause
                ;;
            5)
                "$E93_TC_SCRIPT" stop || true
                sed -i 's/^TC_ENABLE=.*/TC_ENABLE=0/' "$E93_TC_CONF" 2>/dev/null || true
                info "已关闭当前 TC 限速，配置保留但默认不启用。"
                _e93_pause
                ;;
            6)
                systemctl enable xray-tc-limit-e93.service >/dev/null 2>&1 || true
                info "已开启开机自动启用 TC 限速。"
                _e93_pause
                ;;
            7)
                systemctl disable xray-tc-limit-e93.service >/dev/null 2>&1 || true
                info "已关闭开机自动启用 TC 限速。"
                _e93_pause
                ;;
            8)
                systemctl disable --now xray-tc-limit-e93.service >/dev/null 2>&1 || true
                "$E93_TC_SCRIPT" stop || true
                _e93_tc_write_conf "" 0 "auto" "fq" || true
                info "已恢复默认：TC 不启用、不开机自启、root qdisc 尝试恢复 fq。"
                _e93_pause
                ;;
            9)
                systemctl disable --now xray-tc-limit-e93.service >/dev/null 2>&1 || true
                "$E93_TC_SCRIPT" stop >/dev/null 2>&1 || true
                rm -f "$E93_TC_SERVICE" "$E93_TC_SCRIPT" "$E93_TC_CONF" 2>/dev/null || true
                systemctl daemon-reload >/dev/null 2>&1 || true
                info "已删除 e93 TC 组件。"
                _e93_pause
                ;;
            10)
                cat <<'EOF'
TC 带宽控制说明：

1. 本模块用于限制 VPS 出口总带宽，不是提速器。
2. 启用后，默认出口网卡 root qdisc 会由 HTB 接管。
3. HTB 负责总上限，叶子队列优先挂 fq；fq 能较好配合 BBR pacing。
4. 如果你正在使用 CAKE，启用本模块会与 CAKE root qdisc 冲突。
5. 推荐限速到“晚高峰稳定速度”的 85%-95%，避免跑满端口制造排队和丢包。
6. 关闭时会尝试恢复 fq；“恢复默认”会同时禁用开机自启并把 TC_ENABLE=0。
EOF
                _e93_pause
                ;;
            0) return ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

_e93_ping_summary() {
    local host="${1:-1.1.1.1}" count="${2:-6}"
    if ! command -v ping >/dev/null 2>&1; then echo "缺少 ping"; return 0; fi
    ping -c "$count" -W 2 "$host" 2>/dev/null | awk '
        /packets transmitted/ {print "  " $0}
        /rtt min|round-trip/ {print "  " $0}
    '
}

_e93_http_timing() {
    local url="${1:-https://www.cloudflare.com}"
    if ! command -v curl >/dev/null 2>&1; then echo "缺少 curl"; return 0; fi
    curl -k -sL -o /dev/null --connect-timeout 4 -m 10 \
        -w "  url=%{url_effective}\n  dns=%{time_namelookup}s connect=%{time_connect}s tls=%{time_appconnect}s ttfb=%{time_starttransfer}s total=%{time_total}s speed=%{speed_download}B/s\n" \
        "$url" 2>/dev/null || echo "  curl 失败：$url"
}

do_xray_speed_diag_report_e93() {
    _e93_prepare_dirs
    local ts out iface pid cc qdisc mtu
    ts="$(_e93_ts)"
    out="$E93_SPEED_AUDIT_DIR/xray_speed_diag_$ts.txt"
    iface="$(_e93_default_iface 2>/dev/null || echo "")"
    pid=$(systemctl show -p MainPID --value xray 2>/dev/null || echo 0)
    cc=$(sysctl -n net.ipv4.tcp_congestion_control 2>/dev/null || echo "?")
    qdisc=$(sysctl -n net.core.default_qdisc 2>/dev/null || echo "?")
    mtu="?"; test -n "$iface" && mtu=$(cat /sys/class/net/"$iface"/mtu 2>/dev/null || echo "?")

    {
        echo "V198e93 Xray cross-border speed diagnosis"
        echo "time=$(date '+%F %T')"
        echo "kernel=$(uname -r 2>/dev/null || echo unknown)"
        echo "iface=${iface:-unknown}"
        echo "mtu=$mtu cc=$cc default_qdisc=$qdisc"
        echo "xray_active=$(systemctl is-active xray 2>/dev/null || echo inactive)"
        echo "xray_enabled=$(systemctl is-enabled xray 2>/dev/null || echo disabled)"
        echo "xray_pid=$pid"
        if [[ "$pid" =~ ^[0-9]+$ ]] && test "$pid" -gt 0 2>/dev/null; then
            echo "xray_fd=$(ls /proc/$pid/fd 2>/dev/null | wc -l 2>/dev/null || echo 0)"
            echo "xray_rss=$(ps -o rss= -p "$pid" 2>/dev/null | awk '{printf \"%.1fMB\", $1/1024}' || echo '?')"
            echo "xray_cpu=$(ps -o %cpu= -p "$pid" 2>/dev/null | awk '{print $1\"%\"}' || echo '?')"
        fi
        echo "established=$(ss -Htan state established 2>/dev/null | wc -l 2>/dev/null || echo 0)"
        echo ""
        echo "[ping 1.1.1.1]"
        _e93_ping_summary 1.1.1.1 6
        echo ""
        echo "[ping 8.8.8.8]"
        _e93_ping_summary 8.8.8.8 6
        echo ""
        echo "[http timing cloudflare]"
        _e93_http_timing https://www.cloudflare.com
        echo ""
        echo "[http timing microsoft]"
        _e93_http_timing https://www.microsoft.com
        echo ""
        echo "[qdisc]"
        test -n "$iface" && tc -s qdisc show dev "$iface" 2>/dev/null || true
        echo ""
        echo "[ip route]"
        ip route get 1.1.1.1 2>/dev/null || true
        echo ""
        echo "[offload]"
        test -n "$iface" && ethtool -k "$iface" 2>/dev/null | grep -E 'tcp-segmentation|generic-segmentation|generic-receive|large-receive|rx-gro-hw|tx-udp' || true
        echo ""
        echo "[tcp sysctl]"
        sysctl net.ipv4.tcp_congestion_control net.core.default_qdisc net.ipv4.tcp_mtu_probing net.ipv4.tcp_notsent_lowat net.ipv4.tcp_limit_output_bytes net.ipv4.tcp_adv_win_scale net.ipv4.tcp_app_win 2>/dev/null || true
        echo ""
        echo "[conntrack]"
        sysctl net.netfilter.nf_conntrack_count net.netfilter.nf_conntrack_max 2>/dev/null || true
        dmesg 2>/dev/null | grep -i conntrack | tail -n 5 || true
        echo ""
        echo "[BBR connections]"
        ss -tin 2>/dev/null | grep -iE 'bbr|rtt|pacing_rate|bytes_acked|delivery_rate|retrans' | head -n 40 || true
        echo ""
        echo "[top remote ips]"
        ss -Htan state established 2>/dev/null | awk '{print $5}' | sed -E 's/^\[?([^]]+)\]?:[0-9]+$/\1/' | sort | uniq -c | sort -nr | head -n 15 || true
        echo ""
        echo "[journal xray]"
        journalctl -u xray.service --no-pager -n 20 2>/dev/null || true
    } > "$out"

    info "Xray 跨境链路速度诊断报告：$out"
    sed -n '1,120p' "$out" 2>/dev/null || true
}

do_xray_speed_diag_menu_e93() {
    while true; do
        clear
        title "V198e93：Xray 跨境链路速度诊断中心"
        local iface cc qdisc pid est mtu
        iface="$(_e93_default_iface 2>/dev/null || echo "")"
        cc=$(sysctl -n net.ipv4.tcp_congestion_control 2>/dev/null || echo "?")
        qdisc=$(sysctl -n net.core.default_qdisc 2>/dev/null || echo "?")
        pid=$(systemctl show -p MainPID --value xray 2>/dev/null || echo 0)
        est=$(ss -Htan state established 2>/dev/null | wc -l 2>/dev/null || echo 0)
        mtu="?"; test -n "$iface" && mtu=$(cat /sys/class/net/"$iface"/mtu 2>/dev/null || echo "?")
        echo -e "  默认网卡: ${cyan}${iface:-未知}${none} | MTU: ${cyan}${mtu}${none} | cc/qdisc: ${cyan}${cc}/${qdisc}${none}"
        echo -e "  Xray PID: ${cyan}${pid}${none} | ESTABLISHED: ${cyan}${est}${none}"
        hr
        echo "  1) 生成完整诊断报告（推荐）"
        echo "  2) CPU / 内存 / FD / 连接数检查"
        echo "  3) RTT / 丢包快速测试"
        echo "  4) HTTP DNS/连接/TLS/TTFB 耗时测试"
        echo "  5) BBR / TCP 连接摘要"
        echo "  6) qdisc / MTU / offload / 网卡队列检查"
        echo "  7) conntrack / 防火墙容量检查"
        echo "  8) 诊断结论说明：应该先看哪一层"
        echo "  0) 返回主菜单"
        hr
        local opt=""
        read -rp "请选择: " opt || true
        case "${opt:-}" in
            1) do_xray_speed_diag_report_e93; _e93_pause ;;
            2)
                do_service_radar_e92 2>/dev/null || true
                _e93_pause
                ;;
            3)
                echo "[ping 1.1.1.1]"; _e93_ping_summary 1.1.1.1 8
                echo "[ping 8.8.8.8]"; _e93_ping_summary 8.8.8.8 8
                _e93_pause
                ;;
            4)
                echo "[cloudflare]"; _e93_http_timing https://www.cloudflare.com
                echo "[microsoft]"; _e93_http_timing https://www.microsoft.com
                echo "[apple]"; _e93_http_timing https://www.apple.com
                _e93_pause
                ;;
            5)
                ss -tin 2>/dev/null | grep -iE 'bbr|cubic|reno|rtt|bytes_acked|pacing_rate|delivery_rate|retrans' | head -n 60 || true
                _e93_pause
                ;;
            6)
                e92_hardware_capability_audit 2>/dev/null || true
                _e93_pause
                ;;
            7)
                sysctl net.netfilter.nf_conntrack_count net.netfilter.nf_conntrack_max 2>/dev/null || warn "未读取到 conntrack sysctl。"
                dmesg 2>/dev/null | grep -i conntrack | tail -n 10 || true
                _e93_pause
                ;;
            8)
                cat <<'EOF'
诊断顺序建议：

1. 先看线路：RTT、丢包、晚高峰波动。
2. 再看 Xray：CPU、RSS、FD、连接数、日志。
3. 再看 TCP：BBR 状态、重传、rtt、pacing_rate。
4. 再看队列：fq/cake/HTB 是否冲突、qdisc 是否被覆盖。
5. 再看网卡：MTU、offload、RPS/XPS、虚拟化队列。
6. 最后才调 sysctl/BBR 参数；不要一上来堆大缓冲。
EOF
                _e93_pause
                ;;
            0) return ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

