#==============================================================================
# EOF - Apex Vanguard V198e93 Speed Diagnosis + TC Bandwidth Control Layer.
#==============================================================================


#==============================================================================
# V198e94 FINAL OVERRIDE LAYER
# 目标：
#   1) 修复 V198e93 速度诊断报告中的 awk 反斜杠转义错误；
#   2) 重新设计 19) Xray 跨境链路速度诊断中心，避免双引号内嵌 awk；
#   3) 重新设计 20) TC 带宽控制模块：自定义上限、开启/关闭、开机自启、恢复默认不启用；
#   4) 热更新只安装组件，不自动启用 TC、不自动限速、不触碰 DNS 锁死策略。
#==============================================================================

# 保留 e93 热更新入口，e94 覆盖时继续调用。
if declare -F hot_update_from_legacy >/dev/null 2>&1; then
    eval "$(declare -f hot_update_from_legacy | sed '1s/hot_update_from_legacy/hot_update_from_legacy_e93_base/')"
fi

E94_AUDIT_DIR="$CONFIG_DIR/audit_e94"
E94_SPEED_AUDIT_DIR="$E94_AUDIT_DIR/speed"
E94_TC_CONF="$CONFIG_DIR/tc-limit-e94.conf"
E94_TC_SCRIPT="/usr/local/bin/xray-tc-limit-e94.sh"
E94_TC_SERVICE="/etc/systemd/system/xray-tc-limit-e94.service"
E94_TC_LOG="$LOG_DIR/tc-limit-e94.log"

_e94_pause() { local _p=""; read -rp "按 Enter 继续..." _p || true; }
_e94_ts() { date +%Y%m%d_%H%M%S; }

_e94_prepare_dirs() {
    mkdir -p "$CONFIG_DIR" "$SCRIPT_DIR" "$BACKUP_DIR" "$LOG_DIR" "$E94_AUDIT_DIR" "$E94_SPEED_AUDIT_DIR" 2>/dev/null || true
}

_e94_default_iface() {
    ip route get 1.1.1.1 2>/dev/null | awk '{for(i=1;i<=NF;i++) if($i=="dev"){print $(i+1); exit}}'
}

_e94_xray_pid() {
    local p=""
    p=$(systemctl show -p MainPID --value xray 2>/dev/null | awk 'NF{print $1; exit}' || true)
    if [[ "$p" =~ ^[0-9]+$ ]]; then echo "$p"; else echo 0; fi
}

_e94_proc_fd() {
    local pid="${1:-0}"
    if [[ "$pid" =~ ^[0-9]+$ ]] && test "$pid" -gt 0 2>/dev/null && test -d "/proc/$pid/fd"; then
        ls "/proc/$pid/fd" 2>/dev/null | wc -l 2>/dev/null | awk '{print int($1)}'
    else
        echo 0
    fi
}

_e94_proc_rss_mb() {
    local pid="${1:-0}" rss=""
    if [[ "$pid" =~ ^[0-9]+$ ]] && test "$pid" -gt 0 2>/dev/null; then
        rss=$(ps -o rss= -p "$pid" 2>/dev/null | awk 'NF{printf "%.1fMB", $1/1024; found=1} END{if(!found) print "?"}' || echo "?")
        echo "${rss:-?}"
    else
        echo "?"
    fi
}

_e94_proc_cpu_pct() {
    local pid="${1:-0}" cpu=""
    if [[ "$pid" =~ ^[0-9]+$ ]] && test "$pid" -gt 0 2>/dev/null; then
        cpu=$(ps -o %cpu= -p "$pid" 2>/dev/null | awk 'NF{printf "%s%%", $1; found=1} END{if(!found) print "?"}' || echo "?")
        echo "${cpu:-?}"
    else
        echo "?"
    fi
}

_e94_ping_summary() {
    local host="${1:-1.1.1.1}" count="${2:-6}"
    if ! command -v ping >/dev/null 2>&1; then echo "缺少 ping"; return 0; fi
    ping -c "$count" -W 2 "$host" 2>/dev/null | awk '
        /packets transmitted/ {print "  " $0}
        /rtt min|round-trip/ {print "  " $0}
    ' || echo "  ping 失败：$host"
}

_e94_http_timing() {
    local url="${1:-https://www.cloudflare.com}"
    if ! command -v curl >/dev/null 2>&1; then echo "缺少 curl"; return 0; fi
    curl -k -sL -o /dev/null --connect-timeout 4 -m 10 \
        -w "  url=%{url_effective}\n  dns=%{time_namelookup}s connect=%{time_connect}s tls=%{time_appconnect}s ttfb=%{time_starttransfer}s total=%{time_total}s speed=%{speed_download}B/s\n" \
        "$url" 2>/dev/null || echo "  curl 失败：$url"
}

_e94_conntrack_status() {
    if sysctl net.netfilter.nf_conntrack_count >/dev/null 2>&1; then
        sysctl net.netfilter.nf_conntrack_count net.netfilter.nf_conntrack_max 2>/dev/null || true
        local c m pct
        c=$(sysctl -n net.netfilter.nf_conntrack_count 2>/dev/null || echo 0)
        m=$(sysctl -n net.netfilter.nf_conntrack_max 2>/dev/null || echo 0)
        if [[ "$c" =~ ^[0-9]+$ ]] && [[ "$m" =~ ^[0-9]+$ ]] && test "$m" -gt 0 2>/dev/null; then
            pct=$(awk -v c="$c" -v m="$m" 'BEGIN{printf "%.1f", c*100/m}')
            echo "conntrack_usage=${pct}%"
        fi
    else
        echo "conntrack sysctl 未启用或不可读"
    fi
}

do_xray_speed_diag_report_e94() {
    _e94_prepare_dirs
    local ts out iface pid cc qdisc mtu fd rss cpu est
    ts="$(_e94_ts)"
    out="$E94_SPEED_AUDIT_DIR/xray_speed_diag_$ts.txt"
    iface="$(_e94_default_iface 2>/dev/null || echo "")"
    pid="$(_e94_xray_pid)"
    cc=$(sysctl -n net.ipv4.tcp_congestion_control 2>/dev/null || echo "?")
    qdisc=$(sysctl -n net.core.default_qdisc 2>/dev/null || echo "?")
    mtu="?"; test -n "$iface" && mtu=$(cat /sys/class/net/"$iface"/mtu 2>/dev/null || echo "?")
    fd="$(_e94_proc_fd "$pid")"
    rss="$(_e94_proc_rss_mb "$pid")"
    cpu="$(_e94_proc_cpu_pct "$pid")"
    est=$(ss -Htan state established 2>/dev/null | wc -l 2>/dev/null | awk '{print int($1)}' || echo 0)

    {
        echo "V198e94 Xray cross-border speed diagnosis"
        echo "time=$(date '+%F %T')"
        echo "kernel=$(uname -r 2>/dev/null || echo unknown)"
        echo "iface=${iface:-unknown}"
        echo "mtu=$mtu cc=$cc default_qdisc=$qdisc"
        echo "xray_active=$(systemctl is-active xray 2>/dev/null || echo inactive)"
        echo "xray_enabled=$(systemctl is-enabled xray 2>/dev/null || echo disabled)"
        echo "xray_pid=$pid"
        echo "xray_fd=$fd"
        echo "xray_rss=$rss"
        echo "xray_cpu=$cpu"
        echo "established=$est"
        echo ""
        echo "[ping 1.1.1.1]"
        _e94_ping_summary 1.1.1.1 6
        echo ""
        echo "[ping 8.8.8.8]"
        _e94_ping_summary 8.8.8.8 6
        echo ""
        echo "[http timing cloudflare]"
        _e94_http_timing https://www.cloudflare.com
        echo ""
        echo "[http timing microsoft]"
        _e94_http_timing https://www.microsoft.com
        echo ""
        echo "[qdisc]"
        if test -n "$iface"; then
            tc qdisc show dev "$iface" 2>/dev/null || true
            echo ""
            tc -s qdisc show dev "$iface" 2>/dev/null || true
        else
            echo "未识别默认网卡"
        fi
        echo ""
        echo "[route]"
        ip route show table main 2>/dev/null || true
        echo ""
        echo "[offload]"
        if test -n "$iface"; then ethtool -k "$iface" 2>/dev/null | sed -n '1,80p' || true; fi
        echo ""
        echo "[queues]"
        if test -n "$iface"; then
            for p in /sys/class/net/"$iface"/queues/rx-* /sys/class/net/"$iface"/queues/tx-*; do
                test -d "$p" || continue
                echo "$p"
                test -f "$p/rps_cpus" && echo "  rps_cpus=$(cat "$p/rps_cpus" 2>/dev/null)"
                test -f "$p/xps_cpus" && echo "  xps_cpus=$(cat "$p/xps_cpus" 2>/dev/null)"
            done
        fi
        echo ""
        echo "[tcp sysctl key]"
        sysctl net.ipv4.tcp_congestion_control net.core.default_qdisc net.ipv4.tcp_rmem net.ipv4.tcp_wmem net.ipv4.tcp_notsent_lowat net.ipv4.tcp_mtu_probing 2>/dev/null || true
        echo ""
        echo "[conntrack]"
        _e94_conntrack_status || true
        dmesg 2>/dev/null | grep -i conntrack | tail -n 5 || true
        echo ""
        echo "[BBR connections]"
        ss -tin 2>/dev/null | grep -iE 'bbr|rtt|pacing_rate|bytes_acked|delivery_rate|retrans' | head -n 60 || true
        echo ""
        echo "[top remote ips]"
        ss -Htan state established 2>/dev/null | awk '{print $5}' | sed -E 's/^\[?([^]]+)\]?:[0-9]+$/\1/' | sort | uniq -c | sort -nr | head -n 15 || true
        echo ""
        echo "[xray unit security hint]"
        systemctl cat xray 2>/dev/null | sed -n '1,80p' || true
        echo ""
        echo "[journal xray]"
        journalctl -u xray.service --no-pager -n 25 2>/dev/null || true
    } > "$out"

    info "Xray 跨境链路速度诊断报告：$out"
    sed -n '1,140p' "$out" 2>/dev/null || true
}

do_xray_speed_diag_menu_e94() {
    while true; do
        clear
        title "V198e94：Xray 跨境链路速度诊断中心"
        local iface cc qdisc pid est mtu rss cpu fd
        iface="$(_e94_default_iface 2>/dev/null || echo "")"
        cc=$(sysctl -n net.ipv4.tcp_congestion_control 2>/dev/null || echo "?")
        qdisc=$(sysctl -n net.core.default_qdisc 2>/dev/null || echo "?")
        pid="$(_e94_xray_pid)"
        est=$(ss -Htan state established 2>/dev/null | wc -l 2>/dev/null | awk '{print int($1)}' || echo 0)
        mtu="?"; test -n "$iface" && mtu=$(cat /sys/class/net/"$iface"/mtu 2>/dev/null || echo "?")
        fd="$(_e94_proc_fd "$pid")"
        rss="$(_e94_proc_rss_mb "$pid")"
        cpu="$(_e94_proc_cpu_pct "$pid")"
        echo -e "  默认网卡: ${cyan}${iface:-未知}${none} | MTU: ${cyan}${mtu}${none} | cc/qdisc: ${cyan}${cc}/${qdisc}${none}"
        echo -e "  Xray PID: ${cyan}${pid}${none} | FD/RSS/CPU: ${cyan}${fd}/${rss}/${cpu}${none} | ESTABLISHED: ${cyan}${est}${none}"
        hr
        echo "  1) 生成完整诊断报告（推荐，已修复 e93 awk 转义问题）"
        echo "  2) CPU / 内存 / FD / 连接数检查"
        echo "  3) RTT / 丢包快速测试"
        echo "  4) HTTP DNS/连接/TLS/TTFB 耗时测试"
        echo "  5) BBR / TCP 连接摘要"
        echo "  6) qdisc / MTU / offload / 网卡队列检查"
        echo "  7) conntrack / 防火墙容量检查"
        echo "  8) 诊断结论说明：应该先看哪一层"
        echo "  0) 返回主菜单"
        hr
        local opt=""
        read -rp "请选择: " opt || true
        case "${opt:-}" in
            1) do_xray_speed_diag_report_e94; _e94_pause ;;
            2)
                echo "Xray 状态：$(systemctl is-active xray 2>/dev/null || echo inactive) / $(systemctl is-enabled xray 2>/dev/null || echo disabled)"
                echo "PID=$pid FD=$fd RSS=$rss CPU=$cpu ESTABLISHED=$est"
                echo ""
                ps -o pid,ppid,stat,%cpu,%mem,rss,etime,cmd -p "$pid" 2>/dev/null || true
                echo ""
                free -h 2>/dev/null || true
                echo ""
                uptime 2>/dev/null || true
                _e94_pause
                ;;
            3)
                echo "[ping 1.1.1.1]"; _e94_ping_summary 1.1.1.1 8
                echo ""; echo "[ping 8.8.8.8]"; _e94_ping_summary 8.8.8.8 8
                _e94_pause
                ;;
            4)
                echo "[Cloudflare]"; _e94_http_timing https://www.cloudflare.com
                echo ""; echo "[Microsoft]"; _e94_http_timing https://www.microsoft.com
                echo ""; echo "[Apple]"; _e94_http_timing https://www.apple.com
                _e94_pause
                ;;
            5)
                ss -tin 2>/dev/null | grep -iE 'bbr|rtt|pacing_rate|bytes_acked|delivery_rate|retrans' | head -n 80 || true
                _e94_pause
                ;;
            6)
                echo "iface=${iface:-unknown} mtu=$mtu cc=$cc default_qdisc=$qdisc"
                test -n "$iface" && tc qdisc show dev "$iface" 2>/dev/null || true
                echo ""; test -n "$iface" && tc -s qdisc show dev "$iface" 2>/dev/null || true
                echo ""; test -n "$iface" && ethtool -k "$iface" 2>/dev/null | sed -n '1,100p' || true
                echo ""; test -n "$iface" && find /sys/class/net/"$iface"/queues -maxdepth 2 -type f \( -name rps_cpus -o -name xps_cpus \) -print -exec cat {} \; 2>/dev/null || true
                _e94_pause
                ;;
            7)
                _e94_conntrack_status || true
                dmesg 2>/dev/null | grep -i conntrack | tail -n 10 || true
                iptables -S 2>/dev/null | wc -l | awk '{print "iptables_rules=" int($1)}' || true
                _e94_pause
                ;;
            8)
                cat <<'EOF'
诊断顺序建议：

1. 先看线路：RTT、丢包、晚高峰波动。
2. 再看 Xray：CPU、RSS、FD、连接数、日志。
3. 再看 TCP：BBR 状态、重传、rtt、pacing_rate。
4. 再看队列：fq/cake/HTB 是否冲突、qdisc 是否被覆盖。
5. 再看网卡：MTU、offload、RPS/XPS、虚拟化队列。
6. 最后才调 sysctl/BBR 参数；不要一上来堆大缓冲。

你这次 e93 的 awk 报错属于“诊断脚本输出层”的问题，不代表 Xray 或 BBR 本身异常。
journal 里的 “Special user nobody configured, this is not safe!” 是 systemd 对 xray.service 的用户配置提醒，
不等于 Xray 启动失败。后续可单独做服务用户 hardening 修复。
EOF
                _e94_pause
                ;;
            0) return ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

_e94_valid_mbit() {
    local v="${1:-}"
    [[ "$v" =~ ^[0-9]+$ ]] || return 1
    test "$v" -ge 1 2>/dev/null || return 1
    test "$v" -le 10000 2>/dev/null || return 1
}

_e94_valid_restore_qdisc() {
    case "${1:-fq}" in
        fq|fq_codel|pfifo_fast|cake) return 0 ;;
        *) return 1 ;;
    esac
}

_e94_valid_iface_or_auto() {
    local iface="${1:-auto}"
    test "$iface" = "auto" && return 0
    test -d "/sys/class/net/$iface"
}

_e94_tc_current_conf_value() {
    local key="$1" file="${2:-$E94_TC_CONF}"
    awk -F= -v k="$key" '$1==k{gsub(/"/,"",$2); print $2; found=1} END{if(!found) print ""}' "$file" 2>/dev/null || true
}

_e94_install_tc_component() {
    _e94_prepare_dirs

    if test ! -f "$E94_TC_CONF"; then
        cat > "$E94_TC_CONF" <<'EOF'
# V198e94 TC bandwidth control config
# 默认不启用；必须在菜单中手动开启。
TC_ENABLE=0
TC_IFACE="auto"
TC_EGRESS_MBIT=""
TC_LEAF_QDISC="fq"
TC_RESTORE_QDISC="fq"
TC_MODE="egress-htb-fq"
EOF
        chmod 600 "$E94_TC_CONF" 2>/dev/null || true
    fi

    cat > "$E94_TC_SCRIPT" <<'EOF'
#!/usr/bin/env bash
set -euo pipefail
PATH="/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin"

CONF="/usr/local/etc/xray/tc-limit-e94.conf"
LOG="/var/log/xray/tc-limit-e94.log"

log() {
    mkdir -p "$(dirname "$LOG")" 2>/dev/null || true
    echo "[$(date '+%F %T')] $*" >> "$LOG" 2>/dev/null || true
}

default_iface() {
    ip route get 1.1.1.1 2>/dev/null | awk '{for(i=1;i<=NF;i++) if($i=="dev"){print $(i+1); exit}}'
}

valid_mbit() {
    local v="${1:-}"
    [[ "$v" =~ ^[0-9]+$ ]] || return 1
    test "$v" -ge 1 2>/dev/null || return 1
    test "$v" -le 10000 2>/dev/null || return 1
}

valid_restore() {
    case "${1:-fq}" in
        fq|fq_codel|pfifo_fast|cake) return 0 ;;
        *) return 1 ;;
    esac
}

load_conf() {
    if test ! -f "$CONF"; then
        echo "配置文件不存在：$CONF"
        exit 1
    fi
    # shellcheck disable=SC1090
    . "$CONF"
    IFACE="${TC_IFACE:-auto}"
    if test "$IFACE" = "auto"; then IFACE="$(default_iface)"; fi
    MBIT="${TC_EGRESS_MBIT:-}"
    RESTORE="${TC_RESTORE_QDISC:-fq}"
    LEAF="${TC_LEAF_QDISC:-fq}"
    test -n "${IFACE:-}" || { echo "无法识别默认出口网卡"; exit 1; }
}

apply_limit() {
    load_conf

    if test "${TC_ENABLE:-0}" != "1"; then
        echo "TC_ENABLE=0，未启用。"
        log "skip enable=0"
        exit 0
    fi

    if ! valid_mbit "$MBIT"; then
        echo "TC_EGRESS_MBIT 无效：$MBIT；允许范围 1-10000 Mbit/s"
        exit 1
    fi

    modprobe sch_htb 2>/dev/null || true
    modprobe sch_fq 2>/dev/null || true
    modprobe sch_fq_codel 2>/dev/null || true

    # 明确接管 root qdisc：HTB 控总上限，叶子队列优先 fq。
    tc qdisc replace dev "$IFACE" root handle 1: htb default 10
    tc class replace dev "$IFACE" parent 1: classid 1:1 htb rate "${MBIT}mbit" ceil "${MBIT}mbit"
    tc class replace dev "$IFACE" parent 1:1 classid 1:10 htb rate "${MBIT}mbit" ceil "${MBIT}mbit"

    if tc qdisc replace dev "$IFACE" parent 1:10 handle 10: fq 2>/dev/null; then
        LEAF_USED="fq"
    elif tc qdisc replace dev "$IFACE" parent 1:10 handle 10: fq_codel 2>/dev/null; then
        LEAF_USED="fq_codel"
    else
        LEAF_USED="none"
    fi

    log "applied iface=$IFACE egress=${MBIT}mbit leaf=$LEAF_USED"
    echo "已应用出口总限速：$IFACE ${MBIT}mbit，叶子队列：$LEAF_USED"
}

stop_limit() {
    load_conf || true
    if test -z "${IFACE:-}"; then IFACE="$(default_iface)"; fi
    test -n "${IFACE:-}" || { echo "无法识别默认出口网卡"; exit 1; }
    if ! valid_restore "${RESTORE:-fq}"; then RESTORE="fq"; fi

    tc qdisc del dev "$IFACE" root 2>/dev/null || true
    tc qdisc replace dev "$IFACE" root "$RESTORE" 2>/dev/null || tc qdisc replace dev "$IFACE" root fq 2>/dev/null || true
    log "stopped iface=$IFACE restore=${RESTORE:-fq}"
    echo "已停用 TC 限速，并尝试恢复 root qdisc=${RESTORE:-fq}：$IFACE"
}

status_limit() {
    load_conf || true
    if test -z "${IFACE:-}"; then IFACE="$(default_iface)"; fi
    echo "配置文件：$CONF"
    echo "TC_ENABLE=${TC_ENABLE:-0}"
    echo "网卡：${IFACE:-unknown}"
    echo "出口上限：${MBIT:-unset} Mbit/s"
    echo "恢复 qdisc：${RESTORE:-fq}"
    echo
    if test -n "${IFACE:-}"; then
        echo "[qdisc]"
        tc qdisc show dev "$IFACE" 2>/dev/null || true
        echo
        echo "[class]"
        tc class show dev "$IFACE" 2>/dev/null || true
        echo
        echo "[qdisc stats]"
        tc -s qdisc show dev "$IFACE" 2>/dev/null || true
    fi
}

case "${1:-status}" in
    apply) apply_limit ;;
    stop) stop_limit ;;
    status) status_limit ;;
    *) echo "用法：$0 {apply|stop|status}"; exit 1 ;;
esac
EOF

    chmod +x "$E94_TC_SCRIPT" 2>/dev/null || true

    cat > "$E94_TC_SERVICE" <<EOF
[Unit]
Description=Xray V198e94 egress TC bandwidth limiter
After=network-online.target
Wants=network-online.target

[Service]
Type=oneshot
ExecStart=$E94_TC_SCRIPT apply
ExecStop=$E94_TC_SCRIPT stop
RemainAfterExit=yes

[Install]
WantedBy=multi-user.target
EOF

    systemctl daemon-reload >/dev/null 2>&1 || true
}

_e94_tc_write_conf() {
    local mbit="${1:-}" enable="${2:-0}" iface="${3:-auto}" restore="${4:-fq}"

    if test -n "$mbit"; then
        if ! _e94_valid_mbit "$mbit"; then
            error "带宽上限无效：$mbit，允许范围 1-10000 Mbit/s。"
            return 1
        fi
    fi
    if ! _e94_valid_iface_or_auto "$iface"; then
        error "网卡无效：$iface。请输入 auto 或 /sys/class/net 中存在的网卡名。"
        return 1
    fi
    if ! _e94_valid_restore_qdisc "$restore"; then
        error "恢复 qdisc 无效：$restore，仅允许 fq/fq_codel/pfifo_fast/cake。"
        return 1
    fi

    _e94_prepare_dirs
    cat > "$E94_TC_CONF" <<EOF
# V198e94 TC bandwidth control config
TC_ENABLE=$enable
TC_IFACE="$iface"
TC_EGRESS_MBIT="$mbit"
TC_LEAF_QDISC="fq"
TC_RESTORE_QDISC="$restore"
TC_MODE="egress-htb-fq"
EOF
    chmod 600 "$E94_TC_CONF" 2>/dev/null || true
    info "已写入 TC 配置：$E94_TC_CONF"
}

_e94_tc_prompt_conf() {
    local default_enable="${1:-0}" bw iface restore
    read -rp "请输入出口总上限 Mbit/s，例如 80、100、300、800: " bw || true
    if ! _e94_valid_mbit "$bw"; then
        error "带宽上限无效：$bw"
        return 1
    fi
    read -rp "请输入网卡名，直接回车=auto 默认出口网卡: " iface || true
    iface="${iface:-auto}"
    if ! _e94_valid_iface_or_auto "$iface"; then
        error "网卡无效：$iface"
        return 1
    fi
    read -rp "停用后恢复 qdisc [fq/fq_codel/pfifo_fast/cake]，默认 fq: " restore || true
    restore="${restore:-fq}"
    if ! _e94_valid_restore_qdisc "$restore"; then
        error "恢复 qdisc 无效：$restore"
        return 1
    fi
    _e94_tc_write_conf "$bw" "$default_enable" "$iface" "$restore"
}

_e94_tc_enable_config_inplace() {
    test -f "$E94_TC_CONF" || _e94_install_tc_component
    local mbit iface restore
    mbit="$(_e94_tc_current_conf_value TC_EGRESS_MBIT)"
    iface="$(_e94_tc_current_conf_value TC_IFACE)"
    restore="$(_e94_tc_current_conf_value TC_RESTORE_QDISC)"
    iface="${iface:-auto}"
    restore="${restore:-fq}"
    if ! _e94_valid_mbit "$mbit"; then
        error "当前配置没有有效出口上限，请先设置。"
        return 1
    fi
    _e94_tc_write_conf "$mbit" 1 "$iface" "$restore"
}

do_tc_bandwidth_menu_e94() {
    _e94_install_tc_component || true

    while true; do
        clear
        title "V198e94：TC 带宽控制模块（出口上限 / 启停 / 开机自启）"
        local iface qdisc enabled active mbit tenable restore conf_iface
        iface="$(_e94_default_iface 2>/dev/null || echo "")"
        qdisc=""
        if test -n "$iface"; then qdisc=$(tc qdisc show dev "$iface" 2>/dev/null | head -n 1 || true); fi
        enabled=$(systemctl is-enabled xray-tc-limit-e94.service 2>/dev/null || echo "disabled")
        active=$(systemctl is-active xray-tc-limit-e94.service 2>/dev/null || echo "inactive")
        tenable="$(_e94_tc_current_conf_value TC_ENABLE)"; tenable="${tenable:-0}"
        mbit="$(_e94_tc_current_conf_value TC_EGRESS_MBIT)"
        restore="$(_e94_tc_current_conf_value TC_RESTORE_QDISC)"; restore="${restore:-fq}"
        conf_iface="$(_e94_tc_current_conf_value TC_IFACE)"; conf_iface="${conf_iface:-auto}"

        echo -e "  默认出口网卡: ${cyan}${iface:-未知}${none}"
        echo -e "  当前 root qdisc: ${cyan}${qdisc:-未读取}${none}"
        echo -e "  TC配置启用: ${cyan}${tenable}${none} | 服务: ${cyan}${active}/${enabled}${none}"
        echo -e "  配置网卡: ${cyan}${conf_iface}${none} | 出口上限: ${cyan}${mbit:-未设置}${none} Mbit/s | 停用恢复: ${cyan}${restore}${none}"
        hr
        echo "  1) 查看 TC / qdisc / class / stats 当前状态"
        echo "  2) 设置出口总上限，并立即开启"
        echo "  3) 只写入出口总上限配置，不立即开启"
        echo "  4) 按当前配置立即开启 TC 限速"
        echo "  5) 立即关闭 TC 限速，恢复默认 qdisc，并保留配置"
        echo "  6) 开启开机自动启用 TC 限速（要求已有有效上限）"
        echo "  7) 关闭开机自动启用 TC 限速"
        echo "  8) 恢复默认：关闭限速 + 禁用开机自启 + 配置改为不启用"
        echo "  9) 查看 e94 TC 日志"
        echo "  10) 删除 e94 TC 组件（服务/脚本/配置）"
        echo "  11) 查看 TC/BBR/fq/cake 关系说明"
        echo "  0) 返回主菜单"
        hr

        local opt=""
        read -rp "请选择: " opt || true
        case "${opt:-}" in
            1)
                "$E94_TC_SCRIPT" status || true
                _e94_pause
                ;;
            2)
                if _e94_tc_prompt_conf 1; then
                    "$E94_TC_SCRIPT" apply || warn "TC 应用失败，请查看：$E94_TC_LOG"
                fi
                _e94_pause
                ;;
            3)
                _e94_tc_prompt_conf 0 || true
                info "已只写入配置；TC_ENABLE=0，不会立即限速。"
                _e94_pause
                ;;
            4)
                if _e94_tc_enable_config_inplace; then
                    "$E94_TC_SCRIPT" apply || warn "TC 应用失败，请检查带宽上限和网卡。"
                fi
                _e94_pause
                ;;
            5)
                "$E94_TC_SCRIPT" stop || true
                sed -i 's/^TC_ENABLE=.*/TC_ENABLE=0/' "$E94_TC_CONF" 2>/dev/null || true
                info "已关闭当前 TC 限速，配置保留但默认不启用。"
                _e94_pause
                ;;
            6)
                if _e94_tc_enable_config_inplace; then
                    systemctl enable xray-tc-limit-e94.service >/dev/null 2>&1 || true
                    info "已开启开机自动启用 TC 限速。"
                    warn "注意：开机自启只会在 TC_ENABLE=1 且上限有效时生效。"
                fi
                _e94_pause
                ;;
            7)
                systemctl disable xray-tc-limit-e94.service >/dev/null 2>&1 || true
                info "已关闭开机自动启用 TC 限速；当前 qdisc 不会被此操作立即改变。"
                _e94_pause
                ;;
            8)
                systemctl disable --now xray-tc-limit-e94.service >/dev/null 2>&1 || true
                "$E94_TC_SCRIPT" stop || true
                _e94_tc_write_conf "" 0 "auto" "fq" || true
                info "已恢复默认：TC 不启用、不开机自启、root qdisc 尝试恢复 fq。"
                _e94_pause
                ;;
            9)
                tail -n 80 "$E94_TC_LOG" 2>/dev/null || warn "暂无日志：$E94_TC_LOG"
                _e94_pause
                ;;
            10)
                systemctl disable --now xray-tc-limit-e94.service >/dev/null 2>&1 || true
                "$E94_TC_SCRIPT" stop >/dev/null 2>&1 || true
                rm -f "$E94_TC_SERVICE" "$E94_TC_SCRIPT" "$E94_TC_CONF" 2>/dev/null || true
                systemctl daemon-reload >/dev/null 2>&1 || true
                info "已删除 e94 TC 组件。"
                _e94_pause
                ;;
            11)
                cat <<'EOF'
TC 带宽控制说明：

1. 本模块用于限制 VPS 出口总带宽，不是提速器。
2. 启用后，默认出口网卡 root qdisc 会由 HTB 接管。
3. HTB 负责总上限，叶子队列优先挂 fq；fq 能较好配合 BBR pacing。
4. 如果你正在使用 CAKE，启用本模块会与 CAKE root qdisc 冲突。
5. 推荐限速到“晚高峰稳定速度”的 85%-95%，避免跑满端口制造排队和丢包。
6. 关闭时会按配置尝试恢复 fq/fq_codel/pfifo_fast/cake；“恢复默认”会同时禁用开机自启并把 TC_ENABLE=0。
7. “只写配置不立即开启”会写 TC_ENABLE=0；必须选 4 或 6 才会改为 TC_ENABLE=1。
EOF
                _e94_pause
                ;;
            0) return ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

hot_update_from_legacy() {
    title "V198e94：稳态热更新（修复速度诊断 + 精细 TC 控制）"
    if declare -F hot_update_from_legacy_e93_base >/dev/null 2>&1; then
        hot_update_from_legacy_e93_base "$@" || true
    fi

    _e94_prepare_dirs
    _e94_install_tc_component || true
    # 热更新只安装 TC 组件，不启用限速，不启用开机自启。
    systemctl disable xray-tc-limit-e94.service >/dev/null 2>&1 || true
    sed -i 's/^TC_ENABLE=.*/TC_ENABLE=0/' "$E94_TC_CONF" 2>/dev/null || true

    # 不主动停用 e93 TC，避免改变正在运行的网络状态；只提示用户后续可在 e94 菜单里统一恢复默认。
    if systemctl is-active --quiet xray-tc-limit-e93.service 2>/dev/null; then
        warn "检测到旧 e93 TC 服务仍处于 active；e94 不会强行停止，以免改变当前链路。建议进入 20 菜单手动恢复默认。"
    fi

    e92_boot_kernel_safety_audit >/dev/null 2>&1 || true

    echo "198e94" > "$SCRIPT_VERSION_FILE" 2>/dev/null || true
    if test -f "${SCRIPT_PATH:-$0}"; then
        cp -f "${SCRIPT_PATH:-$0}" "$SYMLINK" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e94.sh" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
        chmod +x "$SYMLINK" "$SCRIPT_DIR/ex198e94.sh" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
    fi

    info "V198e94 热更新完成。"
    info "修复：19 完整诊断报告 awk 转义报错。"
    info "新增/重设：20 TC 带宽控制模块 e94 版；默认关闭、不开机自启。"
}

main_menu() {
    while true; do
        clear
        echo -e "${blue}======================================================================${none}"
        echo -e "  ${magenta}Xray System Advanced Management V198e94 - (速度诊断修复 + 精细TC控制)${none}"
        local svc sys_ver arch_level dns_mode tz_line notsent_now notsent_perm qdisc cc adv app bbr_cfg
        svc=$(systemctl is-active xray 2>/dev/null || echo "inactive")
        if test "$svc" = "active"; then svc="${green}平稳在线 (Running)${none}"; else svc="${red}离线静默 (Stopped)${none}"; fi
        sys_ver=$(uname -r 2>/dev/null || echo "未探测到数据")
        if declare -F detect_x86_64_level >/dev/null 2>&1; then arch_level="$(detect_x86_64_level 2>/dev/null || echo '?')"; else arch_level="?"; fi
        dns_mode=$(cat "${E67_DNS_MODE_FILE:-/usr/local/etc/xray/dns_mode.txt}" 2>/dev/null || echo auto)
        tz_line=$(date '+%Z %z' 2>/dev/null || echo unknown)
        notsent_now=$(_e88_current_notsent_lowat 2>/dev/null || echo '?')
        notsent_perm=$(_e88_persistent_notsent_lowat 2>/dev/null || echo '?')
        qdisc=$(_e88_sysctl_get net.core.default_qdisc 2>/dev/null || echo '?')
        cc=$(_e88_sysctl_get net.ipv4.tcp_congestion_control 2>/dev/null || echo '?')
        adv=$(_e88_sysctl_get net.ipv4.tcp_adv_win_scale 2>/dev/null || echo '?')
        app=$(_e88_sysctl_get net.ipv4.tcp_app_win 2>/dev/null || echo '?')
        bbr_cfg=$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)
        echo -e "  引擎态势: $svc | 全局快捷指令: ${cyan}xrv${none} | 外部识别 IP: ${yellow}$(_get_ip 2>/dev/null || echo "探测异常")${none}"
        echo -e "  系统装配内核: ${cyan}${sys_ver}${none} | 微架构侦测: x64-v${yellow}${arch_level}${none} | qdisc/cc: ${yellow}${qdisc}/${cc}${none} | BBR配置:${yellow}${bbr_cfg}${none}"
        echo -e "  DNS模式: ${cyan}${dns_mode}${none} | 时间轴: ${cyan}${tz_line}${none} | notsent: ${yellow}${notsent_now}${none}/${cyan}${notsent_perm}${none} | adv/app: ${yellow}${adv}/${app}${none}"
        echo -e "${blue}======================================================================${none}"
        echo "  1) 创建/重构协议节点：Reality Vision / VLESSENC 自选 / SS2022"
        echo "  2) 用户凭证生命周期与独立参数化管理控制"
        echo "  3) 节点链接与多维信息输出聚合中心"
        echo "  4) 人工发起数据强联，执行路由解析规则库强制覆盖更新"
        echo "  5) Xray Core 手动更新/修复（不设置自动更新）"
        echo "  6) 修改或全自动剔除被拦截的防封伪装特征矩阵域名"
        echo "  7) 系统防火墙策略配置 (阻止内网 BT 滥用及第三方广告请求)"
        echo "  8) Reality Fallback 底层限速沙盒分析器"
        echo "  9) 全景网络连接审计日志与商用级别网络流量记账本"
        echo "  10) 高级发烧：内核双轨编译(APT/源码)/网络/应用层 60余项极限全控板"
        echo -e "  ${cyan}11) 从旧 ex198e 环境稳态热更新到 V198e94${none}"
        echo -e "  ${cyan}12) 清理空间（安全释放 / 快照收敛 / 显示硬盘与 Swap）${none}"
        echo -e "  ${cyan}13) 应用网络参数（缓冲/notsent/adv_win/app_win/txqueue/OOOX/MSS）${none}"
        echo -e "  ${cyan}14) TCP 重传 / 单连接诊断中心（只读排障）${none}"
        echo -e "  ${cyan}15) 检查现有配置并重新输出节点${none}"
        echo -e "  ${cyan}16) 状态隔离审计 + VLESSENC 能力检查${none}"
        echo -e "  ${magenta}17) BBR 本体替换 / 自定义编译中心（模块m/内置y双路线）${none}"
        echo -e "  ${cyan}18) V198e92 安全审计 / Top20复测 / 启动防砖中心${none}"
        echo -e "  ${cyan}19) Xray 跨境链路速度诊断中心（V198e94修复版）${none}"
        echo -e "  ${cyan}20) TC 带宽控制模块（精细上限/启停/开机自启/恢复默认）${none}"
        echo "  0) 折叠命令控制台，返回底层终端"
        echo -e "  ${red}88) 物理不可逆自毁！撤销环境安全防线与系统配置设定${none}"
        hr
        local num=""
        read -rp "请输入操作代码指令: " num || true
        case "${num:-}" in
            1) do_install ;;
            2) do_user_manager ;;
            3) do_summary; while true; do local rb=""; read -rp "输出完毕，按 Enter 退出或者按 b 发起特征替换: " rb || true; if test "$rb" = "b" || test "$rb" = "B"; then if choose_sni; then _update_matrix; do_summary; else break; fi; else break; fi; done ;;
            4) print_magenta ">>> 初始化云网络联通..."; bash "$UPDATE_DAT_SCRIPT" >/dev/null 2>&1 || true; ensure_xray_is_alive; info "配置已穿透替换系统！当前路由库完成热加载！"; local _p=""; read -rp "按 Enter 退回..." _p || true ;;
            5) do_update_core ;;
            6) if choose_sni; then _update_matrix; do_summary; while true; do local rb=""; read -rp "任务完毕，按 Enter 返回，或按 b 连续变更: " rb || true; if test "$rb" = "b" || test "$rb" = "B"; then if choose_sni; then _update_matrix; do_summary; else break; fi; else break; fi; done; fi ;;
            7) _global_block_rules ;;
            8) do_fallback_probe ;;
            9) do_status_menu ;;
            10) do_sys_init_menu ;;
            11) hot_update_from_legacy ;;
            12) do_space_cleanup_menu ;;
            13) do_network_params_menu_e56 ;;
            14) do_tcp_diag_menu_e63 ;;
            15) do_install_repair_e77 ;;
            16) e77_audit_runtime_state; _e94_pause ;;
            17) do_bbr_body_replace_menu_e89 ;;
            18) do_e92_audit_center ;;
            19) do_xray_speed_diag_menu_e94 ;;
            20) do_tc_bandwidth_menu_e94 ;;
            88) do_uninstall ;;
            0) exit 0 ;;
            *) echo -e "${red}错误拦截：代码解析为空值！${none}"; sleep 1 ;;
        esac
    done
}

#==============================================================================
# EOF - Apex Vanguard V198e94 Speed Diagnosis Fix + Fine TC Control Layer.
#==============================================================================

#==============================================================================
# V198e95 FINAL OVERRIDE LAYER
# 目标：
#   1) 审计并修复 V198e94 的遗漏：旧 e93/e94 TC 残留、自启混杂、菜单只管当前版本的问题；
#   2) 重新设计 19) 速度诊断中心：显示 actual root qdisc、TC 状态、legacy TC 状态；
#   3) 重新设计 20) TC 控制：统一接管 e93/e94/e95，支持自定义上限、开启/关闭、自启、恢复默认不启用；
#   4) 热更新默认安全：只安装 e95 组件，禁用 e95/旧版 TC 自启，不主动改当前 qdisc。
#==============================================================================

if declare -F hot_update_from_legacy >/dev/null 2>&1; then
    eval "$(declare -f hot_update_from_legacy | sed '1s/hot_update_from_legacy/hot_update_from_legacy_e94_base/')"
fi

E95_AUDIT_DIR="$CONFIG_DIR/audit_e95"
E95_SPEED_AUDIT_DIR="$E95_AUDIT_DIR/speed"
E95_TC_CONF="$CONFIG_DIR/tc-limit-e95.conf"
E95_TC_SCRIPT="/usr/local/bin/xray-tc-limit-e95.sh"
E95_TC_SERVICE="/etc/systemd/system/xray-tc-limit-e95.service"
E95_TC_LOG="$LOG_DIR/tc-limit-e95.log"

_e95_pause() { local _p=""; read -rp "按 Enter 继续..." _p || true; }
_e95_ts() { date +%Y%m%d_%H%M%S; }

_e95_prepare_dirs() {
    mkdir -p "$CONFIG_DIR" "$SCRIPT_DIR" "$BACKUP_DIR" "$LOG_DIR" "$E95_AUDIT_DIR" "$E95_SPEED_AUDIT_DIR" 2>/dev/null || true
}

_e95_default_iface() {
    ip route get 1.1.1.1 2>/dev/null | awk '{for(i=1;i<=NF;i++) if($i=="dev"){print $(i+1); exit}}'
}

_e95_root_qdisc_line() {
    local iface="${1:-}"
    if test -n "$iface"; then
        tc qdisc show dev "$iface" 2>/dev/null | head -n 1 || true
    fi
}

_e95_xray_pid() {
    local p=""
    p=$(systemctl show -p MainPID --value xray 2>/dev/null | awk 'NF{print $1; exit}' || true)
    if [[ "$p" =~ ^[0-9]+$ ]]; then echo "$p"; else echo 0; fi
}

_e95_proc_fd() {
    local pid="${1:-0}"
    if [[ "$pid" =~ ^[0-9]+$ ]] && test "$pid" -gt 0 2>/dev/null && test -d "/proc/$pid/fd"; then
        find "/proc/$pid/fd" -maxdepth 1 -type l 2>/dev/null | wc -l | awk '{print int($1)}'
    else
        echo 0
    fi
}

_e95_proc_rss_mb() {
    local pid="${1:-0}"
    if [[ "$pid" =~ ^[0-9]+$ ]] && test "$pid" -gt 0 2>/dev/null; then
        ps -o rss= -p "$pid" 2>/dev/null | awk 'NF{printf "%.1fMB\n", $1/1024; found=1} END{if(!found) print "?"}' || echo "?"
    else
        echo "?"
    fi
}

_e95_proc_cpu_pct() {
    local pid="${1:-0}"
    if [[ "$pid" =~ ^[0-9]+$ ]] && test "$pid" -gt 0 2>/dev/null; then
        ps -o %cpu= -p "$pid" 2>/dev/null | awk 'NF{printf "%s%%\n", $1; found=1} END{if(!found) print "?"}' || echo "?"
    else
        echo "?"
    fi
}

_e95_ping_summary() {
    local host="${1:-1.1.1.1}" count="${2:-6}"
    if ! command -v ping >/dev/null 2>&1; then echo "缺少 ping/iputils-ping"; return 0; fi
    ping -c "$count" -W 2 "$host" 2>/dev/null | awk '
        /packets transmitted/ {print "  " $0}
        /rtt min|round-trip/ {print "  " $0}
    ' || echo "  ping 失败：$host"
}

_e95_http_timing() {
    local url="${1:-https://www.cloudflare.com}"
    if ! command -v curl >/dev/null 2>&1; then echo "缺少 curl"; return 0; fi
    curl -k -sL -o /dev/null --connect-timeout 4 -m 10 \
        -w "  url=%{url_effective}\n  dns=%{time_namelookup}s connect=%{time_connect}s tls=%{time_appconnect}s ttfb=%{time_starttransfer}s total=%{time_total}s speed=%{speed_download}B/s\n" \
        "$url" 2>/dev/null || echo "  curl 失败：$url"
}

_e95_conntrack_status() {
    if sysctl net.netfilter.nf_conntrack_count >/dev/null 2>&1; then
        sysctl net.netfilter.nf_conntrack_count net.netfilter.nf_conntrack_max 2>/dev/null || true
        local c m pct
        c=$(sysctl -n net.netfilter.nf_conntrack_count 2>/dev/null || echo 0)
        m=$(sysctl -n net.netfilter.nf_conntrack_max 2>/dev/null || echo 0)
        if [[ "$c" =~ ^[0-9]+$ ]] && [[ "$m" =~ ^[0-9]+$ ]] && test "$m" -gt 0 2>/dev/null; then
            pct=$(awk -v c="$c" -v m="$m" 'BEGIN{printf "%.1f", c*100/m}')
            echo "conntrack_usage=${pct}%"
        fi
    else
        echo "conntrack sysctl 未启用或不可读"
    fi
}

_e95_tc_service_state() {
    local v="$1"
    echo "xray-tc-limit-${v}.service active=$(systemctl is-active xray-tc-limit-${v}.service 2>/dev/null || echo inactive) enabled=$(systemctl is-enabled xray-tc-limit-${v}.service 2>/dev/null || echo disabled)"
}

_e95_tc_legacy_status() {
    _e95_tc_service_state e93
    _e95_tc_service_state e94
    _e95_tc_service_state e95
}

do_xray_speed_diag_report_e95() {
    _e95_prepare_dirs
    local ts out iface pid cc qdisc_default qdisc_actual mtu fd rss cpu est
    ts="$(_e95_ts)"
    out="$E95_SPEED_AUDIT_DIR/xray_speed_diag_$ts.txt"
    iface="$(_e95_default_iface 2>/dev/null || echo "")"
    pid="$(_e95_xray_pid)"
    cc=$(sysctl -n net.ipv4.tcp_congestion_control 2>/dev/null || echo "?")
    qdisc_default=$(sysctl -n net.core.default_qdisc 2>/dev/null || echo "?")
    qdisc_actual="$(_e95_root_qdisc_line "$iface")"
    mtu="?"; test -n "$iface" && mtu=$(cat /sys/class/net/"$iface"/mtu 2>/dev/null || echo "?")
    fd="$(_e95_proc_fd "$pid")"
    rss="$(_e95_proc_rss_mb "$pid")"
    cpu="$(_e95_proc_cpu_pct "$pid")"
    est=$(ss -Htan state established 2>/dev/null | wc -l 2>/dev/null | awk '{print int($1)}' || echo 0)

    {
        echo "V198e95 Xray cross-border speed diagnosis"
        echo "time=$(date '+%F %T')"
        echo "kernel=$(uname -r 2>/dev/null || echo unknown)"
        echo "iface=${iface:-unknown}"
        echo "mtu=$mtu cc=$cc default_qdisc_sysctl=$qdisc_default"
        echo "actual_root_qdisc=${qdisc_actual:-unknown}"
        echo "xray_active=$(systemctl is-active xray 2>/dev/null || echo inactive)"
        echo "xray_enabled=$(systemctl is-enabled xray 2>/dev/null || echo disabled)"
        echo "xray_pid=$pid"
        echo "xray_fd=$fd"
        echo "xray_rss=$rss"
        echo "xray_cpu=$cpu"
        echo "established=$est"
        echo ""
        echo "[tc service states]"
        _e95_tc_legacy_status
        echo ""
        echo "[ping 1.1.1.1]"
        _e95_ping_summary 1.1.1.1 6
        echo ""
        echo "[ping 8.8.8.8]"
        _e95_ping_summary 8.8.8.8 6
        echo ""
        echo "[http timing cloudflare]"
        _e95_http_timing https://www.cloudflare.com
        echo ""
        echo "[http timing microsoft]"
        _e95_http_timing https://www.microsoft.com
        echo ""
        echo "[qdisc]"
        if test -n "$iface"; then
            tc qdisc show dev "$iface" 2>/dev/null || true
            echo ""
            tc -s qdisc show dev "$iface" 2>/dev/null || true
            echo ""
            tc class show dev "$iface" 2>/dev/null || true
        else
            echo "未识别默认网卡"
        fi
        echo ""
        echo "[route]"
        ip route show table main 2>/dev/null || true
        echo ""
        echo "[offload]"
        if test -n "$iface"; then ethtool -k "$iface" 2>/dev/null | sed -n '1,100p' || true; fi
        echo ""
        echo "[queues]"
        if test -n "$iface"; then
            for p in /sys/class/net/"$iface"/queues/rx-* /sys/class/net/"$iface"/queues/tx-*; do
                test -d "$p" || continue
                echo "$p"
                test -f "$p/rps_cpus" && echo "  rps_cpus=$(cat "$p/rps_cpus" 2>/dev/null)"
                test -f "$p/xps_cpus" && echo "  xps_cpus=$(cat "$p/xps_cpus" 2>/dev/null)"
            done
        fi
        echo ""
        echo "[tcp sysctl key]"
        sysctl net.ipv4.tcp_congestion_control net.core.default_qdisc net.ipv4.tcp_rmem net.ipv4.tcp_wmem net.ipv4.tcp_notsent_lowat net.ipv4.tcp_mtu_probing 2>/dev/null || true
        echo ""
        echo "[conntrack]"
        _e95_conntrack_status || true
        dmesg 2>/dev/null | grep -i conntrack | tail -n 5 || true
        echo ""
        echo "[BBR/TCP connections]"
        ss -tin 2>/dev/null | grep -iE 'bbr|rtt|pacing_rate|bytes_acked|delivery_rate|retrans|cwnd|ssthresh' | head -n 80 || true
        echo ""
        echo "[top remote ips]"
        ss -Htan state established 2>/dev/null | awk '{print $5}' | sed -E 's/^\[?([^]]+)\]?:[0-9]+$/\1/' | sort | uniq -c | sort -nr | head -n 15 || true
        echo ""
        echo "[xray unit security hint]"
        systemctl cat xray 2>/dev/null | sed -n '1,100p' || true
        echo ""
        echo "[journal xray]"
        journalctl -u xray.service --no-pager -n 30 2>/dev/null || true
    } > "$out"

    info "Xray 跨境链路速度诊断报告：$out"
    sed -n '1,160p' "$out" 2>/dev/null || true
}

do_xray_speed_diag_menu_e95() {
    while true; do
        clear
        title "V198e95：Xray 跨境链路速度诊断中心"
        local iface cc qdisc_default qdisc_actual pid est mtu rss cpu fd
        iface="$(_e95_default_iface 2>/dev/null || echo "")"
        cc=$(sysctl -n net.ipv4.tcp_congestion_control 2>/dev/null || echo "?")
        qdisc_default=$(sysctl -n net.core.default_qdisc 2>/dev/null || echo "?")
        qdisc_actual="$(_e95_root_qdisc_line "$iface")"
        pid="$(_e95_xray_pid)"
        est=$(ss -Htan state established 2>/dev/null | wc -l 2>/dev/null | awk '{print int($1)}' || echo 0)
        mtu="?"; test -n "$iface" && mtu=$(cat /sys/class/net/"$iface"/mtu 2>/dev/null || echo "?")
        fd="$(_e95_proc_fd "$pid")"
        rss="$(_e95_proc_rss_mb "$pid")"
        cpu="$(_e95_proc_cpu_pct "$pid")"
        echo -e "  默认网卡: ${cyan}${iface:-未知}${none} | MTU: ${cyan}${mtu}${none} | cc/sysctl_qdisc: ${cyan}${cc}/${qdisc_default}${none}"
        echo -e "  实际 root qdisc: ${cyan}${qdisc_actual:-未读取}${none}"
        echo -e "  Xray PID: ${cyan}${pid}${none} | FD/RSS/CPU: ${cyan}${fd}/${rss}/${cpu}${none} | ESTABLISHED: ${cyan}${est}${none}"
        hr
        echo "  1) 生成完整诊断报告（推荐）"
        echo "  2) CPU / 内存 / FD / 连接数检查"
        echo "  3) RTT / 丢包快速测试"
        echo "  4) HTTP DNS/连接/TLS/TTFB 耗时测试"
        echo "  5) BBR / TCP 连接摘要"
        echo "  6) qdisc / MTU / offload / 网卡队列检查"
        echo "  7) conntrack / 防火墙容量检查"
        echo "  8) TC e93/e94/e95 服务状态检查"
        echo "  9) 诊断结论说明：应该先看哪一层"
        echo "  0) 返回主菜单"
        hr
        local opt=""
        read -rp "请选择: " opt || true
        case "${opt:-}" in
            1) do_xray_speed_diag_report_e95; _e95_pause ;;
            2)
                echo "Xray 状态：$(systemctl is-active xray 2>/dev/null || echo inactive) / $(systemctl is-enabled xray 2>/dev/null || echo disabled)"
                echo "PID=$pid FD=$fd RSS=$rss CPU=$cpu ESTABLISHED=$est"
                echo ""
                if [[ "$pid" =~ ^[0-9]+$ ]] && test "$pid" -gt 0 2>/dev/null; then
                    ps -o pid,ppid,stat,%cpu,%mem,rss,etime,cmd -p "$pid" 2>/dev/null || true
                fi
                echo ""
                free -h 2>/dev/null || true
                echo ""
                uptime 2>/dev/null || true
                _e95_pause
                ;;
            3)
                echo "[ping 1.1.1.1]"; _e95_ping_summary 1.1.1.1 8
                echo ""; echo "[ping 8.8.8.8]"; _e95_ping_summary 8.8.8.8 8
                _e95_pause
                ;;
            4)
                echo "[Cloudflare]"; _e95_http_timing https://www.cloudflare.com
                echo ""; echo "[Microsoft]"; _e95_http_timing https://www.microsoft.com
                echo ""; echo "[Apple]"; _e95_http_timing https://www.apple.com
                _e95_pause
                ;;
            5)
                ss -tin 2>/dev/null | grep -iE 'bbr|rtt|pacing_rate|bytes_acked|delivery_rate|retrans|cwnd|ssthresh' | head -n 100 || true
                _e95_pause
                ;;
            6)
                echo "iface=${iface:-unknown} mtu=$mtu cc=$cc default_qdisc_sysctl=$qdisc_default"
                echo "actual_root_qdisc=${qdisc_actual:-unknown}"
                echo ""
                test -n "$iface" && tc qdisc show dev "$iface" 2>/dev/null || true
                echo ""; test -n "$iface" && tc -s qdisc show dev "$iface" 2>/dev/null || true
                echo ""; test -n "$iface" && tc class show dev "$iface" 2>/dev/null || true
                echo ""; test -n "$iface" && ethtool -k "$iface" 2>/dev/null | sed -n '1,120p' || true
                echo ""; test -n "$iface" && find /sys/class/net/"$iface"/queues -maxdepth 2 -type f \( -name rps_cpus -o -name xps_cpus \) -print -exec cat {} \; 2>/dev/null || true
                _e95_pause
                ;;
            7)
                _e95_conntrack_status || true
                dmesg 2>/dev/null | grep -i conntrack | tail -n 10 || true
                _e95_pause
                ;;
            8)
                _e95_tc_legacy_status
                _e95_pause
                ;;
            9)
                cat <<'EOF'
诊断顺序建议：

1. 先看线路：RTT、丢包、晚高峰波动。
2. 再看实际 root qdisc：不要只看 sysctl default_qdisc；启用 TC 后实际 root 可能是 htb。
3. 再看 Xray：CPU、RSS、FD、连接数、日志。
4. 再看 TCP：BBR 状态、重传、rtt、pacing_rate、delivery_rate。
5. 再看队列：fq/cake/HTB 是否冲突，e93/e94/e95 TC 是否残留。
6. 再看网卡：MTU、offload、RPS/XPS、虚拟化队列。
7. 最后才调 sysctl/BBR 参数；不要一上来堆大缓冲。
EOF
                _e95_pause
                ;;
            0) return ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

_e95_valid_mbit() {
    local v="${1:-}"
    [[ "$v" =~ ^[0-9]+$ ]] || return 1
    test "$v" -ge 1 2>/dev/null || return 1
    test "$v" -le 10000 2>/dev/null || return 1
}

_e95_valid_leaf_qdisc() {
    case "${1:-fq}" in fq|fq_codel) return 0 ;; *) return 1 ;; esac
}

_e95_valid_restore_qdisc() {
    case "${1:-fq}" in fq|fq_codel|pfifo_fast|cake) return 0 ;; *) return 1 ;; esac
}

_e95_valid_iface_or_auto() {
    local iface="${1:-auto}"
    test "$iface" = "auto" && return 0
    [[ "$iface" =~ ^[A-Za-z0-9_.:-]+$ ]] || return 1
    test -d "/sys/class/net/$iface"
}

_e95_tc_current_conf_value() {
    local key="$1"
    test -f "$E95_TC_CONF" || return 0
    awk -F= -v k="$key" '$1==k {gsub(/"/,"",$2); print $2; exit}' "$E95_TC_CONF" 2>/dev/null || true
}

_e95_install_tc_component() {
    _e95_prepare_dirs

    if test ! -f "$E95_TC_CONF"; then
        cat > "$E95_TC_CONF" <<'EOF'
# V198e95 TC bandwidth control config
TC_ENABLE=0
TC_IFACE="auto"
TC_EGRESS_MBIT=""
TC_LEAF_QDISC="fq"
TC_RESTORE_QDISC="fq"
TC_MODE="egress-htb-fq"
EOF
        chmod 600 "$E95_TC_CONF" 2>/dev/null || true
    fi

    cat > "$E95_TC_SCRIPT" <<'EOF'
#!/usr/bin/env bash
set -euo pipefail
PATH="/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin"

CONF="/usr/local/etc/xray/tc-limit-e95.conf"
LOG="/var/log/xray/tc-limit-e95.log"

log() {
    mkdir -p "$(dirname "$LOG")" 2>/dev/null || true
    echo "[$(date '+%F %T')] $*" >> "$LOG" 2>/dev/null || true
}

default_iface() {
    ip route get 1.1.1.1 2>/dev/null | awk '{for(i=1;i<=NF;i++) if($i=="dev"){print $(i+1); exit}}'
}

valid_mbit() {
    local v="${1:-}"
    [[ "$v" =~ ^[0-9]+$ ]] || return 1
    test "$v" -ge 1 2>/dev/null || return 1
    test "$v" -le 10000 2>/dev/null || return 1
}

valid_leaf() {
    case "${1:-fq}" in fq|fq_codel) return 0 ;; *) return 1 ;; esac
}

valid_restore() {
    case "${1:-fq}" in fq|fq_codel|pfifo_fast|cake) return 0 ;; *) return 1 ;; esac
}

load_conf() {
    if test ! -f "$CONF"; then
        echo "配置文件不存在：$CONF"
        exit 1
    fi
    # shellcheck disable=SC1090
    . "$CONF"

    IFACE="${TC_IFACE:-auto}"
    if test "$IFACE" = "auto"; then IFACE="$(default_iface)"; fi
    MBIT="${TC_EGRESS_MBIT:-}"
    RESTORE="${TC_RESTORE_QDISC:-fq}"
    LEAF="${TC_LEAF_QDISC:-fq}"

    test -n "${IFACE:-}" || { echo "无法识别默认出口网卡"; exit 1; }
    if ! test -d "/sys/class/net/$IFACE"; then echo "网卡不存在：$IFACE"; exit 1; fi
    if ! valid_restore "$RESTORE"; then RESTORE="fq"; fi
    if ! valid_leaf "$LEAF"; then LEAF="fq"; fi
}

apply_limit() {
    load_conf

    if test "${TC_ENABLE:-0}" != "1"; then
        echo "TC_ENABLE=0，未启用。"
        log "skip enable=0"
        exit 0
    fi

    if ! valid_mbit "$MBIT"; then
        echo "TC_EGRESS_MBIT 无效：$MBIT；允许范围 1-10000 Mbit/s"
        exit 1
    fi

    modprobe sch_htb 2>/dev/null || true
    modprobe sch_fq 2>/dev/null || true
    modprobe sch_fq_codel 2>/dev/null || true

    local before_qdisc leaf_used
    before_qdisc="$(tc qdisc show dev "$IFACE" 2>/dev/null | head -n 1 || true)"

    tc qdisc replace dev "$IFACE" root handle 1: htb default 10
    tc class replace dev "$IFACE" parent 1: classid 1:1 htb rate "${MBIT}mbit" ceil "${MBIT}mbit"
    tc class replace dev "$IFACE" parent 1:1 classid 1:10 htb rate "${MBIT}mbit" ceil "${MBIT}mbit"

    if test "$LEAF" = "fq_codel"; then
        if tc qdisc replace dev "$IFACE" parent 1:10 handle 10: fq_codel 2>/dev/null; then leaf_used="fq_codel"; else leaf_used="none"; fi
    else
        if tc qdisc replace dev "$IFACE" parent 1:10 handle 10: fq 2>/dev/null; then
            leaf_used="fq"
        elif tc qdisc replace dev "$IFACE" parent 1:10 handle 10: fq_codel 2>/dev/null; then
            leaf_used="fq_codel"
        else
            leaf_used="none"
        fi
    fi

    log "applied iface=$IFACE egress=${MBIT}mbit leaf=$leaf_used before=[$before_qdisc]"
    echo "已应用出口总限速：$IFACE ${MBIT}mbit，叶子队列：$leaf_used"
}

stop_limit() {
    load_conf || true
    if test -z "${IFACE:-}"; then IFACE="$(default_iface)"; fi
    test -n "${IFACE:-}" || { echo "无法识别默认出口网卡"; exit 1; }
    if ! valid_restore "${RESTORE:-fq}"; then RESTORE="fq"; fi

    tc qdisc del dev "$IFACE" root 2>/dev/null || true
    tc qdisc replace dev "$IFACE" root "$RESTORE" 2>/dev/null || tc qdisc replace dev "$IFACE" root fq 2>/dev/null || true
    log "stopped iface=$IFACE restore=${RESTORE:-fq}"
    echo "已停用 TC 限速，并尝试恢复 root qdisc=${RESTORE:-fq}：$IFACE"
}

status_limit() {
    load_conf || true
    if test -z "${IFACE:-}"; then IFACE="$(default_iface)"; fi
    echo "配置文件：$CONF"
    echo "TC_ENABLE=${TC_ENABLE:-0}"
    echo "网卡：${IFACE:-unknown}"
    echo "出口上限：${MBIT:-unset} Mbit/s"
    echo "叶子队列：${LEAF:-fq}"
    echo "恢复 qdisc：${RESTORE:-fq}"
    echo
    if test -n "${IFACE:-}"; then
        echo "[qdisc]"
        tc qdisc show dev "$IFACE" 2>/dev/null || true
        echo
        echo "[class]"
        tc class show dev "$IFACE" 2>/dev/null || true
        echo
        echo "[qdisc stats]"
        tc -s qdisc show dev "$IFACE" 2>/dev/null || true
    fi
}

case "${1:-status}" in
    apply) apply_limit ;;
    stop) stop_limit ;;
    status) status_limit ;;
    *) echo "用法：$0 {apply|stop|status}"; exit 1 ;;
esac
EOF

    chmod +x "$E95_TC_SCRIPT" 2>/dev/null || true

    cat > "$E95_TC_SERVICE" <<EOF
[Unit]
Description=Xray V198e95 egress TC bandwidth limiter
After=network-online.target
Wants=network-online.target

[Service]
Type=oneshot
ExecStart=$E95_TC_SCRIPT apply
ExecStop=$E95_TC_SCRIPT stop
RemainAfterExit=yes

[Install]
WantedBy=multi-user.target
EOF

    systemctl daemon-reload >/dev/null 2>&1 || true
}

_e95_tc_write_conf() {
    local mbit="${1:-}" enable="${2:-0}" iface="${3:-auto}" restore="${4:-fq}" leaf="${5:-fq}"

    if test -n "$mbit"; then
        if ! _e95_valid_mbit "$mbit"; then
            error "带宽上限无效：$mbit，允许范围 1-10000 Mbit/s。"
            return 1
        fi
    fi
    if ! _e95_valid_iface_or_auto "$iface"; then
        error "网卡无效：$iface。请输入 auto 或 /sys/class/net 中存在的网卡名。"
        return 1
    fi
    if ! _e95_valid_restore_qdisc "$restore"; then
        error "恢复 qdisc 无效：$restore，仅允许 fq/fq_codel/pfifo_fast/cake。"
        return 1
    fi
    if ! _e95_valid_leaf_qdisc "$leaf"; then
        error "叶子 qdisc 无效：$leaf，仅允许 fq/fq_codel。"
        return 1
    fi

    _e95_prepare_dirs
    cat > "$E95_TC_CONF" <<EOF
# V198e95 TC bandwidth control config
TC_ENABLE=$enable
TC_IFACE="$iface"
TC_EGRESS_MBIT="$mbit"
TC_LEAF_QDISC="$leaf"
TC_RESTORE_QDISC="$restore"
TC_MODE="egress-htb-fq"
EOF
    chmod 600 "$E95_TC_CONF" 2>/dev/null || true
    info "已写入 TC 配置：$E95_TC_CONF"
}

_e95_tc_prompt_conf() {
    local default_enable="${1:-0}" bw iface restore leaf
    read -rp "请输入出口总上限 Mbit/s，例如 80、100、300、800: " bw || true
    if ! _e95_valid_mbit "$bw"; then
        error "带宽上限无效：$bw"
        return 1
    fi
    read -rp "请输入网卡名，直接回车=auto 默认出口网卡: " iface || true
    iface="${iface:-auto}"
    if ! _e95_valid_iface_or_auto "$iface"; then
        error "网卡无效：$iface"
        return 1
    fi
    read -rp "HTB 下方叶子队列 [fq/fq_codel]，默认 fq: " leaf || true
    leaf="${leaf:-fq}"
    if ! _e95_valid_leaf_qdisc "$leaf"; then
        error "叶子 qdisc 无效：$leaf"
        return 1
    fi
    read -rp "停用后恢复 qdisc [fq/fq_codel/pfifo_fast/cake]，默认 fq: " restore || true
    restore="${restore:-fq}"
    if ! _e95_valid_restore_qdisc "$restore"; then
        error "恢复 qdisc 无效：$restore"
        return 1
    fi
    _e95_tc_write_conf "$bw" "$default_enable" "$iface" "$restore" "$leaf"
}

_e95_tc_enable_config_inplace() {
    test -f "$E95_TC_CONF" || _e95_install_tc_component
    local mbit iface restore leaf
    mbit="$(_e95_tc_current_conf_value TC_EGRESS_MBIT)"
    iface="$(_e95_tc_current_conf_value TC_IFACE)"
    restore="$(_e95_tc_current_conf_value TC_RESTORE_QDISC)"
    leaf="$(_e95_tc_current_conf_value TC_LEAF_QDISC)"
    iface="${iface:-auto}"
    restore="${restore:-fq}"
    leaf="${leaf:-fq}"
    if ! _e95_valid_mbit "$mbit"; then
        error "当前配置没有有效出口上限，请先设置。"
        return 1
    fi
    _e95_tc_write_conf "$mbit" 1 "$iface" "$restore" "$leaf"
}

_e95_disable_legacy_tc_autostart_only() {
    systemctl disable xray-tc-limit-e93.service >/dev/null 2>&1 || true
    systemctl disable xray-tc-limit-e94.service >/dev/null 2>&1 || true
}

_e95_stop_legacy_tc_if_confirmed() {
    warn "此操作会尝试停止 e93/e94/e95 所有 TC 服务，并恢复 qdisc，可能短暂影响当前连接。"
    local yn=""
    read -rp "确认统一停用旧版/新版 TC？输入 YES 继续: " yn || true
    if test "$yn" != "YES"; then
        warn "已取消。"
        return 1
    fi
    for v in e95 e94 e93; do
        systemctl disable --now "xray-tc-limit-${v}.service" >/dev/null 2>&1 || true
        if test -x "/usr/local/bin/xray-tc-limit-${v}.sh"; then
            "/usr/local/bin/xray-tc-limit-${v}.sh" stop >/dev/null 2>&1 || true
        fi
    done
    _e95_tc_write_conf "" 0 "auto" "fq" "fq" || true
    info "已统一停用 e93/e94/e95 TC 并恢复默认不启用。"
}

do_tc_bandwidth_menu_e95() {
    _e95_install_tc_component || true

    while true; do
        clear
        title "V198e95：TC 带宽控制模块（统一接管 / 精细上限 / 默认不启用）"
        local iface qdisc enabled active mbit tenable restore conf_iface leaf
        iface="$(_e95_default_iface 2>/dev/null || echo "")"
        qdisc="$(_e95_root_qdisc_line "$iface")"
        enabled=$(systemctl is-enabled xray-tc-limit-e95.service 2>/dev/null || echo "disabled")
        active=$(systemctl is-active xray-tc-limit-e95.service 2>/dev/null || echo "inactive")
        tenable="$(_e95_tc_current_conf_value TC_ENABLE)"; tenable="${tenable:-0}"
        mbit="$(_e95_tc_current_conf_value TC_EGRESS_MBIT)"
        restore="$(_e95_tc_current_conf_value TC_RESTORE_QDISC)"; restore="${restore:-fq}"
        leaf="$(_e95_tc_current_conf_value TC_LEAF_QDISC)"; leaf="${leaf:-fq}"
        conf_iface="$(_e95_tc_current_conf_value TC_IFACE)"; conf_iface="${conf_iface:-auto}"

        echo -e "  默认出口网卡: ${cyan}${iface:-未知}${none}"
        echo -e "  当前 root qdisc: ${cyan}${qdisc:-未读取}${none}"
        echo -e "  e95 TC配置启用: ${cyan}${tenable}${none} | e95服务: ${cyan}${active}/${enabled}${none}"
        echo -e "  配置网卡: ${cyan}${conf_iface}${none} | 出口上限: ${cyan}${mbit:-未设置}${none} Mbit/s | leaf/rest: ${cyan}${leaf}/${restore}${none}"
        echo -e "  旧版TC状态: ${yellow}$(_e95_tc_service_state e93) | $(_e95_tc_service_state e94)${none}"
        hr
        echo "  1) 查看 e95 TC / qdisc / class / stats 当前状态"
        echo "  2) 设置出口总上限，并立即开启"
        echo "  3) 只写入出口总上限配置，不立即开启"
        echo "  4) 按当前配置立即开启 TC 限速"
        echo "  5) 立即关闭 e95 TC 限速，恢复默认 qdisc，并保留配置"
        echo "  6) 开启 e95 开机自动启用 TC 限速（要求已有有效上限）"
        echo "  7) 关闭 e95 开机自动启用 TC 限速"
        echo "  8) 恢复默认：关闭 e95 + 禁用 e93/e94/e95 自启 + 配置改为不启用"
        echo "  9) 统一停用旧版 e93/e94/e95 TC（需要 YES 确认）"
        echo "  10) 查看 e95 TC 日志"
        echo "  11) 删除 e95 TC 组件（服务/脚本/配置）"
        echo "  12) 查看 TC/BBR/fq/cake 关系说明"
        echo "  0) 返回主菜单"
        hr

        local opt=""
        read -rp "请选择: " opt || true
        case "${opt:-}" in
            1)
                "$E95_TC_SCRIPT" status || true
                _e95_pause
                ;;
            2)
                if _e95_tc_prompt_conf 1; then
                    "$E95_TC_SCRIPT" apply || warn "TC 应用失败，请查看：$E95_TC_LOG"
                fi
                _e95_pause
                ;;
            3)
                _e95_tc_prompt_conf 0 || true
                info "已只写入配置；TC_ENABLE=0，不会立即限速，不会开机自动启用。"
                _e95_pause
                ;;
            4)
                if _e95_tc_enable_config_inplace; then
                    "$E95_TC_SCRIPT" apply || warn "TC 应用失败，请检查带宽上限和网卡。"
                fi
                _e95_pause
                ;;
            5)
                "$E95_TC_SCRIPT" stop || true
                sed -i 's/^TC_ENABLE=.*/TC_ENABLE=0/' "$E95_TC_CONF" 2>/dev/null || true
                info "已关闭 e95 当前 TC 限速，配置保留但默认不启用。"
                _e95_pause
                ;;
            6)
                if _e95_tc_enable_config_inplace; then
                    systemctl enable xray-tc-limit-e95.service >/dev/null 2>&1 || true
                    info "已开启 e95 开机自动启用 TC 限速。"
                    warn "注意：开机自启只会在 TC_ENABLE=1 且上限有效时生效。"
                fi
                _e95_pause
                ;;
            7)
                systemctl disable xray-tc-limit-e95.service >/dev/null 2>&1 || true
                info "已关闭 e95 开机自动启用 TC 限速；当前 qdisc 不会被此操作立即改变。"
                _e95_pause
                ;;
            8)
                for v in e95 e94 e93; do
                    systemctl disable --now "xray-tc-limit-${v}.service" >/dev/null 2>&1 || true
                    if test -x "/usr/local/bin/xray-tc-limit-${v}.sh"; then
                        "/usr/local/bin/xray-tc-limit-${v}.sh" stop >/dev/null 2>&1 || true
                    fi
                done
                _e95_tc_write_conf "" 0 "auto" "fq" "fq" || true
                info "已恢复默认：e93/e94/e95 TC 均不启用、不开机自启，root qdisc 已尝试恢复 fq。"
                _e95_pause
                ;;
            9)
                _e95_stop_legacy_tc_if_confirmed || true
                _e95_pause
                ;;
            10)
                tail -n 120 "$E95_TC_LOG" 2>/dev/null || warn "暂无日志：$E95_TC_LOG"
                _e95_pause
                ;;
            11)
                systemctl disable --now xray-tc-limit-e95.service >/dev/null 2>&1 || true
                "$E95_TC_SCRIPT" stop >/dev/null 2>&1 || true
                rm -f "$E95_TC_SERVICE" "$E95_TC_SCRIPT" "$E95_TC_CONF" 2>/dev/null || true
                systemctl daemon-reload >/dev/null 2>&1 || true
                info "已删除 e95 TC 组件。"
                _e95_pause
                ;;
            12)
                cat <<'EOF'
TC 带宽控制说明：

1. 本模块用于限制 VPS 出口总带宽，不是提速器。
2. 启用后，默认出口网卡 root qdisc 会由 HTB 接管；请看“实际 root qdisc”，不要只看 sysctl default_qdisc。
3. HTB 负责总上限，叶子队列可选 fq/fq_codel；fq 通常更适合 BBR pacing。
4. 如果你正在使用 CAKE，启用本模块会与 CAKE root qdisc 冲突。
5. 推荐限速到“晚高峰稳定速度”的 85%-95%，避免跑满端口制造排队和丢包。
6. 只写配置不会开启限速，TC_ENABLE=0；必须选 4 或 6 才会改为 TC_ENABLE=1。
7. e95 菜单会显示 e93/e94 旧版 TC 残留状态；恢复默认会禁用旧版自启，统一停用需要 YES 确认。
EOF
                _e95_pause
                ;;
            0) return ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

hot_update_from_legacy() {
    title "V198e95：稳态热更新（e94审计修复 + 统一TC接管 + 速度诊断补强）"
    if declare -F hot_update_from_legacy_e94_base >/dev/null 2>&1; then
        hot_update_from_legacy_e94_base "$@" || true
    fi

    _e95_prepare_dirs
    _e95_install_tc_component || true
    systemctl disable xray-tc-limit-e95.service >/dev/null 2>&1 || true
    sed -i 's/^TC_ENABLE=.*/TC_ENABLE=0/' "$E95_TC_CONF" 2>/dev/null || true

    # 热更新默认不改变当前 qdisc，但禁用旧版 TC 开机自启，避免重启后 e93/e94/e95 混杂。
    _e95_disable_legacy_tc_autostart_only

    if systemctl is-active --quiet xray-tc-limit-e93.service 2>/dev/null || systemctl is-active --quiet xray-tc-limit-e94.service 2>/dev/null; then
        warn "检测到旧 e93/e94 TC 服务当前仍 active；e95 不会在热更新中强行停止。进入 20 → 9 可统一停用。"
    fi

    e92_boot_kernel_safety_audit >/dev/null 2>&1 || true

    echo "198e95" > "$SCRIPT_VERSION_FILE" 2>/dev/null || true
    if test -f "${SCRIPT_PATH:-$0}"; then
        cp -f "${SCRIPT_PATH:-$0}" "$SYMLINK" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e95.sh" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
        chmod +x "$SYMLINK" "$SCRIPT_DIR/ex198e95.sh" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
    fi

    info "V198e95 热更新完成。"
    info "修复：e94 TC 遗留/自启混杂问题；新增 e95 统一接管。"
    info "增强：19 速度诊断会显示 actual root qdisc 与 e93/e94/e95 TC 状态。"
    info "默认策略：不自动启用 TC、不自动限速、不热停旧 active TC。"
}

main_menu() {
    while true; do
        clear
        echo -e "${blue}======================================================================${none}"
        echo -e "  ${magenta}Xray System Advanced Management V198e95 - (统一TC接管 + 速度诊断补强)${none}"
        local svc sys_ver arch_level dns_mode tz_line notsent_now notsent_perm qdisc cc adv app bbr_cfg iface actual_qdisc
        svc=$(systemctl is-active xray 2>/dev/null || echo "inactive")
        if test "$svc" = "active"; then svc="${green}平稳在线 (Running)${none}"; else svc="${red}离线静默 (Stopped)${none}"; fi
        sys_ver=$(uname -r 2>/dev/null || echo "未探测到数据")
        if declare -F detect_x86_64_level >/dev/null 2>&1; then arch_level="$(detect_x86_64_level 2>/dev/null || echo '?')"; else arch_level="?"; fi
        dns_mode=$(cat "${E67_DNS_MODE_FILE:-/usr/local/etc/xray/dns_mode.txt}" 2>/dev/null || echo auto)
        tz_line=$(date '+%Z %z' 2>/dev/null || echo unknown)
        notsent_now=$(_e88_current_notsent_lowat 2>/dev/null || echo '?')
        notsent_perm=$(_e88_persistent_notsent_lowat 2>/dev/null || echo '?')
        qdisc=$(_e88_sysctl_get net.core.default_qdisc 2>/dev/null || echo '?')
        cc=$(_e88_sysctl_get net.ipv4.tcp_congestion_control 2>/dev/null || echo '?')
        adv=$(_e88_sysctl_get net.ipv4.tcp_adv_win_scale 2>/dev/null || echo '?')
        app=$(_e88_sysctl_get net.ipv4.tcp_app_win 2>/dev/null || echo '?')
        bbr_cfg=$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)
        iface="$(_e95_default_iface 2>/dev/null || echo "")"
        actual_qdisc="$(_e95_root_qdisc_line "$iface")"
        echo -e "  引擎态势: $svc | 全局快捷指令: ${cyan}xrv${none} | 外部识别 IP: ${yellow}$(_get_ip 2>/dev/null || echo "探测异常")${none}"
        echo -e "  系统装配内核: ${cyan}${sys_ver}${none} | 微架构侦测: x64-v${yellow}${arch_level}${none} | sysctl qdisc/cc: ${yellow}${qdisc}/${cc}${none} | BBR配置:${yellow}${bbr_cfg}${none}"
        echo -e "  实际root队列: ${cyan}${actual_qdisc:-未读取}${none}"
        echo -e "  DNS模式: ${cyan}${dns_mode}${none} | 时间轴: ${cyan}${tz_line}${none} | notsent: ${yellow}${notsent_now}${none}/${cyan}${notsent_perm}${none} | adv/app: ${yellow}${adv}/${app}${none}"
        echo -e "${blue}======================================================================${none}"
        echo "  1) 创建/重构协议节点：Reality Vision / VLESSENC 自选 / SS2022"
        echo "  2) 用户凭证生命周期与独立参数化管理控制"
