            0) exit 0 ;;
            *) echo -e "${red}错误拦截：代码解析为空值！${none}"; sleep 1 ;;
        esac
    done
}

#==============================================================================
# EOF - Apex Vanguard V198e96 BBR Source Auto-Recover Layer.
#==============================================================================



#==============================================================================
# V198e96 FINAL OVERRIDE LAYER
# 目标：
#   1) 修复 CONFIG_TCP_CONG_BBR=m 模块型 BBR 替换时，因 Debian/Cloud headers 不带 tcp_bbr.c 导致失败的问题。
#   2) 自动查找 / 安装 / 解包 linux-source，补齐 net/ipv4/tcp_bbr.c 后再走 tcp_bbr.ko 同名替换。
#   3) 覆盖空间清理逻辑，保留 /usr/src/linux-source* 与 headers，避免后续 BBR 模块编译再次缺源码。
#   4) 统一菜单版本显示为 V198e96，并保留 e95 的速度诊断与 TC 统一接管。
#==============================================================================

if declare -F hot_update_from_legacy >/dev/null 2>&1; then
    eval "$(declare -f hot_update_from_legacy | sed '1s/hot_update_from_legacy/hot_update_from_legacy_e95_base/')"
fi
if declare -F _e89_bbr_find_source >/dev/null 2>&1 && ! declare -F _e89_bbr_find_source_e95_base >/dev/null 2>&1; then
    eval "$(declare -f _e89_bbr_find_source | sed '1s/_e89_bbr_find_source/_e89_bbr_find_source_e95_base/')"
fi

E96_AUDIT_DIR="$CONFIG_DIR/audit_e96"
E96_BBR_SRC_ROOT="$E89_BBRX_BUILD_ROOT/sources-e96"

_e96_pause() { local _p=""; read -rp "按 Enter 继续..." _p || true; }
_e96_ts() { date +%Y%m%d_%H%M%S; }

_e96_prepare_dirs() {
    mkdir -p "$CONFIG_DIR" "$SCRIPT_DIR" "$BACKUP_DIR" "$LOG_DIR" "$E96_AUDIT_DIR" "$E96_BBR_SRC_ROOT" \
        "$E89_BBRX_ROOT" "$E89_BBRX_CURRENT" "$E89_BBRX_BACKUP_ROOT" "$E89_BBRX_BUILD_ROOT" 2>/dev/null || true
}

# e96 安全清理：保留 linux-source / linux-headers / modules build，避免 BBR 模块热替换缺 tcp_bbr.c。
check_and_clean_space() {
    info "执行安全空间释放协议（V198e96：保留 linux-source / headers / BBR源码缓存）..."
    export DEBIAN_FRONTEND=noninteractive
    apt-get clean >/dev/null 2>&1 || true
    apt-get autoremove -y --purge >/dev/null 2>&1 || true
    journalctl --vacuum-time=3d >/dev/null 2>&1 || true
    rm -rf \
        /tmp/sni_array.json /tmp/vless_inbound.json /tmp/vless_final.json /tmp/ss_inbound.json \
        /tmp/new_client.json /tmp/xray_users*.txt /tmp/install-release.sh /tmp/sni_test.* \
        /tmp/check_x86-64_psabi.sh /tmp/current_cron /tmp/kernel-arch.cfg /tmp/lsmod.now \
        /usr/src/bbr* /usr/src/xanmod* \
        /compile/bbr* /compile/xanmod* /compile/*.tmp \
        /root/bbr*.patch /root/xanmod*.tar* \
        /var/cache/apt/archives/*.deb \
        2>/dev/null || true
    sync
}

_e96_kernel_shortver() {
    uname -r 2>/dev/null | sed -E 's/^([0-9]+\.[0-9]+).*/\1/'
}

_e96_valid_bbr_source() {
    local f="${1:-}"
    test -n "$f" && test -f "$f" || return 1
    grep -q "tcp_congestion_ops" "$f" 2>/dev/null || return 1
    grep -qi "bbr" "$f" 2>/dev/null || return 1
    return 0
}

_e96_find_tcp_bbr_source_now() {
    local f base
    if test -n "${BBR_SOURCE:-}" && _e96_valid_bbr_source "$BBR_SOURCE"; then
        echo "$BBR_SOURCE"
        return 0
    fi
    if declare -F _e89_bbr_find_source_e95_base >/dev/null 2>&1; then
        f="$(_e89_bbr_find_source_e95_base 2>/dev/null || true)"
        if _e96_valid_bbr_source "$f"; then echo "$f"; return 0; fi
    fi
    for base in \
        "/lib/modules/$(uname -r)/build" \
        "/lib/modules/$(uname -r)/source" \
        "$E96_BBR_SRC_ROOT" \
        "$E89_BBRX_BUILD_ROOT" \
        "/usr/src" \
        "/usr/local/src"; do
        test -d "$base" || continue
        f=$(find "$base" -path '*/net/ipv4/tcp_bbr.c' -type f 2>/dev/null | head -n1 || true)
        if _e96_valid_bbr_source "$f"; then echo "$f"; return 0; fi
    done
    return 1
}

_e96_extract_linux_source_tars() {
    local tarball outdir marker base found=0
    mkdir -p "$E96_BBR_SRC_ROOT" 2>/dev/null || true
    for tarball in /usr/src/linux-source*.tar.* /usr/src/linux-*.tar.* /usr/src/linux_*.orig.tar.*; do
        test -f "$tarball" || continue
        if ! tar -tf "$tarball" 2>/dev/null | grep -q 'net/ipv4/tcp_bbr.c'; then
            continue
        fi
        base=$(basename "$tarball" | sed -E 's/\.tar\..*$//; s/\.orig$//')
        outdir="$E96_BBR_SRC_ROOT/$base"
        marker="$outdir/.e96_extracted"
        if test ! -f "$marker"; then
            info "正在解包内核源码包以补齐 tcp_bbr.c：$tarball"
            rm -rf "$outdir" 2>/dev/null || true
            mkdir -p "$outdir" 2>/dev/null || true
            if tar -xf "$tarball" -C "$outdir" --strip-components=1 2>/dev/null; then
                touch "$marker" 2>/dev/null || true
            else
                warn "解包失败：$tarball"
                rm -rf "$outdir" 2>/dev/null || true
                continue
            fi
        fi
        found=1
    done
    test "$found" -eq 1
}

_e96_try_install_linux_source() {
    local kshort pkglog
    kshort="$(_e96_kernel_shortver)"
    pkglog="$E96_AUDIT_DIR/bbr-source-install.$(_e96_ts).log"
    mkdir -p "$E96_AUDIT_DIR" 2>/dev/null || true
    warn "未找到 tcp_bbr.c，尝试安装/补齐当前内核 headers 与 linux-source。日志：$pkglog"
    export DEBIAN_FRONTEND=noninteractive
    {
        echo "[e96] uname=$(uname -r) kshort=$kshort"
        apt-get update -y
        apt-get install -y "linux-headers-$(uname -r)" || true
        apt-get install -y "linux-source-$kshort" || true
        apt-get install -y linux-source || true
        apt-get install -y build-essential bc bison flex libssl-dev libelf-dev dwarves xz-utils zstd kmod || true
    } >>"$pkglog" 2>&1 || true
}

_e96_bbr_find_or_prepare_source() {
    local src=""
    src="$(_e96_find_tcp_bbr_source_now 2>/dev/null || true)"
    if _e96_valid_bbr_source "$src"; then echo "$src"; return 0; fi

    _e96_extract_linux_source_tars >/dev/null 2>&1 || true
    src="$(_e96_find_tcp_bbr_source_now 2>/dev/null || true)"
    if _e96_valid_bbr_source "$src"; then echo "$src"; return 0; fi

    _e96_try_install_linux_source
    _e96_extract_linux_source_tars >/dev/null 2>&1 || true
    src="$(_e96_find_tcp_bbr_source_now 2>/dev/null || true)"
    if _e96_valid_bbr_source "$src"; then echo "$src"; return 0; fi

    return 1
}

# 覆盖 e89 源码发现函数：让所有旧 BBR 构建函数自动受益。
_e89_bbr_find_source() {
    _e96_bbr_find_or_prepare_source
}

_e96_bbr_module_source_report() {
    title "V198e96：BBR 模块源码 / headers 自动检查"
    echo "  当前内核：$(uname -r)"
    echo "  CONFIG_TCP_CONG_BBR：$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)"
    echo "  tcp_bbr 模块路径：$(_e89_bbr_mod_path 2>/dev/null || echo '')"
    echo "  build 链接：/lib/modules/$(uname -r)/build"
    if test -d "/lib/modules/$(uname -r)/build"; then echo "    状态：存在"; else echo "    状态：缺失，需要 linux-headers-$(uname -r)"; fi
    echo ""
    echo "  正在查找/补齐 tcp_bbr.c ..."
    local src
    src="$(_e96_bbr_find_or_prepare_source 2>/dev/null || true)"
    if _e96_valid_bbr_source "$src"; then
        info "已找到可用 tcp_bbr.c：$src"
        grep -n "tcp_congestion_ops\|MODULE_ALIAS_TCP_CONGESTION\|\.name" "$src" 2>/dev/null | head -n 12 | sed 's/^/    /' || true
    else
        error "仍未找到可用 tcp_bbr.c。"
        warn "可手动导出：export BBR_SOURCE=/path/to/net/ipv4/tcp_bbr.c"
        warn "Debian cloud 内核常见原因：headers 只有构建接口，不包含完整 net/ipv4/tcp_bbr.c；需要 linux-source 包。"
    fi
}

_e96_build_replace_bbr_module() {
    local kind="$1" conf="$2" cfgv modp src work newko bdir release_now
    title "V198e96：模块型 BBR 同名热替换（自动补齐 tcp_bbr.c）"
    _e89_bbr_prepare_dirs
    _e96_prepare_dirs

    cfgv="$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)"
    modp="$(_e89_bbr_mod_path 2>/dev/null || true)"

    if test "$cfgv" != "m"; then
        error "当前 CONFIG_TCP_CONG_BBR=$cfgv，不是模块型 m。"
        return 1
    fi
    if test -z "$modp" || test ! -f "$modp"; then
        error "未找到原版 tcp_bbr.ko 路径，拒绝替换。"
        return 1
    fi
    if test ! -d "/lib/modules/$(uname -r)/build"; then
        warn "缺少 /lib/modules/$(uname -r)/build，尝试安装 linux-headers-$(uname -r)。"
        export DEBIAN_FRONTEND=noninteractive
        apt-get update -y >/dev/null 2>&1 || true
        apt-get install -y "linux-headers-$(uname -r)" >/dev/null 2>&1 || true
    fi
    if test ! -d "/lib/modules/$(uname -r)/build"; then
        error "仍缺少 /lib/modules/$(uname -r)/build，无法编译外部模块。"
        warn "这是 headers 缺失，不是 BBR 参数问题。请安装当前内核 headers 或换完整内核编译路线。"
        return 1
    fi

    src="$(_e96_bbr_find_or_prepare_source 2>/dev/null || true)"
    if ! _e96_valid_bbr_source "$src"; then
        error "未找到与当前内核可用的 tcp_bbr.c 源码。"
        warn "e96 已尝试 linux-source 自动补齐，但当前源不可用。"
        warn "可手动执行：export BBR_SOURCE=/path/to/net/ipv4/tcp_bbr.c 后重试。"
        return 1
    fi
    info "使用源码：$src"

    if declare -F _e91_conf_sane >/dev/null 2>&1; then
        _e91_conf_sane "$conf" "$kind" || return 1
    fi

    bdir="$(_e89_bbr_backup_state)" || { error "备份失败，拒绝继续。"; return 1; }
    _e89_bbr_write_original_param_note "$bdir" "$kind"
    cp -af "$conf" "$bdir/generated_new_params.conf" 2>/dev/null || true
    cp -af "$src" "$bdir/tcp_bbr.c.source.used" 2>/dev/null || true
    echo "$src" > "$bdir/source.path.txt" 2>/dev/null || true
    info "已创建替换前完整备份：$bdir"

    work="$E89_BBRX_BUILD_ROOT/build_$(_e96_ts)_$kind"
    mkdir -p "$work" || return 1
    cp -af "$src" "$work/tcp_bbr.c"
    cp -af "$work/tcp_bbr.c" "$bdir/tcp_bbr.c.new.before_patch" 2>/dev/null || true

    _e89_patch_bbr_source_from_conf "$work/tcp_bbr.c" "$conf" "$kind"
    cp -af "$work/tcp_bbr.c" "$bdir/tcp_bbr.c.new" 2>/dev/null || true

    cat > "$work/Makefile" <<'EOF_MAKE_E96'
obj-m += tcp_bbr.o
all:
	$(MAKE) -C /lib/modules/$(shell uname -r)/build M=$(PWD) modules
clean:
	$(MAKE) -C /lib/modules/$(shell uname -r)/build M=$(PWD) clean
EOF_MAKE_E96

    info "开始编译 tcp_bbr.ko：$work"
    if ! make -C "/lib/modules/$(uname -r)/build" M="$work" modules; then
        error "编译失败，原系统未替换。工作目录：$work"
        warn "常见原因：linux-source 与当前 cloud 内核 ABI 差异；这种情况下应走完整内核源码编译路线。"
        return 1
    fi
    newko="$work/tcp_bbr.ko"
    if test ! -f "$newko"; then error "编译后未发现 $newko，拒绝替换。"; return 1; fi

    cp -af "$newko" "$bdir/tcp_bbr.ko.new" 2>/dev/null || true
    sha256sum "$newko" > "$bdir/tcp_bbr.ko.new.sha256" 2>/dev/null || true
    cat > "$bdir/rollback.sh" <<EOF_ROLLBACK_E96
#!/usr/bin/env bash
set -e
ORIG_KO="$modp"
BACKUP_DIR="$bdir"
sysctl -w net.ipv4.tcp_congestion_control=cubic >/dev/null 2>&1 || true
modprobe -r tcp_bbr 2>/dev/null || rmmod tcp_bbr 2>/dev/null || true
if test -f "\$BACKUP_DIR/tcp_bbr.ko.orig"; then cp -af "\$BACKUP_DIR/tcp_bbr.ko.orig" "\$ORIG_KO"; fi
depmod -a
modprobe tcp_bbr || true
sysctl -w net.ipv4.tcp_congestion_control=bbr >/dev/null 2>&1 || true
sysctl --system >/dev/null 2>&1 || true
echo "已回滚到备份：\$BACKUP_DIR"
EOF_ROLLBACK_E96
    chmod +x "$bdir/rollback.sh" 2>/dev/null || true

    echo ""
    read -rp "是否临时切到 cubic 并尝试卸载旧 tcp_bbr 后立即热替换？[Y/n]: " release_now || true
    if ! [[ "$release_now" =~ ^[nN]$ ]]; then
        sysctl -w net.ipv4.tcp_congestion_control=cubic >/dev/null 2>&1 || true
        modprobe -r tcp_bbr 2>/dev/null || rmmod tcp_bbr 2>/dev/null || warn "旧 tcp_bbr 当前仍被引用，磁盘替换仍会执行；可能需重启后才完全生效。"
    fi
    if ! _e89_install_new_ko_to_original_path "$newko" "$modp"; then
        error "写入新模块失败，尝试保持原状态。"
        return 1
    fi
    depmod -a >/dev/null 2>&1 || true
    modprobe tcp_bbr 2>/dev/null || warn "modprobe tcp_bbr 未立即成功；如果旧模块仍在内存中，请重启后验证。"
    cat > "$E89_BBRX_SYSCTL" <<'EOF_SYSCTL_E96'
net.core.default_qdisc = fq
net.ipv4.tcp_congestion_control = bbr
EOF_SYSCTL_E96
    echo "tcp_bbr" > "$E89_BBRX_MODULES_LOAD"
    sysctl -p "$E89_BBRX_SYSCTL" >/dev/null 2>&1 || true
    info "替换完成。永久配置：$E89_BBRX_SYSCTL / $E89_BBRX_MODULES_LOAD"
    info "回滚脚本：$bdir/rollback.sh"
    sysctl net.ipv4.tcp_congestion_control 2>/dev/null || true
    sysctl net.ipv4.tcp_available_congestion_control 2>/dev/null || true
    modinfo tcp_bbr 2>/dev/null | sed -n '1,10p' || true
}

# 覆盖统一 BBR 替换入口：m 走 e96 模块热替换，y 仍走 e91/e90 完整内核路线。
_e89_build_replace_bbr() {
    local kind="$1" conf="$2" cfgv
    cfgv="$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)"
    case "$cfgv" in
        m)
            _e96_build_replace_bbr_module "$kind" "$conf"
            ;;
        y)
            if declare -F _e91_build_builtin_bbr_kernel_strict >/dev/null 2>&1; then
                _e91_build_builtin_bbr_kernel_strict "$kind" "$conf"
            elif declare -F _e90_build_builtin_bbr_kernel >/dev/null 2>&1; then
                _e90_build_builtin_bbr_kernel "$kind" "$conf"
            else
                error "当前 BBR 是内置型 y，但未找到完整内核编译函数。"
                return 1
            fi
            ;;
        *)
            error "无法确认 CONFIG_TCP_CONG_BBR=$cfgv。请先执行自动检测。"
            return 1
            ;;
    esac
}

_e96_bbr_compile_mode_text() {
    local cfgv
    cfgv="$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)"
    case "$cfgv" in
        m) echo "模块型 m：e96 自动补齐 tcp_bbr.c 后热替换 tcp_bbr.ko" ;;
        y) echo "内置型 y：需补丁源码并完整编译内核，重启后生效" ;;
        *) echo "未知：请先自动检测" ;;
    esac
}

_e96_bbrv1_flow() {
    local m conf go
    while true; do
        title "V198e96：普通 Linux 主线 BBR v1 → bbrx_v1 参数中心"
        echo "  当前替换路线：$(_e96_bbr_compile_mode_text)"
        echo ""
        echo "  1) 查看参数表：参数 / 原版 BBR / bbrx_v1 建议 / 说明"
        echo "  2) 使用 bbrx_v1 推荐参数生成配置"
        echo "  3) 自定义全部参数并生成配置（输入时同步显示参数表字段，?=完整表）"
        echo "  4) 使用当前配置替换 bbr"
        echo "  7) 检查/自动补齐 tcp_bbr.c 源码与 headers"
        echo "  0) 返回"
        read -rp "请选择: " m || true
        case "${m:-}" in
            1) _e89_show_bbrv1_table; _e96_pause ;;
            2) _e89_collect_bbrv1_params recommended || return; conf="$(_e89_write_bbrv1_conf)"; info "已写入：$conf"; read -rp "是否立即替换 bbr？[y/N]: " go || true; [[ "$go" =~ ^[yY]$ ]] && _e89_build_replace_bbr bbrv1 "$conf"; _e96_pause ;;
            3) _e89_collect_bbrv1_params custom || return; conf="$(_e89_write_bbrv1_conf)"; info "已写入：$conf"; read -rp "是否立即替换 bbr？[y/N]: " go || true; [[ "$go" =~ ^[yY]$ ]] && _e89_build_replace_bbr bbrv1 "$conf"; _e96_pause ;;
            4) conf="$E89_BBRX_CURRENT/bbrv1_replace.conf"; if test -f "$conf"; then _e89_build_replace_bbr bbrv1 "$conf"; else warn "配置不存在，请先执行 2 或 3。"; fi; _e96_pause ;;
            7) _e96_bbr_module_source_report; _e96_pause ;;
            0) return ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

_e96_bbr3_flow() {
    local m conf go
    while true; do
        title "V198e96：BBR3 / XanMod → bbrx3_v1 参数中心"
        echo "  当前替换路线：$(_e96_bbr_compile_mode_text)"
        echo ""
        echo "  1) 查看参数表：参数 / 原版 BBR3 / bbrx3_v1 建议 / 说明"
        echo "  2) 使用 bbrx3_v1 推荐参数生成配置"
        echo "  3) 自定义全部参数并生成配置（输入时同步显示参数表字段，?=完整表）"
        echo "  4) 使用当前配置替换 bbr"
        echo "  7) 检查/自动补齐 tcp_bbr.c 源码与 headers"
        echo "  0) 返回"
        read -rp "请选择: " m || true
        case "${m:-}" in
            1) _e89_show_bbr3_table; _e96_pause ;;
            2) _e89_collect_bbr3_params recommended || return; conf="$(_e89_write_bbr3_conf)"; info "已写入：$conf"; read -rp "是否立即替换 bbr？[y/N]: " go || true; [[ "$go" =~ ^[yY]$ ]] && _e89_build_replace_bbr bbr3 "$conf"; _e96_pause ;;
            3) _e89_collect_bbr3_params custom || return; conf="$(_e89_write_bbr3_conf)"; info "已写入：$conf"; read -rp "是否立即替换 bbr？[y/N]: " go || true; [[ "$go" =~ ^[yY]$ ]] && _e89_build_replace_bbr bbr3 "$conf"; _e96_pause ;;
            4) conf="$E89_BBRX_CURRENT/bbr3_replace.conf"; if test -f "$conf"; then _e89_build_replace_bbr bbr3 "$conf"; else warn "配置不存在，请先执行 2 或 3。"; fi; _e96_pause ;;
            7) _e96_bbr_module_source_report; _e96_pause ;;
            0) return ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

do_bbr_body_replace_menu_e89() {
    _e89_bbr_prepare_dirs
    local opt rec
    while true; do
        rec="$(_e89_bbr_recommend_kind)"
        title "V198e96：BBR 本体替换 / 自定义编译中心"
        echo "  自动建议：$(test "$rec" = "bbr3" && echo "BBR3 / XanMod → bbrx3_v1" || echo "普通 Linux 主线 BBR v1 → bbrx_v1")"
        echo "  当前替换路线：$(_e96_bbr_compile_mode_text)"
        echo ""
        echo "  1) 自动检测当前 BBR 类型，并推荐编译方案"
        echo "  2) 普通 Linux 主线 BBR v1 → 自定义全部参数 → 替换 bbr"
        echo "  3) BBR3 / XanMod → 自定义全部参数 → 替换 bbr"
        echo "  4) 查看已备份的原版 BBR / 系统 TCP 设置"
        echo "  5) 无损切换回最近一次编译前 BBR / 或旧内核 GRUB 回滚提示"
        echo "  6) 查看当前拥塞控制 / qdisc / BBR 状态"
        echo "  7) 检查/自动补齐 tcp_bbr.c 源码与 headers（模块型 m 专用）"
        echo "  0) 返回主菜单"
        read -rp "请选择: " opt || true
        case "${opt:-}" in
            1) _e89_bbr_detect; _e96_pause ;;
            2) _e96_bbrv1_flow ;;
            3) _e96_bbr3_flow ;;
            4) _e89_bbr_show_backups; _e96_pause ;;
            5) _e89_bbr_rollback_latest || warn "如果本次是内置型整内核编译，请通过云厂商 VNC/GRUB 选择旧内核回滚。"; _e96_pause ;;
            6) _e89_bbr_status; _e96_pause ;;
            7) _e96_bbr_module_source_report; _e96_pause ;;
            0) return ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

hot_update_from_legacy() {
    title "V198e96：稳态热更新（BBR模块源码自动补齐 + e95诊断/TC保留）"
    if declare -F hot_update_from_legacy_e95_base >/dev/null 2>&1; then
        hot_update_from_legacy_e95_base "$@" || true
    fi
    _e96_prepare_dirs
    # 避免后续热更新/清理再次误删 BBR 模块编译所需源码缓存。
    check_and_clean_space >/dev/null 2>&1 || true
    echo "198e96" > "$SCRIPT_VERSION_FILE" 2>/dev/null || true
    if test -f "${SCRIPT_PATH:-$0}"; then
        cp -f "${SCRIPT_PATH:-$0}" "$SYMLINK" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e96.sh" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
        chmod +x "$SYMLINK" "$SCRIPT_DIR/ex198e96.sh" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
    fi
    hash -r 2>/dev/null || true
    info "V198e96 热更新完成。"
    info "17) BBR 模块型 m 现在会自动查找/安装/解包 linux-source 以补齐 tcp_bbr.c。"
    info "说明：完整内核编译与模块热替换不是同一条路线；模块热替换必须有可编译的 tcp_bbr.c + 当前 headers。"
}

