#==============================================================================
# EOF - Apex Vanguard V198e96 BBR Source Auto-Recover Layer.
#==============================================================================


#==============================================================================
# V198e97 FINAL OVERRIDE LAYER
# 目标：
#   1) 明确区分 tcp_bbr.ko 模块快编 与 整棵内核编译。
#   2) 防止低配 VPS 误入完整内核编译后卡在 Intel i40e/iavf/ice 等海量驱动。
#   3) 模块型 m 替换强制使用外部模块快编、单线程、限时；不允许悄悄编完整内核。
#   4) 完整内核编译增加内存/磁盘/boot 熔断与可选瘦身配置。
#==============================================================================

if declare -F _execute_compilation >/dev/null 2>&1; then
    eval "$(declare -f _execute_compilation | sed '1s/_execute_compilation/_execute_compilation_e96_base/')"
fi
if declare -F hot_update_from_legacy >/dev/null 2>&1; then
    eval "$(declare -f hot_update_from_legacy | sed '1s/hot_update_from_legacy/hot_update_from_legacy_e96_base/')"
fi

readonly E97_AUDIT_DIR="$CONFIG_DIR/audit_e97" 2>/dev/null || E97_AUDIT_DIR="$CONFIG_DIR/audit_e97"
readonly E97_BBR_SRC_ROOT="$E89_BBRX_BUILD_ROOT/sources-e97" 2>/dev/null || E97_BBR_SRC_ROOT="$E89_BBRX_BUILD_ROOT/sources-e97"

_e97_pause() { local _p=""; read -rp "按 Enter 继续..." _p || true; }
_e97_ts() { date +%Y%m%d_%H%M%S; }

_e97_prepare_dirs() {
    mkdir -p "$E97_AUDIT_DIR" "$E97_BBR_SRC_ROOT" "$E89_BBRX_BUILD_ROOT" "$E89_BBRX_BACKUP_ROOT" "$E89_BBRX_CURRENT" 2>/dev/null || true
}

_e97_default_iface() {
    ip route get 1.1.1.1 2>/dev/null | awk '{for(i=1;i<=NF;i++) if($i=="dev"){print $(i+1); exit}}'
}

_e97_boot_free_mb() {
    if findmnt -rn /boot >/dev/null 2>&1; then df -Pm /boot 2>/dev/null | awk 'NR==2{print int($4)}'; else df -Pm / 2>/dev/null | awk 'NR==2{print int($4)}'; fi
}
_e97_root_free_mb() { df -Pm / 2>/dev/null | awk 'NR==2{print int($4)}'; }
_e97_total_mem_swap_mb() { free -m 2>/dev/null | awk '/^Mem:/{m=$2}/^Swap:/{s=$2} END{print int(m+s)}'; }

_e97_full_kernel_compile_guard() {
    local total root_free boot_free cpu ok=1
    total="$(_e97_total_mem_swap_mb 2>/dev/null || echo 0)"
    root_free="$(_e97_root_free_mb 2>/dev/null || echo 0)"
    boot_free="$(_e97_boot_free_mb 2>/dev/null || echo 0)"
    cpu="$(nproc 2>/dev/null || echo 1)"

    title "V198e97：完整内核编译资源熔断检查"
    echo "  CPU核心: ${cpu}"
    echo "  Mem+Swap: ${total} MB"
    echo "  / 可用空间: ${root_free} MB"
    echo "  /boot 可用空间: ${boot_free} MB"
    hr

    if test "${total:-0}" -lt 1000 2>/dev/null; then
        error "Mem+Swap < 1000MB，完整内核编译很容易 OOM/Swap 抖死，拒绝继续。"
        ok=0
    fi
    if test "${root_free:-0}" -lt 12000 2>/dev/null; then
        error "/ 可用空间 < 12GB，完整内核编译容易中途爆盘，拒绝继续。"
        ok=0
    fi
    if test "${boot_free:-0}" -lt 350 2>/dev/null; then
        error "/boot 可用空间 < 350MB，make install/initramfs 可能残缺，拒绝继续。"
        ok=0
    fi

    if test "$ok" -ne 1; then
        warn "你刚才卡在 i40e/iavf/ice，正是完整内核编译在编译大量无关网卡驱动。"
        warn "低配 VPS 不建议完整内核编译；模块型 BBR 请走 17 → 2/3 的 tcp_bbr.ko 模块快编。"
        warn "如你已做快照且坚持完整内核编译，可临时设置 XRAY_E97_ALLOW_FULL_KERNEL_COMPILE_LOW_RESOURCE=1。"
        test "${XRAY_E97_ALLOW_FULL_KERNEL_COMPILE_LOW_RESOURCE:-0}" = "1" || return 1
    fi
    return 0
}

_e97_kernel_driver_slim_before_compile() {
    # 仅在完整内核源码树中执行。保留当前默认网卡驱动与虚拟化/磁盘驱动，尽量禁用无关实体网卡大族。
    test -f .config || return 0
    test -x ./scripts/config || return 0
    local iface drv log
    iface="$(_e97_default_iface 2>/dev/null || true)"
    drv="$(ethtool -i "$iface" 2>/dev/null | awk -F': ' '/^driver:/{print $2; exit}' || true)"
    log="$E97_AUDIT_DIR/kernel-slim.$(_e97_ts).log"
    mkdir -p "$E97_AUDIT_DIR" 2>/dev/null || true
    {
        echo "[e97] iface=$iface driver=$drv kernel=$(uname -r) pwd=$PWD"
        echo "[e97] disable unused physical NIC families to avoid low-end VPS compiling i40e/iavf/ice/fm10k/bnxt/mlx5 unless active driver needs them."
    } > "$log" 2>/dev/null || true

    # 保命项：VPS 常见启动/磁盘/网卡驱动必须保留。
    ./scripts/config --enable CONFIG_VIRTIO 2>/dev/null || true
    ./scripts/config --enable CONFIG_VIRTIO_PCI 2>/dev/null || true
    ./scripts/config --enable CONFIG_VIRTIO_BLK 2>/dev/null || true
    ./scripts/config --enable CONFIG_VIRTIO_NET 2>/dev/null || true
    ./scripts/config --enable CONFIG_SCSI_VIRTIO 2>/dev/null || true
    ./scripts/config --enable CONFIG_BLK_DEV_NVME 2>/dev/null || true
    ./scripts/config --enable CONFIG_NVME_CORE 2>/dev/null || true
    ./scripts/config --enable CONFIG_XEN_BLKDEV_FRONTEND 2>/dev/null || true
    ./scripts/config --enable CONFIG_XEN_NETDEV_FRONTEND 2>/dev/null || true
    ./scripts/config --enable CONFIG_HYPERV_STORAGE 2>/dev/null || true
    ./scripts/config --enable CONFIG_HYPERV_NET 2>/dev/null || true
    ./scripts/config --enable CONFIG_DEVTMPFS 2>/dev/null || true
    ./scripts/config --enable CONFIG_DEVTMPFS_MOUNT 2>/dev/null || true

    if test "${XRAY_E97_NO_KERNEL_SLIM:-0}" = "1"; then
        warn "已设置 XRAY_E97_NO_KERNEL_SLIM=1，跳过驱动瘦身。"
        return 0
    fi

    case "$drv" in
        i40e|iavf|ice|fm10k|ixgbe|igb|e1000|e1000e)
            warn "当前默认网卡驱动是 Intel 系列：$drv，保守起见不禁用 Intel 网卡家族。"
            ;;
        *)
            ./scripts/config --disable CONFIG_I40E 2>/dev/null || true
            ./scripts/config --disable CONFIG_IAVF 2>/dev/null || true
            ./scripts/config --disable CONFIG_ICE 2>/dev/null || true
            ./scripts/config --disable CONFIG_FM10K 2>/dev/null || true
            ./scripts/config --disable CONFIG_IXGBE 2>/dev/null || true
            ./scripts/config --disable CONFIG_IGB 2>/dev/null || true
            ./scripts/config --disable CONFIG_E1000 2>/dev/null || true
            ./scripts/config --disable CONFIG_E1000E 2>/dev/null || true
            ;;
    esac
    case "$drv" in
        mlx4_core|mlx5_core|mlx5e)
            warn "当前默认网卡驱动是 Mellanox：$drv，保守起见不禁用 Mellanox。"
            ;;
        *)
            ./scripts/config --disable CONFIG_MLX4_EN 2>/dev/null || true
            ./scripts/config --disable CONFIG_MLX5_CORE 2>/dev/null || true
            ;;
    esac
    case "$drv" in
        bnxt_en) warn "当前默认网卡驱动是 Broadcom bnxt_en，保守起见不禁用 Broadcom。" ;;
        *) ./scripts/config --disable CONFIG_BNXT 2>/dev/null || true ;;
    esac

    ./scripts/config --disable CONFIG_DEBUG_INFO 2>/dev/null || true
    ./scripts/config --disable CONFIG_DEBUG_INFO_BTF 2>/dev/null || true
    ./scripts/config --disable SYSTEM_TRUSTED_KEYS 2>/dev/null || true
    ./scripts/config --disable SYSTEM_REVOCATION_KEYS 2>/dev/null || true
    make olddefconfig >/dev/null 2>&1 || true
    info "V198e97：完整内核编译前已做低配 VPS 驱动瘦身与保命驱动固化。日志：$log"
}

_execute_compilation() {
    _e97_full_kernel_compile_guard || return 1
    _e97_kernel_driver_slim_before_compile || true
    if declare -F _execute_compilation_e96_base >/dev/null 2>&1; then
        _execute_compilation_e96_base "$@"
    else
        error "未找到完整内核编译基线函数。"
        return 1
    fi
}

# e97 安全清理：再次覆盖，避免误删 linux-source / headers / bbr 源码缓存。
check_and_clean_space() {
    info "执行安全空间释放协议（V198e97：保留 linux-source / headers / BBR源码缓存）..."
    export DEBIAN_FRONTEND=noninteractive
    apt-get clean >/dev/null 2>&1 || true
    journalctl --vacuum-time=3d >/dev/null 2>&1 || true
    rm -f /tmp/sni_array.json /tmp/vless_inbound.json /tmp/vless_final.json /tmp/ss_inbound.json \
          /tmp/new_client.json /tmp/xray_users*.txt /tmp/install-release.sh /tmp/sni_test.* \
          /tmp/check_x86-64_psabi.sh /tmp/current_cron /tmp/kernel-arch.cfg /tmp/lsmod.now 2>/dev/null || true
    find /compile -mindepth 1 -maxdepth 1 -type d \( -name 'linux-*' -o -name 'xanmod*' -o -name 'bbr*' \) -mtime +1 -exec rm -rf {} + 2>/dev/null || true
    rm -rf /usr/src/bbr* /usr/src/xanmod* 2>/dev/null || true
    sync
}

_e97_module_make_timeout() { echo "${XRAY_E97_MODULE_MAKE_TIMEOUT:-900}"; }

_e97_build_replace_bbr_module() {
    local kind="$1" conf="$2" cfgv modp src work newko bdir release_now timeout_s kbuild
    title "V198e97：模块型 BBR 快编热替换（只编 tcp_bbr.ko，不编完整内核）"
    _e89_bbr_prepare_dirs
    _e97_prepare_dirs

    cfgv="$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)"
    modp="$(_e89_bbr_mod_path 2>/dev/null || true)"
    kbuild="/lib/modules/$(uname -r)/build"

    if test "$cfgv" != "m"; then error "当前 CONFIG_TCP_CONG_BBR=$cfgv，不是模块型 m。"; return 1; fi
    if test -z "$modp" || test ! -f "$modp"; then error "未找到原版 tcp_bbr.ko 路径，拒绝替换。"; return 1; fi

    if test ! -d "$kbuild"; then
        warn "缺少 $kbuild，尝试安装当前内核 headers。"
        export DEBIAN_FRONTEND=noninteractive
        apt-get update -y >/dev/null 2>&1 || true
        apt-get install -y "linux-headers-$(uname -r)" >/dev/null 2>&1 || true
    fi
    if test ! -d "$kbuild"; then
        error "仍缺少 $kbuild，无法外部模块快编。"
        return 1
    fi

    src="$(_e96_bbr_find_or_prepare_source 2>/dev/null || true)"
    if ! _e96_valid_bbr_source "$src"; then
        error "未找到可用 tcp_bbr.c。"
        warn "请先用 17 → 7 自动补齐，或手动 export BBR_SOURCE=/path/to/net/ipv4/tcp_bbr.c。"
        return 1
    fi
    info "使用源码：$src"

    if declare -F _e91_conf_sane >/dev/null 2>&1; then _e91_conf_sane "$conf" "$kind" || return 1; fi

    bdir="$(_e89_bbr_backup_state)" || { error "备份失败，拒绝继续。"; return 1; }
    _e89_bbr_write_original_param_note "$bdir" "$kind"
    cp -af "$conf" "$bdir/generated_new_params.conf" 2>/dev/null || true
    cp -af "$src" "$bdir/tcp_bbr.c.source.used" 2>/dev/null || true
    echo "$src" > "$bdir/source.path.txt" 2>/dev/null || true
    info "已创建替换前完整备份：$bdir"

    work="$E89_BBRX_BUILD_ROOT/build_$(_e97_ts)_$kind"
    mkdir -p "$work" || return 1
    cp -af "$src" "$work/tcp_bbr.c"
    cp -af "$work/tcp_bbr.c" "$bdir/tcp_bbr.c.new.before_patch" 2>/dev/null || true
    _e89_patch_bbr_source_from_conf "$work/tcp_bbr.c" "$conf" "$kind"
    cp -af "$work/tcp_bbr.c" "$bdir/tcp_bbr.c.new" 2>/dev/null || true

    cat > "$work/Makefile" <<'EOF_MAKE_E97'
obj-m := tcp_bbr.o
EOF_MAKE_E97

    timeout_s="$(_e97_module_make_timeout)"
    info "开始外部模块快编 tcp_bbr.ko：$work"
    info "命令：timeout ${timeout_s}s make -j1 -C $kbuild M=$work modules"
    if ! timeout "${timeout_s}s" make -j1 -C "$kbuild" M="$work" modules; then
        error "外部模块快编失败或超时，原系统未替换。工作目录：$work"
        warn "如果屏幕开始编 drivers/net/ethernet/intel/i40e/iavf/ice，说明你走错了完整内核编译路线，不是模块快编。"
        return 1
    fi
    newko="$work/tcp_bbr.ko"
    if test ! -f "$newko"; then error "编译后未发现 $newko，拒绝替换。"; return 1; fi

    cp -af "$newko" "$bdir/tcp_bbr.ko.new" 2>/dev/null || true
    sha256sum "$newko" > "$bdir/tcp_bbr.ko.new.sha256" 2>/dev/null || true
    cat > "$bdir/rollback.sh" <<EOF_ROLLBACK_E97
#!/usr/bin/env bash
set -e
ORIG_KO="$modp"
BACKUP_DIR="$bdir"
sysctl -w net.ipv4.tcp_congestion_control=cubic >/dev/null 2>&1 || true
modprobe -r tcp_bbr 2>/dev/null || rmmod tcp_bbr 2>/dev/null || true
if test -f "\$BACKUP_DIR/tcp_bbr.ko.orig"; then cp -af "\$BACKUP_DIR/tcp_bbr.ko.orig" "\$ORIG_KO"; fi
depmod -a
modprobe tcp_bbr || true
sysctl -w net.ipv4.tcp_congestion_control=bbr >/dev/null 2>&1 || true
echo "rollback done"
EOF_ROLLBACK_E97
    chmod +x "$bdir/rollback.sh" 2>/dev/null || true

    warn "准备替换原模块：$modp"
    read -rp "是否临时切到 cubic 并尝试卸载旧 tcp_bbr 后立即热替换？[Y/n]: " release_now || true
    release_now="${release_now:-Y}"
    if [[ "$release_now" =~ ^[yY]$ ]]; then
        sysctl -w net.ipv4.tcp_congestion_control=cubic >/dev/null 2>&1 || true
        modprobe -r tcp_bbr 2>/dev/null || rmmod tcp_bbr 2>/dev/null || warn "旧 tcp_bbr 当前仍被引用，磁盘替换仍会执行；可能需重启后完全生效。"
    fi
    cp -af "$newko" "$modp" || { error "写入 $modp 失败，已保留备份：$bdir"; return 1; }
    depmod -a >/dev/null 2>&1 || true
    modprobe tcp_bbr 2>/dev/null || warn "modprobe tcp_bbr 未立即成功；如果旧模块仍在内存中，请重启后验证。"
    sysctl -w net.ipv4.tcp_congestion_control=bbr >/dev/null 2>&1 || true
    echo "tcp_bbr" > "$E89_BBRX_MODULES_LOAD" 2>/dev/null || true

    info "V198e97 模块型 BBR 快编替换完成。备份目录：$bdir"
    warn "请验证：sysctl net.ipv4.tcp_congestion_control && modinfo tcp_bbr | head && ss -tin"
    return 0
}

_e89_build_replace_bbr() {
    local kind="$1" conf="$2" cfgv
    cfgv="$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)"
    case "$cfgv" in
        m) _e97_build_replace_bbr_module "$kind" "$conf" ;;
        y)
            if declare -F _e90_build_builtin_bbr_kernel >/dev/null 2>&1; then _e90_build_builtin_bbr_kernel "$kind" "$conf"; else error "未找到内置型 BBR 完整内核编译函数。"; return 1; fi
            ;;
        *) error "当前 CONFIG_TCP_CONG_BBR=$cfgv，无法判断替换路线。"; return 1 ;;
    esac
}

_e97_why_intel_compile_stuck() {
    title "V198e97：为什么会卡在 i40e/iavf/ice？"
    cat <<'EOF_E97_STUCK'
你看到：
  CC [M] drivers/net/ethernet/intel/i40e/...
  CC [M] drivers/net/ethernet/intel/iavf/...
  CC [M] drivers/net/ethernet/intel/ice/...

这说明正在编译“完整内核源码树”的大量网卡驱动，不是只编 tcp_bbr.ko。

模块型 BBR 快编应该只出现类似：
  make -C /lib/modules/$(uname -r)/build M=/etc/bbrx/build/build_xxx modules
  CC [M] /etc/bbrx/build/build_xxx/tcp_bbr.o
  LD [M] /etc/bbrx/build/build_xxx/tcp_bbr.ko

如果 VPS 卡住，优先在另一个 SSH/VNC 执行：
  pkill -f "make -j" || true
  pkill -f "drivers/net/ethernet/intel" || true
  dmesg -T | egrep -i 'killed process|out of memory|oom|blocked for more than' | tail -n 50
  free -h; df -h / /boot; ps -eo pid,ppid,stat,pcpu,pmem,comm,args | grep -E 'make|cc1|gcc|ld|objtool' | grep -v grep

后续建议：
  - 当前 CONFIG_TCP_CONG_BBR=m：优先走模块快编，不要完整内核编译。
  - 完整内核编译只适合内存/磁盘足够并且已经做 VPS 快照的机器。
EOF_E97_STUCK
}

do_bbr_body_replace_menu_e89() {
    while true; do
        clear
        title "V198e97：BBR 本体替换 / 自定义编译中心"
        echo "  自动建议：$(_e89_bbr_detect 2>/dev/null || true)"
        echo "  当前替换路线：$(_e96_bbr_compile_mode_text 2>/dev/null || echo unknown)"
        echo
        echo "  1) 自动检测当前 BBR 类型，并推荐编译方案"
        echo "  2) 普通 Linux 主线 BBR v1 → 自定义全部参数 → 替换 bbr"
        echo "  3) BBR3 / XanMod → 自定义全部参数 → 替换 bbr"
        echo "  4) 查看已备份的原版 BBR / 系统 TCP 设置"
        echo "  5) 无损切换回最近一次编译前 BBR / 或旧内核 GRUB 回滚提示"
        echo "  6) 查看当前拥塞控制 / qdisc / BBR 状态"
        echo "  7) 检查/自动补齐 tcp_bbr.c 源码与 headers（模块型 m 专用）"
        echo "  8) 解释：为什么完整编译会卡在 i40e/iavf/ice"
        echo "  0) 返回主菜单"
        read -rp "请选择: " opt || true
        case "${opt:-}" in
            1) _e89_bbr_detect; _e97_pause ;;
            2) _e96_bbrv1_flow ;;
            3) _e96_bbr3_flow ;;
            4) _e89_bbr_show_backups; _e97_pause ;;
            5) _e89_bbr_rollback_latest || warn "如果本次是内置型整内核编译，请通过云厂商 VNC/GRUB 选择旧内核回滚。"; _e97_pause ;;
            6) _e89_bbr_status; _e97_pause ;;
            7) _e96_bbr_module_source_report; _e97_pause ;;
            8) _e97_why_intel_compile_stuck; _e97_pause ;;
            0) return ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

hot_update_from_legacy() {
    title "V198e97：稳态热更新（防整核误编译 + BBR模块快编保护）"
    if declare -F hot_update_from_legacy_e96_base >/dev/null 2>&1; then
        hot_update_from_legacy_e96_base "$@" || true
    fi
    _e97_prepare_dirs
    check_and_clean_space >/dev/null 2>&1 || true
    echo "198e97" > "$SCRIPT_VERSION_FILE" 2>/dev/null || true
    if test -f "${SCRIPT_PATH:-$0}"; then
        cp -f "${SCRIPT_PATH:-$0}" "$SYMLINK" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e97.sh" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
        chmod +x "$SYMLINK" "$SCRIPT_DIR/ex198e97.sh" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
    fi
    hash -r 2>/dev/null || true
    info "V198e97 热更新完成。"
