#==============================================================================

#==============================================================================
# V198e105 FINAL OVERRIDE LAYER
# 目标：
#   1) 保留 ex198e105 完整主菜单 1-20/88，不裁剪任何目录入口。
#   2) 修复菜单显示中的 "8)" 在部分前端/复制环境被表情化的问题：显示为 "8 )"，输入仍为 8。
#   3) BBR 中心显式新增“内置型 y：完整内核源码补丁编译新内核”目录入口。
#   4) 内置型 BBR 完整源码编译仍为 1000MB Mem+Swap 门槛，并保留手动授权防误编译。
#==============================================================================

if declare -F _e90_build_builtin_bbr_kernel >/dev/null 2>&1; then
    eval "$(declare -f _e90_build_builtin_bbr_kernel | sed '1s/_e90_build_builtin_bbr_kernel/_e90_build_builtin_bbr_kernel_e102_base/')"
fi
if declare -F hot_update_from_legacy >/dev/null 2>&1; then
    eval "$(declare -f hot_update_from_legacy | sed '1s/hot_update_from_legacy/hot_update_from_legacy_e102_base/')"
fi
if declare -F _e96_bbr_module_source_report >/dev/null 2>&1; then
    eval "$(declare -f _e96_bbr_module_source_report | sed '1s/_e96_bbr_module_source_report/_e96_bbr_module_source_report_e102_base/')" 2>/dev/null || true
fi

readonly E102_AUDIT_DIR="$CONFIG_DIR/audit_e102" 2>/dev/null || E102_AUDIT_DIR="$CONFIG_DIR/audit_e102"

_e102_pause() { local _p=""; read -rp "按 Enter 继续..." _p || true; }
_e102_ts() { date +%Y%m%d_%H%M%S; }
_e102_total_mem_swap_mb() { free -m 2>/dev/null | awk '/^Mem:/{m=$2}/^Swap:/{s=$2} END{print int(m+s)}'; }
_e102_root_free_mb() { df -Pm / 2>/dev/null | awk 'NR==2{print int($4)}'; }
_e102_boot_free_mb() { if findmnt -rn /boot >/dev/null 2>&1; then df -Pm /boot 2>/dev/null | awk 'NR==2{print int($4)}'; else df -Pm / 2>/dev/null | awk 'NR==2{print int($4)}'; fi; }

_e102_prepare_dirs() {
    mkdir -p "$E102_AUDIT_DIR" "$E89_BBRX_BUILD_ROOT" "$E89_BBRX_BACKUP_ROOT" "$E89_BBRX_CURRENT" 2>/dev/null || true
}

_e102_bbr_mode_text() {
    local cfgv
    cfgv="$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)"
    case "$cfgv" in
        m) echo "模块型 m：可走 tcp_bbr.ko 外部模块快编，通常无需重启" ;;
        y) echo "内置型 y：不能热替换 .ko；请走 9) 完整内核源码补丁编译新内核" ;;
        *) echo "未知：请先执行自动检测，禁止盲改" ;;
    esac
}

_e102_xanmod_hint() {
    local kr
    kr="$(uname -r 2>/dev/null || echo unknown)"
    if echo "$kr" | grep -qi xanmod; then
        echo "当前是 XanMod 预编译/自编译内核：$kr"
        echo "XanMod 常见为 CONFIG_TCP_CONG_BBR=y：BBR/BBR3 编进 vmlinuz，不能像模块 m 那样替换 tcp_bbr.ko。"
        echo "如果要改 BBR3 源码参数，必须使用匹配或可兼容的完整源码树，打补丁/替换 net/ipv4/tcp_bbr.c 后完整编译新内核。"
    fi
}

_e102_builtin_full_compile_precheck() {
    local kind="${1:-}" conf="${2:-}" total root_free boot_free cfgv ok=1 log
    cfgv="$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)"
    total="$(_e102_total_mem_swap_mb 2>/dev/null || echo 0)"
    root_free="$(_e102_root_free_mb 2>/dev/null || echo 0)"
    boot_free="$(_e102_boot_free_mb 2>/dev/null || echo 0)"
    log="$E102_AUDIT_DIR/builtin-compile-precheck.$(_e102_ts).log"
    mkdir -p "$E102_AUDIT_DIR" 2>/dev/null || true

    title "V198e105：内置型 BBR 完整内核编译硬门禁"
    echo "  当前内核: $(uname -r 2>/dev/null || echo unknown)"
    echo "  CONFIG_TCP_CONG_BBR: $cfgv"
    echo "  当前配置文件: $conf"
    echo "  参数模板: $kind"
    echo "  Mem+Swap: ${total} MB"
    echo "  / 可用空间: ${root_free} MB"
    echo "  /boot 可用空间: ${boot_free} MB"
    hr
    _e102_xanmod_hint
    echo ""

    {
        echo "kernel=$(uname -r 2>/dev/null || echo unknown)"
        echo "cfgv=$cfgv"
        echo "kind=$kind"
        echo "conf=$conf"
        echo "mem_swap_mb=$total"
        echo "root_free_mb=$root_free"
        echo "boot_free_mb=$boot_free"
        echo "date=$(date '+%F %T')"
    } > "$log" 2>/dev/null || true

    if test "$cfgv" != "y"; then
        warn "当前不是内置型 y；如果是模块型 m，请优先走 2/3 的 tcp_bbr.ko 快编路线。"
        return 0
    fi

    if test "${total:-0}" -lt 1000 2>/dev/null; then
        error "Mem+Swap < 1000MB。当前约 ${total}MB，完整内核编译高概率 OOM/IO 卡死，已硬拒绝。"
        ok=0
    fi
    if test "${root_free:-0}" -lt 12000 2>/dev/null; then
        error "/ 可用空间 < 12GB，完整内核编译容易爆盘，已拒绝。"
        ok=0
    fi
    if test "${boot_free:-0}" -lt 350 2>/dev/null; then
        error "/boot 可用空间 < 350MB，initramfs/GRUB 有风险，已拒绝。"
        ok=0
    fi

    if test "$ok" -ne 1; then
        warn "这台 VPS 当前不适合完整内核编译。完整编译会编大量驱动，低资源机器很容易卡在 i40e/iavf/ice 或 OOM。"
        warn "审计日志：$log"
        echo ""
        echo "  如你坚持源码编译，请至少满足："
        echo "    1) 做好 VPS 快照/VNC/救援模式；"
        echo "    2) Mem+Swap 最低 1000MB 才放行，仍建议 4GB+，更推荐 6GB+；"
        echo "    3) 根分区 20GB+；/boot 预留 350MB+；"
        echo "    4) 拿到与当前内核 tag 匹配或可兼容的完整源码。"
        echo ""
        echo "  强制继续需要设置授权变量后重新运行："
        echo "    export XRAY_E102_ALLOW_BUILTIN_FULL_COMPILE=1"
        echo "    # 兼容旧变量：export XRAY_E100_ALLOW_BUILTIN_FULL_COMPILE=1"
        echo "    # 兼容旧变量：export XRAY_E98_ALLOW_BUILTIN_FULL_COMPILE=1"
        if test "${XRAY_E102_ALLOW_BUILTIN_FULL_COMPILE:-0}" != "1" && test "${XRAY_E100_ALLOW_BUILTIN_FULL_COMPILE:-0}" != "1" && test "${XRAY_E98_ALLOW_BUILTIN_FULL_COMPILE:-0}" != "1"; then return 1; fi
    fi

    if test "${XRAY_E102_ALLOW_BUILTIN_FULL_COMPILE:-0}" != "1" && test "${XRAY_E100_ALLOW_BUILTIN_FULL_COMPILE:-0}" != "1" && test "${XRAY_E98_ALLOW_BUILTIN_FULL_COMPILE:-0}" != "1"; then
        warn "为避免误触，V198e105 默认禁止内置型 BBR 完整编译。"
        warn "确认资源充足并已快照后，可手动 export XRAY_E102_ALLOW_BUILTIN_FULL_COMPILE=1 再尝试。"
        warn "兼容旧变量：XRAY_E100_ALLOW_BUILTIN_FULL_COMPILE=1 / XRAY_E98_ALLOW_BUILTIN_FULL_COMPILE=1。"
        return 1
    fi
    return 0
}

_e90_build_builtin_bbr_kernel() {
    local kind="$1" conf="$2"
    _e102_prepare_dirs
    _e102_builtin_full_compile_precheck "$kind" "$conf" || { _e102_pause; return 1; }
    if declare -F _e90_build_builtin_bbr_kernel_e102_base >/dev/null 2>&1; then
        _e90_build_builtin_bbr_kernel_e102_base "$kind" "$conf"
    else
        error "未找到内置型 BBR 编译基线函数。"
        return 1
    fi
}

_e102_builtin_explain() {
    title "V198e105：内置型 BBR / XanMod 说明"
    cat <<'EOF_E102_EXPLAIN'
你现在看到 CONFIG_TCP_CONG_BBR=y，含义是：
  BBR/BBR3 已经被编进内核本体，不存在 tcp_bbr.ko 可热替换。

因此：
  - 模块型 m：可以编译 tcp_bbr.ko 并尝试热替换；
  - 内置型 y：只能完整编译新内核，重启进入新内核后生效；
  - e102 已在 17 子菜单显式增加 9) 内置型 BBR：完整内核源码补丁编译新内核；
  - e102 的完整编译 Mem+Swap 门槛为 1000MB，但低资源 VPS 仍有 OOM/IO 卡死/GRUB 风险。

更稳妥的路线：
  1) 先保留当前 XanMod BBR3；
  2) 用 fq/qdisc、notsent、adv_win/app_win、MSS、RPS/XPS 等参数优化；
  3) 如一定要改 BBR3 源码，优先用 4GB~8GB+ 临时编译机生成内核包再部署；
  4) 如果坚持本机编译，必须先做快照、确认 VNC/救援模式可用。
EOF_E102_EXPLAIN
}

_e96_bbr_module_source_report() {
    local cfgv
    cfgv="$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)"
    if test "$cfgv" = "y"; then
        title "V198e105：BBR 源码检查（内置型 y 专用提示）"
        echo "  当前内核：$(uname -r 2>/dev/null || echo unknown)"
        echo "  CONFIG_TCP_CONG_BBR：y"
        echo "  tcp_bbr 模块路径：(builtin)"
        hr
        warn "这是内置型 BBR，不存在 tcp_bbr.ko 热替换路线。"
        warn "headers 只能提供编译辅助，不会把内置 BBR 变成模块。"
        warn "真正修改 BBR 本体必须走 17 → 9 的完整内核源码补丁编译路线。"
        echo ""
        _e102_builtin_explain
        return 0
    fi
    if declare -F _e96_bbr_module_source_report_e102_base >/dev/null 2>&1; then
        _e96_bbr_module_source_report_e102_base
    else
        title "V198e105：BBR 模块源码 / headers 检查"
        _e96_bbr_find_or_prepare_source >/dev/null 2>&1 && info "已找到 tcp_bbr.c。" || warn "未找到 tcp_bbr.c。"
    fi
}

_e102_builtin_bbr_full_compile_menu() {
    local m conf go cfgv
    while true; do
        cfgv="$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)"
        title "V198e105：内置型 BBR 完整源码补丁编译入口"
        echo "  当前替换路线：$(_e102_bbr_mode_text)"
        echo "  CONFIG_TCP_CONG_BBR：$cfgv"
        echo "  编译门槛：Mem+Swap >= 1000MB；仍需手动 export 授权，热更新不会自动编译内核。"
        echo ""
        echo "  1) 仅运行完整编译前硬门禁检查（不编译）"
        echo "  2) 使用 bbrx3_v1 推荐参数 → 完整编译新内核"
        echo "  3) 自定义 BBR3/XanMod 参数 → 完整编译新内核"
        echo "  4) 使用当前 bbr3_replace.conf → 完整编译新内核"
        echo "  5) 使用普通 BBR v1 推荐参数 → 完整编译新内核（不建议 XanMod/BBR3）"
        echo "  7) 查看内置型 y 与模块型 m 说明"
        echo "  8 ) 解释：为什么完整编译会卡在 i40e/iavf/ice"
        echo "  0) 返回"
        read -rp "请选择: " m || true
        case "${m:-}" in
            1) _e102_builtin_full_compile_precheck "bbr3" "$E89_BBRX_CURRENT/bbr3_replace.conf" || true; _e102_pause ;;
            2) _e89_collect_bbr3_params recommended || return; conf="$(_e89_write_bbr3_conf)"; info "已写入：$conf"; read -rp "确认走完整内核源码补丁编译？[y/N]: " go || true; [[ "$go" =~ ^[yY]$ ]] && _e90_build_builtin_bbr_kernel bbr3 "$conf"; _e102_pause ;;
            3) _e89_collect_bbr3_params custom || return; conf="$(_e89_write_bbr3_conf)"; info "已写入：$conf"; read -rp "确认走完整内核源码补丁编译？[y/N]: " go || true; [[ "$go" =~ ^[yY]$ ]] && _e90_build_builtin_bbr_kernel bbr3 "$conf"; _e102_pause ;;
            4) conf="$E89_BBRX_CURRENT/bbr3_replace.conf"; if test -f "$conf"; then read -rp "确认使用 $conf 完整编译新内核？[y/N]: " go || true; [[ "$go" =~ ^[yY]$ ]] && _e90_build_builtin_bbr_kernel bbr3 "$conf"; else warn "配置不存在，请先执行 2 或 3。"; fi; _e102_pause ;;
            5) _e89_collect_bbrv1_params recommended || return; conf="$(_e89_write_bbrv1_conf)"; info "已写入：$conf"; warn "当前若为 XanMod/BBR3，不建议用 BBR v1 模板。"; read -rp "仍确认完整编译新内核？[y/N]: " go || true; [[ "$go" =~ ^[yY]$ ]] && _e90_build_builtin_bbr_kernel bbrv1 "$conf"; _e102_pause ;;
            7) _e102_builtin_explain; _e102_pause ;;
            8) if declare -F _e97_why_intel_compile_stuck >/dev/null 2>&1; then _e97_why_intel_compile_stuck; else _e102_builtin_explain; fi; _e102_pause ;;
            0) return ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

_e102_bbr3_flow() {
    local m conf go cfgv
    while true; do
        cfgv="$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)"
        title "V198e105：BBR3 / XanMod → bbrx3_v1 参数中心"
        echo "  当前替换路线：$(_e102_bbr_mode_text)"
        if test "$cfgv" = "y"; then
            echo -e "  ${yellow}提示：当前是内置型 y；2/3/4 会最终转入完整内核编译，不能热替换 .ko。也可直接返回 17 菜单选 9。${none}"
        fi
        echo ""
        echo "  1) 查看参数表：参数 / 原版 BBR3 / bbrx3_v1 建议 / 说明"
