            3) _e89_collect_bbr3_params custom || return; conf="$(_e89_write_bbr3_conf)"; info "已写入：$conf"; read -rp "是否立即替换 bbr / 内置型完整编译？[y/N]: " go || true; [[ "$go" =~ ^[yY]$ ]] && _e89_build_replace_bbr bbr3 "$conf"; _e102_pause ;;
            4) conf="$E89_BBRX_CURRENT/bbr3_replace.conf"; if test -f "$conf"; then _e89_build_replace_bbr bbr3 "$conf"; else warn "配置不存在，请先执行 2 或 3。"; fi; _e102_pause ;;
            7) _e102_builtin_explain; _e102_pause ;;
            9) _e102_builtin_bbr_full_compile_menu ;;
            0) return ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

