# 兼容旧菜单名称：让旧调用进入 e102 flow。
_e98_bbr3_flow() { _e102_bbr3_flow; }
_e98_bbrv1_flow() { _e102_bbrv1_flow; }
_e96_bbr3_flow() { _e102_bbr3_flow; }
_e96_bbrv1_flow() { _e102_bbrv1_flow; }

_e89_build_replace_bbr() {
    local kind="$1" conf="$2" cfgv
    cfgv="$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)"
    case "$cfgv" in
        m)
            if declare -F _e97_build_replace_bbr_module >/dev/null 2>&1; then _e97_build_replace_bbr_module "$kind" "$conf"; else error "未找到模块型 BBR 快编函数。"; return 1; fi
            ;;
        y)
            _e90_build_builtin_bbr_kernel "$kind" "$conf"
            ;;
        *) error "当前 CONFIG_TCP_CONG_BBR=$cfgv，无法判断替换路线。"; return 1 ;;
    esac
}

do_bbr_body_replace_menu_e89() {
    while true; do
        clear
        title "V198e105：BBR 本体替换 / 自定义编译中心"
        echo "  自动建议：$(_e89_bbr_detect 2>/dev/null || true)"
        echo "  当前替换路线：$(_e102_bbr_mode_text)"
        echo ""
        echo "  1) 自动检测当前 BBR 类型，并推荐编译方案"
        echo "  2) 模块型/自动路由：普通 Linux 主线 BBR v1 → 自定义全部参数 → 替换 bbr"
        echo "  3) 模块型/自动路由：BBR3 / XanMod → 自定义全部参数 → 替换 bbr"
        echo "  4) 查看已备份的原版 BBR / 系统 TCP 设置"
        echo "  5) 无损切换回最近一次编译前 BBR / 或旧内核 GRUB 回滚提示"
        echo "  6) 查看当前拥塞控制 / qdisc / BBR 状态"
        echo "  7) 解释/检查内置型 y 与模块型 m 的区别"
        echo "  8 ) 解释：为什么完整编译会卡在 i40e/iavf/ice"
        echo "  9) 内置型 BBR：完整内核源码补丁编译新内核（1000MB门槛）"
        echo "  0) 返回主菜单"
        read -rp "请选择: " opt || true
        case "${opt:-}" in
            1) _e89_bbr_detect; _e102_pause ;;
            2) _e102_bbrv1_flow ;;
            3) _e102_bbr3_flow ;;
            4) _e89_bbr_show_backups; _e102_pause ;;
            5) _e89_bbr_rollback_latest || warn "如果本次是内置型整内核编译，请通过云厂商 VNC/GRUB 选择旧内核回滚。"; _e102_pause ;;
            6) _e89_bbr_status; _e102_pause ;;
            7) _e102_builtin_explain; _e102_pause ;;
            8) if declare -F _e97_why_intel_compile_stuck >/dev/null 2>&1; then _e97_why_intel_compile_stuck; else _e102_builtin_explain; fi; _e102_pause ;;
            9) _e102_builtin_bbr_full_compile_menu ;;
            0) return ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

hot_update_from_legacy() {
    title "V198e105：稳态热更新（完整主菜单保留 + BBR目录修复 + 真BBRv3源码/补丁1000MB门槛）"
    if declare -F hot_update_from_legacy_e102_base >/dev/null 2>&1; then
        hot_update_from_legacy_e102_base "$@" || true
    fi
    _e102_prepare_dirs
    echo "198e105" > "$SCRIPT_VERSION_FILE" 2>/dev/null || true
    if test -f "${SCRIPT_PATH:-$0}"; then
        cp -f "${SCRIPT_PATH:-$0}" "$SYMLINK" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e105.sh" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
        chmod +x "$SYMLINK" "$SCRIPT_DIR/ex198e105.sh" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
    fi
    hash -r 2>/dev/null || true
    info "V198e105 热更新完成。"
