main_menu() {
    while true; do
        clear
        local running="离线" ip nowtz bbr_cfg actual_qdisc iface
        if systemctl is-active --quiet xray; then running="平稳在线 (Running)"; fi
        ip="$(_get_ip)"
        nowtz="$(date +%Z' '%z 2>/dev/null || true)"
        bbr_cfg=$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)
        iface="$(_e95_default_iface 2>/dev/null || _e97_default_iface 2>/dev/null || true)"
        actual_qdisc="$(tc qdisc show dev "$iface" 2>/dev/null | head -n 1 || echo unknown)"
        echo -e "${blue}======================================================================${none}"
        echo -e "  ${magenta}Xray System Advanced Management V198e105 - (真BBRv3源码/补丁1000MB门槛 + 目录修复 + 防误编译)${none}"
        echo -e "  引擎态势: ${green}${running}${none} | 全局快捷指令: ${cyan}xrv${none} | 外部识别 IP: ${yellow}${ip}${none}"
        echo -e "  系统装配内核: ${cyan}$(uname -r 2>/dev/null || echo unknown)${none} | 微架构侦测: x64-v${yellow}$(detect_x86_64_level 2>/dev/null || echo '?')${none} | sysctl qdisc/cc: ${yellow}$(_e88_sysctl_get net.core.default_qdisc 2>/dev/null || sysctl -n net.core.default_qdisc 2>/dev/null || echo '?')/$(_e88_sysctl_get net.ipv4.tcp_congestion_control 2>/dev/null || sysctl -n net.ipv4.tcp_congestion_control 2>/dev/null || echo '?')${none} | BBR配置:${yellow}${bbr_cfg}${none}"
        echo -e "  实际root队列: ${cyan}${actual_qdisc}${none}"
        echo -e "  DNS模式: ${cyan}$(cat "${E67_DNS_MODE_FILE:-/usr/local/etc/xray/dns_mode.txt}" 2>/dev/null || echo auto)${none} | 时间轴: ${cyan}${nowtz}${none} | notsent: ${yellow}$(_e88_current_notsent_lowat 2>/dev/null || echo '?')${none}/${cyan}$(_e88_persistent_notsent_lowat 2>/dev/null || echo '?')${none} | adv/app: ${yellow}$(_e88_sysctl_get net.ipv4.tcp_adv_win_scale 2>/dev/null || sysctl -n net.ipv4.tcp_adv_win_scale 2>/dev/null || echo '?')/$(_e88_sysctl_get net.ipv4.tcp_app_win 2>/dev/null || sysctl -n net.ipv4.tcp_app_win 2>/dev/null || echo '?')${none}"
        echo -e "${blue}======================================================================${none}"
        echo "  1) 创建/重构协议节点：Reality Vision / VLESSENC 自选 / SS2022"
        echo "  2) 用户凭证生命周期与独立参数化管理控制"
        echo "  3) 节点链接与多维信息输出聚合中心"
        echo "  4) 人工发起数据强联，执行路由解析规则库强制覆盖更新"
        echo "  5) Xray Core 手动更新/修复（不设置自动更新）"
        echo "  6) 修改或全自动剔除被拦截的防封伪装特征矩阵域名"
        echo "  7) 系统防火墙策略配置 (阻止内网 BT 滥用及第三方广告请求)"
        echo "  8 ) Reality Fallback 底层限速沙盒分析器"
        echo "  9) 全景网络连接审计日志与商用级别网络流量记账本"
        echo "  10) 高级发烧：内核双轨编译(APT/源码)/网络/应用层 60余项极限全控板"
        echo -e "  ${green}11) 从旧 ex198e 环境稳态热更新到 V198e105${none}"
        echo -e "  ${cyan}12) 清理空间（安全释放 / 快照收敛 / 显示硬盘与 Swap）${none}"
        echo -e "  ${cyan}13) 应用网络参数（缓冲/notsent/adv_win/app_win/txqueue/OOOX/MSS）${none}"
        echo -e "  ${cyan}14) TCP 重传 / 单连接诊断中心（只读排障）${none}"
        echo -e "  ${cyan}15) 检查现有配置并重新输出节点${none}"
        echo -e "  ${cyan}16) 状态隔离审计 + VLESSENC 能力检查${none}"
        echo -e "  ${magenta}17) BBR 本体替换 / 自定义编译中心（e102真BBRv3源码/补丁1000MB门槛 + 内置型入口）${none}"
        echo -e "  ${cyan}18) V198e92 安全审计 / Top20复测 / 启动防砖中心${none}"
        echo -e "  ${cyan}19) Xray 跨境链路速度诊断中心（V198e95补强版）${none}"
        echo -e "  ${cyan}20) TC 带宽控制模块（统一接管/精细上限/默认不启用）${none}"
        echo "  0) 折叠命令控制台，返回底层终端"
        echo -e "  ${red}88) 物理不可逆自毁！撤销环境安全防线与系统配置设定${none}"
        hr
        local num=""
        read -rp "请输入操作代码指令: " num || true
        case "${num:-}" in
            1) do_install ;;
            2) do_user_manager ;;
            3) do_summary; while true; do local rb=""; read -rp "输出完毕，按 Enter 退出或者按 b 发起特征替换: " rb || true; if test "$rb" = "b" || test "$rb" = "B"; then if choose_sni; then _update_matrix; do_summary; else break; fi; else break; fi; done ;;
            4) print_magenta ">>> 初始化云网络联通."; bash "$UPDATE_DAT_SCRIPT" >/dev/null 2>&1 || true; ensure_xray_is_alive; info "配置已穿透替换系统！当前路由库完成热加载！"; _e102_pause ;;
            5) do_update_core ;;
            6) if choose_sni; then _update_matrix; do_summary; fi ;;
            7) _global_block_rules ;;
            8) do_fallback_probe ;;
            9) do_status_menu ;;
            10) do_sys_init_menu ;;
            11) hot_update_from_legacy ;;
            12) do_space_cleanup_menu ;;
            13) do_network_params_menu_e56 ;;
            14) do_tcp_diag_menu_e63 ;;
            15) do_install_repair_e77 ;;
            16) e77_audit_runtime_state; _e102_pause ;;
            17) do_bbr_body_replace_menu_e89 ;;
            18) do_e92_audit_menu ;;
            19) if declare -F do_xray_speed_diag_menu_e95 >/dev/null 2>&1; then do_xray_speed_diag_menu_e95; else do_xray_speed_diag_menu_e94; fi ;;
            20) if declare -F do_tc_bandwidth_menu_e95 >/dev/null 2>&1; then do_tc_bandwidth_menu_e95; else do_tc_bandwidth_menu_e94; fi ;;
            88) do_uninstall ;;
            0) exit 0 ;;
            *) echo -e "${red}错误拦截：代码解析为空值！${none}"; sleep 1 ;;
        esac
    done
}


#==============================================================================
# V198e105 FINAL OVERRIDE LAYER
# 目标：
#   1) 修复模块型 BBR 快编误拿跨版本 tcp_bbr.c（例如 6.1 内核误拿 /usr/src/linux-6.8）。
#   2) 修复 bbr_pacing_gain 数组替换把字面量 \n 写进 C 源码导致 stray '\\'。
#   3) 模块快编前增加源码/headers ABI 兼容预检，发现 __bpf_kfunc 等跨代特征时直接拒绝。
#   4) 模块替换保留压缩格式处理，避免 .ko.xz/.ko.zst 被直接 cp 成裸 .ko。
#   5) 热更新仅更新脚本与安全逻辑，不自动编译内核、不自动替换 BBR。
#==============================================================================

if declare -F _e96_bbr_find_or_prepare_source >/dev/null 2>&1 && ! declare -F _e96_bbr_find_or_prepare_source_e102_base >/dev/null 2>&1; then
    eval "$(declare -f _e96_bbr_find_or_prepare_source | sed '1s/_e96_bbr_find_or_prepare_source/_e96_bbr_find_or_prepare_source_e102_base/')" 2>/dev/null || true
fi
if declare -F _e89_bbr_find_source >/dev/null 2>&1 && ! declare -F _e89_bbr_find_source_e102_base >/dev/null 2>&1; then
    eval "$(declare -f _e89_bbr_find_source | sed '1s/_e89_bbr_find_source/_e89_bbr_find_source_e102_base/')" 2>/dev/null || true
fi
if declare -F _e89_patch_bbr_source_from_conf >/dev/null 2>&1 && ! declare -F _e89_patch_bbr_source_from_conf_e102_base >/dev/null 2>&1; then
    eval "$(declare -f _e89_patch_bbr_source_from_conf | sed '1s/_e89_patch_bbr_source_from_conf/_e89_patch_bbr_source_from_conf_e102_base/')" 2>/dev/null || true
fi
if declare -F _e97_build_replace_bbr_module >/dev/null 2>&1 && ! declare -F _e97_build_replace_bbr_module_e102_base >/dev/null 2>&1; then
    eval "$(declare -f _e97_build_replace_bbr_module | sed '1s/_e97_build_replace_bbr_module/_e97_build_replace_bbr_module_e102_base/')" 2>/dev/null || true
fi
if declare -F _e96_bbr_module_source_report >/dev/null 2>&1 && ! declare -F _e96_bbr_module_source_report_e102_base >/dev/null 2>&1; then
    eval "$(declare -f _e96_bbr_module_source_report | sed '1s/_e96_bbr_module_source_report/_e96_bbr_module_source_report_e102_base/')" 2>/dev/null || true
fi
if declare -F hot_update_from_legacy >/dev/null 2>&1 && ! declare -F hot_update_from_legacy_e102_base >/dev/null 2>&1; then
    eval "$(declare -f hot_update_from_legacy | sed '1s/hot_update_from_legacy/hot_update_from_legacy_e102_base/')" 2>/dev/null || true
fi

_e102_audit_dir() { echo "$CONFIG_DIR/audit_e102"; }
_e102_ts() { date +%Y%m%d_%H%M%S; }
_e102_pause() { local _p=""; read -rp "按 Enter 继续..." _p || true; }
_e102_prepare_dirs() { mkdir -p "$(_e102_audit_dir)" "$E89_BBRX_BUILD_ROOT" "$E89_BBRX_BACKUP_ROOT" "$E89_BBRX_CURRENT" 2>/dev/null || true; }

_e102_kernel_shortver() {
    uname -r 2>/dev/null | sed -E 's/^([0-9]+\.[0-9]+).*/\1/'
}

_e102_tcp_bbr_root() {
    local f="${1:-}"
    f="${f%/net/ipv4/tcp_bbr.c}"
    printf '%s\n' "$f"
}

_e102_source_declared_release() {
    local root f rel=""
    root="$(_e102_tcp_bbr_root "${1:-}")"
    for f in \
        "$root/include/generated/utsrelease.h" \
        "$root/include/config/kernel.release" \
        "$root/.kernelrelease"; do
        test -f "$f" || continue
        rel=$(sed -n 's/.*UTS_RELEASE[[:space:]]*"\([^"]\+\)".*/\1/p;1p' "$f" 2>/dev/null | head -n1 | tr -d ' \t\r\n"' || true)
        test -n "$rel" && { printf '%s\n' "$rel"; return 0; }
    done
    if test -f "$root/Makefile"; then
        awk '
            /^VERSION[[:space:]]*=/ {v=$3}
            /^PATCHLEVEL[[:space:]]*=/ {p=$3}
            /^SUBLEVEL[[:space:]]*=/ {s=$3}
            /^EXTRAVERSION[[:space:]]*=/ {e=$3}
            END { if (v != "" && p != "") { printf "%s.%s", v, p; if (s != "") printf ".%s", s; if (e != "") printf "%s", e; printf "\n" } }
        ' "$root/Makefile" 2>/dev/null | head -n1
    fi
}

_e102_source_matches_running_kernel() {
    local f="${1:-}" krel kshort rel
    test -n "$f" && test -f "$f" || return 1
    krel="$(uname -r 2>/dev/null || echo unknown)"
    kshort="$(_e102_kernel_shortver)"
    case "$f" in
        /lib/modules/"$krel"/build/*|/lib/modules/"$krel"/source/*) return 0 ;;
    esac
    if test -n "${BBR_SOURCE_FORCE:-}" && test "${BBR_SOURCE_FORCE:-0}" = "1" && test -n "${BBR_SOURCE:-}" && test "$f" = "$BBR_SOURCE"; then
        warn "BBR_SOURCE_FORCE=1：跳过源码版本保护，强制使用 $f。"
        return 0
    fi
    if echo "$f" | grep -Fq "$krel"; then return 0; fi
    if echo "$f" | grep -Eq "linux(-source)?[-_/]?${kshort}([^0-9]|$)"; then return 0; fi
    rel="$(_e102_source_declared_release "$f" 2>/dev/null | head -n1 || true)"
    if test -n "$rel"; then
        if test "$rel" = "$krel" || echo "$rel" | grep -Eq "^${kshort}([.-]|$)"; then return 0; fi
    fi
    return 1
}

_e102_module_headers_support_source() {
    local f="${1:-}" kbuild
    kbuild="/lib/modules/$(uname -r)/build"
    test -d "$kbuild" || return 1
    # 新内核 tcp_bbr.c 若含 __bpf_kfunc，而当前 headers 没有定义，会出现 expected ';' before static。
    if grep -q '__bpf_kfunc' "$f" 2>/dev/null; then
        if ! grep -Rqs '__bpf_kfunc' "$kbuild/include" "$kbuild/scripts" 2>/dev/null; then
            return 1
        fi
    fi
    return 0
}

_e102_valid_current_bbr_module_source() {
    local f="${1:-}"
    _e96_valid_bbr_source "$f" || return 1
    _e102_source_matches_running_kernel "$f" || return 1
    _e102_module_headers_support_source "$f" || return 1
    return 0
}

_e102_find_current_module_tcp_bbr_source_now() {
    local f base krel kshort
    krel="$(uname -r 2>/dev/null || echo unknown)"
    kshort="$(_e102_kernel_shortver)"

    if test -n "${BBR_SOURCE:-}"; then
        if _e102_valid_current_bbr_module_source "$BBR_SOURCE" || { test "${BBR_SOURCE_FORCE:-0}" = "1" && _e96_valid_bbr_source "$BBR_SOURCE"; }; then
            echo "$BBR_SOURCE"
            return 0
        fi
    fi

    for f in \
        "/lib/modules/$krel/build/net/ipv4/tcp_bbr.c" \
        "/lib/modules/$krel/source/net/ipv4/tcp_bbr.c" \
        "/usr/src/linux-headers-$krel/net/ipv4/tcp_bbr.c" \
        "/usr/src/linux-source-$kshort/net/ipv4/tcp_bbr.c" \
        "/usr/src/linux-$kshort/net/ipv4/tcp_bbr.c" \
        "$E96_BBR_SRC_ROOT/linux-source-$kshort/net/ipv4/tcp_bbr.c" \
        "$E96_BBR_SRC_ROOT/linux-$kshort/net/ipv4/tcp_bbr.c"; do
        if _e102_valid_current_bbr_module_source "$f"; then echo "$f"; return 0; fi
    done

    for base in \
        "/lib/modules/$krel/build" \
        "/lib/modules/$krel/source" \
        "$E96_BBR_SRC_ROOT" \
        "/usr/src"; do
        test -d "$base" || continue
        while IFS= read -r f; do
            if _e102_valid_current_bbr_module_source "$f"; then echo "$f"; return 0; fi
        done < <(find "$base" -path '*/net/ipv4/tcp_bbr.c' -type f 2>/dev/null | sort)
    done
    return 1
}

_e102_extract_matching_linux_source_tars() {
    local tarball outdir marker base kshort found=0
    kshort="$(_e102_kernel_shortver)"
    mkdir -p "$E96_BBR_SRC_ROOT" 2>/dev/null || true
    for tarball in "/usr/src/linux-source-${kshort}.tar."* "/usr/src/linux-${kshort}"*.tar.* "/usr/src/linux_${kshort}"*.orig.tar.*; do
        test -f "$tarball" || continue
        if ! tar -tf "$tarball" 2>/dev/null | grep -q 'net/ipv4/tcp_bbr.c'; then continue; fi
        base=$(basename "$tarball" | sed -E 's/\.tar\..*$//; s/\.orig$//')
        outdir="$E96_BBR_SRC_ROOT/$base"
        marker="$outdir/.e102_extracted"
        if test ! -f "$marker"; then
            info "正在解包与当前内核主版本匹配的源码包：$tarball"
            rm -rf "$outdir" 2>/dev/null || true
            mkdir -p "$outdir" 2>/dev/null || true
            if tar -xf "$tarball" -C "$outdir" --strip-components=1 2>/dev/null; then
                touch "$marker" 2>/dev/null || true
            else
                warn "解包失败：$tarball"
                rm -rf "$outdir" 2>/dev/null || true
                continue
            fi
        fi
        found=1
    done
    test "$found" -eq 1
}

_e102_try_install_current_linux_source() {
    local kshort pkglog
    kshort="$(_e102_kernel_shortver)"
    pkglog="$(_e102_audit_dir)/bbr-source-install.$(_e102_ts).log"
    mkdir -p "$(_e102_audit_dir)" 2>/dev/null || true
    warn "未找到匹配当前内核的 tcp_bbr.c，只尝试安装 linux-headers-$(uname -r) 与 linux-source-$kshort。日志：$pkglog"
    export DEBIAN_FRONTEND=noninteractive
    {
        echo "[e102] uname=$(uname -r) kshort=$kshort"
        apt-get update -y
        apt-get install -y "linux-headers-$(uname -r)" || true
        apt-get install -y "linux-source-$kshort" || true
        apt-get install -y build-essential bc bison flex libssl-dev libelf-dev dwarves xz-utils zstd kmod || true
    } >>"$pkglog" 2>&1 || true
}

_e102_bbr_find_or_prepare_source() {
    local src="" cfgv
    cfgv="$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)"
    src="$(_e102_find_current_module_tcp_bbr_source_now 2>/dev/null || true)"
    if _e102_valid_current_bbr_module_source "$src"; then echo "$src"; return 0; fi

    _e102_extract_matching_linux_source_tars >/dev/null 2>&1 || true
    src="$(_e102_find_current_module_tcp_bbr_source_now 2>/dev/null || true)"
    if _e102_valid_current_bbr_module_source "$src"; then echo "$src"; return 0; fi

    # 对模块型 m 才自动补当前 linux-source；内置型 y 不再拿 /usr/src 任意源码误报可快编。
    if test "$cfgv" = "m"; then
        _e102_try_install_current_linux_source
        _e102_extract_matching_linux_source_tars >/dev/null 2>&1 || true
        src="$(_e102_find_current_module_tcp_bbr_source_now 2>/dev/null || true)"
        if _e102_valid_current_bbr_module_source "$src"; then echo "$src"; return 0; fi
    fi
    return 1
}

# 覆盖旧 e96/e97 的宽松源码发现：模块快编只能使用当前内核匹配源码。
_e96_bbr_find_or_prepare_source() { _e102_bbr_find_or_prepare_source; }
_e89_bbr_find_source() { _e102_bbr_find_or_prepare_source; }

_e89_perl_replace_array() {
    local file="$1" body="$2"
    BODY="$body" perl -0pi -e 'my $b=$ENV{BODY}; $b =~ s/\\n/\n/g; s/static\s+const\s+int\s+bbr_pacing_gain\[\]\s*=\s*\{.*?\};/static const int bbr_pacing_gain[] = {\n$b\n};/sg' "$file" 2>/dev/null || true
}

_e102_patched_source_sanity() {
    local f="$1"
    if grep -nE '\\n[[:space:]]*BBR_UNIT|,[[:space:]]*\\n' "$f" >/tmp/e102-bbr-sanity.$$ 2>/dev/null; then
        error "生成后的 tcp_bbr.c 仍含字面量 \\n，拒绝编译。"
        sed 's/^/    /' /tmp/e102-bbr-sanity.$$ 2>/dev/null | head -n 20 || true
        rm -f /tmp/e102-bbr-sanity.$$ 2>/dev/null || true
        return 1
    fi
    rm -f /tmp/e102-bbr-sanity.$$ 2>/dev/null || true
    if grep -q '__bpf_kfunc' "$f" 2>/dev/null && ! _e102_module_headers_support_source "$f"; then
        error "源码包含 __bpf_kfunc，但当前 headers 不支持；这是跨内核版本源码，拒绝模块快编。"
        return 1
    fi
    return 0
}

_e89_patch_bbr_source_from_conf() {
    local src="$1" conf="$2" kind="$3"
    if declare -F _e89_patch_bbr_source_from_conf_e102_base >/dev/null 2>&1; then
        _e89_patch_bbr_source_from_conf_e102_base "$src" "$conf" "$kind"
    else
        error "缺少 BBR 源码补丁基线函数。"
        return 1
    fi
    _e102_patched_source_sanity "$src"
}

_e102_bbr_module_source_report() {
    local cfgv src krel kshort
    cfgv="$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)"
    krel="$(uname -r 2>/dev/null || echo unknown)"
    kshort="$(_e102_kernel_shortver)"
    title "V198e105：BBR 模块源码 / headers 严格检查"
    echo "  当前内核：$krel"
    echo "  CONFIG_TCP_CONG_BBR：$cfgv"
    echo "  tcp_bbr 模块路径：$(_e89_bbr_mod_path 2>/dev/null || echo '')"
    echo "  build 链接：/lib/modules/$krel/build"
    echo "  源码匹配规则：只接受 /lib/modules/$krel/build|source 或 linux-source-$kshort 等当前内核主版本源码。"
    hr
    if test "$cfgv" = "y"; then
        warn "当前是内置型 y，没有 tcp_bbr.ko 快编路线；请走 17 → 9 完整内核源码补丁编译。"
        return 0
    fi
    src="$(_e102_bbr_find_or_prepare_source 2>/dev/null || true)"
    if _e102_valid_current_bbr_module_source "$src"; then
        info "已找到匹配当前内核的 tcp_bbr.c：$src"
        grep -n "tcp_congestion_ops\|MODULE_ALIAS_TCP_CONGESTION\|\.name" "$src" 2>/dev/null | head -n 12 | sed 's/^/    /' || true
    else
        error "未找到匹配当前内核的 tcp_bbr.c。"
        warn "不会再自动拿 /usr/src/linux-6.8 等跨版本源码冒充当前内核源码。"
        warn "如你确定源码完全兼容，可手动：export BBR_SOURCE=/path/to/net/ipv4/tcp_bbr.c；极端强制：export BBR_SOURCE_FORCE=1。"
    fi
}
_e96_bbr_module_source_report() { _e102_bbr_module_source_report; }

_e102_build_replace_bbr_module() {
    local kind="$1" conf="$2" cfgv modp src work newko bdir release_now timeout_s kbuild
    title "V198e105：模块型 BBR 严格快编热替换（只编 tcp_bbr.ko）"
    _e89_bbr_prepare_dirs
    _e102_prepare_dirs

    cfgv="$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)"
    modp="$(_e89_bbr_mod_path 2>/dev/null || true)"
    kbuild="/lib/modules/$(uname -r)/build"

    if test "$cfgv" != "m"; then error "当前 CONFIG_TCP_CONG_BBR=$cfgv，不是模块型 m。"; return 1; fi
    if test -z "$modp" || test ! -f "$modp"; then error "未找到原版 tcp_bbr.ko 路径，拒绝替换。"; return 1; fi

    if test ! -d "$kbuild"; then
        warn "缺少 $kbuild，尝试安装当前内核 headers。"
        export DEBIAN_FRONTEND=noninteractive
        apt-get update -y >/dev/null 2>&1 || true
        apt-get install -y "linux-headers-$(uname -r)" >/dev/null 2>&1 || true
    fi
    if test ! -d "$kbuild"; then error "仍缺少 $kbuild，无法外部模块快编。"; return 1; fi

    src="$(_e102_bbr_find_or_prepare_source 2>/dev/null || true)"
    if ! _e102_valid_current_bbr_module_source "$src"; then
        error "未找到与当前内核匹配且可被当前 headers 编译的 tcp_bbr.c。"
        warn "已拒绝跨版本源码快编，避免 6.1 内核误用 linux-6.8 源码产生 __bpf_kfunc/ABI 错误。"
        warn "可先执行 17 → 7 查看严格检查结果。"
        return 1
    fi
    info "使用匹配源码：$src"

    if declare -F _e91_conf_sane >/dev/null 2>&1; then _e91_conf_sane "$conf" "$kind" || return 1; fi

    bdir="$(_e89_bbr_backup_state)" || { error "备份失败，拒绝继续。"; return 1; }
    _e89_bbr_write_original_param_note "$bdir" "$kind"
    cp -af "$conf" "$bdir/generated_new_params.conf" 2>/dev/null || true
    cp -af "$src" "$bdir/tcp_bbr.c.source.used" 2>/dev/null || true
    echo "$src" > "$bdir/source.path.txt" 2>/dev/null || true
    info "已创建替换前完整备份：$bdir"

    work="$E89_BBRX_BUILD_ROOT/build_$(_e102_ts)_$kind"
    mkdir -p "$work" || return 1
    cp -af "$src" "$work/tcp_bbr.c"
    cp -af "$work/tcp_bbr.c" "$bdir/tcp_bbr.c.new.before_patch" 2>/dev/null || true
    _e89_patch_bbr_source_from_conf "$work/tcp_bbr.c" "$conf" "$kind" || { error "源码补丁后自检失败，拒绝编译。"; return 1; }
    cp -af "$work/tcp_bbr.c" "$bdir/tcp_bbr.c.new" 2>/dev/null || true

    cat > "$work/Makefile" <<'EOF_MAKE_E102'
obj-m := tcp_bbr.o
EOF_MAKE_E102

    timeout_s="900"
    if declare -F _e97_module_make_timeout >/dev/null 2>&1; then timeout_s="$(_e97_module_make_timeout 2>/dev/null || echo 900)"; fi
    info "开始外部模块快编 tcp_bbr.ko：$work"
    info "命令：timeout ${timeout_s}s make -j1 -C $kbuild M=$work modules"
    if ! timeout "${timeout_s}s" make -j1 -C "$kbuild" M="$work" modules; then
        error "外部模块快编失败或超时，原系统未替换。工作目录：$work"
        warn "若错误含 __bpf_kfunc/结构体字段缺失，说明源码仍与当前 headers 不兼容。"
        return 1
    fi
    newko="$work/tcp_bbr.ko"
    if test ! -f "$newko"; then error "编译后未发现 $newko，拒绝替换。"; return 1; fi

    cp -af "$newko" "$bdir/tcp_bbr.ko.new" 2>/dev/null || true
    sha256sum "$newko" > "$bdir/tcp_bbr.ko.new.sha256" 2>/dev/null || true
    cat > "$bdir/rollback.sh" <<EOF_ROLLBACK_E102
#!/usr/bin/env bash
set -e
ORIG_KO="$modp"
BACKUP_DIR="$bdir"
sysctl -w net.ipv4.tcp_congestion_control=cubic >/dev/null 2>&1 || true
modprobe -r tcp_bbr 2>/dev/null || rmmod tcp_bbr 2>/dev/null || true
if test -f "\$BACKUP_DIR/tcp_bbr.ko.orig"; then cp -af "\$BACKUP_DIR/tcp_bbr.ko.orig" "\$ORIG_KO"; fi
depmod -a
modprobe tcp_bbr || true
sysctl -w net.ipv4.tcp_congestion_control=bbr >/dev/null 2>&1 || true
echo "rollback done"
EOF_ROLLBACK_E102
    chmod +x "$bdir/rollback.sh" 2>/dev/null || true

    warn "准备替换原模块：$modp"
    read -rp "是否临时切到 cubic 并尝试卸载旧 tcp_bbr 后立即热替换？[Y/n]: " release_now || true
    release_now="${release_now:-Y}"
    if [[ "$release_now" =~ ^[yY]$ ]]; then
        sysctl -w net.ipv4.tcp_congestion_control=cubic >/dev/null 2>&1 || true
        modprobe -r tcp_bbr 2>/dev/null || rmmod tcp_bbr 2>/dev/null || warn "旧 tcp_bbr 当前仍被引用，磁盘替换仍会执行；可能需重启后完全生效。"
    fi
    if declare -F _e89_install_new_ko_to_original_path >/dev/null 2>&1; then
        _e89_install_new_ko_to_original_path "$newko" "$modp" || { error "写入 $modp 失败，已保留备份：$bdir"; return 1; }
    else
        cp -af "$newko" "$modp" || { error "写入 $modp 失败，已保留备份：$bdir"; return 1; }
    fi
    depmod -a >/dev/null 2>&1 || true
    modprobe tcp_bbr 2>/dev/null || warn "modprobe tcp_bbr 未立即成功；如果旧模块仍在内存中，请重启后验证。"
    sysctl -w net.ipv4.tcp_congestion_control=bbr >/dev/null 2>&1 || true
    echo "tcp_bbr" > "$E89_BBRX_MODULES_LOAD" 2>/dev/null || true

    info "V198e105 模块型 BBR 快编替换完成。备份目录：$bdir"
    warn "请验证：sysctl net.ipv4.tcp_congestion_control && modinfo tcp_bbr | head && ss -tin"
    return 0
}

_e97_build_replace_bbr_module() { _e102_build_replace_bbr_module "$@"; }
_e96_build_replace_bbr_module() { _e102_build_replace_bbr_module "$@"; }

_e102_bbr_compile_mode_text() {
    local cfgv
    cfgv="$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)"
    case "$cfgv" in
        m) echo "模块型 m：只允许匹配当前内核的 tcp_bbr.c 外部快编；拒绝跨版本源码" ;;
        y) echo "内置型 y：不能热替换 .ko；请走 9) 完整内核源码补丁编译新内核" ;;
        *) echo "未知：请先执行自动检测，禁止盲改" ;;
    esac
}
_e101_bbr_mode_text() { _e102_bbr_compile_mode_text; }
_e96_bbr_compile_mode_text() { _e102_bbr_compile_mode_text; }

_e89_build_replace_bbr() {
    local kind="$1" conf="$2" cfgv
    cfgv="$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)"
    case "$cfgv" in
        m) _e102_build_replace_bbr_module "$kind" "$conf" ;;
        y) _e90_build_builtin_bbr_kernel "$kind" "$conf" ;;
        *) error "当前 CONFIG_TCP_CONG_BBR=$cfgv，无法判断替换路线。"; return 1 ;;
    esac
}

_e89_bbr_detect() {
    title "V198e105：BBR 本体自动检测与编译建议"
    _e89_bbr_prepare_dirs
    local krel cfgv cc av modp src kind rec
    krel="$(uname -r 2>/dev/null || echo unknown)"
    cfgv="$(_e89_bbr_kconfig_value 2>/dev/null || echo unknown)"
    cc="$(sysctl -n net.ipv4.tcp_congestion_control 2>/dev/null || echo unknown)"
    av="$(sysctl -n net.ipv4.tcp_available_congestion_control 2>/dev/null || echo unknown)"
    modp="$(_e89_bbr_mod_path 2>/dev/null || true)"
    src="$(_e102_bbr_find_or_prepare_source 2>/dev/null || true)"
    kind="$(_e89_bbr_source_kind "$src" 2>/dev/null || echo unknown)"
    rec="$(_e89_bbr_recommend_kind 2>/dev/null || echo bbrv1)"
    echo "  当前内核：$krel"
    echo "  CONFIG_TCP_CONG_BBR：$cfgv"
    echo "  当前拥塞控制：$cc"
    echo "  可用拥塞控制：$av"
    echo "  tcp_bbr 模块路径：${modp:-未发现/可能内置}"
    if test -n "$src"; then
        echo "  可用 tcp_bbr.c 源码：$src"
        echo "  源码类型判断：$kind"
    else
        echo "  可用 tcp_bbr.c 源码：未找到与当前内核匹配的源码"
        echo "  源码类型判断：unknown"
    fi
    hr
    if test "$cfgv" = "m" && test -n "$modp" && test -f "$modp"; then
        print_green "  替换可行性：模块型 BBR，可热替换 tcp_bbr.ko，但必须使用当前内核匹配源码。"
    elif test "$cfgv" = "y"; then
        print_yellow "  替换可行性：内置型 BBR，不能替换 .ko；只能完整内核源码补丁编译，重启后生效。"
    else
        print_yellow "  替换可行性：未能确认模块型或内置型 BBR。"
    fi
    if test "$rec" = "bbr3"; then echo -e "  ${cyan}推荐编译方案：BBR3 / XanMod → bbrx3_v1 参数模板${none}"; else echo -e "  ${cyan}推荐编译方案：普通 Linux 主线 BBR v1 → bbrx_v1 参数模板${none}"; fi
    echo "  当前替换路线：$(_e102_bbr_compile_mode_text)"
}

hot_update_from_legacy() {
    title "V198e105：稳态热更新（BBR模块源码严格匹配 + 换行补丁修复 + 目录保留）"
    if declare -F hot_update_from_legacy_e102_base >/dev/null 2>&1; then
        hot_update_from_legacy_e102_base "$@" || true
    fi
    _e102_prepare_dirs
    echo "198e105" > "$SCRIPT_VERSION_FILE" 2>/dev/null || true
    if test -f "${SCRIPT_PATH:-$0}"; then
        cp -f "${SCRIPT_PATH:-$0}" "$SYMLINK" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e105.sh" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
        chmod +x "$SYMLINK" "$SCRIPT_DIR/ex198e105.sh" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
    fi
    hash -r 2>/dev/null || true
    info "V198e105 热更新完成。"
    info "修复：模块型 BBR 快编只接受当前内核匹配 tcp_bbr.c，拒绝 6.1 内核误用 linux-6.8 源码。"
    info "修复：bbr_pacing_gain 数组替换会把 \\n 转为真实换行，避免 stray '\\' 编译错误。"
    info "修复：编译前检测 __bpf_kfunc/headers 兼容；不通过则拒绝替换。"
    info "热更新不会自动编译内核、不会自动替换 tcp_bbr.ko。"
}


#==============================================================================
#==============================================================================
# V198e105 FINAL OVERRIDE LAYER
# 目标：
#   1) 修正 e103 误判：--hot-update 默认必须落地 initcwnd/initrwnd=32。
#   2) 菜单 13 不再提供“39) 设置 initcwnd/initrwnd=32”独立档；32 作为热更新默认值由 36 应用。
#   3) 只关闭 Xray Core 自动更新；geoip/geosite dat 自动更新保持启用/恢复，不再误删 xray-dat-update.timer。
#   4) 热更新收尾强制写入版本、快捷入口、默认起步窗口、dat timer 与 Core 自动更新禁用状态。
#==============================================================================

if declare -F hot_update_from_legacy >/dev/null 2>&1 && ! declare -F hot_update_from_legacy_e105_base >/dev/null 2>&1; then
    eval "$(declare -f hot_update_from_legacy | sed '1s/hot_update_from_legacy/hot_update_from_legacy_e105_base/')" 2>/dev/null || true
fi
if declare -F do_update_core >/dev/null 2>&1 && ! declare -F do_update_core_e105_base >/dev/null 2>&1; then
    eval "$(declare -f do_update_core | sed '1s/do_update_core/do_update_core_e105_base/')" 2>/dev/null || true
fi

_e105_prepare_dirs() {
    mkdir -p "$CONFIG_DIR" "$SCRIPT_DIR" "$LOG_DIR" "$DAT_DIR" "$BACKUP_DIR" "$FLAGS_DIR" 2>/dev/null || true
}

_e105_disable_xray_core_auto_update() {
    _e105_prepare_dirs

    # 只处理 Xray Core 自动更新；不要触碰 xray-dat-update.timer / update-dat.sh / geoip.dat / geosite.dat。
    local units=(
        xray-update.timer xray-update.service
        xray-core-update.timer xray-core-update.service
        xray-check-update.timer xray-check-update.service
        xray-install-update.timer xray-install-update.service
        xray-release-update.timer xray-release-update.service
    )
    local u
    for u in "${units[@]}"; do
        systemctl disable --now "$u" >/dev/null 2>&1 || true
    done
    systemctl daemon-reload >/dev/null 2>&1 || true

    # 清理 cron：保留 update-dat.sh / xray-dat-update；只移除 Core 更新器。
    local tmp_cron
    tmp_cron=$(mktemp /tmp/cron_e105_core_XXXXXX) || true
    if test -n "${tmp_cron:-}"; then
        crontab -l 2>/dev/null | awk '
            /update-dat\.sh/ {print; next}
            /xray-dat-update/ {print; next}
            /geoip\.dat/ {print; next}
            /geosite\.dat/ {print; next}
            /install-release\.sh/ {next}
            /XTLS\/Xray-install/ {next}
            /Xray-install/ {next}
            /xray-core-update/ {next}
            /xray-update/ {next}
            /[xX]ray/ && /[uU]pdate/ {next}
            {print}
        ' > "$tmp_cron" || true
        crontab "$tmp_cron" 2>/dev/null || true
        rm -f "$tmp_cron" 2>/dev/null || true
    fi

    printf 'disabled_at=%s\nscope=xray-core-only\ndat_timer=preserve\n' "$(date '+%F %T')" > "$CONFIG_DIR/xray_core_auto_update_disabled_e105.txt" 2>/dev/null || true
}

install_update_dat() {
    # e105：恢复/保持 geoip/geosite dat 自动更新；本函数不更新 Xray Core。
    _e105_prepare_dirs
    cat > "$UPDATE_DAT_SCRIPT" <<'UPDSH_E105'
#!/usr/bin/env bash
set -u
XRAY_DAT_DIR="/usr/local/share/xray"
LOG_FILE="/var/log/xray/update-dat.log"
mkdir -p "$XRAY_DAT_DIR" "$(dirname "$LOG_FILE")" 2>/dev/null || true
log_msg() { echo "[$(date +'%Y-%m-%d %H:%M:%S')] $*" >> "$LOG_FILE"; }
dl_if_changed() {
    local url="$1" out="$2" tmp="$2.tmp.$$"
    if ! curl -fsSL --connect-timeout 10 --max-time 300 -o "$tmp" "$url"; then
        rm -f "$tmp" 2>/dev/null || true
        log_msg "[WARN] 下载失败，保留旧文件: $url"
        return 1
    fi
    if test -s "$out" && cmp -s "$tmp" "$out"; then
        rm -f "$tmp" 2>/dev/null || true
        log_msg "[INFO] 未变化: $(basename "$out")"
        return 0
    fi
    mv -f "$tmp" "$out"
    log_msg "[INFO] 已更新: $(basename "$out")"
    echo changed >> /tmp/xray-dat-changed.$$ 2>/dev/null || true
    return 0
}
rm -f /tmp/xray-dat-changed.$$ 2>/dev/null || true
ok=0
dl_if_changed "https://github.com/Loyalsoldier/v2ray-rules-dat/raw/release/geoip.dat" "$XRAY_DAT_DIR/geoip.dat" || ok=1
dl_if_changed "https://github.com/Loyalsoldier/domain-list-custom/releases/latest/download/geosite.dat" "$XRAY_DAT_DIR/geosite.dat" || ok=1
if test -s /tmp/xray-dat-changed.$$ && systemctl is-active --quiet xray; then
    log_msg "[INFO] dat 文件已变化，重启 Xray 使规则生效。"
    systemctl restart xray >/dev/null 2>&1 || true
fi
rm -f /tmp/xray-dat-changed.$$ 2>/dev/null || true
exit "$ok"
UPDSH_E105
    chmod +x "$UPDATE_DAT_SCRIPT" 2>/dev/null || true

    cat > /etc/systemd/system/xray-dat-update.service <<EOF_SERVICE_E105
[Unit]
Description=Xray geoip/geosite dat safe updater
After=network-online.target
Wants=network-online.target

[Service]
Type=oneshot
ExecStart=$UPDATE_DAT_SCRIPT
EOF_SERVICE_E105

    cat > /etc/systemd/system/xray-dat-update.timer <<'EOF_TIMER_E105'
[Unit]
Description=Daily Xray geoip/geosite dat update timer

[Timer]
OnCalendar=*-*-* 03:00:00
RandomizedDelaySec=20m
Persistent=true

[Install]
WantedBy=timers.target
EOF_TIMER_E105

    systemctl daemon-reload >/dev/null 2>&1 || true
    systemctl enable --now xray-dat-update.timer >/dev/null 2>&1 || true
    info "e105：已保留/恢复 geoip/geosite dat 自动更新 timer；未设置 Xray Core 自动更新。"
}

_e105_init_window_note() {
    _e105_prepare_dirs
    {
        echo "time=$(date '+%F %T')"
        echo "mode=${1:-unknown}"
        echo "initcwnd=${2:-unset}"
        echo "initrwnd=${3:-unset}"
        echo "note=${4:-}"
        echo "route=$(ip route show default 2>/dev/null | head -n1 || true)"
    } > "$CONFIG_DIR/init_window_e105.txt" 2>/dev/null || true
}

_e105_default_route_clean() {
    if declare -F _e88_default_route_clean >/dev/null 2>&1; then
        _e88_default_route_clean 2>/dev/null && return 0
    fi
    local route
    route=$(ip route show default 2>/dev/null | head -n1 || true)
    test -n "$route" || return 1
    printf '%s\n' "$route" | sed 's/[[:space:]]\+initcwnd[[:space:]]\+[0-9]\+//g; s/[[:space:]]\+initrwnd[[:space:]]\+[0-9]\+//g'
}

_e105_install_init_window_boot_restore() {
    local cw="${1:-32}" rw="${2:-32}"
    _e105_prepare_dirs
    systemctl disable --now xray-init-window-e88.service >/dev/null 2>&1 || true
    rm -f /etc/systemd/system/xray-init-window-e88.service /usr/local/bin/xray-init-window-e88.sh 2>/dev/null || true

    cat > /usr/local/bin/xray-init-window-e105.sh <<'EOF_E105_INIT_BOOT'
#!/usr/bin/env bash
set +e
export PATH="/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin"
CONFIG_DIR="/usr/local/etc/xray"
CWND_VAL=$(cat "$CONFIG_DIR/initcwnd.txt" 2>/dev/null | tr -cd '0-9' || true)
RWND_VAL=$(cat "$CONFIG_DIR/initrwnd.txt" 2>/dev/null | tr -cd '0-9' || true)
[ -n "$CWND_VAL" ] || CWND_VAL=32
[ -n "$RWND_VAL" ] || RWND_VAL="$CWND_VAL"
DEF_ROUTE=$(ip route show default 2>/dev/null | head -n 1 || true)
[ -n "$DEF_ROUTE" ] || exit 0
CLEAN_ROUTE=$(printf '%s\n' "$DEF_ROUTE" | sed 's/[[:space:]]\+initcwnd[[:space:]]\+[0-9]\+//g; s/[[:space:]]\+initrwnd[[:space:]]\+[0-9]\+//g')
ip route change $CLEAN_ROUTE initcwnd "$CWND_VAL" initrwnd "$RWND_VAL" 2>/dev/null || true
exit 0
EOF_E105_INIT_BOOT
    chmod +x /usr/local/bin/xray-init-window-e105.sh 2>/dev/null || true

    cat > /etc/systemd/system/xray-init-window-e105.service <<'EOF_E105_INIT_SERVICE'
[Unit]
Description=Xray e105 TCP initcwnd/initrwnd restore after boot
After=network-online.target
Wants=network-online.target
Before=xray.service

[Service]
Type=oneshot
ExecStart=/usr/local/bin/xray-init-window-e105.sh
RemainAfterExit=yes

[Install]
WantedBy=multi-user.target
EOF_E105_INIT_SERVICE
    echo "$cw" > "$CONFIG_DIR/initcwnd.txt" 2>/dev/null || true
    echo "$rw" > "$CONFIG_DIR/initrwnd.txt" 2>/dev/null || true
    systemctl daemon-reload >/dev/null 2>&1 || true
    systemctl enable xray-init-window-e105.service >/dev/null 2>&1 || true
    systemctl restart xray-init-window-e105.service >/dev/null 2>&1 || true
    if declare -F update_hw_boot_script >/dev/null 2>&1; then update_hw_boot_script >/dev/null 2>&1 || true; fi
}

_e88_set_init_window() {
    local cw="${1:-}" rw="${2:-$1}" mode="${3:-manual}" clean=""
    if ! [[ "$cw" =~ ^[0-9]+$ ]] || ! [[ "$rw" =~ ^[0-9]+$ ]]; then
        error "initcwnd/initrwnd 必须为数字。"
        return 1
    fi
    if test "$cw" -lt 2 2>/dev/null || test "$cw" -gt 100 2>/dev/null || test "$rw" -lt 2 2>/dev/null || test "$rw" -gt 100 2>/dev/null; then
        error "initcwnd/initrwnd 建议范围 2~100。"
        return 1
    fi

    _e105_prepare_dirs
    echo "$cw" > "$CONFIG_DIR/initcwnd.txt" 2>/dev/null || true
    echo "$rw" > "$CONFIG_DIR/initrwnd.txt" 2>/dev/null || true
    _e105_install_init_window_boot_restore "$cw" "$rw" || true

    clean=$(_e105_default_route_clean 2>/dev/null || true)
    if test -n "$clean"; then
        if ip route change $clean initcwnd "$cw" initrwnd "$rw" 2>/dev/null; then
            info "已设置默认路由 initcwnd=$cw initrwnd=$rw，并写入开机恢复。"
        else
            warn "运行态 route change 失败；已保留持久化，开机/网络重建后会再次尝试应用。"
        fi
    else
        warn "未检测到默认路由；已保留持久化，开机/网络重建后会尝试应用。"
    fi
    _e105_init_window_note "$mode" "$cw" "$rw" "e105 写入 initcwnd/initrwnd 持久化与开机恢复。"
    return 0
}

_e105_apply_init_window_default32() {
    title "V198e105：应用热更新默认 initcwnd/initrwnd = 32"
    _e88_set_init_window 32 32 "hotupdate-default32"
}

_e105_reset_init_window_to_system_default() {
    local clean
    clean=$(_e105_default_route_clean 2>/dev/null || true)
    if test -n "$clean"; then ip route change $clean 2>/dev/null || true; fi
    rm -f "$CONFIG_DIR/initcwnd.txt" "$CONFIG_DIR/initrwnd.txt" "$CONFIG_DIR/init_window_e105.txt" "${E88_INIT_WINDOW_STATE_FILE:-/dev/null}" 2>/dev/null || true
    systemctl disable --now xray-init-window-e105.service xray-init-window-e88.service >/dev/null 2>&1 || true
    rm -f /etc/systemd/system/xray-init-window-e105.service /usr/local/bin/xray-init-window-e105.sh /etc/systemd/system/xray-init-window-e88.service /usr/local/bin/xray-init-window-e88.sh 2>/dev/null || true
    systemctl daemon-reload >/dev/null 2>&1 || true
}

_e88_reset_init_window_default20() { _e105_apply_init_window_default32; _e88_show_init_window_state; }
_e88_reset_init_window_default21() { _e105_apply_init_window_default32; _e88_show_init_window_state; }
_e88_reset_init_window_default()  { _e105_apply_init_window_default32; _e88_show_init_window_state; }

_e88_show_init_window_state() {
    title "V198e105：TCP 起步窗口 initcwnd / initrwnd 当前状态"
    local route cw rw pcw prw
    route=$(ip route show default 2>/dev/null | head -n1 || true)
    cw=$(printf '%s\n' "$route" | sed -n 's/.*[[:space:]]initcwnd[[:space:]]\+\([0-9]\+\).*/\1/p')
    rw=$(printf '%s\n' "$route" | sed -n 's/.*[[:space:]]initrwnd[[:space:]]\+\([0-9]\+\).*/\1/p')
    pcw=$(cat "$CONFIG_DIR/initcwnd.txt" 2>/dev/null || true)
    prw=$(cat "$CONFIG_DIR/initrwnd.txt" 2>/dev/null || true)
    echo "  默认路由: ${route:-未发现}"
    echo "  当前 initcwnd: ${cw:-系统默认/未显式设置}"
    echo "  当前 initrwnd: ${rw:-系统默认/未显式设置}"
    echo "  持久化 initcwnd: ${pcw:-未记录}"
    echo "  持久化 initrwnd: ${prw:-未记录}"
    echo "  开机恢复服务: $(systemctl is-enabled xray-init-window-e105.service 2>/dev/null || echo disabled/unknown)"
    echo "  e105 记录文件: $CONFIG_DIR/init_window_e105.txt"
    test -f "$CONFIG_DIR/init_window_e105.txt" && sed 's/^/    /' "$CONFIG_DIR/init_window_e105.txt" || true
    echo ""
    echo "  e105 策略：--hot-update 默认写入 initcwnd/initrwnd=32；菜单 39 不再是 32 预设。"
}

_e88_manual_init_window() {
    title "V198e105：手动输入 initcwnd/initrwnd"
    _e88_show_init_window_state
    local cw rw
    echo ""
    read -rp "请输入 initcwnd（默认 32）: " cw || true
    cw=${cw:-32}
    read -rp "请输入 initrwnd（默认与 initcwnd 相同：$cw）: " rw || true
    rw=${rw:-$cw}
    _e88_set_init_window "$cw" "$rw" "manual"
}

_e105_auto_init_window_16_22() {
    title "V198e105：initcwnd/initrwnd 自动检测（16~22 保守封顶；热更新默认仍为32）"
    local rtt source retrans loss cw reason
    rtt=$(_e88_ss_rtt_avg_ms 2>/dev/null || true)
    source="ss -ti 活跃连接 RTT"
    if ! [[ "$rtt" =~ ^[0-9]+$ ]] || test "$rtt" -le 0 2>/dev/null; then
        rtt=$(_e88_ping_rtt_avg_ms 2>/dev/null || true)
        source="ping 1.1.1.1/8.8.8.8 平均 RTT"
    fi
    retrans=$(_e88_ss_retrans_count 2>/dev/null || echo 0)
    loss=$(_e88_ping_loss_percent 2>/dev/null || echo unknown)

    if ! [[ "$rtt" =~ ^[0-9]+$ ]] || test "$rtt" -le 0 2>/dev/null; then
        cw=20; reason="未取得可靠 RTT，回落到 20。"
    elif test "$rtt" -lt 80 2>/dev/null; then
        cw=16; reason="RTT<80ms，选择 16，减少起步突发。"
    elif test "$rtt" -lt 180 2>/dev/null; then
        cw=18; reason="RTT 80~179ms，选择 18。"
    else
        cw=22; reason="RTT>=180ms，自动档选择 22；32 仅作为热更新默认/手动实验。"
    fi
    if [[ "$retrans" =~ ^[0-9]+$ ]] && test "$retrans" -gt 0 2>/dev/null && test "$cw" -gt 18 2>/dev/null; then
        cw=18; reason="$reason 检测到 TCP retrans=$retrans，自动封顶到 18。"
    fi
    if [[ "$loss" =~ ^[0-9]+$ ]] && test "$loss" -ge 3 2>/dev/null && test "$cw" -gt 18 2>/dev/null; then
        cw=18; reason="$reason ping 丢包约 ${loss}%，自动封顶到 18。"
    fi
    echo "  检测来源: $source"
    echo "  RTT: ${rtt:-unknown} ms"
    echo "  ss retrans: ${retrans:-0}"
    echo "  ping loss: ${loss:-unknown}%"
    echo "  自动选择: initcwnd=$cw initrwnd=$cw"
    echo "  理由: $reason"
    echo ""
    _e88_set_init_window "$cw" "$cw" "auto16-22"
}
_e88_auto_init_window_16_32() { _e105_auto_init_window_16_22; }
_e103_auto_init_window_16_22() { _e105_auto_init_window_16_22; }

