do_update_core() {
    title "V198e105：Xray Core 手动更新 / 修复（仅手动，不设自动更新）"
    warn "e105 只关闭 Xray Core 自动更新；geoip/geosite dat 自动更新保持不动。"
    local go=""
    read -rp "是否现在手动更新/修复 Xray Core？[y/N]: " go || true
    if [[ ! "$go" =~ ^[yY]$ ]]; then
        info "已取消；Xray Core 不会自动更新。"
        _e105_disable_xray_core_auto_update || true
        _e52_pause
        return 0
    fi
    if declare -F do_update_core_e105_base >/dev/null 2>&1; then
        do_update_core_e105_base "$@"
    else
        error "未找到 Xray Core 更新基线函数。"
        return 1
    fi
    _e105_disable_xray_core_auto_update || true
    install_update_dat || true
}

hot_update_from_legacy() {
    title "V198e105：稳态热更新（默认 initcwnd/initrwnd=32 + 仅关闭 Core 自动更新）"
    if declare -F hot_update_from_legacy_e105_base >/dev/null 2>&1; then
        hot_update_from_legacy_e105_base "$@" || true
    fi
    _e105_prepare_dirs
    echo "198e105" > "$SCRIPT_VERSION_FILE" 2>/dev/null || true
    if test -f "${SCRIPT_PATH:-$0}"; then
        cp -f "${SCRIPT_PATH:-$0}" "$SYMLINK" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e105.sh" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
        chmod +x "$SYMLINK" "$SCRIPT_DIR/ex198e105.sh" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
    fi
    hash -r 2>/dev/null || true

    # 顺序很重要：先恢复 dat timer，再只清 Core 自动更新，最后强制写 initcwnd/initrwnd=32。
    install_update_dat || warn "geoip/geosite dat 自动更新器恢复未完全成功，请检查 systemctl status xray-dat-update.timer。"
    _e105_disable_xray_core_auto_update || true
    _e105_apply_init_window_default32 || warn "initcwnd/initrwnd=32 运行态应用未完全成功，已尽量写入持久化。"

    info "V198e105 热更新完成。"
    info "已按要求：--hot-update 默认设置 initcwnd/initrwnd=32，并写入开机恢复。"
    info "已按要求：菜单 13 不再提供 39) 设置32；39 为 16~22 自动检测，36 为应用热更新默认32。"
    info "已按要求：只关闭 Xray Core 自动更新；geoip/geosite dat 自动更新保留/恢复。"
}


#==============================================================================

#==============================================================================
# V198e111 FINAL CLEAN STABLE LAYER
# 目标：
#   1) 真正删除 e106/e107/e108/e109 新增的旧网络实验入口，不移动到菜单 13。
#   2) 主菜单回归 1-20/88；菜单 13 仍为历史网络参数菜单。
#   3) 热更新只做稳态动作：initcwnd/initrwnd=32、保留 dat 自动更新、只关闭 Xray Core 自动更新。
#   4) 静默清理旧 service / iptables chain / tc restore 脚本，避免旧层开机继续生效。
#   5) 清理前写入 e111 独立备份，不覆盖普通热更新备份目录。
#==============================================================================

E111_CLEAN_DIR="$CONFIG_DIR/e111_cleanup"
E111_CLEAN_BACKUP_DIR="$E111_CLEAN_DIR/backups"
E111_OBSOLETE_SERVICES="xray-pmtu-mss-e106.service xray-pmtu-mss-e107.service xray-mss-e108.service xray-shape-e108.service xray-mss-e109.service xray-shape-e109.service"
E111_OBSOLETE_CHAINS="XRAY_PMTU_E106 XRAY_PMTU_E107 XRAY_MSS_E108 XRAY_MSS_E109"

_e111_pause() { local _p=""; read -rp "按 Enter 继续..." _p || true; }

_e111_prepare_dirs() {
    mkdir -p "$CONFIG_DIR" "$SCRIPT_DIR" "$LOG_DIR" "$DAT_DIR" "$BACKUP_DIR" "$FLAGS_DIR" "$E111_CLEAN_BACKUP_DIR" 2>/dev/null || true
}

_e111_backup_obsolete_state() {
    _e111_prepare_dirs
    local ts dest
    ts="$(date +%Y%m%d_%H%M%S)"
    dest="$E111_CLEAN_BACKUP_DIR/preclean_${ts}"
    mkdir -p "$dest/files" 2>/dev/null || true

    {
        echo "created_at=$(date '+%F %T')"
        echo "script_version=198e111"
        echo "reason=${1:-manual}"
        echo "normal_hotupdate_backup_dir=$BACKUP_DIR"
    } > "$dest/meta.env" 2>/dev/null || true

    iptables-save > "$dest/iptables-save.txt" 2>/dev/null || true
    ip6tables-save > "$dest/ip6tables-save.txt" 2>/dev/null || true
    tc -s qdisc show > "$dest/tc-qdisc.txt" 2>/dev/null || true
    ip -details link show > "$dest/ip-link.txt" 2>/dev/null || true
    systemctl list-unit-files 'xray-*' --no-pager > "$dest/xray-unit-files.txt" 2>/dev/null || true
    systemctl list-timers --all --no-pager > "$dest/timers.txt" 2>/dev/null || true

    local f
    for f in \
        /etc/systemd/system/xray-pmtu-mss-e106.service \
        /etc/systemd/system/xray-pmtu-mss-e107.service \
        /etc/systemd/system/xray-mss-e108.service \
        /etc/systemd/system/xray-shape-e108.service \
        /etc/systemd/system/xray-mss-e109.service \
        /etc/systemd/system/xray-shape-e109.service \
        /usr/local/bin/xray-pmtu-mss-e106.sh \
        /usr/local/bin/xray-pmtu-mss-e107.sh \
        /usr/local/bin/xray-mss-e108.sh \
        /usr/local/bin/xray-shape-e108.sh \
        /usr/local/bin/xray-mss-e109.sh \
        /usr/local/bin/xray-shape-e109.sh \
        /etc/sysctl.d/99-xray-pmtu-e106.conf \
        /etc/sysctl.d/99-xray-pmtu-e107.conf \
        /etc/sysctl.d/99-auto-tune-relay-e108.conf \
        /etc/sysctl.d/99-auto-tune-relay-e108.profile.txt \
        /etc/sysctl.d/99-auto-tune-relay-e109.conf \
        /etc/sysctl.d/99-auto-tune-relay-e109.profile.txt
    do
        if test -e "$f"; then
            mkdir -p "$dest/files$(dirname "$f")" 2>/dev/null || true
            cp -a "$f" "$dest/files$f" 2>/dev/null || true
        fi
    done

    for f in \
        "$CONFIG_DIR/pmtu_e106" \
        "$CONFIG_DIR/pmtu_e107" \
        "$CONFIG_DIR/netdiag_e108" \
        "$CONFIG_DIR/netdiag_e109"
    do
        if test -e "$f"; then
            tar -C "$(dirname "$f")" -czf "$dest/$(basename "$f").tgz" "$(basename "$f")" 2>/dev/null || true
        fi
    done

    echo "$dest" > "$E111_CLEAN_DIR/latest_backup.txt" 2>/dev/null || true
    info "e111 清理前快照已保存：$dest"
}

_e111_first_iptables() {
    if command -v iptables >/dev/null 2>&1; then echo iptables; return 0; fi
    if command -v iptables-legacy >/dev/null 2>&1; then echo iptables-legacy; return 0; fi
    if command -v iptables-nft >/dev/null 2>&1; then echo iptables-nft; return 0; fi
    return 1
}

_e111_cleanup_chain_with_tool() {
    local tool="$1" chain="$2" hook
    command -v "$tool" >/dev/null 2>&1 || return 0
    "$tool" -t mangle -S "$chain" >/dev/null 2>&1 || return 0
    for hook in OUTPUT POSTROUTING PREROUTING FORWARD INPUT; do
        while "$tool" -t mangle -D "$hook" -j "$chain" >/dev/null 2>&1; do :; done
    done
    "$tool" -t mangle -F "$chain" >/dev/null 2>&1 || true
    "$tool" -t mangle -X "$chain" >/dev/null 2>&1 || true
}

_e111_cleanup_obsolete_network_layers() {
    _e111_prepare_dirs
    local s c iface statefile
    _e111_backup_obsolete_state "${1:-cleanup-obsolete-network-layers}"

    for s in $E111_OBSOLETE_SERVICES; do
        systemctl disable --now "$s" >/dev/null 2>&1 || true
    done

    # 如果旧 shaping 状态曾经写入，清理对应 root qdisc，避免旧限速继续接管出口。
    for statefile in "$CONFIG_DIR/netdiag_e108/shaping_state.env" "$CONFIG_DIR/netdiag_e109/shaping_state.env"; do
        iface=""
        if test -s "$statefile"; then
            # shellcheck disable=SC1090
            . "$statefile" 2>/dev/null || true
            iface="${IFACE:-}"
            if test -n "$iface"; then tc qdisc del dev "$iface" root >/dev/null 2>&1 || true; fi
        fi
    done

    for c in $E111_OBSOLETE_CHAINS; do
        _e111_cleanup_chain_with_tool "$(_e111_first_iptables 2>/dev/null || echo iptables)" "$c"
        _e111_cleanup_chain_with_tool ip6tables "$c"
        _e111_cleanup_chain_with_tool ip6tables-legacy "$c"
        _e111_cleanup_chain_with_tool ip6tables-nft "$c"
    done

    rm -f \
        /etc/systemd/system/xray-pmtu-mss-e106.service \
        /etc/systemd/system/xray-pmtu-mss-e107.service \
        /etc/systemd/system/xray-mss-e108.service \
        /etc/systemd/system/xray-shape-e108.service \
        /etc/systemd/system/xray-mss-e109.service \
        /etc/systemd/system/xray-shape-e109.service \
        /usr/local/bin/xray-pmtu-mss-e106.sh \
        /usr/local/bin/xray-pmtu-mss-e107.sh \
        /usr/local/bin/xray-mss-e108.sh \
        /usr/local/bin/xray-shape-e108.sh \
        /usr/local/bin/xray-mss-e109.sh \
        /usr/local/bin/xray-shape-e109.sh \
        /etc/sysctl.d/99-xray-pmtu-e106.conf \
        /etc/sysctl.d/99-xray-pmtu-e107.conf \
        /etc/sysctl.d/99-auto-tune-relay-e108.conf \
        /etc/sysctl.d/99-auto-tune-relay-e108.profile.txt \
        /etc/sysctl.d/99-auto-tune-relay-e109.conf \
        /etc/sysctl.d/99-auto-tune-relay-e109.profile.txt \
        2>/dev/null || true

    rm -rf \
        "$CONFIG_DIR/pmtu_e106" \
        "$CONFIG_DIR/pmtu_e107" \
        "$CONFIG_DIR/netdiag_e108" \
        "$CONFIG_DIR/netdiag_e109" \
        2>/dev/null || true

    systemctl daemon-reload >/dev/null 2>&1 || true
    info "e111 已静默清理旧网络实验层残留；主菜单不再提供这些功能入口。"
}

_e111_show_cleanup_state() {
    title "V198e111：旧网络实验层残留检查"
    echo "服务残留："
    local s c found=0
    for s in $E111_OBSOLETE_SERVICES; do
        if systemctl list-unit-files "$s" --no-pager 2>/dev/null | grep -q "$s"; then
            echo "  $s : present"
            found=1
        fi
    done
    if test "$found" -eq 0; then echo "  未发现旧 service。"; fi

    echo
    echo "iptables mangle 链残留："
    found=0
    for c in $E111_OBSOLETE_CHAINS; do
        if iptables -t mangle -S "$c" >/dev/null 2>&1; then
            echo "  $c : present"
            found=1
        fi
    done
    if test "$found" -eq 0; then echo "  未发现旧链。"; fi

    echo
    echo "目录残留："
    found=0
    for d in "$CONFIG_DIR/pmtu_e106" "$CONFIG_DIR/pmtu_e107" "$CONFIG_DIR/netdiag_e108" "$CONFIG_DIR/netdiag_e109"; do
        if test -e "$d"; then echo "  $d"; found=1; fi
    done
    if test "$found" -eq 0; then echo "  未发现旧目录。"; fi

    echo
    echo "最近 e111 清理备份：$(cat "$E111_CLEAN_DIR/latest_backup.txt" 2>/dev/null || echo none)"
}

main_menu() {
    while true; do
        clear
        SERVER_IP=$(_get_ip)
        echo -e "${magenta}======================================================================${none}"
        echo -e "  ${cyan}Xray System Advanced Management V198e111 - 稳态精简热更新版${none}"
        echo -e "  ${green}引擎态势:${none} $(systemctl is-active xray 2>/dev/null || echo unknown) | ${cyan}快捷指令:${none} xrv | ${cyan}外部识别 IP:${none} ${SERVER_IP:-unknown}"
        echo -e "${magenta}======================================================================${none}"
        echo "  1) 安装 / 重装三协议节点：VLESS Reality + VLESSENC + SS2022"
        echo "  2) 用户凭证生命周期与独立参数化管理控制"
        echo "  3) 节点链接与多维信息输出聚合中心"
        echo "  4) 人工发起数据强联，执行路由解析规则库强制覆盖更新"
        echo "  5) Xray Core 手动更新/修复（不设置自动更新）"
        echo "  6) 修改或全自动剔除被拦截的防封伪装特征矩阵域名"
        echo "  7) 系统防火墙策略配置 (阻止内网 BT 滥用及第三方广告请求)"
        echo "  8 ) Reality Fallback 底层限速沙盒分析器"
        echo "  9) 全景网络连接审计日志与商用级别网络流量记账本"
        echo "  10) 高级发烧：内核双轨编译(APT/源码)/网络/应用层 60余项极限全控板"
        echo -e "  ${green}11) 从旧 ex198e 环境稳态热更新到 V198e111${none}"
        echo -e "  ${cyan}12) 清理空间（安全释放 / 快照收敛 / 显示硬盘与 Swap）${none}"
        echo -e "  ${cyan}13) 应用网络参数（历史稳态菜单：缓冲/notsent/adv_win/app_win/txqueue 等）${none}"
        echo -e "  ${cyan}14) TCP 重传 / 单连接诊断中心（只读排障）${none}"
        echo -e "  ${cyan}15) 检查现有配置并重新输出节点${none}"
        echo -e "  ${cyan}16) 状态隔离审计 + VLESSENC 能力检查${none}"
        echo -e "  ${magenta}17) BBR 本体替换 / 自定义编译中心（真BBRv3源码/补丁1000MB门槛）${none}"
        echo -e "  ${cyan}18) 安全审计 / Top20复测 / 启动防砖中心${none}"
        echo -e "  ${cyan}19) Xray 跨境链路速度诊断中心${none}"
        echo -e "  ${cyan}20) TC 带宽控制模块（统一接管/精细上限/默认不启用）${none}"
        echo -e "  ${red}88) 物理不可逆自毁！撤销环境安全防线与系统配置设定${none}"
        echo "  0) 退出"
        hr
        local num=""
        read -rp "请输入操作代码指令: " num || true
        case "${num:-}" in
            1) do_install ;;
            2) do_user_manager ;;
            3) do_summary; while true; do local rb=""; read -rp "输出完毕，按 Enter 退出或者按 b 发起特征替换: " rb || true; if test "$rb" = "b" || test "$rb" = "B"; then if choose_sni; then _update_matrix; do_summary; else break; fi; else break; fi; done ;;
            4) print_magenta ">>> 初始化云网络联通."; bash "$UPDATE_DAT_SCRIPT" >/dev/null 2>&1 || true; ensure_xray_is_alive; info "配置已穿透替换系统！当前路由库完成热加载！"; _e111_pause ;;
            5) do_update_core ;;
            6) if choose_sni; then _update_matrix; do_summary; while true; do local rb=""; read -rp "任务完毕，按 Enter 返回，或按 b 连续变更: " rb || true; if test "$rb" = "b" || test "$rb" = "B"; then if choose_sni; then _update_matrix; do_summary; else break; fi; else break; fi; done; fi ;;
            7) _global_block_rules ;;
            8) do_fallback_probe ;;
            9) do_status_menu ;;
            10) do_sys_init_menu ;;
            11) hot_update_from_legacy ;;
            12) do_space_cleanup_menu ;;
            13) do_network_params_menu_e56 ;;
            14) do_tcp_diag_menu_e63 ;;
            15) do_install_repair_e77 ;;
            16) e77_audit_runtime_state; _e111_pause ;;
            17) do_bbr_body_replace_menu_e89 ;;
            18) do_e92_audit_center ;;
            19) do_xray_speed_diag_menu_e94 ;;
            20) do_tc_bandwidth_menu_e94 ;;
            88) do_uninstall ;;
            0) exit 0 ;;
            *) echo -e "${red}错误拦截：代码解析为空值！${none}"; sleep 1 ;;
        esac
    done
}

hot_update_from_legacy() {
    title "V198e111：稳态精简热更新"
    _e111_prepare_dirs

    echo "198e111" > "$SCRIPT_VERSION_FILE" 2>/dev/null || true

    if test -f "${SCRIPT_PATH:-$0}"; then
        cp -f "${SCRIPT_PATH:-$0}" "$SYMLINK" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e111.sh" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
        chmod +x "$SYMLINK" "$SCRIPT_DIR/ex198e111.sh" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
    fi
    hash -r 2>/dev/null || true

    install_update_dat || warn "geoip/geosite dat 自动更新器恢复未完全成功，请检查 xray-dat-update.timer。"
    if declare -F _e105_disable_xray_core_auto_update >/dev/null 2>&1; then
        _e105_disable_xray_core_auto_update || true
    fi
    if declare -F _e105_install_init_window_boot_restore >/dev/null 2>&1; then
        _e105_install_init_window_boot_restore || true
    fi
    if declare -F _e105_apply_init_window_default32 >/dev/null 2>&1; then
        _e105_apply_init_window_default32 || warn "initcwnd/initrwnd=32 应用未完全成功。"
    fi

    _e111_cleanup_obsolete_network_layers "hot-update-e111-remove-obsolete-layers" || true
    echo "198e111" > "$SCRIPT_VERSION_FILE" 2>/dev/null || true

    info "V198e111 热更新完成。"
    info "已删除 e106/e107/e108/e109 新增的旧网络实验功能入口；不移动到菜单 13。"
    info "已保留：主菜单 1-20/88、历史菜单 13、initcwnd/initrwnd=32、dat 自动更新。"
    info "已执行：只关闭 Xray Core 自动更新，不关闭 geoip/geosite dat 自动更新。"
    info "e111 清理备份目录：$E111_CLEAN_BACKUP_DIR；不会替换普通热更新备份：$BACKUP_DIR。"
}



#==============================================================================
# V198e117 FINAL STABLE PATCH LAYER
# 设计原则：不再乱砍主体。以 e111 完整脚本为基线，仅覆盖损坏入口：
# 1) 菜单1建仓：显式选择 Reality / Reality+SS / VLESSENC / SS，并强制校验 Reality。
# 2) 菜单2用户管理：没有 Reality 时不再进入无效管理，提示重建 Reality。
# 3) 菜单3输出：明确区分 Reality 与非 Reality，避免误拼链接。
# 4) 热更新：默认 initcwnd/initrwnd=30；保留 dat 自动更新；轻量 SSH 防爆破/端口自愈。
#==============================================================================

# 保存 e111/e79 主体原函数，后续覆盖只做薄层修复。
if declare -F do_install >/dev/null 2>&1; then eval "$(declare -f do_install | sed '1s/do_install/do_install_e116_base/')" 2>/dev/null || true; fi
if declare -F do_summary >/dev/null 2>&1; then eval "$(declare -f do_summary | sed '1s/do_summary/do_summary_e116_base/')" 2>/dev/null || true; fi
if declare -F do_user_manager >/dev/null 2>&1; then eval "$(declare -f do_user_manager | sed '1s/do_user_manager/do_user_manager_e116_base/')" 2>/dev/null || true; fi
if declare -F hot_update_from_legacy >/dev/null 2>&1; then eval "$(declare -f hot_update_from_legacy | sed '1s/hot_update_from_legacy/hot_update_from_legacy_e116_base/')" 2>/dev/null || true; fi
if declare -F do_network_params_menu_e56 >/dev/null 2>&1; then eval "$(declare -f do_network_params_menu_e56 | sed '1s/do_network_params_menu_e56/do_network_params_menu_e116_base/')" 2>/dev/null || true; fi

readonly E116_DIR="$CONFIG_DIR/e116_stable_fix"
readonly E116_BACKUP_DIR="$E116_DIR/backups"
readonly E116_STATE_FILE="$E116_DIR/state.env"
readonly E116_SSH_PORT_GUARD_SCRIPT="/usr/local/bin/xray-ssh-port-guard-e116.sh"
readonly E116_SSH_PORT_GUARD_SERVICE="/etc/systemd/system/xray-ssh-port-guard-e116.service"
readonly E116_F2B_JAIL="/etc/fail2ban/jail.d/99-xray-sshguard-e116.conf"
readonly E116_F2B_DB_CONF="/etc/fail2ban/fail2ban.d/99-xray-e116-persistence.conf"
readonly E116_F2B_JAIL_NAME="xray-sshd-e116"
readonly E116_FINDTIME="86400"
readonly E116_BANTIME="129600"
readonly E116_MAXRETRY="2"

_e116_pause() { local _p=""; read -rp "按 Enter 继续..." _p || true; }
_e116_prepare_dirs() { mkdir -p "$E116_DIR" "$E116_BACKUP_DIR" "$CONFIG_DIR" "$SCRIPT_DIR" "$BACKUP_DIR" 2>/dev/null || true; }

_e116_backup_state() {
    _e116_prepare_dirs
    local tag="${1:-manual}" ts bdir
    ts="$(date +%Y%m%d_%H%M%S 2>/dev/null || echo now)"
    bdir="$E116_BACKUP_DIR/${tag}_${ts}"
    mkdir -p "$bdir" 2>/dev/null || true
    cp -a "$CONFIG" "$bdir/config.json" 2>/dev/null || true
    cp -a "$PUBKEY_FILE" "$bdir/public.key" 2>/dev/null || true
    cp -a "$USER_SNI_MAP" "$bdir/user_sni.txt" 2>/dev/null || true
    cp -a "$USER_TIME_MAP" "$bdir/user_time.txt" 2>/dev/null || true
    cp -a /etc/fail2ban "$bdir/fail2ban" 2>/dev/null || true
    iptables-save > "$bdir/iptables-save.txt" 2>/dev/null || true
    ip6tables-save > "$bdir/ip6tables-save.txt" 2>/dev/null || true
    echo "$bdir" > "$E116_DIR/latest_backup.txt" 2>/dev/null || true
    echo "$bdir"
}

_e116_restore_config_backup() {
    local bdir="${1:-}"
    test -n "$bdir" || bdir="$(cat "$E116_DIR/latest_backup.txt" 2>/dev/null || true)"
    if test -n "$bdir" && test -s "$bdir/config.json"; then
        cp -f "$bdir/config.json" "$CONFIG" 2>/dev/null || true
        test -s "$bdir/public.key" && cp -f "$bdir/public.key" "$PUBKEY_FILE" 2>/dev/null || true
        fix_permissions || true
        systemctl restart xray >/dev/null 2>&1 || true
        warn "已回滚到 e116 备份：$bdir"
        return 0
    fi
    return 1
}

_e116_config_has_reality_file() {
    local f="${1:-$CONFIG}"
    test -s "$f" || return 1
    jq -e '
      .inbounds[]?
      | select(.protocol=="vless")
      | select((.streamSettings.security // "") == "reality")
      | select(((.streamSettings.realitySettings.privateKey // "")|length) > 10)
      | select(((.streamSettings.realitySettings.serverNames // [])|length) >= 1)
      | select(((.streamSettings.realitySettings.shortIds // [])|length) >= 1)
      | select(((.settings.clients // .settings.users // [])|length) >= 1)
    ' "$f" >/dev/null 2>&1
}

_e116_show_config_brief() {
    title "V198e117：当前 Xray 配置摘要"
    if test ! -s "$CONFIG"; then warn "config.json 不存在。"; return 1; fi
    if ! jq empty "$CONFIG" >/dev/null 2>&1; then error "config.json 不是合法 JSON。"; return 1; fi
    jq -r '
      .inbounds[]? | [(.tag//"-"),(.protocol//"-"),(.port|tostring),(.streamSettings.security//"none"),((.settings.clients//.settings.users//[])|length|tostring)] | @tsv
    ' "$CONFIG" 2>/dev/null | awk 'BEGIN{printf "  %-24s %-14s %-8s %-12s %-8s\n","tag","protocol","port","security","clients"; print "  ----------------------------------------------------------------"} {printf "  %-24s %-14s %-8s %-12s %-8s\n",$1,$2,$3,$4,$5}' || true
}

_e116_validate_generated_config() {
    local f="$1" mode="$2"
    if ! jq empty "$f" >/dev/null 2>&1; then error "生成配置 JSON 语法不合法。"; return 1; fi
    case "$mode" in
        1|4)
            if ! _e116_config_has_reality_file "$f"; then
                error "选择了 Reality 模式，但生成结果没有 streamSettings.security=reality。已拒绝提交。"
                jq -r '.inbounds[]? | "tag=\(.tag//"-") protocol=\(.protocol//"-") port=\(.port) security=\(.streamSettings.security//"none")"' "$f" 2>/dev/null | sed 's/^/    /' || true
                return 1
            fi
            ;;
    esac
    if command -v "$XRAY_BIN" >/dev/null 2>&1; then
        if ! "$XRAY_BIN" test -config "$f" >/tmp/xray-e116-test.log 2>&1; then
            error "Xray 静态配置测试未通过，拒绝提交。"
            sed 's/^/    /' /tmp/xray-e116-test.log 2>/dev/null || true
            return 1
        fi
    fi
    return 0
}

_e116_install_mode() {
    local mode="$1" label="$2"
    title "V198e117：${label} 建仓（保留完整主体 + 强制提交前校验）"
    preflight
    _e116_prepare_dirs
    local bdir; bdir="$(_e116_backup_state "before_install_mode_${mode}")"
    e77_install_self_entrypoint >/dev/null 2>&1 || true
    e76_state_snapshot "before_install_e116_mode_${mode}" >/dev/null 2>&1 || true

    systemctl stop xray >/dev/null 2>&1 || true
    if test ! -f "$INSTALL_DATE_FILE"; then date +"%Y-%m-%d %H:%M:%S" > "$INSTALL_DATE_FILE"; fi

    local reality_port=443 enc_port=443 ss_port=8388 ss_pass="" ss_method="2022-blake3-aes-128-gcm"
    E79_VLESSENC_PROFILE="balanced"; E79_VLESSENC_PROFILE_NAME="均衡模式"; E79_VLESSENC_NETWORK="tcp"; E79_VLESSENC_XHTTP_PATH=""; E79_VLESSENC_REQUESTED_TUNING="default"; E79_VLESSENC_ACTUAL_TUNING="default"

    if test "$mode" = "1" || test "$mode" = "4"; then
        LISTEN_PORT=$(e77_pick_free_port 443 "分配 Reality VLESS 监听端口 (回车默认 443): ")
        reality_port="$LISTEN_PORT"
        local input_remark=""
        read -rp "规划节点基础标识名 (默认 xp-reality): " input_remark || true
        REMARK_NAME=${input_remark:-xp-reality}
        choose_sni || { warn "SNI 选择中止，原配置不变。"; return 0; }
    fi
    if test "$mode" = "2"; then
        if declare -F e79_select_vlessenc_profile >/dev/null 2>&1; then e79_select_vlessenc_profile; fi
        enc_port=$(e77_pick_free_port 443 "分配 VLESSENC 监听端口 (回车默认 443): ")
        local input_remark=""
        read -rp "配置 VLESSENC 标识 (默认 xp-vlessenc): " input_remark || true
        REMARK_NAME=${input_remark:-xp-vlessenc}
    fi
    if test "$mode" = "3" || test "$mode" = "4"; then
        ss_port=$(e77_pick_free_port 8388 "分配 SS2022 端口 (默认 8388): ")
        ss_method=$(e77_select_ss2022_method)
        ss_pass=$(e77_gen_ss2022_pass "$ss_method")
        if test "$mode" = "3"; then
            local input_remark=""
            read -rp "配置 SS2022 标识 (默认 xp-ss2022): " input_remark || true
            REMARK_NAME=${input_remark:-xp-ss2022}
        fi
    fi

    e76_install_or_update_xray_core || { error "Xray Core 安装/更新失败，原配置保留。"; return 1; }
    e76_ensure_xray_service || true
    install_update_dat || warn "DAT 定时更新器安装未完全成功，继续。"
    fix_xray_systemd_limits || true
    remove_xray_env_buffer || true

    local tmp_config
    tmp_config=$(mktemp /tmp/xray.e116.install.XXXXXX.json) || return 1
    if ! e79_build_full_config "$mode" "$reality_port" "$enc_port" "$ss_port" "$ss_method" "$ss_pass" "$tmp_config"; then
        rm -f "$tmp_config" 2>/dev/null || true
        error "配置生成失败，原配置不变。"
        return 1
    fi
    if ! _e116_validate_generated_config "$tmp_config" "$mode"; then
        rm -f "$tmp_config" 2>/dev/null || true
        warn "e116 已阻止错误配置覆盖当前运行配置。"
        return 1
    fi

    if ! e79_commit_generated_state "$mode" "$tmp_config"; then
        # VLESSENC 强参数失败时允许沿用 e79 的回退逻辑。
        if test "$mode" = "2" && { test "${E79_VLESSENC_PROFILE:-}" = "speed" || test "${E79_VLESSENC_PROFILE:-}" = "strong"; }; then
            warn "VLESSENC 候选参数未通过当前 Xray 校验，回退均衡默认。"
            rm -f "$tmp_config" 2>/dev/null || true
            E79_VLESSENC_PROFILE="balanced"; E79_VLESSENC_PROFILE_NAME="均衡模式（由失败回退）"; E79_VLESSENC_NETWORK="tcp"; E79_VLESSENC_XHTTP_PATH=""; E79_VLESSENC_REQUESTED_TUNING="fallback-default"
            tmp_config=$(mktemp /tmp/xray.e116.install.fallback.XXXXXX.json) || return 1
            e79_build_full_config "$mode" "$reality_port" "$enc_port" "$ss_port" "$ss_method" "$ss_pass" "$tmp_config" || { rm -f "$tmp_config"; error "回退配置生成失败。"; return 1; }
            _e116_validate_generated_config "$tmp_config" "$mode" || { rm -f "$tmp_config"; error "回退配置校验失败。"; return 1; }
            e79_commit_generated_state "$mode" "$tmp_config" || { rm -f "$tmp_config"; error "回退配置仍未通过提交，原配置保留。"; return 1; }
        else
            rm -f "$tmp_config" 2>/dev/null || true
            error "配置提交失败，原配置保留。"
            return 1
        fi
    fi
    rm -f "$tmp_config" 2>/dev/null || true

    if test "$mode" = "1" || test "$mode" = "4"; then
        if ! _e116_config_has_reality_file "$CONFIG"; then
            error "提交后复检失败：当前 config.json 仍不是 Reality。立即回滚。"
            _e116_restore_config_backup "$bdir" || true
            return 1
        fi
    fi

    force_apply_xray_core_defaults_e52 >/dev/null 2>&1 || true
    harden_xray_reality_profile >/dev/null 2>&1 || true
    apply_process_priority_default >/dev/null 2>&1 || true
    apply_hotupdate_fast_sysctl >/dev/null 2>&1 || true
    remove_origin_guard auto >/dev/null 2>&1 || true

    systemctl enable xray >/dev/null 2>&1 || true
    if ! ensure_xray_is_alive; then
        error "Xray 启动失败，正在回滚到建仓前配置。"
        _e116_restore_config_backup "$bdir" || true
        return 1
    fi

    echo "198e117" > "$SCRIPT_VERSION_FILE" 2>/dev/null || true
    { echo "time=$(date '+%F %T' 2>/dev/null || true)"; echo "mode=$mode"; echo "label=$label"; echo "has_reality=$(_e116_config_has_reality_file "$CONFIG" && echo yes || echo no)"; } > "$E116_STATE_FILE" 2>/dev/null || true
    info "建仓完成并通过 e116 复检。"
    do_summary || true
    finalize
    return 0
}

do_install() {
    while true; do
        clear
        title "V198e117：安装 / 重装节点（不乱砍完整主体，Reality 默认强校验）"
        echo "  1) VLESS Reality Vision              ${cyan}(默认推荐；必须生成 security=reality)${none}"
        echo "  2) Reality Vision + SS2022            ${cyan}(主通道 + 备用通道)${none}"
        echo "  3) VLESSENC Vision 自选               ${yellow}(实验项；生成 security=none 属于正常)${none}"
        echo "  4) SS2022                             ${cyan}(轻量备用)${none}"
        echo "  9) 进入历史 e79/e111 原始建仓入口       ${yellow}(兼容旧逻辑)${none}"
        echo "  0) 返回主菜单"
        hr
        local sel=""
        read -rp "请输入编号 (回车默认 1=Reality): " sel || true
        sel=${sel:-1}
        case "$sel" in
            1) _e116_install_mode 1 "VLESS Reality Vision"; _e116_pause; return 0 ;;
            2) _e116_install_mode 4 "Reality Vision + SS2022"; _e116_pause; return 0 ;;
            3) _e116_install_mode 2 "VLESSENC Vision 自选"; _e116_pause; return 0 ;;
            4) _e116_install_mode 3 "SS2022"; _e116_pause; return 0 ;;
            9) if declare -F do_install_e116_base >/dev/null 2>&1; then do_install_e116_base || warn "历史建仓入口返回失败。"; else error "历史 do_install 不存在。"; fi; _e116_pause; return 0 ;;
            0) return 0 ;;
            *) warn "无效选择。"; sleep 1 ;;
        esac
    done
}

do_user_manager() {
    if ! _e116_config_has_reality_file "$CONFIG"; then
        title "V198e117：账户管理前置检查"
        warn "当前没有 Reality VLESS 入站；账户生命周期管理只适用于 Reality。"
        _e116_show_config_brief || true
        echo
        echo "  1) 立即重建 VLESS Reality Vision"
        echo "  2) 进入历史用户管理器（不推荐，仅兼容旧配置）"
        echo "  0) 返回主菜单"
        local sel=""
        read -rp "请选择: " sel || true
        case "${sel:-}" in
            1) _e116_install_mode 1 "VLESS Reality Vision"; _e116_pause ;;
            2) if declare -F do_user_manager_e116_base >/dev/null 2>&1; then do_user_manager_e116_base || true; else warn "历史用户管理器不存在。"; _e116_pause; fi ;;
            *) return 0 ;;
        esac
        return 0
    fi
    if declare -F do_user_manager_e116_base >/dev/null 2>&1; then
        do_user_manager_e116_base || { warn "历史用户管理器返回失败，已拦截整脚本退出。"; _e116_pause; return 0; }
    else
        error "历史用户管理函数不存在。"
        _e116_pause
    fi
}

do_summary() {
    if test ! -s "$CONFIG"; then error "config.json 不存在，请先进入菜单 1 建仓。"; return 1; fi
    if ! jq empty "$CONFIG" >/dev/null 2>&1; then error "config.json 非法，请先修复或重建。"; return 1; fi
    if ! _e116_config_has_reality_file "$CONFIG"; then
        title "Xray 配置网络及授权明细（V198e117安全输出）"
        _e116_show_config_brief || true
        if jq -e '.inbounds[]? | select(.protocol=="vless") | select((.streamSettings.security//"none") != "reality")' "$CONFIG" >/dev/null 2>&1; then
            warn "检测到 VLESS 非 Reality 入站。若你本来想创建 Reality，请进入：菜单 1 → 1。"
            warn "VLESSENC 的 security=none 是实验协议正常表现；普通 VLESS security=none 不能当 Reality 输出。"
        fi
        echo
        if declare -F do_summary_e116_base >/dev/null 2>&1; then do_summary_e116_base || true; fi
        return 0
    fi
    if declare -F do_summary_e116_base >/dev/null 2>&1; then
        do_summary_e116_base || true
    else
        _e116_show_config_brief || true
    fi
}

_e116_apply_init_window_default30() {
    _e116_prepare_dirs
    echo 30 > "$CONFIG_DIR/initcwnd.txt" 2>/dev/null || true
    echo 30 > "$CONFIG_DIR/initrwnd.txt" 2>/dev/null || true
    local route clean
    route="$(ip route show default 2>/dev/null | head -n1 || true)"
    clean="$(printf '%s\n' "$route" | sed 's/[[:space:]]\+initcwnd[[:space:]]\+[0-9]\+//g; s/[[:space:]]\+initrwnd[[:space:]]\+[0-9]\+//g')"
    test -n "$clean" && ip route replace $clean initcwnd 30 initrwnd 30 >/dev/null 2>&1 || true
    if declare -F _e105_install_init_window_boot_restore >/dev/null 2>&1; then _e105_install_init_window_boot_restore || true; fi
    { echo "time=$(date '+%F %T' 2>/dev/null || true)"; echo "mode=e116_default30"; echo "initcwnd=30"; echo "initrwnd=30"; echo "route=$(ip route show default 2>/dev/null | head -n1 || true)"; } > "$CONFIG_DIR/init_window_e116.txt" 2>/dev/null || true
    info "e116：initcwnd/initrwnd 默认值已设置为 30。"
}

_e116_detect_ssh_ports() {
    local ports=""
    if command -v sshd >/dev/null 2>&1; then ports="$ports $(sshd -T 2>/dev/null | awk '/^port /{print $2}')"; fi
    ports="$ports $(grep -hEi '^[[:space:]]*Port[[:space:]]+[0-9]+' /etc/ssh/sshd_config /etc/ssh/sshd_config.d/*.conf 2>/dev/null | awk '{print $2}')"
    ports="$ports $(ss -H -ltnp 2>/dev/null | awk '/sshd/ {gsub(/.*:/,"",$4); if($4 ~ /^[0-9]+$/) print $4}')"
    printf '%s\n' $ports 2>/dev/null | awk '$1 ~ /^[0-9]+$/ && $1>=1 && $1<=65535 {print $1}' | sort -n -u
}

_e116_write_ssh_port_guard() {
    _e116_prepare_dirs
    cat > "$E116_SSH_PORT_GUARD_SCRIPT" <<'EOF_E116_SSH_PORT_GUARD'
#!/usr/bin/env bash
set +e
export PATH="/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin"
detect_ports() {
    local ports=""
    if command -v sshd >/dev/null 2>&1; then ports="$ports $(sshd -T 2>/dev/null | awk '/^port /{print $2}')"; fi
    ports="$ports $(grep -hEi '^[[:space:]]*Port[[:space:]]+[0-9]+' /etc/ssh/sshd_config /etc/ssh/sshd_config.d/*.conf 2>/dev/null | awk '{print $2}')"
    ports="$ports $(ss -H -ltnp 2>/dev/null | awk '/sshd/ {gsub(/.*:/,"",$4); if($4 ~ /^[0-9]+$/) print $4}')"
    printf '%s\n' $ports 2>/dev/null | awk '$1 ~ /^[0-9]+$/ && $1>=1 && $1<=65535 {print $1}' | sort -n -u
}
ports="$(detect_ports)"
[ -n "$ports" ] || ports="22"
for p in $ports; do
    if command -v ufw >/dev/null 2>&1 && ufw status 2>/dev/null | grep -qi active; then ufw allow "$p/tcp" >/dev/null 2>&1 || true; fi
    if command -v firewall-cmd >/dev/null 2>&1 && systemctl is-active --quiet firewalld 2>/dev/null; then firewall-cmd --permanent --add-port="${p}/tcp" >/dev/null 2>&1 || true; firewall-cmd --reload >/dev/null 2>&1 || true; fi
    if command -v iptables >/dev/null 2>&1; then iptables -C INPUT -p tcp --dport "$p" -j ACCEPT >/dev/null 2>&1 || iptables -I INPUT 1 -p tcp --dport "$p" -j ACCEPT >/dev/null 2>&1 || true; fi
    if command -v ip6tables >/dev/null 2>&1; then ip6tables -C INPUT -p tcp --dport "$p" -j ACCEPT >/dev/null 2>&1 || ip6tables -I INPUT 1 -p tcp --dport "$p" -j ACCEPT >/dev/null 2>&1 || true; fi
done
exit 0
EOF_E116_SSH_PORT_GUARD
    chmod +x "$E116_SSH_PORT_GUARD_SCRIPT" 2>/dev/null || true
    cat > "$E116_SSH_PORT_GUARD_SERVICE" <<EOF_E116_SSH_PORT_GUARD_SERVICE
[Unit]
Description=Xray e116 SSH port firewall self-healing guard
After=network-online.target ssh.service sshd.service
Wants=network-online.target

[Service]
Type=oneshot
ExecStart=$E116_SSH_PORT_GUARD_SCRIPT
RemainAfterExit=yes

[Install]
WantedBy=multi-user.target
EOF_E116_SSH_PORT_GUARD_SERVICE
    systemctl daemon-reload >/dev/null 2>&1 || true
    systemctl enable --now xray-ssh-port-guard-e116.service >/dev/null 2>&1 || true
    "$E116_SSH_PORT_GUARD_SCRIPT" >/dev/null 2>&1 || true
}

_e116_install_fail2ban_guard() {
    if ! command -v fail2ban-client >/dev/null 2>&1; then
        if command -v apt-get >/dev/null 2>&1; then DEBIAN_FRONTEND=noninteractive apt-get update -y >/dev/null 2>&1 || true; DEBIAN_FRONTEND=noninteractive apt-get install -y fail2ban >/dev/null 2>&1 || true; fi
        if command -v yum >/dev/null 2>&1; then yum install -y fail2ban >/dev/null 2>&1 || true; fi
    fi
    command -v fail2ban-client >/dev/null 2>&1 || { warn "fail2ban 未安装成功，跳过 SSH 失败封禁；端口自愈仍保留。"; return 0; }
    mkdir -p /etc/fail2ban/jail.d /etc/fail2ban/fail2ban.d /var/lib/fail2ban 2>/dev/null || true
    cat > "$E116_F2B_DB_CONF" <<'EOF_E116_F2B_DB'
[Definition]
dbfile = /var/lib/fail2ban/fail2ban.sqlite3
dbpurgeage = 3d
EOF_E116_F2B_DB
    cat > "$E116_F2B_JAIL" <<EOF_E116_F2B_JAIL
[$E116_F2B_JAIL_NAME]
enabled = true
filter = sshd
backend = systemd
journalmatch = _SYSTEMD_UNIT=ssh.service + _SYSTEMD_UNIT=sshd.service
maxretry = $E116_MAXRETRY
findtime = $E116_FINDTIME
bantime = $E116_BANTIME
banaction = iptables-allports
EOF_E116_F2B_JAIL
    fail2ban-client -t >/tmp/fail2ban-e116-test.log 2>&1 || { warn "fail2ban 配置测试未通过，已保留文件但不强制启动。"; sed 's/^/    /' /tmp/fail2ban-e116-test.log 2>/dev/null || true; return 0; }
    systemctl enable --now fail2ban >/dev/null 2>&1 || true
    fail2ban-client reload >/dev/null 2>&1 || systemctl restart fail2ban >/dev/null 2>&1 || true
}

_e116_install_ssh_guard() {
    title "V198e117：SSH 防爆破 + SSH 端口自愈（轻量安全版）"
    _e116_backup_state "ssh_guard_apply" >/dev/null 2>&1 || true
    if command -v sshd >/dev/null 2>&1 && ! sshd -t >/tmp/sshd-e116-test.log 2>&1; then
        error "sshd -t 未通过。为避免锁死 SSH，本次不写 SSH guard。"
        sed 's/^/    /' /tmp/sshd-e116-test.log 2>/dev/null || true
        return 1
    fi
    _e116_write_ssh_port_guard || true
    _e116_install_fail2ban_guard || true
    { echo "time=$(date '+%F %T' 2>/dev/null || true)"; echo "ports=$(_e116_detect_ssh_ports | xargs echo 2>/dev/null || echo 22)"; echo "maxretry=$E116_MAXRETRY"; echo "findtime=$E116_FINDTIME"; echo "bantime=$E116_BANTIME"; } > "$E116_STATE_FILE" 2>/dev/null || true
    info "SSH 策略：24h 内第 ${E116_MAXRETRY} 次密码失败触发封禁 36h；开机自动放行当前 sshd 端口。"
}

_e116_show_ssh_guard_state() {
    title "V198e117：SSH 防护状态"
    echo "检测到 SSH 端口：$(_e116_detect_ssh_ports | xargs echo 2>/dev/null || echo 22)"
    echo "策略：findtime=${E116_FINDTIME}s, maxretry=${E116_MAXRETRY}, bantime=${E116_BANTIME}s"
    echo "端口自愈服务：$(systemctl is-enabled xray-ssh-port-guard-e116.service 2>/dev/null || echo not-enabled)"
    if command -v fail2ban-client >/dev/null 2>&1; then fail2ban-client status "$E116_F2B_JAIL_NAME" 2>/dev/null | sed 's/^/  /' || echo "  fail2ban jail 未激活。"; else echo "  fail2ban-client 未安装。"; fi
    test -f "$E116_STATE_FILE" && { echo; sed 's/^/  /' "$E116_STATE_FILE"; }
}

