hot_update_from_legacy() {
    title "V198e117：稳态完整热更新（保留 e111 主体 + 修复 Reality 建仓）"
    _e116_prepare_dirs
    _e116_backup_state "hot_update_start" >/dev/null 2>&1 || true
    echo "198e117" > "$SCRIPT_VERSION_FILE" 2>/dev/null || true
    if test -f "${SCRIPT_PATH:-$0}"; then
        cp -f "${SCRIPT_PATH:-$0}" "$SYMLINK" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e117.sh" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
        chmod +x "$SYMLINK" "$SCRIPT_DIR/ex198e117.sh" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
    fi
    hash -r 2>/dev/null || true
    install_update_dat || warn "geoip/geosite dat 自动更新器恢复未完全成功。"
    if declare -F _e105_disable_xray_core_auto_update >/dev/null 2>&1; then _e105_disable_xray_core_auto_update || true; fi
    _e116_apply_init_window_default30 || warn "initcwnd/initrwnd=30 应用未完全成功。"
    if declare -F _e111_cleanup_obsolete_network_layers >/dev/null 2>&1; then _e111_cleanup_obsolete_network_layers "hot-update-e116-remove-obsolete-layers" || true; fi
    _e116_install_ssh_guard || warn "SSH guard 安装未完全成功，可稍后进菜单18重试。"
    echo "198e117" > "$SCRIPT_VERSION_FILE" 2>/dev/null || true
    info "V198e117 热更新完成。"
    info "核心原则：保留 e111 完整主体，不再像 e115 一样回退裁剪。"
    info "菜单1已重写：Reality 默认强校验；选 Reality 却生成 security=none 会拒绝提交。"
    info "菜单2已加前置检查：没有 Reality 不进入无效用户管理，提示重建。"
    info "热更新默认 initcwnd/initrwnd=30；保留 dat 自动更新，只关闭 Xray Core 自动更新。"
}


#==============================================================================
# V198e117 FINAL COMPAT PATCH LAYER
# 仅修复 e116 的兼容性错误：Xray 26.x 不支持 `xray test`、菜单颜色转义、preflight 误把包名当命令检测。
# 不裁剪 e111/e116 主体，不改动 1-20 主菜单结构，不恢复 21/22。
#==============================================================================

_e117_xray_test_config() {
    local f="${1:-}" out rc logf
    logf="/tmp/xray-e117-test.log"
    : > "$logf" 2>/dev/null || true

    test -n "$f" || { error "未指定待测试配置文件。"; return 1; }
    test -s "$f" || { error "待测试配置为空或不存在：$f"; return 1; }
    jq empty "$f" >/dev/null 2>&1 || { error "待测试配置不是合法 JSON：$f"; return 1; }

    if test ! -x "${XRAY_BIN:-/usr/local/bin/xray}"; then
        warn "未发现可执行 Xray Core，已仅完成 JSON 语法检查。"
        return 0
    fi

    _e117_try_xray_test_cmd() {
        local label="$1"; shift
        local out rc
        set +e
        out=$("$XRAY_BIN" "$@" 2>&1)
        rc=$?
        set -e
        {
            echo "===== $label ====="
            printf '%s\n' "$out"
            echo "rc=$rc"
        } >> "$logf" 2>/dev/null || true
        if test "$rc" -eq 0; then
            info "Xray 配置测试通过：$XRAY_BIN $*"
            return 0
        fi
        # unknown command / unknown flag 属于命令格式不兼容，继续尝试其它格式；配置错误则最终统一输出完整日志。
        return 1
    }

    # 新版 Xray Core 常用格式：xray run -test -config <file>
    if _e117_try_xray_test_cmd "new-run-test" run -test -config "$f"; then return 0; fi
    # 旧版兼容格式。
    if _e117_try_xray_test_cmd "old-root-test" -test -config "$f"; then return 0; fi
    # 只作为最后兜底；你的 26.3.27 明确会提示 unknown command，但保留给其它分支版本。
    if _e117_try_xray_test_cmd "legacy-subcommand-test" test -config "$f"; then return 0; fi
    if _e117_try_xray_test_cmd "legacy-short-config" test -c "$f"; then return 0; fi

    error "Xray 静态配置测试未通过，拒绝提交。已尝试 run -test/-test/test 多种格式。"
    sed 's/^/    /' "$logf" 2>/dev/null || true
    return 1
}

# 覆盖历史各代配置测试函数，统一走兼容探测，避免任何入口再调用已失效的 `xray test`。
e75_xray_test_config() { _e117_xray_test_config "$1"; }
e76_xray_test_config() { _e117_xray_test_config "$1"; }
_e92_xray_test_config() { _e117_xray_test_config "${1:-$CONFIG}"; }
_e93_xray_test_config() { _e117_xray_test_config "${1:-$CONFIG}"; }

_e116_validate_generated_config() {
    local f="$1" mode="$2"
    if ! jq empty "$f" >/dev/null 2>&1; then error "生成配置 JSON 语法不合法。"; return 1; fi
    case "$mode" in
        1|4)
            if ! _e116_config_has_reality_file "$f"; then
                error "选择了 Reality 模式，但生成结果没有 streamSettings.security=reality。已拒绝提交。"
                jq -r '.inbounds[]? | "tag=\(.tag//"-") protocol=\(.protocol//"-") port=\(.port) security=\(.streamSettings.security//"none")"' "$f" 2>/dev/null | sed 's/^/    /' || true
                return 1
            fi
            ;;
        2|3)
            # VLESSENC / SS2022 不要求 reality，这是正常结果。
            ;;
    esac
    _e117_xray_test_config "$f" || return 1
    return 0
}

# 修复 e116 preflight：不再把 coreutils/e2fsprogs/apt-transport-https 等包名当命令检测，避免每次菜单1都无意义 apt 同步。
preflight() {
    if test "$EUID" -ne 0; then die "此脚本必须以 root 身份运行。"; fi
    if ! command -v systemctl >/dev/null 2>&1; then die "系统缺少 systemctl，请更换标准的 systemd 系统。"; fi
    repair_dns_if_broken || true

    local os_id missing="" item cmd pkg
    os_id=$(detect_os 2>/dev/null || echo unknown)
    local pairs=(
        "jq:jq" "curl:curl" "wget:wget" "xxd:xxd" "unzip:unzip" "qrencode:qrencode"
        "vnstat:vnstat" "openssl:openssl" "sed:sed" "ip:iproute2" "ss:iproute2" "tc:iproute2"
        "ethtool:ethtool" "bc:bc" "bison:bison" "flex:flex" "pahole:dwarves" "rsync:rsync"
        "python3:python3" "cpio:cpio" "lz4:liblz4-tool" "zstd:zstd" "iptables:iptables"
    )
    for item in "${pairs[@]}"; do
        cmd="${item%%:*}"; pkg="${item#*:}"
        if ! command -v "$cmd" >/dev/null 2>&1; then missing="$missing $pkg"; fi
    done
    if ! command -v cron >/dev/null 2>&1 && ! command -v crond >/dev/null 2>&1; then missing="$missing cron"; fi

    # 去重。
    missing=$(printf '%s\n' $missing 2>/dev/null | awk 'NF && !seen[$0]++' | xargs echo 2>/dev/null || true)
    if test -n "$missing"; then
        info "正在同步缺失依赖: $missing"
        pkg_install $missing
    fi

    systemctl start vnstat  >/dev/null 2>&1 || true
    systemctl enable vnstat >/dev/null 2>&1 || true
    systemctl start cron    >/dev/null 2>&1 || systemctl start crond >/dev/null 2>&1 || true
    repair_dns_if_broken || true

    if test -f "${SCRIPT_PATH:-$0}"; then
        cp -f "${SCRIPT_PATH:-$0}" "$SYMLINK" 2>/dev/null || true
        chmod +x "$SYMLINK" 2>/dev/null || true
        hash -r 2>/dev/null || true
    fi
    SERVER_IP=$(_get_ip)
    if test "$SERVER_IP" = "获取失败"; then warn "未能自动获取当前公网 IP 地址。"; fi
}

# 修复 dat 更新器：e103/e111 主体里有禁用 timer 的历史策略；e117 明确恢复每日 03:00 timer。
install_update_dat() {
    mkdir -p "$SCRIPT_DIR" "$DAT_DIR" "$LOG_DIR" 2>/dev/null || true
    cat > "$UPDATE_DAT_SCRIPT" <<'UPDSH_E117'
#!/usr/bin/env bash
set -u
XRAY_DAT_DIR="/usr/local/share/xray"
LOG_FILE="/var/log/xray/update-dat.log"
mkdir -p "$XRAY_DAT_DIR" "$(dirname "$LOG_FILE")" 2>/dev/null || true
log_msg() { echo "[$(date +'%Y-%m-%d %H:%M:%S')] $*" >> "$LOG_FILE"; }
dl_if_changed() {
    local url="$1" out="$2" tmp="$2.tmp.$$"
    if ! curl -fsSL --retry 3 --connect-timeout 10 --max-time 300 -o "$tmp" "$url"; then
        rm -f "$tmp" 2>/dev/null || true
        log_msg "[WARN] 下载失败，保留旧文件: $url"
        return 1
    fi
    if test -s "$out" && cmp -s "$tmp" "$out"; then
        rm -f "$tmp" 2>/dev/null || true
        log_msg "[INFO] 未变化: $(basename "$out")"
        return 0
    fi
    mv -f "$tmp" "$out"
    log_msg "[INFO] 已更新: $(basename "$out")"
    echo changed >> /tmp/xray-dat-changed.$$ 2>/dev/null || true
    return 0
}
rm -f /tmp/xray-dat-changed.$$ 2>/dev/null || true
ok=0
dl_if_changed "https://github.com/Loyalsoldier/v2ray-rules-dat/raw/release/geoip.dat" "$XRAY_DAT_DIR/geoip.dat" || ok=1
dl_if_changed "https://github.com/Loyalsoldier/domain-list-custom/releases/latest/download/geosite.dat" "$XRAY_DAT_DIR/geosite.dat" || ok=1
if test -s /tmp/xray-dat-changed.$$ && systemctl is-active --quiet xray; then
    log_msg "[INFO] dat 文件已变化，重启 Xray 使规则生效。"
    systemctl restart xray >/dev/null 2>&1 || true
fi
rm -f /tmp/xray-dat-changed.$$ 2>/dev/null || true
exit "$ok"
UPDSH_E117
    chmod +x "$UPDATE_DAT_SCRIPT" 2>/dev/null || true
    cat > /etc/systemd/system/xray-dat-update.service <<EOF_SERVICE_E117
[Unit]
Description=Xray geoip/geosite dat safe updater
After=network-online.target
Wants=network-online.target

[Service]
Type=oneshot
ExecStart=$UPDATE_DAT_SCRIPT
EOF_SERVICE_E117
    cat > /etc/systemd/system/xray-dat-update.timer <<'EOF_TIMER_E117'
[Unit]
Description=Daily Xray dat update timer

[Timer]
OnCalendar=*-*-* 03:00:00
RandomizedDelaySec=20m
Persistent=true

[Install]
WantedBy=timers.target
EOF_TIMER_E117
    systemctl daemon-reload >/dev/null 2>&1 || true
    systemctl enable --now xray-dat-update.timer >/dev/null 2>&1 || true
    info "e117：已启用 geoip/geosite 每日自动更新 timer；不设置 Xray Core 自动更新。"
}

# 修复菜单1颜色输出：不用普通 echo 打印转义序列。
do_install() {
    while true; do
        clear
        title "V198e117：安装 / 重装节点（完整主体 + Xray 26.x 兼容校验）"
        printf '  1) VLESS Reality Vision              %b\n' "${cyan}(默认推荐；必须生成 security=reality)${none}"
        printf '  2) Reality Vision + SS2022            %b\n' "${cyan}(主通道 + 备用通道)${none}"
        printf '  3) VLESSENC Vision 自选               %b\n' "${yellow}(实验项；生成 security=none 属于正常)${none}"
        printf '  4) SS2022                             %b\n' "${cyan}(轻量备用)${none}"
        printf '  9) 进入历史 e79/e111 原始建仓入口       %b\n' "${yellow}(兼容旧逻辑)${none}"
        echo "  0) 返回主菜单"
        hr
        local sel=""; read -rp "请输入编号 (回车默认 1=Reality): " sel || true
        sel=${sel:-1}
        case "$sel" in
            1) _e116_install_mode 1 "VLESS Reality Vision"; _e116_pause; return 0 ;;
            2) _e116_install_mode 4 "Reality Vision + SS2022"; _e116_pause; return 0 ;;
            3) _e116_install_mode 2 "VLESSENC Vision 自选"; _e116_pause; return 0 ;;
            4) _e116_install_mode 3 "SS2022"; _e116_pause; return 0 ;;
            9) if declare -F do_install_e116_base >/dev/null 2>&1; then do_install_e116_base || warn "历史建仓入口返回失败。"; else error "历史 do_install 不存在。"; fi; _e116_pause; return 0 ;;
            0|q|Q) return 0 ;;
            *) error "输入无效。"; sleep 1 ;;
        esac
    done
}

# 热更新入口覆盖：写入 e117 文件名/版本，避免继续落盘为 e116。
hot_update_from_legacy() {
    title "V198e117：稳态完整热更新（修复 xray test 兼容，不裁剪主体）"
    _e116_prepare_dirs
    _e116_backup_state "hot_update_start_e117" >/dev/null 2>&1 || true
    echo "198e117" > "$SCRIPT_VERSION_FILE" 2>/dev/null || true
    if test -f "${SCRIPT_PATH:-$0}"; then
        cp -f "${SCRIPT_PATH:-$0}" "$SYMLINK" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e117.sh" 2>/dev/null || true
        cp -f "${SCRIPT_PATH:-$0}" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
        chmod +x "$SYMLINK" "$SCRIPT_DIR/ex198e117.sh" "$SCRIPT_DIR/ex198e_latest.sh" 2>/dev/null || true
    fi
    hash -r 2>/dev/null || true
    install_update_dat || warn "geoip/geosite dat 自动更新器恢复未完全成功。"
    if declare -F _e105_disable_xray_core_auto_update >/dev/null 2>&1; then _e105_disable_xray_core_auto_update || true; fi
    _e116_apply_init_window_default30 || warn "initcwnd/initrwnd=30 应用未完全成功。"
    if declare -F _e111_cleanup_obsolete_network_layers >/dev/null 2>&1; then _e111_cleanup_obsolete_network_layers "hot-update-e117-remove-obsolete-layers" || true; fi
    _e116_install_ssh_guard || warn "SSH guard 安装未完全成功，可稍后进菜单18重试。"
    echo "198e117" > "$SCRIPT_VERSION_FILE" 2>/dev/null || true
    info "V198e117 热更新完成。"
    info "已修复：Xray 26.x 下 xray test unknown command；菜单颜色转义；preflight 误检测包名。"
    info "菜单1选择 3=VLESSENC 时会用兼容测试命令提交，不再因 xray test 子命令闪退。"
}

