#==============================================================================
# V199e137 FINAL TRANSACTIONAL RELIABILITY LAYER
# 这一层统一收口最终入口。旧层保留用于兼容历史菜单，但关键写入全部经过：
# 候选生成 -> JSON/语义/Xray 测试 -> 安全快照 -> 同文件系统原子替换 -> 服务复检 -> 失败回滚。
#==============================================================================

readonly E118_DIR="$CONFIG_DIR/e118_transactional"
readonly E118_BACKUP_DIR="$E118_DIR/backups"
readonly E118_AUDIT_DIR="$E118_DIR/audit"
readonly E118_STATE_FILE="$E118_DIR/state.env"
readonly E118_LOCK_FILE="/run/lock/xrv-transactional.lock"
readonly E118_SSH_GUARD_SCRIPT="/usr/local/bin/xray-ssh-port-guard-e118.sh"
readonly E118_SSH_GUARD_SERVICE="/etc/systemd/system/xray-ssh-port-guard-e118.service"
readonly E118_F2B_JAIL="/etc/fail2ban/jail.d/99-xray-sshguard-e118.conf"
readonly E118_F2B_DB_CONF="/etc/fail2ban/fail2ban.d/99-xray-e118-persistence.conf"
readonly E118_F2B_JAIL_NAME="xray-sshd-e118"
readonly E118_FINDTIME="86400"
readonly E118_BANTIME="129600"
readonly E118_MAXRETRY="2"
readonly E121_F2B_JAIL="/etc/fail2ban/jail.d/99-xray-sshguard-e121.conf"
readonly E121_F2B_DB_CONF="/etc/fail2ban/fail2ban.d/99-xray-e121-persistence.conf"
readonly E121_F2B_COMPAT_CONF="/etc/fail2ban/jail.d/zz-xray-sshguard-e121-compat.local"
readonly E121_F2B_JAIL_NAME="xray-sshd-e121"
readonly E121_F2B_STATE="$E118_DIR/fail2ban.env"
readonly E121_RSYSLOG_CONF="/etc/rsyslog.d/30-xray-ssh-auth-e121.conf"
readonly E121_RSYSLOG_LOG="/var/log/xray-sshd-auth.log"
readonly E121_SSH_GUARD_SCRIPT="/usr/local/bin/xray-ssh-port-guard-e121.sh"
readonly E121_SSH_GUARD_SERVICE="/etc/systemd/system/xray-ssh-port-guard-e121.service"
readonly E121_SSH_GUARD_TIMER="/etc/systemd/system/xray-ssh-port-guard-e121.timer"
readonly E121_SSH_GUARD_STATE="$E118_DIR/ssh_ports_e121.env"
readonly E121_SSH_GUARD_CHAIN="XRAY_SSH_E121"
readonly E121_LOG_RETENTION_SCRIPT="/usr/local/bin/xray-log-retention-e121.sh"
readonly E121_LOG_RETENTION_SERVICE="/etc/systemd/system/xray-log-retention-e121.service"
readonly E121_LOG_RETENTION_TIMER="/etc/systemd/system/xray-log-retention-e121.timer"
readonly E121_JOURNAL_CONF="/etc/systemd/journald.conf.d/zz-xray-retention-e121.conf"
readonly E121_LOGROTATE_CONF="/etc/logrotate.d/xray-e121"

E118_TMPDIR=""
E118_LOCK_DIR=""
E118_RUNTIME_READY=0
E118_TX_ACTIVE=0
E118_TX_BACKUP=""
E118_TX_WAS_ACTIVE=0

cleanup_temp_files() {
    if test -n "${E118_TMPDIR:-}" && test -d "$E118_TMPDIR"; then
        rm -rf -- "$E118_TMPDIR" 2>/dev/null || true
    fi
    if test -n "${E118_LOCK_DIR:-}" && test -d "$E118_LOCK_DIR"; then
        rmdir -- "$E118_LOCK_DIR" 2>/dev/null || true
    fi
}

_e118_prepare_dirs() {
    mkdir -p "$CONFIG_DIR" "$DAT_DIR" "$SCRIPT_DIR" "$LOG_DIR" "$BACKUP_DIR" \
        "$FLAGS_DIR" "$E118_BACKUP_DIR" "$E118_AUDIT_DIR" /run/lock 2>/dev/null || return 1
    chmod 700 "$BACKUP_DIR" "$E118_DIR" "$E118_BACKUP_DIR" "$E118_AUDIT_DIR" 2>/dev/null || true
    touch "$USER_SNI_MAP" "$USER_TIME_MAP" 2>/dev/null || return 1
    chmod 600 "$USER_SNI_MAP" "$USER_TIME_MAP" 2>/dev/null || true
}

_e118_runtime_init() {
    if test "${E118_RUNTIME_READY:-0}" -eq 1; then return 0; fi
    umask 077
    _e118_prepare_dirs || { error "无法创建 V199e137 工作目录。"; return 1; }
    E118_TMPDIR=$(mktemp -d /tmp/ex199e136.XXXXXX) || { error "无法创建安全临时目录。"; return 1; }
    chmod 700 "$E118_TMPDIR" 2>/dev/null || true

    if command -v flock >/dev/null 2>&1; then
        exec 9>"$E118_LOCK_FILE" || return 1
        if ! flock -n 9; then
            error "检测到另一个 ex199e136/xrv 实例正在运行。为避免并发覆盖，本次退出。"
            return 1
        fi
    else
        E118_LOCK_DIR="${E118_LOCK_FILE}.d"
        if ! mkdir "$E118_LOCK_DIR" 2>/dev/null; then
            error "检测到另一个 ex199e136/xrv 实例正在运行，或遗留锁目录：$E118_LOCK_DIR"
            return 1
        fi
    fi
    E118_RUNTIME_READY=1
    trap '_e118_signal_handler INT' INT
    trap '_e118_signal_handler TERM' TERM
    trap '_e118_signal_handler HUP' HUP
    return 0
}

_e118_mktemp() {
    local stem="${1:-tmp}" base ext
    test -n "${E118_TMPDIR:-}" || _e118_runtime_init || return 1
    stem=${stem##*/}
    case "$stem" in
        *.*)
            base=${stem%.*}
            ext=.${stem##*.}
            ;;
        *)
            base=$stem
            ext=""
            ;;
    esac
    base=$(printf '%s' "$base" | tr -c 'A-Za-z0-9_.-' '_')
    ext=$(printf '%s' "$ext" | tr -c 'A-Za-z0-9._-' '_')
    test -n "$base" || base=tmp
    case "$ext" in
        ""|.[A-Za-z0-9]* ) ;;
        *) ext="" ;;
    esac
    mktemp "$E118_TMPDIR/${base}.XXXXXX${ext}"
}


_e118_signal_handler() {
    local sig="${1:-TERM}"
    trap - INT TERM HUP
    if test "${E118_TX_ACTIVE:-0}" -eq 1 && test -n "${E118_TX_BACKUP:-}"; then
        warn "收到 $sig，正在回滚未完成的配置事务。"
        _e118_restore_state "$E118_TX_BACKUP" >/dev/null 2>&1 || true
    fi
    cleanup_temp_files
    exit 130
}

