        title "网络参数中心（V199e137：默认 initcwnd/initrwnd=30）"
        echo "  1) 进入历史完整网络参数菜单"
        echo "  35) 查看 initcwnd/initrwnd 状态"
        echo "  36) 应用 initcwnd/initrwnd=30"
        echo "  37) 只读审计其它可评估加速参数（不自动修改）"
