}

_e124_preinstall_integrity() {
    local td old_tmp old_ready p rc=0 body
    bash -n "$SCRIPT_PATH" || { error "e124 脚本自身未通过 bash -n。"; return 1; }
    td=$(mktemp -d /tmp/ex199e136-precheck.XXXXXX) || return 1
    old_tmp=${E118_TMPDIR:-}; old_ready=${E118_RUNTIME_READY:-0}
    E118_TMPDIR="$td"; E118_RUNTIME_READY=1
    p=$(_e118_mktemp install.json) || rc=1
    case "$p" in *.json) ;; *) rc=1 ;; esac
    E118_TMPDIR="$old_tmp"; E118_RUNTIME_READY="$old_ready"
    rm -rf "$td" 2>/dev/null || true
    test "$rc" -eq 0 || { error "临时配置文件扩展名自检失败，拒绝热更新。"; return 1; }
    for p in _e124_reality_password_from_private _e124_reality_password_for_private \
        _e124_write_password_cache _e124_state_set _e124_reality_key_diagnose; do
        declare -F "$p" >/dev/null 2>&1 || { error "e124 完整性函数缺失：$p"; return 1; }
    done
    body=$(declare -f do_summary 2>/dev/null || true)
    [[ "$body" == *'_e124_reality_password_for_private'* ]] || { error "节点输出未接入逐入站 PBK 派生。"; return 1; }
    body=$(declare -f run_sni_scanner 2>/dev/null || true)
    [[ "$body" == *'time_appconnect'* && "$body" != *' -fsS '* && "$body" == *'e124-new'* ]] \
        || { error "SNI TLS 探测或原子缓存实现缺失。"; return 1; }
}

# Preserve the retained comprehensive self-test, then add executable regressions.
if declare -F _e118_self_test >/dev/null 2>&1; then
    eval "$(declare -f _e118_self_test | sed '1s/_e118_self_test/_e124_self_test_base/')" 2>/dev/null || true
fi
_e118_self_test() {
    local rc=0 sample td old_tmp old_ready p method expected pass actual cfg fake old_override state scanner_def \
        old_pub_override old_meta_override
    declare -F _e124_self_test_base >/dev/null 2>&1 && _e124_self_test_base || rc=1
    echo
    echo "V199e137 回归测试："
    _e124_result() { if "$1"; then echo "  [PASS] $2"; else echo "  [FAIL] $2"; rc=1; fi; }

    sample=$'PrivateKey: MNh7APEE6Z2rn8k4raNocmtUHKPuijmQPekkL1wf7Uw\nPassword (PublicKey): KT9E7OM1dYrdwqbGmuGv3F4QYqKYqB9XmgvBAUXwkl8\nHash32: 3ylVeyW_GLAX8Ibwr0N5vCntnp_GffO_44NAlneDpXQ'
    if _e118_parse_x25519_output "$sample" && test "$E77_REALITY_PUB" = 'KT9E7OM1dYrdwqbGmuGv3F4QYqKYqB9XmgvBAUXwkl8'; then
        echo "  [PASS] Password (PublicKey) 解析"
    else echo "  [FAIL] Password (PublicKey) 解析"; rc=1; fi

    td=$(mktemp -d /tmp/ex199e136-selftest.XXXXXX) || return 1
    old_tmp=${E118_TMPDIR:-}; old_ready=${E118_RUNTIME_READY:-0}
    E118_TMPDIR="$td"; E118_RUNTIME_READY=1
    p=$(_e118_mktemp install.json 2>/dev/null || true)
    case "$p" in *.json) echo "  [PASS] install.XXXXXX.json 扩展名" ;; *) echo "  [FAIL] JSON 临时文件扩展名：$p"; rc=1 ;; esac
    p=$(_e118_mktemp xray.service 2>/dev/null || true)
    case "$p" in *.service) echo "  [PASS] service 临时文件扩展名" ;; *) echo "  [FAIL] service 临时文件扩展名：$p"; rc=1 ;; esac

    fake="$td/fake-xray"
    cat > "$fake" <<'EOF_E124_FAKE_XRAY'
#!/usr/bin/env bash
case "$*" in
  *MNh7APEE6Z2rn8k4raNocmtUHKPuijmQPekkL1wf7Uw*) echo 'Password (PublicKey): KT9E7OM1dYrdwqbGmuGv3F4QYqKYqB9XmgvBAUXwkl8' ;;
  *AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA*) echo 'Password: BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB' ;;
  version) echo 'Xray fake-e124' ;;
  *) echo 'unknown test input' >&2; exit 2 ;;
esac
EOF_E124_FAKE_XRAY
    chmod 0700 "$fake"
    old_override=${E124_XRAY_BIN_OVERRIDE:-}
    E124_XRAY_BIN_OVERRIDE="$fake"
    actual=$(_e124_reality_password_from_private 'MNh7APEE6Z2rn8k4raNocmtUHKPuijmQPekkL1wf7Uw' 2>/dev/null || true)
    if test "$actual" = 'KT9E7OM1dYrdwqbGmuGv3F4QYqKYqB9XmgvBAUXwkl8'; then
        echo "  [PASS] xray -i Password(PublicKey) 实际派生路径"
    else echo "  [FAIL] xray -i 实际派生路径"; rc=1; fi
    actual=$(_e124_reality_password_from_private 'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA' 2>/dev/null || true)
    if test "$actual" = 'BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB'; then
        echo "  [PASS] 多 Reality 私钥逐项独立派生"
    else echo "  [FAIL] 多 Reality 独立派生"; rc=1; fi
    E124_XRAY_BIN_OVERRIDE="$old_override"

    old_pub_override=${E124_PUBKEY_FILE_OVERRIDE:-}
    old_meta_override=${E124_REALITY_CACHE_META_OVERRIDE:-}
    E124_PUBKEY_FILE_OVERRIDE="$td/public.key"
    E124_REALITY_CACHE_META_OVERRIDE="$td/reality-password-cache.env"
    if _e124_write_password_cache 'MNh7APEE6Z2rn8k4raNocmtUHKPuijmQPekkL1wf7Uw' \
            'KT9E7OM1dYrdwqbGmuGv3F4QYqKYqB9XmgvBAUXwkl8' \
        && test "$(_e124_cache_read_matching 'MNh7APEE6Z2rn8k4raNocmtUHKPuijmQPekkL1wf7Uw')" = \
            'KT9E7OM1dYrdwqbGmuGv3F4QYqKYqB9XmgvBAUXwkl8' \
        && ! _e124_cache_read_matching 'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA' >/dev/null 2>&1; then
        echo "  [PASS] PBK 缓存按 privateKey 指纹匹配并拒绝旧私钥"
    else echo "  [FAIL] PBK 缓存指纹校验"; rc=1; fi
    E124_PUBKEY_FILE_OVERRIDE="$old_pub_override"
    E124_REALITY_CACHE_META_OVERRIDE="$old_meta_override"

    state="$td/state.env"
    printf 'same=old\nsame=older\nkeep=yes\n' > "$state"
    _e124_state_set "$state" same new || rc=1
    if test "$(grep -c '^same=' "$state")" = 1 && grep -qx 'same=new' "$state" && grep -qx 'keep=yes' "$state"; then
        echo "  [PASS] 热更新状态键去重原子替换"
    else echo "  [FAIL] 热更新状态键仍会重复"; rc=1; fi

    for method in 2022-blake3-aes-128-gcm 2022-blake3-aes-256-gcm 2022-blake3-chacha20-poly1305; do
        case "$method" in 2022-blake3-aes-128-gcm) expected=16 ;; *) expected=32 ;; esac
        pass=$(e77_gen_ss2022_pass "$method" 2>/dev/null || true)
        actual=$(printf '%s' "$pass" | base64 -d 2>/dev/null | wc -c | tr -d '[:space:]')
        if test "$actual" = "$expected"; then echo "  [PASS] $method=${expected}字节"; else echo "  [FAIL] $method 实际${actual:-0}字节"; rc=1; fi
    done

    if declare -f e77_pick_free_port | grep -q 'ltnu'; then echo "  [PASS] TCP/UDP 端口冲突检测"; else echo "  [FAIL] 仍仅检测 TCP 端口"; rc=1; fi
    scanner_def=$(declare -f run_sni_scanner 2>/dev/null || true)
    if [[ "$scanner_def" != *"dns.alidns.com"* && "$scanner_def" != *"ipinfo.io"* \
        && "$scanner_def" != *" -fsS "* && "$scanner_def" == *"time_appconnect"* \
        && "$scanner_def" == *"e124-new"* && ( "$scanner_def" == *"q|Q"* || "$scanner_def" == *"q | Q"* ) ]]; then
        echo "  [PASS] SNI 扫描不把HTTP错误当TLS失败且缓存原子替换"
    else
        echo "  [FAIL] SNI 扫描仍含HTTP状态误判/非原子缓存/旧外部查询"
        rc=1
    fi
    if _e118_managed_state_files | grep -Fxq "$E124_REALITY_CACHE_META"; then
        echo "  [PASS] PBK 指纹缓存进入事务备份/回滚"
    else echo "  [FAIL] PBK 指纹缓存未进入事务"; rc=1; fi
    if declare -f _e118_validate_generated_config | grep -q '_e124_validate_ss2022_inbounds'; then echo "  [PASS] SS2022 解码长度进入提交前校验"; else echo "  [FAIL] SS2022 长度未进入提交前校验"; rc=1; fi

    cfg=$(_e118_mktemp selftest-config.json) || rc=1
    cat > "$cfg" <<'EOF_E124_SELF_CFG'
{"log":{"loglevel":"warning"},"inbounds":[],"outbounds":[{"protocol":"freedom","settings":{},"tag":"direct"}]}
EOF_E124_SELF_CFG
    if test -x "$XRAY_BIN"; then
        if _e118_xray_test_config "$cfg" 1 >/dev/null 2>&1; then echo "  [PASS] 当前 Xray + .json 实际配置测试"; else echo "  [FAIL] 当前 Xray + .json 实际配置测试"; rc=1; fi
    else
        echo "  [SKIP] 当前环境无 Xray Core，跳过实际 Core 测试"
    fi

    E118_TMPDIR="$old_tmp"; E118_RUNTIME_READY="$old_ready"
    rm -rf "$td" 2>/dev/null || true
    echo "V199e137 回归测试结果：$(test "$rc" -eq 0 && echo PASS || echo FAIL)"
    return "$rc"
}

hot_update_from_legacy() {
    _e124_preinstall_integrity || return 1
    _e118_impl_hot_update "$@" || return 1
    if test -s "$CONFIG" && jq -e '.inbounds[]? | select(.protocol=="vless" and (.streamSettings.security//"")=="reality")' "$CONFIG" >/dev/null 2>&1; then
        _e124_repair_reality_password_cache || { error "热更新主体完成，但 Reality Password(pbk) 修复失败。"; return 1; }
        _e124_state_set "$E118_STATE_FILE" reality_password_cache ok || return 1
    else
        _e124_state_set "$E118_STATE_FILE" reality_password_cache not-applicable || return 1
    fi
    _e124_state_set "$E118_STATE_FILE" temp_config_suffix json-preserved || return 1
    _e124_state_set "$E118_STATE_FILE" ss2022_key_validation enabled || return 1
    _e124_state_set "$E118_STATE_FILE" port_check tcp+udp || return 1
    _e124_state_set "$E118_STATE_FILE" sni_tls_probe http-status-independent || return 1
    printf '%s\n' "$SCRIPT_VERSION" > "$SCRIPT_VERSION_FILE" 2>/dev/null || true
    info "V199e137 热更新完成：JSON临时文件格式、PBK、SS2022密钥及TCP/UDP端口检查已收口。"
}

#==============================================================================
# V199e137 MANAGED ACCELERATION COLLECTION
# 独立 sysctl 所有权、逐项默认值、运行态事务、开机最后复检。
#==============================================================================

readonly E126_ACCEL_DIR="$CONFIG_DIR/e126_accel"
readonly E126_ACCEL_BACKUP_DIR="$E126_ACCEL_DIR/backups"
readonly E126_ACCEL_STATE="$E126_ACCEL_DIR/state.env"
readonly E126_ACCEL_CONF="/etc/sysctl.d/99-xray-e126-accel.conf"
readonly E126_ACCEL_BOOT_SCRIPT="/usr/local/bin/xray-accel-e126.sh"
readonly E126_ACCEL_SERVICE="/etc/systemd/system/xray-accel-e126.service"
readonly E126_ACCEL_BASELINE="$E126_ACCEL_DIR/baseline.env"
readonly E126_LEGACY_ACCEL_DIR="$CONFIG_DIR/e125_accel"
readonly E126_LEGACY_ACCEL_CONF="/etc/sysctl.d/99-xray-e125-accel.conf"
readonly E126_LEGACY_ACCEL_BOOT_SCRIPT="/usr/local/bin/xray-accel-e125.sh"
readonly E126_LEGACY_ACCEL_SERVICE="/etc/systemd/system/xray-accel-e125.service"

_e126_accel_metadata() {
    cat <<'EOF_E126_META'
01|net.core.default_qdisc|pfifo_fast（发行版可覆盖）|fq|低|设置新建队列的默认值；当前网卡实际 qdisc 另行显示且不强拆 TC|pfifo_fast
02|net.ipv4.tcp_congestion_control|内核构建/发行版决定|bbr（不可用则 cubic）|中|只影响新建 TCP 连接；不会伪造不存在的 BBR|
03|net.ipv4.tcp_mtu_probing|0|1|低|仅探测到 ICMP 黑洞时启用 PLPMTUD|0
04|net.ipv4.tcp_slow_start_after_idle|1|0|中|长连接空闲后保留 cwnd；丢包链路可改回1|1
05|net.ipv4.tcp_notsent_lowat|4294967295|131072|中|限制未发送队列，降低应用层排队|4294967295
06|net.ipv4.tcp_limit_output_bytes|4194304|1048576|中|限制 TCP Small Queues 本机排队|4194304
07|net.ipv4.tcp_autocorking|1|1|低|合并连续小写入，减少小包|1
08|net.ipv4.tcp_fastopen|1（客户端位）|1|低|应用必须显式使用；Xray 未启用时无直接收益|1
09|net.ipv4.tcp_no_metrics_save|0|0|低|保留历史路径指标有利于重复连接|0
10|net.ipv4.tcp_moderate_rcvbuf|1|1|低|TCP 接收缓冲自动调节|1
11|net.ipv4.tcp_window_scaling|1|1|低|高 BDP 链路必须保留窗口缩放|1
12|net.ipv4.tcp_sack|1|1|低|保留选择确认，改善丢包恢复|1
13|net.ipv4.tcp_dsack|1|1|低|保留重复 SACK|1
14|net.ipv4.tcp_early_retrans|3|3|低|保留 TLP 尾丢恢复|3
15|net.ipv4.tcp_recovery|1（RACK）|1|低|保留 RACK；不启用实验位|1
16|net.ipv4.tcp_min_rtt_wlen|300|300|低|最小 RTT 过滤窗口，盲目缩短会误判拥塞|300
17|net.ipv4.tcp_ecn|2|2|低|接受 ECN，但默认不主动请求；兼容性优先|2
18|net.ipv4.tcp_pacing_ss_ratio|200|200|低|慢启动 pacing 比例，保持内核默认|200
19|net.ipv4.tcp_pacing_ca_ratio|120|120|低|拥塞避免 pacing 比例，保持内核默认|120
20|net.ipv4.tcp_comp_sack_delay_ns|1000000|1000000|低|SACK 压缩上限，盲目改小会增加 CPU|1000000
21|net.ipv4.tcp_adv_win_scale|1（Linux 6.6+已废弃）|1|低|新内核为 no-op，保留只为兼容旧内核|1
22|net.ipv4.tcp_app_win|31|31|低|应用缓冲保留比例，保持默认|31
23|net.core.somaxconn|4096|8192|中|只改善高并发 accept 队列，不提高单流带宽|4096
24|net.core.netdev_max_backlog|1000|4096|中|突发收包队列；过大可能增加延迟|1000
25|net.core.rmem_max|4194304|56699928|中|高 RTT 接收缓冲上限；不是每连接预分配|4194304
26|net.core.wmem_max|4194304|56699928|中|高 RTT 发送缓冲上限；不是每连接预分配|4194304
27|net.ipv4.tcp_rmem|4096 131072 RAM动态上限|4096 131072 56699928|中|TCP 自动接收缓冲三元组|
28|net.ipv4.tcp_wmem|4096 16384 RAM动态上限|4096 16384 56699928|中|TCP 自动发送缓冲三元组|
29|net.core.busy_poll|0|0|高|全局忙轮询耗 CPU；仅列出，不在推荐档启用|0
30|net.core.busy_read|0|0|高|全局忙轮询耗 CPU；仅列出，不在推荐档启用|0
31|net.ipv4.ip_local_port_range|32768 60999|10240 65535|中|仅改善大量并发出站连接，不提高单流速度|32768 60999
EOF_E126_META
}

_e126_norm() {
    printf '%s\n' "${1:-}" | awk '{$1=$1; print}'
}

_e126_meta_by_id() {
    local wanted="${1:-}"
    _e126_accel_metadata | awk -F'|' -v w="$wanted" '$1==w || ($1+0)==(w+0){print; exit}'
}

_e126_meta_by_key() {
    local wanted="${1:-}"
    _e126_accel_metadata | awk -F'|' -v w="$wanted" '$2==w{print; exit}'
}

_e126_sysctl_supported() {
    local p="/proc/sys/${1//./\/}"
    test -e "$p" && test -w "$p"
}

_e126_current() {
    sysctl -n "$1" 2>/dev/null | awk '{$1=$1; print}'
}

_e126_is_managed() {
    local wanted="$1" key value
    test -s "$E126_ACCEL_CONF" || return 1
    while IFS='=' read -r key value; do
        key=$(_e126_norm "$key")
        test "$key" = "$wanted" && return 0
    done < "$E126_ACCEL_CONF"
    return 1
}

_e126_uint_between() {
    local value="$1" min="$2" max="$3"
    [[ "$value" =~ ^[0-9]+$ ]] || return 1
    (( value >= min && value <= max ))
}

_e126_validate_value() {
    local key="$1" value
    value=$(_e126_norm "${2:-}")
    test -n "$(_e126_meta_by_key "$key")" || return 1
    case "$key" in
        net.core.default_qdisc)
            [[ "$value" =~ ^[A-Za-z0-9_-]{1,32}$ ]]
            ;;
        net.ipv4.tcp_congestion_control)
            [[ "$value" =~ ^[A-Za-z0-9_-]{1,32}$ ]]
            ;;
        net.ipv4.tcp_rmem|net.ipv4.tcp_wmem)
            local a b c extra
            read -r a b c extra <<< "$value"
            test -z "${extra:-}" && _e126_uint_between "$a" 1024 1073741824 \
                && _e126_uint_between "$b" "$a" 1073741824 \
                && _e126_uint_between "$c" "$b" 1073741824
            ;;
        net.ipv4.ip_local_port_range)
            local low high extra
            read -r low high extra <<< "$value"
            test -z "${extra:-}" && _e126_uint_between "$low" 1024 65535 \
                && _e126_uint_between "$high" "$low" 65535
            ;;
        net.ipv4.tcp_mtu_probing) _e126_uint_between "$value" 0 2 ;;
        net.ipv4.tcp_ecn) _e126_uint_between "$value" 0 5 ;;
        net.ipv4.tcp_recovery) _e126_uint_between "$value" 0 255 ;;
        net.ipv4.tcp_adv_win_scale)
            [[ "$value" =~ ^-?[0-9]+$ ]] && (( value >= -31 && value <= 31 ))
            ;;
        net.ipv4.tcp_app_win) _e126_uint_between "$value" 0 31 ;;
        net.ipv4.tcp_fastopen) _e126_uint_between "$value" 0 2047 ;;
        net.ipv4.tcp_autocorking|net.ipv4.tcp_no_metrics_save|net.ipv4.tcp_moderate_rcvbuf|\
        net.ipv4.tcp_window_scaling|net.ipv4.tcp_sack|net.ipv4.tcp_dsack|\
        net.ipv4.tcp_slow_start_after_idle)
            _e126_uint_between "$value" 0 1
            ;;
        net.ipv4.tcp_early_retrans) _e126_uint_between "$value" 0 4 ;;
        net.ipv4.tcp_min_rtt_wlen) _e126_uint_between "$value" 0 86400 ;;
        net.core.busy_poll|net.core.busy_read) _e126_uint_between "$value" 0 1000 ;;
        net.core.rmem_max|net.core.wmem_max)
            _e126_uint_between "$value" 65536 1073741824
            ;;
        net.ipv4.tcp_notsent_lowat)
            _e126_uint_between "$value" 4096 4294967295
            ;;
        *) _e126_uint_between "$value" 0 1073741824 ;;
    esac
}

_e126_prepare_modules() {
    local candidate="$1" key value
    while IFS='=' read -r key value; do
        key=$(_e126_norm "$key"); value=$(_e126_norm "$value")
        case "$key" in
            net.core.default_qdisc) modprobe "sch_${value}" >/dev/null 2>&1 || true ;;
            net.ipv4.tcp_congestion_control) modprobe "tcp_${value}" >/dev/null 2>&1 || true ;;
        esac
    done < "$candidate"
}

_e126_validate_candidate() {
    local candidate="$1" line key value count=0 keys="" available
    test -s "$candidate" || { error "候选参数文件为空。"; return 1; }
    _e126_prepare_modules "$candidate"
    while IFS= read -r line || test -n "$line"; do
        line=$(_e126_norm "$line")
        case "$line" in ""|'#'*) continue ;; esac
        [[ "$line" == *=* ]] || { error "候选配置语法错误：$line"; return 1; }
        key=$(_e126_norm "${line%%=*}"); value=$(_e126_norm "${line#*=}")
        test -n "$key" && test -n "$value" || { error "候选配置键值为空：$line"; return 1; }
        test -n "$(_e126_meta_by_key "$key")" || { error "候选配置含非 E126 白名单参数：$key"; return 1; }
        [[ " $keys " != *" $key "* ]] || { error "候选配置参数重复：$key"; return 1; }
        _e126_sysctl_supported "$key" || { error "当前内核不支持或不可写：$key"; return 1; }
        _e126_validate_value "$key" "$value" || { error "参数值不合法：$key = $value"; return 1; }
        if test "$key" = "net.ipv4.tcp_congestion_control"; then
            available=$(sysctl -n net.ipv4.tcp_available_congestion_control 2>/dev/null || true)
            [[ " $available " == *" $value "* ]] || { error "拥塞控制不可用：$value（可用：${available:-none}）"; return 1; }
        fi
        keys="$keys $key"; count=$((count+1))
    done < "$candidate"
    test "$count" -gt 0 || { error "候选配置没有可应用参数。"; return 1; }
}

_e126_pick_cc() {
    local available current
    modprobe tcp_bbr >/dev/null 2>&1 || true
    available=$(sysctl -n net.ipv4.tcp_available_congestion_control 2>/dev/null || true)
    if [[ " $available " == *" bbr "* ]]; then echo bbr
    elif [[ " $available " == *" cubic "* ]]; then echo cubic
    else
        current=$(_e126_current net.ipv4.tcp_congestion_control)
        if [[ " $available " == *" $current "* ]]; then echo "$current"; else printf '%s\n' "$available" | awk '{print $1}'; fi
    fi
}

_e126_profile_value() {
    local profile="$1" key="$2" recommended="$3" cc
    case "$key" in
        net.core.default_qdisc)
            if modprobe sch_fq >/dev/null 2>&1 || test -d /sys/module/sch_fq; then echo fq
            else _e126_current net.core.default_qdisc
            fi
            return 0
            ;;
        net.ipv4.tcp_congestion_control)
            cc=$(_e126_pick_cc); test -n "$cc" || return 1; echo "$cc"; return 0 ;;
    esac
    case "$profile:$key" in
        low:net.ipv4.tcp_notsent_lowat) echo 131072 ;;
        low:net.ipv4.tcp_limit_output_bytes) echo 524288 ;;
        low:net.core.netdev_max_backlog) echo 2048 ;;
        low:net.core.somaxconn) echo 4096 ;;
        low:net.core.rmem_max|low:net.core.wmem_max) echo 16777216 ;;
        low:net.ipv4.tcp_rmem) echo '4096 131072 16777216' ;;
        low:net.ipv4.tcp_wmem) echo '4096 16384 16777216' ;;
        throughput:net.ipv4.tcp_notsent_lowat) echo 131072 ;;
        throughput:net.ipv4.tcp_limit_output_bytes) echo 4194304 ;;
        throughput:net.core.netdev_max_backlog) echo 8192 ;;
        throughput:net.core.somaxconn) echo 16384 ;;
        *) echo "$recommended" ;;
    esac
}

_e126_build_profile() {
    local profile="$1" output="$2" id key dflt rec risk note reset value
    printf '# Managed by ex199e136; profile=%s; generated=%s\n' "$profile" "$(date -Is 2>/dev/null || date)" > "$output" || return 1
    while IFS='|' read -r id key dflt rec risk note reset; do
        _e126_sysctl_supported "$key" || continue
        value=$(_e126_profile_value "$profile" "$key" "$rec") || continue
        printf '%s = %s\n' "$key" "$value" >> "$output" || return 1
    done < <(_e126_accel_metadata)
    _e126_validate_candidate "$output"
}

_e126_backup_file() {
    local path="$1" name="$2" backup="$3"
    if test -e "$path" || test -L "$path"; then
        cp -a -- "$path" "$backup/$name" || return 1
        : > "$backup/$name.present"
    else
        : > "$backup/$name.absent"
    fi
}

_e126_restore_file() {
    local path="$1" name="$2" backup="$3"
    if test -e "$backup/$name.present"; then
        mkdir -p "$(dirname "$path")" || return 1
        rm -f -- "$path" 2>/dev/null || true
        cp -a -- "$backup/$name" "$path" || return 1
    else
        rm -f -- "$path" 2>/dev/null || true
    fi
}

_e126_baseline_get() {
    local wanted="$1" key value
    test -s "$E126_ACCEL_BASELINE" || return 1
    while IFS='|' read -r key value; do
        test "$key" = "$wanted" || continue
        printf '%s\n' "$value"
        return 0
    done < "$E126_ACCEL_BASELINE"
    return 1
}

_e126_baseline_put_once() {
    local key="$1" value="$2" tmp
    test -n "$key" && test -n "$value" || return 1
    if _e126_baseline_get "$key" >/dev/null 2>&1; then return 0; fi
    mkdir -p "$E126_ACCEL_DIR" || return 1
    tmp="${E126_ACCEL_BASELINE}.new.$$"
    if test -s "$E126_ACCEL_BASELINE"; then cp -f -- "$E126_ACCEL_BASELINE" "$tmp" || return 1
    else printf '# ex199e136 immutable pre-management runtime baseline\n' > "$tmp" || return 1
    fi
    printf '%s|%s\n' "$key" "$(_e126_norm "$value")" >> "$tmp" || { rm -f -- "$tmp"; return 1; }
    chmod 0600 "$tmp" || { rm -f -- "$tmp"; return 1; }
    mv -f -- "$tmp" "$E126_ACCEL_BASELINE" || { rm -f -- "$tmp"; return 1; }
}

_e126_baseline_ensure_candidate() {
    local candidate="$1" key value current
    while IFS='=' read -r key value; do
        key=$(_e126_norm "$key"); case "$key" in ""|'#'*) continue ;; esac
        _e126_baseline_get "$key" >/dev/null 2>&1 && continue
        current=$(_e126_current "$key" 2>/dev/null || true)
        test -n "$current" || { error "无法读取原始基线：$key"; return 1; }
        _e126_baseline_put_once "$key" "$current" || return 1
    done < "$candidate"
}

_e126_restore_key_from_baseline() {
    local key="$1" value actual
    value=$(_e126_baseline_get "$key" 2>/dev/null || true)
    test -n "$value" || { error "缺少原始基线，不能可靠恢复：$key"; return 1; }
    _e126_validate_value "$key" "$value" || { error "原始基线格式异常：$key=$value"; return 1; }
    case "$key" in
        net.core.default_qdisc) modprobe "sch_${value}" >/dev/null 2>&1 || true ;;
        net.ipv4.tcp_congestion_control) modprobe "tcp_${value}" >/dev/null 2>&1 || true ;;
    esac
    sysctl -w "$key=$value" >/dev/null 2>&1 || { error "恢复原始基线失败：$key"; return 1; }
    actual=$(_e126_current "$key" 2>/dev/null || true)
    test "$actual" = "$value" || { error "原始基线读回不一致：$key，期望=$value，实际=$actual"; return 1; }
}

_e126_restore_removed_keys() {
    local oldconf="$1" candidate="$2" key value failed=0
    test -s "$oldconf" || return 0
    while IFS='=' read -r key value; do
        key=$(_e126_norm "$key"); case "$key" in ""|'#'*) continue ;; esac
        if ! awk -F= -v wanted="$key" '
            /^[[:space:]]*#/ {next}
            index($0,"=") {k=$1; gsub(/^[[:space:]]+|[[:space:]]+$/,"",k); if(k==wanted) found=1}
            END{exit !found}' "$candidate"; then
            _e126_restore_key_from_baseline "$key" || failed=1
        fi
    done < "$oldconf"
    test "$failed" -eq 0
}

_e126_restore_all_baselines() {
    local key value failed=0
    test -s "$E126_ACCEL_BASELINE" || { warn "没有可用的 E126 原始基线。"; return 1; }
    while IFS='|' read -r key value; do
        case "$key" in ""|'#'*) continue ;; esac
        _e126_restore_key_from_baseline "$key" || failed=1
    done < "$E126_ACCEL_BASELINE"
    test "$failed" -eq 0
}

_e126_seed_baseline_from_legacy() {
    local candidate="$1" key value reset meta runtime file source="" tmp
    mkdir -p "$E126_ACCEL_DIR" || return 1
    test -s "$E126_ACCEL_BASELINE" && return 0
    tmp="${E126_ACCEL_BASELINE}.legacy-new.$$"
    printf '# ex199e136 reconstructed pre-E125 baseline\n' > "$tmp" || return 1
    while IFS='=' read -r key value; do
        key=$(_e126_norm "$key"); case "$key" in ""|'#'*) continue ;; esac
        test -n "$(_e126_meta_by_key "$key")" || continue
        value=""; source=""
        while IFS= read -r file; do
            runtime=${file#* }
            value=$(awk -F'|' -v wanted="$key" '$1==wanted{print substr($0,index($0,"|")+1); exit}' "$runtime" 2>/dev/null || true)
            if test -n "$value"; then source="legacy-backup"; break; fi
        done < <(find "$E126_LEGACY_ACCEL_DIR/backups" -mindepth 2 -maxdepth 2 -type f -name runtime.before -printf '%T@ %p\n' 2>/dev/null | sort -n)
        if test -z "$value"; then
            meta=$(_e126_meta_by_key "$key")
            reset=$(printf '%s\n' "$meta" | cut -d'|' -f7)
            if [[ "$key" != net.core.default_qdisc && "$key" != net.ipv4.tcp_congestion_control ]] \
                && test -n "$reset" && _e126_validate_value "$key" "$reset"; then value="$reset"; source="documented-default"
            else value=$(_e126_current "$key" 2>/dev/null || true); source="legacy-current-fallback"
            fi
        fi
        test -n "$value" || { rm -f -- "$tmp"; error "无法为旧 E125 参数重建基线：$key"; return 1; }
        _e126_validate_value "$key" "$value" || { rm -f -- "$tmp"; error "旧 E125 基线值非法：$key=$value"; return 1; }
        printf '%s|%s\n' "$key" "$(_e126_norm "$value")" >> "$tmp" || return 1
        printf 'baseline %-34s <- %s\n' "$key" "$source" >&2
    done < "$candidate"
    chmod 0600 "$tmp" && mv -f -- "$tmp" "$E126_ACCEL_BASELINE"
}

_e126_write_boot_assets() {
    local script_tmp unit_tmp
    script_tmp=$(_e118_mktemp accel-e126.sh) || return 1
    unit_tmp=$(_e118_mktemp accel-e126.service) || return 1
    cat > "$script_tmp" <<'EOF_E126_BOOT'
#!/usr/bin/env bash
set -u
PATH=/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin
CONF=/etc/sysctl.d/99-xray-e126-accel.conf
STATE=/usr/local/etc/xray/e126_accel/state.env
BASELINE=/usr/local/etc/xray/e126_accel/baseline.env
mkdir -p "$(dirname "$STATE")"
failed=0 applied=0 details="" rollback="not-needed"
write_state() {
    local result="$1" tmp="${STATE}.new.$$"
    {
        printf 'time=%s\n' "$(date '+%F %T')"
        printf 'result=%s\n' "$result"
        printf 'applied=%s\nfailed=%s\n' "$applied" "$failed"
        printf 'rollback=%s\n' "$rollback"
        printf 'details=%s\n' "${details# }"
    } > "$tmp" || { rm -f -- "$tmp"; return 1; }
    chmod 600 "$tmp" && mv -f -- "$tmp" "$STATE" || { rm -f -- "$tmp"; return 1; }
}
restore_baseline() {
    local wanted key value actual restore_failed=0
    test -s "$BASELINE" || return 1
    while IFS='|' read -r key value; do
        case "$key" in ""|'#'*) continue ;; esac
        wanted=0
        while IFS= read -r line || test -n "$line"; do
            line=$(printf '%s\n' "$line" | awk '{$1=$1; print}')
            case "$line" in ""|'#'*) continue ;; esac
            test "$(printf '%s' "${line%%=*}" | awk '{$1=$1; print}')" = "$key" && { wanted=1; break; }
        done < "$CONF"
        test "$wanted" -eq 1 || continue
        case "$key" in
            net.core.default_qdisc) modprobe "sch_${value}" >/dev/null 2>&1 || true ;;
            net.ipv4.tcp_congestion_control) modprobe "tcp_${value}" >/dev/null 2>&1 || true ;;
        esac
        if ! sysctl -w "$key=$value" >/dev/null 2>&1; then restore_failed=1; continue; fi
        actual=$(sysctl -n "$key" 2>/dev/null | awk '{$1=$1; print}')
        test "$actual" = "$value" || restore_failed=1
    done < "$BASELINE"
    test "$restore_failed" -eq 0
}
if test ! -s "$CONF"; then
    write_state unmanaged || exit 1
    exit 0
fi
while IFS= read -r line || test -n "$line"; do
    line=$(printf '%s\n' "$line" | awk '{$1=$1; print}')
    case "$line" in ""|'#'*) continue ;; esac
    key=$(printf '%s' "${line%%=*}" | awk '{$1=$1; print}')
    value=$(printf '%s' "${line#*=}" | awk '{$1=$1; print}')
    case "$key" in
        net.core.default_qdisc) modprobe "sch_${value}" >/dev/null 2>&1 || true ;;
        net.ipv4.tcp_congestion_control) modprobe "tcp_${value}" >/dev/null 2>&1 || true ;;
    esac
    if sysctl -w "$key=$value" >/dev/null 2>&1; then
        actual=$(sysctl -n "$key" 2>/dev/null | awk '{$1=$1; print}')
        if test "$actual" = "$value"; then applied=$((applied+1)); else failed=$((failed+1)); details="$details verify:$key"; fi
    else
        failed=$((failed+1)); details="$details apply:$key"
    fi
done < "$CONF"
if test "$failed" -ne 0; then
    if restore_baseline; then rollback=ok; else rollback=failed; fi
    write_state failed || exit 1
    exit 1
fi
write_state ok || exit 1
exit 0
EOF_E126_BOOT
    cat > "$unit_tmp" <<'EOF_E126_UNIT'
[Unit]
Description=Xray V199e137 managed network acceleration parameters
After=systemd-sysctl.service
Before=xray.service
Wants=systemd-sysctl.service

[Service]
Type=oneshot
ExecStart=/usr/local/bin/xray-accel-e126.sh
RemainAfterExit=yes

[Install]
WantedBy=multi-user.target
EOF_E126_UNIT
    install -m 0755 -- "$script_tmp" "${E126_ACCEL_BOOT_SCRIPT}.new.$$" || return 1
    mv -f -- "${E126_ACCEL_BOOT_SCRIPT}.new.$$" "$E126_ACCEL_BOOT_SCRIPT" || return 1
    install -m 0644 -- "$unit_tmp" "${E126_ACCEL_SERVICE}.new.$$" || return 1
    mv -f -- "${E126_ACCEL_SERVICE}.new.$$" "$E126_ACCEL_SERVICE" || return 1
}

_e126_restore_runtime() {
    local file="$1" key value
    test -s "$file" || return 0
    while IFS='|' read -r key value; do
        test -n "$key" || continue
        sysctl -w "$key=$value" >/dev/null 2>&1 || true
    done < "$file"
}

_e126_rollback() {
    local backup="$1" was_enabled was_active
    _e126_restore_runtime "$backup/runtime.before"
    systemctl disable --now xray-accel-e126.service >/dev/null 2>&1 || true
    _e126_restore_file "$E126_ACCEL_CONF" conf "$backup" || true
    _e126_restore_file "$E126_ACCEL_BOOT_SCRIPT" script "$backup" || true
    _e126_restore_file "$E126_ACCEL_SERVICE" service "$backup" || true
    _e126_restore_file "$E126_ACCEL_BASELINE" baseline "$backup" || true
    _e126_restore_file "$E126_ACCEL_STATE" state "$backup" || true
    systemctl daemon-reload >/dev/null 2>&1 || true
    was_enabled=$(cat "$backup/service.enabled" 2>/dev/null || echo 0)
    was_active=$(cat "$backup/service.active" 2>/dev/null || echo 0)
    test "$was_enabled" = 1 && systemctl enable xray-accel-e126.service >/dev/null 2>&1 || true
    test "$was_active" = 1 && systemctl start xray-accel-e126.service >/dev/null 2>&1 || true
}

_e126_file_has_key() {
    local file="$1" wanted="$2"
    test -s "$file" || return 1
    awk -F= -v wanted="$wanted" '
      /^[[:space:]]*#/ {next}
      index($0,"=") {k=$1; gsub(/^[[:space:]]+|[[:space:]]+$/,"",k); if(k==wanted) found=1}
      END{exit !found}' "$file"
}

_e126_apply_candidate() {
    local candidate="$1" label="${2:-custom}" backup key value actual failed=0 id dflt rec risk note reset state_tmp
    _e126_validate_candidate "$candidate" || return 1
    mkdir -p "$E126_ACCEL_BACKUP_DIR" || return 1
    chmod 700 "$E126_ACCEL_DIR" "$E126_ACCEL_BACKUP_DIR" 2>/dev/null || true
    backup=$(mktemp -d "$E126_ACCEL_BACKUP_DIR/$(date +%Y%m%d_%H%M%S)-XXXXXX") || return 1
    chmod 700 "$backup" 2>/dev/null || true
    _e126_backup_file "$E126_ACCEL_CONF" conf "$backup" || return 1
    _e126_backup_file "$E126_ACCEL_BOOT_SCRIPT" script "$backup" || return 1
    _e126_backup_file "$E126_ACCEL_SERVICE" service "$backup" || return 1
    _e126_backup_file "$E126_ACCEL_BASELINE" baseline "$backup" || return 1
    _e126_backup_file "$E126_ACCEL_STATE" state "$backup" || return 1
    systemctl is-enabled --quiet xray-accel-e126.service 2>/dev/null && echo 1 > "$backup/service.enabled" || echo 0 > "$backup/service.enabled"
    systemctl is-active --quiet xray-accel-e126.service 2>/dev/null && echo 1 > "$backup/service.active" || echo 0 > "$backup/service.active"
    _e126_baseline_ensure_candidate "$candidate" || { _e126_rollback "$backup"; return 1; }
    : > "$backup/runtime.before"
    while IFS='|' read -r id key dflt rec risk note reset; do
        if ! _e126_file_has_key "$candidate" "$key" && ! _e126_file_has_key "$backup/conf" "$key"; then continue; fi
        value=$(_e126_current "$key") || value=""
        test -n "$value" && printf '%s|%s\n' "$key" "$value" >> "$backup/runtime.before"
    done < <(_e126_accel_metadata)

    _e126_prepare_modules "$candidate"
    while IFS='=' read -r key value; do
        key=$(_e126_norm "$key"); case "$key" in ""|'#'*) continue ;; esac
        value=$(_e126_norm "$value")
        if ! sysctl -w "$key=$value" >/dev/null 2>&1; then error "运行态写入失败：$key"; failed=1; break; fi
        actual=$(_e126_current "$key")
        if test "$actual" != "$value"; then error "运行态读回不一致：$key，期望=$value，实际=$actual"; failed=1; break; fi
    done < "$candidate"
    if test "$failed" -ne 0; then _e126_rollback "$backup"; error "E126 参数事务失败，已回滚运行态与文件。快照：$backup"; return 1; fi

    install -m 0644 -- "$candidate" "${E126_ACCEL_CONF}.new.$$" \
        && mv -f -- "${E126_ACCEL_CONF}.new.$$" "$E126_ACCEL_CONF" \
        && _e126_write_boot_assets \
        && systemctl daemon-reload >/dev/null 2>&1 \
        && systemctl enable --now xray-accel-e126.service >/dev/null 2>&1 \
        || failed=1
    if test "$failed" -eq 0; then
        _e126_restore_removed_keys "$backup/conf" "$candidate" || failed=1
    fi
    if test "$failed" -ne 0 || ! systemctl is-active --quiet xray-accel-e126.service; then
        _e126_rollback "$backup"
        error "E126 持久化/开机复检安装失败，已回滚。快照：$backup"
        return 1
    fi
    state_tmp="${E126_ACCEL_STATE}.new.$$"
    {
        echo "time=$(date '+%F %T')"; echo "result=ok"; echo "profile=$label"
        echo "config=$E126_ACCEL_CONF"; echo "backup=$backup"
        echo "baseline=$E126_ACCEL_BASELINE"
    } > "$state_tmp" || {
        rm -f -- "$state_tmp" 2>/dev/null || true
        _e126_rollback "$backup"
        error "E126 状态原子提交失败，已回滚参数事务。"
        return 1
    }
    if ! chmod 600 "$state_tmp" || ! mv -f -- "$state_tmp" "$E126_ACCEL_STATE"; then
        rm -f -- "$state_tmp" 2>/dev/null || true
        _e126_rollback "$backup"
        error "E126 状态原子提交失败，已回滚参数事务。"
        return 1
    fi
    info "E126 参数已事务应用并写入开机复检：$label"
    info "回滚快照：$backup"
    _e126_prune_backups
}

_e126_prune_backups() {
    local keep=12 line dir count=0
    test -d "$E126_ACCEL_BACKUP_DIR" || return 0
    while IFS= read -r line; do
        count=$((count+1))
        test "$count" -le "$keep" && continue
        dir=${line#* }
        case "$dir" in "$E126_ACCEL_BACKUP_DIR"/*) rm -rf -- "$dir" 2>/dev/null || true ;; esac
    done < <(find "$E126_ACCEL_BACKUP_DIR" -mindepth 1 -maxdepth 1 -type d -printf '%T@ %p\n' 2>/dev/null | sort -nr)
}

_e126_apply_profile() {
    local profile="$1" label="$2" confirm="" candidate
    candidate=$(_e118_mktemp accel-profile.conf) || return 1
    _e126_build_profile "$profile" "$candidate" || return 1
    warn "网络参数会影响全部新建 TCP 连接；现有连接通常不会立刻体现拥塞控制变化。"
    read -rp "输入 APPLY 确认应用【$label】: " confirm || true
    test "$confirm" = "APPLY" || { info "已取消。"; return 0; }
    _e126_apply_candidate "$candidate" "$label"
}

_e126_edit_one() {
    local id="" meta key dflt rec risk note reset input candidate oldkey oldvalue found=0
    read -rp "输入参数编号 01~31: " id || true
    meta=$(_e126_meta_by_id "$id")
    test -n "$meta" || { error "参数编号不存在。"; return 1; }
    IFS='|' read -r id key dflt rec risk note reset <<< "$meta"
    echo "参数：$key"
    echo "当前：$(_e126_current "$key" 2>/dev/null || echo unsupported)"
    echo "Linux默认：$dflt"
    echo "E126推荐：$rec"
    echo "说明：$note"
    echo "输入 R=推荐值，D=文档默认值，U=从E126取消管理，或直接输入新值。"
    read -rp "新值: " input || true
    case "$input" in
        r|R) input="$rec" ;;
        d|D)
            test -n "$reset" || { error "该参数默认值由内核/RAM/发行版动态决定，不能伪造固定默认；请用 U 取消管理。"; return 1; }
            input="$reset"
            ;;
        u|U)
            if ! _e126_is_managed "$key"; then info "$key 当前未由 E126 管理，无需取消。"; return 0; fi
            input=""
            ;;
        "") info "未输入，已取消。"; return 0 ;;
    esac
    if test -n "$input"; then
        if test "$key" = net.ipv4.tcp_congestion_control && [[ "$input" == *'（'* ]]; then input=$(_e126_pick_cc); fi
        _e126_validate_value "$key" "$input" || { error "输入值不符合该参数的安全范围/格式。"; return 1; }
    fi
    candidate=$(_e118_mktemp accel-custom.conf) || return 1
    printf '# Managed by ex199e136; custom; generated=%s\n' "$(date -Is 2>/dev/null || date)" > "$candidate"
    if test -s "$E126_ACCEL_CONF"; then
        while IFS='=' read -r oldkey oldvalue; do
            oldkey=$(_e126_norm "$oldkey"); case "$oldkey" in ""|'#'*) continue ;; esac
            test "$oldkey" = "$key" && { found=1; continue; }
            test -n "$(_e126_meta_by_key "$oldkey")" || continue
            printf '%s = %s\n' "$oldkey" "$(_e126_norm "$oldvalue")" >> "$candidate"
        done < "$E126_ACCEL_CONF"
    fi
    test -n "$input" && printf '%s = %s\n' "$key" "$(_e126_norm "$input")" >> "$candidate"
    if ! grep -Eq '^[A-Za-z0-9_.]+[[:space:]]*=' "$candidate"; then
        _e126_remove_layer "single-last-key"
        return $?
    fi
    _e126_apply_candidate "$candidate" "custom:$key"
}

_e126_show_table() {
    local id key dflt rec risk note reset current flag iface qdisc
    title "V199e137：跨境代理网络参数集合（当前 / Linux默认 / E126推荐）"
    while IFS='|' read -r id key dflt rec risk note reset; do
        current=$(_e126_current "$key" 2>/dev/null || echo unsupported)
        if _e126_is_managed "$key"; then flag="已管"; else flag="未管"; fi
        printf '  [%s] %-34s 当前=%-18s [%s]\n' "$id" "$key" "$current" "$flag"
        printf '       默认=%-28s E126=%s\n' "$dflt" "$rec"
        printf '       风险=%s；%s\n' "$risk" "$note"
    done < <(_e126_accel_metadata)
    echo
    echo "  注：默认值取自 Linux 内核文档；标注动态/发行版决定的项目不冒充固定数值。"
    echo "      initcwnd/initrwnd=30 仍由菜单13管理，不在本集合重复写入。"
    iface=$(ip route show default 2>/dev/null | awk 'NR==1{print $5}')
    if [[ "$iface" =~ ^[A-Za-z0-9_.:-]+$ ]]; then
        qdisc=$(tc qdisc show dev "$iface" 2>/dev/null | paste -sd';' - | cut -c1-220 || true)
        echo "      当前默认路由网卡=$iface；实际 qdisc=${qdisc:-unavailable}"
        echo "      default_qdisc 只决定新建队列；E126 不会覆盖菜单20的 CAKE/HTB/TBF/netem。"
    fi
}

_e126_show_status() {
    local enabled active
    enabled=$(systemctl is-enabled xray-accel-e126.service 2>/dev/null | head -n1 || true)
    active=$(systemctl is-active xray-accel-e126.service 2>/dev/null | head -n1 || true)
    case "$enabled" in enabled|disabled|static|masked|indirect) ;; *) enabled=unavailable ;; esac
    case "$active" in active|inactive|failed|activating|deactivating) ;; *) active=unavailable ;; esac
    _e126_show_table
    echo
    echo "  持久化文件：$(test -s "$E126_ACCEL_CONF" && echo "$E126_ACCEL_CONF" || echo 未启用)"
    echo "  原始基线：$(test -s "$E126_ACCEL_BASELINE" && echo "$E126_ACCEL_BASELINE" || echo 未建立)"
    echo "  旧E125层：$(test -s "$E126_LEGACY_ACCEL_CONF" && echo 待热更新迁移 || echo none)"
    echo "  开机复检：$enabled / $active"
    echo "  最近状态："
    test -s "$E126_ACCEL_STATE" && sed 's/^/    /' "$E126_ACCEL_STATE" || echo "    尚无状态"
}

_e126_conflict_audit() {
    local id key dflt rec risk note reset file line found=0
    title "V199e137：其它 sysctl 来源冲突审计"
    while IFS='|' read -r id key dflt rec risk note reset; do
        for file in /etc/sysctl.conf /etc/sysctl.d/*.conf /run/sysctl.d/*.conf /usr/local/lib/sysctl.d/*.conf /usr/lib/sysctl.d/*.conf /lib/sysctl.d/*.conf; do
            test -f "$file" || continue
            test "$file" = "$E126_ACCEL_CONF" && continue
            line=$(awk -v wanted="$key" '
              /^[[:space:]]*#/ {next}
              index($0,"=") {k=$0; sub(/=.*/,"",k); gsub(/^[[:space:]]+|[[:space:]]+$/,"",k); if(k==wanted){print; exit}}
            ' "$file" 2>/dev/null || true)
            if test -n "$line"; then printf '  %-34s <- %s: %s\n' "$key" "$file" "$(_e126_norm "$line")"; found=1; fi
        done
    done < <(_e126_accel_metadata)
    test "$found" -eq 1 || info "未发现其它文件重复定义 E126 参数。"
    echo "说明：E126 开机服务在 systemd-sysctl 后再次应用自己的文件，因此无需删除发行版或用户配置。"
}

_e126_remove_layer() {
    local reason="${1:-menu}" confirm="" backup key value state_tmp was_enabled=0 was_active=0
    if test "$reason" != "uninstall"; then
        warn "此操作只移除 E126 管理层，然后重新加载系统/发行版现有 sysctl；历史配置可能重新接管。"
        read -rp "输入 REMOVE-E126 确认: " confirm || true
        test "$confirm" = "REMOVE-E126" || { info "已取消。"; return 0; }
    fi
    if test -s "$E126_LEGACY_ACCEL_CONF"; then
        _e126_remove_legacy_accel_with_restore || return 1
    fi
    mkdir -p "$E126_ACCEL_BACKUP_DIR" || { error "无法创建 E126 移除快照目录。"; return 1; }
    backup=$(mktemp -d "$E126_ACCEL_BACKUP_DIR/remove-$(date +%Y%m%d_%H%M%S)-XXXXXX") \
        || { error "无法创建 E126 移除快照。"; return 1; }
    chmod 0700 "$backup" 2>/dev/null || true
    if test -n "$backup"; then
        _e126_backup_file "$E126_ACCEL_CONF" conf "$backup" || { error "E126 配置快照失败。"; return 1; }
        _e126_backup_file "$E126_ACCEL_BOOT_SCRIPT" script "$backup" || { error "E126 启动脚本快照失败。"; return 1; }
        _e126_backup_file "$E126_ACCEL_SERVICE" service "$backup" || { error "E126 服务快照失败。"; return 1; }
        _e126_backup_file "$E126_ACCEL_BASELINE" baseline "$backup" || { error "E126 基线快照失败。"; return 1; }
        _e126_backup_file "$E126_ACCEL_STATE" state "$backup" || { error "E126 状态快照失败。"; return 1; }
        systemctl is-enabled --quiet xray-accel-e126.service 2>/dev/null && was_enabled=1 || true
        systemctl is-active --quiet xray-accel-e126.service 2>/dev/null && was_active=1 || true
        echo "$was_enabled" > "$backup/service.enabled"
        echo "$was_active" > "$backup/service.active"
        : > "$backup/runtime.before"
        if test -s "$E126_ACCEL_BASELINE"; then
            while IFS='|' read -r key value; do
                case "$key" in ""|'#'*) continue ;; esac
                value=$(_e126_current "$key" 2>/dev/null || true)
                test -n "$value" && printf '%s|%s\n' "$key" "$value" >> "$backup/runtime.before"
            done < "$E126_ACCEL_BASELINE"
        fi
    fi
    systemctl disable --now xray-accel-e126.service >/dev/null 2>&1 || true
    if test -s "$E126_ACCEL_CONF" && ! _e126_restore_all_baselines; then
        test -n "$backup" && _e126_rollback "$backup"
        error "E126 原始基线恢复失败，已撤销移除操作。"
        return 1
    fi
    rm -f -- "$E126_ACCEL_CONF" "$E126_ACCEL_BOOT_SCRIPT" "$E126_ACCEL_SERVICE" 2>/dev/null || true
    systemctl daemon-reload >/dev/null 2>&1 || true
    sysctl --system >/dev/null 2>&1 || warn "系统 sysctl 重载存在失败项；已先恢复 E126 原始基线，请用冲突审计定位其它失败项。"
    if test "$reason" != "uninstall"; then
        state_tmp="${E126_ACCEL_STATE}.new.$$"
        {
            echo "time=$(date '+%F %T')"; echo "result=removed"; echo "reason=$reason"
            echo "baseline_restored=yes"; echo "backup=${backup:-none}"
        } > "$state_tmp" && chmod 0600 "$state_tmp" && mv -f -- "$state_tmp" "$E126_ACCEL_STATE" \
            || { rm -f -- "$state_tmp" 2>/dev/null || true; warn "参数已恢复，但移除状态记录写入失败。"; }
        info "E126 管理层已移除。快照：${backup:-未创建}"
    fi
}

