        echo "  5) 立即按持久化文件重放并严格读回"
        echo "  6) 审计其它 sysctl 文件的重复定义"
        echo "  7) 移除 E126 层并恢复系统/发行版配置"
        echo "  0) 返回"
        read -rp "请输入操作代码: " num || true
        case "$num" in
