_e126_preinstall_integrity() {
    local p count keys dup
    bash -n "$SCRIPT_PATH" || { error "e126 脚本自身未通过 bash -n。"; return 1; }
    for p in _e126_accel_metadata _e126_validate_candidate _e126_apply_candidate _e126_write_boot_assets \
        _e126_accel_menu _e126_remove_layer _e126_baseline_ensure_candidate \
        _e126_restore_removed_keys _e126_restore_all_baselines _e126_seed_baseline_from_legacy; do
        declare -F "$p" >/dev/null 2>&1 || { error "e126 完整性函数缺失：$p"; return 1; }
    done
    count=$(_e126_accel_metadata | wc -l | tr -d ' ')
    test "$count" -eq 31 || { error "e126 参数元数据应为31项，实际$count。"; return 1; }
    keys=$(_e126_accel_metadata | cut -d'|' -f2)
    dup=$(printf '%s\n' "$keys" | sort | uniq -d | head -n1)
    test -z "$dup" || { error "e126 参数元数据重复：$dup"; return 1; }
    declare -f main_menu | grep -q '21) 跨境代理网络参数集合' || { error "主菜单21未接入。"; return 1; }
}

_e126_cleanup_legacy_accel() {
    systemctl disable --now xray-accel-e125.service >/dev/null 2>&1 || true
    rm -f -- "$E126_LEGACY_ACCEL_CONF" "$E126_LEGACY_ACCEL_BOOT_SCRIPT" "$E126_LEGACY_ACCEL_SERVICE" 2>/dev/null || true
    systemctl daemon-reload >/dev/null 2>&1 || true
}

# 热更新保留 E124 全部事务；迁移旧 E125，或重装并复检现有 E126 持久化层。
eval "$(declare -f hot_update_from_legacy | sed '1s/hot_update_from_legacy/_e126_hot_update_base/')" 2>/dev/null || true
hot_update_from_legacy() {
    local candidate legacy=0
    _e126_preinstall_integrity || return 1
    _e126_hot_update_base "$@" || return 1
    mkdir -p "$E126_ACCEL_DIR" "$E126_ACCEL_BACKUP_DIR" || return 1
    chmod 700 "$E126_ACCEL_DIR" "$E126_ACCEL_BACKUP_DIR" 2>/dev/null || true
    if test -s "$E126_ACCEL_CONF" || test -s "$E126_LEGACY_ACCEL_CONF"; then
        candidate=$(_e118_mktemp accel-hot-update.conf) || return 1
        if test -s "$E126_ACCEL_CONF"; then
            cp -f -- "$E126_ACCEL_CONF" "$candidate"
        else
            cp -f -- "$E126_LEGACY_ACCEL_CONF" "$candidate"
            sed -i 's/ex199e125/ex199e136/g; s/E125/E126/g' "$candidate" 2>/dev/null || true
            legacy=1
            _e126_seed_baseline_from_legacy "$candidate" || return 1
        fi
        _e126_apply_candidate "$candidate" "hot-update-preserve" || return 1
        _e126_cleanup_legacy_accel
        _e124_state_set "$E118_STATE_FILE" accel_e126 managed-and-verified || return 1
        test "$legacy" -eq 0 || info "旧 E125 参数层已迁移到 E126；原始基线已独立保留。"
    else
        _e126_cleanup_legacy_accel
        _e124_state_set "$E118_STATE_FILE" accel_e126 ready-unmanaged || return 1
        info "菜单21参数集合已就绪；未擅自改变现有网络参数。选择档位后将自动持久化并开机复检。"
    fi
    printf '%s\n' "$SCRIPT_VERSION" > "$SCRIPT_VERSION_FILE" 2>/dev/null || true
    info "V199e137 热更新完成：菜单21参数集合已保留并通过开机严格读回检查。"
}

# 自检叠加，不删减 E124 的 PBK/SS2022/SNI/端口回归。
eval "$(declare -f _e118_self_test | sed '1s/_e118_self_test/_e126_self_test_base/')" 2>/dev/null || true
_e118_self_test() {
    local rc=0 count dup body remove_body hot_body
    _e126_self_test_base || rc=1
    echo
    echo "V199e137 参数集合回归测试："
    count=$(_e126_accel_metadata | wc -l | tr -d ' ')
    test "$count" -eq 31 && echo "  [PASS] 31项参数元数据" || { echo "  [FAIL] 参数元数据数量=$count"; rc=1; }
    dup=$(_e126_accel_metadata | cut -d'|' -f2 | sort | uniq -d | head -n1)
    test -z "$dup" && echo "  [PASS] 参数键唯一" || { echo "  [FAIL] 参数键重复=$dup"; rc=1; }
    body=$(declare -f _e126_write_boot_assets)
    if [[ "$body" == *'After=systemd-sysctl.service'* && "$body" == *'Before=xray.service'* \
        && "$body" == *'restore_baseline'* && "$body" == *'write_state failed || exit 1'* \
        && "$body" == *'rollback=ok'* ]]; then echo "  [PASS] 开机逐项读回、失败整组恢复与状态写入校验"; else echo "  [FAIL] 开机失败回退实现缺失"; rc=1; fi
    body=$(declare -f _e126_apply_candidate)
    if [[ "$body" == *'_e126_baseline_ensure_candidate'* && "$body" == *'_e126_restore_removed_keys'* \
        && "$body" == *'runtime.before'* && "$body" == *'enable --now'* \
        && "$body" == *'baseline'* ]]; then echo "  [PASS] 原始基线、取消单项恢复与事务回滚"; else echo "  [FAIL] 参数基线/取消恢复缺失"; rc=1; fi
    remove_body=$(declare -f _e126_remove_layer)
    if [[ "$remove_body" == *'_e126_restore_all_baselines'* && "$remove_body" == *'sysctl --system'* \
        && "$remove_body" == *'_e126_rollback'* ]]; then echo "  [PASS] 移除层先恢复基线且失败撤销"; else echo "  [FAIL] 移除层可能残留运行值"; rc=1; fi
    hot_body="$(declare -f hot_update_from_legacy 2>/dev/null || true)$(declare -f _e127_hot_update_base 2>/dev/null || true)"
    if [[ "$hot_body" == *'E126_LEGACY_ACCEL_CONF'* && "$hot_body" == *'_e126_seed_baseline_from_legacy'* \
        && "$hot_body" == *'_e126_cleanup_legacy_accel'* ]]; then echo "  [PASS] E125 持久化层兼容迁移"; else echo "  [FAIL] E125 迁移路径缺失"; rc=1; fi
    declare -f main_menu | grep -q '21) 跨境代理网络参数集合' \
        && echo "  [PASS] 主菜单21接入" || { echo "  [FAIL] 主菜单21未接入"; rc=1; }
    echo "V199e137 参数集合回归结果：$(test "$rc" -eq 0 && echo PASS || echo FAIL)"
    return "$rc"
}

# 修复旧卸载包装器在确认前先拆 SSH/日志层的问题，并清理 E126 持久化。
_e126_remove_legacy_accel_with_restore() {
    local candidate
    test -s "$E126_LEGACY_ACCEL_CONF" || { _e126_cleanup_legacy_accel; return 0; }
    candidate=$(_e118_mktemp legacy-e125-remove.conf) || return 1
    cp -f -- "$E126_LEGACY_ACCEL_CONF" "$candidate" || return 1
    _e126_seed_baseline_from_legacy "$candidate" || return 1
    systemctl disable --now xray-accel-e125.service >/dev/null 2>&1 || true
    _e126_restore_all_baselines || { error "旧 E125 参数基线恢复失败，拒绝继续卸载。"; return 1; }
    _e126_cleanup_legacy_accel
    sysctl --system >/dev/null 2>&1 || warn "旧 E125 已移除，但其它系统 sysctl 存在加载失败项。"
}

do_uninstall() {
