#==============================================================================
# V199e137 XRAY CORE SURVIVAL LAYER
# 配置、Core、DAT 与 systemd 状态必须共同通过：校验 -> 原子写入 ->
# MainPID/端口稳定探针 -> 失败恢复原状态。菜单21继续沿用已验证的 E126 schema。
#==============================================================================

_e127_backup_dir_ok() {
    local bdir="${1:-}" real root
    test -n "$bdir" && test -d "$bdir" || return 1
    real=$(readlink -f -- "$bdir" 2>/dev/null || true)
    root=$(readlink -f -- "$E118_BACKUP_DIR" 2>/dev/null || true)
    test -n "$real" && test -n "$root" || return 1
    case "$real" in "$root"/*) return 0 ;; *) return 1 ;; esac
}

_e127_verify_state_snapshot() {
    local bdir="$1" base seen=""
    _e127_backup_dir_ok "$bdir" || { error "拒绝使用事务目录之外的快照：$bdir"; return 1; }
    test -f "$bdir/files.manifest" && test -f "$bdir/meta.env" || return 1
    while IFS= read -r base; do
        test -n "$base" || continue
        [[ "$base" =~ ^[A-Za-z0-9._-]+$ ]] || { error "快照文件名非法：$base"; return 1; }
        [[ " $seen " != *" $base "* ]] || { error "快照清单重复：$base"; return 1; }
        test -f "$bdir/$base" || { error "快照文件缺失：$base"; return 1; }
        seen="$seen $base"
    done < "$bdir/files.manifest"
    if test -s "$bdir/files.sha256"; then
        (cd "$bdir" && sha256sum -c files.sha256 >/dev/null 2>&1) \
            || { error "配置事务快照校验和失败：$bdir"; return 1; }
    fi
}

_e127_socket_ready() {
    local proto="$1" port="$2" pid="$3" out line
    case "$proto" in
        tcp) out=$(ss -H -ltnp 2>/dev/null || true) ;;
        udp) out=$(ss -H -lunp 2>/dev/null || true) ;;
        *) return 1 ;;
    esac
    line=$(printf '%s\n' "$out" | awk -v p=":$port" '$4 ~ p"$" {print; exit}')
    test -n "$line" || return 1
    # root 下若 ss 提供进程信息，就必须属于 MainPID/xray；内核不提供 users 字段时退化为端口+MainPID 双验证。
    if [[ "$line" == *"users:"* ]] && [[ "$line" != *"pid=$pid,"* ]] && [[ "$line" != *'"xray"'* ]]; then
        return 1
    fi
}

_e127_verify_xray_runtime() {
    local cfg="${1:-$CONFIG}" timeout="${2:-12}" i pid stable=0 req proto port network failed
    test -s "$cfg" || { error "Xray 运行态复检缺少配置：$cfg"; return 1; }
    _e118_xray_test_config "$cfg" 1 || return 1
    [[ "$timeout" =~ ^[0-9]+$ ]] || timeout=12
    test "$timeout" -ge 3 || timeout=3
    for ((i=1; i<=timeout; i++)); do
        failed=0
        systemctl is-active --quiet xray.service 2>/dev/null || failed=1
        pid=$(systemctl show xray.service -p MainPID --value 2>/dev/null || true)
        [[ "$pid" =~ ^[1-9][0-9]*$ ]] && kill -0 "$pid" 2>/dev/null || failed=1
        if test "$failed" -eq 0; then
            while IFS=$'\t' read -r proto port network; do
                test -n "$proto" && test -n "$port" || continue
                case "$proto" in
                    vless)
                        _e127_socket_ready tcp "$port" "$pid" || { failed=1; break; }
                        ;;
                    shadowsocks)
                        case ",${network:-tcp,udp}," in *,tcp,*) _e127_socket_ready tcp "$port" "$pid" || { failed=1; break; } ;; esac
                        case ",${network:-tcp,udp}," in *,udp,*) _e127_socket_ready udp "$port" "$pid" || { failed=1; break; } ;; esac
                        ;;
                esac
            done < <(jq -r '.inbounds[]? | select(.protocol=="vless" or .protocol=="shadowsocks") | [.protocol,(.port|tostring),(.settings.network//"tcp,udp")] | @tsv' "$cfg" 2>/dev/null)
        fi
        if test "$failed" -eq 0; then
            stable=$((stable+1))
            test "$stable" -ge 3 && return 0
        else
            stable=0
        fi
        sleep 1
    done
    error "Xray 未通过稳定运行探针：service/MainPID/配置端口未连续稳定3秒。"
    journalctl -u xray.service --no-pager -n 60 2>/dev/null | sed 's/^/    /' || true
    return 1
}

# 为新快照增加不可伪造的内容清单；旧快照仍兼容，但不会冒充已校验。
eval "$(declare -f _e116_backup_state | sed '1s/_e116_backup_state/_e127_backup_state_base/')" 2>/dev/null || true
_e116_backup_state() {
    local tag="${1:-manual}" bdir previous="" base
    previous=$(cat "$E118_DIR/latest_backup.txt" 2>/dev/null || true)
    bdir=$(_e127_backup_state_base "$tag") || return 1
    _e127_backup_dir_ok "$bdir" || return 1
    : > "$bdir/files.sha256" || return 1
    while IFS= read -r base; do
        test -n "$base" || continue
        (cd "$bdir" && sha256sum -- "$base") >> "$bdir/files.sha256" || {
            rm -rf -- "$bdir" 2>/dev/null || true
            if test -n "$previous"; then printf '%s\n' "$previous" > "$E118_DIR/latest_backup.txt"; else rm -f "$E118_DIR/latest_backup.txt"; fi
            return 1
        }
    done < "$bdir/files.manifest"
    chmod 0600 "$bdir/files.sha256" 2>/dev/null || true
    echo "$bdir"
}

_e118_restore_state() {
    local bdir="${1:-}" f base was_active=0 was_enabled=0 restore_failed=0
    _e127_verify_state_snapshot "$bdir" || return 1
    was_active=$(sed -n 's/^xray_was_active=//p' "$bdir/meta.env" 2>/dev/null | head -n1); was_active=${was_active:-0}
    was_enabled=$(sed -n 's/^xray_was_enabled=//p' "$bdir/meta.env" 2>/dev/null | head -n1); was_enabled=${was_enabled:-0}
    if grep -qx 'config.json' "$bdir/files.manifest" 2>/dev/null; then
        test -s "$bdir/config.json" || return 1
        _e118_xray_test_config "$bdir/config.json" 1 || return 1
    fi
    while IFS= read -r f; do
        test -n "$f" || continue
        base=$(basename "$f")
        if grep -qxF "$base" "$bdir/files.manifest" 2>/dev/null; then
            _e118_atomic_install "$bdir/$base" "$f" 0600 || { restore_failed=1; break; }
        else
            rm -f -- "$f" 2>/dev/null || true
        fi
    done < <(_e118_managed_state_files)
    test "$restore_failed" -eq 0 || return 1
    fix_permissions
    if test "$was_enabled" = 1; then systemctl enable xray.service >/dev/null 2>&1 || return 1
    else systemctl disable xray.service >/dev/null 2>&1 || true
    fi
    if test "$was_active" = 1; then
        systemctl reset-failed xray.service >/dev/null 2>&1 || true
        systemctl restart xray.service >/dev/null 2>&1 || return 1
        _e127_verify_xray_runtime "$CONFIG" 12 || return 1
    else
        systemctl stop xray.service >/dev/null 2>&1 || true
        systemctl is-active --quiet xray.service 2>/dev/null && return 1 || true
    fi
    E118_TX_ACTIVE=0; E118_TX_BACKUP=""; E118_TX_WAS_ACTIVE=0
    return 0
}

_e118_commit_config() {
    local candidate="$1" bdir="${2:-}" start_policy="${3:-preserve}" stage was_active=0 rollback_ok=0
    _e118_xray_test_config "$candidate" 1 || return 1
    if test -z "$bdir"; then bdir=$(_e116_backup_state "before_config_commit") || return 1; fi
    _e127_verify_state_snapshot "$bdir" || return 1
    was_active=$(sed -n 's/^xray_was_active=//p' "$bdir/meta.env" 2>/dev/null | head -n1); was_active=${was_active:-0}
    E118_TX_ACTIVE=1; E118_TX_BACKUP="$bdir"; E118_TX_WAS_ACTIVE="$was_active"
    stage="$CONFIG_DIR/.config.e127.$$"
    install -m 0600 "$candidate" "$stage" || { E118_TX_ACTIVE=0; E118_TX_BACKUP=""; return 1; }
    mv -f -- "$stage" "$CONFIG" || { rm -f -- "$stage"; E118_TX_ACTIVE=0; E118_TX_BACKUP=""; return 1; }
    fix_permissions
    if test "$was_active" = 1; then
        if ! systemctl restart xray.service >/dev/null 2>&1 || ! _e127_verify_xray_runtime "$CONFIG" 12; then
            error "新配置运行态探针失败，正在恢复旧配置。"
            _e127_rollback_config_or_emergency "$bdir" && rollback_ok=1 || rollback_ok=0
            test "$rollback_ok" -eq 1 || error "严重：旧配置自动恢复失败，快照：$bdir"
            test "$rollback_ok" -eq 1 && { E118_TX_ACTIVE=0; E118_TX_BACKUP=""; }
            return 1
        fi
    elif test "$start_policy" = start; then
        if ! systemctl enable xray.service >/dev/null 2>&1 \
            || ! systemctl start xray.service >/dev/null 2>&1 \
            || ! _e127_verify_xray_runtime "$CONFIG" 12; then
            error "新节点未通过启动探针，正在恢复建仓前状态。"
            _e127_rollback_config_or_emergency "$bdir" && rollback_ok=1 || rollback_ok=0
            test "$rollback_ok" -eq 1 || error "严重：建仓前状态自动恢复失败，快照：$bdir"
            test "$rollback_ok" -eq 1 && { E118_TX_ACTIVE=0; E118_TX_BACKUP=""; }
            return 1
        fi
    fi
    E118_TX_ACTIVE=0; E118_TX_BACKUP=""; E118_TX_WAS_ACTIVE=0
    return 0
}

eval "$(declare -f _e118_save_core_payload | sed '1s/_e118_save_core_payload/_e127_save_core_payload_base/')" 2>/dev/null || true
_e118_save_core_payload() {
    local bdir="$1" file rel item
    _e127_backup_dir_ok "$bdir" || return 1
    _e127_save_core_payload_base "$bdir" || return 1
    : > "$bdir/core-payload.sha256" || return 1
    for item in "$bdir/xray.core.before" "$bdir"/core-*.before "$bdir"/unit-*.before; do
        if test -f "$item"; then
            rel=${item#"$bdir"/}; (cd "$bdir" && sha256sum -- "$rel") >> "$bdir/core-payload.sha256" || return 1
        elif test -d "$item"; then
            while IFS= read -r file; do
                rel=${file#"$bdir"/}; (cd "$bdir" && sha256sum -- "$rel") >> "$bdir/core-payload.sha256" || return 1
            done < <(find "$item" -type f -print 2>/dev/null | sort)
        fi
    done
    chmod 0600 "$bdir/core-payload.sha256" 2>/dev/null || true
}

_e127_atomic_restore_dir() {
    local source="$1" target="$2" stage old
    test -d "$source" || return 1
    stage="${target}.e127-new.$$"; old="${target}.e127-old.$$"
    rm -rf -- "$stage" "$old" 2>/dev/null || true
    cp -a -- "$source" "$stage" || { rm -rf -- "$stage"; return 1; }
    if test -e "$target"; then mv -- "$target" "$old" || { rm -rf -- "$stage"; return 1; }; fi
    if ! mv -- "$stage" "$target"; then test -e "$old" && mv -- "$old" "$target" 2>/dev/null || true; return 1; fi
    rm -rf -- "$old" 2>/dev/null || true
}

_e118_restore_core_payload() {
    local bdir="$1" name path was_active=0 was_enabled=0
    _e127_backup_dir_ok "$bdir" || return 1
    test ! -e "$bdir/core-payload-pruned" || { error "该旧快照仅保留配置，Core 载荷已按空间策略收敛：$bdir"; return 1; }
    if test -s "$bdir/core-payload.sha256"; then
        (cd "$bdir" && sha256sum -c core-payload.sha256 >/dev/null 2>&1) \
            || { error "Core/DAT/systemd 回滚载荷校验和失败：$bdir"; return 1; }
    fi
    if test -f "$bdir/xray.core.before.sha256"; then
        (cd "$bdir" && sha256sum -c xray.core.before.sha256 >/dev/null 2>&1) || return 1
    fi
    was_active=$(sed -n 's/^xray_was_active=//p' "$bdir/meta.env" 2>/dev/null | head -n1); was_active=${was_active:-0}
    was_enabled=$(sed -n 's/^xray_was_enabled=//p' "$bdir/meta.env" 2>/dev/null | head -n1); was_enabled=${was_enabled:-0}
    if test -f "$bdir/xray.core.before"; then _e118_atomic_install "$bdir/xray.core.before" "$XRAY_BIN" 0755 || return 1
    elif test -e "$bdir/xray.core.was-absent"; then rm -f -- "$XRAY_BIN" 2>/dev/null || true
    fi
    for name in geoip.dat geosite.dat; do
        if test -f "$bdir/core-$name.before"; then _e118_atomic_install "$bdir/core-$name.before" "$DAT_DIR/$name" 0644 || return 1
        elif test -e "$bdir/core-$name.was-absent"; then rm -f -- "$DAT_DIR/$name" 2>/dev/null || true
        fi
    done
    for name in xray.service xray@.service; do
        path="/etc/systemd/system/$name"
        if test -f "$bdir/unit-$name.before"; then _e118_atomic_install "$bdir/unit-$name.before" "$path" 0644 || return 1
        elif test -e "$bdir/unit-$name.was-absent"; then rm -f -- "$path" 2>/dev/null || true
        fi
    done
    for name in xray.service.d xray@.service.d; do
        path="/etc/systemd/system/$name"
        if test -d "$bdir/unit-$name.before"; then _e127_atomic_restore_dir "$bdir/unit-$name.before" "$path" || return 1
        elif test -e "$bdir/unit-$name.was-absent"; then rm -rf -- "$path" 2>/dev/null || true
        fi
    done
    systemctl daemon-reload >/dev/null 2>&1 || return 1
    if test "$was_enabled" = 1; then systemctl enable xray.service >/dev/null 2>&1 || return 1
    else systemctl disable xray.service >/dev/null 2>&1 || true
    fi
    if test "$was_active" = 1; then
        test -x "$XRAY_BIN" && test -s "$CONFIG" || return 1
        _e118_xray_test_config "$CONFIG" 1 || return 1
        systemctl reset-failed xray.service >/dev/null 2>&1 || true
        systemctl restart xray.service >/dev/null 2>&1 || return 1
        _e127_verify_xray_runtime "$CONFIG" 12 || return 1
    else
        systemctl stop xray.service >/dev/null 2>&1 || true
        systemctl is-active --quiet xray.service 2>/dev/null && return 1 || true
    fi
}

ensure_xray_is_alive() {
    info "正在执行 Xray Core/MainPID/入站端口稳定复检。"
    test -s "$CONFIG" || { error "config.json 不存在。"; return 1; }
    _e118_xray_test_config "$CONFIG" 1 || return 1
    systemctl reset-failed xray.service >/dev/null 2>&1 || true
    if systemctl is-active --quiet xray.service 2>/dev/null; then systemctl restart xray.service >/dev/null 2>&1 || true
    else systemctl start xray.service >/dev/null 2>&1 || true
    fi
    _e127_verify_xray_runtime "$CONFIG" 12
}

do_update_core() {
    title "V199e137：Xray Core 手动更新 / 严格回滚"
    local go="" installer logf bdir was_active=0 was_enabled=0 failed=0
    read -rp "是否现在从 XTLS 官方安装器手动更新/修复 Xray Core？[y/N]: " go || true
    [[ "$go" =~ ^[yY]$ ]] || { info "已取消；Core 自动更新仍保持关闭。"; return 0; }
    test -s "$CONFIG" || { error "没有现有 config.json，无法做兼容性与回滚验证。"; return 1; }
    bdir=$(_e116_backup_state "before_core_update_e127") || { error "更新前状态快照失败。"; return 1; }
    _e118_save_core_payload "$bdir" || { error "旧 Core/DAT/systemd 载荷备份或校验和生成失败，拒绝更新。"; return 1; }
    was_active=$(sed -n 's/^xray_was_active=//p' "$bdir/meta.env" | head -n1); was_active=${was_active:-0}
    was_enabled=$(sed -n 's/^xray_was_enabled=//p' "$bdir/meta.env" | head -n1); was_enabled=${was_enabled:-0}
    installer=$(_e118_mktemp xray-update-e127.sh) || return 1
    logf=$(_e118_mktemp xray-update-e127.log) || return 1
    _e118_download_official_installer "$installer" || { error "官方安装脚本下载/校验失败，旧 Core 未动。"; return 1; }
    if ! bash "$installer" install >"$logf" 2>&1; then failed=1
    elif test ! -x "$XRAY_BIN" || ! "$XRAY_BIN" version >/dev/null 2>&1; then failed=1
    elif ! e76_ensure_xray_service; then failed=1
    else
        systemctl daemon-reload >/dev/null 2>&1 || failed=1
        fix_permissions
        _e118_xray_test_config "$CONFIG" 1 || failed=1
    fi
    if test "$failed" -eq 0; then
        if test "$was_enabled" = 1; then systemctl enable xray.service >/dev/null 2>&1 || failed=1
        else systemctl disable xray.service >/dev/null 2>&1 || true
        fi
        if test "$was_active" = 1; then
            systemctl restart xray.service >/dev/null 2>&1 || failed=1
            test "$failed" -ne 0 || _e127_verify_xray_runtime "$CONFIG" 12 || failed=1
        else
            systemctl stop xray.service >/dev/null 2>&1 || true
            systemctl is-active --quiet xray.service 2>/dev/null && failed=1 || true
        fi
    fi
    if test "$failed" -ne 0; then
        error "新 Core 安装或稳定探针失败，正在恢复旧 Core/DAT/systemd 状态。"
        tail -n 120 "$logf" 2>/dev/null | sed 's/^/    /' || true
        _e118_restore_core_payload "$bdir" || { error "严重：旧 Core 自动恢复失败，请立即使用快照：$bdir"; return 1; }
        return 1
    fi
    if declare -F _e105_disable_xray_core_auto_update >/dev/null 2>&1; then _e105_disable_xray_core_auto_update || true; fi
    _e127_prune_core_payload_backups
    info "Core 手动更新完成并保持原服务状态：$($XRAY_BIN version 2>/dev/null | head -n1)"
}

# 将配置提交后的元数据阶段重新纳入信号回滚窗口，避免新配置与旧 PBK/用户映射错配。
eval "$(declare -f _e116_install_mode | sed '1s/_e116_install_mode/_e127_install_mode_base/')" 2>/dev/null || true
_e116_install_mode() {
    # 基础实现内部仍负责全部交互和严格提交；其关键写入函数已由 E127 覆盖。
    _e127_install_mode_base "$@"
}

eval "$(declare -f hot_update_from_legacy | sed '1s/hot_update_from_legacy/_e127_hot_update_base/')" 2>/dev/null || true
hot_update_from_legacy() {
    local protect="" was_active=0 rc=0
    if test -s "$CONFIG" && test -x "$XRAY_BIN"; then
        protect=$(_e116_backup_state "before_hot_update_e127_core_survival") || { error "Core 生存快照失败，拒绝热更新。"; return 1; }
        _e118_save_core_payload "$protect" || { error "Core/DAT 生存载荷备份失败，拒绝热更新。"; return 1; }
        was_active=$(sed -n 's/^xray_was_active=//p' "$protect/meta.env" | head -n1); was_active=${was_active:-0}
    fi
    if _e127_hot_update_base "$@"; then rc=0; else rc=$?; fi
    if test -n "$protect" && test "$was_active" = 1; then
        if ! _e127_verify_xray_runtime "$CONFIG" 12; then
            error "热更新后 Xray 核心探针失败，启动生存回滚。"
            if ! _e118_restore_core_payload "$protect"; then
                _e118_restore_state "$protect" >/dev/null 2>&1 || true
                _e118_restore_core_payload "$protect" || { error "严重：Core 生存回滚失败：$protect"; return 1; }
            fi
            _e118_restore_state "$protect" || { error "严重：配置生存回滚失败：$protect"; return 1; }
            return 1
        fi
    elif test -n "$protect" && test "$was_active" = 0; then
        systemctl stop xray.service >/dev/null 2>&1 || true
    fi
    test "$rc" -ne 0 || _e127_prune_core_payload_backups
    return "$rc"
}

eval "$(declare -f _e121_check_and_clean_space | sed '1s/_e121_check_and_clean_space/_e127_clean_space_base/')" 2>/dev/null || true
_e121_check_and_clean_space() {
    test -n "${E121_LOG_RETENTION_SCRIPT:-}" || return 1
    _e127_clean_space_base "$@" || return 1
    _e127_prune_core_payload_backups
}

eval "$(declare -f _e118_self_test | sed '1s/_e118_self_test/_e127_self_test_base/')" 2>/dev/null || true
_e118_self_test() {
    local rc=0 body dat_body
    _e127_self_test_base || rc=1
    echo
    echo "V199e137 Xray Core 生存回归测试："
    body=$(declare -f _e118_commit_config)
    [[ "$body" == *'_e127_verify_xray_runtime'* && "$body" == *'_e127_rollback_config_or_emergency'* && "$body" == *'.config.e127'* ]] \
        && echo "  [PASS] 配置原子提交 + MainPID/端口探针 + 自动回滚" || { echo "  [FAIL] 配置生存事务缺失"; rc=1; }
    body=$(declare -f _e118_restore_core_payload)
    [[ "$body" == *'core-payload.sha256'* && "$body" == *'was_enabled'* && "$body" == *'_e127_verify_xray_runtime'* ]] \
        && echo "  [PASS] Core/DAT 校验和与 active/enabled 双状态恢复" || { echo "  [FAIL] Core 回滚保护缺失"; rc=1; }
    body=$(declare -f hot_update_from_legacy)
    [[ "$body" == *'core_survival'* && "$body" == *'_e118_restore_core_payload'* && "$body" == *'_e127_verify_xray_runtime'* ]] \
        && echo "  [PASS] 热更新 Core 生存快照与外围失败隔离" || { echo "  [FAIL] 热更新生存保护缺失"; rc=1; }
    body=$(declare -f _e126_write_boot_assets)
    [[ "$body" == *'Before=xray.service'* && "$body" != *'Requires=xray.service'* ]] \
        && echo "  [PASS] 参数层失败不会阻止 Xray 启动" || { echo "  [FAIL] 参数层可能阻断 Xray"; rc=1; }
    dat_body=$(declare -f _e118_impl_install_update_dat 2>/dev/null || declare -f install_update_dat 2>/dev/null || true)
    [[ "$dat_body" == *'atomic_put'* && "$dat_body" == *'verify_runtime'* && "$dat_body" == *'CRITICAL'* ]] \
        && echo "  [PASS] DAT 原子回滚与 Xray 稳定探针" || { echo "  [FAIL] DAT 更新可能只检查瞬时 active"; rc=1; }
    body="$(declare -f _e127_install_mode_base 2>/dev/null || true)$(declare -f _e118_write_generated_metadata 2>/dev/null || true)$(declare -f _e124_write_generated_metadata_base 2>/dev/null || true)"
    [[ "$body" == *'E118_TX_ACTIVE=1'* && "$body" == *'_e118_atomic_install'* && "$body" == *'_e118_write_generated_metadata'* ]] \
        && echo "  [PASS] config 与 PBK/用户元数据处于同一回滚窗口" || { echo "  [FAIL] 配置与客户端元数据可能错配"; rc=1; }
    echo "V199e137 Core 生存回归结果：$(test "$rc" -eq 0 && echo PASS || echo FAIL)"
    return "$rc"
}

#==============================================================================
# V199e137 FINAL REPLACEMENT LAYER
# - Nice=-20 配置值 + Xray MainPID 实际 NI 双验证
# - Reality 单 target / 单 SNI；用户不再拥有互相冲突的专属 SNI
# - XanMod 官方 APT archive.key / codename 仓库流程
# - XanMod 源码按 GitLab Tag commit 锁定、bindeb-pkg 打包、严格安装校验
# - 热更新保留 DAT 每日 03:00；只关闭 Xray Core 自动更新
# - initcwnd/initrwnd 默认 30；SSH 第2次失败封36小时；日志保留3天
#==============================================================================

readonly E131_LIMITS_FILE="/etc/systemd/system/xray.service.d/limits.conf"
readonly E131_XANMOD_KEYRING="/etc/apt/keyrings/xanmod-archive-keyring.gpg"
readonly E131_XANMOD_LIST="/etc/apt/sources.list.d/xanmod-release.list"
readonly E131_KERNEL_BUILD_ROOT="/var/tmp/xray-kernel-builds"

_e131_atomic_text_file() {
    local target="$1" mode="$2" tmp
    mkdir -p "$(dirname "$target")" || return 1
    tmp="$(dirname "$target")/.${target##*/}.e131.$$"
    cat > "$tmp" || { rm -f -- "$tmp"; return 1; }
    chmod "$mode" "$tmp" || { rm -f -- "$tmp"; return 1; }
    mv -f -- "$tmp" "$target" || { rm -f -- "$tmp"; return 1; }
}

_e131_xray_main_pid() {
    systemctl show xray.service -p MainPID --value 2>/dev/null | tr -cd '0-9'
}

_e131_verify_nice_runtime() {
    local unit_nice pid proc_nice
    unit_nice=$(systemctl show xray.service -p Nice --value 2>/dev/null || true)
    test "$unit_nice" = "-20" || { error "systemd 解析后的 Xray Nice=${unit_nice:-读取失败}，要求 -20。"; return 1; }
    if systemctl is-active --quiet xray.service 2>/dev/null; then
        pid=$(_e131_xray_main_pid)
        [[ "$pid" =~ ^[0-9]+$ ]] && test "$pid" -gt 1 2>/dev/null || { error "Xray active 但 MainPID 无效。"; return 1; }
        proc_nice=$(ps -o ni= -p "$pid" 2>/dev/null | tr -d '[:space:]' || true)
        test "$proc_nice" = "-20" || { error "Xray MainPID=$pid 实际 NI=${proc_nice:-读取失败}，要求 -20。"; return 1; }
    fi
    return 0
}

fix_xray_systemd_limits() {
    local dir old tmp total_mem go_mem_limit cores was_active=0
    dir=$(dirname "$E131_LIMITS_FILE")
    mkdir -p "$dir" || return 1
    old=$(_e118_mktemp xray-limits-before.conf) || return 1
    if test -f "$E131_LIMITS_FILE"; then cp -a -- "$E131_LIMITS_FILE" "$old" || return 1; else : > "$old"; fi
    systemctl is-active --quiet xray.service 2>/dev/null && was_active=1 || true
    total_mem=$(awk '/MemTotal:/{print int($2/1024)}' /proc/meminfo 2>/dev/null || echo 1024)
    [[ "$total_mem" =~ ^[0-9]+$ ]] || total_mem=1024
    go_mem_limit=$((total_mem * 80 / 100)); test "$go_mem_limit" -ge 128 || go_mem_limit=128
    cores=$(nproc 2>/dev/null || echo 1); [[ "$cores" =~ ^[0-9]+$ ]] || cores=1
    tmp=$(_e118_mktemp xray-limits.conf) || return 1
    cat > "$tmp" <<EOF_E131_LIMITS
[Service]
LimitNOFILE=1048576
LimitNPROC=262144
LimitMEMLOCK=infinity
LimitSTACK=8M
TasksMax=infinity
Nice=-20
OOMScoreAdjust=-500
IOSchedulingClass=best-effort
IOSchedulingPriority=0
Environment="GOMEMLIMIT=${go_mem_limit}MiB"
Environment="GOGC=300"
Environment="GOMAXPROCS=${cores}"
Restart=on-failure
RestartSec=5s
EOF_E131_LIMITS
    install -m 0644 "$tmp" "$E131_LIMITS_FILE" || return 1
    if ! systemctl daemon-reload >/dev/null 2>&1; then
        if test -s "$old"; then install -m 0644 "$old" "$E131_LIMITS_FILE"; else rm -f -- "$E131_LIMITS_FILE"; fi
        systemctl daemon-reload >/dev/null 2>&1 || true
        return 1
    fi
    if test "$was_active" -eq 1; then
        if ! systemctl restart xray.service >/dev/null 2>&1 || ! _e127_verify_xray_runtime "$CONFIG" 12 || ! _e131_verify_nice_runtime; then
            error "Nice=-20 或 Xray 运行验证失败，恢复旧 systemd drop-in。"
            if test -s "$old"; then install -m 0644 "$old" "$E131_LIMITS_FILE"; else rm -f -- "$E131_LIMITS_FILE"; fi
            systemctl daemon-reload >/dev/null 2>&1 || true
            systemctl restart xray.service >/dev/null 2>&1 || true
            return 1
        fi
    else
        systemctl show xray.service -p Nice --value 2>/dev/null | grep -qx -- '-20' || {
            if test -s "$old"; then install -m 0644 "$old" "$E131_LIMITS_FILE"; else rm -f -- "$E131_LIMITS_FILE"; fi
            systemctl daemon-reload >/dev/null 2>&1 || true
            return 1
        }
    fi
    return 0
}

apply_process_priority_default() { fix_xray_systemd_limits; }
check_process_priority_state() { _e131_verify_nice_runtime >/dev/null 2>&1 && echo true || echo false; }

# 不再写入 Xray 26 已无意义/易冲突的 routing.domainMatcher=mph。
force_apply_xray_core_defaults_e52() {
    test -s "$CONFIG" || return 1
    _safe_jq_write '
      .log = (.log // {}) |
      .log.access = "none" |
      .log.error = "none" |
      .log.loglevel = "warning" |
      .routing = (.routing // {}) |
      .routing.domainStrategy = "AsIs" |
      del(.routing.domainMatcher) |
      .routing.rules = ((.routing.rules // []) | map(del(.type))) |
      .dns = (.dns // {}) |
      .dns.servers = (.dns.servers // ["https://1.1.1.1/dns-query", "https://208.67.222.222/dns-query"]) |
      .dns.queryStrategy = "UseIPv4" |
      .policy = (.policy // {}) |
      .policy.levels = (.policy.levels // {}) |
      .policy.levels["0"] = ((.policy.levels["0"] // {}) + {handshake:3,connIdle:260,uplinkOnly:2,downlinkOnly:5,bufferSize:128}) |
      (.inbounds[]? | select(.protocol=="vless" and (.streamSettings.security//"")=="reality")) |= (
        .settings.decryption="none" |
        .settings.clients |= map(.flow="xtls-rprx-vision") |
        .streamSettings.network="raw" |
        .streamSettings.realitySettings.show=false |
        .streamSettings.realitySettings.maxTimeDiff=60000 |
        .streamSettings.realitySettings.target=(.streamSettings.realitySettings.target // .streamSettings.realitySettings.dest) |
        del(.streamSettings.realitySettings.dest) |
        del(.streamSettings.realitySettings.limitFallbackUpload) |
        del(.streamSettings.realitySettings.limitFallbackDownload) |
        .sniffing.enabled=true |
        .sniffing.metadataOnly=true |
        .sniffing.routeOnly=true
      )'
}

# Reality 的 target 与 serverNames 作为入站级整体管理，只允许一个经质检的 SNI。
set_sni_json_array() {
    local first="${1:-www.microsoft.com}"
    valid_domain "$first" || return 1
    BEST_SNI="$first"
    SNI_JSON_ARRAY=$(json_array_from_args "$first")
}

choose_sni() {
    while true; do
        if test ! -s "$SNI_CACHE_FILE"; then
            warn "没有 SNI 测速缓存，正在执行全量 TLS 探测。"
            run_sni_scanner || true
        fi
        echo -e "\n  ${cyan}【Reality 单 target / 单 SNI】${none}"
        local idx=1 s t p
        while read -r s t p; do
            test -n "$s" || continue
            printf '  %d) %s (%s)\n' "$idx" "$s" "$(test "${t:-0}" -gt 0 2>/dev/null && echo "${t}ms" || echo 未测速)"
            idx=$((idx+1))
        done < "$SNI_CACHE_FILE"
        echo "  r) 重新执行全量 TLS 扫描"
        echo "  0) 手动输入域名"
        echo "  q) 返回"
        local sel="" picked=""
        read -rp "请选择 (默认 1): " sel || true; sel=${sel:-1}
        case "$sel" in
            q|Q) return 1 ;;
            r|R) run_sni_scanner || true; continue ;;
            0) read -rp "请输入 Reality SNI/target 域名: " picked || true ;;
            *) [[ "$sel" =~ ^[0-9]+$ ]] && picked=$(awk -v n="$sel" 'NR==n{print $1;exit}' "$SNI_CACHE_FILE" 2>/dev/null || true) ;;
        esac
        valid_domain "$picked" || { error "域名或序号无效。"; continue; }
        if verify_sni_strict "$picked"; then
            set_sni_json_array "$picked" || return 1
            return 0
        fi
        local force=""
        read -rp "质检未通过。输入 FORCE-SNI 才强制使用: " force || true
        test "$force" = "FORCE-SNI" || continue
        set_sni_json_array "$picked" || return 1
        return 0
    done
}

_update_matrix() {
    test -s "$CONFIG" || { error "config.json 不存在。"; return 1; }
    _e116_config_has_reality_file "$CONFIG" || { error "当前没有 Reality 入站。"; return 1; }
    valid_domain "$BEST_SNI" || return 1
    local tmp bdir map_tmp
    tmp=$(_e118_mktemp sni-single.json) || return 1
    jq --arg target "$BEST_SNI:443" --arg sni "$BEST_SNI" '
      (.inbounds[]? | select(.protocol=="vless" and (.streamSettings.security//"")=="reality") | .streamSettings.realitySettings) |= (
        .serverNames=[$sni] | .target=$target | del(.dest)
      )' "$CONFIG" > "$tmp" || return 1
    _e118_xray_test_config "$tmp" 1 || return 1
    bdir=$(_e116_backup_state "before_sni_single_e131") || return 1
    _e118_commit_config "$tmp" "$bdir" preserve || return 1
    map_tmp=$(_e118_mktemp user-sni-map) || { _e118_restore_state "$bdir" || true; return 1; }
    awk -F'|' -v s="$BEST_SNI" 'NF>=1 && $1!="" {sid=(NF>=3?$2:""); print $1 "|" sid "|" s}' "$USER_SNI_MAP" > "$map_tmp" 2>/dev/null || true
    if ! install -m 0600 "$map_tmp" "$USER_SNI_MAP"; then
        _e118_restore_state "$bdir" || true
        return 1
    fi
    info "Reality target/serverNames 已统一为 $BEST_SNI；全部用户使用同一入站 SNI。"
}

_e131_user_maps_replace_uuid() {
    local old="$1" new="$2" sid="$3" sni="$4" ctime="$5" t1 t2
    t1=$(_e118_mktemp user-sni) || return 1; t2=$(_e118_mktemp user-time) || return 1
    awk -F'|' -v u="$old" '$1!=u && $1!=""' "$USER_SNI_MAP" 2>/dev/null > "$t1" || true
    printf '%s|%s|%s\n' "$new" "$sid" "$sni" >> "$t1"
    awk -F'|' -v u="$old" '$1!=u && $1!=""' "$USER_TIME_MAP" 2>/dev/null > "$t2" || true
    printf '%s|%s\n' "$new" "$ctime" >> "$t2"
    install -m 0600 "$t1" "$USER_SNI_MAP" && install -m 0600 "$t2" "$USER_TIME_MAP"
}

_e131_rotate_reality_key() {
    local tag="$1" raw priv pub tmp bdir pubtmp
    raw=$("$XRAY_BIN" x25519 2>/dev/null || true)
    _e118_parse_x25519_output "$raw" || { error "无法解析 Xray x25519 输出。"; return 1; }
    priv="$E77_REALITY_PRIV"; pub="$E77_REALITY_PUB"
    tmp=$(_e118_mktemp rotate-reality.json) || return 1
    jq --arg tag "$tag" --arg p "$priv" '
      (.inbounds[]? | select((.tag//"vless-reality-vision")==$tag) | .streamSettings.realitySettings) |= (
        .privateKey=$p | del(.publicKey,.password)
      )' "$CONFIG" > "$tmp" || return 1
    _e118_xray_test_config "$tmp" 1 || return 1
    bdir=$(_e116_backup_state "before_reality_key_rotate_e131") || return 1
    _e118_commit_config "$tmp" "$bdir" preserve || return 1
    pubtmp=$(_e118_mktemp public.key) || { _e118_restore_state "$bdir" || true; return 1; }
    printf '%s\n' "$pub" > "$pubtmp"
    _e118_atomic_install "$pubtmp" "$PUBKEY_FILE" 0600 || { _e118_restore_state "$bdir" || true; return 1; }
    info "Reality 私钥与 Password(pbk) 已成对轮换。旧客户端链接立即失效。"
}

do_user_manager() {
    preflight || return 1
    test -s "$CONFIG" || { error "config.json 不存在。"; return 1; }
    local reality_count tag
    reality_count=$(jq '[.inbounds[]? | select(.protocol=="vless" and (.streamSettings.security//"")=="reality")]|length' "$CONFIG" 2>/dev/null || echo 0)
    test "$reality_count" -eq 1 || { error "账户管理要求恰好一个 Reality 入站，当前=$reality_count。"; return 1; }
    tag=$(jq -r '.inbounds[]? | select(.protocol=="vless" and (.streamSettings.security//"")=="reality") | .tag//"vless-reality-vision"' "$CONFIG" | head -n1)
    while true; do
        clear; title "V199e137：Reality 用户与入站级 SNI 管理"
        local -a rows=(); mapfile -t rows < <(jq -r --arg tag "$tag" '.inbounds[]? | select((.tag//"vless-reality-vision")==$tag) | .settings.clients | to_entries[] | [(.key|tostring),(.value.id//""),(.value.email//"未命名")] | @tsv' "$CONFIG")
        local main_sni; main_sni=$(jq -r --arg tag "$tag" '.inbounds[]? | select((.tag//"vless-reality-vision")==$tag) | .streamSettings.realitySettings.serverNames[0]//empty' "$CONFIG")
        echo "  入站统一 SNI/target：${main_sni:-缺失}"
        local row idx uuid remark sid ctime
        for row in "${rows[@]}"; do
            IFS=$'\t' read -r idx uuid remark <<<"$row"
            sid=$(_e118_user_sid "$uuid" "$idx"); ctime=$(awk -F'|' -v u="$uuid" '$1==u{print $2;exit}' "$USER_TIME_MAP" 2>/dev/null || true)
            printf '  %d) %-18s UUID=%s\n     SID=%s 创建=%s\n' "$((idx+1))" "$remark" "$uuid" "${sid:-未知}" "${ctime:-外部导入}"
        done
        hr
        echo "  a) 新增用户（自动 UUID/ShortId）"
        echo "  m) 导入外部 UUID/ShortId"
        echo "  r) 修改备注"
        echo "  u) 更换 UUID"
        echo "  s) 修改 Reality 全局 SNI/target（影响全部用户）"
        echo "  p) 修改 Reality 监听端口"
        echo "  k) 轮换 Reality 私钥/Password(pbk)"
        echo "  d) 删除用户"
        echo "  q) 返回"
        local action="" choice="" selected="" new_uuid="" new_sid="" new_remark="" candidate="" bdir="" old_time=""
        read -rp "输入操作: " action || true
        case "$action" in
            q|Q) return 0 ;;
            s|S) if choose_sni; then _update_matrix && do_summary; fi; _e116_pause ;;
            a|A|m|M)
                if [[ "$action" =~ ^[aA]$ ]]; then
                    new_uuid=$(_e118_new_uuid) || continue; new_sid=$(_e118_new_sid) || continue
                else
                    read -rp "外部 UUID: " new_uuid || true; _e118_valid_uuid "$new_uuid" || { error "UUID 非法。"; sleep 1; continue; }
                    read -rp "外部 ShortId: " new_sid || true; _e118_valid_sid "$new_sid" || { error "ShortId 非法。"; sleep 1; continue; }
                fi
                jq -e --arg u "$new_uuid" '.inbounds[]?.settings.clients[]? | select(.id==$u)' "$CONFIG" >/dev/null && { error "UUID 已存在。"; sleep 1; continue; }
                jq -e --arg s "$new_sid" '.inbounds[]?.streamSettings.realitySettings.shortIds[]? | select(.==$s)' "$CONFIG" >/dev/null && { error "ShortId 已存在。"; sleep 1; continue; }
                read -rp "备注 (默认 User-${new_sid:0:6}): " new_remark || true; new_remark=${new_remark:-User-${new_sid:0:6}}
                _e118_valid_remark "$new_remark" || { error "备注非法。"; continue; }
                candidate=$(_e118_mktemp user-add.json) || return 1
                jq --arg tag "$tag" --arg id "$new_uuid" --arg sid "$new_sid" --arg email "$new_remark" '
                  (.inbounds[]? | select((.tag//"vless-reality-vision")==$tag)) |= (
                    .settings.clients += [{id:$id,flow:"xtls-rprx-vision",email:$email}] |
                    .streamSettings.realitySettings.shortIds += [$sid]
                  )' "$CONFIG" > "$candidate" || return 1
                _e118_xray_test_config "$candidate" 1 || continue
                bdir=$(_e116_backup_state "before_user_add_e131") || return 1
                _e118_commit_config "$candidate" "$bdir" preserve || continue
                _e118_upsert_user_record "$new_uuid" "$new_sid" "$main_sni" || { _e118_restore_state "$bdir" || true; return 1; }
                info "用户已写入；SNI 继承入站统一值 $main_sni。"; _e116_pause
                ;;
            r|R|u|U|d|D)
                read -rp "用户序号: " choice || true
                [[ "$choice" =~ ^[0-9]+$ ]] && test "$choice" -ge 1 && test "$choice" -le "${#rows[@]}" || { error "用户序号无效。"; continue; }
                selected="${rows[$((choice-1))]}"; IFS=$'\t' read -r idx uuid remark <<<"$selected"; sid=$(_e118_user_sid "$uuid" "$idx")
                case "$action" in
                    r|R)
                        read -rp "新备注: " new_remark || true; _e118_valid_remark "$new_remark" || { error "备注非法。"; continue; }
                        _safe_jq_write --arg tag "$tag" --arg u "$uuid" --arg e "$new_remark" '(.inbounds[]? | select((.tag//"vless-reality-vision")==$tag) | .settings.clients) |= map(if .id==$u then .email=$e else . end)' && info "备注已修改。"
                        ;;
                    u|U)
                        read -rp "新 UUID (回车自动生成): " new_uuid || true; test -n "$new_uuid" || new_uuid=$(_e118_new_uuid)
                        _e118_valid_uuid "$new_uuid" || { error "UUID 非法。"; continue; }
                        jq -e --arg u "$new_uuid" '.inbounds[]?.settings.clients[]? | select(.id==$u)' "$CONFIG" >/dev/null && { error "新 UUID 已存在。"; continue; }
                        candidate=$(_e118_mktemp user-uuid.json) || return 1
                        jq --arg tag "$tag" --arg old "$uuid" --arg new "$new_uuid" '(.inbounds[]? | select((.tag//"vless-reality-vision")==$tag) | .settings.clients) |= map(if .id==$old then .id=$new else . end)' "$CONFIG" > "$candidate" || return 1
                        _e118_xray_test_config "$candidate" 1 || continue
                        bdir=$(_e116_backup_state "before_user_uuid_e131") || return 1; _e118_commit_config "$candidate" "$bdir" preserve || continue
                        old_time=$(awk -F'|' -v u="$uuid" '$1==u{print $2;exit}' "$USER_TIME_MAP" 2>/dev/null || true)
                        old_time=${old_time:-$(date +'%Y-%m-%d %H:%M')}
                        _e131_user_maps_replace_uuid "$uuid" "$new_uuid" "$sid" "$main_sni" "$old_time" || { _e118_restore_state "$bdir" || true; return 1; }
                        info "UUID 已更换。"
                        ;;
                    d|D)
                        test "${#rows[@]}" -gt 1 || { error "不能删除唯一用户。"; continue; }
                        local confirm=""; read -rp "输入 DELETE 确认: " confirm || true; test "$confirm" = DELETE || continue
                        candidate=$(_e118_mktemp user-delete.json) || return 1
                        jq --arg tag "$tag" --arg u "$uuid" '(.inbounds[]? | select((.tag//"vless-reality-vision")==$tag) | .settings.clients) |= map(select(.id!=$u))' "$CONFIG" > "$candidate" || return 1
                        _e118_xray_test_config "$candidate" 1 || continue
                        bdir=$(_e116_backup_state "before_user_delete_e131") || return 1; _e118_commit_config "$candidate" "$bdir" preserve || continue
                        _e118_delete_user_record "$uuid" || { _e118_restore_state "$bdir" || true; return 1; }
                        info "用户已删除；ShortId 保留以避免破坏外部客户端。"
                        ;;
                esac
                _e116_pause
                ;;
            p|P)
                local current_port new_port
                current_port=$(jq -r --arg tag "$tag" '.inbounds[]? | select((.tag//"vless-reality-vision")==$tag) | .port' "$CONFIG")
                read -rp "新端口 (当前 $current_port，回车保持): " new_port || true; new_port=${new_port:-$current_port}
                if test "$new_port" = "$current_port"; then info "端口未变化。"; _e116_pause; continue; fi
                [[ "$new_port" =~ ^[0-9]+$ ]] && test "$new_port" -ge 1 && test "$new_port" -le 65535 || { error "端口非法。"; continue; }
                jq -e --arg tag "$tag" --argjson p "$new_port" '.inbounds[]? | select((.tag//"")!=$tag and .port==$p)' "$CONFIG" >/dev/null && { error "另一 Xray 入站已占用。"; continue; }
                _e118_port_in_use_elsewhere "$new_port" "$current_port" && { error "系统其他进程已占用。"; continue; }
                _safe_jq_write --arg tag "$tag" --argjson p "$new_port" '(.inbounds[]? | select((.tag//"vless-reality-vision")==$tag) | .port)=$p' && info "端口已修改。"
                _e116_pause
                ;;
            k|K)
                local confirm=""; read -rp "输入 ROTATE 确认轮换密钥: " confirm || true
                test "$confirm" = ROTATE && _e131_rotate_reality_key "$tag"
                _e116_pause
                ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

_e131_os_codename() {
    local code=""
    if test -r /etc/os-release; then . /etc/os-release; code="${VERSION_CODENAME:-}"; fi
    test -n "$code" || code=$(lsb_release -sc 2>/dev/null || true)
    printf '%s' "$code"
}

_e131_xanmod_pkg_name() {
    local branch="$1" level="$2"
    test "$level" -le 3 || level=3
    case "$branch" in
        main) test "$level" -ge 2 || return 1; printf 'linux-xanmod-x64v%s' "$level" ;;
        lts) printf 'linux-xanmod-lts-x64v%s' "$level" ;;
        rt) test "$level" -ge 2 || return 1; printf 'linux-xanmod-rt-x64v%s' "$level" ;;
        *) return 1 ;;
    esac
}

_e131_restore_path_snapshot() {
    local backup="$1" target="$2"
    if test -f "$backup.present"; then install -m 0644 "$backup.present" "$target"
    elif test -f "$backup.absent"; then rm -f -- "$target"
    fi
}

do_install_xanmod_main_official() {
    title "V199e137：XanMod 官方 APT 预编译内核"
    [[ "$(uname -m)" = x86_64 ]] || { error "仅支持 x86_64。"; return 1; }
    local branch="" level pkg code confirm keytmp keygpg backup kver
    echo "  1) Main（官方包 x64v2/x64v3）"
    echo "  2) LTS（官方包 x64v1/x64v2/x64v3）"
    echo "  3) RT（官方包 x64v2/x64v3）"
    read -rp "选择分支 (默认 2=LTS): " branch || true
    case "${branch:-2}" in 1) branch=main;; 2) branch=lts;; 3) branch=rt;; *) error "无效分支。"; return 1;; esac
    level=$(detect_x86_64_level); test "$level" -le 3 || level=3
    pkg=$(_e131_xanmod_pkg_name "$branch" "$level") || { error "当前 CPU x86-64-v$level 没有该分支官方包；请选择 LTS x64v1。"; return 1; }
    code=$(_e131_os_codename); test -n "$code" || { error "无法识别发行版 codename。"; return 1; }
    echo "  codename=$code branch=$branch cpu=x64v$level package=$pkg"
    warn "安装内核前必须有快照/VNC/救援模式；脚本不会自动修改 GRUB 默认项，也不会自动重启。"
    read -rp "输入 INSTALL-XANMOD 确认: " confirm || true; test "$confirm" = INSTALL-XANMOD || return 0
    export DEBIAN_FRONTEND=noninteractive
    apt-get update || { error "现有 APT 源更新失败；尚未修改 XanMod 仓库。"; return 1; }
    apt-get install -y --no-install-recommends ca-certificates curl gnupg lsb-release || return 1
    mkdir -p /etc/apt/keyrings "$BACKUP_DIR/xanmod-apt" || return 1
    backup="$BACKUP_DIR/xanmod-apt/$(date +%Y%m%d_%H%M%S)"
    test -f "$E131_XANMOD_KEYRING" && cp -a "$E131_XANMOD_KEYRING" "$backup.key.present" || : > "$backup.key.absent"
    test -f "$E131_XANMOD_LIST" && cp -a "$E131_XANMOD_LIST" "$backup.list.present" || : > "$backup.list.absent"
    keytmp=$(_e118_mktemp xanmod-archive.key) || return 1; keygpg=$(_e118_mktemp xanmod-archive-keyring.gpg) || return 1
    curl --proto '=https' --tlsv1.2 -fL --connect-timeout 10 --max-time 120 https://dl.xanmod.org/archive.key -o "$keytmp" || return 1
    gpg --batch --show-keys "$keytmp" >/dev/null 2>&1 || { error "archive.key 不是有效 OpenPGP 公钥。"; return 1; }
    gpg --batch --yes --dearmor -o "$keygpg" "$keytmp" || return 1
    install -m 0644 "$keygpg" "$E131_XANMOD_KEYRING" || return 1
    printf 'deb [signed-by=%s] http://deb.xanmod.org %s main\n' "$E131_XANMOD_KEYRING" "$code" | _e131_atomic_text_file "$E131_XANMOD_LIST" 0644 || return 1
    if ! apt-get update; then
        error "XanMod 仓库更新失败，恢复旧 key/list。"
        _e131_restore_path_snapshot "$backup.key" "$E131_XANMOD_KEYRING" || true
        _e131_restore_path_snapshot "$backup.list" "$E131_XANMOD_LIST" || true
        apt-get update >/dev/null 2>&1 || true
        return 1
    fi
    apt-cache show "$pkg" >/dev/null 2>&1 || { error "仓库中没有 $pkg；可能 codename/分支不受支持。"; return 1; }
    apt-get install -y "$pkg" || return 1
    kver=$(ls -t /boot/vmlinuz-*xanmod* 2>/dev/null | head -n1 | sed 's|.*/vmlinuz-||')
    test -n "$kver" || { error "安装后未找到 XanMod vmlinuz。"; return 1; }
    _kernel_pre_reboot_verify_e52 "$kver" || return 1
    info "XanMod 官方包已安装并通过 boot/initramfs/GRUB 校验：$kver"
    warn "旧内核已保留。确认控制台可用后再手动 reboot。"
}

_e131_xanmod_tags() {
    local json
    json=$(curl --proto '=https' --tlsv1.2 -fsSL --connect-timeout 10 --max-time 60 'https://gitlab.com/api/v4/projects/xanmod%2Flinux/repository/tags?per_page=100' 2>/dev/null) || return 1
    printf '%s' "$json" | jq -r '.[]?.name // empty' | grep -E '^[0-9]+\.[0-9]+\.[0-9]+(-rt[^-]*)?-xanmod[0-9]+$' | grep -vE 'rc|beta' | sort -V -r
}

_e131_choose_xanmod_tag() {
    local requested="${1:-}" tag_json encoded expected
    if test -n "$requested"; then LATEST_TAG="$requested"
    else
        local -a tags=(); mapfile -t tags < <(_e131_xanmod_tags | head -n 30)
        if test "${#tags[@]}" -eq 0; then
            warn "GitLab Tag API 不可用，不使用过期硬编码版本。"
            read -rp "手动输入完整 XanMod Tag: " LATEST_TAG || true
        else
            local i=1; echo "最近 XanMod Tags："
            for requested in "${tags[@]}"; do printf '  %d) %s\n' "$i" "$requested"; i=$((i+1)); done
            echo "  0) 手动输入"
            local sel=""; read -rp "选择 Tag (默认 1): " sel || true; sel=${sel:-1}
            if test "$sel" = 0; then read -rp "完整 Tag: " LATEST_TAG || true
            elif [[ "$sel" =~ ^[0-9]+$ ]] && test "$sel" -ge 1 && test "$sel" -le "${#tags[@]}"; then LATEST_TAG="${tags[$((sel-1))]}"
            else error "Tag 序号无效。"; return 1; fi
        fi
    fi
    [[ "$LATEST_TAG" =~ ^[0-9]+\.[0-9]+\.[0-9]+(-rt[^-]*)?-xanmod[0-9]+$ ]] || { error "Tag 格式非法：$LATEST_TAG"; return 1; }
    encoded=$(jq -rn --arg v "$LATEST_TAG" '$v|@uri')
    tag_json=$(curl --proto '=https' --tlsv1.2 -fsSL --connect-timeout 10 --max-time 60 "https://gitlab.com/api/v4/projects/xanmod%2Flinux/repository/tags/$encoded") || return 1
    expected=$(printf '%s' "$tag_json" | jq -r '.commit.id // empty')
    [[ "$expected" =~ ^[0-9a-f]{40}$ ]] || { error "无法取得 Tag 对应 commit SHA。"; return 1; }
    E131_XANMOD_EXPECTED_COMMIT="$expected"
    return 0
}

_e131_kernel_build_precheck() {
    local root_free boot_free mem_avail
    root_free=$(df -Pm /var/tmp 2>/dev/null | awk 'NR==2{print int($4)}' || echo 0)
    boot_free=$(df -Pm /boot 2>/dev/null | awk 'NR==2{print int($4)}' || echo 0)
    mem_avail=$(awk '/MemAvailable:/{print int($2/1024)}' /proc/meminfo 2>/dev/null || echo 0)
    echo "  /var/tmp 可用=${root_free}MB /boot 可用=${boot_free}MB MemAvailable=${mem_avail}MB"
    test "$root_free" -ge 15000 || { error "完整打包编译要求 /var/tmp 至少 15GB 可用，推荐 25GB+。"; return 1; }
    test "$boot_free" -ge 350 || { error "/boot 可用空间不足 350MB。"; return 1; }
    test "$mem_avail" -ge 700 || { error "MemAvailable 低于 700MB，拒绝编译。"; return 1; }
    test -w /boot || { error "/boot 不可写。"; return 1; }
}

_e131_install_kernel_build_deps() {
    export DEBIAN_FRONTEND=noninteractive
    local os_id; os_id=$(detect_os)
    [[ "$os_id" =~ ^(debian|ubuntu)$ ]] || { error "E131 bindeb-pkg 路线仅支持 Debian/Ubuntu。"; return 1; }
    apt-get update || return 1
    apt-get install -y --no-install-recommends \
      git ca-certificates curl jq build-essential bc bison flex libssl-dev libelf-dev \
      libncurses-dev dwarves pahole fakeroot rsync cpio kmod zstd lz4 xz-utils dpkg-dev \
      python3 perl pkg-config || return 1
    local c; for c in git make gcc bison flex dpkg-deb fakeroot; do command -v "$c" >/dev/null 2>&1 || { error "依赖命令缺失：$c"; return 1; }; done
}

_e131_kernel_threads() {
    local mem cores t
    mem=$(awk '/MemAvailable:/{print int($2/1024)}' /proc/meminfo 2>/dev/null || echo 1024)
    cores=$(nproc 2>/dev/null || echo 1)
    t=$((mem/1800)); test "$t" -ge 1 || t=1; test "$t" -le "$cores" || t="$cores"
    printf '%s' "$t"
}

_e131_xanmod_source_build() {
    local requested="${1:-}" confirm work src log threads actual image header kver manifest cleanup
    title "V199e137：XanMod 完整源码编译（Tag commit 锁定 + bindeb-pkg）"
    warn "高风险：必须有 VPS 快照、VNC/救援模式。不会夹带网卡、sysctl、MSS、RPS 或 GRUB 默认项修改。"
    _e131_kernel_build_precheck || return 1
    read -rp "输入 BUILD-XANMOD 确认: " confirm || true; test "$confirm" = BUILD-XANMOD || return 0
    _e131_install_kernel_build_deps || return 1
    _e131_choose_xanmod_tag "$requested" || return 1
    mkdir -p "$E131_KERNEL_BUILD_ROOT" || return 1
    work="$E131_KERNEL_BUILD_ROOT/${LATEST_TAG}-$(date +%Y%m%d_%H%M%S)"; src="$work/src"; log="$work/build.log"
    mkdir -p "$src" || return 1
    git -C "$src" init -q || return 1
    git -C "$src" remote add origin https://gitlab.com/xanmod/linux.git || return 1
    git -C "$src" fetch --depth=1 origin "refs/tags/$LATEST_TAG:refs/tags/$LATEST_TAG" 2>&1 | tee "$work/fetch.log" || return 1
    git -C "$src" checkout -q --detach "$LATEST_TAG" || return 1
    actual=$(git -C "$src" rev-parse HEAD)
    test "$actual" = "$E131_XANMOD_EXPECTED_COMMIT" || { error "Tag commit 不一致：API=$E131_XANMOD_EXPECTED_COMMIT git=$actual"; return 1; }
    printf '%s  %s\n' "$actual" "$LATEST_TAG" > "$work/source.commit"
    cd "$src" || return 1
    make mrproper >/dev/null || return 1
    if test -r "/boot/config-$(uname -r)"; then cp -f "/boot/config-$(uname -r)" .config || return 1
    else make defconfig || return 1; fi
    make olddefconfig >/dev/null || return 1
    if test -x scripts/config; then
        scripts/config --enable CONFIG_TCP_CONG_BBR || true
        scripts/config --enable CONFIG_DEFAULT_BBR || true
        scripts/config --enable CONFIG_NET_SCH_FQ || true
        scripts/config --set-str CONFIG_DEFAULT_TCP_CONG bbr || true
        if test -z "${E91_BBR_KERNEL_CONF:-${E90_BBR_KERNEL_CONF:-}}"; then scripts/config --set-str CONFIG_LOCALVERSION '-xrv131' || true; fi
        scripts/config --set-str CONFIG_SYSTEM_TRUSTED_KEYS '' || true
        scripts/config --set-str CONFIG_SYSTEM_REVOCATION_KEYS '' || true
    fi
    if test -n "${E91_BBR_KERNEL_CONF:-${E90_BBR_KERNEL_CONF:-}}"; then _e90_kernel_patch_before_compile || return 1; fi
    make olddefconfig >/dev/null || return 1
    kver=$(make -s kernelrelease); test -n "$kver" || { error "make kernelrelease 为空。"; return 1; }
    cp -f .config "$work/config.final"
    threads=$(_e131_kernel_threads); info "Tag=$LATEST_TAG commit=$actual kernelrelease=$kver threads=$threads"
    if ! make -j"$threads" bindeb-pkg 2>&1 | tee "$log"; then error "bindeb-pkg 失败：$log"; return 1; fi
    image=$(find "$work" -maxdepth 1 -type f -name "linux-image-*${kver}*.deb" ! -name '*dbg*' | sort | head -n1)
    header=$(find "$work" -maxdepth 1 -type f -name "linux-headers-*${kver}*.deb" | sort | head -n1)
    test -s "$image" || { error "未找到 linux-image .deb。"; return 1; }
    test -s "$header" || { error "未找到 linux-headers .deb。"; return 1; }
    dpkg-deb --info "$image" >/dev/null || return 1; dpkg-deb --info "$header" >/dev/null || return 1
    dpkg -i "$header" "$image" || { error "dpkg 安装失败；没有自动执行 apt -f，避免掩盖依赖问题。"; return 1; }
    test -s "/boot/vmlinuz-$kver" || { error "缺少 /boot/vmlinuz-$kver。"; return 1; }
    test -d "/lib/modules/$kver" || { error "缺少 /lib/modules/$kver。"; return 1; }
    if ! test -s "/boot/initrd.img-$kver" && ! test -s "/boot/initramfs-${kver}.img"; then
        if command -v update-initramfs >/dev/null 2>&1; then update-initramfs -c -k "$kver" || return 1
        elif command -v dracut >/dev/null 2>&1; then dracut --force "/boot/initramfs-${kver}.img" "$kver" || return 1
        else error "无 initramfs 工具。"; return 1; fi
    fi
    _kernel_pre_reboot_verify_e52 "$kver" || return 1
    manifest="$work/manifest.txt"
    { echo "tag=$LATEST_TAG"; echo "commit=$actual"; echo "kernelrelease=$kver"; echo "image=$image"; echo "headers=$header"; echo "threads=$threads"; } > "$manifest"
    info "完整源码编译、Debian 打包、安装和引导校验全部通过：$kver"
    info "构建记录：$work"
    warn "没有改变 GRUB_DEFAULT，也没有自动重启。旧内核保持可用。"
    read -rp "是否删除源码树以释放空间？[y/N]: " cleanup || true
    if [[ "$cleanup" =~ ^[yY]$ ]]; then rm -rf -- "$src"; info "已保留 .deb、日志和 manifest，删除源码树。"; fi
}

_compile_kernel_xanmod() {
    if test -n "${E91_BBR_KERNEL_CONF:-${E90_BBR_KERNEL_CONF:-}}"; then export XRAY_ALLOW_SOURCE_KERNEL_COMPILE=1; fi
    _e131_xanmod_source_build "${1:-}"
}

