_e131_dat_update_now() {
    if test ! -x "$UPDATE_DAT_SCRIPT"; then install_update_dat || return 1; fi
    "$UPDATE_DAT_SCRIPT"
}

_e118_install_self() {
    local src="${SCRIPT_PATH:-${BASH_SOURCE[0]}}" target tmp name
    test -s "$src" || { error "无法读取当前脚本：$src"; return 1; }
    bash -n "$src" || { error "当前脚本未通过 bash -n。"; return 1; }
    _e118_prepare_dirs || return 1
    for target in "$SYMLINK" "$SCRIPT_DIR/ex199e136.sh" "$SCRIPT_DIR/ex199e_latest.sh"; do
        if test -e "$target" && test "$src" -ef "$target" 2>/dev/null; then chmod 0755 "$target" || return 1; continue; fi
        name=${target##*/}; tmp="$(dirname "$target")/.${name}.e131.$$"
        install -m 0755 "$src" "$tmp" || { rm -f -- "$tmp"; return 1; }
        bash -n "$tmp" || { rm -f -- "$tmp"; return 1; }
        mv -f -- "$tmp" "$target" || { rm -f -- "$tmp"; return 1; }
    done
    hash -r 2>/dev/null || true
}

