# 在 E127 自检基础上增加 E131 可执行路径约束，不吞掉基础失败。
eval "$(declare -f _e118_self_test | sed '1s/_e118_self_test/_e131_self_test_base/')" 2>/dev/null || true
_e118_self_test() {
    local rc=0 body
    _e131_self_test_base || rc=1
    echo; echo "V199e137 最终替换层回归测试："
    body=$(declare -f _e118_install_self); [[ "$body" == *'ex199e136.sh'* && "$body" != *'ex199e128.sh'* ]] && echo "  [PASS] 版本化自安装路径" || { echo "  [FAIL] 自安装路径"; rc=1; }
    body=$(declare -f fix_xray_systemd_limits); [[ "$body" == *'Nice=-20'* && "$body" == *'_e131_verify_nice_runtime'* ]] && echo "  [PASS] Nice=-20 配置及回滚" || { echo "  [FAIL] Nice事务"; rc=1; }
    body=$(declare -f _e131_verify_nice_runtime); [[ "$body" == *'ps -o ni='* && "$body" == *'MainPID'* ]] && echo "  [PASS] MainPID 实际 NI 验证" || { echo "  [FAIL] 仅检查systemd属性"; rc=1; }
    body=$(declare -f do_install_xanmod_main_official); [[ "$body" == *'archive.key'* && "$body" == *'VERSION_CODENAME'* && "$body" != *'gpg.key'* && "$body" != *'releases main'* ]] && echo "  [PASS] XanMod 当前官方APT流程" || { echo "  [FAIL] XanMod APT旧流程残留"; rc=1; }
    body=$(declare -f _e131_xanmod_source_build); [[ "$body" == *'E131_XANMOD_EXPECTED_COMMIT'* && "$body" == *'bindeb-pkg'* && "$body" == *'kernelrelease'* && "$body" != *'make install'* && "$body" != *'ethtool -G'* ]] && echo "  [PASS] 源码commit锁定/打包/无网络夹带" || { echo "  [FAIL] XanMod源码编译事务"; rc=1; }
    body=$(declare -f _update_matrix); [[ "$body" == *'.serverNames=[$sni]'* && "$body" == *'.target=$target'* ]] && echo "  [PASS] Reality单SNI/target" || { echo "  [FAIL] Reality仍允许冲突SNI矩阵"; rc=1; }
    body=$(declare -f main_menu); [[ "$body" == *'declare -F do_xray_speed_diag_menu_e95'* && "$body" == *'_e131_dat_update_now'* ]] && echo "  [PASS] 菜单回退与DAT自修复" || { echo "  [FAIL] 主菜单最终链"; rc=1; }
    body=$(declare -f hot_update_from_legacy); [[ "$body" == *'_e121_install_ssh_guard'* && "$body" == *'_e116_apply_init_window_default30'* && "$body" == *'xray-dat-update.timer'* && "$body" == *'fix_xray_systemd_limits'* ]] && echo "  [PASS] 热更新固定要求" || { echo "  [FAIL] 热更新固定要求缺失"; rc=1; }
    echo "V199e137 回归结果：$(test "$rc" -eq 0 && echo PASS || echo FAIL)"
    return "$rc"
}

_e131_restore_source_context() {
    test "${_E131_SOURCE_ONLY:-0}" -eq 1 || return 0
    IFS="${_E131_CALLER_IFS:-$' \n\t'}"
    PATH="${_E131_CALLER_PATH:-$PATH}"; export PATH
    trap - ERR EXIT
    test -n "${_E131_CALLER_ERR_TRAP:-}" && eval "$_E131_CALLER_ERR_TRAP"
    test -n "${_E131_CALLER_EXIT_TRAP:-}" && eval "$_E131_CALLER_EXIT_TRAP"
    test -n "${_E131_CALLER_SET_STATE:-}" && eval "$_E131_CALLER_SET_STATE"
}

# E131 release-candidate corrections: explicit hot-update survival rollback and corrected executable self-test.
_e131_hot_update_rollback() {
    local protect="${1:-}"
    test -n "$protect" || return 1
    _e118_restore_core_payload "$protect" >/dev/null 2>&1 || true
    _e118_restore_state "$protect" >/dev/null 2>&1 || true
    return 0
}

hot_update_from_legacy() {
    local protect="" was_active=0 rc=0
    if test -s "$CONFIG" && test -x "$XRAY_BIN"; then
        protect=$(_e116_backup_state "before_hot_update_e131_core_survival") || { error "E131 Core生存快照失败。"; return 1; }
        _e118_save_core_payload "$protect" || { error "E131 Core/DAT/systemd载荷快照失败。"; return 1; }
        was_active=$(sed -n 's/^xray_was_active=//p' "$protect/meta.env" | head -n1); was_active=${was_active:-0}
    fi
    if ! _e131_hot_update_base "$@"; then rc=1; fi
    if test "$rc" -eq 0; then _e118_install_self || rc=1; fi
    if test "$rc" -eq 0; then install_update_dat || rc=1; fi
    if test "$rc" -eq 0 && declare -F _e105_disable_xray_core_auto_update >/dev/null 2>&1; then _e105_disable_xray_core_auto_update || rc=1; fi
    if test "$rc" -eq 0; then _e116_apply_init_window_default30 || rc=1; fi
    if test "$rc" -eq 0; then _e121_install_log_retention || rc=1; fi
    if test "$rc" -eq 0; then _e121_install_ssh_guard || rc=1; fi
    if test "$rc" -eq 0; then fix_xray_systemd_limits || rc=1; fi
    if test "$rc" -eq 0; then printf '%s\n' "$SCRIPT_VERSION" > "$SCRIPT_VERSION_FILE" || rc=1; fi
    if test "$rc" -eq 0; then systemctl is-enabled --quiet xray-dat-update.timer 2>/dev/null || { error "DAT每日更新timer未启用。"; rc=1; }; fi
    if test "$rc" -eq 0 && test "$was_active" -eq 1; then
        _e127_verify_xray_runtime "$CONFIG" 12 || rc=1
        test "$rc" -ne 0 || _e131_verify_nice_runtime || rc=1
    fi
    if test "$rc" -ne 0; then
        error "E131 热更新任一关键步骤失败，启动 Core/配置生存回滚。"
        if test -n "$protect"; then
            _e118_restore_core_payload "$protect" >/dev/null 2>&1 || true
            _e118_restore_state "$protect" >/dev/null 2>&1 || true
        fi
        return 1
    fi
    if test -n "$protect" && test "$was_active" -eq 0; then systemctl stop xray.service >/dev/null 2>&1 || true; fi
    _e127_prune_core_payload_backups 2>/dev/null || true
    info "V199e137 热更新完成：Nice=-20、init30、SSH防护、3天日志和DAT 03:00更新均已复检。"
}

