    echo; echo "V199e137 最终替换层回归测试："
    body=$(declare -f _e118_install_self); [[ "$body" == *'ex199e136.sh'* && "$body" != *'ex199e128.sh'* ]] && echo "  [PASS] 版本化自安装路径" || { echo "  [FAIL] 自安装路径"; rc=1; }
