    body=$(declare -f _e131_verify_nice_runtime); [[ "$body" == *'ps -o ni='* && "$body" == *'MainPID'* ]] && echo "  [PASS] MainPID实际NI验证" || { echo "  [FAIL] 仅检查systemd属性"; rc=1; }
    apt_body="$(declare -f do_install_xanmod_main_official)$(declare -f _e131_os_codename)"
    [[ "$apt_body" == *'archive.key'* && "$apt_body" == *'VERSION_CODENAME'* && "$apt_body" != *'https://dl.xanmod.org/gpg.key'* && "$apt_body" != *'releases main'* ]] && echo "  [PASS] XanMod当前官方APT流程" || { echo "  [FAIL] XanMod APT旧流程残留"; rc=1; }
    body=$(declare -f _e131_xanmod_source_build); [[ "$body" == *'E131_XANMOD_EXPECTED_COMMIT'* && "$body" == *'bindeb-pkg'* && "$body" == *'kernelrelease'* && "$body" != *'make install'* && "$body" != *'ethtool -G'* ]] && echo "  [PASS] 源码commit锁定/打包/无网络夹带" || { echo "  [FAIL] XanMod源码编译事务"; rc=1; }
    body=$(declare -f _update_matrix); [[ "$body" == *'.serverNames=[$sni]'* && "$body" == *'.target=$target'* ]] && echo "  [PASS] Reality单SNI/target" || { echo "  [FAIL] Reality仍允许冲突SNI矩阵"; rc=1; }
    body=$(declare -f main_menu); [[ "$body" == *'declare -F do_xray_speed_diag_menu_e95'* && "$body" == *'_e131_dat_update_now'* ]] && echo "  [PASS] 菜单回退与DAT自修复" || { echo "  [FAIL] 主菜单最终链"; rc=1; }
    body=$(declare -f hot_update_from_legacy); [[ "$body" == *'core_survival'* && "$body" == *'_e118_restore_core_payload'* && "$body" == *'_e121_install_ssh_guard'* && "$body" == *'_e116_apply_init_window_default30'* && "$body" == *'xray-dat-update.timer'* && "$body" == *'fix_xray_systemd_limits'* ]] && echo "  [PASS] 热更新生存事务与固定要求" || { echo "  [FAIL] 热更新事务缺失"; rc=1; }
    echo "V199e137 回归结果：$(test "$rc" -eq 0 && echo PASS || echo FAIL)"
    return "$rc"
}


# E131 hardening corrections: safe SNI seed and legacy XanMod APT repair.
_e92_seed_sni_cache_if_empty() {
    test -s "$SNI_CACHE_FILE" && return 0
    mkdir -p "$CONFIG_DIR" || return 1
    cat > "$SNI_CACHE_FILE" <<'EOF_E131_SNI_SEED'
www.honda.com 0 NORM
