_e131_snapshot_file() {
    local src="$1" prefix="$2"
    if test -f "$src"; then cp -a -- "$src" "$prefix.present" || return 1
    else : > "$prefix.absent" || return 1
    fi
}

_e131_restore_xanmod_apt_snapshot() {
    local b="$1"
    _e131_restore_path_snapshot "$b.key" "$E131_XANMOD_KEYRING" || true
    _e131_restore_path_snapshot "$b.list" "$E131_XANMOD_LIST" || true
    _e131_restore_path_snapshot "$b.legacy-list" /etc/apt/sources.list.d/xanmod-kernel.list || true
    _e131_restore_path_snapshot "$b.legacy-key" /etc/apt/keyrings/xanmod.gpg || true
}

do_install_xanmod_main_official() {
    title "V199e137：XanMod 官方 APT 预编译内核 / 旧仓库修复"
    [[ "$(uname -m)" = x86_64 ]] || { error "仅支持 x86_64。"; return 1; }
    local branch="" level pkg code confirm keytmp keygpg backup kver
    echo "  1) Main（官方包 x64v2/x64v3）"
    echo "  2) LTS（官方包 x64v1/x64v2/x64v3）"
    echo "  3) RT（官方包 x64v2/x64v3）"
    read -rp "选择分支 (默认 2=LTS): " branch || true
    case "${branch:-2}" in 1) branch=main;; 2) branch=lts;; 3) branch=rt;; *) error "无效分支。"; return 1;; esac
    level=$(detect_x86_64_level); test "$level" -le 3 || level=3
    pkg=$(_e131_xanmod_pkg_name "$branch" "$level") || { error "当前 CPU x86-64-v$level 没有该分支官方包；请选择 LTS。"; return 1; }
    code=$(_e131_os_codename); test -n "$code" || { error "无法识别发行版 codename。"; return 1; }
    echo "  codename=$code branch=$branch cpu=x64v$level package=$pkg"
    warn "脚本会先备份并移除旧 gpg.key/releases 仓库，避免 apt update 被旧源卡死。"
    warn "安装内核前必须有快照/VNC/救援模式；安装后下一次重启可能因 GRUB_DEFAULT=0 自动选择最新内核。"
    read -rp "输入 INSTALL-XANMOD 确认: " confirm || true; test "$confirm" = INSTALL-XANMOD || return 0
    export DEBIAN_FRONTEND=noninteractive
    mkdir -p /etc/apt/keyrings "$BACKUP_DIR/xanmod-apt" || return 1
    backup="$BACKUP_DIR/xanmod-apt/$(date +%Y%m%d_%H%M%S)"
    _e131_snapshot_file "$E131_XANMOD_KEYRING" "$backup.key" || return 1
    _e131_snapshot_file "$E131_XANMOD_LIST" "$backup.list" || return 1
    _e131_snapshot_file /etc/apt/sources.list.d/xanmod-kernel.list "$backup.legacy-list" || return 1
    _e131_snapshot_file /etc/apt/keyrings/xanmod.gpg "$backup.legacy-key" || return 1
    rm -f -- "$E131_XANMOD_LIST" /etc/apt/sources.list.d/xanmod-kernel.list 2>/dev/null || true
    if ! apt-get update -o Acquire::Retries=3; then
        error "移除旧 XanMod 源后，系统其它 APT 源仍更新失败。恢复原文件。"
        _e131_restore_xanmod_apt_snapshot "$backup"
        return 1
    fi
    apt-get install -y --no-install-recommends ca-certificates curl gnupg lsb-release || { _e131_restore_xanmod_apt_snapshot "$backup"; return 1; }
    keytmp=$(_e118_mktemp xanmod-archive.key) || return 1; keygpg=$(_e118_mktemp xanmod-archive-keyring.gpg) || return 1
    curl --proto '=https' --tlsv1.2 -fL --connect-timeout 10 --max-time 120 https://dl.xanmod.org/archive.key -o "$keytmp" || { _e131_restore_xanmod_apt_snapshot "$backup"; return 1; }
    gpg --batch --show-keys "$keytmp" >/dev/null 2>&1 || { error "archive.key 不是有效 OpenPGP 公钥。"; _e131_restore_xanmod_apt_snapshot "$backup"; return 1; }
    gpg --batch --yes --dearmor -o "$keygpg" "$keytmp" || { _e131_restore_xanmod_apt_snapshot "$backup"; return 1; }
    install -m 0644 "$keygpg" "$E131_XANMOD_KEYRING" || { _e131_restore_xanmod_apt_snapshot "$backup"; return 1; }
    printf 'deb [signed-by=%s] http://deb.xanmod.org %s main\n' "$E131_XANMOD_KEYRING" "$code" | _e131_atomic_text_file "$E131_XANMOD_LIST" 0644 || { _e131_restore_xanmod_apt_snapshot "$backup"; return 1; }
    rm -f /etc/apt/keyrings/xanmod.gpg 2>/dev/null || true
    if ! apt-get update -o Acquire::Retries=3; then
        error "官方 archive.key/codename 仓库更新失败，恢复旧仓库。"
        _e131_restore_xanmod_apt_snapshot "$backup"
        apt-get update >/dev/null 2>&1 || true
        return 1
    fi
    apt-cache show "$pkg" >/dev/null 2>&1 || { error "仓库中没有 $pkg；codename或分支可能不受支持。"; return 1; }
    apt-get install -y "$pkg" || return 1
    kver=$(ls -t /boot/vmlinuz-*xanmod* 2>/dev/null | head -n1 | sed 's|.*/vmlinuz-||')
    test -n "$kver" || { error "安装后未找到 XanMod vmlinuz。"; return 1; }
    _kernel_pre_reboot_verify_e52 "$kver" || return 1
    info "XanMod 官方包已安装并通过 boot/initramfs/GRUB 校验：$kver"
    info "仓库修复前快照：$backup.*"
    warn "旧内核已保留；脚本没有自动 reboot。重启前先确认 GRUB/VNC/救援入口。"
}


# V199e137 FINAL MODULE REWRITE
# Eight final modules are owned here. Historical definitions above remain only
# for helper compatibility; the dispatcher below calls the E135 functions.
#==============================================================================

readonly E135_VERSION="199e136"
readonly E135_DIR="$CONFIG_DIR/e135"
readonly E135_BACKUP_DIR="$E135_DIR/backups"
readonly E135_EXPORT_DIR="$CONFIG_DIR/export"
readonly E135_NETWORK_CONF="/etc/sysctl.d/99-xray-e135-network.conf"
readonly E135_NETWORK_STATE="$E135_DIR/network-state.env"
readonly E135_TRAFFIC_IFACE_FILE="$E135_DIR/traffic-interface.txt"
readonly E135_LIMITS_FILE="/etc/systemd/system/xray.service.d/99-xray-e135.conf"
readonly E135_FAIL2BAN_JAIL="/etc/fail2ban/jail.d/99-xray-sshguard-e135.conf"
readonly E135_FAIL2BAN_NAME="xray-sshd-e135"
readonly E135_SELF_PATH="$SCRIPT_DIR/ex199e136.sh"
readonly E135_LATEST_PATH="$SCRIPT_DIR/ex199e_latest.sh"

_e135_prepare() {
    _e118_runtime_init || return 1
    mkdir -p "$E135_DIR" "$E135_BACKUP_DIR" "$E135_EXPORT_DIR" || return 1
    chmod 0700 "$E135_DIR" "$E135_BACKUP_DIR" "$E135_EXPORT_DIR" 2>/dev/null || true
}

_e135_pause() { local _x=""; read -rp "按 Enter 继续..." _x || true; }

_e135_valid_ip() {
    local v="${1:-}"
    [[ "$v" =~ ^([0-9]{1,3}\.){3}[0-9]{1,3}$ ]] && awk -F. '{for(i=1;i<=4;i++) if($i<0||$i>255) exit 1}' <<<"$v" && return 0
    [[ "$v" == *:* ]] && return 0
    return 1
}

_e135_safe_name() {
    printf '%s' "${1:-node}" | tr -cs 'A-Za-z0-9._-' '_' | sed 's/^_\+//;s/_\+$//' | cut -c1-80
}

_e135_current_ssh_ip() {
    local ip=""
    if test -n "${SSH_CONNECTION:-}"; then ip=${SSH_CONNECTION%% *}
    elif test -n "${SSH_CLIENT:-}"; then ip=${SSH_CLIENT%% *}
    fi
    _e135_valid_ip "$ip" && printf '%s' "$ip"
}

_e135_current_ssh_port() {
    local _a _b _c p=""
    if test -n "${SSH_CONNECTION:-}"; then
        read -r _a _b _c p <<<"$SSH_CONNECTION"
    fi
    [[ "$p" =~ ^[0-9]+$ ]] && ((p>=1 && p<=65535)) && printf '%s' "$p"
}

_e135_snapshot_file() {
    local src="$1" dst="$2"
    mkdir -p "$(dirname "$dst")" || return 1
    if test -e "$src" || test -L "$src"; then
        cp -a -- "$src" "$dst.present" || return 1
    else
        : > "$dst.absent" || return 1
    fi
}

_e135_restore_file() {
    local dst="$1" src="$2"
    if test -e "$src.present" || test -L "$src.present"; then
        mkdir -p "$(dirname "$dst")" || return 1
        rm -rf -- "$dst" 2>/dev/null || true
        cp -a -- "$src.present" "$dst" || return 1
    elif test -e "$src.absent"; then
        rm -rf -- "$dst" 2>/dev/null || true
    fi
}

#------------------------------------------------------------------------------
# Module 7: one network owner. Default tcp_notsent_lowat is always 131072.
#------------------------------------------------------------------------------
_e135_network_keys() {
    cat <<'EOF_E135_KEYS'
net.core.default_qdisc
net.ipv4.tcp_congestion_control
net.ipv4.tcp_mtu_probing
net.ipv4.tcp_slow_start_after_idle
net.ipv4.tcp_notsent_lowat
net.ipv4.tcp_limit_output_bytes
net.ipv4.tcp_fastopen
net.ipv4.tcp_ecn
net.core.somaxconn
net.core.netdev_max_backlog
net.core.rmem_max
net.core.wmem_max
net.ipv4.tcp_rmem
net.ipv4.tcp_wmem
net.ipv4.ip_local_port_range
EOF_E135_KEYS
}

_e135_network_candidate() {
    local profile="${1:-balanced}" out="$2" cc=qdisc
    modprobe tcp_bbr >/dev/null 2>&1 || true
    modprobe sch_fq >/dev/null 2>&1 || true
    if sysctl -n net.ipv4.tcp_available_congestion_control 2>/dev/null | grep -qw bbr; then cc=bbr
    elif sysctl -n net.ipv4.tcp_available_congestion_control 2>/dev/null | grep -qw cubic; then cc=cubic
    else cc=$(sysctl -n net.ipv4.tcp_congestion_control 2>/dev/null || echo reno); fi
    qdisc=fq
    {
        echo "# Managed exclusively by ex199e136; profile=$profile; generated=$(date -Is 2>/dev/null || date)"
        echo "net.core.default_qdisc = $qdisc"
        echo "net.ipv4.tcp_congestion_control = $cc"
        echo "net.ipv4.tcp_mtu_probing = 1"
        echo "net.ipv4.tcp_slow_start_after_idle = 0"
        echo "net.ipv4.tcp_notsent_lowat = 131072"
        case "$profile" in
            low)
                echo "net.ipv4.tcp_limit_output_bytes = 524288"
                echo "net.core.somaxconn = 4096"
                echo "net.core.netdev_max_backlog = 2048"
                echo "net.core.rmem_max = 16777216"
                echo "net.core.wmem_max = 16777216"
                echo "net.ipv4.tcp_rmem = 4096 131072 16777216"
                echo "net.ipv4.tcp_wmem = 4096 16384 16777216"
                ;;
            throughput)
                echo "net.ipv4.tcp_limit_output_bytes = 4194304"
                echo "net.core.somaxconn = 16384"
                echo "net.core.netdev_max_backlog = 8192"
                echo "net.core.rmem_max = 97108868"
                echo "net.core.wmem_max = 97108868"
                echo "net.ipv4.tcp_rmem = 4096 7990577 97108868"
                echo "net.ipv4.tcp_wmem = 4096 7990577 97108868"
                ;;
            *)
                echo "net.ipv4.tcp_limit_output_bytes = 1048576"
                echo "net.core.somaxconn = 8192"
                echo "net.core.netdev_max_backlog = 4096"
                echo "net.core.rmem_max = 56699928"
                echo "net.core.wmem_max = 56699928"
                echo "net.ipv4.tcp_rmem = 4096 131072 56699928"
                echo "net.ipv4.tcp_wmem = 4096 16384 56699928"
                ;;
        esac
        echo "net.ipv4.tcp_fastopen = 1"
        echo "net.ipv4.tcp_ecn = 2"
        echo "net.ipv4.ip_local_port_range = 10240 65535"
    } > "$out"
}

_e135_network_validate() {
    local f="$1" key value seen="" available
    test -s "$f" || { error "网络候选文件为空。"; return 1; }
    while IFS='=' read -r key value; do
        key=$(printf '%s' "$key" | xargs); value=$(printf '%s' "$value" | xargs)
        case "$key" in ''|'#'*) continue ;; esac
        grep -Fxq "$key" < <(_e135_network_keys) || { error "非 E135 白名单参数：$key"; return 1; }
        [[ " $seen " != *" $key "* ]] || { error "候选参数重复：$key"; return 1; }
        seen="$seen $key"
        test -w "/proc/sys/${key//./\/}" || { warn "当前内核不支持：$key"; continue; }
        case "$key" in
            net.ipv4.tcp_notsent_lowat) test "$value" = 131072 || { error "默认 tcp_notsent_lowat 必须为131072。"; return 1; } ;;
            net.ipv4.tcp_congestion_control)
                available=$(sysctl -n net.ipv4.tcp_available_congestion_control 2>/dev/null || true)
                [[ " $available " == *" $value "* ]] || { error "拥塞控制不可用：$value"; return 1; }
                ;;
            net.ipv4.tcp_rmem|net.ipv4.tcp_wmem)
                [[ "$value" =~ ^[0-9]+[[:space:]]+[0-9]+[[:space:]]+[0-9]+$ ]] || return 1 ;;
            *) [[ "$value" =~ ^[A-Za-z0-9._-]+([[:space:]][0-9]+)?$ ]] || { error "参数值格式非法：$key=$value"; return 1; } ;;
        esac
    done < "$f"
}

_e135_sysctl_sources() {
    printf '%s\n' /etc/sysctl.conf
    find /etc/sysctl.d -maxdepth 1 -type f -name '*.conf' -print 2>/dev/null | sort
}

_e135_network_audit() {
    title "V199e137：网络参数单一所有权审计"
    local key hits=0
    while IFS= read -r key; do
        echo "[$key]"
        grep -RnsE "^[[:space:]]*${key//./\\.}[[:space:]]*=" /etc/sysctl.conf /etc/sysctl.d 2>/dev/null | sed 's/^/  /' || echo "  未定义"
        local c; c=$(grep -RhsE "^[[:space:]]*${key//./\\.}[[:space:]]*=" /etc/sysctl.conf /etc/sysctl.d 2>/dev/null | wc -l)
        (( c > 1 )) && hits=$((hits+1))
    done < <(_e135_network_keys)
    echo
    echo "运行态 tcp_notsent_lowat=$(sysctl -n net.ipv4.tcp_notsent_lowat 2>/dev/null || echo unsupported)"
    echo "唯一目标文件：$E135_NETWORK_CONF"
    echo "存在重复定义的受管参数数：$hits"
}

_e135_network_backup_and_strip() {
    local bdir="$1" f tmp keyexpr
    mkdir -p "$bdir/files" || return 1
    : > "$bdir/manifest"
    keyexpr=$( _e135_network_keys | awk '{gsub(/\./,"\\."); printf "%s%s",sep,$0; sep="|"}' )
    while IFS= read -r f; do
        test -f "$f" || continue
        test "$f" = "$E135_NETWORK_CONF" && continue
        if grep -Eq "^[[:space:]]*($keyexpr)[[:space:]]*=" "$f"; then
            printf '%s\n' "$f" >> "$bdir/manifest"
            cp -a --parents "$f" "$bdir/files" || return 1
            tmp=$(_e118_mktemp sysctl-strip.conf) || return 1
            awk -v re="^[[ :space:]]*(""$keyexpr" ")[[ :space:]]*=" '$0 !~ re {print}' "$f" > "$tmp" || return 1
            install -m 0644 "$tmp" "$f" || return 1
        fi
    done < <(_e135_sysctl_sources)
}

_e135_network_restore_files() {
    local bdir="$1" f
    test -s "$bdir/manifest" || return 0
    while IFS= read -r f; do
        test -n "$f" || continue
        cp -a "$bdir/files$f" "$f" || return 1
    done < "$bdir/manifest"
}

_e135_network_apply() {
    local profile="${1:-balanced}" confirm="${2:-}" candidate backup key old failed=0
    _e135_prepare || return 1
    candidate=$(_e118_mktemp e135-network.conf) || return 1
    _e135_network_candidate "$profile" "$candidate" || return 1
    _e135_network_validate "$candidate" || return 1
    if test "$confirm" != force; then
        warn "将清理所有受管参数的旧重复定义，并把 tcp_notsent_lowat 固定为131072。"
        read -rp "输入 APPLY-NETWORK 确认: " confirm || true
        test "$confirm" = APPLY-NETWORK || { info "已取消。"; return 0; }
    fi
    backup="$E135_BACKUP_DIR/network-$(date +%Y%m%d_%H%M%S)-$$"
    mkdir -p "$backup" || return 1
    : > "$backup/runtime.env"
    while IFS= read -r key; do
        old=$(sysctl -n "$key" 2>/dev/null || true)
        printf '%s|%s\n' "$key" "$old" >> "$backup/runtime.env"
    done < <(_e135_network_keys)
    _e135_snapshot_file "$E135_NETWORK_CONF" "$backup/e135-conf" || return 1
    _e135_network_backup_and_strip "$backup" || { error "旧定义迁移失败。"; _e135_network_restore_files "$backup" || true; return 1; }
    systemctl disable --now xray-accel-e125.service xray-accel-e126.service >/dev/null 2>&1 || true
    rm -f /etc/systemd/system/xray-accel-e125.service /etc/systemd/system/xray-accel-e126.service \
        /usr/local/bin/xray-accel-e125.sh /usr/local/bin/xray-accel-e126.sh \
        /etc/sysctl.d/99-xray-e125-accel.conf /etc/sysctl.d/99-xray-e126-accel.conf 2>/dev/null || true
    install -m 0644 "$candidate" "$E135_NETWORK_CONF" || failed=1
    if test "$failed" -eq 0; then
        while IFS='=' read -r key old; do
            key=$(printf '%s' "$key" | xargs); old=$(printf '%s' "$old" | xargs)
            case "$key" in ''|'#'*) continue ;; esac
            test -w "/proc/sys/${key//./\/}" || continue
            sysctl -w "$key=$old" >/dev/null 2>&1 || { failed=1; break; }
        done < "$candidate"
    fi
    if test "$failed" -eq 0; then
        while IFS='=' read -r key old; do
            key=$(printf '%s' "$key" | xargs); old=$(printf '%s' "$old" | xargs)
            case "$key" in ''|'#'*) continue ;; esac
            test -e "/proc/sys/${key//./\/}" || continue
            test "$(sysctl -n "$key" 2>/dev/null | xargs)" = "$old" || { error "运行态读回失败：$key"; failed=1; break; }
        done < "$candidate"
    fi
    if test "$failed" -ne 0; then
        error "E135网络参数应用失败，恢复旧文件和运行值。"
        _e135_restore_file "$E135_NETWORK_CONF" "$backup/e135-conf" || true
        _e135_network_restore_files "$backup" || true
        while IFS='|' read -r key old; do test -n "$old" && sysctl -w "$key=$old" >/dev/null 2>&1 || true; done < "$backup/runtime.env"
        return 1
    fi
    {
        echo "profile=$profile"
        echo "applied=$(date -Is 2>/dev/null || date)"
        echo "tcp_notsent_lowat=131072"
        echo "backup=$backup"
    } > "$E135_NETWORK_STATE"
    chmod 0600 "$E135_NETWORK_STATE" 2>/dev/null || true
    systemctl daemon-reload >/dev/null 2>&1 || true
    info "E135网络参数已应用；tcp_notsent_lowat=131072；旧重复定义已迁出。"
}

_e82_set_tcp_notsent_lowat() { _e135_network_apply balanced force; }
_e88_set_tcp_notsent_lowat() { _e135_network_apply balanced force; }
apply_default_full_sysctl_profile_e60() { _e135_network_apply balanced force; }
_e126_apply_profile() { _e135_network_apply "${1:-balanced}"; }

_e135_network_menu() {
    local n=""
    while true; do
        clear; title "V199e137：统一网络优化参数中心"
        echo "  当前 tcp_notsent_lowat: $(sysctl -n net.ipv4.tcp_notsent_lowat 2>/dev/null || echo unsupported)"
        echo "  唯一持久化文件: $E135_NETWORK_CONF"
        echo "  1) 稳态推荐档（默认 tcp_notsent_lowat=131072）"
        echo "  2) 低排队延迟档（仍固定 tcp_notsent_lowat=131072）"
        echo "  3) 高吞吐档（仍固定 tcp_notsent_lowat=131072）"
        echo "  4) 审计全部重复定义"
        echo "  5) 重新清理重复定义并重放当前档"
        echo "  6) 显示全部受管参数运行值"
        echo "  0) 返回"
        read -rp "请输入操作代码: " n || true
        case "$n" in
            1) _e135_network_apply balanced; _e135_pause ;;
            2) _e135_network_apply low; _e135_pause ;;
            3) _e135_network_apply throughput; _e135_pause ;;
            4) _e135_network_audit; _e135_pause ;;
            5) _e135_network_apply "$(sed -n 's/^profile=//p' "$E135_NETWORK_STATE" 2>/dev/null | head -n1 || echo balanced)" force; _e135_pause ;;
            6) while IFS= read -r key; do printf '  %-44s %s\n' "$key" "$(sysctl -n "$key" 2>/dev/null || echo unsupported)"; done < <(_e135_network_keys); _e135_pause ;;
            0) return 0 ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

do_network_params_menu_e56() { _e135_network_menu; }
_e126_accel_menu() { _e135_network_menu; }

#------------------------------------------------------------------------------
# Nice=-20 has one drop-in owner and validates the actual Xray process.
#------------------------------------------------------------------------------
fix_xray_systemd_limits() {
    local old tmp was_active=0
    _e135_prepare || return 1
    mkdir -p "$(dirname "$E135_LIMITS_FILE")" || return 1
    old=$(_e118_mktemp e135-limits-old.conf) || return 1
    if test -f "$E135_LIMITS_FILE"; then cp -a "$E135_LIMITS_FILE" "$old"; else : > "$old"; fi
    systemctl is-active --quiet xray.service 2>/dev/null && was_active=1 || true
    tmp=$(_e118_mktemp e135-limits.conf) || return 1
    cat > "$tmp" <<'EOF_E135_LIMITS'
[Service]
LimitNOFILE=1048576
LimitNPROC=262144
LimitSTACK=8M
TasksMax=infinity
Nice=-20
OOMScoreAdjust=-500
Environment="GOGC=300"
Restart=on-failure
RestartSec=5s
EOF_E135_LIMITS
    install -m 0644 "$tmp" "$E135_LIMITS_FILE" || return 1
    systemctl daemon-reload >/dev/null 2>&1 || return 1
    if test "$was_active" -eq 1; then
        if ! systemctl restart xray.service >/dev/null 2>&1 || ! _e127_verify_xray_runtime "$CONFIG" 12 || ! _e131_verify_nice_runtime; then
            error "Nice=-20运行态验证失败，恢复旧drop-in。"
            if test -s "$old"; then install -m 0644 "$old" "$E135_LIMITS_FILE"; else rm -f "$E135_LIMITS_FILE"; fi
            systemctl daemon-reload >/dev/null 2>&1 || true
            systemctl restart xray.service >/dev/null 2>&1 || true
            return 1
        fi
    else
        test "$(systemctl show xray.service -p Nice --value 2>/dev/null || true)" = -20 || return 1
    fi
    info "Xray Nice=-20 已由 E135 单一drop-in管理。"
}

#------------------------------------------------------------------------------
# Module 2: node export. Address and port are separate; QR failures are visible.
#------------------------------------------------------------------------------
_e135_ensure_qrencode() {
    command -v qrencode >/dev/null 2>&1 && return 0
    warn "未检测到 qrencode。请先执行热更新，或手动安装 qrencode；URI仍会正常导出。"
    return 1
}

_e135_emit_qr() {
    local uri="$1" label="$2" safe png txt terminal_ok=0
    safe=$(_e135_safe_name "$label"); test -n "$safe" || safe=node
    mkdir -p "$E135_EXPORT_DIR" || return 1
    txt="$E135_EXPORT_DIR/${safe}.txt"; png="$E135_EXPORT_DIR/${safe}.png"
    printf '%s\n' "$uri" > "$txt"; chmod 0600 "$txt" 2>/dev/null || true
    if ! _e135_ensure_qrencode; then
        warn "qrencode不可用；已保存完整链接：$txt"
        return 0
    fi
    if test -t 1; then
        echo
        if qrencode -m 2 -t ANSIUTF8 "$uri" 2>/dev/null; then terminal_ok=1
        elif qrencode -m 2 -t UTF8 "$uri" 2>/dev/null; then terminal_ok=1
        else warn "终端二维码生成失败，继续尝试PNG。"; fi
    fi
    if qrencode -m 2 -o "$png" "$uri" 2>/dev/null && test -s "$png"; then
        chmod 0600 "$png" 2>/dev/null || true
        info "二维码PNG：$png"
    else
        rm -f "$png" 2>/dev/null || true
        warn "该链接未能生成PNG二维码，可能是参数过长；完整URI已保存：$txt"
    fi
    test "$terminal_ok" -eq 1 || info "终端未显示二维码；可使用上面的PNG或URI文件。"
}

_e135_print_host_port() {
    printf '  %-18s %s\n' "地址:" "$1"
    printf '  %-18s %s\n' "端口:" "$2"
}

do_summary() {
    _e135_prepare || return 1
    test -s "$CONFIG" || { error "config.json不存在，请先新建节点。"; return 1; }
    jq empty "$CONFIG" >/dev/null 2>&1 || { error "config.json不是合法JSON。"; return 1; }
    title "V199e137 节点链接、参数与二维码输出中心"
    local ip host inbound port security network tag idx uuid flow email sid sni priv pbk link enc path type_part found=0 label method pass b64
    ip=$(_get_ip); test -n "$ip" && test "$ip" != 获取失败 || { ip=YOUR_SERVER_IP; warn "公网IP获取失败，请手动替换。"; }
    [[ "$ip" == *:* ]] && host="[$ip]" || host="$ip"
    while IFS= read -r inbound; do
        security=$(jq -r '.streamSettings.security//"none"' <<<"$inbound")
        network=$(jq -r '.streamSettings.network//"tcp"' <<<"$inbound")
        port=$(jq -r '.port' <<<"$inbound"); tag=$(jq -r '.tag//"vless"' <<<"$inbound")
        if test "$security" = reality; then
            priv=$(jq -r '.streamSettings.realitySettings.privateKey//empty' <<<"$inbound")
            pbk=$(_e124_reality_password_for_private "$priv" "" 2>/dev/null || true)
            sni=$(jq -r '.streamSettings.realitySettings.serverNames[0]//empty' <<<"$inbound")
            idx=0
            while IFS= read -r uuid; do
                test -n "$uuid" || continue; found=1
                flow=$(jq -r --argjson i "$idx" '.settings.clients[$i].flow//"xtls-rprx-vision"' <<<"$inbound")
                email=$(jq -r --argjson i "$idx" '.settings.clients[$i].email//"Reality"' <<<"$inbound")
                sid=$(_e118_user_sid "$uuid" "$idx")
                hr; printf '  %b【VLESS Reality Vision】%b\n' "$cyan" "$none"
                _e135_print_host_port "$ip" "$port"
                printf '  %-18s %s\n' "UUID:" "$uuid"
                printf '  %-18s %s\n' "流控:" "$flow"
                printf '  %-18s %s\n' "传输:" "$network"
                printf '  %-18s %s\n' "安全:" "reality"
                printf '  %-18s %s\n' "SNI:" "$sni"
                printf '  %-18s %s\n' "Password(pbk):" "${pbk:-缺失}"
                printf '  %-18s %s\n' "ShortId:" "${sid:-缺失}"
                printf '  %-18s %s\n' "Fingerprint:" "chrome"
                if test -n "$pbk" && test -n "$sid" && test -n "$sni"; then
                    link="vless://${uuid}@${host}:${port}?encryption=none&flow=$(_e118_urlencode "$flow")&security=reality&sni=$(_e118_urlencode "$sni")&fp=chrome&pbk=$(_e118_urlencode "$pbk")&sid=$(_e118_urlencode "$sid")&type=tcp#$(_e118_urlencode "$email")"
                    printf '\n  %b配置导入链接:%b\n%s\n' "$cyan" "$none" "$link"
                    _e135_emit_qr "$link" "${tag}-${email}-${idx}-reality"
                else warn "Reality参数不完整，拒绝生成无效链接。"; fi
                idx=$((idx+1))
            done < <(jq -r '.settings.clients[]?.id//empty' <<<"$inbound")
        elif test "$(jq -r '.settings.decryption//"none"' <<<"$inbound")" != none; then
            enc=$(cat "${E77_VLESSENC_CLIENT_FILE:-$CONFIG_DIR/vlessenc.client.txt}" 2>/dev/null || true)
            idx=0
            while IFS= read -r uuid; do
                test -n "$uuid" || continue; found=1
                flow=$(jq -r --argjson i "$idx" '.settings.clients[$i].flow//"xtls-rprx-vision"' <<<"$inbound")
                email=$(jq -r --argjson i "$idx" '.settings.clients[$i].email//"VLESSENC"' <<<"$inbound")
                hr; printf '  %b【VLESSENC Vision】%b\n' "$cyan" "$none"
                _e135_print_host_port "$ip" "$port"
                printf '  %-18s %s\n' "UUID:" "$uuid"
                printf '  %-18s %s\n' "流控:" "$flow"
                printf '  %-18s %s\n' "传输:" "$network"
                printf '  %-18s %s\n' "安全:" "none"
                if test -n "$enc"; then
                    if test "$network" = xhttp; then path=$(jq -r '.streamSettings.xhttpSettings.path//empty' <<<"$inbound"); type_part="type=xhttp&path=$(_e118_urlencode "$path")&mode=auto"; else type_part=type=tcp; fi
                    link="vless://${uuid}@${host}:${port}?encryption=$(_e118_urlencode "$enc")&flow=$(_e118_urlencode "$flow")&security=none&${type_part}#$(_e118_urlencode "$email")"
                    printf '\n  %b完整导入链接:%b\n%s\n' "$cyan" "$none" "$link"
                    _e135_emit_qr "$link" "${tag}-${email}-${idx}-vlessenc"
                else warn "缺少VLESSENC客户端encryption参数文件。"; fi
                idx=$((idx+1))
            done < <(jq -r '.settings.clients[]?.id//empty' <<<"$inbound")
        fi
    done < <(jq -c '.inbounds[]? | select(.protocol=="vless")' "$CONFIG")
    while IFS= read -r inbound; do
        found=1; port=$(jq -r '.port' <<<"$inbound"); method=$(jq -r '.settings.method' <<<"$inbound"); pass=$(jq -r '.settings.password' <<<"$inbound")
        label="${REMARK_NAME:-xp-reality}-SS2022"; b64=$(printf '%s:%s' "$method" "$pass" | base64 | tr '+/' '-_' | tr -d '=\n\r')
        link="ss://${b64}@${host}:${port}#$(_e118_urlencode "$label")"
        hr; printf '  %b【SS2022】%b\n' "$cyan" "$none"; _e135_print_host_port "$ip" "$port"
        printf '  %-18s %s\n' "加密方式:" "$method"; printf '  %-18s %s\n' "密码:" "$pass"
        printf '\n  %b配置导入链接:%b\n%s\n' "$cyan" "$none" "$link"
        _e135_emit_qr "$link" "${label}-${port}"
    done < <(jq -c '.inbounds[]? | select(.protocol=="shadowsocks")' "$CONFIG")
    test "$found" -eq 1 || { warn "没有可导出的节点。"; return 1; }
    info "导出目录：$E135_EXPORT_DIR"
}

#------------------------------------------------------------------------------
# Module 3: unified user and credential management with one rollback window.
#------------------------------------------------------------------------------
_e135_port_available() {
    local p="$1" current="${2:-}"
    [[ "$p" =~ ^[0-9]+$ ]] && ((p>=1 && p<=65535)) || return 1
    test "$p" = "$current" && return 0
    ss -H -tuln 2>/dev/null | awk '{print $5}' | grep -Eq "(^|:|\])${p}$" && return 1
    return 0
}

_e135_copy_or_empty() {
    local src="$1" dst="$2"
    if test -f "$src"; then cp -f "$src" "$dst"; else : > "$dst"; fi
}

_e135_bundle_commit() {
    local cfg="$1" smap="$2" tmap="$3" pkey="$4" reason="${5:-user-change}" bdir was_active=0 failed=0
    _e118_xray_test_config "$cfg" 1 || return 1
    bdir=$(_e116_backup_state "before_e135_${reason}") || return 1
    was_active=$(sed -n 's/^xray_was_active=//p' "$bdir/meta.env" 2>/dev/null | head -n1); was_active=${was_active:-0}
    E118_TX_ACTIVE=1; E118_TX_BACKUP="$bdir"; E118_TX_WAS_ACTIVE="$was_active"
    trap '' INT TERM HUP
    install -m 0600 "$cfg" "$CONFIG_DIR/.config.e135.$$" || failed=1
    test "$failed" -ne 0 || install -m 0600 "$smap" "$CONFIG_DIR/.user_sni.e135.$$" || failed=1
    test "$failed" -ne 0 || install -m 0600 "$tmap" "$CONFIG_DIR/.user_time.e135.$$" || failed=1
    if test -n "$pkey"; then test "$failed" -ne 0 || install -m 0600 "$pkey" "$CONFIG_DIR/.public.e135.$$" || failed=1; fi
    if test "$failed" -eq 0; then
        mv -f "$CONFIG_DIR/.config.e135.$$" "$CONFIG" || failed=1
        test "$failed" -ne 0 || mv -f "$CONFIG_DIR/.user_sni.e135.$$" "$USER_SNI_MAP" || failed=1
        test "$failed" -ne 0 || mv -f "$CONFIG_DIR/.user_time.e135.$$" "$USER_TIME_MAP" || failed=1
        if test -n "$pkey"; then test "$failed" -ne 0 || mv -f "$CONFIG_DIR/.public.e135.$$" "$PUBKEY_FILE" || failed=1; fi
    fi
    rm -f "$CONFIG_DIR"/.config.e135.$$ "$CONFIG_DIR"/.user_sni.e135.$$ "$CONFIG_DIR"/.user_time.e135.$$ "$CONFIG_DIR"/.public.e135.$$ 2>/dev/null || true
    trap '_e118_signal_handler INT' INT; trap '_e118_signal_handler TERM' TERM; trap '_e118_signal_handler HUP' HUP
    if test "$failed" -eq 0; then
        fix_permissions
        if test "$was_active" = 1; then
            systemctl restart xray.service >/dev/null 2>&1 || failed=1
            test "$failed" -ne 0 || _e127_verify_xray_runtime "$CONFIG" 12 || failed=1
        fi
    fi
    if test "$failed" -ne 0; then
        error "用户/凭据事务失败，恢复变更前配置与元数据。"
        _e118_restore_state "$bdir" || error "自动回滚失败：$bdir"
        E118_TX_ACTIVE=0; E118_TX_BACKUP=""; E118_TX_WAS_ACTIVE=0
        return 1
    fi
    E118_TX_ACTIVE=0; E118_TX_BACKUP=""; E118_TX_WAS_ACTIVE=0
    info "事务提交成功：$reason"
}

_e135_map_remove_uuid() {
    local file="$1" uuid="$2" out="$3"
    awk -F'|' -v u="$uuid" '$1!=u && $1!="" {print}' "$file" 2>/dev/null > "$out" || true
}

_e135_map_replace_uuid() {
    local old="$1" new="$2" sid="$3" sni="$4" ctime="$5" smap="$6" tmap="$7" t
    t=$(_e118_mktemp map-replace-sni) || return 1
    awk -F'|' -v u="$old" '$1!=u && $1!="" {print}' "$smap" > "$t" 2>/dev/null || true
    test -n "$sid" && printf '%s|%s|%s\n' "$new" "$sid" "$sni" >> "$t"
    mv -f "$t" "$smap" || return 1
    t=$(_e118_mktemp map-replace-time) || return 1
    awk -F'|' -v u="$old" '$1!=u && $1!="" {print}' "$tmap" > "$t" 2>/dev/null || true
    printf '%s|%s\n' "$new" "$ctime" >> "$t"
    mv -f "$t" "$tmap"
}

_e135_choose_single_sni() {
    local d="" choice=""
    echo "  1) 使用缓存第一项：$(awk 'NR==1{print $1}' "$SNI_CACHE_FILE" 2>/dev/null || echo www.honda.com)"
    echo "  2) 手动输入"
    read -rp "选择 (默认2): " choice || true
    if test "${choice:-2}" = 1; then d=$(awk 'NR==1{print $1}' "$SNI_CACHE_FILE" 2>/dev/null || true)
    else read -rp "请输入单一 Reality SNI/target 域名: " d || true; fi
    valid_domain "$d" || { error "域名格式非法。"; return 1; }
    verify_sni_strict "$d" || {
        read -rp "质检失败。输入 FORCE-SNI 强制使用: " choice || true
        test "$choice" = FORCE-SNI || return 1
    }
    BEST_SNI="$d"; SNI_JSON_ARRAY=$(json_array_from_args "$d")
}

verify_sni_strict() {
    local target="$1" out verify=0
    valid_domain "$target" || return 1
    out=$(timeout 10 openssl s_client -connect "$target:443" -servername "$target" -verify_hostname "$target" -verify_return_error -alpn h2 -tls1_3 </dev/null 2>&1 || true)
    grep -qi 'Verification: OK\|Verify return code: 0' <<<"$out" || verify=1
    grep -qi 'TLSv1.3\|TLSv1\.3' <<<"$out" || verify=1
    grep -qiE 'ALPN.*h2|ALPN protocol: h2' <<<"$out" || verify=1
    if test "$verify" -ne 0; then
        error "SNI证书主机名/TLS1.3/ALPN h2质检未全部通过。"
        printf '%s\n' "$out" | tail -n 20 | sed 's/^/    /'
        return 1
    fi
    info "SNI证书主机名、TLS1.3和ALPN h2质检通过。"
}

_e135_vless_users_menu() {
    local tag="$1" reality="$2" action idx count sid_count uuid remark new_uuid new_remark sid sni ctime current_port new_port cfg smap tmap pkey raw
    while true; do
        clear; title "V199e137：$(test "$reality" = 1 && echo Reality || echo VLESSENC) 用户事务中心"
        count=$(jq -r --arg t "$tag" '.inbounds[]|select(.tag==$t)|.settings.clients|length' "$CONFIG")
        current_port=$(jq -r --arg t "$tag" '.inbounds[]|select(.tag==$t)|.port' "$CONFIG")
        if test "$reality" = 1; then
            sid_count=$(jq -r --arg t "$tag" '.inbounds[]|select(.tag==$t)|.streamSettings.realitySettings.shortIds|length' "$CONFIG")
            test "$sid_count" = "$count" || { error "Reality clients数量($count)与shortIds数量($sid_count)不一致，拒绝用户操作；请先修复配置。"; return 1; }
            sni=$(jq -r --arg t "$tag" '.inbounds[]|select(.tag==$t)|.streamSettings.realitySettings.serverNames[0]//empty' "$CONFIG")
        else sni=""; fi
        jq -r --arg t "$tag" '.inbounds[]|select(.tag==$t)|.settings.clients|to_entries[]|"  \(.key+1)) \(.value.email//"未命名")  UUID=\(.value.id)"' "$CONFIG"
        echo "  端口: $current_port"; test "$reality" = 1 && echo "  全局SNI: $sni"
        hr
        echo "  a) 新增用户     m) 导入UUID"
        echo "  r) 修改备注     u) 更换UUID"
        test "$reality" = 1 && echo "  i) 轮换ShortId  s) 修改全局SNI/target  k) 轮换Reality密钥"
        echo "  p) 修改端口     d) 删除用户"
        echo "  q) 返回"
        read -rp "输入操作: " action || true
        case "$action" in
            q|Q) return 0 ;;
            a|A|m|M)
                if [[ "$action" =~ ^[aA]$ ]]; then uuid=$(_e118_new_uuid) || continue
                else read -rp "UUID: " uuid || true; _e118_valid_uuid "$uuid" || { error "UUID非法。"; _e135_pause; continue; }; fi
                jq -e --arg u "$uuid" '[.inbounds[]?.settings.clients[]?.id]|index($u)==null' "$CONFIG" >/dev/null || { error "UUID重复。"; _e135_pause; continue; }
                read -rp "备注: " remark || true; remark=${remark:-user-$(date +%s)}
                sid=""; test "$reality" = 1 && sid=$(_e118_new_sid)
                cfg=$(_e118_mktemp user-add.json); smap=$(_e118_mktemp user-add-sni); tmap=$(_e118_mktemp user-add-time)
                _e135_copy_or_empty "$USER_SNI_MAP" "$smap"; _e135_copy_or_empty "$USER_TIME_MAP" "$tmap"
                jq --arg t "$tag" --arg u "$uuid" --arg e "$remark" --arg sid "$sid" '
                  (.inbounds[]|select(.tag==$t)) |= (
                    .settings.clients += [{id:$u,flow:"xtls-rprx-vision",email:$e}] |
                    if (.streamSettings.security//"")=="reality" then .streamSettings.realitySettings.shortIds += [$sid] else . end
                  )' "$CONFIG" > "$cfg" || continue
                if test "$reality" = 1; then printf '%s|%s|%s\n' "$uuid" "$sid" "$sni" >> "$smap"; fi
                printf '%s|%s\n' "$uuid" "$(date '+%F %T')" >> "$tmap"
                _e135_bundle_commit "$cfg" "$smap" "$tmap" "" user-add && do_summary
                _e135_pause ;;
            r|R|u|U|i|I|d|D)
                read -rp "用户序号: " idx || true; [[ "$idx" =~ ^[0-9]+$ ]] && ((idx>=1 && idx<=count)) || { error "序号无效。"; _e135_pause; continue; }; idx=$((idx-1))
                uuid=$(jq -r --arg t "$tag" --argjson i "$idx" '.inbounds[]|select(.tag==$t)|.settings.clients[$i].id' "$CONFIG")
                remark=$(jq -r --arg t "$tag" --argjson i "$idx" '.inbounds[]|select(.tag==$t)|.settings.clients[$i].email//"未命名"' "$CONFIG")
                sid=""; test "$reality" = 1 && sid=$(jq -r --arg t "$tag" --argjson i "$idx" '.inbounds[]|select(.tag==$t)|.streamSettings.realitySettings.shortIds[$i]//empty' "$CONFIG")
                ctime=$(awk -F'|' -v u="$uuid" '$1==u{print $2;exit}' "$USER_TIME_MAP" 2>/dev/null || true); ctime=${ctime:-$(date '+%F %T')}
                cfg=$(_e118_mktemp user-edit.json); smap=$(_e118_mktemp user-edit-sni); tmap=$(_e118_mktemp user-edit-time)
                _e135_copy_or_empty "$USER_SNI_MAP" "$smap"; _e135_copy_or_empty "$USER_TIME_MAP" "$tmap"
                case "$action" in
                    r|R)
                        read -rp "新备注: " new_remark || true; test -n "$new_remark" || continue
                        jq --arg t "$tag" --argjson i "$idx" --arg e "$new_remark" '(.inbounds[]|select(.tag==$t)|.settings.clients[$i].email)=$e' "$CONFIG" > "$cfg" || { error "候选配置生成失败。"; _e135_pause; continue; } ;;
                    u|U)
                        read -rp "新UUID（回车自动）: " new_uuid || true; new_uuid=${new_uuid:-$(_e118_new_uuid)}
                        _e118_valid_uuid "$new_uuid" || { error "UUID非法。"; _e135_pause; continue; }
                        jq -e --arg u "$new_uuid" '[.inbounds[]?.settings.clients[]?.id]|index($u)==null' "$CONFIG" >/dev/null || { error "UUID重复。"; _e135_pause; continue; }
                        jq --arg t "$tag" --argjson i "$idx" --arg u "$new_uuid" '(.inbounds[]|select(.tag==$t)|.settings.clients[$i].id)=$u' "$CONFIG" > "$cfg" || { error "候选配置生成失败。"; _e135_pause; continue; }
                        _e135_map_replace_uuid "$uuid" "$new_uuid" "$sid" "$sni" "$ctime" "$smap" "$tmap" || continue ;;
                    i|I)
                        test "$reality" = 1 || { warn "VLESSENC没有ShortId。"; _e135_pause; continue; }
                        sid=$(_e118_new_sid) || continue
                        jq --arg t "$tag" --argjson i "$idx" --arg sid "$sid" '(.inbounds[]|select(.tag==$t)|.streamSettings.realitySettings.shortIds[$i])=$sid' "$CONFIG" > "$cfg" || { error "候选配置生成失败。"; _e135_pause; continue; }
                        awk -F'|' -v u="$uuid" -v sid="$sid" -v s="$sni" 'BEGIN{OFS="|";found=0} $1==u{print u,sid,s;found=1;next}{print} END{if(!found)print u,sid,s}' "$smap" > "$smap.new" && mv "$smap.new" "$smap" || { error "ShortId元数据更新失败。"; _e135_pause; continue; } ;;
                    d|D)
                        ((count>1)) || { error "至少保留一个用户。"; _e135_pause; continue; }
                        read -rp "输入 DELETE-$((idx+1)) 确认: " new_remark || true; test "$new_remark" = "DELETE-$((idx+1))" || continue
                        jq --arg t "$tag" --argjson i "$idx" '(.inbounds[]|select(.tag==$t)) |= (.settings.clients |= del(.[$i]) | if (.streamSettings.security//"")=="reality" then .streamSettings.realitySettings.shortIds |= del(.[$i]) else . end)' "$CONFIG" > "$cfg" || { error "候选配置生成失败。"; _e135_pause; continue; }
                        _e135_map_remove_uuid "$smap" "$uuid" "$smap.new"; mv "$smap.new" "$smap"
                        _e135_map_remove_uuid "$tmap" "$uuid" "$tmap.new"; mv "$tmap.new" "$tmap" ;;
                esac
                _e135_bundle_commit "$cfg" "$smap" "$tmap" "" "user-${action}" && do_summary
                _e135_pause ;;
            p|P)
                read -rp "新端口（当前$current_port）: " new_port || true; new_port=${new_port:-$current_port}
                _e135_port_available "$new_port" "$current_port" || { error "端口无效或被其它进程占用。"; _e135_pause; continue; }
                cfg=$(_e118_mktemp port.json); smap=$(_e118_mktemp port-sni); tmap=$(_e118_mktemp port-time)
                _e135_copy_or_empty "$USER_SNI_MAP" "$smap"; _e135_copy_or_empty "$USER_TIME_MAP" "$tmap"
                jq --arg t "$tag" --argjson p "$new_port" '(.inbounds[]|select(.tag==$t)|.port)=$p' "$CONFIG" > "$cfg" || { error "候选配置生成失败。"; _e135_pause; continue; }
                _e135_bundle_commit "$cfg" "$smap" "$tmap" "" port-change && do_summary; _e135_pause ;;
            s|S)
                test "$reality" = 1 || continue; _e135_choose_single_sni || { _e135_pause; continue; }
                cfg=$(_e118_mktemp sni.json); smap=$(_e118_mktemp sni-map); tmap=$(_e118_mktemp sni-time)
                _e135_copy_or_empty "$USER_SNI_MAP" "$smap"; _e135_copy_or_empty "$USER_TIME_MAP" "$tmap"
                jq --arg t "$tag" --arg s "$BEST_SNI" --arg target "$BEST_SNI:443" '(.inbounds[]|select(.tag==$t)|.streamSettings.realitySettings) |= (.serverNames=[$s]|.target=$target|del(.dest))' "$CONFIG" > "$cfg" || { error "候选配置生成失败。"; _e135_pause; continue; }
                awk -F'|' -v s="$BEST_SNI" 'BEGIN{OFS="|"} $1!=""{print $1,$2,s}' "$smap" > "$smap.new" && mv "$smap.new" "$smap"
                _e135_bundle_commit "$cfg" "$smap" "$tmap" "" sni-change && do_summary; _e135_pause ;;
            k|K)
                test "$reality" = 1 || continue
                raw=$("$XRAY_BIN" x25519 2>/dev/null || true); _e118_parse_x25519_output "$raw" || { error "X25519输出解析失败。"; _e135_pause; continue; }
                cfg=$(_e118_mktemp key.json); smap=$(_e118_mktemp key-sni); tmap=$(_e118_mktemp key-time); pkey=$(_e118_mktemp public.key)
                _e135_copy_or_empty "$USER_SNI_MAP" "$smap"; _e135_copy_or_empty "$USER_TIME_MAP" "$tmap"; printf '%s\n' "$E77_REALITY_PUB" > "$pkey"
                jq --arg t "$tag" --arg p "$E77_REALITY_PRIV" '(.inbounds[]|select(.tag==$t)|.streamSettings.realitySettings) |= (.privateKey=$p|del(.publicKey,.password))' "$CONFIG" > "$cfg" || { error "候选配置生成失败。"; _e135_pause; continue; }
                _e135_bundle_commit "$cfg" "$smap" "$tmap" "$pkey" key-rotate && do_summary; _e135_pause ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

_e135_ss_manager() {
    local tag="$1" action port new_port method pass cfg smap tmap
    while true; do
        clear; title "V199e137：SS2022凭据管理"
        port=$(jq -r --arg t "$tag" '.inbounds[]|select(.tag==$t)|.port' "$CONFIG")
        method=$(jq -r --arg t "$tag" '.inbounds[]|select(.tag==$t)|.settings.method' "$CONFIG")
        echo "  tag=$tag 端口=$port 方法=$method"
        echo "  1) 轮换密码  2) 修改端口  3) 修改方法并轮换密码  0) 返回"
        read -rp "操作: " action || true
        cfg=$(_e118_mktemp ss-edit.json); smap=$(_e118_mktemp ss-sni); tmap=$(_e118_mktemp ss-time)
        _e135_copy_or_empty "$USER_SNI_MAP" "$smap"; _e135_copy_or_empty "$USER_TIME_MAP" "$tmap"
        case "$action" in
            1) pass=$(e77_gen_ss2022_pass "$method") || continue; jq --arg t "$tag" --arg p "$pass" '(.inbounds[]|select(.tag==$t)|.settings.password)=$p' "$CONFIG" > "$cfg" || { error "候选配置生成失败。"; _e135_pause; continue; } ;;
            2) read -rp "新端口: " new_port || true; _e135_port_available "$new_port" "$port" || { error "端口无效或占用。"; _e135_pause; continue; }; jq --arg t "$tag" --argjson p "$new_port" '(.inbounds[]|select(.tag==$t)|.port)=$p' "$CONFIG" > "$cfg" || { error "候选配置生成失败。"; _e135_pause; continue; } ;;
            3) method=$(e77_select_ss2022_method); pass=$(e77_gen_ss2022_pass "$method") || continue; jq --arg t "$tag" --arg m "$method" --arg p "$pass" '(.inbounds[]|select(.tag==$t)|.settings.method)=$m|(.inbounds[]|select(.tag==$t)|.settings.password)=$p' "$CONFIG" > "$cfg" || { error "候选配置生成失败。"; _e135_pause; continue; } ;;
            0) return 0 ;;
            *) continue ;;
        esac
        _e135_bundle_commit "$cfg" "$smap" "$tmap" "" ss2022-change && do_summary
        _e135_pause
    done
}

do_user_manager() {
    _e135_prepare || return 1
    test -s "$CONFIG" || { error "config.json不存在。"; return 1; }
    jq empty "$CONFIG" >/dev/null 2>&1 || { error "config.json不是有效JSON。"; return 1; }
    local -a rows=(); local i=1 row protocol security tag choice
    mapfile -t rows < <(jq -r '.inbounds[]? | select(.protocol=="vless" or .protocol=="shadowsocks") | [.tag,.protocol,(.streamSettings.security//"none")] | @tsv' "$CONFIG")
    test "${#rows[@]}" -gt 0 || { warn "没有可管理入站。"; return 1; }
    while true; do
        clear; title "V199e137：用户、凭据、端口与密钥管理"
        i=1; for row in "${rows[@]}"; do IFS=$'\t' read -r tag protocol security <<<"$row"; printf '  %d) %-28s protocol=%s security=%s\n' "$i" "$tag" "$protocol" "$security"; i=$((i+1)); done
        echo "  0) 返回"; read -rp "选择入站: " choice || true
        test "$choice" = 0 && return 0
        [[ "$choice" =~ ^[0-9]+$ ]] && ((choice>=1 && choice<=${#rows[@]})) || { warn "序号无效。"; sleep 1; continue; }
        IFS=$'\t' read -r tag protocol security <<<"${rows[$((choice-1))]}"
        if test "$protocol" = shadowsocks; then _e135_ss_manager "$tag"
        elif test "$security" = reality; then _e135_vless_users_menu "$tag" 1
        else _e135_vless_users_menu "$tag" 0
        fi
        mapfile -t rows < <(jq -r '.inbounds[]? | select(.protocol=="vless" or .protocol=="shadowsocks") | [.tag,.protocol,(.streamSettings.security//"none")] | @tsv' "$CONFIG")
    done
}

#------------------------------------------------------------------------------
# Module 4: traffic center. vnStat is host-interface traffic, never mislabeled.
#------------------------------------------------------------------------------
_e135_default_iface() {
    local i
    i=$(cat "$E135_TRAFFIC_IFACE_FILE" 2>/dev/null || true)
    test -n "$i" && test -d "/sys/class/net/$i" && { printf '%s' "$i"; return; }
    ip -4 route show default 2>/dev/null | awk 'NR==1{print $5}'
}

_e135_vnstat_prepare() {
    local iface="$1"
    command -v vnstat >/dev/null 2>&1 || { pkg_install vnstat; command -v vnstat >/dev/null 2>&1 || return 1; }
    systemctl enable --now vnstat.service >/dev/null 2>&1 || systemctl enable --now vnstat >/dev/null 2>&1 || true
    if ! vnstat --iflist 2>/dev/null | tr ' ' '\n' | grep -Fxq "$iface"; then
        vnstat --add -i "$iface" >/dev/null 2>&1 || vnstat -u -i "$iface" >/dev/null 2>&1 || true
        systemctl restart vnstat.service >/dev/null 2>&1 || systemctl restart vnstat >/dev/null 2>&1 || true
    fi
    test -d "/sys/class/net/$iface"
}

_e135_xray_connections() {
    title "Xray当前连接与入站监听"
    local ports p
    ports=$(jq -r '.inbounds[]?.port//empty' "$CONFIG" 2>/dev/null | sort -nu | xargs echo)
    echo "  入站端口: ${ports:-none}"
    printf '  Xray进程TCP连接数: %s\n' "$(ss -Hntp 2>/dev/null | grep -c 'xray' || true)"
    for p in $ports; do printf '  端口 %-6s ESTABLISHED=%s\n' "$p" "$(ss -Hnt state established 2>/dev/null | awk -v p="$p" '$4 ~ (":"p"$") || $3 ~ (":"p"$") {c++} END{print c+0}')"; done
}

_e135_set_month_rotate() {
    local day old tmp
    read -rp "月结日1-28: " day || true; [[ "$day" =~ ^[0-9]+$ ]] && ((day>=1&&day<=28)) || { error "无效日期。"; return 1; }
    old=$(_e118_mktemp vnstat-old.conf); tmp=$(_e118_mktemp vnstat-new.conf)
    cp -a /etc/vnstat.conf "$old" || return 1
    awk -v d="$day" 'BEGIN{done=0} /^[[:space:]]*MonthRotate[[:space:]]+/ {print "MonthRotate " d;done=1;next} {print} END{if(!done) print "MonthRotate " d}' /etc/vnstat.conf > "$tmp" || return 1
    install -m 0644 "$tmp" /etc/vnstat.conf || return 1
    if ! systemctl restart vnstat.service >/dev/null 2>&1 && ! systemctl restart vnstat >/dev/null 2>&1; then install -m 0644 "$old" /etc/vnstat.conf; return 1; fi
    grep -Eq "^[[:space:]]*MonthRotate[[:space:]]+$day([[:space:]]|$)" /etc/vnstat.conf || { install -m 0644 "$old" /etc/vnstat.conf; return 1; }
    info "vnStat月结日已设为$day。"
}

do_traffic_monitor() {
    _e135_prepare || return 1
    local iface n list
    iface=$(_e135_default_iface); test -n "$iface" || { error "无法识别默认出口网卡。"; return 1; }
    _e135_vnstat_prepare "$iface" || { error "vnStat初始化失败。"; return 1; }
    while true; do
        clear; title "V199e137：宿主机流量与Xray连接中心"
        echo "  监控网卡: $iface"
        echo "  说明: vnStat统计整台VPS网卡总流量，不等于Xray独占流量。"
        echo "  1) 今日/本月汇总  2) 实时流量  3) 小时  4) 每日  5) 每月"
        echo "  6) Xray连接与入站端口  7) 数据库健康  8) 选择网卡  9) 设置月结日  0) 返回"
        read -rp "操作: " n || true
        case "$n" in
            1) vnstat -i "$iface"; _e135_pause ;;
            2) vnstat -l -i "$iface" || true; _e135_pause ;;
            3) vnstat -h -i "$iface"; _e135_pause ;;
            4) vnstat -d -i "$iface"; _e135_pause ;;
            5) vnstat -m -i "$iface"; _e135_pause ;;
            6) _e135_xray_connections; _e135_pause ;;
            7) echo "vnStat: $(vnstat --version 2>/dev/null | head -n1)"; systemctl status vnstat.service --no-pager -n 10 2>/dev/null || systemctl status vnstat --no-pager -n 10 2>/dev/null || true; vnstat --iflist 2>/dev/null || true; _e135_pause ;;
            8) list=$(find /sys/class/net -mindepth 1 -maxdepth 1 -printf '%f\n' | grep -v '^lo$'); printf '%s\n' "$list"; read -rp "输入网卡名: " iface || true; test -d "/sys/class/net/$iface" || { error "网卡不存在。"; iface=$(_e135_default_iface); _e135_pause; continue; }; printf '%s\n' "$iface" > "$E135_TRAFFIC_IFACE_FILE"; _e135_vnstat_prepare "$iface" || true ;;
            9) _e135_set_month_rotate; _e135_pause ;;
            0) return 0 ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

# Correct duplicate stripping with an exact key table instead of a fragile regex.
_e135_network_backup_and_strip() {
    local bdir="$1" f tmp keys
    mkdir -p "$bdir/files" || return 1
    : > "$bdir/manifest"
    keys=$(_e118_mktemp e135-sysctl-keys) || return 1
    _e135_network_keys > "$keys"
    while IFS= read -r f; do
        test -f "$f" || continue
        test "$f" = "$E135_NETWORK_CONF" && continue
        if awk 'NR==FNR{k[$1]=1;next} {s=$0;sub(/^[[:space:]]*/,"",s);split(s,a,/[[:space:]]*=[[:space:]]*/);if(a[1] in k){found=1}} END{exit !found}' "$keys" "$f"; then
            printf '%s\n' "$f" >> "$bdir/manifest"
            cp -a --parents "$f" "$bdir/files" || return 1
            tmp=$(_e118_mktemp sysctl-strip.conf) || return 1
            awk 'NR==FNR{k[$1]=1;next} {s=$0;sub(/^[[:space:]]*/,"",s);split(s,a,/[[:space:]]*=[[:space:]]*/);if(a[1] in k)next;print}' "$keys" "$f" > "$tmp" || return 1
            install -m 0644 "$tmp" "$f" || return 1
        fi
    done < <(_e135_sysctl_sources)
}

#------------------------------------------------------------------------------
# Module 5: complete XanMod source build with branch separation and rollback.
#------------------------------------------------------------------------------
_e135_xanmod_choose_tag() {
    local mode="${1:-}" json tag encoded expected sel i
    if test -z "$mode"; then
        echo "  1) 普通 XanMod（非RT最新Tag）"
        echo "  2) XanMod RT（实时内核最新Tag）"
        echo "  3) 手动输入精确Tag"
        read -rp "选择 (默认1): " mode || true
        case "${mode:-1}" in 1) mode=normal;;2) mode=rt;;3) mode=manual;;*) return 1;; esac
    fi
    if test "$mode" = manual; then
        read -rp "完整Tag: " tag || true
    else
        json=$(curl --proto '=https' --tlsv1.2 -fsSL --connect-timeout 10 --max-time 90 'https://gitlab.com/api/v4/projects/xanmod%2Flinux/repository/tags?per_page=100' 2>/dev/null) || return 1
        if test "$mode" = rt; then
            mapfile -t E135_TAGS < <(printf '%s' "$json" | jq -r '.[]?.name//empty' | grep -E '^[0-9]+\.[0-9]+\.[0-9]+-rt[^-]*-xanmod[0-9]+$' | grep -vE 'rc|beta' | sort -Vr | head -n 20)
        else
            mapfile -t E135_TAGS < <(printf '%s' "$json" | jq -r '.[]?.name//empty' | grep -E '^[0-9]+\.[0-9]+\.[0-9]+-xanmod[0-9]+$' | grep -vE 'rc|beta|rt' | sort -Vr | head -n 20)
        fi
        test "${#E135_TAGS[@]}" -gt 0 || return 1
        i=1; for tag in "${E135_TAGS[@]}"; do printf '  %d) %s\n' "$i" "$tag"; i=$((i+1)); done
        read -rp "选择Tag (默认1): " sel || true; sel=${sel:-1}
        [[ "$sel" =~ ^[0-9]+$ ]] && ((sel>=1&&sel<=${#E135_TAGS[@]})) || return 1
        tag=${E135_TAGS[$((sel-1))]}
    fi
    [[ "$tag" =~ ^[0-9]+\.[0-9]+\.[0-9]+(-rt[^-]*)?-xanmod[0-9]+$ ]] || { error "Tag格式非法：$tag"; return 1; }
    encoded=$(jq -rn --arg v "$tag" '$v|@uri')
    json=$(curl --proto '=https' --tlsv1.2 -fsSL --connect-timeout 10 --max-time 90 "https://gitlab.com/api/v4/projects/xanmod%2Flinux/repository/tags/$encoded") || return 1
    expected=$(printf '%s' "$json" | jq -r '.commit.id//empty')
    [[ "$expected" =~ ^[0-9a-f]{40}$ ]] || return 1
    LATEST_TAG="$tag"; E131_XANMOD_EXPECTED_COMMIT="$expected"
}

_e135_kernel_precheck() {
    local work_free boot_free mem_avail cfg
    [[ "$(uname -m)" = x86_64 ]] || { error "源码编译仅支持x86_64。"; return 1; }
    work_free=$(df -Pm /var/tmp 2>/dev/null | awk 'NR==2{print int($4)}' || echo 0)
    boot_free=$(df -Pm /boot 2>/dev/null | awk 'NR==2{print int($4)}' || echo 0)
    mem_avail=$(awk '/MemAvailable:/{print int($2/1024)}' /proc/meminfo 2>/dev/null || echo 0)
    cfg="/boot/config-$(uname -r)"
    echo "  /var/tmp=${work_free}MB /boot=${boot_free}MB MemAvailable=${mem_avail}MB"
    ((work_free>=20000)) || { error "要求/var/tmp至少20GB可用。"; return 1; }
    ((boot_free>=500)) || { error "要求/boot至少500MB可用。"; return 1; }
    ((mem_avail>=1024)) || { error "MemAvailable低于1GB，拒绝完整编译。"; return 1; }
    test -r "$cfg" || { error "缺少当前内核配置$cfg；为避免云VPS驱动缺失，拒绝使用裸defconfig。"; return 1; }
}

_e135_kernel_threads() {
    local mem cores t
    mem=$(awk '/MemAvailable:/{print int($2/1024)}' /proc/meminfo 2>/dev/null || echo 1024)
    cores=$(nproc 2>/dev/null || echo 1)
    t=$((mem/1800)); ((t<1))&&t=1; ((t>cores))&&t=$cores; ((t>8))&&t=8
    echo "$t"
}

_e135_kernel_config_guard() {
    local src="$1" virt fs dev missing=0
    virt=$(systemd-detect-virt 2>/dev/null || echo none)
    fs=$(findmnt -n -o FSTYPE / 2>/dev/null || echo ext4)
    dev=$(findmnt -n -o SOURCE / 2>/dev/null || true)
    test -x "$src/scripts/config" || return 1
    "$src/scripts/config" --enable CONFIG_BLK_DEV_INITRD --enable CONFIG_DEVTMPFS --enable CONFIG_DEVTMPFS_MOUNT || return 1
    case "$fs" in ext4) "$src/scripts/config" --enable CONFIG_EXT4_FS;; xfs) "$src/scripts/config" --enable CONFIG_XFS_FS;; btrfs) "$src/scripts/config" --enable CONFIG_BTRFS_FS;; esac
    case "$virt" in
        kvm|qemu)
            "$src/scripts/config" --enable CONFIG_VIRTIO --enable CONFIG_VIRTIO_PCI --enable CONFIG_VIRTIO_BLK --enable CONFIG_VIRTIO_NET --enable CONFIG_SCSI_VIRTIO || return 1 ;;
        xen*) "$src/scripts/config" --enable CONFIG_XEN --enable CONFIG_XEN_PV --enable CONFIG_XEN_BLKDEV_FRONTEND --enable CONFIG_XEN_NETDEV_FRONTEND || true ;;
        microsoft) "$src/scripts/config" --enable CONFIG_HYPERV --enable CONFIG_HYPERV_STORAGE --enable CONFIG_HYPERV_NET || true ;;
    esac
    [[ "$dev" == *nvme* ]] && "$src/scripts/config" --enable CONFIG_BLK_DEV_NVME --enable CONFIG_NVME_CORE || true
    "$src/scripts/config" --enable CONFIG_TCP_CONG_BBR --enable CONFIG_NET_SCH_FQ --set-str CONFIG_DEFAULT_TCP_CONG bbr || true
    "$src/scripts/config" --set-str CONFIG_LOCALVERSION '-xrv135' || true
    "$src/scripts/config" --set-str CONFIG_SYSTEM_TRUSTED_KEYS '' --set-str CONFIG_SYSTEM_REVOCATION_KEYS '' || true
}

_e135_kernel_config_verify() {
    local src="$1" virt fs dev sym failed=0
    virt=$(systemd-detect-virt 2>/dev/null || echo none)
    fs=$(findmnt -n -o FSTYPE / 2>/dev/null || echo ext4)
    dev=$(findmnt -n -o SOURCE / 2>/dev/null || true)
    _need_y() { grep -qx "$1=y" "$src/.config" || { error "内核配置缺少启动必需项：$1=y"; failed=1; }; }
    _need_y CONFIG_BLK_DEV_INITRD
    _need_y CONFIG_DEVTMPFS
    _need_y CONFIG_DEVTMPFS_MOUNT
    case "$fs" in ext4) _need_y CONFIG_EXT4_FS;; xfs) _need_y CONFIG_XFS_FS;; btrfs) _need_y CONFIG_BTRFS_FS;; esac
    case "$virt" in
        kvm|qemu) for sym in CONFIG_VIRTIO CONFIG_VIRTIO_PCI CONFIG_VIRTIO_BLK CONFIG_VIRTIO_NET CONFIG_SCSI_VIRTIO; do _need_y "$sym"; done ;;
        xen*) for sym in CONFIG_XEN CONFIG_XEN_BLKDEV_FRONTEND CONFIG_XEN_NETDEV_FRONTEND; do _need_y "$sym"; done ;;
        microsoft) for sym in CONFIG_HYPERV CONFIG_HYPERV_STORAGE CONFIG_HYPERV_NET; do _need_y "$sym"; done ;;
    esac
    if [[ "$dev" == *nvme* ]]; then _need_y CONFIG_BLK_DEV_NVME; _need_y CONFIG_NVME_CORE; fi
    grep -Eq '^CONFIG_TCP_CONG_BBR=(y|m)$' "$src/.config" || { error "缺少CONFIG_TCP_CONG_BBR。"; failed=1; }
    grep -Eq '^CONFIG_NET_SCH_FQ=(y|m)$' "$src/.config" || { error "缺少CONFIG_NET_SCH_FQ。"; failed=1; }
    return "$failed"
}

_e135_remove_kernel_packages() {
    local p; for p in "$@"; do test -n "$p" && dpkg -r "$p" >/dev/null 2>&1 || true; done
    update-grub >/dev/null 2>&1 || true
}

_e135_xanmod_source_build() {
    local mode="${1:-}" confirm work src log threads actual kver image header image_pkg header_pkg cleanup failed=0 dkms_before
    title "V199e137：XanMod完整源码编译与Debian包事务"
    warn "必须先创建VPS快照，并确保VNC/救援控制台可用。不会自动改变GRUB_DEFAULT或重启。"
    _e135_kernel_precheck || return 1
    _e135_xanmod_choose_tag "$mode" || { error "无法选择或验证Tag。"; return 1; }
    read -rp "输入 BUILD-XANMOD-$LATEST_TAG 确认: " confirm || true
    test "$confirm" = "BUILD-XANMOD-$LATEST_TAG" || return 0
    _e131_install_kernel_build_deps || return 1
    mkdir -p "$E131_KERNEL_BUILD_ROOT" || return 1
    work="$E131_KERNEL_BUILD_ROOT/${LATEST_TAG}-$(date +%Y%m%d_%H%M%S)"; src="$work/src"; log="$work/build.log"
    mkdir -p "$src" || return 1
    dkms_before="$work/dkms.before"; command -v dkms >/dev/null 2>&1 && dkms status > "$dkms_before" 2>/dev/null || : > "$dkms_before"
    git -C "$src" init -q && git -C "$src" remote add origin https://gitlab.com/xanmod/linux.git || return 1
    git -C "$src" fetch --depth=1 origin "refs/tags/$LATEST_TAG:refs/tags/$LATEST_TAG" 2>&1 | tee "$work/fetch.log" || return 1
    git -C "$src" checkout -q --detach "$LATEST_TAG" || return 1
    actual=$(git -C "$src" rev-parse HEAD); test "$actual" = "$E131_XANMOD_EXPECTED_COMMIT" || { error "Tag commit不一致。"; return 1; }
    cd "$src" || return 1; make mrproper >/dev/null || return 1
    cp -f "/boot/config-$(uname -r)" .config || return 1
    make olddefconfig >/dev/null || return 1
    _e135_kernel_config_guard "$src" || return 1
    make olddefconfig >/dev/null || return 1
    _e135_kernel_config_verify "$src" || { error "最终内核配置未通过云VPS启动驱动审计。"; return 1; }
    kver=$(make -s kernelrelease); test -n "$kver" || return 1
    cp -f .config "$work/config.final"
    threads=$(_e135_kernel_threads); info "Tag=$LATEST_TAG commit=$actual kernelrelease=$kver threads=$threads"
    make -j"$threads" bindeb-pkg 2>&1 | tee "$log" || { error "bindeb-pkg失败：$log"; return 1; }
    image=$(find "$work" -maxdepth 1 -type f -name "linux-image-*${kver}*.deb" ! -name '*dbg*' | sort | head -n1)
    header=$(find "$work" -maxdepth 1 -type f -name "linux-headers-*${kver}*.deb" | sort | head -n1)
    test -s "$image" && test -s "$header" || { error "缺少image或headers包。"; return 1; }
    dpkg-deb --info "$image" >/dev/null && dpkg-deb --info "$header" >/dev/null || return 1
    image_pkg=$(dpkg-deb -f "$image" Package); header_pkg=$(dpkg-deb -f "$header" Package)
    dpkg -i "$header" "$image" || failed=1
    if test "$failed" -eq 0 && command -v dkms >/dev/null 2>&1; then dkms autoinstall -k "$kver" || failed=1; fi
    test "$failed" -ne 0 || test -s "/boot/vmlinuz-$kver" || failed=1
    test "$failed" -ne 0 || test -d "/lib/modules/$kver" || failed=1
    if test "$failed" -eq 0 && ! test -s "/boot/initrd.img-$kver" && ! test -s "/boot/initramfs-${kver}.img"; then
        if command -v update-initramfs >/dev/null 2>&1; then update-initramfs -c -k "$kver" || failed=1
        elif command -v dracut >/dev/null 2>&1; then dracut --force "/boot/initramfs-${kver}.img" "$kver" || failed=1
        else failed=1; fi
    fi
    test "$failed" -ne 0 || _kernel_pre_reboot_verify_e52 "$kver" || failed=1
    if test "$failed" -ne 0; then
        error "新内核安装后校验失败，卸载本次新增包并保留构建记录。"
        _e135_remove_kernel_packages "$image_pkg" "$header_pkg"
        return 1
    fi
    {
        echo "tag=$LATEST_TAG"; echo "commit=$actual"; echo "kernelrelease=$kver"; echo "image=$image"; echo "headers=$header"; echo "threads=$threads"; echo "installed=$(date -Is)"
    } > "$work/manifest.txt"
    info "源码编译、打包、DKMS/initramfs/GRUB校验通过：$kver"
    warn "当前默认内核未被修改；请确认控制台后再自行选择重启。"
    read -rp "删除源码树，仅保留deb/日志/manifest？[y/N]: " cleanup || true
    [[ "$cleanup" =~ ^[yY]$ ]] && rm -rf -- "$src"
}

