#------------------------------------------------------------------------------
# Module 6: adaptive SSH/fail2ban guard with current-session anti-lockout.
#------------------------------------------------------------------------------
_e135_detect_ssh_ports() {
    local p current
    {
        if command -v sshd >/dev/null 2>&1; then sshd -T 2>/dev/null | awk '$1=="port"{print $2}'; fi
        _e121_detect_configured_ssh_ports 2>/dev/null || true
        _e121_detect_listening_ssh_ports 2>/dev/null || true
        current=$(_e135_current_ssh_port); test -n "$current" && echo "$current"
    } | awk '/^[0-9]+$/{if($1>=1&&$1<=65535&&!s[$1]++)print $1}' | sort -n
}

_e121_detect_ssh_ports() { _e135_detect_ssh_ports; }
_e116_detect_ssh_ports() { _e135_detect_ssh_ports; }

_e135_patch_fail2ban_ignoreip() {
    local ip="$1" tmp
    test -n "$ip" || return 0
    test -f "$E121_F2B_JAIL" || return 1
    tmp=$(_e118_mktemp f2b-ignore.conf) || return 1
    awk -v ip="$ip" '
      BEGIN{done=0}
      /^[[:space:]]*ignoreip[[:space:]]*=/ {print "ignoreip = 127.0.0.1/8 ::1 " ip;done=1;next}
      {print}
      END{if(!done) print "ignoreip = 127.0.0.1/8 ::1 " ip}
    ' "$E121_F2B_JAIL" > "$tmp" || return 1
    install -m 0644 "$tmp" "$E121_F2B_JAIL" || return 1
    fail2ban-client -t >/dev/null 2>&1 || return 1
    systemctl restart fail2ban >/dev/null 2>&1 || return 1
    fail2ban-client set "$E121_F2B_JAIL_NAME" unbanip "$ip" >/dev/null 2>&1 || true
    fail2ban-client get "$E121_F2B_JAIL_NAME" ignoreip 2>/dev/null | grep -Fq "$ip"
}

if declare -F _e121_install_ssh_guard >/dev/null 2>&1; then
    eval "$(declare -f _e121_install_ssh_guard | sed '1s/_e121_install_ssh_guard/_e135_ssh_guard_base/')"
fi

_e135_install_ssh_guard() {
    local ip ports current_port f2b_backup="" ip4="" ip6="" failed=0
    _e135_prepare || return 1
    title "V199e137：SSH端口自适应 + fail2ban防自锁"
    command -v sshd >/dev/null 2>&1 || { error "未检测到OpenSSH sshd。"; return 1; }
    sshd -t > "$E118_TMPDIR/sshd-e135.log" 2>&1 || { error "sshd_config语法错误，拒绝变更。"; sed 's/^/    /' "$E118_TMPDIR/sshd-e135.log"; return 1; }
    ports=$(_e135_detect_ssh_ports | xargs echo); test -n "$ports" || ports=22
    ip=$(_e135_current_ssh_ip); current_port=$(_e135_current_ssh_port)
    echo "  sshd -T/sshd_config.d/监听端口合并结果: $ports"
    echo "  当前SSH会话端口: ${current_port:-控制台/未知}"
    echo "  当前SSH客户端IP: ${ip:-控制台/未知}"
    test -z "$current_port" || grep -qw "$current_port" <<<"$ports" || { error "当前会话端口未进入放行集合，拒绝继续。"; return 1; }
    command -v iptables-save >/dev/null 2>&1 && { ip4=$(_e118_mktemp iptables-e135.rules); iptables-save > "$ip4" || ip4=""; }
    command -v ip6tables-save >/dev/null 2>&1 && { ip6=$(_e118_mktemp ip6tables-e135.rules); ip6tables-save > "$ip6" || ip6=""; }
    declare -F _e121_backup_fail2ban_state >/dev/null 2>&1 && f2b_backup=$(_e121_backup_fail2ban_state 2>/dev/null || true)
    _e135_ssh_guard_base || failed=1
    test "$failed" -ne 0 || _e135_patch_fail2ban_ignoreip "$ip" || failed=1
    if test "$failed" -eq 0; then
        _e121_verify_ssh_port_guard || failed=1
        _e121_verify_fail2ban_runtime || failed=1
    fi
    if test "$failed" -ne 0; then
        error "SSH防护应用失败，恢复Fail2ban和防火墙快照。"
        test -n "$f2b_backup" && _e121_restore_fail2ban_state "$f2b_backup" >/dev/null 2>&1 || true
        test -s "$ip4" && command -v iptables-restore >/dev/null 2>&1 && iptables-restore < "$ip4" || true
        test -s "$ip6" && command -v ip6tables-restore >/dev/null 2>&1 && ip6tables-restore < "$ip6" || true
        return 1
    fi
    info "SSH认证失败策略：24小时内第2次触发，封禁36小时。"
    test -z "$ip" || info "当前会话IP已加入ignoreip并执行unban：$ip"
    info "当前sshd有效端口已从sshd -T、配置文件、Include和监听socket交叉确认：$ports"
}

_e121_install_ssh_guard() { _e135_install_ssh_guard; }
_e116_install_ssh_guard() { _e135_install_ssh_guard; }

_e135_ssh_menu() {
    local n
    while true; do
        clear; title "V199e137：SSH/Fail2ban安全中心"
        echo "  1) 应用自适应防爆破并保护当前会话"
        echo "  2) 查看sshd最终端口和监听状态"
        echo "  3) 查看Fail2ban状态/封禁列表"
        echo "  4) 仅同步SSH端口放行"
        echo "  0) 返回"
        read -rp "操作: " n || true
        case "$n" in
            1) _e135_install_ssh_guard; _e135_pause ;;
            2) echo "sshd -T:"; sshd -T 2>/dev/null | awk '$1=="port"||$1=="listenaddress"'; echo "合并端口:"; _e135_detect_ssh_ports; ss -lntp | grep -E 'sshd|:22\b' || true; _e135_pause ;;
            3) fail2ban-client status "$E121_F2B_JAIL_NAME" 2>/dev/null || fail2ban-client status 2>/dev/null || true; _e135_pause ;;
            4) _e121_write_ssh_port_guard && _e121_apply_ssh_port_guard && _e121_verify_ssh_port_guard; _e135_pause ;;
            0) return ;;
        esac
    done
}

#------------------------------------------------------------------------------
# Module 1: node creation wrapper. Nice and runtime checks are in one rollback.
#------------------------------------------------------------------------------
_e135_install_mode() {
    local mode="$1" label="$2" protect="" rc=0
    _e135_prepare || return 1
    protect=$(_e116_backup_state "before_e135_install_mode_${mode}") || return 1
    _e118_save_core_payload "$protect" || { error "Core/DAT/systemd快照失败，拒绝建仓。"; return 1; }
    if ! _e116_install_mode "$mode" "$label"; then rc=1; fi
    if test "$rc" -eq 0; then fix_xray_systemd_limits || rc=1; fi
    if test "$rc" -eq 0; then _e118_xray_test_config "$CONFIG" 1 || rc=1; fi
    if test "$rc" -eq 0 && systemctl is-active --quiet xray.service; then _e127_verify_xray_runtime "$CONFIG" 12 || rc=1; _e131_verify_nice_runtime || rc=1; fi
    if test "$rc" -ne 0; then
        error "E135建仓总事务失败，恢复旧Core/DAT/systemd/config/用户状态。"
        _e118_restore_core_payload "$protect" >/dev/null 2>&1 || true
        _e118_restore_state "$protect" >/dev/null 2>&1 || true
        return 1
    fi
    info "E135建仓事务完成。"
    do_summary
}

do_install() {
    local n
    while true; do
        clear; title "V199e137：安装/重装节点总事务"
        echo "  1) VLESS Reality Vision"
        echo "  2) Reality Vision + SS2022"
        echo "  3) VLESSENC Vision自选"
        echo "  4) SS2022"
        echo "  0) 返回"
        read -rp "编号 (默认1): " n || true
        case "${n:-1}" in
            1) _e135_install_mode 1 "VLESS Reality Vision"; _e135_pause ;;
            2) _e135_install_mode 2 "Reality Vision + SS2022"; _e135_pause ;;
            3) _e135_install_mode 3 "VLESSENC Vision"; _e135_pause ;;
            4) _e135_install_mode 4 "SS2022"; _e135_pause ;;
            0) return ;;
            *) warn "无效编号。"; sleep 1 ;;
        esac
    done
}

#------------------------------------------------------------------------------
# Module 8: clean hot-update transaction; no historical wrapper chain.
#------------------------------------------------------------------------------
_e135_system_paths() {
    cat <<EOF_E135_PATHS
/usr/local/bin/xrv
$E135_SELF_PATH
$E135_LATEST_PATH
$E135_NETWORK_CONF
/etc/sysctl.conf
/etc/sysctl.d
$E135_LIMITS_FILE
$UPDATE_DAT_SCRIPT
/etc/systemd/system/xray-dat-update.service
/etc/systemd/system/xray-dat-update.timer
$E121_F2B_JAIL
$E121_F2B_DB_CONF
$E121_F2B_COMPAT_CONF
$E121_SSH_GUARD_SCRIPT
$E121_SSH_GUARD_SERVICE
$E121_SSH_GUARD_TIMER
$E121_LOG_RETENTION_SCRIPT
$E121_LOG_RETENTION_SERVICE
$E121_LOG_RETENTION_TIMER
$E121_JOURNAL_CONF
$E121_LOGROTATE_CONF
/etc/systemd/system/xray-hw-tweaks.service
/usr/local/bin/xray-hw-tweaks.sh
/etc/systemd/system/nic-optimize.service
/usr/local/bin/nic-optimize.sh
/etc/systemd/system/rps-optimize.service
/usr/local/bin/rps-optimize.sh
/etc/systemd/system/txqueue.service
/usr/local/bin/txqueue.sh
/etc/systemd/system/xray-accel-e125.service
/etc/systemd/system/xray-accel-e126.service
/usr/local/bin/xray-accel-e125.sh
/usr/local/bin/xray-accel-e126.sh
EOF_E135_PATHS
}

_e135_system_snapshot() {
    local b="$1" p rel
    mkdir -p "$b" || return 1
    : > "$b/present.list"; : > "$b/absent.list"; : > "$b/runtime-sysctl.env"
    while IFS= read -r p; do
        test -n "$p" || continue; rel=${p#/}
        if test -e "$p" || test -L "$p"; then echo "$rel" >> "$b/present.list"; else echo "$rel" >> "$b/absent.list"; fi
    done < <(_e135_system_paths)
    if test -s "$b/present.list"; then tar -C / -cpf "$b/files.tar" -T "$b/present.list" || return 1; fi
    while IFS= read -r p; do printf '%s|%s\n' "$p" "$(sysctl -n "$p" 2>/dev/null || true)" >> "$b/runtime-sysctl.env"; done < <(_e135_network_keys)
    command -v iptables-save >/dev/null 2>&1 && iptables-save > "$b/iptables.rules" 2>/dev/null || true
    command -v ip6tables-save >/dev/null 2>&1 && ip6tables-save > "$b/ip6tables.rules" 2>/dev/null || true
    for p in xray.service fail2ban.service xray-dat-update.timer vnstat.service xray-hw-tweaks.service nic-optimize.service rps-optimize.service txqueue.service xray-accel-e125.service xray-accel-e126.service; do
        printf '%s|%s|%s\n' "$p" "$(systemctl is-enabled "$p" 2>/dev/null || true)" "$(systemctl is-active "$p" 2>/dev/null || true)" >> "$b/services.env"
    done
}

_e135_system_restore() {
    local b="$1" rel key value svc enabled active
    test -d "$b" || return 1
    while IFS= read -r rel; do test -n "$rel" && rm -rf -- "/$rel" 2>/dev/null || true; done < <(cat "$b/present.list" "$b/absent.list" 2>/dev/null)
    test -s "$b/files.tar" && tar -C / -xpf "$b/files.tar" || true
    while IFS='|' read -r key value; do test -n "$value" && sysctl -w "$key=$value" >/dev/null 2>&1 || true; done < "$b/runtime-sysctl.env"
    test -s "$b/iptables.rules" && command -v iptables-restore >/dev/null 2>&1 && iptables-restore < "$b/iptables.rules" || true
    test -s "$b/ip6tables.rules" && command -v ip6tables-restore >/dev/null 2>&1 && ip6tables-restore < "$b/ip6tables.rules" || true
    systemctl daemon-reload >/dev/null 2>&1 || true
    while IFS='|' read -r svc enabled active; do
        if test "$enabled" = enabled; then systemctl enable "$svc" >/dev/null 2>&1 || true; else systemctl disable "$svc" >/dev/null 2>&1 || true; fi
        if test "$active" = active; then systemctl restart "$svc" >/dev/null 2>&1 || true; else systemctl stop "$svc" >/dev/null 2>&1 || true; fi
    done < "$b/services.env"
}

_e135_install_self() {
    test -f "$SCRIPT_PATH" || return 1
    mkdir -p "$SCRIPT_DIR" || return 1
    install -m 0755 "$SCRIPT_PATH" "$SYMLINK" || return 1
    install -m 0755 "$SCRIPT_PATH" "$E135_SELF_PATH" || return 1
    install -m 0755 "$SCRIPT_PATH" "$E135_LATEST_PATH" || return 1
    hash -r 2>/dev/null || true
}

hot_update_from_legacy() {
    local protect="" sysbackup rc=0 was_active=0
    _e135_prepare || return 1
    protect=$(_e116_backup_state before_hot_update_e135) || return 1
    _e118_save_core_payload "$protect" || { error "Core/DAT/systemd快照失败。"; return 1; }
    was_active=$(sed -n 's/^xray_was_active=//p' "$protect/meta.env" 2>/dev/null | head -n1); was_active=${was_active:-0}
    sysbackup="$E135_BACKUP_DIR/hot-update-$(date +%Y%m%d_%H%M%S)-$$"
    _e135_system_snapshot "$sysbackup" || return 1
    _e135_install_self || rc=1
    test "$rc" -ne 0 || install_update_dat || rc=1
    test "$rc" -ne 0 || systemctl enable --now xray-dat-update.timer >/dev/null 2>&1 || rc=1
    if test "$rc" -eq 0 && declare -F _e105_disable_xray_core_auto_update >/dev/null 2>&1; then _e105_disable_xray_core_auto_update || rc=1; fi
    test "$rc" -ne 0 || _e116_apply_init_window_default30 || rc=1
    test "$rc" -ne 0 || _e135_network_apply balanced force || rc=1
    test "$rc" -ne 0 || _e121_install_log_retention || rc=1
    test "$rc" -ne 0 || _e135_install_ssh_guard || rc=1
    test "$rc" -ne 0 || fix_xray_systemd_limits || rc=1
    test "$rc" -ne 0 || printf '%s\n' "$E135_VERSION" > "$SCRIPT_VERSION_FILE" || rc=1
    if test "$rc" -eq 0 && test "$was_active" = 1; then _e127_verify_xray_runtime "$CONFIG" 12 || rc=1; _e131_verify_nice_runtime || rc=1; fi
    test "$rc" -ne 0 || test "$(sysctl -n net.ipv4.tcp_notsent_lowat 2>/dev/null)" = 131072 || rc=1
    test "$rc" -ne 0 || systemctl is-enabled --quiet xray-dat-update.timer || rc=1
    if test "$rc" -ne 0; then
        error "E135热更新失败，恢复系统文件、防火墙、sysctl、Core和节点状态。"
        _e135_system_restore "$sysbackup" || true
        _e118_restore_core_payload "$protect" >/dev/null 2>&1 || true
        _e118_restore_state "$protect" >/dev/null 2>&1 || true
        return 1
    fi
    info "V199e137热更新完成：Nice=-20、init30、notsent=131072、SSH防自锁、3天日志、DAT 03:00。"
    info "热更新前系统快照：$sysbackup"
}


#------------------------------------------------------------------------------
# E135 final hardening: runtime dependencies, legacy-owner shutdown, clean
# advanced menu, robust Nice semantics, and a single hot-update path.
#------------------------------------------------------------------------------
E135_NEW_PACKAGES=()

_e135_pkg_present() {
    local pkg="$1"
    if command -v dpkg-query >/dev/null 2>&1; then dpkg-query -W -f='${Status}' "$pkg" 2>/dev/null | grep -q 'install ok installed'
    elif command -v rpm >/dev/null 2>&1; then rpm -q "$pkg" >/dev/null 2>&1
    else return 1; fi
}

_e135_install_package_verified() {
    local pkg="$1" cmd="$2" was=0
    command -v "$cmd" >/dev/null 2>&1 && return 0
    _e135_pkg_present "$pkg" && was=1 || true
    pkg_install "$pkg"
    command -v "$cmd" >/dev/null 2>&1 || { error "依赖安装失败：$pkg（缺少命令 $cmd）"; return 1; }
    test "$was" -eq 1 || E135_NEW_PACKAGES+=("$pkg")
}

_e135_require_runtime_tools() {
    _e135_install_package_verified qrencode qrencode || return 1
    _e135_install_package_verified vnstat vnstat || return 1
    systemctl enable --now vnstat.service >/dev/null 2>&1 || systemctl enable --now vnstat >/dev/null 2>&1 || { error "vnStat服务无法启动。"; return 1; }
    vnstat --version >/dev/null 2>&1 || return 1
    qrencode --version >/dev/null 2>&1 || return 1
}

_e135_remove_new_runtime_tools() {
    local pkg
    test "${#E135_NEW_PACKAGES[@]}" -gt 0 || return 0
    for pkg in "${E135_NEW_PACKAGES[@]}"; do
        if command -v apt-get >/dev/null 2>&1; then apt-get remove -y "$pkg" >/dev/null 2>&1 || true
        elif command -v dnf >/dev/null 2>&1; then dnf remove -y "$pkg" >/dev/null 2>&1 || true
        elif command -v yum >/dev/null 2>&1; then yum remove -y "$pkg" >/dev/null 2>&1 || true
        fi
    done
}

_e135_disable_legacy_optimizers() {
    local svc
    # Only disable broad legacy owners that silently overwrite several features.
    # Dedicated offload/RPS/MSS/TC services remain user-controlled in menu 10.
    for svc in \
        xray-hw-tweaks.service nic-optimize.service rps-optimize.service \
        txqueue.service xray-accel-e125.service xray-accel-e126.service
    do
        systemctl disable --now "$svc" >/dev/null 2>&1 || true
    done
    rm -f \
        /etc/systemd/system/xray-hw-tweaks.service /usr/local/bin/xray-hw-tweaks.sh \
        /etc/systemd/system/nic-optimize.service /usr/local/bin/nic-optimize.sh \
        /etc/systemd/system/rps-optimize.service /usr/local/bin/rps-optimize.sh \
        /etc/systemd/system/txqueue.service /usr/local/bin/txqueue.sh \
        /etc/systemd/system/xray-accel-e125.service /usr/local/bin/xray-accel-e125.sh \
        /etc/systemd/system/xray-accel-e126.service /usr/local/bin/xray-accel-e126.sh \
        2>/dev/null || true
    systemctl daemon-reload >/dev/null 2>&1 || true
}

_e135_show_optimization_status() {
    local iface pid
    iface=$(_e135_default_iface 2>/dev/null || true)
    pid=$(systemctl show xray.service -p MainPID --value 2>/dev/null || echo 0)
    title "V199e137：全部优化参数运行态"
    printf '  %-32s %s\n' "tcp_notsent_lowat" "$(sysctl -n net.ipv4.tcp_notsent_lowat 2>/dev/null || echo unsupported)"
    printf '  %-32s %s/%s\n' "qdisc/CC" "$(sysctl -n net.core.default_qdisc 2>/dev/null || echo unsupported)" "$(sysctl -n net.ipv4.tcp_congestion_control 2>/dev/null || echo unsupported)"
    printf '  %-32s %s\n' "tcp_mtu_probing" "$(sysctl -n net.ipv4.tcp_mtu_probing 2>/dev/null || echo unsupported)"
    printf '  %-32s %s\n' "initcwnd/initrwnd" "$(ip route show default 2>/dev/null | head -n1 | grep -oE 'initcwnd [0-9]+|initrwnd [0-9]+' | xargs echo || true)"
    printf '  %-32s %s\n' "Xray Nice(systemd/process)" "$(systemctl show xray.service -p Nice --value 2>/dev/null || echo n/a)/$(test "$pid" -gt 0 2>/dev/null && ps -o ni= -p "$pid" 2>/dev/null | xargs || echo n/a)"
    printf '  %-32s %s\n' "default interface" "${iface:-unknown}"
    if test -n "$iface" && command -v ethtool >/dev/null 2>&1; then
        echo "  Offload:"; ethtool -k "$iface" 2>/dev/null | grep -E '(^generic-receive-offload|^generic-segmentation-offload|^tcp-segmentation-offload|^large-receive-offload)' | sed 's/^/    /' || true
        echo "  Ring:"; ethtool -g "$iface" 2>/dev/null | sed -n '/Current hardware settings/,$p' | sed 's/^/    /' || true
    fi
    echo "  Legacy broad optimizer units:"
    for svc in xray-hw-tweaks.service nic-optimize.service rps-optimize.service txqueue.service xray-accel-e125.service xray-accel-e126.service; do
        printf '    %-34s enabled=%-9s active=%s\n' "$svc" "$(systemctl is-enabled "$svc" 2>/dev/null || echo no)" "$(systemctl is-active "$svc" 2>/dev/null || echo no)"
    done
}

