# Resolve /etc/sysctl.conf symlinks instead of replacing the symlink itself.
_e135_sysctl_sources() {
    local f
    {
        if test -e /etc/sysctl.conf || test -L /etc/sysctl.conf; then
            f=$(readlink -f /etc/sysctl.conf 2>/dev/null || true)
            test -n "$f" && printf '%s\n' "$f"
        fi
        find /etc/sysctl.d -maxdepth 1 -type f -name '*.conf' -print 2>/dev/null
    } | awk '!seen[$0]++'
}

# Nice=-20 is valid even before the Xray unit exists; runtime verification is
# mandatory whenever the service is active.
fix_xray_systemd_limits() {
    local old tmp was_active=0 load_state
    _e135_prepare || return 1
    mkdir -p "$(dirname "$E135_LIMITS_FILE")" || return 1
    old=$(_e118_mktemp e135-limits-old.conf) || return 1
    if test -f "$E135_LIMITS_FILE"; then cp -a "$E135_LIMITS_FILE" "$old"; else : > "$old"; fi
    tmp=$(_e118_mktemp e135-limits.conf) || return 1
    cat > "$tmp" <<'EOF_E135_LIMITS_FINAL'
[Service]
LimitNOFILE=1048576
LimitNPROC=262144
LimitSTACK=8M
TasksMax=infinity
Nice=-20
OOMScoreAdjust=-500
Environment="GOGC=300"
Restart=on-failure
RestartSec=5s
EOF_E135_LIMITS_FINAL
    install -m 0644 "$tmp" "$E135_LIMITS_FILE" || return 1
    systemctl daemon-reload >/dev/null 2>&1 || return 1
    load_state=$(systemctl show xray.service -p LoadState --value 2>/dev/null || echo not-found)
    if test "$load_state" = not-found || test -z "$load_state"; then
        grep -qx 'Nice=-20' "$E135_LIMITS_FILE" || return 1
        info "Nice=-20 drop-in已预置；Xray安装后首次启动会生效。"
        return 0
    fi
    systemctl is-active --quiet xray.service 2>/dev/null && was_active=1 || true
    if test "$was_active" -eq 1; then
        if ! systemctl restart xray.service >/dev/null 2>&1 || ! _e127_verify_xray_runtime "$CONFIG" 12 || ! _e131_verify_nice_runtime; then
            error "Nice=-20运行态验证失败，恢复旧drop-in。"
            if test -s "$old"; then install -m 0644 "$old" "$E135_LIMITS_FILE"; else rm -f "$E135_LIMITS_FILE"; fi
            systemctl daemon-reload >/dev/null 2>&1 || true
            systemctl restart xray.service >/dev/null 2>&1 || true
            return 1
        fi
    else
        test "$(systemctl show xray.service -p Nice --value 2>/dev/null || true)" = -20 || { error "inactive unit未读回Nice=-20。"; return 1; }
    fi
    info "Xray Nice=-20 已由 E135 单一drop-in管理。"
}

hot_update_from_legacy() {
    local protect="" sysbackup rc=0 was_active=0
    E135_NEW_PACKAGES=()
    _e135_prepare || return 1
    protect=$(_e116_backup_state before_hot_update_e135) || return 1
    _e118_save_core_payload "$protect" || { error "Core/DAT/systemd快照失败。"; return 1; }
    was_active=$(sed -n 's/^xray_was_active=//p' "$protect/meta.env" 2>/dev/null | head -n1); was_active=${was_active:-0}
    sysbackup="$E135_BACKUP_DIR/hot-update-$(date +%Y%m%d_%H%M%S)-$$"
    _e135_system_snapshot "$sysbackup" || return 1
    _e135_require_runtime_tools || rc=1
    test "$rc" -ne 0 || _e135_disable_legacy_optimizers || rc=1
    test "$rc" -ne 0 || _e135_install_self || rc=1
    test "$rc" -ne 0 || install_update_dat || rc=1
    test "$rc" -ne 0 || systemctl enable --now xray-dat-update.timer >/dev/null 2>&1 || rc=1
    if test "$rc" -eq 0 && declare -F _e105_disable_xray_core_auto_update >/dev/null 2>&1; then _e105_disable_xray_core_auto_update || rc=1; fi
    test "$rc" -ne 0 || _e116_apply_init_window_default30 || rc=1
    test "$rc" -ne 0 || _e135_network_apply balanced force || rc=1
    test "$rc" -ne 0 || _e121_install_log_retention || rc=1
    test "$rc" -ne 0 || _e135_install_ssh_guard || rc=1
    test "$rc" -ne 0 || fix_xray_systemd_limits || rc=1
    test "$rc" -ne 0 || printf '%s\n' "$E135_VERSION" > "$SCRIPT_VERSION_FILE" || rc=1
    if test "$rc" -eq 0 && test "$was_active" = 1; then _e127_verify_xray_runtime "$CONFIG" 12 || rc=1; _e131_verify_nice_runtime || rc=1; fi
    test "$rc" -ne 0 || test "$(sysctl -n net.ipv4.tcp_notsent_lowat 2>/dev/null)" = 131072 || rc=1
    test "$rc" -ne 0 || systemctl is-enabled --quiet xray-dat-update.timer || rc=1
    test "$rc" -ne 0 || command -v qrencode >/dev/null 2>&1 || rc=1
    test "$rc" -ne 0 || command -v vnstat >/dev/null 2>&1 || rc=1
    if test "$rc" -ne 0; then
        error "E135热更新失败，恢复系统文件、防火墙、sysctl、Core和节点状态。"
        _e135_system_restore "$sysbackup" || true
        _e118_restore_core_payload "$protect" >/dev/null 2>&1 || true
        _e118_restore_state "$protect" >/dev/null 2>&1 || true
        _e135_remove_new_runtime_tools || true
        return 1
    fi
    info "V199e137热更新完成：Nice=-20、init30、notsent=131072、QR、vnStat、SSH防自锁、3天日志、DAT 03:00。"
    info "热更新前系统快照：$sysbackup"
}

