_e135_self_test() {
    local rc=0 body tmp
    echo "V199e137 release gate:"
    test "$SCRIPT_VERSION" = 199e136 && echo "  [PASS] version" || { echo "  [FAIL] version"; rc=1; }
    body=$(declare -f do_summary); [[ "$body" == *'_e135_print_host_port'* && "$body" == *'_e135_emit_qr'* ]] && echo "  [PASS] export format/QR" || { echo "  [FAIL] export"; rc=1; }
    body="$(declare -f _e135_install_ssh_guard)$(declare -f _e135_patch_fail2ban_ignoreip)"; [[ "$body" == *'_e135_current_ssh_ip'* && "$body" == *'unbanip'* ]] && echo "  [PASS] SSH current-session protection" || { echo "  [FAIL] SSH anti-lockout"; rc=1; }
    body="$(declare -f _e135_xanmod_source_build)$(declare -f _e135_kernel_config_verify)"; [[ "$body" == *'bindeb-pkg'* && "$body" == *'dkms autoinstall'* && "$body" == *'_e135_remove_kernel_packages'* && "$body" == *'CONFIG_VIRTIO_NET'* ]] && echo "  [PASS] XanMod build transaction" || { echo "  [FAIL] XanMod"; rc=1; }
    body=$(declare -f hot_update_from_legacy); [[ "$body" == *'_e135_system_snapshot'* && "$body" == *'_e135_system_restore'* && "$body" == *'_e135_network_apply balanced force'* && "$body" == *'_e135_require_runtime_tools'* && "$body" == *'_e135_disable_legacy_optimizers'* ]] && echo "  [PASS] clean hot-update transaction" || { echo "  [FAIL] hot-update"; rc=1; }
    tmp=$(mktemp); _e135_network_candidate balanced "$tmp" || rc=1
    grep -qx 'net.ipv4.tcp_notsent_lowat = 131072' "$tmp" && echo "  [PASS] notsent default=131072" || { echo "  [FAIL] notsent default"; rc=1; }
    test "$(grep -cE '^[[:space:]]*net\.ipv4\.tcp_notsent_lowat[[:space:]]*=[[:space:]]*16384[[:space:]]*$' "$SCRIPT_PATH" 2>/dev/null || true)" = 0 && echo "  [PASS] no legacy literal 16384 owner" || { echo "  [FAIL] legacy 16384 definition"; rc=1; }
    rm -f "$tmp"
    body=$(declare -f do_user_manager); [[ "$body" == *'_e135_vless_users_menu'* && "$body" == *'_e135_ss_manager'* ]] && echo "  [PASS] unified user manager" || { echo "  [FAIL] users"; rc=1; }
    body=$(declare -f do_traffic_monitor); [[ "$body" == *'vnStat统计整台VPS'* && "$body" == *'_e135_xray_connections'* ]] && echo "  [PASS] traffic semantics" || { echo "  [FAIL] traffic"; rc=1; }
    body=$(declare -f do_sys_init_menu); [[ "$body" == *'无旧大包围入口'* && "$body" == *'_e135_network_menu'* ]] && echo "  [PASS] clean optimization menu" || { echo "  [FAIL] optimization menu"; rc=1; }
    body=$(declare -f fix_xray_systemd_limits); [[ "$body" == *'LoadState'* && "$body" == *'Nice=-20'* ]] && echo "  [PASS] Nice preinstall/runtime semantics" || { echo "  [FAIL] Nice semantics"; rc=1; }
    echo "V199e137 result: $(test "$rc" -eq 0 && echo PASS || echo FAIL)"
    return "$rc"
}

