readonly E136_VERSION="199e136"
readonly E136_DIR="$CONFIG_DIR/e136"
readonly E136_BACKUP_DIR="$E136_DIR/backups"
readonly E136_NETWORK_CONF="/etc/sysctl.d/99-xray-e136-network.conf"
readonly E136_NETWORK_STATE="$E136_DIR/network-state.env"
readonly E136_SELF_PATH="$SCRIPT_DIR/ex199e136.sh"
readonly E136_LATEST_PATH="$SCRIPT_DIR/ex199e_latest.sh"
readonly E136_WARP_STATE="$E136_DIR/warp-state.env"
readonly E136_WARP_PORT="40000"
readonly E136_WARP_TAG="warp-e136"
readonly E136_WARP_BLOCK_TAG="warp-block-udp-e136"
readonly E136_WARP_KEYRING="/usr/share/keyrings/cloudflare-warp-archive-keyring.gpg"
readonly E136_WARP_REPO="/etc/apt/sources.list.d/cloudflare-client.list"
readonly E136_WARP_HEALTH_SERVICE="/etc/systemd/system/xray-warp-e136-health.service"
readonly E136_WARP_HEALTH_TIMER="/etc/systemd/system/xray-warp-e136-health.timer"
readonly E136_WARP_LOG="/var/log/xray/warp-e136.log"

_e136_prepare() {
    _e118_runtime_init || return 1
    mkdir -p "$E136_DIR" "$E136_BACKUP_DIR" "$E135_EXPORT_DIR" "$LOG_DIR" || return 1
    chmod 0700 "$E136_DIR" "$E136_BACKUP_DIR" "$E135_EXPORT_DIR" 2>/dev/null || true
}

_e136_pause() { local _x=""; read -rp "按 Enter 继续..." _x || true; }

# Correct Linux cpumask formatting for systems with more than 32 CPUs.
cpu_mask_all() {
    local cores="${1:-$(nproc 2>/dev/null || echo 1)}"
    [[ "$cores" =~ ^[0-9]+$ ]] && ((cores >= 1)) || cores=1
    python3 - "$cores" <<'PY_E136_MASK'
import sys
n=max(1,int(sys.argv[1]))
chunks=[]
while n>0:
    bits=min(32,n)
    chunks.append(f"{(1<<bits)-1:08x}")
    n-=bits
while len(chunks)>1 and chunks[-1].startswith("0"):
    chunks[-1]=chunks[-1].lstrip("0") or "0"
print(",".join(reversed(chunks)))
PY_E136_MASK
}

#------------------------------------------------------------------------------
# IPv4-only network ownership. IPv6 is disabled persistently and at runtime.
#------------------------------------------------------------------------------
_e136_network_keys() {
    cat <<'EOF_E136_KEYS'
net.core.default_qdisc
net.ipv4.tcp_congestion_control
net.ipv4.tcp_mtu_probing
net.ipv4.tcp_slow_start_after_idle
net.ipv4.tcp_notsent_lowat
net.ipv4.tcp_limit_output_bytes
net.ipv4.tcp_fastopen
net.ipv4.tcp_ecn
net.core.somaxconn
net.core.netdev_max_backlog
net.core.rmem_max
net.core.wmem_max
net.ipv4.tcp_rmem
net.ipv4.tcp_wmem
net.ipv4.ip_local_port_range
net.ipv6.conf.all.disable_ipv6
net.ipv6.conf.default.disable_ipv6
net.ipv6.conf.lo.disable_ipv6
EOF_E136_KEYS
}

_e135_network_keys() { _e136_network_keys; }

_e136_network_candidate() {
    local profile="${1:-balanced}" out="$2" cc qdisc
    modprobe tcp_bbr >/dev/null 2>&1 || true
    modprobe sch_fq >/dev/null 2>&1 || true
    if sysctl -n net.ipv4.tcp_available_congestion_control 2>/dev/null | grep -qw bbr; then cc=bbr
    elif sysctl -n net.ipv4.tcp_available_congestion_control 2>/dev/null | grep -qw cubic; then cc=cubic
    else cc=$(sysctl -n net.ipv4.tcp_congestion_control 2>/dev/null || echo reno); fi
    qdisc=fq
    {
        echo "# Managed exclusively by ex199e136; profile=$profile; generated=$(date -Is 2>/dev/null || date)"
        echo "net.core.default_qdisc = $qdisc"
        echo "net.ipv4.tcp_congestion_control = $cc"
        echo "net.ipv4.tcp_mtu_probing = 1"
        echo "net.ipv4.tcp_slow_start_after_idle = 0"
        echo "net.ipv4.tcp_notsent_lowat = 131072"
        case "$profile" in
            low)
                echo "net.ipv4.tcp_limit_output_bytes = 524288"
                echo "net.core.somaxconn = 4096"
                echo "net.core.netdev_max_backlog = 2048"
                echo "net.core.rmem_max = 16777216"
                echo "net.core.wmem_max = 16777216"
                echo "net.ipv4.tcp_rmem = 4096 131072 16777216"
                echo "net.ipv4.tcp_wmem = 4096 16384 16777216"
                ;;
            throughput)
                echo "net.ipv4.tcp_limit_output_bytes = 4194304"
                echo "net.core.somaxconn = 16384"
                echo "net.core.netdev_max_backlog = 8192"
                echo "net.core.rmem_max = 97108868"
                echo "net.core.wmem_max = 97108868"
                echo "net.ipv4.tcp_rmem = 4096 7990577 97108868"
                echo "net.ipv4.tcp_wmem = 4096 7990577 97108868"
                ;;
            *)
                echo "net.ipv4.tcp_limit_output_bytes = 1048576"
                echo "net.core.somaxconn = 8192"
                echo "net.core.netdev_max_backlog = 4096"
                echo "net.core.rmem_max = 56699928"
                echo "net.core.wmem_max = 56699928"
                echo "net.ipv4.tcp_rmem = 4096 131072 56699928"
                echo "net.ipv4.tcp_wmem = 4096 16384 56699928"
                ;;
        esac
        echo "net.ipv4.tcp_fastopen = 1"
        echo "net.ipv4.tcp_ecn = 2"
        echo "net.ipv4.ip_local_port_range = 10240 65535"
        echo "net.ipv6.conf.all.disable_ipv6 = 1"
        echo "net.ipv6.conf.default.disable_ipv6 = 1"
        echo "net.ipv6.conf.lo.disable_ipv6 = 1"
    } > "$out"
}

_e135_network_candidate() { _e136_network_candidate "$@"; }

_e136_strip_sysctl_file() {
    local keys="$1" src="$2" out="$3"
    awk '
      NR==FNR {managed[$1]=1; next}
      {
        raw=$0; s=$0
        sub(/^[[:space:]]*/, "", s)
        if (s ~ /^#/ || s == "") {print raw; next}
        p=index(s, "=")
        if (p>0) {
          key=substr(s,1,p-1)
          gsub(/[[:space:]]/, "", key)
          if (key in managed) next
        }
        print raw
      }
    ' "$keys" "$src" > "$out"
}

_e136_network_backup_and_strip() {
    local bdir="$1" f tmp keys
    mkdir -p "$bdir/files" || return 1
    : > "$bdir/manifest"
    keys=$(_e118_mktemp e136-sysctl-keys) || return 1
    _e136_network_keys > "$keys"
    while IFS= read -r f; do
        test -f "$f" || continue
        test "$f" = "$E136_NETWORK_CONF" && continue
        tmp=$(_e118_mktemp e136-sysctl-strip) || return 1
        _e136_strip_sysctl_file "$keys" "$f" "$tmp" || return 1
        if ! cmp -s "$f" "$tmp"; then
            printf '%s\n' "$f" >> "$bdir/manifest"
            cp -a --parents "$f" "$bdir/files" || return 1
            install -m 0644 "$tmp" "$f" || return 1
        fi
    done < <(_e135_sysctl_sources)
}

_e135_network_backup_and_strip() { _e136_network_backup_and_strip "$@"; }

_e136_network_apply() {
    local profile="${1:-balanced}" confirm="${2:-}" candidate backup key value old failed=0
    _e136_prepare || return 1
    candidate=$(_e118_mktemp e136-network.conf) || return 1
    _e136_network_candidate "$profile" "$candidate" || return 1
    _e135_network_validate "$candidate" || return 1
    if test "$confirm" != force; then
        warn "将清理受管参数的全部旧定义，固定 tcp_notsent_lowat=131072，并默认关闭IPv6。"
        read -rp "输入 APPLY-NETWORK 确认: " confirm || true
        test "$confirm" = APPLY-NETWORK || { info "已取消。"; return 0; }
    fi
    backup="$E136_BACKUP_DIR/network-$(date +%Y%m%d_%H%M%S)-$$"
    mkdir -p "$backup" || return 1
    : > "$backup/runtime.env"
    while IFS= read -r key; do
        old=$(sysctl -n "$key" 2>/dev/null || true)
        printf '%s|%s\n' "$key" "$old" >> "$backup/runtime.env"
    done < <(_e136_network_keys)
    _e135_snapshot_file "$E136_NETWORK_CONF" "$backup/e136-conf" || return 1
    _e136_network_backup_and_strip "$backup" || {
        error "旧sysctl定义迁移失败。"
        _e135_network_restore_files "$backup" || true
        return 1
    }
    # Disable legacy owners without deleting their files in a standalone apply.
    systemctl disable --now xray-accel-e125.service xray-accel-e126.service \
        xray-hw-tweaks.service nic-optimize.service rps-optimize.service txqueue.service \
        >/dev/null 2>&1 || true
    install -m 0644 "$candidate" "$E136_NETWORK_CONF" || failed=1
    if test "$failed" -eq 0; then
        while IFS='=' read -r key value; do
            key=$(printf '%s' "$key" | xargs); value=$(printf '%s' "$value" | xargs)
            case "$key" in ''|'#'*) continue ;; esac
            test -w "/proc/sys/${key//./\/}" || continue
            sysctl -w "$key=$value" >/dev/null 2>&1 || { failed=1; break; }
        done < "$candidate"
    fi
    if test "$failed" -eq 0; then
        while IFS='=' read -r key value; do
            key=$(printf '%s' "$key" | xargs); value=$(printf '%s' "$value" | xargs)
            case "$key" in ''|'#'*) continue ;; esac
            test -e "/proc/sys/${key//./\/}" || continue
            test "$(sysctl -n "$key" 2>/dev/null | xargs)" = "$value" || {
                error "运行态读回失败：$key"
                failed=1; break
            }
        done < "$candidate"
    fi
    if test "$failed" -ne 0; then
        error "E136网络参数应用失败，恢复旧文件与运行值。"
        _e135_restore_file "$E136_NETWORK_CONF" "$backup/e136-conf" || true
        _e135_network_restore_files "$backup" || true
        while IFS='|' read -r key old; do
            test -n "$old" && sysctl -w "$key=$old" >/dev/null 2>&1 || true
        done < "$backup/runtime.env"
        return 1
    fi
    rm -f "$E135_NETWORK_CONF" 2>/dev/null || true
    {
        echo "profile=$profile"
        echo "applied=$(date -Is 2>/dev/null || date)"
        echo "tcp_notsent_lowat=131072"
        echo "ipv6_disabled=1"
        echo "backup=$backup"
    } > "$E136_NETWORK_STATE"
    chmod 0600 "$E136_NETWORK_STATE" 2>/dev/null || true
    info "E136网络参数已应用：tcp_notsent_lowat=131072，IPv6默认关闭。"
}

_e135_network_apply() { _e136_network_apply "$@"; }
_e82_set_tcp_notsent_lowat() { _e136_network_apply balanced force; }
_e88_set_tcp_notsent_lowat() { _e136_network_apply balanced force; }
apply_default_full_sysctl_profile_e60() { _e136_network_apply balanced force; }
_e126_apply_profile() { _e136_network_apply "${1:-balanced}"; }

_e136_ipv6_status() {
    title "V199e137：IPv4-only / IPv6状态"
    printf '  %-42s %s\n' "net.ipv6.conf.all.disable_ipv6" "$(sysctl -n net.ipv6.conf.all.disable_ipv6 2>/dev/null || echo unsupported)"
    printf '  %-42s %s\n' "net.ipv6.conf.default.disable_ipv6" "$(sysctl -n net.ipv6.conf.default.disable_ipv6 2>/dev/null || echo unsupported)"
    printf '  %-42s %s\n' "net.ipv6.conf.lo.disable_ipv6" "$(sysctl -n net.ipv6.conf.lo.disable_ipv6 2>/dev/null || echo unsupported)"
    echo "  IPv6地址："
    ip -6 addr show 2>/dev/null | sed 's/^/    /' || true
    echo "  IPv6默认路由："
    ip -6 route show default 2>/dev/null | sed 's/^/    /' || true
}

_e136_network_audit() {
    title "V199e137：网络参数单一所有权审计"
    local key hits=0 c
    while IFS= read -r key; do
        echo "[$key]"
        grep -RnsE "^[[:space:]]*${key//./\\.}[[:space:]]*=" /etc/sysctl.conf /etc/sysctl.d 2>/dev/null | sed 's/^/  /' || echo "  未定义"
        c=$(grep -RhsE "^[[:space:]]*${key//./\\.}[[:space:]]*=" /etc/sysctl.conf /etc/sysctl.d 2>/dev/null | wc -l)
        (( c > 1 )) && hits=$((hits+1))
    done < <(_e136_network_keys)
    echo
    echo "运行态 tcp_notsent_lowat=$(sysctl -n net.ipv4.tcp_notsent_lowat 2>/dev/null || echo unsupported)"
    echo "运行态 IPv6(all/default/lo)=$(sysctl -n net.ipv6.conf.all.disable_ipv6 2>/dev/null || echo unsupported)/$(sysctl -n net.ipv6.conf.default.disable_ipv6 2>/dev/null || echo unsupported)/$(sysctl -n net.ipv6.conf.lo.disable_ipv6 2>/dev/null || echo unsupported)"
    echo "唯一目标文件：$E136_NETWORK_CONF"
    echo "存在重复定义的受管参数数：$hits"
}

_e135_network_audit() { _e136_network_audit; }

_e136_network_menu() {
    local n profile
    while true; do
        clear; title "V199e137：统一网络优化参数中心（IPv4-only）"
        profile=$(sed -n 's/^profile=//p' "$E136_NETWORK_STATE" 2>/dev/null | head -n1); profile=${profile:-balanced}
        echo "  当前档位: $profile"
        echo "  tcp_notsent_lowat: $(sysctl -n net.ipv4.tcp_notsent_lowat 2>/dev/null || echo unsupported)"
        echo "  IPv6关闭状态: $(sysctl -n net.ipv6.conf.all.disable_ipv6 2>/dev/null || echo unsupported)"
        echo "  唯一持久化文件: $E136_NETWORK_CONF"
        echo "  1) 稳态推荐档（notsent=131072，IPv6关闭）"
        echo "  2) 低排队延迟档（notsent仍为131072）"
        echo "  3) 高吞吐档（notsent仍为131072）"
        echo "  4) 审计全部重复定义"
        echo "  5) 重放当前档并重新清理历史定义"
        echo "  6) IPv4-only/IPv6状态"
        echo "  7) 显示全部受管参数运行值"
        echo "  0) 返回"
        read -rp "操作: " n || true
        case "$n" in
            1) _e136_network_apply balanced; _e136_pause ;;
            2) _e136_network_apply low; _e136_pause ;;
            3) _e136_network_apply throughput; _e136_pause ;;
            4) _e136_network_audit; _e136_pause ;;
            5) _e136_network_apply "$profile" force; _e136_pause ;;
            6) _e136_ipv6_status; _e136_pause ;;
            7) while IFS= read -r key; do printf '  %-44s %s\n' "$key" "$(sysctl -n "$key" 2>/dev/null || echo unsupported)"; done < <(_e136_network_keys); _e136_pause ;;
            0) return 0 ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

_e135_network_menu() { _e136_network_menu; }
do_network_params_menu_e56() { _e136_network_menu; }
_e126_accel_menu() { _e136_network_menu; }

#------------------------------------------------------------------------------
# Preserve every existing Fail2ban ignoreip token and add current SSH client.
#------------------------------------------------------------------------------
_e136_merge_ignoreip_values() {
    local existing="${1:-}" ip="${2:-}" token out="" seen=" "
    for token in 127.0.0.1/8 ::1 $existing $ip; do
        test -n "$token" || continue
        [[ "$seen" == *" $token "* ]] && continue
        seen+="$token "
        out+="${out:+ }$token"
    done
    printf '%s' "$out"
}

_e135_patch_fail2ban_ignoreip() {
    local ip="$1" tmp existing merged
    test -f "$E121_F2B_JAIL" || return 1
    existing=$(awk -F= '/^[[:space:]]*ignoreip[[:space:]]*=/{v=$2;sub(/^[[:space:]]*/,"",v);print v}' "$E121_F2B_JAIL" | xargs echo)
    merged=$(_e136_merge_ignoreip_values "$existing" "$ip")
    tmp=$(_e118_mktemp f2b-ignore-e136.conf) || return 1
    awk -v merged="$merged" '
      BEGIN{done=0}
      /^[[:space:]]*ignoreip[[:space:]]*=/ {if(!done){print "ignoreip = " merged;done=1};next}
      {print}
      END{if(!done) print "ignoreip = " merged}
    ' "$E121_F2B_JAIL" > "$tmp" || return 1
    install -m 0644 "$tmp" "$E121_F2B_JAIL" || return 1
    fail2ban-client -t >/dev/null 2>&1 || return 1
    systemctl restart fail2ban >/dev/null 2>&1 || return 1
    if test -n "$ip"; then
        fail2ban-client set "$E121_F2B_JAIL_NAME" unbanip "$ip" >/dev/null 2>&1 || true
        fail2ban-client get "$E121_F2B_JAIL_NAME" ignoreip 2>/dev/null | grep -Fq "$ip" || return 1
    fi
}

#------------------------------------------------------------------------------
# Cloudflare WARP local proxy. Never enables system-wide WARP routing.
#------------------------------------------------------------------------------
_e136_warp_cli() {
    warp-cli --accept-tos "$@" 2>/dev/null || warp-cli "$@" 2>/dev/null
}

_e136_warp_service_name() {
    systemctl list-unit-files warp-svc.service >/dev/null 2>&1 && echo warp-svc.service || echo warp-svc
}

_e136_warp_route4() { ip -4 route show default 2>/dev/null | LC_ALL=C sort; }

_e136_warp_listener_ok() {
    local p="${1:-$E136_WARP_PORT}" local_addr
    local_addr=$(ss -H -lnt4 2>/dev/null | awk -v p="$p" '$4 ~ (":" p "$"){print $4}')
    grep -Eq "^127\\.0\\.0\\.1:${p}$" <<<"$local_addr" || return 1
    ! grep -Eq "^(0\\.0\\.0\\.0|[0-9]+\\.[0-9]+\\.[0-9]+\\.[0-9]+):${p}$" <<<"$local_addr" || {
        test "$local_addr" = "127.0.0.1:$p" || return 1
    }
}

_e136_warp_trace() {
    curl -4 -fsS --connect-timeout 5 --max-time 12 \
        --proxy "socks5h://127.0.0.1:$E136_WARP_PORT" \
        https://www.cloudflare.com/cdn-cgi/trace 2>/dev/null
}

_e136_warp_proxy_ready() {
    local trace
    command -v warp-cli >/dev/null 2>&1 || return 1
    _e136_warp_listener_ok || return 1
    trace=$(_e136_warp_trace) || return 1
    grep -qx 'warp=on' <<<"$trace"
}

_e136_warp_register() {
    _e136_warp_cli registration show >/dev/null 2>&1 && return 0
    _e136_warp_cli registration new >/dev/null 2>&1 || true
    _e136_warp_cli registration show >/dev/null 2>&1 || {
        # Older clients may not implement registration show; status must at least not report missing registration.
        ! _e136_warp_cli status 2>&1 | grep -qiE 'missing registration|not registered|registration.*missing'
    }
}

_e136_warp_set_masque() {
    _e136_warp_cli tunnel protocol set MASQUE >/dev/null 2>&1 || \
    _e136_warp_cli tunnel protocol set masque >/dev/null 2>&1 || return 1
}

_e136_warp_set_proxy_port() {
    _e136_warp_cli proxy port "$E136_WARP_PORT" >/dev/null 2>&1 || \
    _e136_warp_cli proxy port set "$E136_WARP_PORT" >/dev/null 2>&1 || \
    _e136_warp_cli proxy set-port "$E136_WARP_PORT" >/dev/null 2>&1 || return 1
}

_e136_warp_set_proxy_mode() {
    _e136_warp_cli mode proxy >/dev/null 2>&1 || \
    _e136_warp_cli mode set proxy >/dev/null 2>&1 || return 1
}

_e136_warp_connect_local_proxy() {
    local before after svc
    before=$(_e136_warp_route4)
    svc=$(_e136_warp_service_name)
    systemctl enable --now "$svc" >/dev/null 2>&1 || return 1
    _e136_warp_register || { error "WARP设备注册失败。"; return 1; }
    _e136_warp_set_masque || { error "无法把WARP隧道协议设为MASQUE。"; return 1; }
    _e136_warp_set_proxy_port || { error "当前warp-cli不支持设置本地代理端口。"; return 1; }
    _e136_warp_set_proxy_mode || {
        error "当前客户端/账户未允许Local proxy模式。可在Cloudflare Zero Trust设备配置中启用Local proxy后重试。"
        return 1
    }
    _e136_warp_cli connect >/dev/null 2>&1 || return 1
    sleep 4
    after=$(_e136_warp_route4)
    if test "$before" != "$after"; then
        error "WARP改变了IPv4默认路由；为防SSH失联，立即断开。"
        _e136_warp_cli disconnect >/dev/null 2>&1 || true
        return 1
    fi
    _e136_warp_proxy_ready || { error "WARP本地代理未在127.0.0.1:$E136_WARP_PORT正常提供warp=on出口。"; return 1; }
}

_e136_os_codename() {
    local code=""
    if test -r /etc/os-release; then . /etc/os-release; code=${VERSION_CODENAME:-${UBUNTU_CODENAME:-}}; fi
    test -n "$code" || code=$(lsb_release -cs 2>/dev/null || true)
    printf '%s' "$code"
}

_e136_warp_install_package() {
    local tx="$1" preinstalled=0 code keytmp listtmp svc
    command -v apt-get >/dev/null 2>&1 || { error "官方WARP自动安装当前仅支持Debian/Ubuntu APT系统。"; return 1; }
    [[ "$(uname -m)" =~ ^(x86_64|aarch64)$ ]] || { error "当前架构不在本脚本WARP安装白名单。"; return 1; }
    dpkg-query -W -f='${Status}' cloudflare-warp 2>/dev/null | grep -q 'install ok installed' && preinstalled=1 || true
    printf 'preinstalled=%s\n' "$preinstalled" > "$tx/package.env"
    _e135_snapshot_file "$E136_WARP_KEYRING" "$tx/keyring" || return 1
    _e135_snapshot_file "$E136_WARP_REPO" "$tx/repo" || return 1
    export DEBIAN_FRONTEND=noninteractive
    apt-get update -o Acquire::Retries=3 >/dev/null || return 1
    apt-get install -y --no-install-recommends ca-certificates curl gnupg lsb-release >/dev/null || return 1
    code=$(_e136_os_codename); test -n "$code" || { error "无法识别发行版codename。"; return 1; }
    keytmp=$(_e118_mktemp cloudflare-warp-pubkey.gpg) || return 1
    listtmp=$(_e118_mktemp cloudflare-client.list) || return 1
    curl --proto '=https' --tlsv1.2 -fsSL --connect-timeout 10 --max-time 120 \
        https://pkg.cloudflareclient.com/pubkey.gpg -o "$keytmp" || return 1
    gpg --batch --show-keys "$keytmp" >/dev/null 2>&1 || { error "Cloudflare WARP公钥格式无效。"; return 1; }
    mkdir -p "$(dirname "$E136_WARP_KEYRING")" "$(dirname "$E136_WARP_REPO")" || return 1
    gpg --batch --yes --dearmor -o "${keytmp}.dearmored" "$keytmp" || return 1
    install -m 0644 "${keytmp}.dearmored" "$E136_WARP_KEYRING" || return 1
    printf 'deb [signed-by=%s] https://pkg.cloudflareclient.com/ %s main\n' "$E136_WARP_KEYRING" "$code" > "$listtmp"
    install -m 0644 "$listtmp" "$E136_WARP_REPO" || return 1
    apt-get update -o Acquire::Retries=3 || return 1
    apt-get install -y cloudflare-warp || return 1
    command -v warp-cli >/dev/null 2>&1 || return 1
    svc=$(_e136_warp_service_name)
    systemctl enable --now "$svc" >/dev/null 2>&1 || return 1
}

_e136_warp_install_rollback() {
    local tx="$1" preinstalled
    preinstalled=$(sed -n 's/^preinstalled=//p' "$tx/package.env" 2>/dev/null | head -n1); preinstalled=${preinstalled:-1}
    _e136_warp_cli disconnect >/dev/null 2>&1 || true
    if test "$preinstalled" = 0; then
        apt-get remove -y cloudflare-warp >/dev/null 2>&1 || true
    fi
    _e135_restore_file "$E136_WARP_KEYRING" "$tx/keyring" || true
    _e135_restore_file "$E136_WARP_REPO" "$tx/repo" || true
    apt-get update >/dev/null 2>&1 || true
}

