_e136_warp_domains_json() {
    _e136_warp_domains_lines "${1:-google-meta-core}" | awk 'NF&&!seen[$0]++' | jq -Rsc 'split("\n")|map(select(length>0))'
}

_e136_warp_config_build() {
    local profile="$1" enable="$2" out="$3" src="${4:-$CONFIG}" domains
    test -s "$src" || { error "Xray配置不存在：$src"; return 1; }
    domains=$(_e136_warp_domains_json "$profile") || return 1
    jq --arg warp "$E136_WARP_TAG" --arg block "$E136_WARP_BLOCK_TAG" \
       --argjson port "$E136_WARP_PORT" --argjson domains "$domains" --argjson enable "$enable" '
      .outbounds = (.outbounds // []) |
      .routing = (.routing // {}) |
      .routing.rules = (.routing.rules // []) |
      .outbounds |= map(select((.tag // "") != $warp and (.tag // "") != $block)) |
      .routing.rules |= map(select((.outboundTag // "") != $warp and (.outboundTag // "") != $block)) |
      .outbounds |= map(if .protocol == "freedom" then .settings = ((.settings // {}) + {domainStrategy:"UseIPv4"}) else . end) |
      if (.dns|type) == "object" then .dns.queryStrategy = "UseIPv4" else . end |
      if $enable then
        .outbounds += [
          {tag:$warp,protocol:"socks",settings:{servers:[{address:"127.0.0.1",port:$port}]}},
          {tag:$block,protocol:"blackhole",settings:{response:{type:"none"}}}
        ] |
        .routing.rules = [
          {type:"field",network:"udp",domain:$domains,outboundTag:$block},
          {type:"field",network:"tcp",domain:$domains,outboundTag:$warp}
        ] + .routing.rules
      else . end
    ' "$src" > "$out"
}

_e136_xray_apply_warp_route() {
    local profile="${1:-google-meta-core}" enable="${2:-true}" cand old was_active=0 failed=0
    _e136_prepare || return 1
    test -x "$XRAY_BIN" && test -s "$CONFIG" || { error "Xray尚未安装或配置不存在。"; return 1; }
    if test "$enable" = true; then _e136_warp_proxy_ready || { error "WARP本地代理未就绪。"; return 1; }; fi
    cand=$(_e118_mktemp xray-warp-e136.json) || return 1
    old=$(_e118_mktemp xray-warp-e136-old.json) || return 1
    cp -a "$CONFIG" "$old" || return 1
    _e136_warp_config_build "$profile" "$enable" "$cand" "$CONFIG" || return 1
    _e118_xray_test_config "$cand" 1 || { error "WARP候选配置未通过Xray测试。"; return 1; }
    systemctl is-active --quiet xray.service 2>/dev/null && was_active=1 || true
    install -m 0600 "$cand" "$CONFIG" || return 1
    fix_permissions
    if test "$was_active" -eq 1; then
        systemctl restart xray.service >/dev/null 2>&1 || failed=1
        test "$failed" -ne 0 || _e127_verify_xray_runtime "$CONFIG" 12 || failed=1
    fi
    if test "$failed" -ne 0; then
        error "WARP分流配置运行验证失败，恢复旧Xray配置。"
        install -m 0600 "$old" "$CONFIG" || true
        fix_permissions
        test "$was_active" -eq 0 || systemctl restart xray.service >/dev/null 2>&1 || true
        return 1
    fi
    if test "$enable" = true; then
        {
            echo "route_enabled=1"
            echo "profile=$profile"
            echo "port=$E136_WARP_PORT"
            echo "updated=$(date -Is 2>/dev/null || date)"
        } > "$E136_WARP_STATE"
    else
        {
            echo "route_enabled=0"
            echo "profile=disabled"
            echo "port=$E136_WARP_PORT"
            echo "updated=$(date -Is 2>/dev/null || date)"
        } > "$E136_WARP_STATE"
    fi
    chmod 0600 "$E136_WARP_STATE" 2>/dev/null || true
}

_e136_warp_health_install() {
    _e136_install_self || return 1
    cat > "$E136_WARP_HEALTH_SERVICE" <<EOF_E136_WARP_SERVICE
[Unit]
Description=Xray WARP Local Proxy Health Check E136
After=network-online.target warp-svc.service
Wants=network-online.target

[Service]
Type=oneshot
ExecStart=$SYMLINK --warp-health-check
EOF_E136_WARP_SERVICE
    cat > "$E136_WARP_HEALTH_TIMER" <<'EOF_E136_WARP_TIMER'
[Unit]
Description=Periodic Xray WARP Local Proxy Health Check E136

[Timer]
OnBootSec=2min
OnUnitActiveSec=5min
RandomizedDelaySec=30s
Persistent=true

[Install]
WantedBy=timers.target
EOF_E136_WARP_TIMER
    systemctl daemon-reload >/dev/null 2>&1 || return 1
    systemctl enable --now xray-warp-e136-health.timer >/dev/null 2>&1 || return 1
}

_e136_warp_health_check() {
    mkdir -p "$(dirname "$E136_WARP_LOG")" 2>/dev/null || true
    if _e136_warp_proxy_ready; then
        echo "[$(date -Is)] OK local proxy 127.0.0.1:$E136_WARP_PORT" >> "$E136_WARP_LOG"
        return 0
    fi
    echo "[$(date -Is)] WARN proxy unhealthy; restart warp-svc" >> "$E136_WARP_LOG"
    systemctl restart "$(_e136_warp_service_name)" >/dev/null 2>&1 || true
    sleep 2
    _e136_warp_cli connect >/dev/null 2>&1 || true
    sleep 4
    if _e136_warp_proxy_ready; then
        echo "[$(date -Is)] RECOVERED" >> "$E136_WARP_LOG"
        return 0
    fi
    echo "[$(date -Is)] FAIL" >> "$E136_WARP_LOG"
    return 1
}

_e136_warp_enable_profile() {
    local profile="${1:-google-meta-core}" confirm tx route_before
    title "V199e137：启用WARP本地代理与Xray定向分流"
    warn "不会启用全局WARP；SSH、Xray入站和系统默认流量继续走原IPv4。"
    warn "Cloudflare Local proxy使用MASQUE并监听127.0.0.1:$E136_WARP_PORT。"
    warn "Local proxy存在请求超时限制；默认核心档不代理Google视频CDN和Meta实时聊天域名。"
    test "$profile" != google-meta-full || warn "完整档包含YouTube视频、WhatsApp和Messenger，属于实验用途。"
    echo "  目标档位: $profile"
    read -rp "输入 ENABLE-WARP 确认接受Cloudflare客户端条款并继续: " confirm || true
    test "$confirm" = ENABLE-WARP || { info "已取消。"; return 0; }
    _e136_prepare || return 1
    tx="$E136_BACKUP_DIR/warp-enable-$(date +%Y%m%d_%H%M%S)-$$"
    mkdir -p "$tx" || return 1
    _e135_snapshot_file "$CONFIG" "$tx/config" || return 1
    _e135_snapshot_file "$E136_WARP_STATE" "$tx/state" || return 1
    _e135_snapshot_file "$E136_WARP_HEALTH_SERVICE" "$tx/health-service" || return 1
    _e135_snapshot_file "$E136_WARP_HEALTH_TIMER" "$tx/health-timer" || return 1
    route_before=$(_e136_warp_route4); printf '%s\n' "$route_before" > "$tx/default-route.before"
    if ! _e136_warp_install_package "$tx" || ! _e136_warp_connect_local_proxy || \
       ! _e136_xray_apply_warp_route "$profile" true || ! _e136_warp_health_install; then
        error "WARP启用失败，恢复Xray配置、仓库和本次新增软件。"
        _e135_restore_file "$CONFIG" "$tx/config" || true
        _e135_restore_file "$E136_WARP_STATE" "$tx/state" || true
        _e135_restore_file "$E136_WARP_HEALTH_SERVICE" "$tx/health-service" || true
        _e135_restore_file "$E136_WARP_HEALTH_TIMER" "$tx/health-timer" || true
        systemctl daemon-reload >/dev/null 2>&1 || true
        systemctl restart xray.service >/dev/null 2>&1 || true
        _e136_warp_install_rollback "$tx"
        return 1
    fi
    test "$route_before" = "$(_e136_warp_route4)" || {
        error "完成后IPv4默认路由发生变化，执行安全回滚。"
        _e136_xray_apply_warp_route disabled false || true
        _e136_warp_cli disconnect >/dev/null 2>&1 || true
        return 1
    }
    info "WARP定向分流已启用：$profile。Google/Meta匹配TCP走WARP，匹配UDP被阻断以防QUIC直连泄漏。"
    _e136_warp_status
}

_e136_warp_disable_route() {
    _e136_xray_apply_warp_route disabled false || return 1
    systemctl disable --now xray-warp-e136-health.timer >/dev/null 2>&1 || true
    info "Xray WARP分流已删除；WARP客户端仍保留。"
}

_e136_warp_uninstall() {
    local confirm
    title "V199e137：移除WARP"
    read -rp "输入 REMOVE-WARP 确认删除分流、客户端和官方仓库: " confirm || true
    test "$confirm" = REMOVE-WARP || return 0
    _e136_warp_disable_route || return 1
    _e136_warp_cli disconnect >/dev/null 2>&1 || true
    systemctl disable --now xray-warp-e136-health.timer xray-warp-e136-health.service >/dev/null 2>&1 || true
    rm -f "$E136_WARP_HEALTH_SERVICE" "$E136_WARP_HEALTH_TIMER" "$E136_WARP_STATE" 2>/dev/null || true
    systemctl daemon-reload >/dev/null 2>&1 || true
    if command -v apt-get >/dev/null 2>&1; then apt-get remove -y cloudflare-warp || return 1; fi
    rm -f "$E136_WARP_REPO" "$E136_WARP_KEYRING" 2>/dev/null || true
    apt-get update >/dev/null 2>&1 || true
    info "WARP客户端与E136分流已移除。"
}

_e136_warp_status() {
    local route_enabled profile trace direct_ip warp_ip loc colo mode listener="DOWN"
    route_enabled=$(sed -n 's/^route_enabled=//p' "$E136_WARP_STATE" 2>/dev/null | head -n1); route_enabled=${route_enabled:-0}
    profile=$(sed -n 's/^profile=//p' "$E136_WARP_STATE" 2>/dev/null | head -n1); profile=${profile:-none}
    _e136_warp_listener_ok && listener="127.0.0.1:$E136_WARP_PORT" || true
    direct_ip=$(curl -4 -fsS --connect-timeout 3 --max-time 8 https://api.ipify.org 2>/dev/null || echo unavailable)
    trace=$(_e136_warp_trace 2>/dev/null || true)
    warp_ip=$(awk -F= '$1=="ip"{print $2}' <<<"$trace"); warp_ip=${warp_ip:-unavailable}
    loc=$(awk -F= '$1=="loc"{print $2}' <<<"$trace"); loc=${loc:-unknown}
    colo=$(awk -F= '$1=="colo"{print $2}' <<<"$trace"); colo=${colo:-unknown}
    mode=$(command -v warp-cli >/dev/null 2>&1 && _e136_warp_cli settings 2>/dev/null | grep -Ei 'mode|service|proxy|protocol' | xargs echo || echo not-installed)
    title "V199e137：WARP定向分流状态"
    printf '  %-28s %s\n' "客户端" "$(command -v warp-cli >/dev/null 2>&1 && echo installed || echo not-installed)"
    printf '  %-28s %s\n' "本地代理" "$listener"
    printf '  %-28s %s\n' "Xray分流" "enabled=$route_enabled profile=$profile"
    printf '  %-28s %s\n' "原始IPv4" "$direct_ip"
    printf '  %-28s %s\n' "WARP出口IPv4" "$warp_ip"
    printf '  %-28s %s\n' "Cloudflare loc/colo" "$loc/$colo"
    printf '  %-28s %s\n' "warp-cli模式" "$mode"
    printf '  %-28s %s\n' "默认IPv4路由" "$(_e136_warp_route4 | xargs echo)"
    printf '  %-28s %s\n' "IPv6关闭" "$(sysctl -n net.ipv6.conf.all.disable_ipv6 2>/dev/null || echo unsupported)"
    if test "$route_enabled" = 1 && test -s "$CONFIG"; then
        echo "  Xray规则："
        jq -r --arg w "$E136_WARP_TAG" --arg b "$E136_WARP_BLOCK_TAG" '.routing.rules[]?|select(.outboundTag==$w or .outboundTag==$b)|"    network=\(.network) outbound=\(.outboundTag) domains=\(.domain|length)"' "$CONFIG" 2>/dev/null || true
    fi
}

_e136_warp_menu() {
    local n
    while true; do
        clear; title "V199e137：WARP定向分流中心"
        echo "  1) Google + Meta网页定位核心档（推荐）"
        echo "  2) 仅Google网页定位核心档"
        echo "  3) 仅Meta网页定位核心档"
        echo "  4) Google + Meta完整档（含视频/聊天，实验）"
        echo "  5) 查看状态、出口IP与Cloudflare loc"
        echo "  6) 修复/重连本地代理"
        echo "  7) 关闭Xray分流但保留WARP客户端"
        echo "  8) 完全卸载WARP"
        echo "  0) 返回"
        read -rp "操作: " n || true
        case "$n" in
            1) _e136_warp_enable_profile google-meta-core; _e136_pause ;;
            2) _e136_warp_enable_profile google-core; _e136_pause ;;
            3) _e136_warp_enable_profile meta-core; _e136_pause ;;
            4) _e136_warp_enable_profile google-meta-full; _e136_pause ;;
            5) _e136_warp_status; _e136_pause ;;
            6) _e136_warp_connect_local_proxy && _e136_warp_health_install; _e136_pause ;;
            7) _e136_warp_disable_route; _e136_pause ;;
            8) _e136_warp_uninstall; _e136_pause ;;
            0) return 0 ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

#------------------------------------------------------------------------------
# E136 script installation, snapshot paths, and non-mutating hot-update preflight.
#------------------------------------------------------------------------------
_e136_install_self() {
    test -f "$SCRIPT_PATH" || return 1
    mkdir -p "$SCRIPT_DIR" || return 1
    install -m 0755 "$SCRIPT_PATH" "$SYMLINK" || return 1
    install -m 0755 "$SCRIPT_PATH" "$E136_SELF_PATH" || return 1
    install -m 0755 "$SCRIPT_PATH" "$E136_LATEST_PATH" || return 1
    hash -r 2>/dev/null || true
}

_e135_install_self() { _e136_install_self; }

if declare -F _e135_system_paths >/dev/null 2>&1; then
    eval "$(declare -f _e135_system_paths | sed '1s/_e135_system_paths/_e136_system_paths_base/')"
fi
_e135_system_paths() {
    declare -F _e136_system_paths_base >/dev/null 2>&1 && _e136_system_paths_base
    cat <<EOF_E136_PATHS
$E136_SELF_PATH
$E136_LATEST_PATH
$E136_NETWORK_CONF
$E136_NETWORK_STATE
$E136_WARP_STATE
$E136_WARP_KEYRING
$E136_WARP_REPO
$E136_WARP_HEALTH_SERVICE
$E136_WARP_HEALTH_TIMER
EOF_E136_PATHS
}

_e136_hot_update_preflight() {
    test "$EUID" -eq 0 || { error "热更新必须使用root。"; return 1; }
    command -v systemctl >/dev/null 2>&1 || { error "缺少systemd。"; return 1; }
    local c
    for c in bash jq curl ip ss tar install awk sed grep sysctl; do
        command -v "$c" >/dev/null 2>&1 || { error "热更新预检缺少命令：$c"; return 1; }
    done
    test -r "$SCRIPT_PATH" || { error "当前脚本不可读。"; return 1; }
    return 0
}

hot_update_from_legacy() {
    local protect="" sysbackup rc=0 was_active=0 warp_route=0
    E135_NEW_PACKAGES=()
    _e136_prepare || return 1
    protect=$(_e116_backup_state before_hot_update_e136) || return 1
    _e118_save_core_payload "$protect" || { error "Core/DAT/systemd快照失败。"; return 1; }
    was_active=$(sed -n 's/^xray_was_active=//p' "$protect/meta.env" 2>/dev/null | head -n1); was_active=${was_active:-0}
    warp_route=$(sed -n 's/^route_enabled=//p' "$E136_WARP_STATE" 2>/dev/null | head -n1); warp_route=${warp_route:-0}
    sysbackup="$E136_BACKUP_DIR/hot-update-$(date +%Y%m%d_%H%M%S)-$$"
    _e135_system_snapshot "$sysbackup" || return 1
    _e135_require_runtime_tools || rc=1
    test "$rc" -ne 0 || _e135_disable_legacy_optimizers || rc=1
    test "$rc" -ne 0 || _e136_install_self || rc=1
    test "$rc" -ne 0 || install_update_dat || rc=1
    test "$rc" -ne 0 || systemctl enable --now xray-dat-update.timer >/dev/null 2>&1 || rc=1
    if test "$rc" -eq 0 && declare -F _e105_disable_xray_core_auto_update >/dev/null 2>&1; then _e105_disable_xray_core_auto_update || rc=1; fi
    test "$rc" -ne 0 || _e116_apply_init_window_default30 || rc=1
    test "$rc" -ne 0 || _e136_network_apply balanced force || rc=1
    test "$rc" -ne 0 || _e121_install_log_retention || rc=1
    test "$rc" -ne 0 || _e135_install_ssh_guard || rc=1
    test "$rc" -ne 0 || fix_xray_systemd_limits || rc=1
    test "$rc" -ne 0 || printf '%s\n' "$E136_VERSION" > "$SCRIPT_VERSION_FILE" || rc=1
    if test "$rc" -eq 0 && test "$was_active" = 1; then
        _e127_verify_xray_runtime "$CONFIG" 12 || rc=1
        _e131_verify_nice_runtime || rc=1
    fi
    test "$rc" -ne 0 || test "$(sysctl -n net.ipv4.tcp_notsent_lowat 2>/dev/null)" = 131072 || rc=1
    test "$rc" -ne 0 || test "$(sysctl -n net.ipv6.conf.all.disable_ipv6 2>/dev/null)" = 1 || rc=1
    test "$rc" -ne 0 || test "$(sysctl -n net.ipv6.conf.default.disable_ipv6 2>/dev/null)" = 1 || rc=1
    test "$rc" -ne 0 || systemctl is-enabled --quiet xray-dat-update.timer || rc=1
    test "$rc" -ne 0 || command -v qrencode >/dev/null 2>&1 || rc=1
    test "$rc" -ne 0 || command -v vnstat >/dev/null 2>&1 || rc=1
    if test "$rc" -eq 0 && test "$warp_route" = 1; then
        _e136_warp_proxy_ready || { error "现有WARP分流已启用，但本地代理不健康。"; rc=1; }
        jq -e --arg w "$E136_WARP_TAG" '.outbounds[]?|select(.tag==$w)' "$CONFIG" >/dev/null 2>&1 || rc=1
    fi
    if test "$rc" -ne 0; then
        error "E136热更新失败，恢复系统文件、防火墙、sysctl、Core和节点状态。"
        _e135_system_restore "$sysbackup" || true
        _e118_restore_core_payload "$protect" >/dev/null 2>&1 || true
        _e118_restore_state "$protect" >/dev/null 2>&1 || true
        _e135_remove_new_runtime_tools || true
        return 1
    fi
    info "V199e137热更新完成：IPv4-only、Nice=-20、init30、notsent=131072、SSH防自锁、3天日志、DAT 03:00。"
    test "$warp_route" = 0 || info "原有WARP定向分流已验证保持可用。"
    info "热更新前系统快照：$sysbackup"
}

