            20) if declare -F do_tc_bandwidth_menu_e95 >/dev/null 2>&1; then do_tc_bandwidth_menu_e95; else warn "TC模块缺失。"; fi ;;
            22) _e136_warp_menu ;;
            88) do_uninstall ;;
            0) return 0 ;;
            *) warn "无效操作。"; sleep 1 ;;
        esac
    done
}

