_e136_self_test() {
    local rc=0 tmpd net keys src stripped domains sample enabled disabled merged body
    tmpd=$(mktemp -d /tmp/e136-selftest.XXXXXX) || return 1
    echo "V199e137 release gate:"
    test "$SCRIPT_VERSION" = 199e136 && echo "  [PASS] version" || { echo "  [FAIL] version"; rc=1; }
    net="$tmpd/network.conf"; _e136_network_candidate balanced "$net" || rc=1
    grep -qx 'net.ipv4.tcp_notsent_lowat = 131072' "$net" && \
    grep -qx 'net.ipv6.conf.all.disable_ipv6 = 1' "$net" && \
    grep -qx 'net.ipv6.conf.default.disable_ipv6 = 1' "$net" && \
    echo "  [PASS] IPv4-only network candidate" || { echo "  [FAIL] network candidate"; rc=1; }
    keys="$tmpd/keys"; src="$tmpd/src.conf"; stripped="$tmpd/stripped.conf"
    _e136_network_keys > "$keys"
    printf '%s\n' 'net.ipv4.tcp_notsent_lowat = 16384' 'foo.bar = 1' 'net.ipv6.conf.all.disable_ipv6 = 0' > "$src"
    _e136_strip_sysctl_file "$keys" "$src" "$stripped" || rc=1
    test "$(cat "$stripped")" = 'foo.bar = 1' && echo "  [PASS] duplicate sysctl behavior" || { echo "  [FAIL] sysctl strip"; rc=1; }
    domains=$(_e136_warp_domains_json google-meta-core) || rc=1
    test "$(jq 'length' <<<"$domains")" -ge 20 && test "$(jq 'length == (unique|length)' <<<"$domains")" = true && echo "  [PASS] WARP domain profile" || { echo "  [FAIL] WARP domains"; rc=1; }
    sample="$tmpd/sample.json"; enabled="$tmpd/enabled.json"; disabled="$tmpd/disabled.json"
    printf '%s\n' '{"dns":{"servers":["1.1.1.1"]},"outbounds":[{"tag":"direct","protocol":"freedom","settings":{}}],"routing":{"rules":[]}}' > "$sample"
    _e136_warp_config_build google-meta-core true "$enabled" "$sample" || rc=1
    jq -e --arg w "$E136_WARP_TAG" --arg b "$E136_WARP_BLOCK_TAG" '
      ([.outbounds[]|select(.tag==$w)]|length)==1 and
      ([.outbounds[]|select(.tag==$b)]|length)==1 and
      ([.routing.rules[]|select(.outboundTag==$w)]|length)==1 and
      ([.routing.rules[]|select(.outboundTag==$b)]|length)==1 and
      .dns.queryStrategy=="UseIPv4"
    ' "$enabled" >/dev/null && echo "  [PASS] Xray WARP route build" || { echo "  [FAIL] WARP config build"; rc=1; }
    _e136_warp_config_build disabled false "$disabled" "$enabled" || rc=1
    jq -e --arg w "$E136_WARP_TAG" --arg b "$E136_WARP_BLOCK_TAG" '
      ([.outbounds[]|select(.tag==$w or .tag==$b)]|length)==0 and
      ([.routing.rules[]|select(.outboundTag==$w or .outboundTag==$b)]|length)==0
    ' "$disabled" >/dev/null && echo "  [PASS] Xray WARP route removal" || { echo "  [FAIL] WARP removal"; rc=1; }
    test "$(cpu_mask_all 64)" = 'ffffffff,ffffffff' && echo "  [PASS] 64-core cpumask" || { echo "  [FAIL] cpumask"; rc=1; }
    merged=$(_e136_merge_ignoreip_values '10.0.0.0/8 192.168.1.5' '203.0.113.9')
    [[ "$merged" == *'10.0.0.0/8'* && "$merged" == *'192.168.1.5'* && "$merged" == *'203.0.113.9'* ]] && echo "  [PASS] Fail2ban ignoreip preservation" || { echo "  [FAIL] ignoreip merge"; rc=1; }
    body=$(declare -f _e136_warp_connect_local_proxy)
    [[ "$body" == *'_e136_warp_route4'* && "$body" == *'_e136_warp_listener_ok'* && "$body" == *'disconnect'* ]] && echo "  [PASS] WARP anti-lockout guard" || { echo "  [FAIL] WARP anti-lockout"; rc=1; }
    body=$(declare -f hot_update_from_legacy)
    [[ "$body" == *'_e135_system_snapshot'* && "$body" == *'_e136_network_apply balanced force'* && "$body" == *'net.ipv6.conf.all.disable_ipv6'* ]] && echo "  [PASS] E136 hot-update chain" || { echo "  [FAIL] hot-update"; rc=1; }
    body=$(declare -f _e136_hot_update_preflight)
    [[ "$body" != *'install '* && "$body" != *'cp '* && "$body" != *'apt-get'* ]] && echo "  [PASS] non-mutating hot-update preflight" || { echo "  [FAIL] preflight mutates"; rc=1; }
    test "$(grep -c 'bash ex199e136.sh' "$SCRIPT_PATH" 2>/dev/null || true)" = 0 && echo "  [PASS] stale execution hint removed" || { echo "  [FAIL] stale hint"; rc=1; }
    rm -rf "$tmpd"
    echo "V199e137 result: $(test "$rc" -eq 0 && echo PASS || echo FAIL)"
    return "$rc"
}


#==============================================================================
# V199e137 FINAL AUDIT CORRECTION LAYER
# - WARP fail-closed route safety
# - health-check anti-lockout
# - WARP transaction rollback/adoption guard
# - standalone network service-state rollback
# - minimal non-mutating WARP/network preflight
# - corrected release gate
#==============================================================================

_e136_warp_preflight() {
    test "$EUID" -eq 0 || { error "WARP管理必须使用root。"; return 1; }
    command -v systemctl >/dev/null 2>&1 || { error "缺少systemd。"; return 1; }
    local c
    for c in bash curl jq ip ss awk sed grep install tar; do
        command -v "$c" >/dev/null 2>&1 || { error "WARP预检缺少命令：$c"; return 1; }
    done
    test -r "$SCRIPT_PATH" || { error "当前脚本不可读。"; return 1; }
    return 0
}

_e136_network_preflight() {
    test "$EUID" -eq 0 || { error "网络参数管理必须使用root。"; return 1; }
    local c
    for c in bash jq ip sysctl awk sed grep install; do
        command -v "$c" >/dev/null 2>&1 || { error "网络参数预检缺少命令：$c"; return 1; }
    done
    return 0
}

_e136_warp_disconnect_fail_closed() {
    local before="${1:-}" after
    _e136_warp_cli disconnect >/dev/null 2>&1 || true
    sleep 1
    after=$(_e136_warp_route4)
    if test -n "$before" && test "$before" != "$after"; then
        error "WARP断开后IPv4默认路由仍未恢复。请保持当前SSH会话并通过云控制台检查路由。"
        return 1
    fi
    return 0
}

_e136_warp_connect_local_proxy() {
    local before after svc
    before=$(_e136_warp_route4)
    test -n "$before" || { error "未检测到IPv4默认路由，拒绝启动WARP。"; return 1; }
    svc=$(_e136_warp_service_name)
    systemctl enable --now "$svc" >/dev/null 2>&1 || return 1
    _e136_warp_register || { error "WARP设备注册失败。"; return 1; }
    _e136_warp_set_masque || { error "无法把WARP隧道协议设为MASQUE。"; return 1; }
    _e136_warp_set_proxy_port || { error "当前warp-cli不支持设置本地代理端口。"; return 1; }
    _e136_warp_set_proxy_mode || {
        error "Local proxy模式未获允许。请在Cloudflare Zero Trust设备配置中选择Local proxy与MASQUE后重试。"
        return 1
    }
    _e136_warp_cli connect >/dev/null 2>&1 || return 1
    sleep 4
    after=$(_e136_warp_route4)
    if test "$before" != "$after"; then
        error "WARP改变了IPv4默认路由；为防SSH失联，立即断开。"
        _e136_warp_disconnect_fail_closed "$before" || true
        return 1
    fi
    if ! _e136_warp_listener_ok || ! _e136_warp_proxy_ready; then
        error "WARP没有以仅127.0.0.1本地代理方式提供warp=on出口；立即断开，拒绝留下未知模式。"
        _e136_warp_disconnect_fail_closed "$before" || true
        return 1
    fi
    return 0
}

_e136_warp_health_check() {
    local before after route_enabled
    mkdir -p "$(dirname "$E136_WARP_LOG")" 2>/dev/null || true
    route_enabled=$(sed -n 's/^route_enabled=//p' "$E136_WARP_STATE" 2>/dev/null | head -n1)
    route_enabled=${route_enabled:-0}
    test "$route_enabled" = 1 || return 0
    before=$(_e136_warp_route4)
    if _e136_warp_proxy_ready; then
        echo "[$(date -Is)] OK local proxy 127.0.0.1:$E136_WARP_PORT" >> "$E136_WARP_LOG"
        return 0
    fi
    echo "[$(date -Is)] WARN proxy unhealthy; fail-closed reconnect" >> "$E136_WARP_LOG"
    if _e136_warp_connect_local_proxy; then
        after=$(_e136_warp_route4)
        if test "$before" = "$after" && _e136_warp_proxy_ready; then
            echo "[$(date -Is)] RECOVERED" >> "$E136_WARP_LOG"
            return 0
        fi
    fi
    _e136_warp_disconnect_fail_closed "$before" >/dev/null 2>&1 || true
    echo "[$(date -Is)] FAIL; disconnected to protect default route" >> "$E136_WARP_LOG"
    return 1
}

_e136_warp_tx_restore() {
    local tx="$1" was_active="${2:-0}"
    _e135_restore_file "$CONFIG" "$tx/config" || true
    _e135_restore_file "$E136_WARP_STATE" "$tx/state" || true
    _e135_restore_file "$E136_WARP_HEALTH_SERVICE" "$tx/health-service" || true
    _e135_restore_file "$E136_WARP_HEALTH_TIMER" "$tx/health-timer" || true
    systemctl daemon-reload >/dev/null 2>&1 || true
    if test "$was_active" = 1 && test -s "$CONFIG"; then
        systemctl restart xray.service >/dev/null 2>&1 || true
    fi
    _e136_warp_install_rollback "$tx"
}

_e136_warp_enable_profile() {
    local profile="${1:-google-meta-core}" confirm tx route_before route_after was_active=0 preinstalled=0 managed=""
    title "V199e137：启用WARP本地代理与Xray定向分流"
    warn "不会启用全局WARP；SSH、Xray入站和系统默认流量继续走原IPv4。"
    warn "Local proxy必须使用MASQUE并仅监听127.0.0.1:$E136_WARP_PORT。"
    warn "Local proxy存在10秒请求限制；默认核心档不代理Google视频CDN和Meta实时聊天域名。"
    test "$profile" != google-meta-full || warn "完整档包含YouTube视频、WhatsApp和Messenger，属于实验用途。"
    echo "  目标档位: $profile"
    dpkg-query -W -f='${Status}' cloudflare-warp 2>/dev/null | grep -q 'install ok installed' && preinstalled=1 || true
    managed=$(sed -n 's/^managed_by=//p' "$E136_WARP_STATE" 2>/dev/null | head -n1)
    if test "$preinstalled" = 1 && test "$managed" != e136; then
        error "检测到非E136管理的现有Cloudflare WARP。为避免破坏原模式/账户，本脚本拒绝接管。"
        error "请先手工备份并卸载旧WARP，或继续使用原有配置。"
        return 1
    fi
    read -rp "输入 ENABLE-WARP 确认接受Cloudflare客户端条款并继续: " confirm || true
    test "$confirm" = ENABLE-WARP || { info "已取消。"; return 0; }
    _e136_prepare || return 1
    tx="$E136_BACKUP_DIR/warp-enable-$(date +%Y%m%d_%H%M%S)-$$"
    mkdir -p "$tx" || return 1
    _e135_snapshot_file "$CONFIG" "$tx/config" || return 1
    _e135_snapshot_file "$E136_WARP_STATE" "$tx/state" || return 1
    _e135_snapshot_file "$E136_WARP_HEALTH_SERVICE" "$tx/health-service" || return 1
    _e135_snapshot_file "$E136_WARP_HEALTH_TIMER" "$tx/health-timer" || return 1
    systemctl is-active --quiet xray.service 2>/dev/null && was_active=1 || true
    route_before=$(_e136_warp_route4)
    test -n "$route_before" || { error "IPv4默认路由为空，拒绝继续。"; return 1; }
    printf '%s\n' "$route_before" > "$tx/default-route.before"
    if ! _e136_warp_install_package "$tx" || \
       ! _e136_warp_connect_local_proxy || \
       ! _e136_xray_apply_warp_route "$profile" true || \
       ! _e136_warp_health_install; then
        error "WARP启用失败，恢复Xray配置、仓库、服务与本次新增软件。"
        _e136_warp_tx_restore "$tx" "$was_active"
        return 1
    fi
    route_after=$(_e136_warp_route4)
    if test "$route_before" != "$route_after"; then
        error "完成后IPv4默认路由发生变化，执行完整安全回滚。"
        _e136_warp_disconnect_fail_closed "$route_before" || true
        _e136_warp_tx_restore "$tx" "$was_active"
        return 1
    fi
    {
        echo "managed_by=e136"
        echo "route_enabled=1"
        echo "profile=$profile"
        echo "port=$E136_WARP_PORT"
        echo "default_route_sha256=$(printf '%s' "$route_before" | sha256sum | awk '{print $1}')"
        echo "updated=$(date -Is 2>/dev/null || date)"
    } > "$E136_WARP_STATE"
    chmod 0600 "$E136_WARP_STATE" 2>/dev/null || true
    info "WARP定向分流已启用：$profile。匹配TCP走WARP，匹配UDP被阻断以防QUIC直连泄漏。"
    _e136_warp_status
}

_e136_warp_disable_route() {
    local has_route=0
    if test -s "$CONFIG" && command -v jq >/dev/null 2>&1; then
        jq -e --arg w "$E136_WARP_TAG" --arg b "$E136_WARP_BLOCK_TAG" \
          'any(.outbounds[]?; .tag==$w or .tag==$b) or any(.routing.rules[]?; .outboundTag==$w or .outboundTag==$b)' \
          "$CONFIG" >/dev/null 2>&1 && has_route=1 || true
    fi
    if test "$has_route" = 1; then
        _e136_xray_apply_warp_route disabled false || return 1
    else
        {
            echo "managed_by=e136"
            echo "route_enabled=0"
            echo "profile=disabled"
            echo "port=$E136_WARP_PORT"
            echo "updated=$(date -Is 2>/dev/null || date)"
        } > "$E136_WARP_STATE"
        chmod 0600 "$E136_WARP_STATE" 2>/dev/null || true
    fi
    systemctl disable --now xray-warp-e136-health.timer >/dev/null 2>&1 || true
    info "Xray WARP分流已删除；WARP客户端仍保留。"
}

_e136_warp_uninstall() {
    local confirm tx was_active=0 failed=0
    title "V199e137：移除WARP"
    read -rp "输入 REMOVE-WARP 确认删除分流、客户端和官方仓库: " confirm || true
    test "$confirm" = REMOVE-WARP || return 0
    _e136_prepare || return 1
    tx="$E136_BACKUP_DIR/warp-uninstall-$(date +%Y%m%d_%H%M%S)-$$"
    mkdir -p "$tx" || return 1
    _e135_snapshot_file "$CONFIG" "$tx/config" || return 1
    _e135_snapshot_file "$E136_WARP_STATE" "$tx/state" || return 1
    _e135_snapshot_file "$E136_WARP_REPO" "$tx/repo" || return 1
    _e135_snapshot_file "$E136_WARP_KEYRING" "$tx/keyring" || return 1
    _e135_snapshot_file "$E136_WARP_HEALTH_SERVICE" "$tx/health-service" || return 1
    _e135_snapshot_file "$E136_WARP_HEALTH_TIMER" "$tx/health-timer" || return 1
    systemctl is-active --quiet xray.service 2>/dev/null && was_active=1 || true
    _e136_warp_disable_route || failed=1
    _e136_warp_cli disconnect >/dev/null 2>&1 || true
    systemctl disable --now xray-warp-e136-health.timer xray-warp-e136-health.service >/dev/null 2>&1 || true
    if test "$failed" = 0 && command -v apt-get >/dev/null 2>&1; then
        apt-get remove -y cloudflare-warp || failed=1
    fi
    if test "$failed" != 0; then
        error "WARP卸载未完成，恢复Xray分流状态与E136文件。"
        _e135_restore_file "$CONFIG" "$tx/config" || true
        _e135_restore_file "$E136_WARP_STATE" "$tx/state" || true
        _e135_restore_file "$E136_WARP_REPO" "$tx/repo" || true
        _e135_restore_file "$E136_WARP_KEYRING" "$tx/keyring" || true
        _e135_restore_file "$E136_WARP_HEALTH_SERVICE" "$tx/health-service" || true
        _e135_restore_file "$E136_WARP_HEALTH_TIMER" "$tx/health-timer" || true
        systemctl daemon-reload >/dev/null 2>&1 || true
        test "$was_active" = 0 || systemctl restart xray.service >/dev/null 2>&1 || true
        return 1
    fi
    rm -f "$E136_WARP_HEALTH_SERVICE" "$E136_WARP_HEALTH_TIMER" "$E136_WARP_STATE" "$E136_WARP_REPO" "$E136_WARP_KEYRING" 2>/dev/null || true
    systemctl daemon-reload >/dev/null 2>&1 || true
    apt-get update >/dev/null 2>&1 || true
    info "WARP客户端与E136分流已移除。"
}

_e136_service_state_snapshot() {
    local out="$1" svc
    : > "$out" || return 1
    for svc in xray-accel-e125.service xray-accel-e126.service xray-hw-tweaks.service nic-optimize.service rps-optimize.service txqueue.service; do
        printf '%s|%s|%s\n' "$svc" "$(systemctl is-enabled "$svc" 2>/dev/null || true)" "$(systemctl is-active "$svc" 2>/dev/null || true)" >> "$out"
    done
}

_e136_service_state_restore() {
    local in="$1" svc enabled active
    test -s "$in" || return 0
    while IFS='|' read -r svc enabled active; do
        test -n "$svc" || continue
        if test "$enabled" = enabled; then systemctl enable "$svc" >/dev/null 2>&1 || true; else systemctl disable "$svc" >/dev/null 2>&1 || true; fi
        if test "$active" = active; then systemctl restart "$svc" >/dev/null 2>&1 || true; else systemctl stop "$svc" >/dev/null 2>&1 || true; fi
    done < "$in"
}

# Preserve the audited implementation, then add standalone service-state rollback.
eval "$(declare -f _e136_network_apply | sed '1s/^_e136_network_apply[[:space:]]*()/_e136_network_apply_base_audited ()/')"
_e136_network_apply() {
    local state_file rc=0 iface_file
    state_file=$(mktemp /tmp/e136-network-services.XXXXXX) || return 1
    _e136_service_state_snapshot "$state_file" || { rm -f "$state_file"; return 1; }
    if _e136_network_apply_base_audited "$@"; then
        # all/default normally covers current interfaces; explicitly enforce/read back each existing interface.
        for iface_file in /proc/sys/net/ipv6/conf/*/disable_ipv6; do
            test -e "$iface_file" || continue
            printf '1\n' > "$iface_file" 2>/dev/null || { error "IPv6关闭失败：$iface_file"; rc=1; break; }
            test "$(cat "$iface_file" 2>/dev/null)" = 1 || { error "IPv6读回失败：$iface_file"; rc=1; break; }
        done
        if test "$rc" = 0; then
            rm -f "$state_file"
            return 0
        fi
    else
        rc=$?
    fi
    _e136_service_state_restore "$state_file"
    rm -f "$state_file"
    return "${rc:-1}"
}

_e136_hot_update_preflight() {
    test "$EUID" -eq 0 || { error "热更新必须使用root。"; return 1; }
    command -v systemctl >/dev/null 2>&1 || { error "缺少systemd。"; return 1; }
    local c
    for c in bash jq curl ip ss tar install awk sed grep sysctl; do
        command -v "$c" >/dev/null 2>&1 || { error "热更新预检缺少命令：$c"; return 1; }
    done
    test -r "$SCRIPT_PATH" || { error "当前脚本不可读。"; return 1; }
    return 0
}

_e136_self_test() {
    local rc=0 tmpd net keys src stripped domains sample enabled disabled merged body oldhint
    tmpd=$(mktemp -d /tmp/e136-selftest.XXXXXX) || return 1
    echo "V199e137 release gate:"
    test "$SCRIPT_VERSION" = 199e136 && echo "  [PASS] version" || { echo "  [FAIL] version"; rc=1; }
    net="$tmpd/network.conf"; _e136_network_candidate balanced "$net" || rc=1
    grep -qx 'net.ipv4.tcp_notsent_lowat = 131072' "$net" && \
    grep -qx 'net.ipv6.conf.all.disable_ipv6 = 1' "$net" && \
    grep -qx 'net.ipv6.conf.default.disable_ipv6 = 1' "$net" && \
    echo "  [PASS] IPv4-only network candidate" || { echo "  [FAIL] network candidate"; rc=1; }
    keys="$tmpd/keys"; src="$tmpd/src.conf"; stripped="$tmpd/stripped.conf"
    _e136_network_keys > "$keys"
    printf '%s\n' 'net.ipv4.tcp_notsent_lowat = 16384' 'foo.bar = 1' 'net.ipv6.conf.all.disable_ipv6 = 0' > "$src"
    _e136_strip_sysctl_file "$keys" "$src" "$stripped" || rc=1
    test "$(cat "$stripped")" = 'foo.bar = 1' && echo "  [PASS] duplicate sysctl behavior" || { echo "  [FAIL] sysctl strip"; rc=1; }
    domains=$(_e136_warp_domains_json google-meta-core) || rc=1
    test "$(jq 'length' <<<"$domains")" -ge 20 && test "$(jq 'length == (unique|length)' <<<"$domains")" = true && echo "  [PASS] WARP domain profile" || { echo "  [FAIL] WARP domains"; rc=1; }
    sample="$tmpd/sample.json"; enabled="$tmpd/enabled.json"; disabled="$tmpd/disabled.json"
    printf '%s\n' '{"dns":{"servers":["1.1.1.1"]},"outbounds":[{"tag":"direct","protocol":"freedom","settings":{}}],"routing":{"rules":[]}}' > "$sample"
    _e136_warp_config_build google-meta-core true "$enabled" "$sample" || rc=1
    jq -e --arg w "$E136_WARP_TAG" --arg b "$E136_WARP_BLOCK_TAG" '
      ([.outbounds[]|select(.tag==$w)]|length)==1 and
      ([.outbounds[]|select(.tag==$b)]|length)==1 and
      ([.routing.rules[]|select(.outboundTag==$w)]|length)==1 and
      ([.routing.rules[]|select(.outboundTag==$b)]|length)==1 and
      .dns.queryStrategy=="UseIPv4"
    ' "$enabled" >/dev/null && echo "  [PASS] Xray WARP route build" || { echo "  [FAIL] WARP config build"; rc=1; }
    _e136_warp_config_build disabled false "$disabled" "$enabled" || rc=1
    jq -e --arg w "$E136_WARP_TAG" --arg b "$E136_WARP_BLOCK_TAG" '
      ([.outbounds[]|select(.tag==$w or .tag==$b)]|length)==0 and
      ([.routing.rules[]|select(.outboundTag==$w or .outboundTag==$b)]|length)==0
    ' "$disabled" >/dev/null && echo "  [PASS] Xray WARP route removal" || { echo "  [FAIL] WARP removal"; rc=1; }
    test "$(cpu_mask_all 64)" = 'ffffffff,ffffffff' && echo "  [PASS] 64-core cpumask" || { echo "  [FAIL] cpumask"; rc=1; }
    merged=$(_e136_merge_ignoreip_values '10.0.0.0/8 192.168.1.5' '203.0.113.9')
    [[ "$merged" == *'10.0.0.0/8'* && "$merged" == *'192.168.1.5'* && "$merged" == *'203.0.113.9'* ]] && echo "  [PASS] Fail2ban ignoreip preservation" || { echo "  [FAIL] ignoreip merge"; rc=1; }
    body=$(declare -f _e136_warp_connect_local_proxy)
    [[ "$body" == *'_e136_warp_route4'* && "$body" == *'_e136_warp_listener_ok'* && "$body" == *'_e136_warp_disconnect_fail_closed'* ]] && echo "  [PASS] WARP anti-lockout" || { echo "  [FAIL] WARP anti-lockout"; rc=1; }
    body=$(declare -f _e136_warp_health_check)
    [[ "$body" == *'_e136_warp_connect_local_proxy'* && "$body" == *'route_enabled'* ]] && echo "  [PASS] WARP health fail-closed" || { echo "  [FAIL] WARP health guard"; rc=1; }
    body=$(declare -f _e136_network_apply)
    [[ "$body" == *'_e136_service_state_snapshot'* && "$body" == *'_e136_service_state_restore'* ]] && echo "  [PASS] network service rollback" || { echo "  [FAIL] network service rollback"; rc=1; }
    body=$(declare -f hot_update_from_legacy)
    [[ "$body" == *'_e135_system_snapshot'* && "$body" == *'_e136_network_apply balanced force'* && "$body" == *'net.ipv6.conf.all.disable_ipv6'* ]] && echo "  [PASS] E136 hot-update chain" || { echo "  [FAIL] hot-update"; rc=1; }
    body=$(declare -f _e136_hot_update_preflight)
    [[ "$body" != *'apt-get '* && "$body" != *'cp -'* && "$body" != *'systemctl enable'* && "$body" != *'systemctl restart'* ]] && echo "  [PASS] non-mutating hot-update preflight" || { echo "  [FAIL] preflight mutates"; rc=1; }
    oldhint="ex199e""131"
    test "$(grep -c "$oldhint" "$SCRIPT_PATH" 2>/dev/null || true)" = 0 && echo "  [PASS] stale version text removed" || { echo "  [FAIL] stale text"; rc=1; }
    rm -rf "$tmpd"
    echo "V199e137 result: $(test "$rc" -eq 0 && echo PASS || echo FAIL)"
    return "$rc"
}


#==============================================================================
# V199e137 FINAL AUDIT CORRECTION 2
# - detect policy-routing/global-WARP changes, not only default-route changes
# - preserve direct VPS IPv4 and reject CN WARP exits
# - make --self-test non-mutating (no modprobe)
# - make per-interface IPv6 enforcement fail-safe
#==============================================================================

_e136_is_ipv4() {
    awk -F. 'NF==4{for(i=1;i<=4;i++)if($i!~/^[0-9]+$/||$i<0||$i>255)exit 1;exit 0}{exit 1}' <<<"${1:-}"
}

_e136_direct_ipv4() {
    local ip="" n
    for n in 1 2; do
        ip=$(curl -4 -fsS --noproxy '*' --connect-timeout 3 --max-time 8 https://api.ipify.org 2>/dev/null | tr -d '\r\n' || true)
        _e136_is_ipv4 "$ip" && { printf '%s\n' "$ip"; return 0; }
        ip=$(curl -4 -fsS --noproxy '*' --connect-timeout 3 --max-time 8 https://ifconfig.me/ip 2>/dev/null | tr -d '\r\n' || true)
        _e136_is_ipv4 "$ip" && { printf '%s\n' "$ip"; return 0; }
        sleep 1
    done
    return 1
}

_e136_route_guard_snapshot() {
    local ssh_ip=""
    declare -F _e135_current_ssh_ip >/dev/null 2>&1 && ssh_ip=$(_e135_current_ssh_ip 2>/dev/null || true)
    {
        echo '[default]'
        ip -4 route show default 2>/dev/null | LC_ALL=C sort
        echo '[rules]'
        ip -4 rule show 2>/dev/null | sed 's/[[:space:]]\+/ /g' | LC_ALL=C sort
        if _e136_is_ipv4 "$ssh_ip"; then
            echo '[ssh-route]'
            ip -4 route get "$ssh_ip" 2>/dev/null | head -n1 | sed 's/[[:space:]]\+/ /g'
        fi
    }
}

_e136_warp_proxy_ready() {
    local trace
    command -v warp-cli >/dev/null 2>&1 || return 1
    _e136_warp_listener_ok || return 1
    trace=$(_e136_warp_trace) || return 1
    grep -Eq '^warp=(on|plus)$' <<<"$trace"
}

_e136_warp_connect_local_proxy() {
    local before_guard after_guard before_ip="" after_ip="" svc trace loc warp_state
    before_guard=$(_e136_route_guard_snapshot)
    test -n "$before_guard" || { error "无法建立IPv4路由安全基线，拒绝启动WARP。"; return 1; }
    before_ip=$(_e136_direct_ipv4 2>/dev/null || true)
    svc=$(_e136_warp_service_name)
    systemctl enable --now "$svc" >/dev/null 2>&1 || return 1
    _e136_warp_register || { error "WARP设备注册失败。"; return 1; }
    _e136_warp_set_masque || { error "无法把WARP隧道协议设为MASQUE。"; return 1; }
    _e136_warp_set_proxy_port || { error "当前warp-cli不支持设置本地代理端口。"; return 1; }
    _e136_warp_set_proxy_mode || {
        error "Local proxy模式未获允许。请在Cloudflare Zero Trust设备配置中选择Local proxy与MASQUE后重试。"
        return 1
    }
    _e136_warp_cli connect >/dev/null 2>&1 || return 1
    sleep 4
    after_guard=$(_e136_route_guard_snapshot)
    after_ip=$(_e136_direct_ipv4 2>/dev/null || true)
    if test "$before_guard" != "$after_guard" || { test -n "$before_ip" && test "$before_ip" != "$after_ip"; }; then
        error "WARP改变了IPv4策略路由、SSH回程或VPS直连出口；立即断开。"
        _e136_warp_cli disconnect >/dev/null 2>&1 || true
        sleep 1
        return 1
    fi
    if ! _e136_warp_listener_ok; then
        error "WARP未仅监听127.0.0.1:$E136_WARP_PORT；立即断开。"
        _e136_warp_cli disconnect >/dev/null 2>&1 || true
        return 1
    fi
    trace=$(_e136_warp_trace 2>/dev/null || true)
    warp_state=$(awk -F= '$1=="warp"{print $2}' <<<"$trace")
    loc=$(awk -F= '$1=="loc"{print toupper($2)}' <<<"$trace")
    if ! [[ "$warp_state" =~ ^(on|plus)$ ]]; then
        error "本地代理没有返回有效WARP出口；立即断开。"
        _e136_warp_cli disconnect >/dev/null 2>&1 || true
        return 1
    fi
    if test "$loc" = CN; then
        error "Cloudflare报告WARP出口仍位于CN，不能解决Google/Meta送中；立即断开。"
        _e136_warp_cli disconnect >/dev/null 2>&1 || true
        return 1
    fi
    return 0
}

_e136_warp_health_check() {
    local route_enabled managed before_guard before_ip after_guard after_ip
    mkdir -p "$(dirname "$E136_WARP_LOG")" 2>/dev/null || true
    route_enabled=$(sed -n 's/^route_enabled=//p' "$E136_WARP_STATE" 2>/dev/null | head -n1); route_enabled=${route_enabled:-0}
    managed=$(sed -n 's/^managed_by=//p' "$E136_WARP_STATE" 2>/dev/null | head -n1)
    test "$route_enabled" = 1 && test "$managed" = e136 || return 0
    before_guard=$(_e136_route_guard_snapshot)
    before_ip=$(_e136_direct_ipv4 2>/dev/null || true)
    if _e136_warp_proxy_ready; then
        echo "[$(date -Is)] OK local proxy 127.0.0.1:$E136_WARP_PORT" >> "$E136_WARP_LOG"
        return 0
    fi
    echo "[$(date -Is)] WARN proxy unhealthy; fail-closed reconnect" >> "$E136_WARP_LOG"
    if _e136_warp_connect_local_proxy; then
        after_guard=$(_e136_route_guard_snapshot)
        after_ip=$(_e136_direct_ipv4 2>/dev/null || true)
        if test "$before_guard" = "$after_guard" && { test -z "$before_ip" || test "$before_ip" = "$after_ip"; } && _e136_warp_proxy_ready; then
            echo "[$(date -Is)] RECOVERED" >> "$E136_WARP_LOG"
            return 0
        fi
    fi
    _e136_warp_cli disconnect >/dev/null 2>&1 || true
    echo "[$(date -Is)] FAIL; disconnected to protect IPv4 route/policy" >> "$E136_WARP_LOG"
    return 1
}

_e136_warp_status() {
    local route_enabled profile trace direct_ip warp_ip loc colo mode listener="DOWN" managed
    route_enabled=$(sed -n 's/^route_enabled=//p' "$E136_WARP_STATE" 2>/dev/null | head -n1); route_enabled=${route_enabled:-0}
    profile=$(sed -n 's/^profile=//p' "$E136_WARP_STATE" 2>/dev/null | head -n1); profile=${profile:-none}
    managed=$(sed -n 's/^managed_by=//p' "$E136_WARP_STATE" 2>/dev/null | head -n1); managed=${managed:-no}
    _e136_warp_listener_ok && listener="127.0.0.1:$E136_WARP_PORT" || true
    direct_ip=$(_e136_direct_ipv4 2>/dev/null || echo unavailable)
    trace=$(_e136_warp_trace 2>/dev/null || true)
    warp_ip=$(awk -F= '$1=="ip"{print $2}' <<<"$trace"); warp_ip=${warp_ip:-unavailable}
    loc=$(awk -F= '$1=="loc"{print $2}' <<<"$trace"); loc=${loc:-unknown}
    colo=$(awk -F= '$1=="colo"{print $2}' <<<"$trace"); colo=${colo:-unknown}
    mode=$(command -v warp-cli >/dev/null 2>&1 && _e136_warp_cli settings 2>/dev/null | grep -Ei 'mode|service|proxy|protocol' | xargs echo || echo not-installed)
    title "V199e137：WARP定向分流状态"
    printf '  %-28s %s\n' "客户端" "$(command -v warp-cli >/dev/null 2>&1 && echo installed || echo not-installed)"
    printf '  %-28s %s\n' "E136管理" "$managed"
    printf '  %-28s %s\n' "本地代理" "$listener"
    printf '  %-28s %s\n' "Xray分流" "enabled=$route_enabled profile=$profile"
    printf '  %-28s %s\n' "VPS原始IPv4" "$direct_ip"
    printf '  %-28s %s\n' "WARP出口IPv4" "$warp_ip"
    printf '  %-28s %s\n' "Cloudflare loc/colo" "$loc/$colo"
    printf '  %-28s %s\n' "warp-cli模式" "$mode"
    printf '  %-28s %s\n' "默认IPv4路由" "$(_e136_warp_route4 | xargs echo)"
    printf '  %-28s %s\n' "IPv6关闭" "$(sysctl -n net.ipv6.conf.all.disable_ipv6 2>/dev/null || echo unsupported)"
    test "${loc^^}" != CN || warn "当前WARP出口仍被Cloudflare判为CN，不建议启用Google/Meta分流。"
    if test "$route_enabled" = 1 && test -s "$CONFIG"; then
        echo "  Xray规则："
        jq -r --arg w "$E136_WARP_TAG" --arg b "$E136_WARP_BLOCK_TAG" '.routing.rules[]?|select(.outboundTag==$w or .outboundTag==$b)|"    network=\(.network) outbound=\(.outboundTag) domains=\(.domain|length)"' "$CONFIG" 2>/dev/null || true
    fi
}

# Pure candidate generation: no module loads during --self-test/read-only analysis.
_e136_network_candidate() {
    local profile="${1:-balanced}" out="$2" cc qdisc
    if sysctl -n net.ipv4.tcp_available_congestion_control 2>/dev/null | grep -qw bbr; then cc=bbr
    elif sysctl -n net.ipv4.tcp_available_congestion_control 2>/dev/null | grep -qw cubic; then cc=cubic
    else cc=$(sysctl -n net.ipv4.tcp_congestion_control 2>/dev/null || echo reno); fi
    qdisc=fq
    {
        echo "# Managed exclusively by ex199e136; profile=$profile; generated=$(date -Is 2>/dev/null || date)"
        echo "net.core.default_qdisc = $qdisc"
        echo "net.ipv4.tcp_congestion_control = $cc"
        echo "net.ipv4.tcp_mtu_probing = 1"
        echo "net.ipv4.tcp_slow_start_after_idle = 0"
        echo "net.ipv4.tcp_notsent_lowat = 131072"
        case "$profile" in
            low)
                echo "net.ipv4.tcp_limit_output_bytes = 524288"; echo "net.core.somaxconn = 4096"; echo "net.core.netdev_max_backlog = 2048"
                echo "net.core.rmem_max = 16777216"; echo "net.core.wmem_max = 16777216"
                echo "net.ipv4.tcp_rmem = 4096 131072 16777216"; echo "net.ipv4.tcp_wmem = 4096 16384 16777216" ;;
            throughput)
                echo "net.ipv4.tcp_limit_output_bytes = 4194304"; echo "net.core.somaxconn = 16384"; echo "net.core.netdev_max_backlog = 8192"
                echo "net.core.rmem_max = 97108868"; echo "net.core.wmem_max = 97108868"
                echo "net.ipv4.tcp_rmem = 4096 7990577 97108868"; echo "net.ipv4.tcp_wmem = 4096 7990577 97108868" ;;
            *)
                echo "net.ipv4.tcp_limit_output_bytes = 1048576"; echo "net.core.somaxconn = 8192"; echo "net.core.netdev_max_backlog = 4096"
                echo "net.core.rmem_max = 56699928"; echo "net.core.wmem_max = 56699928"
                echo "net.ipv4.tcp_rmem = 4096 131072 56699928"; echo "net.ipv4.tcp_wmem = 4096 16384 56699928" ;;
        esac
        echo "net.ipv4.tcp_fastopen = 1"
        echo "net.ipv4.tcp_ecn = 2"
        echo "net.ipv4.ip_local_port_range = 10240 65535"
        echo "net.ipv6.conf.all.disable_ipv6 = 1"
        echo "net.ipv6.conf.default.disable_ipv6 = 1"
        echo "net.ipv6.conf.lo.disable_ipv6 = 1"
    } > "$out"
}

_e136_network_apply() {
    local state_file iface_file
    state_file=$(mktemp /tmp/e136-network-services.XXXXXX) || return 1
    _e136_service_state_snapshot "$state_file" || { rm -f "$state_file"; return 1; }
    # Check writability before changing persistent or runtime state.
    for iface_file in /proc/sys/net/ipv6/conf/*/disable_ipv6; do
        test -e "$iface_file" || continue
        test -w "$iface_file" || { error "IPv6 sysctl不可写：$iface_file"; rm -f "$state_file"; return 1; }
    done
    modprobe tcp_bbr >/dev/null 2>&1 || true
    modprobe sch_fq >/dev/null 2>&1 || true
    if ! _e136_network_apply_base_audited "$@"; then
        _e136_service_state_restore "$state_file"
        rm -f "$state_file"
        return 1
    fi
    for iface_file in /proc/sys/net/ipv6/conf/*/disable_ipv6; do
        test -e "$iface_file" || continue
        printf '1\n' > "$iface_file" 2>/dev/null || warn "无法单独写入：$iface_file；all.disable_ipv6已为1。"
    done
    rm -f "$state_file"
    return 0
}

_e136_self_test() {
    local rc=0 tmpd net keys src stripped domains sample enabled disabled merged body oldhint
    tmpd=$(mktemp -d /tmp/e136-selftest.XXXXXX) || return 1
    echo "V199e137 release gate:"
    test "$SCRIPT_VERSION" = 199e136 && echo "  [PASS] version" || { echo "  [FAIL] version"; rc=1; }
    net="$tmpd/network.conf"; _e136_network_candidate balanced "$net" || rc=1
    grep -qx 'net.ipv4.tcp_notsent_lowat = 131072' "$net" && grep -qx 'net.ipv6.conf.all.disable_ipv6 = 1' "$net" && grep -qx 'net.ipv6.conf.default.disable_ipv6 = 1' "$net" && echo "  [PASS] IPv4-only network candidate" || { echo "  [FAIL] network candidate"; rc=1; }
    body=$(declare -f _e136_network_candidate); [[ "$body" != *'modprobe'* ]] && echo "  [PASS] read-only candidate generation" || { echo "  [FAIL] candidate mutates"; rc=1; }
    keys="$tmpd/keys"; src="$tmpd/src.conf"; stripped="$tmpd/stripped.conf"; _e136_network_keys > "$keys"
    printf '%s\n' 'net.ipv4.tcp_notsent_lowat = 16384' 'foo.bar = 1' 'net.ipv6.conf.all.disable_ipv6 = 0' > "$src"
    _e136_strip_sysctl_file "$keys" "$src" "$stripped" || rc=1
    test "$(cat "$stripped")" = 'foo.bar = 1' && echo "  [PASS] duplicate sysctl behavior" || { echo "  [FAIL] sysctl strip"; rc=1; }
    domains=$(_e136_warp_domains_json google-meta-core) || rc=1
    test "$(jq 'length' <<<"$domains")" -ge 20 && test "$(jq 'length == (unique|length)' <<<"$domains")" = true && echo "  [PASS] WARP domain profile" || { echo "  [FAIL] WARP domains"; rc=1; }
    sample="$tmpd/sample.json"; enabled="$tmpd/enabled.json"; disabled="$tmpd/disabled.json"
    printf '%s\n' '{"dns":{"servers":["1.1.1.1"]},"outbounds":[{"tag":"direct","protocol":"freedom","settings":{}}],"routing":{"rules":[]}}' > "$sample"
    _e136_warp_config_build google-meta-core true "$enabled" "$sample" || rc=1
    jq -e --arg w "$E136_WARP_TAG" --arg b "$E136_WARP_BLOCK_TAG" '([.outbounds[]|select(.tag==$w)]|length)==1 and ([.outbounds[]|select(.tag==$b)]|length)==1 and ([.routing.rules[]|select(.outboundTag==$w)]|length)==1 and ([.routing.rules[]|select(.outboundTag==$b)]|length)==1 and .dns.queryStrategy=="UseIPv4"' "$enabled" >/dev/null && echo "  [PASS] Xray WARP route build" || { echo "  [FAIL] WARP config build"; rc=1; }
    _e136_warp_config_build disabled false "$disabled" "$enabled" || rc=1
    jq -e --arg w "$E136_WARP_TAG" --arg b "$E136_WARP_BLOCK_TAG" '([.outbounds[]|select(.tag==$w or .tag==$b)]|length)==0 and ([.routing.rules[]|select(.outboundTag==$w or .outboundTag==$b)]|length)==0' "$disabled" >/dev/null && echo "  [PASS] Xray WARP route removal" || { echo "  [FAIL] WARP removal"; rc=1; }
    test "$(cpu_mask_all 64)" = 'ffffffff,ffffffff' && echo "  [PASS] 64-core cpumask" || { echo "  [FAIL] cpumask"; rc=1; }
    merged=$(_e136_merge_ignoreip_values '10.0.0.0/8 192.168.1.5' '203.0.113.9')
    [[ "$merged" == *'10.0.0.0/8'* && "$merged" == *'192.168.1.5'* && "$merged" == *'203.0.113.9'* ]] && echo "  [PASS] Fail2ban ignoreip preservation" || { echo "  [FAIL] ignoreip merge"; rc=1; }
    body=$(declare -f _e136_warp_connect_local_proxy)
    [[ "$body" == *'_e136_route_guard_snapshot'* && "$body" == *'_e136_direct_ipv4'* && "$body" == *'loc" = CN'* && "$body" == *'disconnect'* ]] && echo "  [PASS] WARP route/policy/CN fail-closed" || { echo "  [FAIL] WARP anti-lockout"; rc=1; }
    body=$(declare -f _e136_warp_health_check)
    [[ "$body" == *'_e136_warp_connect_local_proxy'* && "$body" == *'managed'* && "$body" == *'route_enabled'* ]] && echo "  [PASS] WARP health fail-closed" || { echo "  [FAIL] WARP health guard"; rc=1; }
    body=$(declare -f _e136_network_apply)
    [[ "$body" == *'_e136_service_state_snapshot'* && "$body" == *'_e136_service_state_restore'* ]] && echo "  [PASS] network service rollback" || { echo "  [FAIL] network service rollback"; rc=1; }
    body=$(declare -f hot_update_from_legacy)
    [[ "$body" == *'_e135_system_snapshot'* && "$body" == *'_e136_network_apply balanced force'* && "$body" == *'net.ipv6.conf.all.disable_ipv6'* ]] && echo "  [PASS] E136 hot-update chain" || { echo "  [FAIL] hot-update"; rc=1; }
    body=$(declare -f _e136_hot_update_preflight)
    [[ "$body" != *'apt-get '* && "$body" != *'cp -'* && "$body" != *'systemctl enable'* && "$body" != *'systemctl restart'* ]] && echo "  [PASS] non-mutating hot-update preflight" || { echo "  [FAIL] preflight mutates"; rc=1; }
    oldhint="ex199e""131"; test "$(grep -c "$oldhint" "$SCRIPT_PATH" 2>/dev/null || true)" = 0 && echo "  [PASS] stale version text removed" || { echo "  [FAIL] stale text"; rc=1; }
    rm -rf "$tmpd"
    echo "V199e137 result: $(test "$rc" -eq 0 && echo PASS || echo FAIL)"
    return "$rc"
}


