# V199e137 FINAL AUDIT CORRECTION 3
# - XanMod config fallback (/boot -> /proc/config.gz -> defconfig)
# - Ring Buffer becomes an independent verified service
# - MSS Clamp records ON only after real rule/service verification
#==============================================================================

eval "$(declare -f _e135_system_paths | sed '1s/^_e135_system_paths[[:space:]]*()/_e135_system_paths_base_e136c3 ()/')"
_e135_system_paths() {
    _e135_system_paths_base_e136c3
    cat <<EOF_E136_C3_PATHS
/etc/systemd/system/xray-ring-e136.service
/usr/local/bin/xray-ring-e136.sh
/etc/systemd/system/xray-mss-clamp-e88.service
/usr/local/bin/xray-mss-clamp-e88.sh
EOF_E136_C3_PATHS
}

apply_ring_max_adaptive_default() {
    local iface max_rx max_tx old_rx old_tx actual_rx actual_tx mode="rx" script unit failed=0
    iface=$(_get_default_iface 2>/dev/null || ip -4 route get 1.1.1.1 2>/dev/null | awk '{print $5; exit}' || true)
    test -n "$iface" || { error "无法识别默认IPv4出口网卡。"; return 1; }
    command -v ethtool >/dev/null 2>&1 || { error "缺少ethtool。"; return 1; }
    ethtool -g "$iface" >/dev/null 2>&1 || { warn "网卡 $iface 不支持Ring Buffer设置。"; return 1; }
    max_rx=$(_ring_max_rx_e52 "$iface"); max_tx=$(_ring_max_tx_e52 "$iface")
    old_rx=$(_ring_cur_rx_e52 "$iface"); old_tx=$(_ring_cur_tx_e52 "$iface")
    [[ "$max_rx" =~ ^[0-9]+$ && "$old_rx" =~ ^[0-9]+$ ]] || { error "无法解析RX Ring值。"; return 1; }
    if [[ "$max_tx" =~ ^[0-9]+$ && "$old_tx" =~ ^[0-9]+$ ]] && ethtool -G "$iface" rx "$max_rx" tx "$max_tx" >/dev/null 2>&1; then
        mode="both"
    else
        ethtool -G "$iface" rx "$max_rx" >/dev/null 2>&1 || { error "RX Ring设置失败。"; return 1; }
    fi
    actual_rx=$(_ring_cur_rx_e52 "$iface"); actual_tx=$(_ring_cur_tx_e52 "$iface")
    test "$actual_rx" = "$max_rx" || { error "RX Ring读回不一致：目标=$max_rx 实际=${actual_rx:-unknown}"; ethtool -G "$iface" rx "$old_rx" >/dev/null 2>&1 || true; return 1; }
    script=/usr/local/bin/xray-ring-e136.sh
    unit=/etc/systemd/system/xray-ring-e136.service
    if test "$mode" = both; then
        cat > "$script" <<EOF_E136_RING_SCRIPT
#!/usr/bin/env bash
set -euo pipefail
export PATH="/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin"
IFACE="$iface"
ethtool -G "\$IFACE" rx "$actual_rx" tx "$actual_tx"
EOF_E136_RING_SCRIPT
    else
        cat > "$script" <<EOF_E136_RING_SCRIPT
#!/usr/bin/env bash
set -euo pipefail
export PATH="/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin"
IFACE="$iface"
ethtool -G "\$IFACE" rx "$actual_rx"
EOF_E136_RING_SCRIPT
    fi
    chmod 0755 "$script" || failed=1
    if test "$failed" = 0; then
        cat > "$unit" <<EOF_E136_RING_UNIT
[Unit]
Description=Xray E136 independent Ring Buffer restore
After=network-online.target
Wants=network-online.target

[Service]
Type=oneshot
ExecStart=$script
RemainAfterExit=yes

[Install]
WantedBy=multi-user.target
EOF_E136_RING_UNIT
        systemctl daemon-reload >/dev/null 2>&1 || failed=1
        test "$failed" != 0 || systemctl enable --now xray-ring-e136.service >/dev/null 2>&1 || failed=1
        test "$failed" != 0 || systemctl is-active --quiet xray-ring-e136.service || failed=1
    fi
    if test "$failed" != 0; then
        error "Ring独立恢复服务验证失败，恢复原运行值。"
        if [[ "$old_tx" =~ ^[0-9]+$ ]]; then ethtool -G "$iface" rx "$old_rx" tx "$old_tx" >/dev/null 2>&1 || ethtool -G "$iface" rx "$old_rx" >/dev/null 2>&1 || true
        else ethtool -G "$iface" rx "$old_rx" >/dev/null 2>&1 || true; fi
        systemctl disable --now xray-ring-e136.service >/dev/null 2>&1 || true
        rm -f "$unit" "$script" 2>/dev/null || true
        systemctl daemon-reload >/dev/null 2>&1 || true
        return 1
    fi
    mkdir -p "$CONFIG_DIR" "$FLAGS_DIR" || return 1
    printf '%s\n' "$actual_rx" > "$CONFIG_DIR/ring_target_rx.txt"
    printf '%s\n' "${actual_tx:-$old_tx}" > "$CONFIG_DIR/ring_target_tx.txt"
    printf '%s\n' "$mode" > "$CONFIG_DIR/ring_mode.txt"
    rm -f "$FLAGS_DIR/ring_low_latency" 2>/dev/null || true
    touch "$FLAGS_DIR/ring_max_adaptive"
    info "Ring独立优化已验证：$iface RX=$actual_rx TX=${actual_tx:-unchanged} mode=$mode（原RX=$old_rx TX=${old_tx:-?}）。"
}

_e88_mss_clamp_on() {
    local snapshot="" script=/usr/local/bin/xray-mss-clamp-e88.sh unit=/etc/systemd/system/xray-mss-clamp-e88.service failed=0
    command -v iptables >/dev/null 2>&1 || { error "缺少iptables，不能启用MSS Clamp。"; return 1; }
    command -v iptables-save >/dev/null 2>&1 && snapshot=$(_e118_mktemp mss-before.rules) || true
    test -z "$snapshot" || iptables-save > "$snapshot" 2>/dev/null || snapshot=""
    cat > "$script" <<'EOF_E136_MSS_SCRIPT'
#!/usr/bin/env bash
set -euo pipefail
export PATH="/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin"
modprobe iptable_mangle >/dev/null 2>&1 || true
modprobe xt_TCPMSS >/dev/null 2>&1 || true
iptables -w 5 -t mangle -N XRAY_MSS_CLAMP 2>/dev/null || true
iptables -w 5 -t mangle -F XRAY_MSS_CLAMP
iptables -w 5 -t mangle -A XRAY_MSS_CLAMP -p tcp -m tcp --tcp-flags SYN,RST SYN -j TCPMSS --clamp-mss-to-pmtu
iptables -w 5 -t mangle -C POSTROUTING -j XRAY_MSS_CLAMP 2>/dev/null || iptables -w 5 -t mangle -A POSTROUTING -j XRAY_MSS_CLAMP
iptables -w 5 -t mangle -C POSTROUTING -j XRAY_MSS_CLAMP
iptables -w 5 -t mangle -C XRAY_MSS_CLAMP -p tcp -m tcp --tcp-flags SYN,RST SYN -j TCPMSS --clamp-mss-to-pmtu
EOF_E136_MSS_SCRIPT
    chmod 0755 "$script" || failed=1
    if test "$failed" = 0; then
        cat > "$unit" <<EOF_E136_MSS_UNIT
[Unit]
Description=Xray E136 verified IPv4 MSS Clamp restore
After=network-online.target
Wants=network-online.target

[Service]
Type=oneshot
ExecStart=$script
RemainAfterExit=yes

[Install]
WantedBy=multi-user.target
EOF_E136_MSS_UNIT
        systemctl daemon-reload >/dev/null 2>&1 || failed=1
        test "$failed" != 0 || systemctl enable --now xray-mss-clamp-e88.service >/dev/null 2>&1 || failed=1
        test "$failed" != 0 || systemctl is-active --quiet xray-mss-clamp-e88.service || failed=1
        test "$failed" != 0 || iptables -w 5 -t mangle -C POSTROUTING -j XRAY_MSS_CLAMP >/dev/null 2>&1 || failed=1
        test "$failed" != 0 || iptables -w 5 -t mangle -C XRAY_MSS_CLAMP -p tcp -m tcp --tcp-flags SYN,RST SYN -j TCPMSS --clamp-mss-to-pmtu >/dev/null 2>&1 || failed=1
    fi
    if test "$failed" != 0; then
        error "MSS Clamp应用/读回失败，恢复原防火墙。"
        test -s "$snapshot" && command -v iptables-restore >/dev/null 2>&1 && iptables-restore < "$snapshot" || true
        systemctl disable --now xray-mss-clamp-e88.service >/dev/null 2>&1 || true
        rm -f "$unit" "$script" 2>/dev/null || true
        systemctl daemon-reload >/dev/null 2>&1 || true
        return 1
    fi
    echo "ON" > "$E88_MSS_STATE_FILE"
    info "MSS Clamp已启用，规则与开机恢复服务均通过读回验证。"
}

_e135_xanmod_source_build() {
    local mode="${1:-}" confirm work src log threads actual kver image header image_pkg header_pkg cleanup failed=0 dkms_before config_source
    title "V199e137：XanMod源码、云VPS配置保护与Debian包事务"
    warn "这是使用XanMod源码树的云VPS自定义构建；不会自动改变GRUB_DEFAULT或重启。"
    warn "必须先创建VPS快照，并确保VNC/救援控制台可用。"
    _e135_kernel_precheck || return 1
    _e135_xanmod_choose_tag "$mode" || { error "无法选择或验证Tag。"; return 1; }
    read -rp "输入 BUILD-XANMOD-$LATEST_TAG 确认: " confirm || true
    test "$confirm" = "BUILD-XANMOD-$LATEST_TAG" || return 0
    _e131_install_kernel_build_deps || return 1
    mkdir -p "$E131_KERNEL_BUILD_ROOT" || return 1
    work="$E131_KERNEL_BUILD_ROOT/${LATEST_TAG}-$(date +%Y%m%d_%H%M%S)"; src="$work/src"; log="$work/build.log"
    mkdir -p "$src" || return 1
    dkms_before="$work/dkms.before"; command -v dkms >/dev/null 2>&1 && dkms status > "$dkms_before" 2>/dev/null || : > "$dkms_before"
    git -C "$src" init -q && git -C "$src" remote add origin https://gitlab.com/xanmod/linux.git || return 1
    git -C "$src" fetch --depth=1 origin "refs/tags/$LATEST_TAG:refs/tags/$LATEST_TAG" 2>&1 | tee "$work/fetch.log" || return 1
    git -C "$src" checkout -q --detach "$LATEST_TAG" || return 1
    actual=$(git -C "$src" rev-parse HEAD); test "$actual" = "$E131_XANMOD_EXPECTED_COMMIT" || { error "Tag commit不一致。"; return 1; }
    cd "$src" || return 1
    make mrproper >/dev/null || return 1
    if test -s "/boot/config-$(uname -r)"; then
        cp -f "/boot/config-$(uname -r)" .config || return 1; config_source="/boot/config-$(uname -r)"
    elif test -r /proc/config.gz && command -v zcat >/dev/null 2>&1; then
        zcat /proc/config.gz > .config || return 1; config_source=/proc/config.gz
    else
        make defconfig >/dev/null || return 1; config_source=x86_64_defconfig
    fi
    make olddefconfig >/dev/null || return 1
    _e135_kernel_config_guard "$src" || return 1
    make olddefconfig >/dev/null || return 1
    _e135_kernel_config_verify "$src" || { error "最终内核配置未通过云VPS启动驱动审计。"; return 1; }
    kver=$(make -s kernelrelease); test -n "$kver" || return 1
    cp -f .config "$work/config.final"
    threads=$(_e135_kernel_threads)
    info "Tag=$LATEST_TAG commit=$actual kernelrelease=$kver threads=$threads config_source=$config_source"
    make -j"$threads" bindeb-pkg 2>&1 | tee "$log" || { error "bindeb-pkg失败：$log"; return 1; }
    image=$(find "$work" -maxdepth 1 -type f -name "linux-image-*${kver}*.deb" ! -name '*dbg*' | sort | head -n1)
    header=$(find "$work" -maxdepth 1 -type f -name "linux-headers-*${kver}*.deb" | sort | head -n1)
    test -s "$image" && test -s "$header" || { error "缺少image或headers包。"; return 1; }
    dpkg-deb --info "$image" >/dev/null && dpkg-deb --info "$header" >/dev/null || return 1
    image_pkg=$(dpkg-deb -f "$image" Package); header_pkg=$(dpkg-deb -f "$header" Package)
    dpkg -i "$header" "$image" || failed=1
    if test "$failed" = 0 && command -v dkms >/dev/null 2>&1; then dkms autoinstall -k "$kver" || failed=1; fi
    test "$failed" != 0 || test -s "/boot/vmlinuz-$kver" || failed=1
    test "$failed" != 0 || test -d "/lib/modules/$kver" || failed=1
    if test "$failed" = 0 && ! test -s "/boot/initrd.img-$kver" && ! test -s "/boot/initramfs-${kver}.img"; then
        if command -v update-initramfs >/dev/null 2>&1; then update-initramfs -c -k "$kver" || failed=1
        elif command -v dracut >/dev/null 2>&1; then dracut --force "/boot/initramfs-${kver}.img" "$kver" || failed=1
        else failed=1; fi
    fi
    test "$failed" != 0 || _kernel_pre_reboot_verify_e52 "$kver" || failed=1
    if test "$failed" != 0; then
        error "新内核安装后校验失败，卸载本次新增包并保留构建记录。"
        _e135_remove_kernel_packages "$image_pkg" "$header_pkg"
        return 1
    fi
    {
        echo "tag=$LATEST_TAG"; echo "commit=$actual"; echo "kernelrelease=$kver"; echo "config_source=$config_source"
        echo "image=$image"; echo "headers=$header"; echo "threads=$threads"; echo "installed=$(date -Is)"
    } > "$work/manifest.txt"
    info "源码编译、打包、DKMS/initramfs/GRUB校验通过：$kver"
    warn "当前默认内核未被修改；请确认控制台后再自行选择重启。"
    read -rp "删除源码树，仅保留deb/日志/manifest？[y/N]: " cleanup || true
    [[ "$cleanup" =~ ^[yY]$ ]] && rm -rf -- "$src"
}

# Supplement the existing gate without repeating all base checks.
eval "$(declare -f _e136_self_test | sed '1s/^_e136_self_test[[:space:]]*()/_e136_self_test_base_e136c3 ()/')"
_e136_self_test() {
    local rc=0 body
    _e136_self_test_base_e136c3 || rc=1
    echo "V199e137 supplemental gate:"
    body=$(declare -f _e135_xanmod_source_build)
    [[ "$body" == *'/proc/config.gz'* && "$body" == *'make defconfig'* && "$body" == *'config_source'* ]] && echo "  [PASS] XanMod config fallback" || { echo "  [FAIL] XanMod config fallback"; rc=1; }
    body=$(declare -f apply_ring_max_adaptive_default)
    [[ "$body" == *'xray-ring-e136.service'* && "$body" != *'update_hw_boot_script'* && "$body" == *'actual_rx'* ]] && echo "  [PASS] independent Ring transaction" || { echo "  [FAIL] Ring transaction"; rc=1; }
    body=$(declare -f _e88_mss_clamp_on)
    [[ "$body" == *'iptables-restore'* && "$body" == *'systemctl is-active'* && "$body" == *'echo "ON"'* ]] && echo "  [PASS] verified MSS transaction" || { echo "  [FAIL] MSS transaction"; rc=1; }
    echo "V199e137 supplemental result: $(test "$rc" = 0 && echo PASS || echo FAIL)"
    return "$rc"
}

#==============================================================================
# V199e137 final convergence layer
# - semantic install-mode mapping is the single source of truth
# - WARP desired state must match Xray runtime configuration
# - boot restore services verify readback and remain repeatable
# - hot update uses explicit snapshot/apply/verify/rollback phases
#==============================================================================
readonly E137_VERSION="199e138"
readonly E137_DIR="$CONFIG_DIR/e137"
readonly E137_BACKUP_DIR="$E137_DIR/backups"
readonly E137_SELF_PATH="$SCRIPT_DIR/ex199e137.sh"
readonly E137_LATEST_PATH="$SCRIPT_DIR/ex199e_latest.sh"
readonly E137_WARP_STATE="$E137_DIR/warp-state.env"
readonly E137_WARP_PORT="40000"
readonly E137_WARP_TAG="warp-selective"
readonly E137_WARP_BLOCK_TAG="warp-selective-udp-block"
readonly E137_WARP_HEALTH_SERVICE="/etc/systemd/system/xray-warp-e137-health.service"
readonly E137_WARP_HEALTH_TIMER="/etc/systemd/system/xray-warp-e137-health.timer"
readonly E137_WARP_LOG="/var/log/xray/warp-e137.log"
readonly E137_INIT_SCRIPT="/usr/local/bin/xray-init-window-e137.sh"
readonly E137_INIT_SERVICE="/etc/systemd/system/xray-init-window-e137.service"
readonly E137_INIT_TIMER="/etc/systemd/system/xray-init-window-e137.timer"
readonly E137_OFFLOAD_SCRIPT="/usr/local/bin/xray-offload-e137.sh"
readonly E137_OFFLOAD_SERVICE="/etc/systemd/system/xray-offload-e137.service"
readonly E137_OFFLOAD_TIMER="/etc/systemd/system/xray-offload-e137.timer"
readonly E137_RPS_SCRIPT="/usr/local/bin/xray-rps-rfs-e137.sh"
readonly E137_RPS_SERVICE="/etc/systemd/system/xray-rps-rfs-e137.service"
readonly E137_RPS_TIMER="/etc/systemd/system/xray-rps-rfs-e137.timer"
readonly E137_TXQ_SCRIPT="/usr/local/bin/xray-txqueue-e137.sh"
readonly E137_TXQ_SERVICE="/etc/systemd/system/xray-txqueue-e137.service"
readonly E137_TXQ_TIMER="/etc/systemd/system/xray-txqueue-e137.timer"
readonly E137_RING_SCRIPT="/usr/local/bin/xray-ring-e137.sh"
readonly E137_RING_SERVICE="/etc/systemd/system/xray-ring-e137.service"
readonly E137_RING_TIMER="/etc/systemd/system/xray-ring-e137.timer"
readonly E137_MSS_TIMER="/etc/systemd/system/xray-mss-clamp-e137.timer"
E137_SEMANTIC_MODE=""

_e137_prepare() {
    mkdir -p "$E137_DIR" "$E137_BACKUP_DIR" "$SCRIPT_DIR" "$LOG_DIR" || return 1
}

_e137_pause() { local _p=""; read -rp "按 Enter 继续..." _p || true; }

#------------------------------------------------------------------------------
# Single mode map. Semantic mode is what the user sees; internal mode is the
# historical builder's mode number.
#------------------------------------------------------------------------------
_e137_mode_internal() {
    case "${1:-}" in
        1|reality) echo 1 ;;
        2|reality-ss2022) echo 4 ;;
        3|vlessenc) echo 2 ;;
        4|ss2022) echo 3 ;;
        *) return 1 ;;
    esac
}

_e137_mode_name() {
    case "${1:-}" in
        1) echo "VLESS Reality Vision" ;;
        2) echo "Reality Vision + SS2022" ;;
        3) echo "VLESSENC Vision" ;;
        4) echo "SS2022" ;;
        *) return 1 ;;
    esac
}

_e137_validate_semantic_config() {
    local file="$1" semantic="$2"
    jq -e --arg mode "$semantic" '
      def reality: [.inbounds[]? | select(.protocol=="vless" and (.streamSettings.security//"")=="reality")];
      def venc: [.inbounds[]? | select(.protocol=="vless" and (.settings.decryption//"none")!="none" and (.streamSettings.security//"none")=="none")];
      def ss: [.inbounds[]? | select(.protocol=="shadowsocks")];
      if $mode=="1" then (reality|length)==1 and (venc|length)==0 and (ss|length)==0
      elif $mode=="2" then (reality|length)==1 and (venc|length)==0 and (ss|length)==1
      elif $mode=="3" then (reality|length)==0 and (venc|length)==1 and (ss|length)==0
      elif $mode=="4" then (reality|length)==0 and (venc|length)==0 and (ss|length)==1
      else false end
    ' "$file" >/dev/null 2>&1
}

# Preserve the currently effective metadata writer, then correct version and
# record both semantic and historical internal mode atomically.
if declare -F _e118_write_generated_metadata >/dev/null 2>&1; then
    eval "$(declare -f _e118_write_generated_metadata | sed '1s/_e118_write_generated_metadata/_e137_metadata_base/')"
fi
_e118_write_generated_metadata() {
    local internal="${1:-}" semantic="${E137_SEMANTIC_MODE:-}" meta tmp
    _e137_metadata_base "$@" || return 1
    test -n "$semantic" || semantic="$internal"
    meta="${E77_NODE_META_FILE:-$CONFIG_DIR/node.meta}"
    tmp=$(_e118_mktemp node-meta-e137) || return 1
    {
        echo "version=$E137_VERSION"
        echo "mode_semantic=$semantic"
        echo "mode_internal=$internal"
        echo "remark=${REMARK_NAME:-xp-reality}"
        echo "created=${E77_CTIME:-$(date -Is 2>/dev/null || date)}"
        echo "vlessenc_profile=${E79_VLESSENC_PROFILE:-none}"
        echo "vlessenc_network=${E79_VLESSENC_NETWORK:-none}"
        echo "vlessenc_actual_tuning=${E79_VLESSENC_ACTUAL_TUNING:-none}"
    } > "$tmp" || return 1
    _e118_atomic_install "$tmp" "$meta" 0600 || return 1
    printf '%s\n' "$E137_VERSION" > "$SCRIPT_VERSION_FILE" || return 1
}

#------------------------------------------------------------------------------
# Three-target self-install transaction.
#------------------------------------------------------------------------------
_e137_install_self() {
    local tx t tmp failed=0
    test -f "$SCRIPT_PATH" || { error "当前脚本文件不存在：$SCRIPT_PATH"; return 1; }
    _e137_prepare || return 1
    tx="$E137_BACKUP_DIR/self-install-$(date +%Y%m%d_%H%M%S)-$$"
    mkdir -p "$tx" || return 1
    for t in "$SYMLINK" "$E137_SELF_PATH" "$E137_LATEST_PATH"; do
        _e135_snapshot_file "$t" "$tx/$(printf '%s' "$t" | sha256sum | awk '{print $1}')" || return 1
    done
    for t in "$SYMLINK" "$E137_SELF_PATH" "$E137_LATEST_PATH"; do
        mkdir -p "$(dirname "$t")" || { failed=1; break; }
        tmp="$(dirname "$t")/.e137.$(basename "$t").$$"
        install -m 0755 "$SCRIPT_PATH" "$tmp" || { failed=1; break; }
        mv -f -- "$tmp" "$t" || { rm -f -- "$tmp"; failed=1; break; }
    done
    if test "$failed" -ne 0; then
        error "脚本三个入口未能整体提交，恢复全部旧入口。"
        for t in "$SYMLINK" "$E137_SELF_PATH" "$E137_LATEST_PATH"; do
            _e135_restore_file "$t" "$tx/$(printf '%s' "$t" | sha256sum | awk '{print $1}')" || true
        done
        return 1
    fi
    hash -r 2>/dev/null || true
}
_e136_install_self() { _e137_install_self; }
_e118_install_self() { _e137_install_self; }

#------------------------------------------------------------------------------
# WARP state and Xray configuration are a single state machine.
#------------------------------------------------------------------------------
_e137_state_get() {
    local key="$1" def="${2:-}"
    local val
    val=$(sed -n "s/^${key}=//p" "$E137_WARP_STATE" 2>/dev/null | tail -n1)
    printf '%s\n' "${val:-$def}"
}

_e137_state_write() {
    local enabled="$1" profile="$2" tmp
    _e137_prepare || return 1
    tmp=$(_e118_mktemp warp-state-e137) || return 1
    {
        echo "managed_by=e137"
        echo "route_enabled=$enabled"
        echo "profile=$profile"
        echo "port=$E137_WARP_PORT"
        echo "updated=$(date -Is 2>/dev/null || date)"
    } > "$tmp" || return 1
    install -m 0600 "$tmp" "$E137_WARP_STATE" || return 1
}

_e137_warp_domains_json() { _e136_warp_domains_json "$@"; }

_e137_warp_config_build() {
    local profile="$1" enable="$2" out="$3" src="${4:-$CONFIG}" domains
    test -s "$src" || { error "Xray配置不存在：$src"; return 1; }
    domains=$(_e137_warp_domains_json "$profile") || return 1
    jq --arg warp "$E137_WARP_TAG" --arg block "$E137_WARP_BLOCK_TAG" \
       --arg oldw "${E136_WARP_TAG:-warp-e136}" --arg oldb "${E136_WARP_BLOCK_TAG:-warp-block-udp-e136}" \
       --argjson port "$E137_WARP_PORT" --argjson domains "$domains" --argjson enable "$enable" '
      .outbounds = (.outbounds // []) |
      .routing = (.routing // {}) |
      .routing.rules = (.routing.rules // []) |
      .outbounds |= map(select(((.tag // "") != $warp) and ((.tag // "") != $block) and ((.tag // "") != $oldw) and ((.tag // "") != $oldb))) |
      .routing.rules |= map(select(((.outboundTag // "") != $warp) and ((.outboundTag // "") != $block) and ((.outboundTag // "") != $oldw) and ((.outboundTag // "") != $oldb))) |
      .outbounds |= map(if .protocol == "freedom" then .settings = ((.settings // {}) + {targetStrategy:"UseIPv4"}) else . end) |
      if (.dns|type) == "object" then .dns.queryStrategy = "UseIPv4" else . end |
      if $enable then
        .outbounds += [
          {tag:$warp,protocol:"socks",settings:{address:"127.0.0.1",port:$port}},
          {tag:$block,protocol:"blackhole",settings:{response:{type:"none"}}}
        ] |
        .routing.rules = [
          {type:"field",network:"udp",domain:$domains,outboundTag:$block},
          {type:"field",network:"tcp",domain:$domains,outboundTag:$warp}
        ] + .routing.rules
      else . end
    ' "$src" > "$out"
}

_e137_warp_config_integrity() {
    local profile="${1:-$(_e137_state_get profile google-meta-core)}" domains
    test -s "$CONFIG" || return 1
    domains=$(_e137_warp_domains_json "$profile") || return 1
    jq -e --arg w "$E137_WARP_TAG" --arg b "$E137_WARP_BLOCK_TAG" --argjson port "$E137_WARP_PORT" --argjson domains "$domains" '
      ([.outbounds[]? | select(.tag==$w and .protocol=="socks" and .settings.address=="127.0.0.1" and .settings.port==$port)]|length)==1 and
      ([.outbounds[]? | select(.tag==$b and .protocol=="blackhole")]|length)==1 and
      ([.routing.rules[]? | select(.outboundTag==$w and .network=="tcp" and (.domain|type)=="array" and (.domain|length)>0)]|length)==1 and
      ([.routing.rules[]? | select(.outboundTag==$b and .network=="udp" and (.domain|type)=="array" and (.domain|length)>0)]|length)==1
    ' "$CONFIG" >/dev/null 2>&1
}

_e137_warp_proxy_ready() { _e136_warp_proxy_ready; }
_e137_warp_connect_local_proxy() { _e136_warp_connect_local_proxy; }

_e137_xray_apply_warp_route() {
    local profile="${1:-google-meta-core}" enable="${2:-true}" tx cand was_active=0 failed=0
    _e137_prepare || return 1
    test -x "$XRAY_BIN" && test -s "$CONFIG" || { error "Xray尚未安装或配置不存在。"; return 1; }
    test "$enable" != true || _e137_warp_proxy_ready || { error "WARP本地代理未就绪。"; return 1; }
    tx="$E137_BACKUP_DIR/warp-route-$(date +%Y%m%d_%H%M%S)-$$"
    mkdir -p "$tx" || return 1
    _e135_snapshot_file "$CONFIG" "$tx/config" || return 1
    _e135_snapshot_file "$E137_WARP_STATE" "$tx/state" || return 1
    cand=$(_e118_mktemp xray-warp-e137.json) || return 1
    _e137_warp_config_build "$profile" "$enable" "$cand" "$CONFIG" || return 1
    _e118_xray_test_config "$cand" 1 || { error "WARP候选配置未通过Xray测试。"; return 1; }
    systemctl is-active --quiet xray.service 2>/dev/null && was_active=1 || true
    install -m 0600 "$cand" "$CONFIG" || failed=1
    test "$failed" -ne 0 || fix_permissions
    if test "$failed" -eq 0 && test "$was_active" -eq 1; then
        systemctl restart xray.service >/dev/null 2>&1 || failed=1
        test "$failed" -ne 0 || _e127_verify_xray_runtime "$CONFIG" 12 || failed=1
    fi
    if test "$failed" -eq 0 && test "$enable" = true; then
        _e137_warp_config_integrity "$profile" || failed=1
    fi
    if test "$failed" -eq 0; then
        if test "$enable" = true; then _e137_state_write 1 "$profile" || failed=1
        else _e137_state_write 0 disabled || failed=1; fi
    fi
    if test "$failed" -ne 0; then
        error "WARP路由事务失败，恢复Xray配置和状态。"
        _e135_restore_file "$CONFIG" "$tx/config" || true
        _e135_restore_file "$E137_WARP_STATE" "$tx/state" || true
        fix_permissions
        test "$was_active" -eq 0 || systemctl restart xray.service >/dev/null 2>&1 || true
        return 1
    fi
}

_e137_warp_migrate_state() {
    local old_enabled old_profile actual_old=0
    _e137_prepare || return 1
    test -s "$E137_WARP_STATE" && return 0
    old_enabled=$(sed -n 's/^route_enabled=//p' "${E136_WARP_STATE:-/nonexistent}" 2>/dev/null | tail -n1)
    old_profile=$(sed -n 's/^profile=//p' "${E136_WARP_STATE:-/nonexistent}" 2>/dev/null | tail -n1)
    if test -s "$CONFIG"; then
        jq -e --arg w "${E136_WARP_TAG:-warp-e136}" --arg b "${E136_WARP_BLOCK_TAG:-warp-block-udp-e136}" \
          'any(.outbounds[]?; .tag==$w or .tag==$b) or any(.routing.rules[]?; .outboundTag==$w or .outboundTag==$b)' \
          "$CONFIG" >/dev/null 2>&1 && actual_old=1 || true
    fi
    if test "${old_enabled:-0}" = 1 || test "$actual_old" = 1; then
        _e137_state_write 1 "${old_profile:-google-meta-core}"
    else
        _e137_state_write 0 disabled
    fi
}

_e137_warp_reconcile() {
    local desired profile
    _e137_warp_migrate_state || return 1
    desired=$(_e137_state_get route_enabled 0)
    profile=$(_e137_state_get profile google-meta-core)
    if test "$desired" = 1; then
        _e137_warp_connect_local_proxy || return 1
        if ! _e137_warp_config_integrity "$profile"; then
            _e137_xray_apply_warp_route "$profile" true || return 1
        fi
    else
        # Remove stale old/new WARP routes without turning state on.
        if test -s "$CONFIG" && jq -e --arg w "$E137_WARP_TAG" --arg b "$E137_WARP_BLOCK_TAG" --arg ow "${E136_WARP_TAG:-warp-e136}" --arg ob "${E136_WARP_BLOCK_TAG:-warp-block-udp-e136}" \
          'any(.outbounds[]?; .tag==$w or .tag==$b or .tag==$ow or .tag==$ob) or any(.routing.rules[]?; .outboundTag==$w or .outboundTag==$b or .outboundTag==$ow or .outboundTag==$ob)' "$CONFIG" >/dev/null 2>&1; then
            _e137_xray_apply_warp_route disabled false || return 1
        fi
    fi
}

_e137_warp_health_install() {
    _e137_install_self || return 1
    cat > "$E137_WARP_HEALTH_SERVICE" <<EOF_E137_WARP_SERVICE
[Unit]
Description=Xray WARP selective route reconciliation E137
After=network-online.target warp-svc.service xray.service
Wants=network-online.target

[Service]
Type=oneshot
ExecStart=$SYMLINK --warp-health-check
EOF_E137_WARP_SERVICE
    cat > "$E137_WARP_HEALTH_TIMER" <<'EOF_E137_WARP_TIMER'
[Unit]
Description=Periodic Xray WARP selective route reconciliation E137

[Timer]
OnBootSec=2min
OnUnitInactiveSec=5min
RandomizedDelaySec=30s
Persistent=true

[Install]
WantedBy=timers.target
EOF_E137_WARP_TIMER
    systemctl disable --now xray-warp-e136-health.timer xray-warp-e136-health.service >/dev/null 2>&1 || true
    systemctl daemon-reload >/dev/null 2>&1 || return 1
    systemctl enable --now xray-warp-e137-health.timer >/dev/null 2>&1 || return 1
    systemctl is-enabled --quiet xray-warp-e137-health.timer || return 1
}

_e137_warp_health_check() {
    local desired profile before_guard before_ip after_guard after_ip
    _e137_prepare || return 1
    desired=$(_e137_state_get route_enabled 0)
    profile=$(_e137_state_get profile google-meta-core)
    test "$desired" = 1 || return 0
    mkdir -p "$(dirname "$E137_WARP_LOG")" || true
    before_guard=$(_e136_route_guard_snapshot)
    before_ip=$(_e136_direct_ipv4 2>/dev/null || true)
    if _e137_warp_proxy_ready && _e137_warp_config_integrity "$profile"; then
        echo "[$(date -Is)] OK proxy+Xray-route" >> "$E137_WARP_LOG"
        return 0
    fi
    echo "[$(date -Is)] WARN drift detected; reconciling" >> "$E137_WARP_LOG"
    if _e137_warp_connect_local_proxy && _e137_xray_apply_warp_route "$profile" true; then
        after_guard=$(_e136_route_guard_snapshot)
        after_ip=$(_e136_direct_ipv4 2>/dev/null || true)
        if test "$before_guard" = "$after_guard" && { test -z "$before_ip" || test "$before_ip" = "$after_ip"; } && \
           _e137_warp_proxy_ready && _e137_warp_config_integrity "$profile"; then
            echo "[$(date -Is)] RECOVERED" >> "$E137_WARP_LOG"
            return 0
        fi
    fi
    _e136_warp_cli disconnect >/dev/null 2>&1 || true
    echo "[$(date -Is)] FAIL; route remains fail-closed, WARP disconnected" >> "$E137_WARP_LOG"
    return 1
}

_e137_warp_repair() {
    local desired profile
    _e137_warp_migrate_state || return 1
    desired=$(_e137_state_get route_enabled 0)
    profile=$(_e137_state_get profile google-meta-core)
    _e137_warp_connect_local_proxy || return 1
    if test "$desired" = 1; then
        _e137_xray_apply_warp_route "$profile" true || return 1
        _e137_warp_health_install || return 1
    else
        info "WARP本地代理已恢复；Xray定向分流保持关闭。"
    fi
}

_e137_warp_enable_profile() {
    local profile="${1:-google-meta-core}" confirm tx route_before was_active=0 preinstalled=0 managed
    title "V199e137：启用WARP本地代理与Xray定向分流"
    warn "不会启用全局WARP；SSH、Xray入站和系统默认流量继续走原IPv4。"
    warn "Local proxy必须使用MASQUE并仅监听127.0.0.1:$E137_WARP_PORT。"
    dpkg-query -W -f='${Status}' cloudflare-warp 2>/dev/null | grep -q 'install ok installed' && preinstalled=1 || true
    managed=$(_e137_state_get managed_by "")
    if test "$preinstalled" = 1 && test -z "$managed" && test ! -s "${E136_WARP_STATE:-/nonexistent}"; then
        error "检测到非本脚本管理的WARP，拒绝覆盖其账户和模式。"
        return 1
    fi
    read -rp "输入 ENABLE-WARP 确认: " confirm || true
    test "$confirm" = ENABLE-WARP || return 0
    _e137_prepare || return 1
    tx="$E137_BACKUP_DIR/warp-enable-$(date +%Y%m%d_%H%M%S)-$$"
    mkdir -p "$tx" || return 1
    _e135_snapshot_file "$CONFIG" "$tx/config" || return 1
    _e135_snapshot_file "$E137_WARP_STATE" "$tx/state" || return 1
    _e135_snapshot_file "$E137_WARP_HEALTH_SERVICE" "$tx/service" || return 1
    _e135_snapshot_file "$E137_WARP_HEALTH_TIMER" "$tx/timer" || return 1
    systemctl is-active --quiet xray.service 2>/dev/null && was_active=1 || true
    route_before=$(_e136_warp_route4)
    test -n "$route_before" || { error "IPv4默认路由为空。"; return 1; }
    if ! _e136_warp_install_package "$tx" || ! _e137_warp_connect_local_proxy || \
       ! _e137_xray_apply_warp_route "$profile" true || ! _e137_warp_health_install; then
        error "WARP启用失败，恢复配置和软件状态。"
        _e135_restore_file "$CONFIG" "$tx/config" || true
        _e135_restore_file "$E137_WARP_STATE" "$tx/state" || true
        _e135_restore_file "$E137_WARP_HEALTH_SERVICE" "$tx/service" || true
        _e135_restore_file "$E137_WARP_HEALTH_TIMER" "$tx/timer" || true
        systemctl daemon-reload >/dev/null 2>&1 || true
        test "$was_active" -eq 0 || systemctl restart xray.service >/dev/null 2>&1 || true
        _e136_warp_install_rollback "$tx" || true
        return 1
    fi
    test "$route_before" = "$(_e136_warp_route4)" || { error "IPv4默认路由发生变化，回滚。"; return 1; }
    _e137_warp_config_integrity "$profile" || return 1
    info "WARP定向分流已启用：$profile。"
    _e137_warp_status
}

_e137_warp_disable_route() {
    _e137_xray_apply_warp_route disabled false || return 1
    systemctl disable --now xray-warp-e137-health.timer >/dev/null 2>&1 || true
    info "Xray WARP分流已删除；WARP客户端保留。"
}

_e137_warp_status() {
    local desired profile actual="MISSING" proxy="DOWN" trace loc warpip
    _e137_warp_migrate_state >/dev/null 2>&1 || true
    desired=$(_e137_state_get route_enabled 0)
    profile=$(_e137_state_get profile none)
    _e137_warp_proxy_ready && proxy="UP" || true
    _e137_warp_config_integrity "$profile" && actual="CONSISTENT" || true
    trace=$(_e136_warp_trace 2>/dev/null || true)
    loc=$(awk -F= '$1=="loc"{print $2}' <<<"$trace"); loc=${loc:-unknown}
    warpip=$(awk -F= '$1=="ip"{print $2}' <<<"$trace"); warpip=${warpip:-unknown}
    title "V199e137：WARP定向分流状态"
    printf '  %-24s %s\n' "期望状态" "enabled=$desired profile=$profile"
    printf '  %-24s %s\n' "本地代理" "$proxy (127.0.0.1:$E137_WARP_PORT)"
    printf '  %-24s %s\n' "Xray配置一致性" "$actual"
    printf '  %-24s %s\n' "WARP出口/loc" "$warpip/$loc"
    printf '  %-24s %s\n' "VPS原始IPv4" "$(_e136_direct_ipv4 2>/dev/null || echo unknown)"
    printf '  %-24s %s\n' "默认IPv4路由" "$(_e136_warp_route4 | xargs echo)"
    if test "$desired" = 1 && test "$actual" != CONSISTENT; then warn "状态文件与Xray配置脱节，请运行 --warp-repair。"; fi
    test "${loc^^}" != CN || warn "Cloudflare仍将WARP出口定位为CN。"
}

_e137_warp_menu() {
    local n
    while true; do
        clear; _e137_warp_status
        echo "  1) 启用Google+Meta核心档"
        echo "  2) 仅Google核心档"
        echo "  3) 仅Meta核心档"
        echo "  4) Google+Meta完整实验档"
        echo "  5) 修复代理并按期望状态重建Xray规则"
        echo "  6) 关闭Xray WARP分流（保留客户端）"
        echo "  7) 卸载WARP客户端（调用兼容卸载事务）"
        echo "  0) 返回"
        read -rp "操作: " n || true
        case "$n" in
            1) _e137_warp_enable_profile google-meta-core; _e137_pause ;;
            2) _e137_warp_enable_profile google-core; _e137_pause ;;
            3) _e137_warp_enable_profile meta-core; _e137_pause ;;
            4) _e137_warp_enable_profile google-meta-full; _e137_pause ;;
            5) _e137_warp_repair; _e137_pause ;;
            6) _e137_warp_disable_route; _e137_pause ;;
            7) _e136_warp_uninstall; _e137_pause ;;
            0) return ;;
        esac
    done
}

# Legacy entry names now delegate to the E137 state machine.
