_e136_warp_health_check() { _e137_warp_health_check; }
_e136_warp_health_install() { _e137_warp_health_install; }
_e136_warp_enable_profile() { _e137_warp_enable_profile "$@"; }
_e136_warp_disable_route() { _e137_warp_disable_route; }
_e136_warp_status() { _e137_warp_status; }
_e136_warp_menu() { _e137_warp_menu; }

#------------------------------------------------------------------------------
# Repeatable initcwnd/initrwnd=30 restore with readback and periodic drift check.
#------------------------------------------------------------------------------
_e137_write_init_window_units() {
    cat > "$E137_INIT_SCRIPT" <<'EOF_E137_INIT_SCRIPT'
#!/usr/bin/env bash
set -euo pipefail
export PATH="/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin"
CWND=30
RWND=30
route=$(ip -4 route show default 2>/dev/null | head -n1)
[ -n "$route" ] || exit 1
clean=$(printf '%s\n' "$route" | sed -E 's/[[:space:]]+initcwnd[[:space:]]+[0-9]+//g;s/[[:space:]]+initrwnd[[:space:]]+[0-9]+//g')
ip -4 route replace $clean initcwnd "$CWND" initrwnd "$RWND"
now=$(ip -4 route show default 2>/dev/null | head -n1)
printf '%s\n' "$now" | grep -Eq '(^|[[:space:]])initcwnd[[:space:]]+30([[:space:]]|$)'
printf '%s\n' "$now" | grep -Eq '(^|[[:space:]])initrwnd[[:space:]]+30([[:space:]]|$)'
EOF_E137_INIT_SCRIPT
    chmod 0755 "$E137_INIT_SCRIPT" || return 1
    cat > "$E137_INIT_SERVICE" <<EOF_E137_INIT_SERVICE
[Unit]
Description=Verify and restore initcwnd/initrwnd=30 E137
After=network-online.target
Wants=network-online.target

[Service]
Type=oneshot
ExecStart=$E137_INIT_SCRIPT
EOF_E137_INIT_SERVICE
    cat > "$E137_INIT_TIMER" <<'EOF_E137_INIT_TIMER'
[Unit]
Description=Periodic initcwnd/initrwnd=30 drift check E137

[Timer]
OnBootSec=45s
OnUnitInactiveSec=5min
Persistent=true

[Install]
WantedBy=timers.target
EOF_E137_INIT_TIMER
}

_e137_apply_init_window_default30() {
    local tx oldroute failed=0
    _e137_prepare || return 1
    tx="$E137_BACKUP_DIR/init30-$(date +%Y%m%d_%H%M%S)-$$"; mkdir -p "$tx" || return 1
    oldroute=$(ip -4 route show default 2>/dev/null | head -n1 || true)
    test -n "$oldroute" || { error "没有IPv4默认路由。"; return 1; }
    printf '%s\n' "$oldroute" > "$tx/route"
    for p in "$E137_INIT_SCRIPT" "$E137_INIT_SERVICE" "$E137_INIT_TIMER" "$CONFIG_DIR/initcwnd.txt" "$CONFIG_DIR/initrwnd.txt"; do
        _e135_snapshot_file "$p" "$tx/$(printf '%s' "$p"|sha256sum|awk '{print $1}')" || return 1
    done
    printf '30\n' > "$CONFIG_DIR/initcwnd.txt" || failed=1
    printf '30\n' > "$CONFIG_DIR/initrwnd.txt" || failed=1
    test "$failed" -ne 0 || _e137_write_init_window_units || failed=1
    test "$failed" -ne 0 || systemctl daemon-reload >/dev/null 2>&1 || failed=1
    test "$failed" -ne 0 || systemctl start xray-init-window-e137.service >/dev/null 2>&1 || failed=1
    test "$failed" -ne 0 || systemctl enable --now xray-init-window-e137.timer >/dev/null 2>&1 || failed=1
    test "$failed" -ne 0 || grep -Eq 'initcwnd[[:space:]]+30' < <(ip -4 route show default) || failed=1
    test "$failed" -ne 0 || grep -Eq 'initrwnd[[:space:]]+30' < <(ip -4 route show default) || failed=1
    if test "$failed" -ne 0; then
        error "init30应用或读回失败，恢复旧路由和文件。"
        ip -4 route replace $oldroute >/dev/null 2>&1 || true
        for p in "$E137_INIT_SCRIPT" "$E137_INIT_SERVICE" "$E137_INIT_TIMER" "$CONFIG_DIR/initcwnd.txt" "$CONFIG_DIR/initrwnd.txt"; do
            _e135_restore_file "$p" "$tx/$(printf '%s' "$p"|sha256sum|awk '{print $1}')" || true
        done
        systemctl daemon-reload >/dev/null 2>&1 || true
        return 1
    fi
    systemctl disable --now xray-init-window-e105.service >/dev/null 2>&1 || true
    info "initcwnd/initrwnd=30已通过运行态、开机和5分钟漂移检查。"
}
_e116_apply_init_window_default30() { _e137_apply_init_window_default30; }
_e118_impl_apply_init_window_default30() { _e137_apply_init_window_default30; }

#------------------------------------------------------------------------------
# DAT updater: distinguish fatal installation damage from transient network
# failure when existing DAT files and current Xray configuration remain valid.
#------------------------------------------------------------------------------
if declare -F install_update_dat >/dev/null 2>&1; then
    eval "$(declare -f install_update_dat | sed '1s/install_update_dat/_e137_install_update_dat_base/')"
fi
_e137_existing_dat_valid() {
    test -s "$DAT_DIR/geoip.dat" && test -s "$DAT_DIR/geosite.dat" || return 1
    if test -x "$XRAY_BIN" && test -s "$CONFIG"; then _e118_xray_test_config "$CONFIG" 1 >/dev/null 2>&1; else return 0; fi
}
install_update_dat() {
    local rc=0
    _e137_install_update_dat_base "$@" || rc=$?
    if test "$rc" -eq 0; then return 0; fi
    if test -x "$UPDATE_DAT_SCRIPT" && test -f /etc/systemd/system/xray-dat-update.timer && _e137_existing_dat_valid; then
        warn "DAT即时联网更新失败，但旧DAT与当前Xray配置有效；按降级成功处理，timer后续重试。"
        return 0
    fi
    error "DAT更新器、timer或现有DAT不可用。"
    return 1
}
_e131_dat_update_now() {
    test -x "$UPDATE_DAT_SCRIPT" || install_update_dat || return 1
    if "$UPDATE_DAT_SCRIPT"; then return 0; fi
    _e137_existing_dat_valid && { warn "本次联网更新失败，继续使用已验证旧DAT。"; return 0; }
    return 1
}

#------------------------------------------------------------------------------
# Fail2ban ignore list inherits the runtime jail list instead of replacing it.
#------------------------------------------------------------------------------
_e137_normalize_ignore_tokens() {
    tr ',[]' '   ' | tr -d "'\"" | xargs -n1 2>/dev/null | grep -E '^([0-9A-Fa-f:.]+(/[0-9]{1,3})?|localhost)$' || true
}
_e135_patch_fail2ban_ignoreip() {
    local ip="$1" tmp file_values runtime_values merged
    test -f "$E121_F2B_JAIL" || return 1
    file_values=$(awk -F= '/^[[:space:]]*ignoreip[[:space:]]*=/{sub(/^[^=]*=/,"");print}' "$E121_F2B_JAIL" | _e137_normalize_ignore_tokens | xargs echo)
    runtime_values=$(fail2ban-client get "$E121_F2B_JAIL_NAME" ignoreip 2>/dev/null | _e137_normalize_ignore_tokens | xargs echo || true)
    merged=$(_e136_merge_ignoreip_values "$runtime_values $file_values" "$ip")
    tmp=$(_e118_mktemp f2b-ignore-e137.conf) || return 1
    awk -v merged="$merged" '
      BEGIN{done=0}
      /^[[:space:]]*ignoreip[[:space:]]*=/ {if(!done){print "ignoreip = " merged;done=1};next}
      {print}
      END{if(!done) print "ignoreip = " merged}
    ' "$E121_F2B_JAIL" > "$tmp" || return 1
    install -m 0644 "$tmp" "$E121_F2B_JAIL" || return 1
    fail2ban-client -t >/dev/null 2>&1 || return 1
    systemctl restart fail2ban >/dev/null 2>&1 || return 1
    test -z "$ip" || fail2ban-client set "$E121_F2B_JAIL_NAME" unbanip "$ip" >/dev/null 2>&1 || true
    runtime_values=$(fail2ban-client get "$E121_F2B_JAIL_NAME" ignoreip 2>/dev/null || true)
    test -z "$ip" || grep -Fq "$ip" <<<"$runtime_values"
}

_e137_ssh_backend_supported() {
    if command -v ufw >/dev/null 2>&1 && ufw status 2>/dev/null | grep -q '^Status: active'; then return 0; fi
    if command -v firewall-cmd >/dev/null 2>&1 && firewall-cmd --state 2>/dev/null | grep -q running; then return 0; fi
    command -v iptables >/dev/null 2>&1 && return 0
    error "仅检测到纯nftables且无iptables兼容层，当前SSH守护实现无法证明链序，拒绝半配置。"
    return 1
}
if declare -F _e135_install_ssh_guard >/dev/null 2>&1; then
    eval "$(declare -f _e135_install_ssh_guard | sed '1s/_e135_install_ssh_guard/_e137_ssh_guard_base/')"
fi
_e135_install_ssh_guard() { _e137_ssh_backend_supported || return 1; _e137_ssh_guard_base; }
_e121_install_ssh_guard() { _e135_install_ssh_guard; }
_e116_install_ssh_guard() { _e135_install_ssh_guard; }

